// Two-input f64-output counterpart of zerocopy_f64_unary_flat. When a and b are
// exact same-shape C-contiguous float64 ndarrays, read both buffers and write
// `op.apply(a[i], b[i])` straight into the output buffer — no intermediate Rust
// Vec for either input or the output, removing the three cold allocations whose
// first-touch page faults dominate these ops (bead lglck). `op.apply` is the
// SAME BinaryOp kernel the extract path uses, so output is bit-identical by
// construction. Returns Ok(None) — fall through to the extract path, all other
// inputs unchanged — for non-float64, broadcasting/shape-mismatch, scalar, or
// non-ndarray operands.
fn zerocopy_f64_binary_flat<'py>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    a: &Bound<'py, PyAny>,
    b: &Bound<'py, PyAny>,
    op: BinaryOp,
) -> PyResult<Option<(Bound<'py, PyAny>, Vec<usize>)>> {
    const FLOAT_POWER_PARALLEL_MIN_LEN: usize = 16_384;

    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.get_type().is(&ndarray_type) || !b.get_type().is(&ndarray_type) {
        return Ok(None);
    }
    let (Ok(a_buffer), Ok(b_buffer)) = (PyBuffer::<f64>::get(a), PyBuffer::<f64>::get(b)) else {
        return Ok(None);
    };
    let (Some(a_in), Some(b_in)) = (a_buffer.as_slice(py), b_buffer.as_slice(py)) else {
        return Ok(None);
    };
    // No broadcasting: identical shapes only, so flat index i pairs a[i] with b[i].
    if a_buffer.shape() != b_buffer.shape() {
        return Ok(None);
    }
    let shape: Vec<usize> = a_buffer.shape().to_vec();
    let n = a_in.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // Compute-bound binary transcendentals (powf/atan2/logaddexp): numpy runs
        // these single-threaded (SIMD), so copying the two borrowed buffers into
        // Vecs and fanning the expensive scalar libm op across the rayon pool beats
        // the serial op.apply loop. `op.apply` is the SAME per-element function, so
        // the result is bit-identical to the serial path. PyBuffer cells are !Sync
        // (cannot be read from rayon threads), hence the one-time Vec copy.
        let parallelizable = matches!(
            op,
            BinaryOp::FloatPower
                | BinaryOp::Arctan2
                | BinaryOp::Logaddexp
                | BinaryOp::Logaddexp2
                | BinaryOp::Hypot
        );
        // Per-op crossover: expensive transcendentals (atan2/pow/logaddexp) amortize the
        // rayon fan-out from ~16K, but cheap near-memory-bound ops (hypot = sqrt(a^2+b^2))
        // only win once aggregate bandwidth dominates (~2M, like the cheap unary class) —
        // a low gate REGRESSES medium N for them.
        let parallel_min = match op {
            BinaryOp::Hypot => 1 << 21,
            _ => FLOAT_POWER_PARALLEL_MIN_LEN,
        };
        if parallelizable && n >= parallel_min && rayon::current_num_threads() >= 2 {
            use rayon::prelude::*;
            // No Vec copy: read the borrowed buffers as &[f64] and write op.apply straight
            // into the numpy.empty output. ReadOnlyCell<f64>/Cell<f64> are repr(transparent)
            // over f64; inputs are read-only under the GIL and `output` is a fresh buffer we
            // own (no alias). Bit-identical to the serial op.apply loop. (The old one-time
            // Vec copy predated this from_raw_parts trick and taxed the cheaper ops.)
            let lhs: &[f64] =
                unsafe { std::slice::from_raw_parts(a_in.as_ptr().cast::<f64>(), n) };
            let rhs: &[f64] =
                unsafe { std::slice::from_raw_parts(b_in.as_ptr().cast::<f64>(), n) };
            let out_data: &mut [f64] =
                unsafe { std::slice::from_raw_parts_mut(output.as_ptr() as *mut f64, n) };
            let chunk = n.div_ceil(rayon::current_num_threads());
            out_data
                .par_chunks_mut(chunk)
                .zip(lhs.par_chunks(chunk))
                .zip(rhs.par_chunks(chunk))
                .for_each(|((o, l), r)| {
                    for ((s, &x), &y) in o.iter_mut().zip(l.iter()).zip(r.iter()) {
                        *s = op.apply(x, y);
                    }
                });
        } else {
            for ((slot, a_cell), b_cell) in output.iter().zip(a_in.iter()).zip(b_in.iter()) {
                slot.set(op.apply(a_cell.get(), b_cell.get()));
            }
        }
    }
    Ok(Some((flat, shape)))
}

// Wrap zerocopy_f64_binary_flat with the shared reshape / 0-d scalar handling.
fn try_zerocopy_f64_binary(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    b: &Bound<'_, PyAny>,
    op: BinaryOp,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let Some((flat, shape)) = zerocopy_f64_binary_flat(py, &numpy, a, b, op)? else {
        return Ok(None);
    };
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    if shape.is_empty() {
        return Ok(Some(output.bind(py).get_item(())?.unbind()));
    }
    Ok(Some(output))
}

fn ndarray_has_native_f64_dtype(value: &Bound<'_, PyAny>) -> PyResult<bool> {
    let dtype = value.getattr("dtype")?;
    let dtype_kind: String = dtype.getattr("kind")?.extract()?;
    let dtype_itemsize: usize = dtype.getattr("itemsize")?.extract()?;
    let is_native: bool = dtype.getattr("isnative")?.extract()?;
    Ok(matches!(dtype_kind.as_str(), "f") && dtype_itemsize == 8 && is_native)
}

fn ndarray_has_native_i32_dtype(value: &Bound<'_, PyAny>) -> PyResult<bool> {
    let dtype = value.getattr("dtype")?;
    let dtype_kind: String = dtype.getattr("kind")?.extract()?;
    let dtype_itemsize: usize = dtype.getattr("itemsize")?.extract()?;
    let is_native: bool = dtype.getattr("isnative")?.extract()?;
    Ok(matches!(dtype_kind.as_str(), "i") && dtype_itemsize == 4 && is_native)
}

fn scalbn_f64_normal_result(mantissa: f64, exponent: i32) -> Option<f64> {
    const SIGN_MASK: u64 = 0x8000_0000_0000_0000;
    const FRACTION_MASK: u64 = 0x000f_ffff_ffff_ffff;
    const EXPONENT_MASK: u64 = 0x7ff0_0000_0000_0000;
    const EXPONENT_SHIFT: u32 = 52;

    let bits = mantissa.to_bits();
    let exponent_bits = ((bits & EXPONENT_MASK) >> EXPONENT_SHIFT) as i64;
    if exponent_bits == 0 || exponent_bits == 0x7ff {
        return None;
    }

    let scaled_exponent = exponent_bits + i64::from(exponent);
    if !(1..0x7ff).contains(&scaled_exponent) {
        return None;
    }

    let scaled_bits =
        (bits & SIGN_MASK) | ((scaled_exponent as u64) << EXPONENT_SHIFT) | (bits & FRACTION_MASK);
    Some(f64::from_bits(scaled_bits))
}

// Zero-copy np.ldexp for the profiled native-boundary shape: exact C-contiguous
// float64 mantissas and exact same-shape native int32 exponents. The element
// formula is identical to the existing Rust path (`x * 2.0.powf(exp as f64)`),
// but reads both NumPy buffers directly and writes the result buffer directly.
// NaN payload-sensitive inputs and overflow/underflow flag cases fall through to
// the existing path, preserving error-state handling and all non-profiled
// dtype/broadcast/subclass/stride behavior.
fn try_zerocopy_f64_i32_ldexp(
    py: Python<'_>,
    x1: &Bound<'_, PyAny>,
    x2: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !x1.is_exact_instance(&ndarray_type) || !x2.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    if !ndarray_has_native_f64_dtype(x1)? || !ndarray_has_native_i32_dtype(x2)? {
        return Ok(None);
    }
    let (Ok(x1_buffer), Ok(x2_buffer)) = (PyBuffer::<f64>::get(x1), PyBuffer::<i32>::get(x2))
    else {
        return Ok(None);
    };
    if x1_buffer.shape() != x2_buffer.shape() {
        return Ok(None);
    }
    let (Some(mantissas), Some(exponents)) = (x1_buffer.as_slice(py), x2_buffer.as_slice(py))
    else {
        return Ok(None);
    };

    let shape = x1_buffer.shape().to_vec();
    let n = mantissas.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        for ((slot, mantissa_cell), exponent_cell) in
            output.iter().zip(mantissas.iter()).zip(exponents.iter())
        {
            let mantissa = mantissa_cell.get();
            if mantissa.is_nan() {
                return Ok(None);
            }
            let exponent = exponent_cell.get();
            let Some(result) = scalbn_f64_normal_result(mantissa, exponent) else {
                let result = mantissa * 2.0_f64.powf(f64::from(exponent));
                let mantissa_magnitude_bits = mantissa.to_bits() & 0x7fff_ffff_ffff_ffff;
                let result_magnitude_bits = result.to_bits() & 0x7fff_ffff_ffff_ffff;
                if mantissa.is_finite()
                    && ((result.is_infinite() && !mantissa.is_infinite())
                        || (mantissa_magnitude_bits != 0 && result_magnitude_bits == 0))
                {
                    return Ok(None);
                }
                slot.set(result);
                continue;
            };
            slot.set(result);
        }
    }

    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    if shape.is_empty() {
        return Ok(Some(output.bind(py).get_item(())?.unbind()));
    }
    Ok(Some(output))
}

// Zero-copy clip for exact C-contiguous float64 ndarrays with scalar bounds.
// numpy's clip is min(max(x, lo), hi) with NaN propagating; the two comparisons
// below reproduce that bit-for-bit (NaN fails both `<`/`>` so it passes through;
// lo > hi clamps to hi, matching numpy). For an f64 input array with real scalar
// bounds the result_type promotion is always a no-op, so the caller's promotion
// guard is satisfied by construction. Reads the input buffer and writes the
// output buffer with no intermediate Rust Vec (bead lglck). Returns Ok(None) for
// any non-f64 / non-contiguous / non-ndarray input (caller falls through).
fn try_zerocopy_f64_clip(
    py: Python<'_>,
    x: &Bound<'_, PyAny>,
    lo: f64,
    hi: f64,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !x.get_type().is(&ndarray_type) {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(x) else {
        return Ok(None);
    };
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    let n = input.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        for (slot, cell) in output.iter().zip(input.iter()) {
            let v = cell.get();
            let t = if v < lo { lo } else { v };
            slot.set(if t > hi { hi } else { t });
        }
    }
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    if shape.is_empty() {
        return Ok(Some(output.bind(py).get_item(())?.unbind()));
    }
    Ok(Some(output))
}

// Zero-copy clip for exact C-contiguous float32 ndarrays with scalar bounds. The
// f64 helper gates on float64, so float32 otherwise round-trips through an f64 Vec
// (~19x slower). Clamps in float32 with the same comparison form as the f64 path
// (`if v < lo {lo} else {v}` then `if t > hi {hi} else {t}`): for a NaN element
// both comparisons are false so NaN propagates, matching numpy. Gated on a no-op
// promotion (result_type(a, a_min, a_max) == float32) so a strong numpy-float64
// scalar bound — which would widen the result to float64 — correctly defers. The
// weak python-float bounds are cast f64 -> f32 by round-to-nearest, exactly as
// numpy adopts them into the array's float32 dtype. Returns None otherwise.
fn try_zerocopy_f32_clip(
    py: Python<'_>,
    x: &Bound<'_, PyAny>,
    a_min: &Bound<'_, PyAny>,
    a_max: &Bound<'_, PyAny>,
    lo_f64: f64,
    hi_f64: f64,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !x.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = x.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 4
    {
        return Ok(None);
    }
    // Result dtype must equal float32 (no promotion): a strong numpy-float64 scalar
    // bound would widen the result to float64, which this path cannot produce.
    let promoted = numpy.getattr("result_type")?.call1((x, a_min, a_max))?;
    if !promoted.eq(&dtype)? {
        return Ok(None);
    }
    let lo = lo_f64 as f32;
    let hi = hi_f64 as f32;
    let Ok(in_buffer) = PyBuffer::<f32>::get(x) else {
        return Ok(None);
    };
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    let n = input.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float32")?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<f32>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        for (slot, cell) in output.iter().zip(input.iter()) {
            let v = cell.get();
            let t = if v < lo { lo } else { v };
            slot.set(if t > hi { hi } else { t });
        }
    }
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    if shape.is_empty() {
        return Ok(Some(output.bind(py).get_item(())?.unbind()));
    }
    Ok(Some(output))
}

// Generic typed core for integer clip: clamp each element into [lo, hi] in the
// input integer width (max(lo).min(hi) — gives hi when lo>hi, matching numpy)
// and write to a fresh buffer of dtype `dtype_name`. Clamping in the integer
// width (not f64) is required: i64/u64 values above 2^53 would lose precision
// through an f64 round-trip. Branchless -> autovectorizes.
fn clip_typed<'py, T>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    a: &Bound<'py, PyAny>,
    dtype_name: &str,
    lo: T,
    hi: T,
) -> PyResult<Option<(Bound<'py, PyAny>, Vec<usize>)>>
where
    T: pyo3::buffer::Element + Copy + Ord,
{
    let Ok(in_buffer) = PyBuffer::<T>::get(a) else {
        return Ok(None);
    };
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    let n = input.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", dtype_name)?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<T>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        for (slot, cell) in output.iter().zip(input.iter()) {
            slot.set(cell.get().max(lo).min(hi));
        }
    }
    Ok(Some((flat, shape)))
}

// Zero-copy integer clip for exact int8/16/32/64 and uint8/16/32/64 ndarrays
// with scalar bounds. Gated on a no-op dtype promotion (result_type(a, lo, hi)
// == a.dtype) so the result dtype matches numpy exactly — this also guarantees
// both bounds fit the input integer width, so extracting them as T succeeds.
// Otherwise the f64 round-trip the extract path takes is both ~100-300x slower
// and lossy for wide integers.
fn try_zerocopy_int_clip(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    a_min: &Bound<'_, PyAny>,
    a_max: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if kind != "i" && kind != "u" {
        return Ok(None);
    }
    // Result dtype must equal the input dtype (no promotion), e.g. a strong
    // numpy-int64 scalar bound on an int8 array would widen to int64 in numpy.
    let promoted = numpy.getattr("result_type")?.call1((a, a_min, a_max))?;
    if !promoted.eq(&dtype)? {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    let result = match (kind.as_str(), itemsize) {
        ("i", 1) => {
            let (Ok(lo), Ok(hi)) = (a_min.extract::<i8>(), a_max.extract::<i8>()) else {
                return Ok(None);
            };
            clip_typed::<i8>(py, &numpy, a, "int8", lo, hi)?
        }
        ("i", 2) => {
            let (Ok(lo), Ok(hi)) = (a_min.extract::<i16>(), a_max.extract::<i16>()) else {
                return Ok(None);
            };
            clip_typed::<i16>(py, &numpy, a, "int16", lo, hi)?
        }
        ("i", 4) => {
            let (Ok(lo), Ok(hi)) = (a_min.extract::<i32>(), a_max.extract::<i32>()) else {
                return Ok(None);
            };
            clip_typed::<i32>(py, &numpy, a, "int32", lo, hi)?
        }
        ("i", 8) => {
            let (Ok(lo), Ok(hi)) = (a_min.extract::<i64>(), a_max.extract::<i64>()) else {
                return Ok(None);
            };
            clip_typed::<i64>(py, &numpy, a, "int64", lo, hi)?
        }
        ("u", 1) => {
            let (Ok(lo), Ok(hi)) = (a_min.extract::<u8>(), a_max.extract::<u8>()) else {
                return Ok(None);
            };
            clip_typed::<u8>(py, &numpy, a, "uint8", lo, hi)?
        }
        ("u", 2) => {
            let (Ok(lo), Ok(hi)) = (a_min.extract::<u16>(), a_max.extract::<u16>()) else {
                return Ok(None);
            };
            clip_typed::<u16>(py, &numpy, a, "uint16", lo, hi)?
        }
        ("u", 4) => {
            let (Ok(lo), Ok(hi)) = (a_min.extract::<u32>(), a_max.extract::<u32>()) else {
                return Ok(None);
            };
            clip_typed::<u32>(py, &numpy, a, "uint32", lo, hi)?
        }
        ("u", 8) => {
            let (Ok(lo), Ok(hi)) = (a_min.extract::<u64>(), a_max.extract::<u64>()) else {
                return Ok(None);
            };
            clip_typed::<u64>(py, &numpy, a, "uint64", lo, hi)?
        }
        _ => return Ok(None),
    };
    let Some((flat, shape)) = result else {
        return Ok(None);
    };
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    if shape.is_empty() {
        return Ok(Some(output.bind(py).get_item(())?.unbind()));
    }
    Ok(Some(output))
}

// Zero-copy nan_to_num for exact C-contiguous float64 ndarrays. numpy replaces
// NaN -> nan_rep, +inf -> posinf_rep, -inf -> neginf_rep, and leaves every
// finite value (including signed zeros) untouched — reproduced bit-for-bit
// below. For an f64 input the default posinf/neginf are f64::MAX / f64::MIN
// (== numpy finfo(float64).max / -max), which the caller passes in. Reads the
// input buffer and writes the output buffer with no intermediate Rust Vec
// (bead lglck). Returns Ok(None) for any non-f64 / non-contiguous / non-ndarray
// input (caller falls through to the dtype-aware extract path).
// Zero-copy np.nan_to_num for integer ndarrays. Integers cannot be NaN or +-inf,
// so numpy.nan_to_num (copy=True; the copy=False in-place mode is handled earlier by
// delegating to numpy) is a pure dtype- and layout-preserving copy regardless of the
// nan/posinf/neginf args. The
// extract path instead routes integers through an f64 Vec + rebuild (~155-296x
// slower, lossy for wide ints). numpy materializes the copy with np.array(x,
// copy=True, order='K'), so x.copy(order='K') is bit- and layout-identical. Returns
// None for a non-integer dtype or a non-ndarray input.
fn try_zerocopy_int_nan_to_num(
    py: Python<'_>,
    x: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !x.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let kind = x.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
    if kind != "i" && kind != "u" {
        return Ok(None);
    }
    let kwargs = PyDict::new(py);
    kwargs.set_item("order", "K")?;
    Ok(Some(x.call_method("copy", (), Some(&kwargs))?.unbind()))
}

fn try_zerocopy_f64_nan_to_num(
    py: Python<'_>,
    x: &Bound<'_, PyAny>,
    nan_rep: f64,
    posinf_rep: f64,
    neginf_rep: f64,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !x.get_type().is(&ndarray_type) {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(x) else {
        return Ok(None);
    };
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    let n = input.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        for (slot, cell) in output.iter().zip(input.iter()) {
            let v = cell.get();
            let replaced = if v.is_nan() {
                nan_rep
            } else if v == f64::INFINITY {
                posinf_rep
            } else if v == f64::NEG_INFINITY {
                neginf_rep
            } else {
                v
            };
            slot.set(replaced);
        }
    }
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    if shape.is_empty() {
        return Ok(Some(output.bind(py).get_item(())?.unbind()));
    }
    Ok(Some(output))
}

// Zero-copy nan_to_num for exact C-contiguous float32 ndarrays — the float32 sibling
// of try_zerocopy_f64_nan_to_num. numpy replaces NaN -> nan_rep, +inf -> posinf_rep,
// -inf -> neginf_rep and leaves every finite value (incl. signed zeros) untouched,
// all in float32. The replacement scalars are the python-float args cast to float32
// exactly as numpy assigns them into the float32 array (a too-large posinf saturates
// to inf, matching numpy's overflow-on-cast). The f64 helper gates on float64, so
// float32 otherwise extracted to an f64 Vec (~9.6x slower). The caller passes the
