// Zero-copy np.where(cond, x, y) for the common select form: a bool cond ndarray
// with float64 x and y of the identical shape. out[i] = x[i] if cond[i] else
// y[i] — a pure element-wise select (the chosen value is copied verbatim, so it
// is bit-identical incl. nan/inf/signed zeros). Reads all three buffers and
// writes the output buffer with no intermediate Rust Vec, dropping the four cold
// extract/build Vecs (bead lglck). The bool buffer's format is '?' which
// PyBuffer::<u8> rejects, so cond is viewed as uint8 (its bytes are 0x00/0x01)
// first. Returns Ok(None) — caller falls through — for non-bool cond, non-f64 /
// broadcasting / shape-mismatch x or y, or any non-ndarray operand.
fn try_zerocopy_f64_where(
    py: Python<'_>,
    condition: &Bound<'_, PyAny>,
    x: &Bound<'_, PyAny>,
    y: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    // cond must be a bool dtype ndarray; other kinds keep the dtype-aware path.
    if condition
        .getattr("dtype")?
        .getattr("kind")?
        .extract::<String>()?
        != "b"
    {
        return Ok(None);
    }
    let cond_u8 = condition.call_method1("view", (numpy.getattr("uint8")?,))?;
    let Ok(cond_buffer) = PyBuffer::<u8>::get(&cond_u8) else {
        return Ok(None);
    };
    let Some(cond_in) = cond_buffer.as_slice(py) else {
        return Ok(None);
    };
    let shape: Vec<usize> = cond_buffer.shape().to_vec();
    let n = cond_in.len();

    // Each of x, y is either a same-shape f64 ndarray (zero-copy buffer) or an
    // f64-extractable scalar (so `np.where(cond, arr, 0.0)` / scalar branches keep
    // the single-pass path instead of falling back to numpy). Buffers are held in
    // locals to keep them alive for the slice borrows.
    let x_buffer = PyBuffer::<f64>::get(x)
        .ok()
        .filter(|b| b.shape() == shape.as_slice());
    let y_buffer = PyBuffer::<f64>::get(y)
        .ok()
        .filter(|b| b.shape() == shape.as_slice());
    let x_scalar = if x_buffer.is_none() {
        x.extract::<f64>().ok()
    } else {
        None
    };
    let y_scalar = if y_buffer.is_none() {
        y.extract::<f64>().ok()
    } else {
        None
    };
    // Every operand must be classified (array or f64 scalar).
    if (x_buffer.is_none() && x_scalar.is_none()) || (y_buffer.is_none() && y_scalar.is_none()) {
        return Ok(None);
    }
    // numpy's result dtype must be float64: an f64 array, or a FLOAT (not integer)
    // scalar, on either side. Two integer scalars (np.where(c, 1, 0)) promote to
    // int64, so defer those to numpy.
    let x_is_float = x_buffer.is_some() || x.is_instance_of::<pyo3::types::PyFloat>();
    let y_is_float = y_buffer.is_some() || y.is_instance_of::<pyo3::types::PyFloat>();
    if !x_is_float && !y_is_float {
        return Ok(None);
    }
    let x_in = match &x_buffer {
        Some(b) => match b.as_slice(py) {
            Some(s) => Some(s),
            None => return Ok(None),
        },
        None => None,
    };
    let y_in = match &y_buffer {
        Some(b) => match b.as_slice(py) {
            Some(s) => Some(s),
            None => return Ok(None),
        },
        None => None,
    };
    let xs = x_scalar.unwrap_or(0.0);
    let ys = y_scalar.unwrap_or(0.0);
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // Branch once on the operand shapes so each loop is a tight, bounds-check-free
        // zipped blend (the arr/arr case is identical to the original fast path).
        match (x_in, y_in) {
            (Some(xa), Some(ya)) => {
                for (((slot, c), xv), yv) in
                    output.iter().zip(cond_in).zip(xa.iter()).zip(ya.iter())
                {
                    slot.set(if c.get() != 0 { xv.get() } else { yv.get() });
                }
            }
            (Some(xa), None) => {
                for ((slot, c), xv) in output.iter().zip(cond_in).zip(xa.iter()) {
                    slot.set(if c.get() != 0 { xv.get() } else { ys });
                }
            }
            (None, Some(ya)) => {
                for ((slot, c), yv) in output.iter().zip(cond_in).zip(ya.iter()) {
                    slot.set(if c.get() != 0 { xs } else { yv.get() });
                }
            }
            (None, None) => {
                for (slot, c) in output.iter().zip(cond_in) {
                    slot.set(if c.get() != 0 { xs } else { ys });
                }
            }
        }
    }
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    if shape.is_empty() {
        return Ok(Some(output.bind(py).get_item(())?.unbind()));
    }
    Ok(Some(output))
}

// Generic typed core for np.where(cond, x, y) element-wise select with no
// broadcasting (cond bool + x/y same-shape same-dtype `T` ndarrays). The
// per-element `if cond { x } else { y }` is a branchless integer blend (cmov), so
// it autovectorizes. Requiring PyBuffer::<T> for both x and y enforces x.dtype ==
// y.dtype == T, matching numpy's result_type(x, y) for the equal-dtype case.
fn where_typed<'py, T: pyo3::buffer::Element + Copy>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    cond_u8: &Bound<'py, PyAny>,
    x: &Bound<'py, PyAny>,
    y: &Bound<'py, PyAny>,
    dtype_name: &str,
) -> PyResult<Option<(Bound<'py, PyAny>, Vec<usize>)>> {
    let (Ok(cond_buffer), Ok(x_buffer), Ok(y_buffer)) = (
        PyBuffer::<u8>::get(cond_u8),
        PyBuffer::<T>::get(x),
        PyBuffer::<T>::get(y),
    ) else {
        return Ok(None);
    };
    let (Some(cond_in), Some(x_in), Some(y_in)) = (
        cond_buffer.as_slice(py),
        x_buffer.as_slice(py),
        y_buffer.as_slice(py),
    ) else {
        return Ok(None);
    };
    if cond_buffer.shape() != x_buffer.shape() || x_buffer.shape() != y_buffer.shape() {
        return Ok(None);
    }
    let shape: Vec<usize> = x_buffer.shape().to_vec();
    let n = x_in.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", dtype_name)?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<T>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        for (((slot, cond_cell), x_cell), y_cell) in output
            .iter()
            .zip(cond_in.iter())
            .zip(x_in.iter())
            .zip(y_in.iter())
        {
            slot.set(if cond_cell.get() != 0 {
                x_cell.get()
            } else {
                y_cell.get()
            });
        }
    }
    Ok(Some((flat, shape)))
}

// Zero-copy np.where(cond, x, y) select for bool cond + same-shape same-dtype
// int8/16/32/64, uint8/16/32/64, or bool x/y. The f64 helper above leaves these
// to the cold extract path (~16x slower, lossy for wide ints). Returns None for
// a non-bool cond, mismatched x/y dtypes (PyBuffer::<T> gates it), broadcasting,
// or a non-ndarray operand.
fn try_zerocopy_int_where(
    py: Python<'_>,
    condition: &Bound<'_, PyAny>,
    x: &Bound<'_, PyAny>,
    y: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !x.is_exact_instance(&ndarray_type) || !y.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    if condition
        .getattr("dtype")?
        .getattr("kind")?
        .extract::<String>()?
        != "b"
    {
        return Ok(None);
    }
    let cond_u8 = condition.call_method1("view", (numpy.getattr("uint8")?,))?;
    let x_dtype = x.getattr("dtype")?;
    let kind = x_dtype.getattr("kind")?.extract::<String>()?;
    let itemsize = x_dtype.getattr("itemsize")?.extract::<usize>()?;
    // The integer/bool arms are dtype-safe because PyBuffer::<T> requires a
    // matching buffer format; the float arms select through an unsigned view, which
    // bypasses that check, so they additionally require x and y to share the exact
    // dtype (numpy would otherwise promote — deferred to the general path).
    let same_dtype = x_dtype.eq(y.getattr("dtype")?)?;
    let result = match (kind.as_str(), itemsize) {
        ("i", 1) => where_typed::<i8>(py, &numpy, &cond_u8, x, y, "int8")?,
        ("i", 2) => where_typed::<i16>(py, &numpy, &cond_u8, x, y, "int16")?,
        ("i", 4) => where_typed::<i32>(py, &numpy, &cond_u8, x, y, "int32")?,
        ("i", 8) => where_typed::<i64>(py, &numpy, &cond_u8, x, y, "int64")?,
        ("u", 1) => where_typed::<u8>(py, &numpy, &cond_u8, x, y, "uint8")?,
        ("u", 2) => where_typed::<u16>(py, &numpy, &cond_u8, x, y, "uint16")?,
        ("u", 4) => where_typed::<u32>(py, &numpy, &cond_u8, x, y, "uint32")?,
        ("u", 8) => where_typed::<u64>(py, &numpy, &cond_u8, x, y, "uint64")?,
        // bool select also goes through a uint8 view, which (like the float arms)
        // bypasses PyBuffer's format check, so it likewise requires x and y to share
        // the bool dtype — otherwise e.g. where(bool_x, int8_y) must promote to int8
        // (deferred to numpy) instead of being returned as bool.
        ("b", 1) if same_dtype => {
            let x_u8 = x.call_method1("view", (numpy.getattr("uint8")?,))?;
            let y_u8 = y.call_method1("view", (numpy.getattr("uint8")?,))?;
            match where_typed::<u8>(py, &numpy, &cond_u8, &x_u8, &y_u8, "uint8")? {
                Some((flat_u8, shape)) => {
                    let flat_bool = flat_u8.call_method1("view", (numpy.getattr("bool_")?,))?;
                    Some((flat_bool, shape))
                }
                None => None,
            }
        }
        // float16 / float32 select is value-agnostic: pick verbatim through a
        // same-width unsigned view of x and y, reusing the existing u16/u32
        // where_typed instantiations, then view the result back to the float dtype
        // (f64 is handled by try_zerocopy_f64_where before this). A non-contiguous
        // x/y makes .view raise; defer to numpy then.
        ("f", 2) if same_dtype => {
            let u16t = numpy.getattr("uint16")?;
            let (Ok(x_u), Ok(y_u)) = (
                x.call_method1("view", (&u16t,)),
                y.call_method1("view", (&u16t,)),
            ) else {
                return Ok(None);
            };
            match where_typed::<u16>(py, &numpy, &cond_u8, &x_u, &y_u, "uint16")? {
                Some((flat_u16, shape)) => {
                    let flat_f = flat_u16.call_method1("view", (numpy.getattr("float16")?,))?;
                    Some((flat_f, shape))
                }
                None => None,
            }
        }
        ("f", 4) if same_dtype => {
            let u32t = numpy.getattr("uint32")?;
            let (Ok(x_u), Ok(y_u)) = (
                x.call_method1("view", (&u32t,)),
                y.call_method1("view", (&u32t,)),
            ) else {
                return Ok(None);
            };
            match where_typed::<u32>(py, &numpy, &cond_u8, &x_u, &y_u, "uint32")? {
                Some((flat_u32, shape)) => {
                    let flat_f = flat_u32.call_method1("view", (numpy.getattr("float32")?,))?;
                    Some((flat_f, shape))
                }
                None => None,
            }
        }
        _ => return Ok(None),
    };
    let Some((flat, shape)) = result else {
        return Ok(None);
    };
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    if shape.is_empty() {
        return Ok(Some(output.bind(py).get_item(())?.unbind()));
    }
    Ok(Some(output))
}

// Zero-copy np.where(cond, x, y) where exactly ONE of x/y is an ndarray and the other is
// a SCALAR (the extremely common `np.where(c, arr, 0)` idiom). The f64 helper handles
// f64-array+scalar; this covers ANY numeric dtype (f32/int*/complex/bool) via a byte-level
// select: the result is just arr[i]'s bytes or the scalar's bytes per element. A
// result_type(arr, scalar)==arr.dtype guard rejects value-based promotion (e.g.
// where(int_arr, 0.5) -> float64), which is deferred. Bit-identical (pure byte placement).
// Returns None for non-bool cond, two-array / two-scalar forms (handled elsewhere),
// shape mismatch, non-contiguous, or non-numeric / promoting dtypes.
fn try_zerocopy_where_array_scalar(
    py: Python<'_>,
    condition: &Bound<'_, PyAny>,
    x: &Bound<'_, PyAny>,
    y: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if condition
        .getattr("dtype")?
        .getattr("kind")?
        .extract::<String>()?
        != "b"
    {
        return Ok(None);
    }
    let x_is_arr = x.is_exact_instance(&ndarray_type);
    let y_is_arr = y.is_exact_instance(&ndarray_type);
    if x_is_arr == y_is_arr {
        return Ok(None); // need exactly one array + one scalar
    }
    let (arr, scalar_obj, scalar_is_x) = if x_is_arr { (x, y, false) } else { (y, x, true) };
    // The non-array side must be a TRUE scalar. ndarray SUBCLASSES (e.g. an
    // __array_function__ override), 0-d arrays, lists, and tuples all expose __len__ and
    // must defer to numpy (which dispatches subclass overrides and broadcasts sequences);
    // Python int/float/complex/bool and numpy scalars have no __len__ -> fast path.
    if scalar_obj.hasattr("__len__")? {
        return Ok(None);
    }
    let dtype = arr.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if !matches!(kind.as_str(), "f" | "i" | "u" | "c" | "b") {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    if itemsize == 0 {
        return Ok(None);
    }
    // No value-based promotion: numpy's result must stay arr's dtype.
    if !numpy
        .call_method1("result_type", (arr, scalar_obj))?
        .eq(&dtype)?
    {
        return Ok(None);
    }
    let cond_shape: Vec<usize> = condition.getattr("shape")?.extract()?;
    let arr_shape: Vec<usize> = arr.getattr("shape")?.extract()?;
    if cond_shape != arr_shape {
        return Ok(None);
    }
    if !condition
        .getattr("flags")?
        .getattr("c_contiguous")?
        .extract::<bool>()?
        || !arr
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return Ok(None);
    }
    // View arr/out/scalar as a same-width UNSIGNED integer and run a TYPED select
    // (vectorizable cmov/blend) — bit-identical to placing the raw bytes, but unlike a
    // per-element byte memcpy it vectorizes and beats numpy.where (like the f64 path).
    // Complex128 (itemsize 16) has no u128 buffer Element -> defer to numpy.
    let cond_u8 = condition.call_method1("view", (&numpy.getattr("uint8")?,))?;
    let Ok(cond_buf) = PyBuffer::<u8>::get(&cond_u8) else {
        return Ok(None);
    };
    let Some(cond_cells) = cond_buf.as_slice(py) else {
        return Ok(None);
    };
    let n = cond_cells.len();
    macro_rules! select_unsigned {
        ($U:ty, $uname:literal) => {{
            let un = numpy.getattr($uname)?;
            let arr_u = arr.call_method1("view", (&un,))?;
            let Ok(arr_buf) = PyBuffer::<$U>::get(&arr_u) else {
                return Ok(None);
            };
            let Some(arr_in) = arr_buf.as_slice(py) else {
                return Ok(None);
            };
            if arr_in.len() != n {
                return Ok(None);
            }
            let sc_kwargs = PyDict::new(py);
            sc_kwargs.set_item("dtype", &dtype)?;
            // 1-element array (not 0-d, which can't change itemsize on view) cast to dtype.
            let sc_arr = numpy.call_method("full", ((1usize,), scalar_obj), Some(&sc_kwargs))?;
            let sc_u = sc_arr.call_method1("view", (&un,))?;
            let Ok(sc_buf) = PyBuffer::<$U>::get(&sc_u) else {
                return Ok(None);
            };
            let Some(sc_in) = sc_buf.as_slice(py) else {
                return Ok(None);
            };
            if sc_in.len() != 1 {
                return Ok(None);
            }
            let scalar_u = sc_in[0].get();
            let out_kwargs = PyDict::new(py);
            out_kwargs.set_item("dtype", &dtype)?;
            let shape_tuple = PyTuple::new(py, arr_shape.iter().copied())?;
            let out = numpy.call_method("empty", (&shape_tuple,), Some(&out_kwargs))?;
            if n > 0 {
                let out_u = out.call_method1("view", (&un,))?;
                let Ok(out_buf) = PyBuffer::<$U>::get(&out_u) else {
                    return Ok(None);
                };
                let Some(out_cells) = out_buf.as_mut_slice(py) else {
                    return Ok(None);
                };
                for ((slot, cc), av) in out_cells
                    .iter()
                    .zip(cond_cells.iter())
                    .zip(arr_in.iter())
                {
                    // arr is x when scalar is y; arr is y when scalar is x.
                    let use_arr = (cc.get() != 0) != scalar_is_x;
                    slot.set(if use_arr { av.get() } else { scalar_u });
                }
            }
            return Ok(Some(out.unbind()));
        }};
    }
    match itemsize {
        1 => select_unsigned!(u8, "uint8"),
        2 => select_unsigned!(u16, "uint16"),
        4 => select_unsigned!(u32, "uint32"),
        8 => select_unsigned!(u64, "uint64"),
        _ => Ok(None),
    }
}

// Zero-copy np.select(condlist, choicelist, default) for the common all-float64
// form: K bool-ndarray conditions and K float64-ndarray choices, all of one
// identical shape, with a scalar default (numpy's default is 0). For each output
// element it walks the conditions in order and copies the first matching choice
// (verbatim — bit-identical incl. nan/inf/signed zeros), else the default. This
// is numpy.select's first-match-wins semantics in a single pass, replacing the
// chained where_select fold (K full-array passes + K intermediate Vecs) and the
// cold extract/build Vecs (bead lglck). The bool buffers' '?' format is rejected
// by PyBuffer::<u8>, so each condition is viewed as uint8 (bytes 0x00/0x01)
// first. Returns Ok(None) — caller falls through to the general path — for an
// empty/length-mismatched list, a non-scalar / non-float default, any non-bool
// condition, any non-f64 / shape-mismatched / non-ndarray choice, or a
// non-iterable condlist/choicelist.
fn try_zerocopy_f64_select(
    py: Python<'_>,
    condlist: &Bound<'_, PyAny>,
    choicelist: &Bound<'_, PyAny>,
    default: Option<&Py<PyAny>>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;

    let Ok(cond_iter) = condlist.try_iter() else {
        return Ok(None);
    };
    let cond_items: Vec<Bound<'_, PyAny>> = cond_iter.collect::<PyResult<Vec<_>>>()?;
    let Ok(choice_iter) = choicelist.try_iter() else {
        return Ok(None);
    };
    let choice_items: Vec<Bound<'_, PyAny>> = choice_iter.collect::<PyResult<Vec<_>>>()?;
    let k = cond_items.len();
    if k == 0 || k != choice_items.len() {
        return Ok(None);
    }

    // numpy's default is the scalar 0. A scalar float default, or an f64 ndarray
    // default of the same shape (no broadcast), keeps the fast path; broadcasting
    // array defaults are deferred to numpy.
    let mut default_scalar: f64 = 0.0;
    let default_buffer: Option<PyBuffer<f64>> = match default {
        None => None,
        Some(d) => {
            let bound = d.bind(py);
            if bound.is_none() {
                None
            } else if let Ok(value) = bound.extract::<f64>() {
                default_scalar = value;
                None
            } else if bound.is_exact_instance(&ndarray_type) && numpy_dtype_is_f64(py, bound) {
                match PyBuffer::<f64>::get(bound) {
                    Ok(buffer) => Some(buffer),
                    Err(_) => return Ok(None),
                }
            } else {
                return Ok(None);
            }
        }
    };

    let uint8 = numpy.getattr("uint8")?;
    let mut cond_buffers: Vec<PyBuffer<u8>> = Vec::with_capacity(k);
    let mut shape: Option<Vec<usize>> = None;
    for condition in &cond_items {
        if !condition.is_exact_instance(&ndarray_type) {
            return Ok(None);
        }
        if condition
            .getattr("dtype")?
            .getattr("kind")?
            .extract::<String>()?
            != "b"
        {
            return Ok(None);
        }
        let view = condition.call_method1("view", (&uint8,))?;
        let Ok(buffer) = PyBuffer::<u8>::get(&view) else {
            return Ok(None);
        };
        let this_shape = buffer.shape().to_vec();
        match &shape {
            None => shape = Some(this_shape),
            Some(existing) if *existing != this_shape => return Ok(None),
            _ => {}
        }
        cond_buffers.push(buffer);
    }
    let shape = shape.expect("k >= 1 guarantees a shape");

    let mut choice_buffers: Vec<PyBuffer<f64>> = Vec::with_capacity(k);
    for choice in &choice_items {
        if !choice.is_exact_instance(&ndarray_type) || !numpy_dtype_is_f64(py, choice) {
            return Ok(None);
        }
        let Ok(buffer) = PyBuffer::<f64>::get(choice) else {
            return Ok(None);
        };
        if buffer.shape() != shape.as_slice() {
            return Ok(None);
        }
        choice_buffers.push(buffer);
    }

    let mut cond_slices: Vec<&[pyo3::buffer::ReadOnlyCell<u8>]> = Vec::with_capacity(k);
    for buffer in &cond_buffers {
        let Some(slice) = buffer.as_slice(py) else {
            return Ok(None);
        };
        cond_slices.push(slice);
    }
    let mut choice_slices: Vec<&[pyo3::buffer::ReadOnlyCell<f64>]> = Vec::with_capacity(k);
    for buffer in &choice_buffers {
        let Some(slice) = buffer.as_slice(py) else {
            return Ok(None);
        };
        choice_slices.push(slice);
    }

    // An array default must match the common shape exactly (no broadcast).
    let default_slice: Option<&[pyo3::buffer::ReadOnlyCell<f64>]> = match &default_buffer {
        None => None,
        Some(buffer) => {
            if buffer.shape() != shape.as_slice() {
                return Ok(None);
            }
            match buffer.as_slice(py) {
                Some(slice) => Some(slice),
                None => return Ok(None),
            }
        }
    };

    let n = choice_slices[0].len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        for (i, slot) in output.iter().enumerate() {
            // First true condition wins (numpy.select picks the earliest match);
            // otherwise the per-element default (or scalar default).
            let mut value = match default_slice {
                Some(d) => d[i].get(),
                None => default_scalar,
            };
            for j in 0..k {
                if cond_slices[j][i].get() != 0 {
                    value = choice_slices[j][i].get();
                    break;
                }
            }
            slot.set(value);
        }
    }
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    if shape.is_empty() {
        return Ok(Some(output.bind(py).get_item(())?.unbind()));
    }
    Ok(Some(output))
}

// Zero-copy np.roll for the flatten form: a C-contiguous float64 ndarray rolled
// by a scalar shift with axis=None (numpy flattens, rolls, and reshapes back) or
// a 1-D array with axis in {0, -1} (equivalent to the flatten case). Every value
// is moved verbatim, so it is bit-identical (incl. nan/inf/signed zeros). With
// s = shift mod n, numpy's result is x[n-s..] ++ x[..n-s]; this writes those two
// runs straight into the output buffer with no intermediate Rust Vec, dropping
// the cold extract/build Vecs (bead lglck). Returns Ok(None) — caller falls
// through — for a per-axis roll on a multi-dim array, a tuple shift/axis, a
// non-int shift, or any non-f64 / non-contiguous / non-ndarray input.
fn try_zerocopy_f64_roll(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    shift: &Bound<'_, PyAny>,
    axis: Option<&Py<PyAny>>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let Ok(shift_scalar) = shift.extract::<i64>() else {
        return Ok(None);
    };
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    // Accept only the flatten-equivalent roll: axis=None (any ndim) or a 1-D
    // array with axis in {0, -1}. A per-axis roll on a multi-dim array moves
    // elements differently and is left to the general path.
    let ndim = in_buffer.shape().len();
    let flatten_ok = match axis {
        None => true,
        Some(value) => {
            let bound = value.bind(py);
            if bound.is_none() {
                true
            } else if let Ok(axis_int) = bound.extract::<i64>() {
                ndim == 1 && (axis_int == 0 || axis_int == -1)
            } else {
                return Ok(None);
            }
        }
    };
    if !flatten_ok {
        return Ok(None);
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = input.len();
    let out = numpy
        .getattr("empty_like")?
        .call1((a,))?;
    if n > 0 {
        // Normalize the shift into [0, n); result[i] = input[(i - shift) mod n],
        // i.e. result = input[n-s..] ++ input[..n-s].
        let s = (((shift_scalar % n as i64) + n as i64) % n as i64) as usize;
        let Ok(out_buffer) = PyBuffer::<f64>::get(&out) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        let split = n - s;
        // SAFETY: ReadOnlyCell<f64> and Cell<f64> are repr(transparent) over f64.
        // `flat` is a freshly allocated numpy.empty output, so it cannot alias the
        // input buffer. Both contiguous runs are moved verbatim, matching np.roll.
        let input_f64: &[f64] =
            unsafe { std::slice::from_raw_parts(input.as_ptr().cast::<f64>(), n) };
        let output_f64: &mut [f64] =
            unsafe { std::slice::from_raw_parts_mut(output.as_ptr() as *mut f64, n) };
        output_f64[..s].copy_from_slice(&input_f64[split..]);
        output_f64[s..].copy_from_slice(&input_f64[..split]);
    }
    Ok(Some(out.unbind()))
}

// Dtype-agnostic flatten roll (axis=None any ndim, or 1-D axis 0/-1) for any
// numeric/bool/complex dtype the f64 helper above does not handle. np.roll moves
// whole elements verbatim, so rolling the raw little-endian byte image by
// shift*itemsize bytes is bit-identical for every dtype. The data is viewed as
// 1-D uint8, the two contiguous runs are copied into a fresh uint8 buffer, then
// viewed back to the input dtype and reshaped — no extract Vec (which for ints
// is also lossy/crashes on wide values). Returns Ok(None) for a non-scalar
// shift, a per-axis multi-dim roll, or a non-ndarray input.
fn try_zerocopy_any_roll(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    shift: &Bound<'_, PyAny>,
    axis: Option<&Py<PyAny>>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let Ok(shift_scalar) = shift.extract::<i64>() else {
        return Ok(None);
    };
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len();
    if ndim == 0 {
        return Ok(None);
    }
    let flatten_ok = match axis {
        None => true,
        Some(value) => {
            let bound = value.bind(py);
            if bound.is_none() {
                true
            } else if let Ok(axis_int) = bound.extract::<i64>() {
                ndim == 1 && (axis_int == 0 || axis_int == -1)
            } else {
                return Ok(None);
            }
        }
    };
    if !flatten_ok {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    if itemsize == 0 {
        return Ok(None);
    }
    let n: usize = shape.iter().product();
    // 1-D uint8 view of the (C-order) data. reshape(-1) yields a contiguous view
    // (or ravel copy) whose byte image matches numpy's flatten order.
    let uint8 = numpy.getattr("uint8")?;
    let Ok(flat_in) = a.call_method1("reshape", (-1i64,)) else {
        return Ok(None);
    };
    let flat_in_u8 = flat_in.call_method1("view", (&uint8,))?;
    let Ok(in_buffer) = PyBuffer::<u8>::get(&flat_in_u8) else {
        return Ok(None);
    };
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let total_bytes = input.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "uint8")?;
    let out_u8 = numpy.call_method("empty", (total_bytes,), Some(&kwargs))?;
    if n > 0 {
        let s = (((shift_scalar % n as i64) + n as i64) % n as i64) as usize;
        let split_bytes = (n - s) * itemsize;
        let s_bytes = s * itemsize;
        let Ok(out_buffer) = PyBuffer::<u8>::get(&out_u8) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // result = input[split..] ++ input[..split], in bytes.
        // SAFETY: ReadOnlyCell<u8> and Cell<u8> are repr(transparent) over u8.
        // `out_u8` is freshly allocated and unaliased; roll copies raw element bytes.
        let input_u8: &[u8] =
            unsafe { std::slice::from_raw_parts(input.as_ptr().cast::<u8>(), total_bytes) };
        let output_u8: &mut [u8] =
            unsafe { std::slice::from_raw_parts_mut(output.as_ptr() as *mut u8, total_bytes) };
        output_u8[..s_bytes].copy_from_slice(&input_u8[split_bytes..]);
        output_u8[s_bytes..].copy_from_slice(&input_u8[..split_bytes]);
    }
    let out_typed = out_u8.call_method1("view", (&dtype,))?;
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = out_typed
        .call_method1("reshape", (&output_shape,))?
        .unbind();
    Ok(Some(output))
}

// Zero-copy np.roll(a, shift, axis=ax) along a single explicit axis of a
// C-contiguous float64 ndarray (the multi-dim case the flatten helper above
// leaves alone). Decomposing the C-contiguous layout into outer * axis_len *
// inner element groups, numpy's per-axis roll is out(o, a, i) = in(o, (a-s) mod
// axis_len, i): each (outer, inner) lane has its axis_len entries rotated by s.
// This copies the rotated inner-blocks straight into a numpy.empty buffer (then
// reshaped) with no intermediate Rust Vec, dropping the cold extract/build Vecs
// (bead lglck). Values are moved verbatim, so it is bit-identical incl.
// nan/inf/signed zeros. Returns Ok(None) — caller falls through — for a 0-d
// array, an out-of-range axis (numpy raises), or any non-f64 / non-contiguous /
// non-ndarray input.
fn try_zerocopy_f64_roll_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    shift_scalar: i64,
    axis: i64,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    let ndim = shape.len() as i64;
    if ndim == 0 {
        return Ok(None);
    }
    let norm_axis = if axis < 0 { axis + ndim } else { axis };
    if norm_axis < 0 || norm_axis >= ndim {
        // Out-of-range axis: let the general path reproduce numpy's AxisError.
        return Ok(None);
    }
    let ax = norm_axis as usize;
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let total = input.len();
    let axis_len = shape[ax];
    let outer: usize = shape[..ax].iter().product();
    let inner: usize = shape[ax + 1..].iter().product();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (total,), Some(&kwargs))?;
    if total > 0 && axis_len > 0 {
        let s = (((shift_scalar % axis_len as i64) + axis_len as i64) % axis_len as i64) as usize;
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // Each outer lane (length axis_len*inner, contiguous in C order) is just a
        // 1-D roll by s*inner positions: lane = in[lane_len - s*inner ..] ++
        // in[.. lane_len - s*inner]. Two sequential block copies per lane — far
        // faster than a strided per-element gather, and contiguous so it stays
        // bit-identical.
        let lane_len = axis_len * inner;
        let head = s * inner; // number of leading output elements
        let split = lane_len - head; // input prefix length that moves to the tail
        for o in 0..outer {
            let obase = o * lane_len;
            for k in 0..head {
                output[obase + k].set(input[obase + split + k].get());
            }
            for k in 0..split {
                output[obase + head + k].set(input[obase + k].get());
            }
        }
    }
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    Ok(Some(output))
}

// Dtype-agnostic per-axis np.roll (scalar shift, explicit integer axis) for the
// dtypes the f64 helper above does not handle — int (all widths), float32, bool,
// etc. Same insight as the f64 path: in C order each outer lane (axis_len*inner
// contiguous elements) is a flat roll by s*inner positions, i.e. two contiguous
// byte-runs of head*itemsize and split*itemsize bytes. np.roll moves elements
// verbatim, so rolling the raw byte image is bit-identical for any fixed-width
// dtype. Complex is excluded (its existing fallback already matches the byte
// copy — no regression). Returns None for a 0-d array, an out-of-range axis
// (numpy raises AxisError via the general path), or a non-ndarray input.
fn try_zerocopy_any_roll_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    shift_scalar: i64,
    axis: i64,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let a_dtype = a.getattr("dtype")?;
    // Complex already has an efficient fallback; skip it (and zero-itemsize).
    if a_dtype.getattr("kind")?.extract::<String>()? == "c" {
        return Ok(None);
    }
    let itemsize = a_dtype.getattr("itemsize")?.extract::<usize>()?;
    if itemsize == 0 {
        return Ok(None);
    }
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len() as i64;
    if ndim == 0 {
        return Ok(None);
    }
    let norm_axis = if axis < 0 { axis + ndim } else { axis };
    if norm_axis < 0 || norm_axis >= ndim {
        return Ok(None);
    }
    let ax = norm_axis as usize;
    let axis_len = shape[ax];
    let inner: usize = shape[ax + 1..].iter().product();
    let outer: usize = shape[..ax].iter().product();
    let uint8 = numpy.getattr("uint8")?;
    let Ok(a_flat) = a.call_method1("reshape", (-1i64,)) else {
        return Ok(None);
    };
    let a_u8 = a_flat.call_method1("view", (&uint8,))?;
    let Ok(in_buffer) = PyBuffer::<u8>::get(&a_u8) else {
        return Ok(None);
    };
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let total_bytes = input.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "uint8")?;
    let out_u8 = numpy.call_method("empty", (total_bytes,), Some(&kwargs))?;
    if total_bytes > 0 && axis_len > 0 {
        let s = (((shift_scalar % axis_len as i64) + axis_len as i64) % axis_len as i64) as usize;
        let Ok(out_buffer) = PyBuffer::<u8>::get(&out_u8) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // Per outer lane: a flat byte rotation by head bytes (two contiguous runs).
        let lane_bytes = axis_len * inner * itemsize;
        let head = s * inner * itemsize;
        let split = lane_bytes - head;
        for o in 0..outer {
            let obase = o * lane_bytes;
            for k in 0..head {
                output[obase + k].set(input[obase + split + k].get());
            }
            for k in 0..split {
                output[obase + head + k].set(input[obase + k].get());
            }
        }
    }
    let out_typed = out_u8.call_method1("view", (&a_dtype,))?;
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = out_typed.call_method1("reshape", (&output_shape,))?.unbind();
    Ok(Some(output))
}

// Zero-copy multi-axis np.roll for a 2-D C-contiguous float64 ndarray: a roll
// along independent axes (a tuple of shifts + matching axes) moves each element
// by the net shift on each axis simultaneously. This accumulates the net row and
// column shift, then rolls in a SINGLE pass / single allocation: each output row
// i is copied from source row (i - s_row) mod rows with a fused column roll (two
// contiguous segments) — far cheaper than composing per-axis rolls (which would
// allocate and copy the whole matrix once per axis). Values are moved verbatim,
// so it is bit-identical to numpy incl. nan/inf/signed zeros. Returns Ok(None) —
// caller falls through — for a non-2-D array, an out-of-range axis, or any non-f64
// / non-contiguous / non-ndarray input.
fn try_zerocopy_f64_roll_2d_multi(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    shifts: &[i64],
    axes: &[i64],
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) || !numpy_dtype_is_f64(py, a) {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    let shape = in_buffer.shape();
    if shape.len() != 2 {
        return Ok(None);
    }
    let rows = shape[0];
    let cols = shape[1];
    // Accumulate the net shift per axis (axes normalized into {0, 1}); any
    // out-of-range axis defers to the general path so numpy raises its AxisError.
    let mut s_row: i64 = 0;
    let mut s_col: i64 = 0;
    for (&sh, &ax) in shifts.iter().zip(axes.iter()) {
        let norm = if ax < 0 { ax + 2 } else { ax };
        match norm {
            0 => s_row += sh,
            1 => s_col += sh,
            _ => return Ok(None),
        }
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let out = numpy.call_method("empty", ((rows, cols),), Some(&kwargs))?;
    if rows > 0 && cols > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&out) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        let sr = (((s_row % rows as i64) + rows as i64) % rows as i64) as usize;
        let sc = (((s_col % cols as i64) + cols as i64) % cols as i64) as usize;
        // Each output row = input row[cols-sc..] ++ input row[..cols-sc].
        let split = cols - sc;
        for i in 0..rows {
            let src_row = (i + rows - sr) % rows;
            let in_base = src_row * cols;
            let out_base = i * cols;
            for j in 0..sc {
                output[out_base + j].set(input[in_base + split + j].get());
            }
            for j in 0..split {
                output[out_base + sc + j].set(input[in_base + j].get());
            }
        }
    }
    Ok(Some(out.unbind()))
}

// Zero-copy np.extract(condition, arr) for a bool condition ndarray and a float64
// arr ndarray of the same flattened length: returns the 1-D run of arr values at
// the positions where condition is True (numpy.extract == take(ravel(arr),
// nonzero(ravel(condition)))). Two passes over the buffers — count the selected
// elements, then gather them into a numpy.empty(count) output — with no
// intermediate Rust Vec, dropping the cold extract/build Vecs (bead lglck). The
// gathered values are copied verbatim, so the result is bit-identical incl.
// nan/inf/signed zeros. The bool buffer's '?' format is rejected by
// PyBuffer::<u8>, so condition is viewed as uint8 first. Returns Ok(None) —
// caller falls through — for a non-bool condition, a length mismatch, or any
// non-f64 / non-contiguous / non-ndarray input.
// Zero-copy np.compress(condition, a, axis=None) for a bool condition ndarray and
// a float64 a ndarray: numpy flattens a and returns a.flat[i] for the first
// len(condition) positions where condition is True (condition may be shorter than
// a; longer is an error left to numpy). Two passes over the buffers — count the
// selected elements among the first m=len(condition), then gather them into a
// numpy.empty(count) output — with no intermediate Rust Vec, dropping the cold
// extract/build Vecs (bead lglck). Gathered values are copied verbatim, so the
// result is bit-identical incl. nan/inf/signed zeros. Returns Ok(None) — caller
// falls through — for a per-axis compress (axis given), a non-bool condition, a
// condition longer than a, or any non-f64 / non-contiguous / non-ndarray input.
fn try_zerocopy_f64_compress(
    py: Python<'_>,
    condition: &Bound<'_, PyAny>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
) -> PyResult<Option<Py<PyAny>>> {
    if axis.is_some() {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) || !condition.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    if condition
        .getattr("dtype")?
        .getattr("kind")?
        .extract::<String>()?
        != "b"
    {
        return Ok(None);
    }
    let cond_u8 = condition.call_method1("view", (numpy.getattr("uint8")?,))?;
    let (Ok(cond_buffer), Ok(arr_buffer)) =
        (PyBuffer::<u8>::get(&cond_u8), PyBuffer::<f64>::get(a))
    else {
        return Ok(None);
    };
    let (Some(cond_in), Some(arr_in)) = (cond_buffer.as_slice(py), arr_buffer.as_slice(py)) else {
        return Ok(None);
    };
    // numpy.compress only inspects the first len(condition) flattened elements and
    // errors if the condition is longer than the array; defer that error to numpy.
    let m = cond_in.len();
    if m > arr_in.len() {
        return Ok(None);
    }
    let count = count_true_u8_prefix(cond_in, m);
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (count,), Some(&kwargs))?;
    if count > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        let mut w = 0usize;
        for (cond_cell, arr_cell) in cond_in.iter().zip(arr_in.iter()) {
            if cond_cell.get() != 0 {
                output[w].set(arr_cell.get());
                w += 1;
            }
        }
    }
    Ok(Some(flat.unbind()))
}

// Zero-copy np.compress(condition, a, axis=k) for a C-contiguous float64 ndarray:
// select the slabs along `axis` where `condition` is True, in order. The slab at
// index j (a[.., j, ..]) is `inner` contiguous f64, so each kept slab is a
// contiguous block copy off the borrowed buffer into numpy.empty — no whole-array
// extract, no native rebuild. Elements move verbatim, so the result is
// bit-identical to numpy.compress. Defers (returns None) for non-f64, bool, a
// condition longer than the axis (numpy errors), non-contiguous, or non-ndarray.
fn try_zerocopy_f64_compress_axis(
    py: Python<'_>,
    condition: &Bound<'_, PyAny>,
    a: &Bound<'_, PyAny>,
    axis: isize,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) || !condition.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let a_dtype = a.getattr("dtype")?;
    if a_dtype.getattr("kind")?.extract::<String>()? != "f"
        || a_dtype.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    if condition.getattr("dtype")?.getattr("kind")?.extract::<String>()? != "b" {
        return Ok(None);
    }
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len() as isize;
    let ax = if axis < 0 { axis + ndim } else { axis };
    if ax < 0 || ax >= ndim {
        return Ok(None);
    }
    let ax = ax as usize;
    let axis_len = shape[ax];
    let Ok(arr_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    if !arr_buffer.is_c_contiguous() {
        return Ok(None);
    }
    let cond_u8 = condition.call_method1("view", (numpy.getattr("uint8")?,))?;
    let (Ok(cond_buffer), Some(arr_in)) = (PyBuffer::<u8>::get(&cond_u8), arr_buffer.as_slice(py))
    else {
        return Ok(None);
    };
    let Some(cond_in) = cond_buffer.as_slice(py) else {
        return Ok(None);
    };
    let m = cond_in.len();
    if m > axis_len {
        return Ok(None); // numpy raises when condition is longer than the axis; defer
    }
    // Selected indices along the axis, in order (positions m..axis_len are dropped).
    let sel: Vec<usize> = (0..m).filter(|&j| cond_in[j].get() != 0).collect();
    let count = sel.len();
    let outer: usize = shape[..ax].iter().product();
    let inner: usize = shape[ax + 1..].iter().product();
    let mut out_shape = shape.clone();
    out_shape[ax] = count;
    let out_elems = outer * count * inner;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (out_elems,), Some(&kwargs))?;
    if out_elems > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        let in_lane = axis_len * inner;
        let out_lane = count * inner;
        // Each kept slab is a contiguous `inner`-element block (a full row for
        // axis 0). Sequential-write + gather of the selected blocks; the contiguous
        // inner copy autovectorizes. (A branchless per-row store-advance was tried
        // for the last axis but regressed — its data-dependent write index does not
        // vectorize for f64.)
        for o in 0..outer {
            let in_base = o * in_lane;
            let out_base = o * out_lane;
            for (si, &j) in sel.iter().enumerate() {
                let src = &arr_in[in_base + j * inner..in_base + j * inner + inner];
                let dst = &output[out_base + si * inner..out_base + si * inner + inner];
                for (d, s) in dst.iter().zip(src) {
                    d.set(s.get());
                }
            }
        }
    }
    let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
    Ok(Some(flat.call_method1("reshape", (&output_shape,))?.unbind()))
}

// Generic typed core for boolean-mask stream compaction (np.compress / np.extract
// flat case). Counts the True positions in the first `cond.len()` elements (must
// be <= arr length), then gathers arr[i] (read as `T`) where cond[i] into a fresh
// `dtype_name` buffer — one typed element-move per kept element. (A byte-per-
// element copy would not vectorize; whole-element typed moves stay near numpy.)
// Returns the 1-D output (compress/extract are flat).
fn compact_typed<'py, T: pyo3::buffer::Element + Copy>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    cond: &Bound<'py, PyAny>,
    arr_src: &Bound<'py, PyAny>,
    dtype_name: &str,
) -> PyResult<Option<Py<PyAny>>> {
    let cond_u8 = cond.call_method1("view", (numpy.getattr("uint8")?,))?;
    let (Ok(cond_buffer), Ok(arr_buffer)) =
        (PyBuffer::<u8>::get(&cond_u8), PyBuffer::<T>::get(arr_src))
    else {
        return Ok(None);
    };
    let (Some(cond_in), Some(arr_in)) = (cond_buffer.as_slice(py), arr_buffer.as_slice(py)) else {
        return Ok(None);
    };
    let m = cond_in.len();
    if m > arr_in.len() {
        return Ok(None);
    }
    let count = cond_in.iter().filter(|cell| cell.get() != 0).count();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", dtype_name)?;
    let flat = numpy.call_method("empty", (count,), Some(&kwargs))?;
    if count > 0 {
        let Ok(out_buffer) = PyBuffer::<T>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // Build a mask per condition chunk, then gather only selected
        // lanes with trailing-zero iteration. This avoids both per-element branch
        // mispredicts and speculative stores for unkept lanes.
        let mut w = 0usize;
        let mut base = 0usize;
        while base + 16 <= m {
            let mut mask = 0u16;
            for lane in 0..16 {
                mask |= ((cond_in[base + lane].get() != 0) as u16) << lane;
            }
            while mask != 0 {
                let lane = mask.trailing_zeros() as usize;
                output[w].set(arr_in[base + lane].get());
                w += 1;
                mask &= mask - 1;
            }
            base += 16;
        }
        for i in base..m {
            if cond_in[i].get() != 0 {
                output[w].set(arr_in[i].get());
                w += 1;
            }
        }
    }
    Ok(Some(flat.unbind()))
}

fn count_true_u8_prefix(cond: &[pyo3::buffer::ReadOnlyCell<u8>], len: usize) -> usize {
    let mut count = 0usize;
    let mut base = 0usize;
    while base + 16 <= len {
        let mut mask = 0u16;
        for lane in 0..16 {
            mask |= ((cond[base + lane].get() != 0) as u16) << lane;
        }
        count += mask.count_ones() as usize;
        base += 16;
    }
    for cell in cond.iter().take(len).skip(base) {
        count += (cell.get() != 0) as usize;
    }
    count
}

// Dispatch a branchless compaction for every fixed-width numeric dtype (all 8
// integer widths, float32/float64, bool). compress/extract move whole elements
// verbatim by mask, so the move is value-agnostic: we VIEW the array as the
// same-width unsigned integer, compact that, then view the result back to the
// input dtype. This is bit-identical (incl. nan/inf/signed zeros), preserves the
// dtype, and reuses a single per-width unsigned `compact_typed` instantiation
// (u8/u16/u32/u64) for every kind — so int64/uint64/float64 share the same hot
// code with no extra monomorphizations, while narrow ints/float32 (previously
// widened through f64 by the cold extract path, 24x slower) get the fast path
// too. complex keeps its existing fast path (returns None for itemsize 16).
// Returns None for non-ndarray operands or non-bool conditions.
fn try_zerocopy_any_compact(
    py: Python<'_>,
    cond: &Bound<'_, PyAny>,
    arr: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !arr.is_exact_instance(&ndarray_type) || !cond.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    if cond.getattr("dtype")?.getattr("kind")?.extract::<String>()? != "b" {
        return Ok(None);
    }
    let a_dtype = arr.getattr("dtype")?;
    let kind = a_dtype.getattr("kind")?.extract::<String>()?;
    // Only fixed-width int/uint/float/bool; complex (kind 'c') and anything else
    // keep their existing fast paths.
    if !matches!(kind.as_str(), "i" | "u" | "f" | "b") {
        return Ok(None);
    }
    let itemsize = a_dtype.getattr("itemsize")?.extract::<usize>()?;
    // Compact the array through its same-width unsigned-integer view, then view
    // the compacted result back to the original dtype.
    let compacted = match itemsize {
        1 => {
            let v = arr.call_method1("view", (numpy.getattr("uint8")?,))?;
            compact_typed::<u8>(py, &numpy, cond, &v, "uint8")?
        }
        2 => {
            let v = arr.call_method1("view", (numpy.getattr("uint16")?,))?;
            compact_typed::<u16>(py, &numpy, cond, &v, "uint16")?
        }
        4 => {
            let v = arr.call_method1("view", (numpy.getattr("uint32")?,))?;
            compact_typed::<u32>(py, &numpy, cond, &v, "uint32")?
        }
        8 => {
            let v = arr.call_method1("view", (numpy.getattr("uint64")?,))?;
            compact_typed::<u64>(py, &numpy, cond, &v, "uint64")?
        }
        _ => return Ok(None),
    };
    match compacted {
        Some(flat) => Ok(Some(
            flat.bind(py).call_method1("view", (&a_dtype,))?.unbind(),
        )),
        None => Ok(None),
    }
}

// Zero-copy np.take(a, indices, axis=None, mode="raise") for a float64 a ndarray
// and an int64 indices ndarray: numpy flattens a and gathers a.flat[idx] for each
// index (with numpy's negative-index wraparound idx += n), returning a result of
// the indices' shape. A first pass validates every index against [-n, n); if any
// is out of range this returns Ok(None) so the caller's general path reproduces
// numpy's exact IndexError. Otherwise a second pass gathers the values into a
// numpy.empty(indices.size) buffer (then reshaped), with no intermediate Rust
// Vec, dropping the cold extract/build Vecs (bead lglck). Values are copied
// verbatim, so the result is bit-identical incl. nan/inf/signed zeros. Returns
// Ok(None) — caller falls through — for a per-axis take, a non-"raise" mode, a
// non-int64 index array, or any non-f64 / non-contiguous / non-ndarray input.
fn try_zerocopy_f64_take(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    indices: &Bound<'_, PyAny>,
    axis: Option<isize>,
    mode: &str,
) -> PyResult<Option<Py<PyAny>>> {
    if axis.is_some() || mode != "raise" {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) || !indices.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    // indices must be a signed 64-bit integer ndarray (numpy's default index
    // width on 64-bit); other widths/kinds keep the general path.
    {
        let dtype = indices.getattr("dtype")?;
        if dtype.getattr("kind")?.extract::<String>()? != "i"
            || dtype.getattr("itemsize")?.extract::<usize>()? != 8
        {
            return Ok(None);
        }
    }
    let (Ok(a_buffer), Ok(idx_buffer)) = (PyBuffer::<f64>::get(a), PyBuffer::<i64>::get(indices))
    else {
        return Ok(None);
    };
    let (Some(a_in), Some(idx_in)) = (a_buffer.as_slice(py), idx_buffer.as_slice(py)) else {
        return Ok(None);
    };
    let n = a_in.len() as i64;
    let out_shape: Vec<usize> = idx_buffer.shape().to_vec();
    let count = idx_in.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (count,), Some(&kwargs))?;
    if count > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // Fused validate-and-gather in one pass over the index stream (no
        // intermediate index Vec). numpy's negative-index wraparound is idx += n;
        // an out-of-range index bails to the general path — the partially written
        // output buffer is simply dropped (take has no side effects) and numpy
        // reproduces the exact IndexError. take never reorders within a lane, so
        // gathering verbatim is bit-identical.
        for (slot, idx_cell) in output.iter().zip(idx_in.iter()) {
            let mut idx = idx_cell.get();
            if idx < 0 {
                idx += n;
            }
            if idx < 0 || idx >= n {
                return Ok(None);
            }
            slot.set(a_in[idx as usize].get());
        }
    }
    let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    if out_shape.is_empty() {
        return Ok(Some(output.bind(py).get_item(())?.unbind()));
    }
    Ok(Some(output))
}

// Generic typed core for the flat gather (np.take, axis=None, mode="raise"):
// one element-move per index (NOT a byte loop — a per-element itemsize-byte copy
// does not vectorize and leaves the gather far behind numpy). Reads `src` as a
// `T` buffer and the int64 index stream, validating each index (negative-
// wraparound idx += n; out-of-range -> None so numpy reproduces the IndexError),
// and gathers verbatim into a fresh `dtype_name` buffer. Returns the flat output
// plus the indices' shape.
fn take_typed<'py, T: pyo3::buffer::Element + Copy>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    src: &Bound<'py, PyAny>,
    indices: &Bound<'py, PyAny>,
    dtype_name: &str,
) -> PyResult<Option<(Bound<'py, PyAny>, Vec<usize>)>> {
    let (Ok(a_buffer), Ok(idx_buffer)) = (PyBuffer::<T>::get(src), PyBuffer::<i64>::get(indices))
    else {
        return Ok(None);
    };
    let (Some(a_in), Some(idx_in)) = (a_buffer.as_slice(py), idx_buffer.as_slice(py)) else {
        return Ok(None);
    };
    let n = a_in.len() as i64;
    let out_shape: Vec<usize> = idx_buffer.shape().to_vec();
    let count = idx_in.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", dtype_name)?;
    let flat = numpy.call_method("empty", (count,), Some(&kwargs))?;
    if count > 0 {
        let Ok(out_buffer) = PyBuffer::<T>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        for (slot, idx_cell) in output.iter().zip(idx_in.iter()) {
            let mut idx = idx_cell.get();
            if idx < 0 {
                idx += n;
            }
            if idx < 0 || idx >= n {
                return Ok(None);
            }
            slot.set(a_in[idx as usize].get());
        }
    }
    Ok(Some((flat, out_shape)))
}

// Per-axis gather core for np.take(a, idx, axis=ax). Unlike take_along_axis the
// index list is SHARED across every outer/inner position (broadcast), so the same
// flat idx array gathers a contiguous inner-block per (outer, idx) pair. Output is
// outer * count * inner elements; each block of `inner` is copied with a
// subslice+zip (the contiguous-block-copy pattern that memcpy-vectorizes — for
// inner==1 it degrades to a single typed move, the correct form for a scattered
// last-axis gather). OOB/negative-after-wrap indices return None so numpy raises
// IndexError. T is the uintN bit-mover chosen by itemsize, so one core covers
// int/uint/float/bool verbatim.
#[allow(clippy::too_many_arguments)]
fn take_axis_typed<'py, T: pyo3::buffer::Element + Copy>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    arr_u: &Bound<'py, PyAny>,
    idx_in: &[pyo3::buffer::ReadOnlyCell<i64>],
    out_dtype_name: &str,
    outer: usize,
    la: usize,
    inner: usize,
) -> PyResult<Option<Bound<'py, PyAny>>> {
    let Ok(arr_buf) = PyBuffer::<T>::get(arr_u) else {
        return Ok(None);
    };
    let Some(arr_s) = arr_buf.as_slice(py) else {
        return Ok(None);
    };
    let count = idx_in.len();
    let total_out = outer * count * inner;
    // Resolve + bounds-check each index ONCE, up front. The previous loop re-ran the
    // negative-wrap and OOB check for every outer slab, so an axis=last gather (inner=1,
    // e.g. np.take(NxN, idx, axis=1)) validated `outer * count` times — N× redundant —
    // making the column gather ~2.7x slower than numpy. Resolving once leaves only the
    // raw element moves in the hot loop. Any OOB index still defers to numpy (None) so
    // the exact IndexError surfaces, identical to before.
    let la_i = la as i64;
    let mut resolved = Vec::with_capacity(count);
    for idx_cell in idx_in.iter() {
        let mut k = idx_cell.get();
        if k < 0 {
            k += la_i;
        }
        if k < 0 || k >= la_i {
            return Ok(None); // OOB → defer to numpy for exact IndexError
        }
        resolved.push(k as usize);
    }
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", out_dtype_name)?;
    let flat = numpy.call_method("empty", (total_out,), Some(&kwargs))?;
    if total_out > 0 {
        let Ok(out_buffer) = PyBuffer::<T>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        if inner == 1 {
            // Scalar gather (axis is the last axis): out[o*count + j] = arr[o*la + k_j].
            // Specialized so the destination side iterates without per-element slice
            // bounds checks; only the gather read indexes randomly.
            for o in 0..outer {
                let abase = o * la;
                let obase = o * count;
                for (dst, &k) in output[obase..obase + count].iter().zip(resolved.iter()) {
                    dst.set(arr_s[abase + k].get());
                }
            }
        } else {
            for o in 0..outer {
                let abase = o * la * inner;
                let obase = o * count * inner;
                for (j, &k) in resolved.iter().enumerate() {
                    let sbase = abase + k * inner;
                    let dbase = obase + j * inner;
                    for (dst, src) in output[dbase..dbase + inner]
                        .iter()
                        .zip(arr_s[sbase..sbase + inner].iter())
                    {
                        dst.set(src.get());
                    }
                }
            }
        }
    }
    Ok(Some(flat))
}

// Zero-copy np.take with an explicit axis for the gated dtypes (bool/int64/uint64/
// float64) — the per-axis case the flat helpers skip, currently routed through the
// cold extract→ndarray.take path (30-100x slower than numpy). numpy moves whole
// elements, so the gather runs on a uintN bit-view chosen by itemsize and is
// viewed back. Gated to: axis=Some, mode="raise", both ndarrays, an int64 index
// array, and a C-contiguous source; non-contiguous/OOB inputs defer to numpy.
fn try_zerocopy_take_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    indices: &Bound<'_, PyAny>,
    axis: Option<isize>,
    mode: &str,
) -> PyResult<Option<Py<PyAny>>> {
    let Some(axis) = axis else {
        return Ok(None);
    };
    if mode != "raise" {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) || !indices.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    {
        let dtype = indices.getattr("dtype")?;
        if dtype.getattr("kind")?.extract::<String>()? != "i"
            || dtype.getattr("itemsize")?.extract::<usize>()? != 8
        {
            return Ok(None);
        }
    }
    if !a
        .getattr("flags")?
        .getattr("c_contiguous")?
        .extract::<bool>()?
    {
        return Ok(None); // non-contiguous source: as_slice would be in wrong order
    }
    let a_dtype = a.getattr("dtype")?;
    let kind = a_dtype.getattr("kind")?.extract::<String>()?;
    let itemsize = a_dtype.getattr("itemsize")?.extract::<usize>()?;
    let s_arr: Vec<usize> = a.getattr("shape")?.extract()?;
    let d = s_arr.len();
    if d == 0 {
        return Ok(None);
    }
    let ax = if axis < 0 { axis + d as isize } else { axis };
    if ax < 0 || ax >= d as isize {
        return Ok(None); // out-of-range axis → defer for numpy AxisError
    }
    let ax = ax as usize;
    let la = s_arr[ax];
    let outer: usize = s_arr[..ax].iter().product();
    let inner: usize = s_arr[ax + 1..].iter().product();
    let s_idx: Vec<usize> = indices.getattr("shape")?.extract()?;
    let Ok(idx_buf) = PyBuffer::<i64>::get(indices) else {
        return Ok(None);
    };
    let Some(idx_in) = idx_buf.as_slice(py) else {
        return Ok(None);
    };
    let mover_name = match itemsize {
        1 => "uint8",
        2 => "uint16",
        4 => "uint32",
        8 => "uint64",
        _ => return Ok(None),
    };
    let orig_name = a_dtype.getattr("name")?.extract::<String>()?;
    let arr_u = a.call_method1("view", (numpy.getattr(mover_name)?,))?;
    let flat = match itemsize {
        1 => take_axis_typed::<u8>(py, &numpy, &arr_u, idx_in, "uint8", outer, la, inner)?,
        2 => take_axis_typed::<u16>(py, &numpy, &arr_u, idx_in, "uint16", outer, la, inner)?,
        4 => take_axis_typed::<u32>(py, &numpy, &arr_u, idx_in, "uint32", outer, la, inner)?,
        _ => take_axis_typed::<u64>(py, &numpy, &arr_u, idx_in, "uint64", outer, la, inner)?,
    };
    let Some(flat) = flat else {
        return Ok(None);
    };
    let _ = kind;
    let restored = flat.call_method1("view", (numpy.getattr(orig_name.as_str())?,))?;
    // out shape = a.shape[:ax] + indices.shape + a.shape[ax+1:]
    let mut out_shape: Vec<usize> = s_arr[..ax].to_vec();
    out_shape.extend_from_slice(&s_idx);
    out_shape.extend_from_slice(&s_arr[ax + 1..]);
    let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
    Ok(Some(
        restored.call_method1("reshape", (&output_shape,))?.unbind(),
    ))
}

// Zero-copy flat gather for the non-f64 gated dtypes the f64 helper leaves to the
// cold extract path: int64/uint64 (~39x slower, lossy for wide ints) and bool.
// One element-move per index, bit-identical to numpy. Bool is gathered through a
// uint8 view and returned as bool. Returns None for a non-int64 index array, a
// per-axis take, or a non-ndarray operand.
fn try_zerocopy_int_take(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    indices: &Bound<'_, PyAny>,
    axis: Option<isize>,
    mode: &str,
) -> PyResult<Option<Py<PyAny>>> {
    if axis.is_some() || mode != "raise" {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) || !indices.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    {
        let dtype = indices.getattr("dtype")?;
        if dtype.getattr("kind")?.extract::<String>()? != "i"
            || dtype.getattr("itemsize")?.extract::<usize>()? != 8
        {
            return Ok(None);
        }
    }
    let a_dtype = a.getattr("dtype")?;
    let kind = a_dtype.getattr("kind")?.extract::<String>()?;
    let itemsize = a_dtype.getattr("itemsize")?.extract::<usize>()?;
    let (flat, out_shape) = match (kind.as_str(), itemsize) {
        ("i", 8) => match take_typed::<i64>(py, &numpy, a, indices, "int64")? {
            Some(r) => r,
            None => return Ok(None),
        },
        ("u", 8) => match take_typed::<u64>(py, &numpy, a, indices, "uint64")? {
            Some(r) => r,
            None => return Ok(None),
        },
        ("b", 1) => {
            let a_u8 = a.call_method1("view", (numpy.getattr("uint8")?,))?;
            match take_typed::<u8>(py, &numpy, &a_u8, indices, "uint8")? {
                Some((flat_u8, shape)) => {
                    let flat_bool = flat_u8.call_method1("view", (numpy.getattr("bool_")?,))?;
                    (flat_bool, shape)
                }
                None => return Ok(None),
            }
        }
        _ => return Ok(None),
    };
    let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    if out_shape.is_empty() {
        return Ok(Some(output.bind(py).get_item(())?.unbind()));
    }
    Ok(Some(output))
}

// Zero-copy in-place np.putmask(a, mask, values) for a writable float64 a ndarray,
// a bool mask of the identical shape, and a non-empty float64 values ndarray.
// numpy sets a.flat[i] = values.flat[i % values.size] at every flat position i
// where mask is True; this writes those positions straight into a's own buffer
// (no extract of a/values and no full copy-back — only the masked slots are
// touched), dropping the cold boundary-tax Vecs (bead lglck). Values are copied
// verbatim, so the mutation is bit-identical incl. -0.0/inf/nan. The bool mask's
// '?' format is rejected by PyBuffer::<u8>, so it is viewed as uint8 first.
// Returns Ok(false) — caller falls through to the general path — for a shape
// mismatch, an empty values array (numpy raises), a read-only a, or any non-f64 /
// non-bool / non-contiguous / non-ndarray operand.
fn try_zerocopy_f64_putmask(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    mask: &Bound<'_, PyAny>,
    values: &Bound<'_, PyAny>,
) -> PyResult<bool> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type)
        || !mask.is_exact_instance(&ndarray_type)
        || !values.is_exact_instance(&ndarray_type)
    {
        return Ok(false);
    }
    if mask
        .getattr("dtype")?
        .getattr("kind")?
        .extract::<String>()?
        != "b"
        || !numpy_dtype_is_f64(py, a)
        || !numpy_dtype_is_f64(py, values)
    {
        return Ok(false);
    }
    let mask_u8 = mask.call_method1("view", (numpy.getattr("uint8")?,))?;
    let (Ok(a_buffer), Ok(mask_buffer), Ok(val_buffer)) = (
        PyBuffer::<f64>::get(a),
        PyBuffer::<u8>::get(&mask_u8),
        PyBuffer::<f64>::get(values),
    ) else {
        return Ok(false);
    };
    // numpy.putmask requires a and mask to share a shape; require an exact match
    // (no broadcasting) so the flat index aligns.
    if a_buffer.shape() != mask_buffer.shape() {
        return Ok(false);
    }
    let (Some(mask_in), Some(val_in)) = (mask_buffer.as_slice(py), val_buffer.as_slice(py)) else {
        return Ok(false);
    };
    let v = val_in.len();
    if v == 0 {
        // numpy raises ValueError("Cannot insert from an empty object"); defer.
        return Ok(false);
    }
    let Some(a_out) = a_buffer.as_mut_slice(py) else {
        return Ok(false);
    };
    let n = a_out.len();
    // numpy.putmask cycles `values` by FLAT position (`values[i % v]`), NOT by masked-count, so
    // every output slot is independent — embarrassingly parallel. Scatter into a's own buffer
    // over disjoint raw-slice chunks (in-place, no copy-back); numpy runs this single-threaded.
    // SAFETY: ReadOnlyCell<u8/f64>/Cell<f64> are repr(transparent); read-only mask/values under
    // the GIL, a's buffer written only at disjoint, non-overlapping chunk positions.
    let a_slice: &mut [f64] = unsafe { std::slice::from_raw_parts_mut(a_out.as_ptr() as *mut f64, n) };
    let m: &[u8] = unsafe { std::slice::from_raw_parts(mask_in.as_ptr().cast::<u8>(), n) };
    let vals: &[f64] = unsafe { std::slice::from_raw_parts(val_in.as_ptr().cast::<f64>(), v) };
    const PUTMASK_PARALLEL_MIN: usize = 1 << 19;
    if n >= PUTMASK_PARALLEL_MIN && rayon::current_num_threads() >= 2 {
        use rayon::prelude::*;
        let chunk = n.div_ceil(rayon::current_num_threads());
        a_slice
            .par_chunks_mut(chunk)
            .enumerate()
            .for_each(|(ci, ac)| {
                let base = ci * chunk;
                for (j, slot) in ac.iter_mut().enumerate() {
                    let i = base + j;
                    if m[i] != 0 {
                        *slot = vals[i % v];
                    }
                }
            });
    } else {
        for (i, slot) in a_slice.iter_mut().enumerate() {
            if m[i] != 0 {
                *slot = vals[i % v];
            }
        }
    }
    Ok(true)
}

// Generic in-place masked scatter for np.putmask over an unsigned-integer view of
// the writable array and the values array (both already viewed as the same width
// `T`). numpy.putmask sets a.flat[i] = values.flat[i % values.size] for every i
// where mask.flat[i] is True, so the move is value-agnostic — a same-width typed
// store is bit-identical (incl. nan/inf/signed zeros) and mutates a's own buffer.
// Returns Ok(false) — caller falls through — on a shape mismatch, empty values, a
// read-only/non-contiguous array, or a buffer-protocol failure.
fn putmask_scatter_typed<T: pyo3::buffer::Element + Copy>(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    mask: &Bound<'_, PyAny>,
    a_view: &Bound<'_, PyAny>,
    val_view: &Bound<'_, PyAny>,
) -> PyResult<bool> {
    let mask_u8 = mask.call_method1("view", (numpy.getattr("uint8")?,))?;
    let (Ok(a_buffer), Ok(mask_buffer), Ok(val_buffer)) = (
        PyBuffer::<T>::get(a_view),
        PyBuffer::<u8>::get(&mask_u8),
        PyBuffer::<T>::get(val_view),
    ) else {
        return Ok(false);
    };
    if a_buffer.shape() != mask_buffer.shape() {
        return Ok(false);
    }
    let (Some(mask_in), Some(val_in)) = (mask_buffer.as_slice(py), val_buffer.as_slice(py)) else {
        return Ok(false);
    };
    let v = val_in.len();
    if v == 0 {
        return Ok(false);
    }
    let Some(a_out) = a_buffer.as_mut_slice(py) else {
        return Ok(false);
    };
    // numpy cycles values by flat position (a.flat[i] = values.flat[i % v]); track
    // the wrapped index with a counter+reset instead of a per-element modulo. When
    // values spans the array (v >= len, the overwhelmingly common a-shaped values
    // and scalar-broadcast cases) the index never wraps — a plain zip with no
    // bookkeeping, which autovectorizes the masked store.
    if v >= mask_in.len() {
        for (slot, (mask_cell, val_cell)) in a_out.iter().zip(mask_in.iter().zip(val_in.iter())) {
            if mask_cell.get() != 0 {
                slot.set(val_cell.get());
            }
        }
    } else {
        let mut vi = 0usize;
        for (slot, mask_cell) in a_out.iter().zip(mask_in.iter()) {
            if mask_cell.get() != 0 {
                slot.set(val_in[vi].get());
            }
            vi += 1;
            if vi == v {
                vi = 0;
            }
        }
    }
    Ok(true)
}

// All-width zero-copy np.putmask: the f64 helper covers only float64, leaving
// narrow ints, int64/uint64, float32 and bool on the cold extract path that
// widens through f64 (24x slower for narrow ints). putmask moves elements
// verbatim by mask, so dispatch by itemsize through a same-width UNSIGNED view of
// both the array and the values (the array view aliases its own buffer, so the
// scatter is in-place). Requires a and values to share an identical dtype (numpy
// otherwise casts values — deferred to the fallback) and a bool mask. complex
// (itemsize 16) and mismatched/unsupported dtypes return Ok(false).
fn try_zerocopy_any_putmask(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    mask: &Bound<'_, PyAny>,
    values: &Bound<'_, PyAny>,
) -> PyResult<bool> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type)
        || !mask.is_exact_instance(&ndarray_type)
        || !values.is_exact_instance(&ndarray_type)
    {
        return Ok(false);
    }
    if mask.getattr("dtype")?.getattr("kind")?.extract::<String>()? != "b" {
        return Ok(false);
    }
    let a_dtype = a.getattr("dtype")?;
    let kind = a_dtype.getattr("kind")?.extract::<String>()?;
    if !matches!(kind.as_str(), "i" | "u" | "f" | "b") {
        return Ok(false);
    }
    // numpy casts values to a's dtype; only an identical dtype is a verbatim move.
    if !a_dtype.eq(values.getattr("dtype")?)? {
        return Ok(false);
    }
    let itemsize = a_dtype.getattr("itemsize")?.extract::<usize>()?;
    let uname = match itemsize {
        1 => "uint8",
        2 => "uint16",
        4 => "uint32",
        8 => "uint64",
        _ => return Ok(false),
    };
    let uview = numpy.getattr(uname)?;
    let a_u = a.call_method1("view", (&uview,))?;
    let v_u = values.call_method1("view", (&uview,))?;
    match itemsize {
        1 => putmask_scatter_typed::<u8>(py, &numpy, mask, &a_u, &v_u),
        2 => putmask_scatter_typed::<u16>(py, &numpy, mask, &a_u, &v_u),
        4 => putmask_scatter_typed::<u32>(py, &numpy, mask, &a_u, &v_u),
        8 => putmask_scatter_typed::<u64>(py, &numpy, mask, &a_u, &v_u),
        _ => Ok(false),
    }
}

// Generic in-place masked scatter for np.place over an unsigned-integer view of
// the writable array and the values array (both already viewed as the same width
// `T`). numpy.place assigns the True positions in flat order, the k-th True taking
// values.flat[k % values.size] — it cycles values by the RUNNING True count
// (unlike putmask, which cycles by flat position). The move is value-agnostic, so
// a same-width typed store is bit-identical (incl. nan/inf/signed zeros) and
// mutates arr's own buffer. The wrapped index is tracked with a counter+reset
// instead of a per-element modulo (the reset never fires when v >= the number of
// True positions). Returns Ok(false) on shape mismatch, empty values, a read-only/
// non-contiguous array, or a buffer-protocol failure.
fn place_scatter_typed<T: pyo3::buffer::Element + Copy>(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    mask: &Bound<'_, PyAny>,
    a_view: &Bound<'_, PyAny>,
    val_view: &Bound<'_, PyAny>,
) -> PyResult<bool> {
    let mask_u8 = mask.call_method1("view", (numpy.getattr("uint8")?,))?;
    let (Ok(a_buffer), Ok(mask_buffer), Ok(val_buffer)) = (
        PyBuffer::<T>::get(a_view),
        PyBuffer::<u8>::get(&mask_u8),
        PyBuffer::<T>::get(val_view),
    ) else {
        return Ok(false);
    };
    if a_buffer.shape() != mask_buffer.shape() {
        return Ok(false);
    }
    let (Some(mask_in), Some(val_in)) = (mask_buffer.as_slice(py), val_buffer.as_slice(py)) else {
        return Ok(false);
    };
    let v = val_in.len();
    if v == 0 {
        return Ok(false);
    }
    let Some(a_out) = a_buffer.as_mut_slice(py) else {
        return Ok(false);
    };
    let mut k = 0usize;
    for (slot, mask_cell) in a_out.iter().zip(mask_in.iter()) {
        if mask_cell.get() != 0 {
            slot.set(val_in[k].get());
            k += 1;
            if k == v {
                k = 0;
            }
        }
    }
    Ok(true)
}

// All-width zero-copy np.place: the f64 helper covers only float64, leaving narrow
// ints, int64/uint64, float32 and bool on the cold extract path (6-8x slower).
// place cycles values by the running True count but still moves elements verbatim,
// so dispatch by itemsize through a same-width UNSIGNED view of both the array and
// the values (the array view aliases its own buffer, so the scatter is in-place).
// Requires arr and values to share an identical dtype (numpy otherwise casts —
// deferred to the fallback) and a bool mask. complex / mismatched dtypes return
// Ok(false).
fn try_zerocopy_any_place(
    py: Python<'_>,
    arr: &Bound<'_, PyAny>,
    mask: &Bound<'_, PyAny>,
    vals: &Bound<'_, PyAny>,
) -> PyResult<bool> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !arr.is_exact_instance(&ndarray_type)
        || !mask.is_exact_instance(&ndarray_type)
        || !vals.is_exact_instance(&ndarray_type)
    {
        return Ok(false);
    }
    if mask.getattr("dtype")?.getattr("kind")?.extract::<String>()? != "b" {
        return Ok(false);
    }
    let a_dtype = arr.getattr("dtype")?;
    let kind = a_dtype.getattr("kind")?.extract::<String>()?;
    if !matches!(kind.as_str(), "i" | "u" | "f" | "b") {
        return Ok(false);
    }
    if !a_dtype.eq(vals.getattr("dtype")?)? {
        return Ok(false);
    }
    let itemsize = a_dtype.getattr("itemsize")?.extract::<usize>()?;
    let uname = match itemsize {
        1 => "uint8",
        2 => "uint16",
        4 => "uint32",
        8 => "uint64",
        _ => return Ok(false),
    };
    let uview = numpy.getattr(uname)?;
    let a_u = arr.call_method1("view", (&uview,))?;
    let v_u = vals.call_method1("view", (&uview,))?;
    match itemsize {
        1 => place_scatter_typed::<u8>(py, &numpy, mask, &a_u, &v_u),
        2 => place_scatter_typed::<u16>(py, &numpy, mask, &a_u, &v_u),
        4 => place_scatter_typed::<u32>(py, &numpy, mask, &a_u, &v_u),
        8 => place_scatter_typed::<u64>(py, &numpy, mask, &a_u, &v_u),
        _ => Ok(false),
    }
}

// Zero-copy in-place np.place(arr, mask, vals) for a writable float64 arr ndarray,
// a bool mask of the identical shape, and a non-empty float64 vals ndarray.
// numpy.place assigns the True positions in flat order, the k-th True taking
// vals.flat[k % vals.size] — i.e. it cycles vals by the running count of True
// values (unlike putmask, which cycles by flat position). This writes those
// positions straight into arr's own buffer (no extract of arr/vals and no full
// copy-back — only masked slots are touched), dropping the cold boundary-tax Vecs
// (bead lglck). Values are copied verbatim, so the mutation is bit-identical incl.
// -0.0/inf/nan. The bool mask's '?' format is rejected by PyBuffer::<u8>, so it is
// viewed as uint8 first. Returns Ok(false) — caller falls through — for a shape
// mismatch, an empty vals array (numpy raises), a read-only arr, or any non-f64 /
// non-bool / non-contiguous / non-ndarray operand.
fn try_zerocopy_f64_place(
    py: Python<'_>,
    arr: &Bound<'_, PyAny>,
    mask: &Bound<'_, PyAny>,
    vals: &Bound<'_, PyAny>,
) -> PyResult<bool> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !arr.is_exact_instance(&ndarray_type)
        || !mask.is_exact_instance(&ndarray_type)
        || !vals.is_exact_instance(&ndarray_type)
    {
        return Ok(false);
    }
    if mask
        .getattr("dtype")?
        .getattr("kind")?
        .extract::<String>()?
        != "b"
        || !numpy_dtype_is_f64(py, arr)
        || !numpy_dtype_is_f64(py, vals)
    {
        return Ok(false);
    }
    let mask_u8 = mask.call_method1("view", (numpy.getattr("uint8")?,))?;
    let (Ok(a_buffer), Ok(mask_buffer), Ok(val_buffer)) = (
        PyBuffer::<f64>::get(arr),
        PyBuffer::<u8>::get(&mask_u8),
        PyBuffer::<f64>::get(vals),
    ) else {
        return Ok(false);
    };
    if a_buffer.shape() != mask_buffer.shape() {
        return Ok(false);
    }
    let (Some(mask_in), Some(val_in)) = (mask_buffer.as_slice(py), val_buffer.as_slice(py)) else {
        return Ok(false);
    };
    let v = val_in.len();
    if v == 0 {
        return Ok(false);
    }
    let Some(a_out) = a_buffer.as_mut_slice(py) else {
        return Ok(false);
    };
    let mut k = 0usize;
    for (i, slot) in a_out.iter().enumerate() {
        if mask_in[i].get() != 0 {
            slot.set(val_in[k % v].get());
            k += 1;
        }
    }
    Ok(true)
}

// Zero-copy np.cumsum for the flatten form: a C-contiguous float64 ndarray with
// axis=None (numpy flattens and returns a 1-D cumulative sum) or a 1-D array with
// axis in {0, -1}. The running sum is strictly sequential — out[i] = out[i-1] +
// in[i] — exactly numpy's left-to-right accumulation, so it is bit-identical
// (no reordering, which would perturb the non-associative f64 adds). The first
// element is copied verbatim (out[0] = in[0]) rather than 0.0 + in[0] so a
// leading -0.0 keeps its sign. Reads the input buffer and writes the output
// buffer with no intermediate Rust Vec, dropping the cold extract/build Vecs
// (bead lglck). Returns Ok(None) — caller falls through — for a per-axis cumsum
// on a multi-dim array or any non-f64 / non-contiguous / non-ndarray input.
fn try_zerocopy_f64_cumsum(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    // Accept only the flatten-equivalent cumsum: axis=None (any ndim) or a 1-D
    // array with axis in {0, -1}. A per-axis cumsum on a multi-dim array sums
    // along one axis only and is left to the general path.
    let ndim = in_buffer.shape().len();
    let flatten_ok = match axis {
        None => true,
        Some(ax) => ndim == 1 && (ax == 0 || ax == -1),
    };
    if !flatten_ok {
        return Ok(None);
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = input.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // Copy the first element verbatim (preserves a leading -0.0), then carry
        // the running sum forward exactly as numpy does.
        let mut acc = input[0].get();
        output[0].set(acc);
        for i in 1..n {
            acc += input[i].get();
            output[i].set(acc);
        }
    }
    Ok(Some(flat.unbind()))
}

// Generic typed core for integer cumsum: read the input `T` buffer and write a
// strictly-sequential running sum into a fresh `A` buffer (the numpy-promoted
// accumulator dtype — int64 for signed, uint64 for unsigned). `convert` widens
// each input element to the accumulator type; `add` is the wrapping sum. numpy's
// integer cumsum accumulates in the promoted type and wraps on overflow, so this
// is bit-identical. Returns the 1-D result (cumsum flattens for axis=None).
fn cumsum_typed<'py, T, A, FC, FA>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    a: &Bound<'py, PyAny>,
    out_dtype_name: &str,
    convert: FC,
    add: FA,
) -> PyResult<Option<Py<PyAny>>>
where
    T: pyo3::buffer::Element + Copy,
    A: pyo3::buffer::Element + Copy,
    FC: Fn(T) -> A,
    FA: Fn(A, A) -> A,
{
    let Ok(in_buffer) = PyBuffer::<T>::get(a) else {
        return Ok(None);
    };
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = input.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", out_dtype_name)?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<A>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        let mut acc = convert(input[0].get());
        output[0].set(acc);
        for i in 1..n {
            acc = add(acc, convert(input[i].get()));
            output[i].set(acc);
        }
    }
    Ok(Some(flat.unbind()))
}

// Zero-copy integer cumsum for the flatten case (axis=None any ndim, or 1-D with
// axis 0/-1). numpy promotes the accumulator: signed widths -> int64, unsigned ->
// uint64 (on 64-bit). Each width reads its own buffer, widens, and wrapping-sums.
// Otherwise these extracted to an f64 Vec and rebuilt (~50x slower, lossy for
// wide ints). Returns None for a non-integer dtype, an explicit per-axis multi-
// dim cumsum, or a non-ndarray input.
fn try_zerocopy_int_cumsum(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if kind != "i" && kind != "u" && kind != "b" {
        return Ok(None);
    }
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len();
    let flatten_ok = match axis {
        None => true,
        Some(ax) => ndim == 1 && (ax == 0 || ax == -1),
    };
    if !flatten_ok {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    // numpy promotes a bool cumsum to an int64 accumulator. bool buffers export '?'
    // (PyBuffer<u8> rejects it) so read the 0/1 bytes via a zero-copy uint8 view. Was
    // falling through to the f64-bridge extract path (~3.7x slower than numpy).
    if kind == "b" {
        let viewed = a.call_method1("view", (numpy.getattr("uint8")?,))?;
        return cumsum_typed::<u8, i64, _, _>(
            py,
            &numpy,
            &viewed,
            "int64",
            |v| v as i64,
            |a, b| a.wrapping_add(b),
        );
    }
    match (kind.as_str(), itemsize) {
        ("i", 1) => cumsum_typed::<i8, i64, _, _>(
            py,
            &numpy,
            a,
            "int64",
            |v| v as i64,
            |a, b| a.wrapping_add(b),
        ),
        ("i", 2) => cumsum_typed::<i16, i64, _, _>(
            py,
            &numpy,
            a,
            "int64",
            |v| v as i64,
            |a, b| a.wrapping_add(b),
        ),
        ("i", 4) => cumsum_typed::<i32, i64, _, _>(
            py,
            &numpy,
            a,
            "int64",
            |v| v as i64,
            |a, b| a.wrapping_add(b),
        ),
        ("i", 8) => {
            cumsum_typed::<i64, i64, _, _>(py, &numpy, a, "int64", |v| v, |a, b| a.wrapping_add(b))
        }
        ("u", 1) => cumsum_typed::<u8, u64, _, _>(
            py,
            &numpy,
            a,
            "uint64",
            |v| v as u64,
            |a, b| a.wrapping_add(b),
        ),
        ("u", 2) => cumsum_typed::<u16, u64, _, _>(
            py,
            &numpy,
            a,
            "uint64",
            |v| v as u64,
            |a, b| a.wrapping_add(b),
        ),
        ("u", 4) => cumsum_typed::<u32, u64, _, _>(
            py,
            &numpy,
            a,
            "uint64",
            |v| v as u64,
            |a, b| a.wrapping_add(b),
        ),
        ("u", 8) => {
            cumsum_typed::<u64, u64, _, _>(py, &numpy, a, "uint64", |v| v, |a, b| a.wrapping_add(b))
        }
        _ => Ok(None),
    }
}

// Zero-copy np.cumprod — the cumulative-product sibling of try_zerocopy_f64_cumsum
// with identical gating (axis=None any ndim, or 1-D with axis 0/-1). The running
// product is strictly sequential (out[i] = out[i-1] * in[i]), matching numpy's
// left-to-right accumulation, so it is bit-identical. The first element is copied
// verbatim (preserving a leading -0.0). Returns Ok(None) for a per-axis cumprod
// on a multi-dim array or any non-f64 / non-contiguous / non-ndarray input.
fn try_zerocopy_f64_cumprod(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    let ndim = in_buffer.shape().len();
    let flatten_ok = match axis {
        None => true,
        Some(ax) => ndim == 1 && (ax == 0 || ax == -1),
    };
    if !flatten_ok {
        return Ok(None);
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = input.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        let mut acc = input[0].get();
        output[0].set(acc);
        for i in 1..n {
            acc *= input[i].get();
            output[i].set(acc);
        }
    }
    Ok(Some(flat.unbind()))
}

// Zero-copy nan-aware flatten cumulative sum/product (np.nancumsum / np.nancumprod):
// NaN is treated as the additive (0.0) / multiplicative (1.0) identity, then the running
// accumulation is byte-identical to the cumsum/cumprod zero-copy path. Reading the existing
// float64 ndarray buffer and writing a fresh float64 output buffer skips the cold extract
// Vec (and its first-touch page faults), so it beats numpy's nan-cumulative the same way the
// plain cumsum zero-copy path does. Only the flatten-equivalent case (axis=None any ndim, or
// 1-D axis 0/-1); other layouts and non-float64 dtypes fall through to the caller's passthrough.
fn try_zerocopy_f64_nancumsum(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    let ndim = in_buffer.shape().len();
    let flatten_ok = match axis {
        None => true,
        Some(ax) => ndim == 1 && (ax == 0 || ax == -1),
    };
    if !flatten_ok {
        return Ok(None);
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = input.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // NaN contributes 0 to the running sum; a non-NaN first element (incl. -0.0)
        // carries through verbatim, matching np.nancumsum.
        let first = input[0].get();
        let mut acc = if first.is_nan() { 0.0 } else { first };
        output[0].set(acc);
        for i in 1..n {
            let v = input[i].get();
            if !v.is_nan() {
                acc += v;
            }
            output[i].set(acc);
        }
    }
    Ok(Some(flat.unbind()))
}

fn try_zerocopy_f64_nancumprod(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    let ndim = in_buffer.shape().len();
    let flatten_ok = match axis {
        None => true,
        Some(ax) => ndim == 1 && (ax == 0 || ax == -1),
    };
    if !flatten_ok {
        return Ok(None);
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = input.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // NaN contributes 1 to the running product, matching np.nancumprod.
        let first = input[0].get();
        let mut acc = if first.is_nan() { 1.0 } else { first };
        output[0].set(acc);
        for i in 1..n {
            let v = input[i].get();
            if !v.is_nan() {
                acc *= v;
            }
            output[i].set(acc);
        }
    }
    Ok(Some(flat.unbind()))
}

// Zero-copy np.cumsum / np.cumprod along an explicit axis of a multi-dim
// C-contiguous float64 ndarray (the case the flatten cumulative helpers above
// leave alone). Decomposing the layout into outer * axis_len * inner groups, the
// cumulative result is out(o, a, i) = out(o, a-1, i) (+ or *) in(o, a, i), with
// the first slab along the axis copied verbatim (so a leading -0.0 keeps its
// sign). Accumulating slab-by-slab — out block `a` reads the just-written block
// `a-1` and the input block `a`, both contiguous — keeps the access sequential
// (cache-friendly even for axis 0, where a naive per-column scan would stride)
// while preserving numpy's exact left-to-right order along the axis, so it is
// bit-identical (non-associative f64 adds/muls are never reordered). Writes
// straight into a numpy.empty buffer (reshaped), no intermediate Rust Vec (bead
// lglck). `is_prod` selects product vs sum. Returns Ok(None) — caller falls
// through — for a 0-d array, an empty or out-of-range axis, or any non-f64 /
// non-contiguous / non-ndarray input.
fn try_zerocopy_f64_cumulative_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: isize,
    is_prod: bool,
    skip_nan: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    let ndim = shape.len() as isize;
    if ndim == 0 {
        return Ok(None);
    }
    let norm_axis = if axis < 0 { axis + ndim } else { axis };
    if norm_axis < 0 || norm_axis >= ndim {
        return Ok(None);
    }
    let ax = norm_axis as usize;
    let axis_len = shape[ax];
    if axis_len == 0 {
        return Ok(None);
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let total = input.len();
    let outer: usize = shape[..ax].iter().product();
    let inner: usize = shape[ax + 1..].iter().product();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (total,), Some(&kwargs))?;
    if total > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        let lane = axis_len * inner;
        // skip_nan (nancumsum/nancumprod): a NaN contributes the identity (0 for sum,
        // 1 for prod) so the running accumulator carries through unchanged, matching
        // numpy.nancumsum/nancumprod. skip_nan=false keeps NaN verbatim (plain cum*).
        let ident = if is_prod { 1.0 } else { 0.0 };
        if inner == 1 {
            // Last-axis case: each outer lane is a contiguous run, so carry the
            // accumulator in a register (no read-back of the previous output cell)
            // exactly like the 1-D flatten scan — much faster than slab-by-slab.
            for o in 0..outer {
                let obase = o * axis_len;
                let first = input[obase].get();
                let mut acc = if skip_nan && first.is_nan() {
                    ident
                } else {
                    first
                };
                output[obase].set(acc);
                for a_idx in 1..axis_len {
                    let value = input[obase + a_idx].get();
                    if !(skip_nan && value.is_nan()) {
                        acc = if is_prod { acc * value } else { acc + value };
                    }
                    output[obase + a_idx].set(acc);
                }
            }
        } else {
            // inner > 1: accumulate slab-by-slab so the access stays sequential and
            // cache-friendly (a per-column register scan would stride by `inner`).
            // out block a = (out block a-1) op (in block a).
            for o in 0..outer {
                let obase = o * lane;
                // First slab along the axis is copied verbatim (preserves -0.0); under
                // skip_nan a NaN in the first slab becomes the identity.
                for i in 0..inner {
                    let v = input[obase + i].get();
                    output[obase + i].set(if skip_nan && v.is_nan() { ident } else { v });
                }
                for a_idx in 1..axis_len {
                    let cur = obase + a_idx * inner;
                    let prev = obase + (a_idx - 1) * inner;
                    for i in 0..inner {
                        let carried = output[prev + i].get();
                        let value = input[cur + i].get();
                        let contrib = if skip_nan && value.is_nan() {
                            ident
                        } else {
                            value
                        };
                        output[cur + i].set(if is_prod {
                            carried * contrib
                        } else {
                            carried + contrib
                        });
                    }
                }
            }
        }
    }
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    Ok(Some(output))
}

// Generic typed core for per-axis integer cumsum. Reads the input `T` buffer and
// writes the running sum into a fresh `A` buffer (the numpy-promoted accumulator
// dtype) using the same outer*axis*inner decomposition as the f64 path: inner==1
// (last axis) carries the accumulator in a register; inner>1 accumulates slab by
// slab. `convert` widens each input element to A; `op` is the wrapping add.
fn cumsum_axis_typed<'py, T, A, FC, FA>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    a: &Bound<'py, PyAny>,
    axis: isize,
    dtype_name: &str,
    convert: FC,
    op: FA,
) -> PyResult<Option<(Bound<'py, PyAny>, Vec<usize>)>>
where
    T: pyo3::buffer::Element + Copy,
    A: pyo3::buffer::Element + Copy,
    FC: Fn(T) -> A,
    FA: Fn(A, A) -> A,
{
    let Ok(in_buffer) = PyBuffer::<T>::get(a) else {
        return Ok(None);
    };
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    let ndim = shape.len() as isize;
    if ndim == 0 {
        return Ok(None);
    }
    let norm_axis = if axis < 0 { axis + ndim } else { axis };
    if norm_axis < 0 || norm_axis >= ndim {
        return Ok(None);
    }
    let ax = norm_axis as usize;
    let axis_len = shape[ax];
    if axis_len == 0 {
        return Ok(None);
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let total = input.len();
    let outer: usize = shape[..ax].iter().product();
    let inner: usize = shape[ax + 1..].iter().product();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", dtype_name)?;
    let flat = numpy.call_method("empty", (total,), Some(&kwargs))?;
    if total > 0 {
        let Ok(out_buffer) = PyBuffer::<A>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        let lane = axis_len * inner;
        if inner == 1 {
            for o in 0..outer {
                let obase = o * axis_len;
                let mut acc = convert(input[obase].get());
                output[obase].set(acc);
                for a_idx in 1..axis_len {
                    acc = op(acc, convert(input[obase + a_idx].get()));
                    output[obase + a_idx].set(acc);
                }
            }
        } else {
            for o in 0..outer {
                let obase = o * lane;
                for i in 0..inner {
                    output[obase + i].set(convert(input[obase + i].get()));
                }
                for a_idx in 1..axis_len {
                    let cur = obase + a_idx * inner;
                    let prev = obase + (a_idx - 1) * inner;
                    for i in 0..inner {
                        let carried = output[prev + i].get();
                        output[cur + i].set(op(carried, convert(input[cur + i].get())));
                    }
                }
            }
        }
    }
    Ok(Some((flat, shape)))
}

// Zero-copy per-axis integer cumsum (explicit axis), all widths, with numpy's
// accumulator promotion (signed -> int64, unsigned -> uint64). The flatten helper
// covers axis=None; this covers a single integer axis of a multi-dim array.
// Otherwise these extracted to an f64 Vec (~6-30x slower). Returns None for a
// non-integer dtype, a 0-d / out-of-range axis, or a non-ndarray input.
fn try_zerocopy_int_cumsum_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: isize,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if kind != "i" && kind != "u" && kind != "b" {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    let add_i64 = |x: i64, y: i64| x.wrapping_add(y);
    let add_u64 = |x: u64, y: u64| x.wrapping_add(y);
    // bool -> int64 accumulator (uint8 view of the 0/1 bytes; see try_zerocopy_int_cumsum).
    let result = if kind == "b" {
        let viewed = a.call_method1("view", (numpy.getattr("uint8")?,))?;
        cumsum_axis_typed::<u8, i64, _, _>(py, &numpy, &viewed, axis, "int64", |v| v as i64, add_i64)?
    } else {
        match (kind.as_str(), itemsize) {
        ("i", 1) => cumsum_axis_typed::<i8, i64, _, _>(py, &numpy, a, axis, "int64", |v| v as i64, add_i64)?,
        ("i", 2) => cumsum_axis_typed::<i16, i64, _, _>(py, &numpy, a, axis, "int64", |v| v as i64, add_i64)?,
        ("i", 4) => cumsum_axis_typed::<i32, i64, _, _>(py, &numpy, a, axis, "int64", |v| v as i64, add_i64)?,
        ("i", 8) => cumsum_axis_typed::<i64, i64, _, _>(py, &numpy, a, axis, "int64", |v| v, add_i64)?,
        ("u", 1) => cumsum_axis_typed::<u8, u64, _, _>(py, &numpy, a, axis, "uint64", |v| v as u64, add_u64)?,
        ("u", 2) => cumsum_axis_typed::<u16, u64, _, _>(py, &numpy, a, axis, "uint64", |v| v as u64, add_u64)?,
        ("u", 4) => cumsum_axis_typed::<u32, u64, _, _>(py, &numpy, a, axis, "uint64", |v| v as u64, add_u64)?,
        ("u", 8) => cumsum_axis_typed::<u64, u64, _, _>(py, &numpy, a, axis, "uint64", |v| v, add_u64)?,
        _ => return Ok(None),
        }
    };
    let Some((flat, shape)) = result else {
        return Ok(None);
    };
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    Ok(Some(output))
}

// Zero-copy float32 cumsum for the flatten case (axis=None any ndim, or 1-D with
// axis 0/-1). numpy does NOT promote float32 cumsum (the accumulator stays float32,
// unlike the integer path) and accumulates strictly left-to-right, so the generic
// cumsum_typed core with T=A=f32 and a plain f32 add is bit-identical (nan/inf and
// f32 overflow-to-inf propagate exactly; verified 0 mismatch in a numpy prototype).
// The f64 helper gates on float64, so float32 otherwise extracted to an f64 Vec
// (~7.5x slower). Returns None for a non-float32 dtype, an explicit per-axis multi-
// dim cumsum, or a non-ndarray input.
fn try_zerocopy_f32_cumsum(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 4
    {
        return Ok(None);
    }
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len();
    let flatten_ok = match axis {
        None => true,
        Some(ax) => ndim == 1 && (ax == 0 || ax == -1),
    };
    if !flatten_ok {
        return Ok(None);
    }
    cumsum_typed::<f32, f32, _, _>(py, &numpy, a, "float32", |v| v, |a, b| a + b)
}

// Zero-copy per-axis float32 cumsum (explicit axis); slab-by-slab f32 accumulation
// via the generic cumsum_axis_typed core (T=A=f32, plain f32 add). numpy keeps the
// float32 accumulator and accumulates left-to-right, so it is bit-identical. The
// flatten helper above only covers axis=None. Returns None for a non-float32 dtype,
// a 0-d / out-of-range axis, or a non-ndarray input.
fn try_zerocopy_f32_cumsum_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: isize,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 4
    {
        return Ok(None);
    }
    let result =
        cumsum_axis_typed::<f32, f32, _, _>(py, &numpy, a, axis, "float32", |v| v, |a, b| a + b)?;
    let Some((flat, shape)) = result else {
        return Ok(None);
    };
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    Ok(Some(output))
}

// Per-axis float32 nancumsum/nancumprod: numpy replaces NaN with the identity (0 for sum,
// 1 for prod) IN float32 then runs the plain f32 cumulative, so mapping NaN->identity in the
// `convert` closure of cumsum_axis_typed (which applies to every element) is bit-identical —
// and reuses the fast slab kernel instead of delegating (par -> ~0.25x). The f64 cumulative
// helper is f64-only; f32 cannot widen (numpy keeps the f32 accumulator). (BlackThrush 2026-06-22.)
fn try_zerocopy_f32_nancumulative_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: isize,
    is_prod: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 4
    {
        return Ok(None);
    }
    let result = if is_prod {
        cumsum_axis_typed::<f32, f32, _, _>(
            py,
            &numpy,
            a,
            axis,
            "float32",
            |v| if v.is_nan() { 1.0 } else { v },
            |a, b| a * b,
        )?
    } else {
        cumsum_axis_typed::<f32, f32, _, _>(
            py,
            &numpy,
            a,
            axis,
            "float32",
            |v| if v.is_nan() { 0.0 } else { v },
            |a, b| a + b,
        )?
    };
    let Some((flat, shape)) = result else {
        return Ok(None);
    };
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    Ok(Some(output))
}

// Zero-copy integer cumprod for the flatten case (axis=None any ndim, or 1-D with
// axis 0/-1). The multiplicative sibling of try_zerocopy_int_cumsum: numpy promotes
// the accumulator identically (signed -> int64, unsigned -> uint64) and the running
// product wraps. cumprod is strictly sequential (out[i] = out[i-1] * in[i]) so the
// wrapping_mul running product is bit-identical. Reuses the generic cumsum_typed
// core with a multiply op. Otherwise these extracted to an f64 Vec (~30x slower,
// and overflow-to-inf for wide products). Returns None for a non-integer dtype, an
// explicit per-axis multi-dim cumprod, or a non-ndarray input.
fn try_zerocopy_int_cumprod(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if kind != "i" && kind != "u" && kind != "b" {
        return Ok(None);
    }
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len();
    let flatten_ok = match axis {
        None => true,
        Some(ax) => ndim == 1 && (ax == 0 || ax == -1),
    };
    if !flatten_ok {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    let mul_i64 = |x: i64, y: i64| x.wrapping_mul(y);
    let mul_u64 = |x: u64, y: u64| x.wrapping_mul(y);
    // numpy promotes a bool cumprod to an int64 accumulator (the 0/1 product never
    // wraps). bool buffers export format '?', which PyBuffer<u8> rejects, so read the
    // bytes through a zero-copy uint8 view. Was falling through to the f64-bridge
    // extract path (~15x slower than numpy at 4M).
    if kind == "b" {
        let viewed = a.call_method1("view", (numpy.getattr("uint8")?,))?;
        return cumsum_typed::<u8, i64, _, _>(py, &numpy, &viewed, "int64", |v| v as i64, mul_i64);
    }
    match (kind.as_str(), itemsize) {
        ("i", 1) => cumsum_typed::<i8, i64, _, _>(py, &numpy, a, "int64", |v| v as i64, mul_i64),
        ("i", 2) => cumsum_typed::<i16, i64, _, _>(py, &numpy, a, "int64", |v| v as i64, mul_i64),
        ("i", 4) => cumsum_typed::<i32, i64, _, _>(py, &numpy, a, "int64", |v| v as i64, mul_i64),
        ("i", 8) => cumsum_typed::<i64, i64, _, _>(py, &numpy, a, "int64", |v| v, mul_i64),
        ("u", 1) => cumsum_typed::<u8, u64, _, _>(py, &numpy, a, "uint64", |v| v as u64, mul_u64),
        ("u", 2) => cumsum_typed::<u16, u64, _, _>(py, &numpy, a, "uint64", |v| v as u64, mul_u64),
        ("u", 4) => cumsum_typed::<u32, u64, _, _>(py, &numpy, a, "uint64", |v| v as u64, mul_u64),
        ("u", 8) => cumsum_typed::<u64, u64, _, _>(py, &numpy, a, "uint64", |v| v, mul_u64),
        _ => Ok(None),
    }
}

// Zero-copy per-axis integer cumprod (explicit axis), all widths, multiplicative
// sibling of try_zerocopy_int_cumsum_axis with the same accumulator promotion.
// Reuses the generic cumsum_axis_typed core with a wrapping multiply. Returns None
// for a non-integer dtype, a 0-d / out-of-range axis, or a non-ndarray input.
fn try_zerocopy_int_cumprod_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: isize,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if kind != "i" && kind != "u" && kind != "b" {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    let mul_i64 = |x: i64, y: i64| x.wrapping_mul(y);
    let mul_u64 = |x: u64, y: u64| x.wrapping_mul(y);
    // bool -> int64 accumulator (uint8 view of the 0/1 bytes; see try_zerocopy_int_cumprod).
    let result = if kind == "b" {
        let viewed = a.call_method1("view", (numpy.getattr("uint8")?,))?;
        cumsum_axis_typed::<u8, i64, _, _>(py, &numpy, &viewed, axis, "int64", |v| v as i64, mul_i64)?
    } else {
        match (kind.as_str(), itemsize) {
        ("i", 1) => cumsum_axis_typed::<i8, i64, _, _>(py, &numpy, a, axis, "int64", |v| v as i64, mul_i64)?,
        ("i", 2) => cumsum_axis_typed::<i16, i64, _, _>(py, &numpy, a, axis, "int64", |v| v as i64, mul_i64)?,
        ("i", 4) => cumsum_axis_typed::<i32, i64, _, _>(py, &numpy, a, axis, "int64", |v| v as i64, mul_i64)?,
        ("i", 8) => cumsum_axis_typed::<i64, i64, _, _>(py, &numpy, a, axis, "int64", |v| v, mul_i64)?,
        ("u", 1) => cumsum_axis_typed::<u8, u64, _, _>(py, &numpy, a, axis, "uint64", |v| v as u64, mul_u64)?,
        ("u", 2) => cumsum_axis_typed::<u16, u64, _, _>(py, &numpy, a, axis, "uint64", |v| v as u64, mul_u64)?,
        ("u", 4) => cumsum_axis_typed::<u32, u64, _, _>(py, &numpy, a, axis, "uint64", |v| v as u64, mul_u64)?,
        ("u", 8) => cumsum_axis_typed::<u64, u64, _, _>(py, &numpy, a, axis, "uint64", |v| v, mul_u64)?,
        _ => return Ok(None),
        }
    };
    let Some((flat, shape)) = result else {
        return Ok(None);
    };
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    Ok(Some(output))
}

// Zero-copy float32 cumprod (flatten: axis=None any ndim, or 1-D axis 0/-1). The
// multiplicative sibling of try_zerocopy_f32_cumsum: numpy does NOT promote a
// float32 cumprod (the accumulator stays float32) and accumulates left-to-right, so
// the generic cumsum_typed core with T=A=f32 and a plain f32 multiply is
// bit-identical (nan/inf and f32 overflow-to-inf propagate; verified 0 mismatch in
// a numpy prototype). The f64 helper gates on float64, so float32 otherwise
// extracted to an f64 Vec (~7.8x slower). Returns None for a non-float32 dtype, an
// explicit per-axis multi-dim cumprod, or a non-ndarray input.
fn try_zerocopy_f32_cumprod(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 4
    {
        return Ok(None);
    }
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len();
    let flatten_ok = match axis {
        None => true,
        Some(ax) => ndim == 1 && (ax == 0 || ax == -1),
    };
    if !flatten_ok {
        return Ok(None);
    }
    cumsum_typed::<f32, f32, _, _>(py, &numpy, a, "float32", |v| v, |a, b| a * b)
}

// Zero-copy per-axis float32 cumprod (explicit axis); slab-by-slab f32 product via
// the generic cumsum_axis_typed core (T=A=f32, plain f32 multiply). numpy keeps the
// float32 accumulator and accumulates left-to-right, so it is bit-identical. The
// flatten helper above only covers axis=None. Returns None for a non-float32 dtype,
// a 0-d / out-of-range axis, or a non-ndarray input.
fn try_zerocopy_f32_cumprod_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: isize,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 4
    {
        return Ok(None);
    }
    let result =
        cumsum_axis_typed::<f32, f32, _, _>(py, &numpy, a, axis, "float32", |v| v, |a, b| a * b)?;
    let Some((flat, shape)) = result else {
        return Ok(None);
    };
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    Ok(Some(output))
}

// Zero-copy np.tile(a, reps) for the 1-D scalar-reps form: a C-contiguous float64
// 1-D ndarray tiled `reps` times into a length-(n*reps) result. numpy.tile lays
// the input down end to end, so each output block is a verbatim copy of the
// input — bit-identical incl. nan/inf/signed zeros. Writes the reps blocks
// straight into a numpy.empty(n*reps) buffer with no intermediate Rust Vec,
// dropping the cold extract/build Vecs (bead lglck). Returns Ok(None) — caller
// falls through — for a multi-dim input, a multi-element reps tuple (which adds
// leading axes), or any non-f64 / non-contiguous / non-ndarray input.
fn try_zerocopy_f64_tile(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    reps: &[usize],
) -> PyResult<Option<Py<PyAny>>> {
    // Only the single-axis tile of a 1-D array maps to a flat block copy; a
    // multi-element reps tuple promotes dimensions and is left to the general path.
    if reps.len() != 1 {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    if in_buffer.shape().len() != 1 {
        return Ok(None);
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = input.len();
    let r = reps[0];
    let Some(total) = n.checked_mul(r) else {
        return Ok(None);
    };
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (total,), Some(&kwargs))?;
    if total > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        for block in 0..r {
            let base = block * n;
            for i in 0..n {
                output[base + i].set(input[i].get());
            }
        }
    }
    Ok(Some(flat.unbind()))
}

// Dtype-agnostic 1-D tile (scalar reps) for any dtype the f64 helper above does
// not handle — all integer widths, float32, complex, bool. np.tile replicates
// elements verbatim, so repeating the raw byte image r times is bit-identical
// for every dtype. Views the data as 1-D uint8, copies the byte block r times
// into a fresh uint8 buffer, then views back to the input dtype. Returns
// Ok(None) for a multi-element reps tuple, a non-1-D array, or a non-ndarray.
fn try_zerocopy_any_tile(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    reps: &[usize],
) -> PyResult<Option<Py<PyAny>>> {
    // 1-D input only. For a 1-D array the tiled data has no inner structure to break,
    // so tile(a, reps) is a flat repetition by prod(reps) reshaped to the result shape
    // (= reps with its last entry scaled by len(a)) — even for a multi-element reps
    // tuple. Multi-dim inputs (whose inner axes do interleave) fall through.
    if reps.is_empty() {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    if shape.len() != 1 {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    // Complex already has an efficient native/numpy fallback; the byte copy does
    // not beat it, so leave it (and any zero-itemsize dtype) on the existing path.
    if dtype.getattr("kind")?.extract::<String>()? == "c" {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    if itemsize == 0 {
        return Ok(None);
    }
    let uint8 = numpy.getattr("uint8")?;
    let Ok(in_u8) = a.call_method1("view", (&uint8,)) else {
        return Ok(None);
    };
    let Ok(in_buffer) = PyBuffer::<u8>::get(&in_u8) else {
        return Ok(None);
    };
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let n_bytes = input.len();
    // prod(reps): total flat repetition count (1-D input tiles flat).
    let mut r: usize = 1;
    for &rep in reps {
        let Some(p) = r.checked_mul(rep) else {
            return Ok(None);
        };
        r = p;
    }
    let Some(total_bytes) = n_bytes.checked_mul(r) else {
        return Ok(None);
    };
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "uint8")?;
    let out_u8 = numpy.call_method("empty", (total_bytes,), Some(&kwargs))?;
    if total_bytes > 0 {
        let Ok(out_buffer) = PyBuffer::<u8>::get(&out_u8) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        for block in 0..r {
            let base = block * n_bytes;
            for i in 0..n_bytes {
                output[base + i].set(input[i].get());
            }
        }
    }
    // view back to the input dtype; the 1-D length is total_bytes/itemsize = n*r.
    let out_typed = out_u8.call_method1("view", (&dtype,))?;
    if reps.len() == 1 {
        // 1-D result, length n*r — no reshape needed.
        return Ok(Some(out_typed.unbind()));
    }
    // Multi-element reps: result shape = reps with the last entry scaled by len(a).
    // (a is 1-D, so a is right-aligned under the reps: result[k] = reps[k] for k <
    // last, and reps[last] * n_elems for the last axis.) prod == n*r, so the flat
    // buffer reshapes exactly.
    let n_elems = n_bytes / itemsize;
    let mut out_shape: Vec<usize> = reps.to_vec();
    let last = out_shape.len() - 1;
    out_shape[last] = out_shape[last].saturating_mul(n_elems);
    let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
    Ok(Some(
        out_typed.call_method1("reshape", (&output_shape,))?.unbind(),
    ))
}

// Zero-copy multi-dim np.tile (a.ndim >= 2) via byte row-block replication. tile
// moves whole elements, and along the last axis the source data is contiguous, so the
// result is built one last-axis "row" at a time: each output super-row (the index over
// all axes but the last) maps to a SOURCE super-row by per-axis modulo, and that
// source row (a contiguous block of A[last] elements) is copied R[last] times. The
// block copy uses a subslice so it memcpy-vectorizes; the modular source index is
// tracked with an odometer over the output super-shape. Covers int/float/bool/complex
// in one path. numpy pads the shorter of a.shape / reps with leading 1s. Returns None
// for a 1-D input (the dedicated helper handles it), complex (fast already), a
// non-contiguous / zero-itemsize / non-ndarray input.
fn try_zerocopy_any_tile_multidim(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    reps: &[usize],
) -> PyResult<Option<Py<PyAny>>> {
    if reps.is_empty() {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let a_shape: Vec<usize> = a.getattr("shape")?.extract()?;
    if a_shape.len() < 2 {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? == "c" {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    if itemsize == 0 {
        return Ok(None);
    }
    // Pad a.shape and reps to a common ndim d with leading 1s (numpy's rule).
    let d = a_shape.len().max(reps.len());
    let mut av = vec![1usize; d];
    av[d - a_shape.len()..].copy_from_slice(&a_shape);
    let mut rv = vec![1usize; d];
    rv[d - reps.len()..].copy_from_slice(reps);
    let out_shape: Vec<usize> = (0..d).map(|k| av[k] * rv[k]).collect();
    let a_last = av[d - 1];
    let out_last = out_shape[d - 1];
    let r_last = rv[d - 1];
    // Source row strides (in rows) for the modular super-index → source-row mapping.
    let mut a_rowstride = vec![1usize; d - 1];
    for k in (0..d - 1).rev() {
        a_rowstride[k] = if k + 1 < d - 1 {
            a_rowstride[k + 1] * av[k + 1]
        } else {
            1
        };
    }
    let n_super_out: usize = out_shape[..d - 1].iter().product();
    let uint8 = numpy.getattr("uint8")?;
    let Ok(in_u8) = a.call_method1("view", (&uint8,)) else {
        return Ok(None);
    };
    let Ok(in_buffer) = PyBuffer::<u8>::get(&in_u8) else {
        return Ok(None);
    };
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let row_bytes = a_last * itemsize;
    let total_bytes: usize = out_shape.iter().product::<usize>() * itemsize;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "uint8")?;
    let out_u8 = numpy.call_method("empty", (total_bytes,), Some(&kwargs))?;
    if total_bytes > 0 && row_bytes > 0 {
        let Ok(out_buffer) = PyBuffer::<u8>::get(&out_u8) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        let out_row_bytes = out_last * itemsize;
        let mut digits = vec![0usize; d - 1];
        let mut out_off = 0usize;
        for _s in 0..n_super_out {
            // source row = sum over non-last axes of (digit mod A[k]) * a_rowstride[k]
            let mut src_row = 0usize;
            for k in 0..d - 1 {
                src_row += (digits[k] % av[k]) * a_rowstride[k];
            }
            let src_off = src_row * row_bytes;
            let src = &input[src_off..src_off + row_bytes];
            let mut o = out_off;
            for _rep in 0..r_last {
                let dst = &output[o..o + row_bytes];
                for (d8, s8) in dst.iter().zip(src.iter()) {
                    d8.set(s8.get());
                }
                o += row_bytes;
            }
            out_off += out_row_bytes;
            // odometer increment of the output super-index (rightmost digit fastest)
            for k in (0..d - 1).rev() {
                digits[k] += 1;
                if digits[k] < out_shape[k] {
                    break;
                }
                digits[k] = 0;
            }
        }
    }
    let out_typed = out_u8.call_method1("view", (&dtype,))?;
    let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
    Ok(Some(
        out_typed.call_method1("reshape", (&output_shape,))?.unbind(),
    ))
}

// Zero-copy first-difference (np.diff with n==1) for a 1-D C-contiguous float64
// ndarray. Output[i] = a[i+1] - a[i], length len-1 (empty for len 0 or 1, which
// matches numpy). Reads the input buffer and writes the (len-1)-length output
// buffer with no intermediate Rust Vec, dropping the cold extract/build Vecs
// (bead lglck). The per-element subtraction is the same op numpy performs, so it
// is bit-identical (nan/inf propagate: e.g. inf-inf -> nan). Returns Ok(None)
// for n != 1, multi-dim, an axis that is not the single 1-D axis (-1 or 0), or
// any non-f64 / non-contiguous / non-ndarray input (caller falls through to the
// general a.diff path).
fn try_zerocopy_f64_diff1d(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    n: usize,
    axis: i64,
) -> PyResult<Option<Py<PyAny>>> {
    if n != 1 || !(axis == -1 || axis == 0) {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    if in_buffer.shape().len() != 1 {
        return Ok(None);
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let n_out = input.len().saturating_sub(1);
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (n_out,), Some(&kwargs))?;
    if n_out > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        for (i, slot) in output.iter().enumerate() {
            slot.set(input[i + 1].get() - input[i].get());
        }
    }
    Ok(Some(flat.unbind()))
}

// Zero-copy np.diff(n=1) along an explicit axis of a multi-dim C-contiguous
// float64 ndarray (the case the 1-D diff helper leaves alone). Decomposing the
// layout into outer * axis_len * inner groups, numpy's per-axis first difference
// is out(o, a, i) = in(o, a+1, i) - in(o, a, i) for a in [0, axis_len-1); the
// output's axis dimension shrinks by one. This writes each per-lane difference
// straight into a numpy.empty buffer (then reshaped) with no intermediate Rust
// Vec, dropping the cold extract/build Vecs (bead lglck). The subtraction is the
// same op numpy performs in the same order, so it is bit-identical (nan/inf
// propagate). Returns Ok(None) — caller falls through — for n != 1, a 0-d array,
// an empty or out-of-range axis, or any non-f64 / non-contiguous / non-ndarray
// input.
fn try_zerocopy_f64_diff_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    n: usize,
    axis: i64,
) -> PyResult<Option<Py<PyAny>>> {
    if n != 1 {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    let ndim = shape.len() as i64;
    if ndim == 0 {
        return Ok(None);
    }
    let norm_axis = if axis < 0 { axis + ndim } else { axis };
    if norm_axis < 0 || norm_axis >= ndim {
        return Ok(None);
    }
    let ax = norm_axis as usize;
    let axis_len = shape[ax];
    if axis_len == 0 {
        return Ok(None);
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let outer: usize = shape[..ax].iter().product();
    let inner: usize = shape[ax + 1..].iter().product();
    let out_axis_len = axis_len - 1;
    let mut out_shape = shape.clone();
    out_shape[ax] = out_axis_len;
    let total_out = outer * out_axis_len * inner;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (total_out,), Some(&kwargs))?;
    if total_out > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        let in_lane = axis_len * inner;
        let out_lane = out_axis_len * inner;
        if inner == 1 {
            // Last-axis (or 1-D) lanes are contiguous: pair each element with its
            // successor over slice iterators so bounds checks elide and the
            // subtraction autovectorizes. The strided indexed branch below does
            // not vectorize (the old code used it for every case, leaving f64
            // 2-D last-axis diff ~7.7x behind numpy — integer diff already used
            // this fast path via diff_typed).
            for o in 0..outer {
                let inl = &input[o * in_lane..o * in_lane + axis_len];
                let outl = &output[o * out_lane..o * out_lane + out_axis_len];
                for ((slot, cur), nxt) in outl.iter().zip(inl.iter()).zip(inl[1..].iter()) {
                    slot.set(nxt.get() - cur.get());
                }
            }
        } else {
            for o in 0..outer {
                let ibase = o * in_lane;
                let obase = o * out_lane;
                for a_out in 0..out_axis_len {
                    let dst = obase + a_out * inner;
                    let cur = ibase + a_out * inner;
                    let nxt = ibase + (a_out + 1) * inner;
                    for i in 0..inner {
                        output[dst + i].set(input[nxt + i].get() - input[cur + i].get());
                    }
                }
            }
        }
    }
    let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    Ok(Some(output))
}

// Generic typed core for np.diff(n=1) along an axis, via the same
// outer * axis_len * inner decomposition as the f64 path (the 1-D case is
// outer=inner=1). Reads the `T` buffer and writes sub(in[a+1], in[a]) per lane
// into a fresh `T` buffer; returns it plus the (axis-shrunk) shape.
fn diff_typed<'py, T, F>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    a: &Bound<'py, PyAny>,
    dtype_name: &str,
    axis: i64,
    sub: F,
) -> PyResult<Option<(Bound<'py, PyAny>, Vec<usize>)>>
where
    T: pyo3::buffer::Element + Copy,
    F: Fn(T, T) -> T,
{
    let Ok(in_buffer) = PyBuffer::<T>::get(a) else {
        return Ok(None);
    };
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    let ndim = shape.len() as i64;
    if ndim == 0 {
        return Ok(None);
    }
    let norm_axis = if axis < 0 { axis + ndim } else { axis };
    if norm_axis < 0 || norm_axis >= ndim {
        return Ok(None);
    }
    let ax = norm_axis as usize;
    let axis_len = shape[ax];
    if axis_len == 0 {
        return Ok(None);
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let outer: usize = shape[..ax].iter().product();
    let inner: usize = shape[ax + 1..].iter().product();
    let out_axis_len = axis_len - 1;
    let mut out_shape = shape.clone();
    out_shape[ax] = out_axis_len;
    let total_out = outer * out_axis_len * inner;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", dtype_name)?;
    let flat = numpy.call_method("empty", (total_out,), Some(&kwargs))?;
    if total_out > 0 {
        let Ok(out_buffer) = PyBuffer::<T>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        let in_lane = axis_len * inner;
        let out_lane = out_axis_len * inner;
        if inner == 1 {
            // Last-axis (or 1-D) lanes are contiguous: pair each element with its
            // successor over slice iterators so bounds checks elide and the
            // subtraction autovectorizes (the strided branch below cannot).
            for o in 0..outer {
                let inl = &input[o * in_lane..o * in_lane + axis_len];
                let outl = &output[o * out_lane..o * out_lane + out_axis_len];
                for ((slot, cur), nxt) in outl.iter().zip(inl.iter()).zip(inl[1..].iter()) {
                    slot.set(sub(nxt.get(), cur.get()));
                }
            }
        } else {
            for o in 0..outer {
                let ibase = o * in_lane;
                let obase = o * out_lane;
                for a_out in 0..out_axis_len {
                    let dst = obase + a_out * inner;
                    let cur = ibase + a_out * inner;
                    let nxt = ibase + (a_out + 1) * inner;
                    for i in 0..inner {
                        output[dst + i].set(sub(input[nxt + i].get(), input[cur + i].get()));
                    }
                }
            }
        }
    }
    Ok(Some((flat, out_shape)))
}

// Zero-copy np.diff(n=1) for integer ndarrays (int8/16/32/64, uint8/16/32/64),
// any axis. numpy's integer diff wraps on two's-complement overflow and
// preserves dtype, so wrapping_sub is bit-identical. Otherwise these extracted
// to an f64 Vec and rebuilt (~120-280x slower), lossy for wide ints. Returns
// None for n != 1, non-integer dtypes, or non-ndarray inputs.
fn try_zerocopy_int_diff(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    n: usize,
    axis: i64,
) -> PyResult<Option<Py<PyAny>>> {
    if n != 1 {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if kind != "i" && kind != "u" {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    let result = match (kind.as_str(), itemsize) {
        ("i", 1) => diff_typed::<i8, _>(py, &numpy, a, "int8", axis, |x, y| x.wrapping_sub(y))?,
        ("i", 2) => diff_typed::<i16, _>(py, &numpy, a, "int16", axis, |x, y| x.wrapping_sub(y))?,
        ("i", 4) => diff_typed::<i32, _>(py, &numpy, a, "int32", axis, |x, y| x.wrapping_sub(y))?,
        ("i", 8) => diff_typed::<i64, _>(py, &numpy, a, "int64", axis, |x, y| x.wrapping_sub(y))?,
        ("u", 1) => diff_typed::<u8, _>(py, &numpy, a, "uint8", axis, |x, y| x.wrapping_sub(y))?,
        ("u", 2) => diff_typed::<u16, _>(py, &numpy, a, "uint16", axis, |x, y| x.wrapping_sub(y))?,
        ("u", 4) => diff_typed::<u32, _>(py, &numpy, a, "uint32", axis, |x, y| x.wrapping_sub(y))?,
        ("u", 8) => diff_typed::<u64, _>(py, &numpy, a, "uint64", axis, |x, y| x.wrapping_sub(y))?,
        _ => return Ok(None),
    };
    let Some((flat, out_shape)) = result else {
        return Ok(None);
    };
    let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    Ok(Some(output))
}

// Zero-copy np.diff(n=1) for float32 ndarrays, any axis. numpy's float diff is the
// plain IEEE-754 single-precision subtraction out[i] = a[i+1] - a[i] preserving the
// float32 dtype, so the same diff_typed core with `x - y` is bit-identical (nan/inf
// and signed-zero propagate exactly). The f64 helpers gate on float64 only, so
// float32 otherwise extracted to an f64 Vec and rebuilt (~33x slower). Returns None
// for n != 1, a non-float32 dtype, or a non-ndarray input.
fn try_zerocopy_f32_diff(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    n: usize,
    axis: i64,
) -> PyResult<Option<Py<PyAny>>> {
    if n != 1 {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 4
    {
        return Ok(None);
    }
    let result = diff_typed::<f32, _>(py, &numpy, a, "float32", axis, |x, y| x - y)?;
    let Some((flat, out_shape)) = result else {
        return Ok(None);
    };
    let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    Ok(Some(output))
}

// Zero-copy consecutive differences (np.ediff1d, no to_begin/to_end) for a
// C-contiguous float64 ndarray of any shape. numpy.ediff1d flattens its input
// in C order and returns out[i] = flat[i+1] - flat[i], length total_elems-1
// (empty for 0 or 1 elements). PyBuffer::as_slice only yields Some for a
// C-contiguous buffer, so iterating the flat slice reproduces numpy's flatten
// order exactly for any ndim; the per-element subtraction is bit-identical
// (nan/inf propagate). Drops the cold extract/ravel/build Vecs (bead lglck).
// Returns Ok(None) when to_begin/to_end are present, or for any non-f64 /
// non-contiguous / non-ndarray input (caller falls through to the general path).
fn try_zerocopy_f64_ediff1d(
    py: Python<'_>,
    ary: &Bound<'_, PyAny>,
    to_begin: Option<&Py<PyAny>>,
    to_end: Option<&Py<PyAny>>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !ary.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(ary) else {
        return Ok(None);
    };
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let n_diff = input.len().saturating_sub(1);

    // Materialize an optional to_begin/to_end as a flat Vec<f64>, matching
    // numpy.ediff1d's flatten + cast-to-result-dtype (f64 here). These arrays are
    // small (usually a scalar), so a tiny Vec is cheap — the n-1 diffs stay
    // zero-copy. Returns Ok(None) on an uncastable dtype (complex / object /
    // string) so the caller falls through to the general path.
    let materialize = |value: Option<&Py<PyAny>>| -> PyResult<Option<Vec<f64>>> {
        let Some(value) = value else {
            return Ok(Some(Vec::new()));
        };
        let arr = numpy.call_method1("asarray", (value.bind(py),))?;
        let kind = arr.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
        if !matches!(kind.as_str(), "b" | "i" | "u" | "f") {
            return Ok(None);
        }
        let flat = arr
            .call_method1("astype", ("float64",))?
            .call_method0("ravel")?;
        let Ok(buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(slice) = buffer.as_slice(py) else {
            return Ok(None);
        };
        Ok(Some(slice.iter().map(|cell| cell.get()).collect()))
    };

    let Some(begin) = materialize(to_begin)? else {
        return Ok(None);
    };
    let Some(end) = materialize(to_end)? else {
        return Ok(None);
    };

    let total = begin.len() + n_diff + end.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (total,), Some(&kwargs))?;
    if total > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        let mut w = 0usize;
        for value in &begin {
            output[w].set(*value);
            w += 1;
        }
        for i in 0..n_diff {
            output[w].set(input[i + 1].get() - input[i].get());
            w += 1;
        }
        for value in &end {
            output[w].set(*value);
            w += 1;
        }
    }
    Ok(Some(flat.unbind()))
}

// Generic typed core for the integer ediff1d (flat consecutive differences, no
// to_begin/to_end). Reads the C-order `T` buffer (== numpy's ravel order) and
// writes wrapping out[i] = in[i+1] - in[i] into a fresh same-dtype buffer via a
// slice-iterator triple-zip so bounds checks elide and it autovectorizes.
fn ediff1d_typed<'py, T: pyo3::buffer::Element + Copy, F: Fn(T, T) -> T>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    ary: &Bound<'py, PyAny>,
    dtype_name: &str,
    sub: F,
) -> PyResult<Option<Py<PyAny>>> {
    let Ok(in_buffer) = PyBuffer::<T>::get(ary) else {
        return Ok(None);
    };
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let n_out = input.len().saturating_sub(1);
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", dtype_name)?;
    let flat = numpy.call_method("empty", (n_out,), Some(&kwargs))?;
    if n_out > 0 {
        let Ok(out_buffer) = PyBuffer::<T>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        for ((slot, cur), nxt) in output.iter().zip(input.iter()).zip(input[1..].iter()) {
            slot.set(sub(nxt.get(), cur.get()));
        }
    }
    Ok(Some(flat.unbind()))
}

// Zero-copy integer np.ediff1d (no to_begin/to_end), all widths. numpy flattens
// the input and returns the wrapping consecutive differences in the same dtype.
// Otherwise these extracted to an f64 Vec (~57x slower, lossy for wide ints).
// Returns None when to_begin/to_end are present (handled by the general path), a
// non-integer dtype, or a non-ndarray input.
fn try_zerocopy_int_ediff1d(
    py: Python<'_>,
    ary: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !ary.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = ary.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if kind != "i" && kind != "u" {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    match (kind.as_str(), itemsize) {
        ("i", 1) => ediff1d_typed::<i8, _>(py, &numpy, ary, "int8", |x, y| x.wrapping_sub(y)),
        ("i", 2) => ediff1d_typed::<i16, _>(py, &numpy, ary, "int16", |x, y| x.wrapping_sub(y)),
        ("i", 4) => ediff1d_typed::<i32, _>(py, &numpy, ary, "int32", |x, y| x.wrapping_sub(y)),
        ("i", 8) => ediff1d_typed::<i64, _>(py, &numpy, ary, "int64", |x, y| x.wrapping_sub(y)),
        ("u", 1) => ediff1d_typed::<u8, _>(py, &numpy, ary, "uint8", |x, y| x.wrapping_sub(y)),
        ("u", 2) => ediff1d_typed::<u16, _>(py, &numpy, ary, "uint16", |x, y| x.wrapping_sub(y)),
        ("u", 4) => ediff1d_typed::<u32, _>(py, &numpy, ary, "uint32", |x, y| x.wrapping_sub(y)),
        ("u", 8) => ediff1d_typed::<u64, _>(py, &numpy, ary, "uint64", |x, y| x.wrapping_sub(y)),
        _ => Ok(None),
    }
}

// Zero-copy np.ediff1d (no to_begin/to_end) for float32 ndarrays. numpy flattens
// the input in C order and returns out[i] = flat[i+1] - flat[i] in the same float32
// dtype. The f64 helper gates on float64, so float32 otherwise extracted to an f64
// Vec (~311x slower). Reuses the generic ediff1d_typed core with plain IEEE-754
// single-precision subtraction x - y (bit-identical; nan/inf/-0.0 propagate exactly).
// Returns None for a non-float32 dtype or a non-ndarray input.
fn try_zerocopy_f32_ediff1d(
    py: Python<'_>,
    ary: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !ary.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = ary.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 4
    {
        return Ok(None);
    }
    ediff1d_typed::<f32, _>(py, &numpy, ary, "float32", |x, y| x - y)
}

fn build_numpy_array_from_storage(
    py: Python<'_>,
    shape: &[usize],
    storage: ArrayStorage,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let array = match storage {
        // Numeric dtypes whose Rust storage matches the NumPy element layout copy
        // through the buffer protocol (see numpy_array_from_slice).
        ArrayStorage::I8(values) => numpy_array_from_slice(py, &numpy, &values, "int8")?,
        ArrayStorage::I16(values) => numpy_array_from_slice(py, &numpy, &values, "int16")?,
        ArrayStorage::I32(values) => numpy_array_from_slice(py, &numpy, &values, "int32")?,
        ArrayStorage::I64(values) => numpy_array_from_slice(py, &numpy, &values, "int64")?,
        ArrayStorage::U8(values) => numpy_array_from_slice(py, &numpy, &values, "uint8")?,
        ArrayStorage::U16(values) => numpy_array_from_slice(py, &numpy, &values, "uint16")?,
        ArrayStorage::U32(values) => numpy_array_from_slice(py, &numpy, &values, "uint32")?,
        ArrayStorage::U64(values) => numpy_array_from_slice(py, &numpy, &values, "uint64")?,
        ArrayStorage::F32(values) => numpy_array_from_slice(py, &numpy, &values, "float32")?,
        ArrayStorage::F64(values) => numpy_array_from_slice(py, &numpy, &values, "float64")?,
        // NumPy bool_ is a single byte (1 = True, 0 = False), so build the result
        // through the uint8 buffer fast path (one memcpy) and reinterpret it as
        // bool_ with a zero-copy .view — bit-identical to the old per-element
        // PyList construction, but without boxing each element into a Python bool.
        // Matters a lot for large boolean results (isin, comparisons, logical ops).
        ArrayStorage::Bool(values) => {
            let bytes: Vec<u8> = values.iter().map(|&b| u8::from(b)).collect();
            let u8_arr = numpy_array_from_slice(py, &numpy, &bytes, "uint8")?;
            let bool_dtype = numpy.getattr("bool_")?;
            u8_arr.call_method1("view", (bool_dtype,))?
        }
        ArrayStorage::F16(values) => {
            // Write the raw 2-byte values through the uint16 buffer fast path (one
            // memcpy) and reinterpret as float16 with a zero-copy .view — bit-identical
            // to the old per-element PyList(f32) construction, which boxed one Python
            // float per element (~1700x slower than numpy on a 4M abs/sqrt result).
            let bits: Vec<u16> = values.iter().map(|value| value.to_bits()).collect();
            let u16_arr = numpy_array_from_slice(py, &numpy, &bits, "uint16")?;
            u16_arr.call_method1("view", ("float16",))?
        }
        unsupported => {
            return Err(PyTypeError::new_err(format!(
                "fnp-python: cannot export dtype {} to NumPy yet",
                unsupported.dtype().name()
            )));
        }
    };

    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    Ok(array.call_method1("reshape", (&output_shape,))?.unbind())
}

fn build_numpy_array_from_ufunc(py: Python<'_>, array: &UFuncArray) -> PyResult<Py<PyAny>> {
    // Fast path for the overwhelmingly common float64 result with no integer
    // sidecar: the generic to_storage() path clones the value Vec, runs a
    // bridge-validity scan, and a cast_to(F64) element pass before the buffer
    // copy — three extra O(n) passes that are pure waste when the storage already
    // IS the f64 values. Copy array.values() straight into the NumPy buffer. f64
    // holds NaN/inf, so no validity gate is needed. Bit-identical to the generic
    // path (same bytes, same C-contiguous reshape).
    if array.dtype() == DType::F64 && !array.has_integer_sidecar() {
        let numpy = py.import("numpy")?;
        let flat = numpy_array_from_slice(py, &numpy, array.values(), "float64")?;
        let output_shape = PyTuple::new(py, array.shape().iter().copied())?;
        return Ok(flat.call_method1("reshape", (&output_shape,))?.unbind());
    }
    // Same fast path for exact integer (int64/uint64) results: the sidecar already
    // holds the bytes NumPy wants, so copy it straight into the buffer instead of
    // letting to_storage() clone the sidecar Vec first. Only when the dtype matches
    // the sidecar width (int64<->I64, uint64<->U64); other integer dtypes/casts keep
    // the generic path. Bit-identical (same integer values).
    if let Some(sidecar) = array.integer_sidecar() {
        let dtype_name = match (array.dtype(), sidecar) {
            (DType::I64, IntegerSidecar::I64(_)) => Some("int64"),
            (DType::U64, IntegerSidecar::U64(_)) => Some("uint64"),
            _ => None,
        };
        if let Some(name) = dtype_name {
            let numpy = py.import("numpy")?;
            let flat = match sidecar {
                IntegerSidecar::I64(v) => numpy_array_from_slice(py, &numpy, v, name)?,
                IntegerSidecar::U64(v) => numpy_array_from_slice(py, &numpy, v, name)?,
            };
            let output_shape = PyTuple::new(py, array.shape().iter().copied())?;
            return Ok(flat.call_method1("reshape", (&output_shape,))?.unbind());
        }
    }
    let storage = array.to_storage().map_err(map_ufunc_error)?;
    build_numpy_array_from_storage(py, array.shape(), storage)
}

// F-contiguous counterpart of build_numpy_array_from_ufunc. numpy's
// `ascontiguousarray` / `asfortranarray` / `order='F'` paths all need
// output whose `flags['F_CONTIGUOUS']` is True; our C-contig export
// bridge never satisfies that. Strategy: build the array C-contiguously
// (so logical element placement matches our row-major UFuncArray
// values), then `.copy(order='F')` to get an F-contig buffer with the
// same logical layout. For 1-D / 0-d arrays both flags are True and the
// copy is skipped.
fn build_numpy_array_from_ufunc_fortran(py: Python<'_>, array: &UFuncArray) -> PyResult<Py<PyAny>> {
    let c_contig = build_numpy_array_from_ufunc(py, array)?;
    if array.shape().len() < 2 {
        return Ok(c_contig);
    }
    let py_arr = c_contig.bind(py);
    let kwargs = PyDict::new(py);
    kwargs.set_item("order", "F")?;
    Ok(py_arr.call_method("copy", (), Some(&kwargs))?.unbind())
}

fn build_numpy_scalar_or_array(py: Python<'_>, array: &UFuncArray) -> PyResult<Py<PyAny>> {
    let output = build_numpy_array_from_ufunc(py, array)?;
    if array.shape().is_empty() {
        return Ok(output.bind(py).get_item(())?.unbind());
    }
    Ok(output)
}

fn build_numpy_masked_array(py: Python<'_>, array: &MaskedArray) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let ma = numpy.getattr("ma")?;
    let data = build_numpy_array_from_ufunc(py, array.data())?;
    let kwargs = PyDict::new(py);
    if let Some(mask) = array.mask() {
        let mask = build_numpy_array_from_ufunc(py, mask)?;
        kwargs.set_item("mask", mask.bind(py))?;
    } else {
        kwargs.set_item("mask", ma.getattr("nomask")?)?;
    }
    Ok(ma
        .getattr("array")?
        .call((data.bind(py),), Some(&kwargs))?
        .unbind())
}

// Retained for a future robust native eigvals; `eigvals` currently delegates to
// NumPy's LAPACK geev because the native QR solver did not reliably converge.
#[allow(dead_code)]
fn build_numpy_eigvals_vector_from_flat_interleaved(
    py: Python<'_>,
    values: &[f64],
    input_dtype: DType,
) -> PyResult<Py<PyAny>> {
    if !values.len().is_multiple_of(2) {
        return Err(PyTypeError::new_err(
            "complex output must contain flat interleaved real/imag pairs",
        ));
    }

    let numpy = py.import("numpy")?;
    let all_real = values.chunks_exact(2).all(|chunk| chunk[1] == 0.0);
    if all_real {
        let kwargs = PyDict::new(py);
        match input_dtype {
            DType::F32 => {
                let real_values = values
                    .chunks_exact(2)
                    .map(|chunk| chunk[0] as f32)
                    .collect::<Vec<_>>();
                kwargs.set_item("dtype", numpy.getattr("float32")?)?;
                return Ok(numpy
                    .getattr("array")?
                    .call(
                        (PyList::new(py, real_values.iter().copied())?,),
                        Some(&kwargs),
                    )?
                    .unbind());
            }
            _ => {
                let real_values = values
                    .chunks_exact(2)
                    .map(|chunk| chunk[0])
                    .collect::<Vec<_>>();
                kwargs.set_item("dtype", numpy.getattr("float64")?)?;
                return Ok(numpy
                    .getattr("array")?
                    .call(
                        (PyList::new(py, real_values.iter().copied())?,),
                        Some(&kwargs),
                    )?
                    .unbind());
            }
        }
    }

    let builtins = py.import("builtins")?;
    let complex_values = values
        .chunks_exact(2)
        .map(|chunk| builtins.getattr("complex")?.call1((chunk[0], chunk[1])))
        .collect::<PyResult<Vec<_>>>()?;
    let kwargs = PyDict::new(py);
    let complex_dtype = match input_dtype {
        DType::F32 => numpy.getattr("complex64")?,
        _ => numpy.getattr("complex128")?,
    };
    kwargs.set_item("dtype", complex_dtype)?;
    Ok(numpy
        .getattr("array")?
        .call((PyList::new(py, complex_values.iter())?,), Some(&kwargs))?
        .unbind())
}

#[allow(dead_code)]
fn extract_complex_interleaved_array(
    py: Python<'_>,
    value: &Bound<'_, PyAny>,
    context: &str,
) -> PyResult<UFuncArray> {
    let numpy = py.import("numpy")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", numpy.getattr("complex128")?)?;
    let array = numpy.call_method("asarray", (value,), Some(&kwargs))?;
    let shape = array.getattr("shape")?.extract::<Vec<usize>>()?;
    if shape.len() != 1 {
        return Err(PyTypeError::new_err(format!(
            "{context}: expected a 1-D complex array"
        )));
    }
    let flat = array.call_method1("reshape", (-1,))?;
    let real = flat
        .getattr("real")?
        .call_method0("tolist")?
        .extract::<Vec<f64>>()?;
    let imag = flat
        .getattr("imag")?
        .call_method0("tolist")?
        .extract::<Vec<f64>>()?;
    let mut values = Vec::with_capacity(real.len() * 2);
    for (&re, &im) in real.iter().zip(&imag) {
        values.push(re);
        values.push(im);
    }
    UFuncArray::new(vec![shape[0], 2], values, DType::F64).map_err(map_ufunc_error)
}

fn build_numpy_tuple_from_ufuncs(py: Python<'_>, arrays: &[UFuncArray]) -> PyResult<Py<PyAny>> {
    let arrays = arrays
        .iter()
        .map(|array| build_numpy_array_from_ufunc(py, array))
        .collect::<PyResult<Vec<_>>>()?;
    Ok(PyTuple::new(py, arrays.iter().map(|array| array.bind(py)))?
        .into_any()
        .unbind())
}

fn build_numpy_scalar_or_array_tuple(py: Python<'_>, arrays: &[UFuncArray]) -> PyResult<Py<PyAny>> {
    let arrays = arrays
        .iter()
        .map(|array| build_numpy_scalar_or_array(py, array))
        .collect::<PyResult<Vec<_>>>()?;
    Ok(PyTuple::new(py, arrays.iter().map(|array| array.bind(py)))?
        .into_any()
        .unbind())
}

#[allow(dead_code)]
fn build_numpy_list_from_ufuncs(py: Python<'_>, arrays: &[UFuncArray]) -> PyResult<Py<PyAny>> {
    let arrays = arrays
        .iter()
        .map(|array| build_numpy_array_from_ufunc(py, array))
        .collect::<PyResult<Vec<_>>>()?;
    Ok(PyList::new(py, arrays.iter().map(|array| array.bind(py)))?
        .into_any()
        .unbind())
}

fn build_numpy_scalar_or_array_from_ufunc(
    py: Python<'_>,
    array: &UFuncArray,
) -> PyResult<Py<PyAny>> {
    let output = build_numpy_array_from_ufunc(py, array)?;
    if array.shape().is_empty() {
        Ok(output.bind(py).get_item(())?.unbind())
    } else {
        Ok(output)
    }
}

fn build_numpy_index_tuple_from_ufuncs(
    py: Python<'_>,
    arrays: &[UFuncArray],
    scalar_output: bool,
) -> PyResult<Py<PyAny>> {
    if !scalar_output {
        return build_numpy_tuple_from_ufuncs(py, arrays);
    }

    let scalars = arrays
        .iter()
        .map(|array| {
            let output = build_numpy_array_from_ufunc(py, array)?;
            output.bind(py).get_item(())
        })
        .collect::<PyResult<Vec<_>>>()?;
    Ok(PyTuple::new(py, scalars.iter())?.into_any().unbind())
}

fn build_numpy_tuple_from_pyarrays(py: Python<'_>, arrays: &[Py<PyAny>]) -> PyResult<Py<PyAny>> {
    Ok(PyTuple::new(py, arrays.iter().map(|array| array.bind(py)))?
        .into_any()
        .unbind())
}

fn build_meshgrid_numpy_outputs(
    py: Python<'_>,
    arrays: &[Py<PyAny>],
    indexing: &str,
    sparse: bool,
    copy: bool,
) -> PyResult<Py<PyAny>> {
    validate_meshgrid_indexing(indexing)?;
    if arrays.is_empty() {
        return build_numpy_tuple_from_pyarrays(py, &[]);
    }

    let numpy = py.import("numpy")?;
    let ndim = arrays.len();
    let reshaped = arrays
        .iter()
        .enumerate()
        .map(|(index, array)| {
            let axis = meshgrid_output_axis(index, ndim, indexing);
            let mut shape = vec![1_usize; ndim];
            shape[axis] = array.bind(py).len()?;
            let shape = PyTuple::new(py, shape.iter().copied())?;
            Ok(array.bind(py).call_method1("reshape", (&shape,))?.unbind())
        })
        .collect::<PyResult<Vec<_>>>()?;

    let outputs = if sparse {
        reshaped
    } else {
        let broadcast = numpy.getattr("broadcast_arrays")?.call1(PyTuple::new(
            py,
            reshaped.iter().map(|array| array.bind(py)),
        )?)?;
        let broadcast = broadcast.cast::<PyTuple>()?;
        broadcast
            .try_iter()?
            .map(|item| Ok(item?.unbind()))
            .collect::<PyResult<Vec<_>>>()?
    };

    let outputs = if copy {
        outputs
            .into_iter()
            .map(|array| Ok(array.bind(py).call_method0("copy")?.unbind()))
            .collect::<PyResult<Vec<_>>>()?
    } else {
        outputs
    };

    build_numpy_tuple_from_pyarrays(py, &outputs)
}

fn frompyfunc_display_name(callable: &Bound<'_, PyAny>) -> String {
    let base_name = callable
        .getattr("__name__")
        .and_then(|name| name.extract::<String>())
        .unwrap_or_else(|_| "pyfunc".to_string());
    format!("{base_name} (vectorized)")
}

fn parse_frompyfunc_identity(
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<FromPyFuncReduceIdentity<Py<PyAny>>> {
    let Some(kwargs) = kwargs else {
        return Ok(FromPyFuncReduceIdentity::Omitted);
    };

    let mut identity = FromPyFuncReduceIdentity::Omitted;
    for (key, value) in kwargs.iter() {
        let key = key
            .extract::<String>()
            .map_err(|_| PyTypeError::new_err("frompyfunc() keywords must be strings"))?;
        match key.as_str() {
            "identity" => {
                identity = if value.is_none() {
                    FromPyFuncReduceIdentity::ReorderableNone
                } else {
                    FromPyFuncReduceIdentity::Value(value.unbind())
                };
            }
            other => {
                return Err(PyTypeError::new_err(format!(
                    "frompyfunc() got an unexpected keyword argument '{other}'",
                )));
            }
        }
    }

    Ok(identity)
}

fn extract_object_array_input(
    py: Python<'_>,
    value: &Bound<'_, PyAny>,
    context: &str,
) -> PyResult<(Vec<usize>, Vec<Py<PyAny>>)> {
    let numpy = py.import("numpy")?;
    let builtins = py.import("builtins")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", builtins.getattr("object")?)?;
    let array = numpy.call_method("asarray", (value,), Some(&kwargs))?;
    let shape = array.getattr("shape")?.extract::<Vec<usize>>()?;
    let flat = array.call_method1("reshape", (-1,))?;
    let values = flat
        .call_method0("tolist")?
        .extract::<Vec<Py<PyAny>>>()
        .map_err(|_| {
            PyTypeError::new_err(format!("{context}: failed to normalize object array"))
        })?;
    Ok((shape, values))
}

fn build_numpy_object_array_from_flat_values(
    py: Python<'_>,
    shape: &[usize],
    values: &[Py<PyAny>],
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let builtins = py.import("builtins")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", builtins.getattr("object")?)?;
    let list = PyList::new(py, values.iter().map(|value| value.bind(py)))?;
    let array = numpy.call_method("array", (list,), Some(&kwargs))?;
    let shape = PyTuple::new(py, shape.iter().copied())?;
    Ok(array.call_method1("reshape", (shape,))?.unbind())
}

fn build_numpy_scalar_or_array_from_object_values(
    py: Python<'_>,
    shape: &[usize],
    values: &[Py<PyAny>],
) -> PyResult<Py<PyAny>> {
    let array = build_numpy_object_array_from_flat_values(py, shape, values)?;
    if shape.is_empty() {
        Ok(array.bind(py).get_item(())?.unbind())
    } else {
        Ok(array)
    }
}

fn normalize_reduce_out_argument(py: Python<'_>, out: &Bound<'_, PyAny>) -> PyResult<Py<PyAny>> {
    let candidate = if let Ok(tuple) = out.cast::<PyTuple>() {
        if tuple.len() != 1 {
            return Err(PyTypeError::new_err("return arrays must be of ArrayType"));
        }
        tuple.get_item(0)?
    } else if out.cast::<PyList>().is_ok() {
        return Err(PyTypeError::new_err("return arrays must be of ArrayType"));
    } else {
        out.clone()
    };

    if require_numpy_ndarray(py, &candidate, "reduce(out)").is_err() {
        return Err(PyTypeError::new_err("return arrays must be of ArrayType"));
    }
    Ok(candidate.unbind())
}

fn extract_frompyfunc_reduce_axis_spec(
    py: Python<'_>,
    axis: Option<Py<PyAny>>,
) -> PyResult<FromPyFuncReduceAxisSpec> {
    let Some(axis) = axis else {
        return Ok(FromPyFuncReduceAxisSpec::Default);
    };

    let axis = axis.bind(py);
    if axis.is_none() {
        return Ok(FromPyFuncReduceAxisSpec::All);
    }

    if let Ok(axis) = axis.extract::<isize>() {
        return Ok(FromPyFuncReduceAxisSpec::Axis(axis));
    }

    if let Ok(iter) = axis.try_iter() {
        let axes = iter
            .enumerate()
            .map(|(index, item)| {
                item?.extract::<isize>().map_err(|_| {
                    PyTypeError::new_err(format!("reduce: axis[{index}] must be an integer"))
                })
            })
            .collect::<PyResult<Vec<_>>>()?;
        return Ok(FromPyFuncReduceAxisSpec::Axes(axes));
    }

    Err(PyTypeError::new_err(
        "reduce: axis must be an integer, tuple/list of integers, or None",
    ))
}

fn extract_frompyfunc_where_mask(
    py: Python<'_>,
    shape: &[usize],
    where_value: &Bound<'_, PyAny>,
) -> PyResult<Option<Vec<bool>>> {
    if where_value.is_instance_of::<PyBool>() {
        return if where_value.extract::<bool>()? {
            Ok(None)
        } else {
            Ok(Some(vec![
                false;
                element_count(shape).map_err(|err| {
                    PyValueError::new_err(err.to_string())
                })?
            ]))
        };
    }

    let numpy = py.import("numpy")?;
    let builtins = py.import("builtins")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", builtins.getattr("bool")?)?;
    let mask = numpy.call_method("asarray", (where_value,), Some(&kwargs))?;
    let shape = PyTuple::new(py, shape.iter().copied())?;
    let broadcast = numpy.call_method1("broadcast_to", (mask, shape))?;
    let flat = broadcast.call_method1("reshape", (-1,))?;
    Ok(Some(flat.call_method0("tolist")?.extract::<Vec<bool>>()?))
}

struct ParsedFromPyFuncReduce {
    array: Py<PyAny>,
    axis_spec: FromPyFuncReduceAxisSpec,
    out: Option<Py<PyAny>>,
    keepdims: bool,
    initial: Option<Py<PyAny>>,
    where_arg: Option<Py<PyAny>>,
}

fn set_reduce_kwarg<T>(slot: &mut Option<T>, value: T, name: &str) -> PyResult<()> {
    if slot.is_some() {
        Err(PyTypeError::new_err(format!(
            "reduce() got multiple values for argument '{name}'",
        )))
    } else {
        *slot = Some(value);
        Ok(())
    }
}

fn parse_frompyfunc_reduce_call(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<ParsedFromPyFuncReduce> {
    if args.is_empty() {
        return Err(PyTypeError::new_err(
            "reduce() missing required argument 'array' (pos 1)",
        ));
    }
    if args.len() > 7 {
        return Err(PyTypeError::new_err(format!(
            "reduce() takes at most 7 arguments ({} given)",
            args.len()
        )));
    }

    let array = args.get_item(0)?.unbind();
    let mut axis = args.get_item(1).ok().map(|value| value.unbind());
    let mut out = args
        .get_item(3)
        .ok()
        .filter(|value| !value.is_none())
        .map(|value| value.unbind());
    let mut keepdims = args
        .get_item(4)
        .ok()
        .map(|value| value.extract::<bool>())
        .transpose()?
        .unwrap_or(false);
    let mut initial = args
        .get_item(5)
        .ok()
        .filter(|value| !value.is_none())
        .map(|value| value.unbind());
    let mut where_arg = args.get_item(6).ok().map(|value| value.unbind());

    if let Some(kwargs) = kwargs {
        for (key, value) in kwargs.iter() {
            let key = key
                .extract::<String>()
                .map_err(|_| PyTypeError::new_err("reduce() keywords must be strings"))?;
            match key.as_str() {
                "axis" => set_reduce_kwarg(&mut axis, value.unbind(), "axis")?,
                "dtype" => {}
                "out" => {
                    if !value.is_none() {
                        set_reduce_kwarg(&mut out, value.unbind(), "out")?;
                    }
                }
                "keepdims" => {
                    if args.get_item(4).is_ok() {
                        return Err(PyTypeError::new_err(
                            "reduce() got multiple values for argument 'keepdims'",
                        ));
                    }
                    keepdims = value.extract::<bool>()?;
                }
                "initial" => {
                    if !value.is_none() {
                        set_reduce_kwarg(&mut initial, value.unbind(), "initial")?;
                    }
                }
                "where" => set_reduce_kwarg(&mut where_arg, value.unbind(), "where")?,
                other => {
                    return Err(PyTypeError::new_err(format!(
                        "reduce() got an unexpected keyword argument '{other}'",
                    )));
                }
            }
        }
    }

    Ok(ParsedFromPyFuncReduce {
        array,
        axis_spec: extract_frompyfunc_reduce_axis_spec(py, axis)?,
        out,
        keepdims,
        initial,
        where_arg,
    })
}

impl PyFromPyFunc {
    fn new_checked(
        callable: Py<PyAny>,
        nin: usize,
        nout: usize,
        kwargs: Option<&Bound<'_, PyDict>>,
        py: Python<'_>,
    ) -> PyResult<Self> {
        if !callable.bind(py).is_callable() {
            return Err(PyTypeError::new_err(
                "frompyfunc: callable_obj must be callable",
            ));
        }
        let display_name = frompyfunc_display_name(callable.bind(py));
        let identity = parse_frompyfunc_identity(kwargs)?;

        Ok(Self {
            callable,
            display_name,
            identity,
            nin,
            nout,
        })
    }

    fn call_bound(&self, py: Python<'_>, args: &Bound<'_, PyTuple>) -> PyResult<Py<PyAny>> {
        if args.len() != self.nin {
            return Err(PyValueError::new_err(format!(
                "frompyfunc: expected {} input arrays, got {}",
                self.nin,
                args.len()
            )));
        }

        let numpy = py.import("numpy")?;
        let builtins = py.import("builtins")?;
        let object_dtype = builtins.getattr("object")?;

        let mut input_shapes = Vec::with_capacity(args.len());
        let mut input_arrays = Vec::with_capacity(args.len());

        for arg in args.iter() {
            let kwargs = PyDict::new(py);
            kwargs.set_item("dtype", &object_dtype)?;

            let array = numpy.call_method("asarray", (arg,), Some(&kwargs))?;
            let shape = array.getattr("shape")?.extract::<Vec<usize>>()?;

            input_shapes.push(shape);
            input_arrays.push(array.unbind());
        }

        let shape_refs: Vec<&[usize]> = input_shapes.iter().map(Vec::as_slice).collect();
        let out_shape =
            broadcast_shapes(&shape_refs).map_err(|err| PyValueError::new_err(err.to_string()))?;
        let flat_len =
            element_count(&out_shape).map_err(|err| PyValueError::new_err(err.to_string()))?;
        let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
        let mut broadcasted_inputs = Vec::with_capacity(input_arrays.len());

        for array in input_arrays {
            let broadcasted =
                numpy.call_method1("broadcast_to", (array.bind(py), output_shape.clone()))?;
            let flattened = broadcasted.call_method1("reshape", (-1,))?;
            let list = flattened.call_method0("tolist")?;
            broadcasted_inputs.push(list.extract::<Vec<Py<PyAny>>>()?);
        }

        let mut outputs: Vec<Vec<Py<PyAny>>> = (0..self.nout)
            .map(|_| Vec::with_capacity(flat_len))
            .collect();

        for element_idx in 0..flat_len {
            let call_args = PyTuple::new(
                py,
                broadcasted_inputs
                    .iter()
                    .map(|values| values[element_idx].bind(py)),
            )?;
            let result = self.callable.bind(py).call1(call_args)?;

            if self.nout == 0 {
                continue;
            }

            if self.nout == 1 {
                outputs[0].push(result.unbind());
                continue;
            }

            if let Ok(values) = result.cast::<PyTuple>() {
                if values.len() != self.nout {
                    return Err(PyValueError::new_err(format!(
                        "frompyfunc: expected {} outputs, got {}",
                        self.nout,
                        values.len()
                    )));
                }

                for (output, value) in outputs.iter_mut().zip(values.iter()) {
                    output.push(value.unbind());
                }
                continue;
            }

            if let Ok(values) = result.cast::<PyList>() {
                if values.len() != self.nout {
                    return Err(PyValueError::new_err(format!(
                        "frompyfunc: expected {} outputs, got {}",
                        self.nout,
                        values.len()
                    )));
                }

                for (output, value) in outputs.iter_mut().zip(values.iter()) {
                    output.push(value.unbind());
                }
                continue;
            }

            return Err(PyTypeError::new_err(format!(
                "frompyfunc: callable must return a tuple or list with {} outputs",
                self.nout
            )));
        }

        let mut arrays = Vec::with_capacity(self.nout);
        for values in outputs {
            let list = PyList::new(py, values.iter().map(|value| value.bind(py)))?;
            let kwargs = PyDict::new(py);
            kwargs.set_item("dtype", &object_dtype)?;
            let array = numpy.call_method("array", (list,), Some(&kwargs))?;
            let reshaped = array.call_method1("reshape", (&output_shape,))?;
            arrays.push(reshaped.unbind());
        }

        if self.nout == 1 {
            Ok(arrays.remove(0))
        } else {
            Ok(PyTuple::new(py, arrays.iter().map(|array| array.bind(py)))?
                .into_any()
                .unbind())
        }
    }
}

impl PyVectorize {
    fn new_checked(
        callable: Py<PyAny>,
        otypes: Option<Py<PyAny>>,
        signature: Option<Py<PyAny>>,
        excluded: Option<Vec<usize>>,
        py: Python<'_>,
    ) -> PyResult<Self> {
        if !callable.bind(py).is_callable() {
            return Err(PyTypeError::new_err(
                "vectorize: callable_obj must be callable",
            ));
        }

        let mut excluded = excluded.unwrap_or_default();
        excluded.sort_unstable();
        excluded.dedup();

        let otypes = otypes.filter(|value| !value.bind(py).is_none());
        let signature = signature.filter(|value| !value.bind(py).is_none());

        Ok(Self {
            callable,
            excluded,
            otypes,
            signature,
        })
    }

    fn infer_output_dtype(
        py: Python<'_>,
        numpy: &Bound<'_, PyModule>,
        value: &Bound<'_, PyAny>,
    ) -> PyResult<Py<PyAny>> {
        let probe = PyList::new(py, [value])?;
        Ok(numpy
            .call_method1("array", (probe,))?
            .getattr("dtype")?
            .unbind())
    }

    fn call_bound(&self, py: Python<'_>, args: &Bound<'_, PyTuple>) -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;

        // A gufunc `signature=` changes broadcasting in ways the native
        // per-element path does not model, so delegate the whole call to
        // numpy.vectorize (carrying otypes/excluded for parity).
        if let Some(sig) = self.signature.as_ref() {
            let kwargs = PyDict::new(py);
            kwargs.set_item("signature", sig.bind(py))?;
            if let Some(ot) = self.otypes.as_ref() {
                kwargs.set_item("otypes", ot.bind(py))?;
            }
            if !self.excluded.is_empty() {
                kwargs.set_item("excluded", PyList::new(py, self.excluded.iter().copied())?)?;
            }
            let np_vec = numpy
                .getattr("vectorize")?
                .call((self.callable.bind(py),), Some(&kwargs))?;
            return Ok(np_vec.call1(args)?.unbind());
        }

        if args.is_empty() {
            return Err(PyValueError::new_err(
                "vectorize: need at least one input array",
            ));
        }

        // Resolve forced output dtype(s) from `otypes=` (typecode string or a
        // sequence of dtype-likes); None means infer from the first result.
        let forced_dtypes: Option<Vec<Py<PyAny>>> = match self.otypes.as_ref() {
            Some(otypes) => {
                let otypes = otypes.bind(py);
                let dtype_fn = numpy.getattr("dtype")?;
                let mut resolved = Vec::new();
                if let Ok(codes) = otypes.extract::<String>() {
                    for code in codes.chars() {
                        resolved.push(dtype_fn.call1((code.to_string(),))?.unbind());
                    }
                } else {
                    for item in otypes.try_iter()? {
                        resolved.push(dtype_fn.call1((item?,))?.unbind());
                    }
                }
                Some(resolved)
            }
            None => None,
        };

        let mut vectorized_shapes = Vec::new();
        let mut slots = Vec::with_capacity(args.len());

        for (idx, arg) in args.iter().enumerate() {
            if self.excluded.binary_search(&idx).is_ok() {
                slots.push(VectorizeArgSlot::Fixed(arg.unbind()));
                continue;
            }

            let array = numpy.call_method1("asarray", (arg,))?;
            let shape = array.getattr("shape")?.extract::<Vec<usize>>()?;
            vectorized_shapes.push(shape);
            slots.push(VectorizeArgSlot::PendingArray(array.unbind()));
        }

        let out_shape = if vectorized_shapes.is_empty() {
            Vec::new()
        } else {
            let shape_refs: Vec<&[usize]> = vectorized_shapes.iter().map(Vec::as_slice).collect();
            broadcast_shapes(&shape_refs).map_err(|err| PyValueError::new_err(err.to_string()))?
        };
        let flat_len = if out_shape.is_empty() {
            1
        } else {
            element_count(&out_shape).map_err(|err| PyValueError::new_err(err.to_string()))?
        };
        let output_shape = PyTuple::new(py, out_shape.iter().copied())?;

        let mut prepared_slots = Vec::with_capacity(slots.len());
        for slot in slots {
            match slot {
                VectorizeArgSlot::Fixed(value) => {
                    prepared_slots.push(VectorizeArgSlot::Fixed(value))
                }
                VectorizeArgSlot::PendingArray(array) => {
                    let broadcasted = numpy
                        .call_method1("broadcast_to", (array.bind(py), output_shape.clone()))?;
                    let flattened = broadcasted.call_method1("reshape", (-1,))?;
                    let values = flattened
                        .call_method0("tolist")?
                        .extract::<Vec<Py<PyAny>>>()?;
                    prepared_slots.push(VectorizeArgSlot::Broadcast(values));
                }
                VectorizeArgSlot::Broadcast(_) => unreachable!("pending slots are prepared once"),
            }
        }

        let mut outputs: Vec<Vec<Py<PyAny>>> = Vec::new();
        let mut output_dtypes: Vec<Py<PyAny>> = Vec::new();

        for element_idx in 0..flat_len {
            let call_args = PyTuple::new(
                py,
                prepared_slots.iter().map(|slot| match slot {
                    VectorizeArgSlot::Fixed(value) => value.bind(py),
                    VectorizeArgSlot::Broadcast(values) => values[element_idx].bind(py),
                    VectorizeArgSlot::PendingArray(_) => unreachable!("pending slots are prepared"),
                }),
            )?;
            let result = self.callable.bind(py).call1(call_args)?;
            let values = if let Ok(tuple) = result.cast::<PyTuple>() {
                tuple.iter().map(|value| value.unbind()).collect::<Vec<_>>()
            } else {
                vec![result.unbind()]
            };

            if outputs.is_empty() {
                outputs = (0..values.len())
                    .map(|_| Vec::with_capacity(flat_len))
                    .collect();
            } else if values.len() != outputs.len() {
                return Err(PyValueError::new_err(format!(
                    "vectorize: output arity changed from {} to {}",
                    outputs.len(),
                    values.len()
                )));
            }

            for (output_idx, value) in values.into_iter().enumerate() {
                if output_dtypes.len() == output_idx {
                    let dtype = match forced_dtypes.as_ref() {
                        Some(dtypes) => dtypes
                            .get(output_idx)
                            .map(|d| d.clone_ref(py))
                            .ok_or_else(|| {
                                PyValueError::new_err(format!(
                                    "vectorize: otypes specifies {} dtype(s) but the function \
                                     produced output {}",
                                    dtypes.len(),
                                    output_idx + 1
                                ))
                            })?,
                        None => Self::infer_output_dtype(py, &numpy, value.bind(py))?,
                    };
                    output_dtypes.push(dtype);
                }
                outputs[output_idx].push(value);
            }
        }

        // Empty inputs never enter the per-element loop; with `otypes` set we
        // still return correctly-typed empty outputs (NumPy parity).
        if outputs.is_empty()
            && let Some(dtypes) = forced_dtypes.as_ref()
        {
            outputs = dtypes.iter().map(|_| Vec::new()).collect();
            output_dtypes = dtypes.iter().map(|d| d.clone_ref(py)).collect();
        }

        let mut arrays = Vec::with_capacity(outputs.len());
        for (values, dtype) in outputs.into_iter().zip(output_dtypes) {
            let list = PyList::new(py, values.iter().map(|value| value.bind(py)))?;
            let kwargs = PyDict::new(py);
            kwargs.set_item("dtype", dtype.bind(py))?;
            let array = numpy.call_method("array", (list,), Some(&kwargs))?;
            let reshaped = array.call_method1("reshape", (&output_shape,))?;
            arrays.push(reshaped.unbind());
        }

        if arrays.len() == 1 {
            Ok(arrays.remove(0))
        } else {
            Ok(PyTuple::new(py, arrays.iter().map(|array| array.bind(py)))?
                .into_any()
                .unbind())
        }
    }
}

