#[pyfunction]
#[pyo3(
    signature = (*args, **kwargs),
    text_signature = "(x, /, out=None, *, where=True, casting='same_kind', order='K', dtype=None, subok=True, signature=None)"
)]
fn spacing(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    // out=/where=/dtype= etc → numpy passthrough (matches np.spacing accepting out=).
    if !(kwargs.is_none_or(|kwargs| kwargs.is_empty()) && args.len() == 1) {
        return core_numpy_passthrough(py, "spacing", args, kwargs);
    }
    let x: Py<PyAny> = args.get_item(0)?.unbind();
    // NumPy's spacing returns a float result whose width follows numpy's type
    // resolution: float32 -> float32, float16 -> float16, and integer inputs map to
    // float16 (int8/uint8), float32 (int16/uint16), or float64 (wider ints).
    // extract_numeric_array canonicalizes every narrow width to f64, so the native
    // kernel only matches numpy for float64 input; defer all other dtypes to numpy.
    if !numpy_dtype_is_f64(py, x.bind(py)) {
        let numpy = py.import("numpy")?;
        return Ok(numpy.getattr("spacing")?.call1((x.bind(py),))?.unbind());
    }
    // Zero-copy fast path: read the contiguous f64 buffer and write spacing(v) straight
    // into the np.empty output (no extract-to-Vec + rebuild, which was ~6x slower than
    // numpy from the extra full-size copies + cold page faults). The per-element formula
    // is byte-identical to ufunc_spacing (UFuncArray::spacing).
    let numpy = py.import("numpy")?;
    if let Some((flat, shape)) = zerocopy_f64_unary_flat_with(py, &numpy, x.bind(py), |v| {
        if v.is_nan() || v.is_infinite() {
            f64::NAN
        } else if v == 0.0 {
            f64::from_bits(1)
        } else {
            let abs_v = v.abs();
            let s = f64::from_bits(abs_v.to_bits().wrapping_add(1)) - abs_v;
            if v.is_sign_negative() { -s } else { s }
        }
    })? {
        let output_shape = PyTuple::new(py, shape.iter().copied())?;
        let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
        if shape.is_empty() {
            return Ok(output.bind(py).get_item(())?.unbind());
        }
        return Ok(output);
    }
    let x = extract_numeric_array(py, x.bind(py), "spacing(x)")?;
    let result = ufunc_spacing(&x).map_err(map_ufunc_error)?;
    build_numpy_scalar_or_array(py, &result)
}

#[pyfunction]
#[pyo3(
    signature = (*args, **kwargs),
    text_signature = "(x, /, out=None, *, where=True, casting='same_kind', order='K', dtype=None, subok=True, signature=None)"
)]
fn sign(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    // out=/where=/dtype= etc → numpy passthrough (full ufunc kwarg surface, matching
    // np.sign which accepts out=). Bare single-arg call uses the native fast paths below.
    if !(kwargs.is_none_or(|kwargs| kwargs.is_empty()) && args.len() == 1) {
        return core_numpy_passthrough(py, "sign", args, kwargs);
    }
    let x: Py<PyAny> = args.get_item(0)?.unbind();
    let numpy = py.import("numpy")?;
    let arr = numpy.call_method1("asarray", (x.bind(py),))?;
    let dtype_kind = arr.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
    // Native UnaryOp::Sign only covers real numeric dtypes. Delegate every
    // other kind to numpy.sign so it matches exactly: timedelta64 ('m') yields
    // signs, while complex ('c'), datetime64 ('M'), string, etc. raise numpy's
    // own error rather than our generic numeric-only TypeError.
    if !matches!(dtype_kind.as_str(), "b" | "i" | "u" | "f") {
        return Ok(numpy.getattr("sign")?.call1((arr,))?.unbind());
    }
    if let Some(out) = try_zerocopy_f64_unary(py, x.bind(py), UnaryOp::Sign)? {
        return Ok(out);
    }
    // float32 input must stay float32; the extract path below widens to f64.
    if let Some(out) = try_zerocopy_f32_unary(py, x.bind(py), UnaryOp::Sign)? {
        return Ok(out);
    }
    // Integer input keeps its dtype (signed -1/0/1, unsigned 0/1); the extract
    // path widens to f64 and is lossy for wide ints.
    if let Some(out) = try_zerocopy_int_sign(py, x.bind(py))? {
        return Ok(out);
    }
    // float16 (and any non-contiguous narrow input that slipped the typed fast paths)
    // would be widened to f64 by extract_numeric_array; numpy keeps the input float
    // width (e.g. sign(float16) -> float16). Defer every non-f64 input to numpy.sign.
    if !numpy_dtype_is_f64(py, x.bind(py)) {
        return Ok(numpy.getattr("sign")?.call1((arr,))?.unbind());
    }
    // Non-contiguous (transposed/strided) ndarrays bail the zero-copy path into the
    // cold extract → rebuild (transpose-copy, ~5.6x slower). Delegate to numpy.
    if x.bind(py).is_exact_instance(&numpy.getattr("ndarray")?)
        && !x
            .bind(py)
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return Ok(numpy.getattr("sign")?.call1((arr,))?.unbind());
    }
    let x = extract_numeric_array(py, x.bind(py), "sign(x)")?;
    build_numpy_scalar_or_array(py, &x.elementwise_unary(UnaryOp::Sign))
}

fn native_rounding_unary(
    py: Python<'_>,
    x: &Bound<'_, PyAny>,
    op: UnaryOp,
    numpy_name: &str,
    extract_label: &str,
) -> PyResult<Py<PyAny>> {
    // NumPy's floor/ceil/trunc preserve the input dtype exactly (int32 -> int32,
    // float32 -> float32, bool -> bool). extract_numeric_array canonicalizes narrow
    // widths, so the native path only matches NumPy for float64; defer the rest.
    if !numpy_dtype_is_f64(py, x) {
        let numpy = py.import("numpy")?;
        return Ok(numpy.getattr(numpy_name)?.call1((x,))?.unbind());
    }
    if let Some(out) = try_zerocopy_f64_unary(py, x, op)? {
        return Ok(out);
    }
    // Non-contiguous (transposed/strided) ndarrays bail the zero-copy path into the
    // cold extract → rebuild (transpose-copy, ~6x slower than numpy's strided ufunc).
    // Delegate them to numpy.
    let numpy = py.import("numpy")?;
    if x.is_exact_instance(&numpy.getattr("ndarray")?)
        && !x
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return Ok(numpy.getattr(numpy_name)?.call1((x,))?.unbind());
    }
    let x = extract_numeric_array(py, x, extract_label)?;
    build_numpy_scalar_or_array(py, &x.elementwise_unary(op))
}

fn floor_native(py: Python<'_>, x: &Bound<'_, PyAny>) -> PyResult<Py<PyAny>> {
    native_rounding_unary(py, x, UnaryOp::Floor, "floor", "floor(x)")
}

