#[pyfunction]
#[pyo3(
    signature = (*args, **kwargs),
    text_signature = "(x1, x2, /, out=None, *, where=True, casting='same_kind', order='K', dtype=None, subok=True, signature=None)"
)]
fn nextafter(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    // out=/where=/dtype= etc → numpy passthrough (matches np.nextafter accepting out=).
    if !(kwargs.is_none_or(|kwargs| kwargs.is_empty()) && args.len() == 2) {
        return core_numpy_passthrough(py, "nextafter", args, kwargs);
    }
    let x1: Py<PyAny> = args.get_item(0)?.unbind();
    let x2: Py<PyAny> = args.get_item(1)?.unbind();
    let numpy = py.import("numpy")?;
    if !numpy_dtype_is_f64(py, x1.bind(py)) || !numpy_dtype_is_f64(py, x2.bind(py)) {
        return Ok(numpy
            .getattr("nextafter")?
            .call1((x1.bind(py), x2.bind(py)))?
            .unbind());
    }
    if noncontiguous_ndarray(&numpy, x1.bind(py))? || noncontiguous_ndarray(&numpy, x2.bind(py))? {
        return Ok(numpy
            .getattr("nextafter")?
            .call1((x1.bind(py), x2.bind(py)))?
            .unbind());
    }
    if let Some(out) = try_zerocopy_f64_binary(py, x1.bind(py), x2.bind(py), BinaryOp::Nextafter)? {
        return Ok(out);
    }
    // Scalar / broadcasting f64 operands: ufunc_nextafter's extract+broadcast is 5-10x slower than
    // numpy's C nextafter (scalar 10x, row/col-bcast 5-6x; same-shape won above). Delegate. (BlackThrush 2026-06-23.)
    Ok(numpy
        .getattr("nextafter")?
        .call1((x1.bind(py), x2.bind(py)))?
        .unbind())
}

