// Per-element frexp == numpy: x = m * 2^e with |m| in [0.5, 1.0); zero preserves
// its sign with e=0; nan/inf pass through with e=0. Subnormals are normalized by
// scaling up by 2^54 (exact) and subtracting 54 from the exponent — this avoids
// the `v / 2^exp` underflow-to-0.0 (=> inf) that the older decomposition hit on
// the minimum subnormal 5e-324, where numpy returns (0.5, -1073).
#[inline(always)]
fn frexp_one(v: f64) -> (f64, i32) {
    if v == 0.0 {
        return (v, 0); // preserves the sign of zero
    }
    if v.is_nan() {
        return (f64::from_bits(v.to_bits() | (1_u64 << 51)), 0);
    }
    if v.is_infinite() {
        return (v, 0);
    }
    let mut bits = v.to_bits();
    let mut extra = 0i32;
    let mut biased = ((bits >> 52) & 0x7FF) as i32;
    if biased == 0 {
        // Subnormal: scale into the normal range (2.0^54 is exact, no underflow).
        let scaled = v * f64::from_bits(0x4350_0000_0000_0000);
        bits = scaled.to_bits();
        biased = ((bits >> 52) & 0x7FF) as i32;
        extra = -54;
    }
    // Replace the biased-exponent field with 1022 so |m| lands in [0.5, 1.0),
    // keeping sign + fraction; the removed power of two becomes the exponent.
    let m_bits = (bits & !0x7FF0_0000_0000_0000) | (1022_u64 << 52);
    (f64::from_bits(m_bits), biased - 1022 + extra)
}

// Zero-copy frexp for an exact f64 C-contiguous ndarray: read the input buffer
// and write the mantissa (float64) and exponent (int32, the dtype numpy
// exposes) into two fresh buffers — no cold extract Vec, no per-element I32
// re-collect. Bit-identical to the ufunc_frexp path. Returns None for 0-d
// (scalar tuple unwrap stays on the slow path) and any non-f64 / non-ndarray.
fn try_zerocopy_f64_frexp(py: Python<'_>, x: &Bound<'_, PyAny>) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    if !x.is_exact_instance(&numpy.getattr("ndarray")?) {
        return Ok(None);
    }
    if x.getattr("dtype")?.getattr("kind")?.extract::<String>()? != "f"
        || !numpy_dtype_is_f64(py, x)
    {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(x) else {
        return Ok(None);
    };
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    if shape.is_empty() {
        return Ok(None);
    }
    let n = input.len();
    let mkw = PyDict::new(py);
    mkw.set_item("dtype", "float64")?;
    let mantissa = numpy.call_method("empty", (n,), Some(&mkw))?;
    let ekw = PyDict::new(py);
    ekw.set_item("dtype", "int32")?;
    let exponent = numpy.call_method("empty", (n,), Some(&ekw))?;
    if n > 0 {
        let (Ok(m_buf), Ok(e_buf)) = (
            PyBuffer::<f64>::get(&mantissa),
            PyBuffer::<i32>::get(&exponent),
        ) else {
            return Ok(None);
        };
        let (Some(m_out), Some(e_out)) = (m_buf.as_mut_slice(py), e_buf.as_mut_slice(py)) else {
            return Ok(None);
        };
        // SAFETY: ReadOnlyCell<f64>/Cell<f64>/Cell<i32> are repr(transparent); `input` is
        // read-only under the GIL and the two output buffers are fresh numpy.empty arrays we
        // own (no alias). par_chunks_mut splits into disjoint, non-overlapping slices.
        let data: &[f64] = unsafe { std::slice::from_raw_parts(input.as_ptr().cast::<f64>(), n) };
        let m_slice: &mut [f64] =
            unsafe { std::slice::from_raw_parts_mut(m_out.as_ptr() as *mut f64, n) };
        let e_slice: &mut [i32] =
            unsafe { std::slice::from_raw_parts_mut(e_out.as_ptr() as *mut i32, n) };
        let kernel = |m: &mut [f64], e: &mut [i32], d: &[f64]| {
            for ((ms, es), &v) in m.iter_mut().zip(e.iter_mut()).zip(d) {
                let (mm, ee) = frexp_one(v);
                *ms = mm;
                *es = ee;
            }
        };
        // frexp reads n f64 + writes n f64 + n i32 (~20n bytes, memory-bound); numpy runs it
        // single-threaded, so multi-threaded chunks win the DRAM bandwidth at large n.
        const FREXP_PARALLEL_MIN: usize = 1 << 19;
        if n >= FREXP_PARALLEL_MIN && rayon::current_num_threads() >= 2 {
            use rayon::prelude::*;
            let chunk = n.div_ceil(rayon::current_num_threads());
            m_slice
                .par_chunks_mut(chunk)
                .zip(e_slice.par_chunks_mut(chunk))
                .zip(data.par_chunks(chunk))
                .for_each(|((m, e), d)| kernel(m, e, d));
        } else {
            kernel(m_slice, e_slice, data);
        }
    }
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let mantissa = mantissa.call_method1("reshape", (&output_shape,))?;
    let exponent = exponent.call_method1("reshape", (&output_shape,))?;
    Ok(Some(
        PyTuple::new(py, [&mantissa, &exponent])?
            .into_any()
            .unbind(),
    ))
}

// f32 counterpart of try_zerocopy_f64_frexp. numpy.frexp(float32) -> (mantissa float32, exponent
// int32). For an f32 value x = m*2^e (m in [0.5,1)), m is exactly representable in f32, so computing
// frexp_one(x as f64) and casting the mantissa back to f32 is bit-identical to numpy's frexpf.
fn try_zerocopy_f32_frexp(py: Python<'_>, x: &Bound<'_, PyAny>) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    if !x.is_exact_instance(&numpy.getattr("ndarray")?) || !numpy_dtype_is_f32(x) {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f32>::get(x) else {
        return Ok(None);
    };
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    if shape.is_empty() {
        return Ok(None);
    }
    let n = input.len();
    let mkw = PyDict::new(py);
    mkw.set_item("dtype", "float32")?;
    let mantissa = numpy.call_method("empty", (n,), Some(&mkw))?;
    let ekw = PyDict::new(py);
    ekw.set_item("dtype", "int32")?;
    let exponent = numpy.call_method("empty", (n,), Some(&ekw))?;
    if n > 0 {
        let (Ok(m_buf), Ok(e_buf)) = (
            PyBuffer::<f32>::get(&mantissa),
            PyBuffer::<i32>::get(&exponent),
        ) else {
            return Ok(None);
        };
        let (Some(m_out), Some(e_out)) = (m_buf.as_mut_slice(py), e_buf.as_mut_slice(py)) else {
            return Ok(None);
        };
        // SAFETY: repr(transparent) cells; input read-only under GIL; outputs are fresh owned arrays.
        let data: &[f32] = unsafe { std::slice::from_raw_parts(input.as_ptr().cast::<f32>(), n) };
        let m_slice: &mut [f32] =
            unsafe { std::slice::from_raw_parts_mut(m_out.as_ptr() as *mut f32, n) };
        let e_slice: &mut [i32] =
            unsafe { std::slice::from_raw_parts_mut(e_out.as_ptr() as *mut i32, n) };
        let kernel = |m: &mut [f32], e: &mut [i32], d: &[f32]| {
            for ((ms, es), &v) in m.iter_mut().zip(e.iter_mut()).zip(d) {
                let (mm, ee) = frexp_one(v as f64);
                *ms = mm as f32;
                *es = ee;
            }
        };
        const FREXP_PARALLEL_MIN: usize = 1 << 19;
        if n >= FREXP_PARALLEL_MIN && rayon::current_num_threads() >= 2 {
            use rayon::prelude::*;
            let chunk = n.div_ceil(rayon::current_num_threads());
            m_slice
                .par_chunks_mut(chunk)
                .zip(e_slice.par_chunks_mut(chunk))
                .zip(data.par_chunks(chunk))
                .for_each(|((m, e), d)| kernel(m, e, d));
        } else {
            kernel(m_slice, e_slice, data);
        }
    }
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let mantissa = mantissa.call_method1("reshape", (&output_shape,))?;
    let exponent = exponent.call_method1("reshape", (&output_shape,))?;
    Ok(Some(
        PyTuple::new(py, [&mantissa, &exponent])?.into_any().unbind(),
    ))
}

#[pyfunction]
fn frexp(py: Python<'_>, x: Py<PyAny>) -> PyResult<Py<PyAny>> {
    if let Some(out) = try_zerocopy_f64_frexp(py, x.bind(py))? {
        return Ok(out);
    }
    if let Some(out) = try_zerocopy_f32_frexp(py, x.bind(py))? {
        return Ok(out);
    }
    // numpy.frexp preserves the input float width for the mantissa (float16->float16,
    // float32->float32) and resolves integer inputs to float16 (int8/uint8),
    // float32 (int16/uint16), or float64 (wider ints); the exponent is always int32.
    // extract_numeric_array canonicalizes every narrow dtype to f64, so the native
    // kernel only matches numpy for float64 input; defer all other dtypes to numpy.frexp.
    if !numpy_dtype_is_f64(py, x.bind(py)) {
        let numpy = py.import("numpy")?;
        return Ok(numpy.getattr("frexp")?.call1((x.bind(py),))?.unbind());
    }
    let x = extract_numeric_array(py, x.bind(py), "frexp(x)")?;
    let is_scalar = x.shape().is_empty();
    let (mantissas, exponents) = ufunc_frexp(&x).map_err(map_ufunc_error)?;
    let mantissa = build_numpy_array_from_ufunc(py, &mantissas)?;
    // NumPy exposes the exponent output as an integer array.
    let exponent = build_numpy_array_from_storage(
        py,
        exponents.shape(),
        ArrayStorage::I32(
            exponents
                .values()
                .iter()
                .map(|value| *value as i32)
                .collect(),
        ),
    )?;
    // For scalar inputs, unwrap 0-d arrays to numpy scalars.
    if is_scalar {
        let mantissa_scalar = mantissa.bind(py).get_item(())?.unbind();
        let exponent_scalar = exponent.bind(py).get_item(())?.unbind();
        Ok(
            PyTuple::new(py, [mantissa_scalar.bind(py), exponent_scalar.bind(py)])?
                .into_any()
                .unbind(),
        )
    } else {
        Ok(PyTuple::new(py, [mantissa.bind(py), exponent.bind(py)])?
            .into_any()
            .unbind())
    }
}

// Zero-copy modf for exact f64 C-contiguous ndarrays. numpy.modf returns
// (fractional, integral): integral = trunc(x) toward zero, and fractional carries
// the sign of x. A single vectorizable pass writes both output buffers directly,
// replacing extract -> ufunc_modf -> two array builds. Unsupported layouts and
// 0-d arrays defer to the existing path so scalar tuple unwrapping and fallback
// parity stay unchanged.
fn try_zerocopy_f64_modf(py: Python<'_>, x: &Bound<'_, PyAny>) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !x.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = x.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    let ndim = x.getattr("ndim")?.extract::<usize>()?;
    if ndim == 0 {
        return Ok(None); // 0-d returns numpy scalars — keep the existing path
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(x) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() {
        return Ok(None);
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let shape = x.getattr("shape")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let frac_arr = numpy.call_method("empty", (&shape,), Some(&kwargs))?;
    let int_arr = numpy.call_method("empty", (&shape,), Some(&kwargs))?;
    if !cells.is_empty() {
        let (Ok(frac_buf), Ok(int_buf)) = (
            PyBuffer::<f64>::get(&frac_arr),
            PyBuffer::<f64>::get(&int_arr),
        ) else {
            return Ok(None);
        };
        let (Some(frac_out), Some(int_out)) = (frac_buf.as_mut_slice(py), int_buf.as_mut_slice(py))
        else {
            return Ok(None);
        };
        for ((c, fo), io) in cells.iter().zip(frac_out.iter()).zip(int_out.iter()) {
            let v = c.get();
            let t = v.trunc();
            io.set(t);
            let base = if v.is_infinite() { 0.0 } else { v - t };
            fo.set(base.copysign(v));
        }
    }
    Ok(Some(PyTuple::new(py, [frac_arr, int_arr])?.unbind().into()))
}

// f32 counterpart of try_zerocopy_f64_modf. numpy.modf(float32) -> (fractional f32, integral f32),
// both computed in f32 (integral = trunc toward zero; fractional carries the sign of x) -> the same
// f32 ops are bit-identical to numpy. Non-f32 / 0-d / non-contiguous defer.
fn try_zerocopy_f32_modf(py: Python<'_>, x: &Bound<'_, PyAny>) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    if !x.is_exact_instance(&numpy.getattr("ndarray")?) || !numpy_dtype_is_f32(x) {
        return Ok(None);
    }
    if x.getattr("ndim")?.extract::<usize>()? == 0 {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f32>::get(x) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() {
        return Ok(None);
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let shape = x.getattr("shape")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float32")?;
    let frac_arr = numpy.call_method("empty", (&shape,), Some(&kwargs))?;
    let int_arr = numpy.call_method("empty", (&shape,), Some(&kwargs))?;
    if !cells.is_empty() {
        let (Ok(frac_buf), Ok(int_buf)) = (
            PyBuffer::<f32>::get(&frac_arr),
            PyBuffer::<f32>::get(&int_arr),
        ) else {
            return Ok(None);
        };
        let (Some(frac_out), Some(int_out)) = (frac_buf.as_mut_slice(py), int_buf.as_mut_slice(py))
        else {
            return Ok(None);
        };
        for ((c, fo), io) in cells.iter().zip(frac_out.iter()).zip(int_out.iter()) {
            let v = c.get();
            let t = v.trunc();
            io.set(t);
            let base = if v.is_infinite() { 0.0 } else { v - t };
            fo.set(base.copysign(v));
        }
    }
    Ok(Some(PyTuple::new(py, [frac_arr, int_arr])?.unbind().into()))
}

#[pyfunction]
fn modf(py: Python<'_>, x: Py<PyAny>) -> PyResult<Py<PyAny>> {
    if let Some(out) = try_zerocopy_f64_modf(py, x.bind(py))? {
        return Ok(out);
    }
    if let Some(out) = try_zerocopy_f32_modf(py, x.bind(py))? {
        return Ok(out);
    }
    // numpy.modf preserves the input float width for both outputs (float16->float16,
    // float32->float32) and resolves integer inputs to float16 (int8/uint8),
    // float32 (int16/uint16), or float64 (wider ints). extract_numeric_array
    // canonicalizes every narrow dtype to f64, so the native kernel only matches
    // numpy for float64 input; defer all other dtypes to numpy.modf for exact parity.
    if !numpy_dtype_is_f64(py, x.bind(py)) {
        let numpy = py.import("numpy")?;
        return Ok(numpy.getattr("modf")?.call1((x.bind(py),))?.unbind());
    }
    let x = extract_numeric_array(py, x.bind(py), "modf(x)")?;
    let (fractional, integral) = ufunc_modf(&x).map_err(map_ufunc_error)?;
    let outputs = [fractional, integral];
    build_numpy_scalar_or_array_tuple(py, &outputs)
}

#[pyfunction]
#[pyo3(signature = (x, copy=true, nan=0.0, posinf=None, neginf=None))]
fn nan_to_num(
    py: Python<'_>,
    x: Py<PyAny>,
    copy: bool,
    nan: f64,
    posinf: Option<f64>,
    neginf: Option<f64>,
) -> PyResult<Py<PyAny>> {
    // copy=False asks numpy to replace NaN/+-inf IN PLACE on the input ndarray and
    // return that same object (np.array(x, copy=False) is the input when x is already
    // an ndarray). The native fast paths below all allocate a fresh result, so for the
    // (rare) in-place mode delegate to numpy with copy=False to preserve exact aliasing
    // semantics. copy=True (the default, and the overwhelmingly common call) keeps the
    // native zero-extract paths.
    if !copy {
        let numpy = py.import("numpy")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("copy", false)?;
        kwargs.set_item("nan", nan)?;
        if let Some(p) = posinf {
            kwargs.set_item("posinf", p)?;
        }
        if let Some(n) = neginf {
            kwargs.set_item("neginf", n)?;
        }
        return Ok(numpy
            .getattr("nan_to_num")?
            .call((x.bind(py),), Some(&kwargs))?
            .unbind());
    }
    // Zero-copy fast path for exact f64 ndarrays: their default posinf/neginf
    // are f64::MAX / f64::MIN (the dtype-aware defaults the slow path computes
    // for F64), so this is bit-identical while skipping the cold extract/build.
    if let Some(out) = try_zerocopy_f64_nan_to_num(
        py,
        x.bind(py),
        nan,
        posinf.unwrap_or(f64::MAX),
        neginf.unwrap_or(f64::MIN),
    )? {
        return Ok(out);
    }
    // Integer ndarrays cannot hold NaN/inf, so nan_to_num is a layout-preserving
    // copy; skip the cold (and for wide ints lossy) f64 extract + rebuild.
    if let Some(out) = try_zerocopy_int_nan_to_num(py, x.bind(py))? {
        return Ok(out);
    }
    // float32 ndarrays: replace NaN/+-inf in float32 with the args cast to float32
    // (defaults finfo(float32).max / -max); skips the cold f64 round-trip.
    if let Some(out) = try_zerocopy_f32_nan_to_num(
        py,
        x.bind(py),
        nan as f32,
        posinf.map(|p| p as f32).unwrap_or(f32::MAX),
        neginf.map(|p| p as f32).unwrap_or(f32::MIN),
    )? {
        return Ok(out);
    }
    // bool has no NaN/inf, so nan_to_num(bool) is a plain bool copy — but the extract
    // below bridges bool->f64 and rebuilds (~900x slower than numpy's bool copy). numpy
    // is the parity reference; defer bool (only on the fallthrough — f64/int/f32 above).
    {
        let numpy = py.import("numpy")?;
        if x.bind(py).is_exact_instance(&numpy.getattr("ndarray")?)
            && x.bind(py).getattr("dtype")?.getattr("kind")?.extract::<String>()? == "b"
        {
            let kwargs = PyDict::new(py);
            kwargs.set_item("nan", nan)?;
            if let Some(p) = posinf {
                kwargs.set_item("posinf", p)?;
            }
            if let Some(n) = neginf {
                kwargs.set_item("neginf", n)?;
            }
            return Ok(numpy
                .getattr("nan_to_num")?
                .call((x.bind(py),), Some(&kwargs))?
                .unbind());
        }
    }
    // Non-contiguous (transposed/strided) ndarrays bail the zero-copy paths into the
    // cold extract → rebuild (transpose-copy, ~2.5x slower). Delegate to numpy.
    {
        let numpy = py.import("numpy")?;
        if noncontiguous_ndarray(&numpy, x.bind(py))? {
            let kwargs = PyDict::new(py);
            kwargs.set_item("copy", true)?;
            kwargs.set_item("nan", nan)?;
            if let Some(p) = posinf {
                kwargs.set_item("posinf", p)?;
            }
            if let Some(n) = neginf {
                kwargs.set_item("neginf", n)?;
            }
            return Ok(numpy
                .getattr("nan_to_num")?
                .call((x.bind(py),), Some(&kwargs))?
                .unbind());
        }
    }
    let x_arr = match extract_precise_numeric_array(py, x.bind(py), "nan_to_num(x)") {
        Ok(arr) => arr,
        Err(_) => {
            // Complex (and any other dtype the native real kernel cannot represent)
            // is handled by numpy.nan_to_num — it replaces NaN/+-inf in BOTH the real
            // and imaginary parts, applying nan/posinf/neginf to each. Delegate with
            // the same args so the result is exact; genuinely invalid input (e.g. a
            // string array) reproduces numpy's own error.
            let numpy = py.import("numpy")?;
            let kwargs = PyDict::new(py);
            kwargs.set_item("nan", nan)?;
            if let Some(p) = posinf {
                kwargs.set_item("posinf", p)?;
            }
            if let Some(n) = neginf {
                kwargs.set_item("neginf", n)?;
            }
            return Ok(numpy
                .getattr("nan_to_num")?
                .call((x.bind(py),), Some(&kwargs))?
                .unbind());
        }
    };
    let (default_posinf, default_neginf) = x_arr.nan_to_num_default_inf_replacements();
    let result = x_arr.nan_to_num(
        nan,
        posinf.unwrap_or(default_posinf),
        neginf.unwrap_or(default_neginf),
    );
    build_numpy_scalar_or_array(py, &result)
}

#[pyfunction]
#[pyo3(signature = (condition, a, axis=None))]
fn compress(
    py: Python<'_>,
    condition: Py<PyAny>,
    a: Py<PyAny>,
    axis: Option<isize>,
) -> PyResult<Py<PyAny>> {
    let condition_for_fallback = condition.clone_ref(py);
    let a_for_fallback = a.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let kwargs = PyDict::new(py);
        if let Some(axis) = axis {
            kwargs.set_item("axis", axis)?;
        }
        Ok(numpy
            .getattr("compress")?
            .call(
                (condition_for_fallback.bind(py), a_for_fallback.bind(py)),
                Some(&kwargs),
            )?
            .unbind())
    };
    // Zero-copy branchless compaction for the flat case (axis=None, bool
    // condition) over every fixed-width numeric dtype — all 8 integer widths,
    // float32/float64, bool. Skips the cold extract_numeric_array path that
    // widens narrow ints/float32 through f64 (24x) and the older branchy f64
    // helper (5x). Bit-identical (elements move verbatim). Per-axis compress,
    // complex, non-bool conditions, and non-ndarray operands fall through.
    if axis.is_none()
        && let Some(out) = try_zerocopy_any_compact(py, condition.bind(py), a.bind(py))?
    {
        return Ok(out);
    }
    // Remaining flat float64 cases (e.g. when the generic path declines) and any
    // residue keep the dedicated f64 helper before the cold extract path.
    if let Some(out) = try_zerocopy_f64_compress(py, condition.bind(py), a.bind(py), axis)? {
        return Ok(out);
    }
    // Per-axis float64 compress: select slabs along the axis with contiguous block
    // copies off the borrowed buffer, skipping the whole-array extract + native
    // rebuild (which was ~17x numpy on a 1000x1000 axis-0 compress).
    if let Some(axis) = axis
        && let Some(out) = try_zerocopy_f64_compress_axis(py, condition.bind(py), a.bind(py), axis)?
    {
        return Ok(out);
    }
    // Residual — most importantly NON-f64 per-axis compress (the f64-only axis fast
    // path above misses it): the old path extracted the WHOLE array to a UFuncArray,
    // selected slabs, and rebuilt across the export bridge. This both WIDENED the
    // dtype (compress(int8, axis) returned int64 — a dtype-parity BUG; numpy keeps
    // int8) and ran 73-1124x slower than numpy (int8 axis-0 1124x). numpy selects the
    // kept slabs in one strided pass and preserves the dtype, so delegate.
    fallback()
}

#[pyfunction]
fn extract(py: Python<'_>, condition: Py<PyAny>, arr: Py<PyAny>) -> PyResult<Py<PyAny>> {
    let condition_for_fallback = condition.clone_ref(py);
    let arr_for_fallback = arr.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        Ok(numpy
            .getattr("extract")?
            .call1((condition_for_fallback.bind(py), arr_for_fallback.bind(py)))?
            .unbind())
    };
    // NumPy's extract preserves the data array's dtype; our native kernel
    // canonicalizes narrow ints/floats, so defer non-canonical widths to NumPy.
    if !numpy_dtype_native_roundtrip_preserves(py, arr.bind(py)) {
        return fallback();
    }
    // Typed BRANCHLESS compaction (extract == compress over the raveled
    // operands); skips the cold, for-wide-ints lossy extract Vec. This is the
    // same path compress uses — it handles every canonical width (int64/uint64/
    // float64/bool) that reaches here (narrow ints/float32 are already deferred
    // to NumPy by the dtype-roundtrip guard above) and a condition equal-or-
    // shorter than arr (numpy.extract == compress(ravel(cond), ravel(arr))). It
    // replaces the old f64-only `if cond { store; w+=1 }` extract loop, whose
    // ~50% branch-mispredict on a balanced mask made extract ~4-5x slower than
    // compress for identical inputs. Bit-identical (elements move verbatim).
    if let Some(out) = try_zerocopy_any_compact(py, condition.bind(py), arr.bind(py))? {
        return Ok(out);
    }
    let condition = match extract_numeric_array(py, condition.bind(py), "extract(condition)") {
        Ok(condition) => condition,
        Err(_) => return fallback(),
    };
    let arr = match extract_numeric_array(py, arr.bind(py), "extract(arr)") {
        Ok(arr) => arr,
        Err(_) => return fallback(),
    };
    let result = match UFuncArray::extract(&condition, &arr) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    build_numpy_array_from_ufunc(py, &result)
}

#[pyfunction]
#[pyo3(signature = (condlist, choicelist, default=None))]
fn select(
    py: Python<'_>,
    condlist: Py<PyAny>,
    choicelist: Py<PyAny>,
    default: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let condlist_for_fallback = condlist.clone_ref(py);
    let choicelist_for_fallback = choicelist.clone_ref(py);
    let default_for_fallback = default.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let select_fn = numpy.getattr("select")?;
        if let Some(default) = default_for_fallback.as_ref() {
            let kwargs = PyDict::new(py);
            kwargs.set_item("default", default.bind(py))?;
            Ok(select_fn
                .call(
                    (
                        condlist_for_fallback.bind(py),
                        choicelist_for_fallback.bind(py),
                    ),
                    Some(&kwargs),
                )?
                .unbind())
        } else {
            Ok(select_fn
                .call1((
                    condlist_for_fallback.bind(py),
                    choicelist_for_fallback.bind(py),
                ))?
                .unbind())
        }
    };

    // numpy.select's output dtype is result_type(choices..., default); our native
    // where_select chain runs through extract_numeric_array, which canonicalizes
    // narrow widths (int32 -> int64, float32 -> float64). Only take the native path
    // when every choice (and an explicit default) is float64 — the one case the
    // round-trip reproduces exactly — and defer every other dtype mix to numpy,
    // which preserves the promoted result dtype.
    let choices_all_f64 = || -> PyResult<bool> {
        for item in choicelist.bind(py).try_iter()? {
            if !numpy_dtype_is_f64(py, &item?) {
                return Ok(false);
            }
        }
        if let Some(default_val) = default.as_ref() {
            let bound = default_val.bind(py);
            if !bound.is_none() && !numpy_dtype_is_f64(py, bound) {
                return Ok(false);
            }
        }
        Ok(true)
    };
    if !choices_all_f64().unwrap_or(false) {
        return fallback();
    }

    // Single-pass zero-copy select for the all-f64 common case (bool conditions +
    // f64 choices of one shape, scalar default); skips the chained where_select
    // fold and the cold extract/build Vecs. Bit-identical; broadcasting,
    // non-contiguous, or non-scalar-default cases fall through below.
    if let Some(out) =
        try_zerocopy_f64_select(py, condlist.bind(py), choicelist.bind(py), default.as_ref())?
    {
        return Ok(out);
    }

    let condlist = match extract_numeric_array_sequence(py, condlist.bind(py), "select(condlist)") {
        Ok(condlist) => condlist,
        Err(_) => return fallback(),
    };
    let choicelist =
        match extract_numeric_array_sequence(py, choicelist.bind(py), "select(choicelist)") {
            Ok(choicelist) => choicelist,
            Err(_) => return fallback(),
        };

    if condlist.len() != choicelist.len() {
        return fallback();
    }
    if condlist.is_empty() {
        return fallback();
    }
    if condlist
        .iter()
        .any(|condition| condition.dtype() != DType::Bool)
    {
        return fallback();
    }

    let mut result = match default {
        Some(default) => match extract_numeric_array(py, default.bind(py), "select(default)") {
            Ok(default) => default,
            Err(_) => return fallback(),
        },
        None => {
            UFuncArray::from_storage(vec![], ArrayStorage::I64(vec![0])).map_err(map_ufunc_error)?
        }
    };

    for (condition, choice) in condlist.iter().zip(choicelist.iter()).rev() {
        result = match UFuncArray::where_select(condition, choice, &result) {
            Ok(result) => result,
            Err(_) => return fallback(),
        };
    }

    build_numpy_array_from_ufunc(py, &result)
}

// Generic zero-copy multi-way select out[i] = choices[a[i]][i] for one integer
// dtype. numpy.choose with mode='raise' picks, at each flat position, the element
// from the choice array named by the index a[i]. With all choices the same shape
// as a (no broadcast) and the same dtype, this is a per-element gather across K
// contiguous slices. Indices are validated in [0, K) BEFORE any write, so an
// out-of-range index leaves us deferring to numpy.choose for the exact ValueError
// (numpy's negative-index / OOB handling stays authoritative). Returns None to
// fall through.
fn choose_typed<'py, T: pyo3::buffer::Element + Copy>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    a64: &Bound<'py, PyAny>,
    choices: &[Bound<'py, PyAny>],
    dtype_name: &str,
    out_shape: &[usize],
) -> PyResult<Option<Py<PyAny>>> {
    let Ok(a_buffer) = PyBuffer::<i64>::get(a64) else {
        return Ok(None);
    };
    let Some(a_in) = a_buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = a_in.len();
    let k = choices.len() as i64;
    // Hold each choice's buffer alive; collect read-only slices.
    let mut buffers = Vec::with_capacity(choices.len());
    for c in choices {
        let Ok(buf) = PyBuffer::<T>::get(c) else {
            return Ok(None);
        };
        if buf.item_count() != n {
            return Ok(None);
        }
        buffers.push(buf);
    }
    let mut slices = Vec::with_capacity(buffers.len());
    for buf in &buffers {
        let Some(s) = buf.as_slice(py) else {
            return Ok(None);
        };
        slices.push(s);
    }
    // Validate ALL indices first so an OOB defers to numpy (exact ValueError).
    for c in a_in.iter() {
        let idx = c.get();
        if idx < 0 || idx >= k {
            return Ok(None);
        }
    }
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", dtype_name)?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<T>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        for (i, c) in a_in.iter().enumerate() {
            let sel = c.get() as usize;
            output[i].set(slices[sel][i].get());
        }
    }
    let shape = PyTuple::new(py, out_shape.iter().copied())?;
    Ok(Some(flat.call_method1("reshape", (&shape,))?.unbind()))
}

// Zero-copy integer np.choose for the dtypes the native path sends through the
// cold extract f64-bridge (~7x slower, lossy for wide ints). Requires: 'raise'
// mode; an integer index ndarray; choices a non-empty list/tuple of ndarrays all
// sharing a's exact shape and one integer dtype (numpy result_type of matching
// int dtypes is that dtype). Broadcasting, mismatched dtypes/shapes, scalar a,
// bool, complex, and non-list choices fall through.
fn try_zerocopy_int_choose(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    choices: &Bound<'_, PyAny>,
    mode: &str,
) -> PyResult<Option<Py<PyAny>>> {
    if mode != "raise" {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let a_kind = a.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
    if a_kind != "i" && a_kind != "u" {
        return Ok(None);
    }
    let a_shape = a.getattr("shape")?.extract::<Vec<usize>>()?;
    if a_shape.is_empty() {
        return Ok(None); // scalar index → numpy returns a scalar; defer
    }
    // Collect choices from a list or tuple of ndarrays.
    let items: Vec<Bound<'_, PyAny>> = if let Ok(list) = choices.cast::<pyo3::types::PyList>() {
        list.iter().collect()
    } else if let Ok(tup) = choices.cast::<pyo3::types::PyTuple>() {
        tup.iter().collect()
    } else {
        return Ok(None);
    };
    if items.is_empty() {
        return Ok(None);
    }
    // All choices must be ndarrays of a's shape and one shared integer dtype.
    // Guard items[0] before reading its dtype, else array_like (Python list)
    // choices raise AttributeError here instead of deferring to numpy.
    if !items[0].is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let c0_dtype = items[0].getattr("dtype")?;
    let kind = c0_dtype.getattr("kind")?.extract::<String>()?;
    let itemsize = c0_dtype.getattr("itemsize")?.extract::<usize>()?;
    if kind != "i" && kind != "u" && kind != "f" {
        return Ok(None);
    }
    for c in &items {
        if !c.is_exact_instance(&ndarray_type)
            || c.getattr("shape")?.extract::<Vec<usize>>()? != a_shape
        {
            return Ok(None);
        }
        let d = c.getattr("dtype")?;
        if d.getattr("kind")?.extract::<String>()? != kind
            || d.getattr("itemsize")?.extract::<usize>()? != itemsize
        {
            return Ok(None);
        }
    }
    // Normalize the index array to contiguous int64.
    let kw = PyDict::new(py);
    kw.set_item("dtype", "int64")?;
    let a64 = numpy.getattr("ascontiguousarray")?.call((a,), Some(&kw))?;
    match (kind.as_str(), itemsize) {
        ("i", 8) => choose_typed::<i64>(py, &numpy, &a64, &items, "int64", &a_shape),
        ("i", 4) => choose_typed::<i32>(py, &numpy, &a64, &items, "int32", &a_shape),
        ("i", 2) => choose_typed::<i16>(py, &numpy, &a64, &items, "int16", &a_shape),
        ("i", 1) => choose_typed::<i8>(py, &numpy, &a64, &items, "int8", &a_shape),
        ("u", 8) => choose_typed::<u64>(py, &numpy, &a64, &items, "uint64", &a_shape),
        ("u", 4) => choose_typed::<u32>(py, &numpy, &a64, &items, "uint32", &a_shape),
        ("u", 2) => choose_typed::<u16>(py, &numpy, &a64, &items, "uint16", &a_shape),
        ("u", 1) => choose_typed::<u8>(py, &numpy, &a64, &items, "uint8", &a_shape),
        // Float choose is a value-agnostic gather: view every (same-shape,
        // same-dtype) choice as the same-width unsigned integer, gather through the
        // existing u16/u32/u64 choose_typed instantiations, then view the result
        // back to the float dtype. No new monomorphizations, so the integer path is
        // unchanged. A non-contiguous choice makes .view raise; defer to numpy then.
        ("f", 8) => choose_float_via_unsigned::<u64>(
            py, &numpy, &a64, &items, "uint64", "float64", &a_shape,
        ),
        ("f", 4) => choose_float_via_unsigned::<u32>(
            py, &numpy, &a64, &items, "uint32", "float32", &a_shape,
        ),
        ("f", 2) => choose_float_via_unsigned::<u16>(
            py, &numpy, &a64, &items, "uint16", "float16", &a_shape,
        ),
        _ => Ok(None),
    }
}

// Float np.choose through a same-width unsigned-integer view: gather the unsigned
// reinterpretations of the choices with the existing choose_typed::<u*>, then view
// the result back to `float_name`. Verbatim element move => bit-identical incl.
// nan/inf/signed zeros. Returns Ok(None) — caller defers to numpy — if any choice
// is non-contiguous (so .view raises) or the gather declines.
fn choose_float_via_unsigned<'py, U: pyo3::buffer::Element + Copy>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    a64: &Bound<'py, PyAny>,
    items: &[Bound<'py, PyAny>],
    uint_name: &str,
    float_name: &str,
    out_shape: &[usize],
) -> PyResult<Option<Py<PyAny>>> {
    let uview = numpy.getattr(uint_name)?;
    let mut viewed = Vec::with_capacity(items.len());
    for c in items {
        let Ok(cv) = c.call_method1("view", (&uview,)) else {
            return Ok(None);
        };
        viewed.push(cv);
    }
    match choose_typed::<U>(py, numpy, a64, &viewed, uint_name, out_shape)? {
        Some(out_u) => Ok(Some(
            out_u
                .bind(py)
                .call_method1("view", (numpy.getattr(float_name)?,))?
                .unbind(),
        )),
        None => Ok(None),
    }
}

#[pyfunction]
#[pyo3(signature = (a, choices, mode="raise"))]
fn choose(py: Python<'_>, a: Py<PyAny>, choices: Py<PyAny>, mode: &str) -> PyResult<Py<PyAny>> {
    // Check if any choices array is complex dtype and fallback to numpy
    let numpy = py.import("numpy")?;
    let choices_bound = choices.bind(py);
    if let Ok(choices_list) = choices_bound.cast::<pyo3::types::PyList>() {
        for item in choices_list.iter() {
            let arr = numpy.call_method1("asarray", (item,))?;
            let dtype_kind = arr.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
            if dtype_kind == "c" {
                let kwargs = PyDict::new(py);
                kwargs.set_item("mode", mode)?;
                return Ok(numpy
                    .getattr("choose")?
                    .call((a.bind(py), choices_bound), Some(&kwargs))?
                    .unbind());
            }
        }
    }

    // Zero-copy multi-way select for integer index + same-shape same-int-dtype
    // ndarray choices (the common case); skips the cold extract + rebuild. Bit-
    // identical; broadcasting, mismatched dtypes/shapes, OOB indices, scalar a,
    // and other dtypes fall through.
    if let Some(result) = try_zerocopy_int_choose(py, a.bind(py), choices_bound, mode)? {
        return Ok(result);
    }

    let a = extract_integer_array(py, a.bind(py), "choose(a)")?;
    let choices = extract_numeric_array_sequence(py, choices_bound, "choose(choices)")?;
    let result = a
        .choose_with_mode(&choices, mode)
        .map_err(map_ufunc_error)?;
    build_numpy_array_from_ufunc(py, &result)
}

#[pyfunction]
#[pyo3(signature = (a, v, side="left", sorter=None))]
fn searchsorted(
    py: Python<'_>,
    a: Py<PyAny>,
    v: Py<PyAny>,
    side: &str,
    sorter: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    // The native binary-search path only handles real numeric dtypes. numpy
    // also searches sorted string ('U'/'S'), datetime64 ('M'), timedelta64
    // ('m'), and complex haystacks; for any non-numeric `a` dtype delegate the
    // whole call to numpy.searchsorted so it returns the right index (and the
    // right scalar-vs-array shape) instead of being rejected as non-numeric.
    let numpy = py.import("numpy")?;
    let a_arr = numpy.call_method1("asarray", (a.bind(py),))?;
    let a_kind = a_arr
        .getattr("dtype")?
        .getattr("kind")?
        .extract::<String>()?;
    if !matches!(a_kind.as_str(), "b" | "i" | "u" | "f") {
        let kwargs = PyDict::new(py);
        kwargs.set_item("side", side)?;
        if let Some(sorter) = sorter.as_ref() {
            kwargs.set_item("sorter", sorter.bind(py))?;
        }
        return Ok(numpy
            .getattr("searchsorted")?
            .call((a_arr, v.bind(py)), Some(&kwargs))?
            .unbind());
    }

    // Mirror numpy's scalar-vs-array return shape: when `v` is a Python
    // scalar or a 0-D ndarray, numpy.searchsorted returns a numpy scalar
    // (e.g. np.int64(2)); otherwise it returns an ndarray. Detect on the
    // *original* Python object before we materialize a UFuncArray, since
    // extract_numeric_array normalizes everything to an array.
    //
    // Self-review on 9awh found that the prior fallback `unwrap_or(true)`
    // misclassified Python lists/tuples (which lack `ndim`) as scalars,
    // making `searchsorted([1,3,5], [4])` return a scalar instead of
    // array([2]) like numpy. Fix: when `ndim` is unavailable, treat as
    // scalar only if the object also extracts as a Python numeric scalar
    // (int / float / bool). Lists, tuples, and other sequences fail that
    // extraction and correctly fall through to the array branch.
    let v_bound = v.bind(py);
    let v_is_scalar = match v_bound.getattr("ndim").and_then(|n| n.extract::<i64>()) {
        Ok(ndim_val) => ndim_val == 0,
        Err(_) => {
            v_bound.extract::<i64>().is_ok()
                || v_bound.extract::<f64>().is_ok()
                || v_bound.extract::<bool>().is_ok()
        }
    };
    // Zero-copy scalar-query fast path: a single binary search over the haystack
    // buffer, with no extract of the (potentially huge) sorted array. The cold path
    // below materializes the entire haystack into a UFuncArray just to answer one
    // lookup — ~1600x (f64) to ~36000x (i64) slower than numpy for a scalar v. This
    // reuses the same lower/upper-bound loop as the array path, so it is bit-exact.
    // Non-f64/i64/u64 haystacks and int-haystack-with-float-query (numpy promotes to
    // f64) defer to the existing path.
    if sorter.is_none()
        && v_is_scalar
        && let Some(out) = try_zerocopy_scalar_searchsorted(py, a.bind(py), v_bound, side)?
    {
        return Ok(out);
    }
    // Fast typed binary search for matched integer dtypes with an array `v` and no
    // sorter — skips the cold extract→UFuncArray path (~11x slower).
    if sorter.is_none()
        && !v_is_scalar
        && let Some(out) = try_zerocopy_int_searchsorted(py, a.bind(py), v_bound, side)?
    {
        return Ok(out);
    }
    // Same idea for an f64 haystack + f64 array query: the cold path extracts the whole
    // haystack, which dominates for a small query array (~13x slower at n_query=1000).
    if sorter.is_none()
        && !v_is_scalar
        && let Some(out) = try_zerocopy_f64_searchsorted(py, a.bind(py), v_bound, side)?
    {
        return Ok(out);
    }
    let a = extract_numeric_array(py, a.bind(py), "searchsorted(a)")?;
    let v = extract_numeric_array(py, v_bound, "searchsorted(v)")?;
    let sorter = sorter
        .map(|sorter| extract_index_vector(py, sorter.bind(py), "searchsorted(sorter)"))
        .transpose()?;
    let result = a
        .searchsorted(&v, Some(side), sorter.as_deref())
        .map_err(map_ufunc_error)?;
    let array = build_numpy_array_from_ufunc(py, &result)?;
    if v_is_scalar {
        // result[()] unwraps a 0-D ndarray into the corresponding numpy
        // scalar (np.intp / np.int64), matching numpy.searchsorted's
        // scalar-input return type exactly.
        Ok(array.bind(py).get_item(())?.unbind())
    } else {
        Ok(array)
    }
}

// Lower/upper-bound insertion index for a single key over a sorted PyBuffer slice —
// the same branchless loop searchsorted_typed runs per array element. side="left"
// (right=false) counts elements < key; side="right" counts elements <= key.
// Insertion index of `key` over a sorted integer PyBuffer slice — the same branchless
// loop searchsorted_typed runs per array element. Integers are totally ordered (no
// NaN), so plain </<= matches numpy. side="left" counts elements < key; side="right"
// counts elements <= key.
fn scalar_search_index<T: pyo3::buffer::Element + Copy + PartialOrd>(
    s: &[pyo3::buffer::ReadOnlyCell<T>],
    key: T,
    right: bool,
) -> usize {
    let mut left = 0usize;
    let mut len = s.len();
    while len > 0 {
        let half = len / 2;
        let mid = left + half;
        let probe = s[mid].get();
        let cond = if right { probe <= key } else { probe < key };
        if cond {
            left = mid + 1;
            len -= half + 1;
        } else {
            len = half;
        }
    }
    left
}

// f64 variant with numpy's NaN-aware ordering: NaN sorts after every real value, so a
// NaN key inserts at the end and a NaN probe compares greater than any real key.
// `lt(a, b) = a < b || (b.is_nan() && !a.is_nan())`; using is_nan keeps it clippy-clean.
fn scalar_search_index_f64(s: &[pyo3::buffer::ReadOnlyCell<f64>], key: f64, right: bool) -> usize {
    let mut left = 0usize;
    let mut len = s.len();
    while len > 0 {
        let half = len / 2;
        let mid = left + half;
        let probe = s[mid].get();
        let cond = if right {
            !(key < probe || (probe.is_nan() && !key.is_nan()))
        } else {
            probe < key || (key.is_nan() && !probe.is_nan())
        };
        if cond {
            left = mid + 1;
            len -= half + 1;
        } else {
            len = half;
        }
    }
    left
}

// Zero-copy np.searchsorted for a SCALAR query `v` over a 1-D numeric haystack `a`,
// returning numpy's np.intp scalar. Reads `a`'s buffer directly and runs one binary
// search — no extract of the haystack. Handles the haystacks where the comparison is
// unambiguous: f64 (numpy compares in f64 whether v is int or float), and i64/u64
// with an integer-valued query. An int/uint haystack with a non-integer (float) query
// promotes to f64 in numpy, so that — and every other dtype (narrow ints, f32,
// complex, datetime) — defers (returns None) to the existing path. Bit-exact: the
// search loop is identical to the array fast path.
fn try_zerocopy_scalar_searchsorted(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    v: &Bound<'_, PyAny>,
    side: &str,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    if a.getattr("ndim")?.extract::<usize>()? != 1 {
        return Ok(None); // numpy searchsorted requires a 1-D haystack
    }
    let right = match side {
        "left" => false,
        "right" => true,
        _ => return Ok(None),
    };
    let a_dtype = a.getattr("dtype")?;
    let kind = a_dtype.getattr("kind")?.extract::<String>()?;
    let itemsize = a_dtype.getattr("itemsize")?.extract::<usize>()?;
    let idx = match (kind.as_str(), itemsize) {
        ("f", 8) => {
            let Ok(key) = v.extract::<f64>() else {
                return Ok(None);
            };
            let Ok(buffer) = PyBuffer::<f64>::get(a) else {
                return Ok(None);
            };
            let Some(slice) = buffer.as_slice(py) else {
                return Ok(None);
            };
            scalar_search_index_f64(slice, key, right)
        }
        ("i", 8) => {
            // A float (non-integer) query promotes both sides to f64 in numpy; defer.
            let Ok(key) = v.extract::<i64>() else {
                return Ok(None);
            };
            let Ok(buffer) = PyBuffer::<i64>::get(a) else {
                return Ok(None);
            };
            let Some(slice) = buffer.as_slice(py) else {
                return Ok(None);
            };
            scalar_search_index(slice, key, right)
        }
        ("u", 8) => {
            let Ok(key) = v.extract::<u64>() else {
                return Ok(None);
            };
            let Ok(buffer) = PyBuffer::<u64>::get(a) else {
                return Ok(None);
            };
            let Some(slice) = buffer.as_slice(py) else {
                return Ok(None);
            };
            scalar_search_index(slice, key, right)
        }
        _ => return Ok(None),
    };
    Ok(Some(numpy.getattr("intp")?.call1((idx as i64,))?.unbind()))
}

// Zero-copy np.searchsorted for an f64 haystack `a` and an f64 array query `v`
// (sorter=None). Reads both buffers and runs the NaN-aware f64 binary search per
// query, writing an intp output of v.shape — no extract of the haystack (the cold
// path's haystack copy dominates for a small query array). Mixed dtypes (numpy would
// promote) and non-ndarray/non-1-D-haystack inputs defer (None). Bit-exact: same
// NaN-aware comparison numpy uses.
fn try_zerocopy_f64_searchsorted(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    v: &Bound<'_, PyAny>,
    side: &str,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) || !v.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    if a.getattr("ndim")?.extract::<usize>()? != 1 {
        return Ok(None); // numpy searchsorted requires a 1-D haystack
    }
    if !numpy_dtype_is_f64(py, a) || !numpy_dtype_is_f64(py, v) {
        return Ok(None); // mixed dtypes → numpy promotes; defer for exact semantics
    }
    let right = match side {
        "left" => false,
        "right" => true,
        _ => return Ok(None),
    };
    let (Ok(a_buf), Ok(v_buf)) = (PyBuffer::<f64>::get(a), PyBuffer::<f64>::get(v)) else {
        return Ok(None);
    };
    let (Some(a_s), Some(v_s)) = (a_buf.as_slice(py), v_buf.as_slice(py)) else {
        return Ok(None);
    };
    let m = v_s.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "intp")?;
    let flat = numpy.call_method("empty", (m,), Some(&kwargs))?;
    if m > 0 {
        let Ok(o_buf) = PyBuffer::<i64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = o_buf.as_mut_slice(py) else {
            return Ok(None);
        };
        for (o, vc) in output.iter().zip(v_s.iter()) {
            o.set(scalar_search_index_f64(a_s, vc.get(), right) as i64);
        }
    }
    let shape: Vec<usize> = v.getattr("shape")?.extract()?;
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    Ok(Some(flat.call_method1("reshape", (&output_shape,))?.unbind()))
}

// Typed binary-search core for np.searchsorted over a sorted haystack. For each
// query it computes the insertion index via a tight lower/upper-bound loop (the
// `if cond { left=mid+1 } else { len=half }` form the compiler lowers to a cmov,
// so it is effectively branchless). side="left" counts elements < key (first
// index >= key); side="right" counts elements <= key (first index > key). Integer
// ordering is total, so this is bit-exact with numpy. Output is intp of v.shape.
fn searchsorted_typed<'py, T: pyo3::buffer::Element + Copy + PartialOrd>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    a: &Bound<'py, PyAny>,
    v: &Bound<'py, PyAny>,
    right: bool,
) -> PyResult<Option<Bound<'py, PyAny>>> {
    let (Ok(a_buf), Ok(v_buf)) = (PyBuffer::<T>::get(a), PyBuffer::<T>::get(v)) else {
        return Ok(None);
    };
    let (Some(a_s), Some(v_s)) = (a_buf.as_slice(py), v_buf.as_slice(py)) else {
        return Ok(None);
    };
    let m = v_s.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "intp")?;
    let flat = numpy.call_method("empty", (m,), Some(&kwargs))?;
    if m > 0 {
        let Ok(o_buf) = PyBuffer::<i64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = o_buf.as_mut_slice(py) else {
            return Ok(None);
        };
        let n = a_s.len();
        for (o, vc) in output.iter().zip(v_s.iter()) {
            let key = vc.get();
            let mut left = 0usize;
            let mut len = n;
            while len > 0 {
                let half = len / 2;
                let mid = left + half;
                let probe = a_s[mid].get();
                let cond = if right { probe <= key } else { probe < key };
                if cond {
                    left = mid + 1;
                    len -= half + 1;
                } else {
                    len = half;
                }
            }
            o.set(left as i64);
        }
    }
    let shape: Vec<usize> = v.getattr("shape")?.extract()?;
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    Ok(Some(flat.call_method1("reshape", (&output_shape,))?))
}

// Zero-copy np.searchsorted for a matched integer dtype haystack/query (array v,
// sorter=None). Gated to: both ndarrays, identical integer dtype (numpy would
// otherwise promote to a common type — defer for exact comparison semantics).
// float/complex/mixed/sorter/scalar-v keep the existing path.
fn try_zerocopy_int_searchsorted(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    v: &Bound<'_, PyAny>,
    side: &str,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) || !v.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    if a.getattr("ndim")?.extract::<usize>()? != 1 {
        return Ok(None); // numpy searchsorted requires a 1-D haystack
    }
    let a_dtype = a.getattr("dtype")?;
    if !a_dtype.eq(&v.getattr("dtype")?)? {
        return Ok(None); // differing dtypes → numpy promotes; defer
    }
    let right = match side {
        "left" => false,
        "right" => true,
        _ => return Ok(None),
    };
    let kind = a_dtype.getattr("kind")?.extract::<String>()?;
    let itemsize = a_dtype.getattr("itemsize")?.extract::<usize>()?;
    let flat = match (kind.as_str(), itemsize) {
        ("i", 1) => searchsorted_typed::<i8>(py, &numpy, a, v, right)?,
        ("i", 2) => searchsorted_typed::<i16>(py, &numpy, a, v, right)?,
        ("i", 4) => searchsorted_typed::<i32>(py, &numpy, a, v, right)?,
        ("i", 8) => searchsorted_typed::<i64>(py, &numpy, a, v, right)?,
        ("u", 1) => searchsorted_typed::<u8>(py, &numpy, a, v, right)?,
        ("u", 2) => searchsorted_typed::<u16>(py, &numpy, a, v, right)?,
        ("u", 4) => searchsorted_typed::<u32>(py, &numpy, a, v, right)?,
        ("u", 8) => searchsorted_typed::<u64>(py, &numpy, a, v, right)?,
        _ => return Ok(None),
    };
    Ok(flat.map(|f| f.unbind()))
}

#[pyfunction]
#[pyo3(signature = (a, bins=None, range=None, density=None, weights=None))]
fn histogram(
    py: Python<'_>,
    a: Py<PyAny>,
    bins: Option<Py<PyAny>>,
    range: Option<Py<PyAny>>,
    density: Option<Py<PyAny>>,
    weights: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let histogram_fn = numpy.getattr("histogram")?;
        let kwargs = PyDict::new(py);
        if let Some(bins_val) = bins.as_ref() {
            kwargs.set_item("bins", bins_val.bind(py))?;
        }
        if let Some(range_val) = range.as_ref() {
            kwargs.set_item("range", range_val.bind(py))?;
        }
        if let Some(density_val) = density.as_ref() {
            kwargs.set_item("density", density_val.bind(py))?;
        }
        if let Some(weights_val) = weights.as_ref() {
            kwargs.set_item("weights", weights_val.bind(py))?;
        }
        Ok(histogram_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    // Native path only handles int bins without range/weights/density —
    // everything else lands on numpy.
    if range.as_ref().is_some_and(|v| !v.bind(py).is_none())
        || density.as_ref().is_some_and(|v| !v.bind(py).is_none())
        || weights.as_ref().is_some_and(|v| !v.bind(py).is_none())
    {
        return fallback(py);
    }
    let nbins: usize = match bins.as_ref() {
        Some(v) => {
            let b = v.bind(py);
            if b.is_none() {
                10
            } else if let Ok(n) = b.extract::<i64>() {
                if n <= 0 {
                    return fallback(py);
                }
                n as usize
            } else {
                // Explicit edges array or estimator string: delegate.
                return fallback(py);
            }
        }
        None => 10,
    };

    // O(n) uniform-bin counting for 1-D f64/f32/integer arrays — skips the cold
    // extract→UFuncArray::histogram path (several-x slower than numpy).
    let a_bound = a.bind(py);
    if let Some(out) = try_zerocopy_histogram(py, a_bound, nbins)? {
        return Ok(out);
    }
    let ndarray_type = numpy.getattr("ndarray")?;
    if a_bound.is_exact_instance(&ndarray_type) {
        let dtype = a_bound.getattr("dtype")?;
        if dtype.getattr("kind")?.extract::<String>()? == "f"
            && dtype.getattr("itemsize")?.extract::<usize>()? == 4
        {
            return fallback(py);
        }
    }

    let native = match extract_precise_numeric_array(py, a_bound, "histogram(a)") {
        Ok(value) => value,
        Err(_) => return fallback(py),
    };
    if native.has_integer_sidecar()
        || matches!(native.dtype(), DType::Complex64 | DType::Complex128)
        || native.shape().len() != 1
    {
        return fallback(py);
    }
    // Reject non-finite inputs so we match numpy's ValueError surface
    // for autorange without inadvertently producing nonsense buckets.
    if native.values().iter().any(|v| !v.is_finite()) {
        return fallback(py);
    }

    let (counts, edges) = match native.histogram(nbins) {
        Ok(value) => value,
        Err(_) => return fallback(py),
    };
    // UFuncArray::histogram returns counts with DType::I64 but stored as
    // f64 values — build_numpy_array_from_ufunc emits an int64 ndarray.
    // Bridge each component through the C-order export helpers.
    let counts_py = build_numpy_array_from_ufunc(py, &counts)?;
    let edges_py = build_numpy_array_from_ufunc(py, &edges)?;
    Ok(PyTuple::new(py, [counts_py.bind(py), edges_py.bind(py)])?
        .into_any()
        .unbind())
}

// Typed O(n) uniform-bin histogram core. Reads the input buffer as T, mapping each
// element to f64 via `to_f64` (identity for f64, widening cast for exactly
// representable integers). Wider i64/u64 values defer because NumPy keeps integer
// outer edges before producing float64 bins, and large non-representable values can
// intentionally raise "too many bins" rather than returning duplicate edges.
fn i64_is_f64_exact(value: i64) -> bool {
    const F64_EXACT_INT_LIMIT: i64 = 9_007_199_254_740_992;
    (-F64_EXACT_INT_LIMIT..=F64_EXACT_INT_LIMIT).contains(&value)
}

fn u64_is_f64_exact(value: u64) -> bool {
    const F64_EXACT_INT_LIMIT: u64 = 9_007_199_254_740_992;
    value <= F64_EXACT_INT_LIMIT
}

fn histogram_typed<T: pyo3::buffer::Element + Copy + Sync>(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    a: &Bound<'_, PyAny>,
    nbins: usize,
    to_f64: fn(T) -> f64,
    check_finite: bool,
    value_supported: fn(T) -> bool,
) -> PyResult<Option<Py<PyAny>>> {
    let Ok(buf) = PyBuffer::<T>::get(a) else {
        return Ok(None);
    };
    if buf.shape().len() != 1 {
        return Ok(None);
    }
    let n = buf.item_count();
    if n == 0 {
        let edges = numpy.call_method1("linspace", (0.0f64, 1.0f64, nbins + 1))?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("dtype", "int64")?;
        let counts = numpy.call_method("zeros", (nbins,), Some(&kwargs))?;
        return Ok(Some(
            PyTuple::new(py, [counts, edges])?.into_any().unbind(),
        ));
    }
    let Some(s) = buf.as_slice(py) else {
        let histogram_fn = numpy.getattr("histogram")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("bins", nbins)?;
        return Ok(Some(histogram_fn.call((a,), Some(&kwargs))?.unbind()));
    };
    // Large 1-D arrays: numpy runs histogram single-threaded, so a privatized
    // parallel min/max reduce + privatized bin-tally fold across the rayon pool
    // beats it outright. The buffer is read-only and contiguous (as_slice
    // succeeded) and the GIL is held, so reading the cells as a plain `&[T]`
    // (T is a POD numeric Sync type) for the duration of this call is sound;
    // par_iter then needs no per-element copy. Bins are chosen with the same
    // partition_point-over-edges rule as UFuncArray::histogram_full
    // (franken_numpy-40n4u), which is bit-identical to NumPy's edge binning and
    // avoids the f64 internal-edge rounding drop. Integer +1 tallies merge
    // order-independently, so the reduced counts are exact regardless of how the
    // pool folds them.
    const HISTOGRAM_PARALLEL_MIN_ELEMS: usize = 1 << 16;
    if n >= HISTOGRAM_PARALLEL_MIN_ELEMS && rayon::current_num_threads() >= 2 {
        use rayon::prelude::*;
        // SAFETY: `s` is a contiguous, read-only PyBuffer slice of length `n`
        // and ReadOnlyCell<T> is repr(transparent) over T. The GIL is held for
        // this whole function, so Python cannot mutate or free the buffer while
        // `data` is alive, and the parallel closures only read it.
        let data: &[T] = unsafe { std::slice::from_raw_parts(s.as_ptr().cast::<T>(), n) };

        // Parallel range scan: (min, max, all_supported, all_finite).
        let (mn, mx, supported, finite) = data
            .par_iter()
            .map(|&raw| {
                let v = to_f64(raw);
                (
                    v,
                    v,
                    value_supported(raw),
                    !check_finite || v.is_finite(),
                )
            })
            .reduce(
                || (f64::INFINITY, f64::NEG_INFINITY, true, true),
                |(amn, amx, aok, afin), (bmn, bmx, bok, bfin)| {
                    (amn.min(bmn), amx.max(bmx), aok && bok, afin && bfin)
                },
            );
        if !supported || !finite {
            return Ok(None);
        }

        let (mut first, mut last) = (mn, mx);
        if first == last {
            first -= 0.5;
            last += 0.5;
        }
        let edges = numpy.call_method1("linspace", (first, last, nbins + 1))?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("dtype", "int64")?;
        let counts = numpy.call_method("zeros", (nbins,), Some(&kwargs))?;

        let Ok(ebuf) = PyBuffer::<f64>::get(&edges) else {
            return Ok(None);
        };
        let Some(es) = ebuf.as_slice(py) else {
            return Ok(None);
        };
        let edges_vec: Vec<f64> = es.iter().map(|c| c.get()).collect();
        for i in 1..edges_vec.len() {
            if edges_vec[i - 1] >= edges_vec[i] {
                return Ok(None);
            }
        }

        let last_bin = nbins - 1;
        // Direct equal-width index (numpy's algorithm), NOT partition_point: the
        // edges are uniform (linspace), so idx = floor((x-first)/(last-first)*nbins)
        // plus numpy's ±1-ULP edge corrections is O(1) per element vs the binary
        // search's O(log nbins) — bit-identical to the serial path above (which is
        // already conformance-verified against numpy) and to numpy itself. For data
        // gated to [first,last], idx is always in [0,nbins] (==nbins only at x==last),
        // and the decrement never fires at idx==0 (x>=first=edges[0]).
        let norm_denom = last - first;
        let norm_numerator = nbins as f64;
        let local_counts = data
            .par_iter()
            .fold(
                || vec![0i64; nbins],
                |mut local, &raw| {
                    let x = to_f64(raw);
                    if x >= first && x <= last {
                        let mut idx = (((x - first) / norm_denom) * norm_numerator) as usize;
                        if idx == nbins {
                            idx -= 1;
                        }
                        if idx != 0 && x < edges_vec[idx] {
                            idx -= 1;
                        }
                        if idx != last_bin && x >= edges_vec[idx + 1] {
                            idx += 1;
                        }
                        local[idx] += 1;
                    }
                    local
                },
            )
            .reduce(
                || vec![0i64; nbins],
                |mut a, b| {
                    for (x, y) in a.iter_mut().zip(b.iter()) {
                        *x += *y;
                    }
                    a
                },
            );

        let Ok(cbuf) = PyBuffer::<i64>::get(&counts) else {
            return Ok(None);
        };
        let Some(cs) = cbuf.as_mut_slice(py) else {
            return Ok(None);
        };
        for (slot, value) in cs.iter().zip(local_counts) {
            slot.set(value);
        }
        return Ok(Some(
            PyTuple::new(py, [counts, edges])?.into_any().unbind(),
        ));
    }

    let mut mn = to_f64(s[0].get());
    let mut mx = mn;
    for c in s.iter() {
        let raw = c.get();
        if !value_supported(raw) {
            return Ok(None);
        }
        let v = to_f64(raw);
        if check_finite && !v.is_finite() {
            return Ok(None);
        }
        if v < mn {
            mn = v;
        }
        if v > mx {
            mx = v;
        }
    }
    let (mut first, mut last) = (mn, mx);
    if first == last {
        first -= 0.5;
        last += 0.5;
    }
    // Delegate the (nbins+1) edge floats to numpy.linspace for bit-identical edges.
    let edges = numpy.call_method1("linspace", (first, last, nbins + 1))?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "int64")?;
    let counts = numpy.call_method("zeros", (nbins,), Some(&kwargs))?;
    if n > 0 {
        let Ok(ebuf) = PyBuffer::<f64>::get(&edges) else {
            return Ok(None);
        };
        let Some(es) = ebuf.as_slice(py) else {
            return Ok(None);
        };
        for i in 1..es.len() {
            if es[i - 1].get() >= es[i].get() {
                return Ok(None);
            }
        }
        let Ok(cbuf) = PyBuffer::<i64>::get(&counts) else {
            return Ok(None);
        };
        let Some(cs) = cbuf.as_mut_slice(py) else {
            return Ok(None);
        };
        let norm_denom = last - first;
        let norm_numerator = nbins as f64;
        for c in s.iter() {
            let x = to_f64(c.get());
            if x < first || x > last {
                continue;
            }
            let mut idx = (((x - first) / norm_denom) * norm_numerator) as usize;
            if idx > nbins {
                return Ok(None);
            }
            if idx == nbins {
                idx -= 1;
            }
            if x < es[idx].get() {
                if idx == 0 {
                    return Ok(None);
                }
                idx -= 1;
            }
            if idx != nbins - 1 && x >= es[idx + 1].get() {
                idx += 1;
            }
            let slot = &cs[idx];
            slot.set(slot.get() + 1);
        }
    }
    Ok(Some(
        PyTuple::new(py, [counts, edges])?.into_any().unbind(),
    ))
}

fn histogram_f32(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    a: &Bound<'_, PyAny>,
    nbins: usize,
) -> PyResult<Option<Py<PyAny>>> {
    let Ok(buf) = PyBuffer::<f32>::get(a) else {
        return Ok(None);
    };
    if buf.shape().len() != 1 {
        return Ok(None);
    }
    let n = buf.item_count();
    if n == 0 {
        let edge_kwargs = PyDict::new(py);
        edge_kwargs.set_item("dtype", "float32")?;
        let np_float32 = numpy.getattr("float32")?;
        let first_py = np_float32.call1((0.0f32,))?;
        let last_py = np_float32.call1((1.0f32,))?;
        let edges = numpy.call_method(
            "linspace",
            (&first_py, &last_py, nbins + 1),
            Some(&edge_kwargs),
        )?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("dtype", "int64")?;
        let counts = numpy.call_method("zeros", (nbins,), Some(&kwargs))?;
        return Ok(Some(
            PyTuple::new(py, [counts, edges])?.into_any().unbind(),
        ));
    }
    let Some(s) = buf.as_slice(py) else {
        let histogram_fn = numpy.getattr("histogram")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("bins", nbins)?;
        return Ok(Some(histogram_fn.call((a,), Some(&kwargs))?.unbind()));
    };
    let mut mn = s[0].get();
    let mut mx = mn;
    let mut prev = mn;
    let mut sorted_non_decreasing = true;
    for c in s.iter() {
        let v = c.get();
        if !v.is_finite() {
            return Ok(None);
        }
        if v < prev {
            sorted_non_decreasing = false;
        }
        prev = v;
        if v < mn {
            mn = v;
        }
        if v > mx {
            mx = v;
        }
    }
    // Returned edges: numpy computes float32 histogram edges natively in float32
    // (linspace(min, max, nbins+1, dtype=float32), with the equal-range +/-0.5
    // expansion done in float32). Build those for the result tuple.
    let (mut first32, mut last32) = (mn, mx);
    if first32 == last32 {
        first32 -= 0.5;
        last32 += 0.5;
    }
    let edge_kwargs = PyDict::new(py);
    edge_kwargs.set_item("dtype", "float32")?;
    let np_float32 = numpy.getattr("float32")?;
    let first_py = np_float32.call1((first32,))?;
    let last_py = np_float32.call1((last32,))?;
    let edges = numpy.call_method(
        "linspace",
        (&first_py, &last_py, nbins + 1),
        Some(&edge_kwargs),
    )?;
    // Counts: numpy bins float32 data using float32 arithmetic against the float32
    // edges (this genuinely differs from an f64 computation at extreme scales).
    // Monotone inputs can classify with a streaming edge pointer; unsorted inputs
    // use the same O(1) affine index + edge corrections as the f64/integer path.
    // first32/last32 are the float32 edge endpoints used for the linspace.
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "int64")?;
    let counts = numpy.call_method("zeros", (nbins,), Some(&kwargs))?;
    {
        let Ok(ebuf) = PyBuffer::<f32>::get(&edges) else {
            return Ok(None);
        };
        let Some(es) = ebuf.as_slice(py) else {
            return Ok(None);
        };
        // numpy raises "Too many bins for data range" when the float32 edges are not
        // strictly increasing (the bin width underflows). Defer so numpy raises.
        for i in 1..es.len() {
            if es[i - 1].get() >= es[i].get() {
                return Ok(None);
            }
        }
        let norm_denom = last32 - first32;
        let norm_numerator = nbins as f32;
        let Ok(cbuf) = PyBuffer::<i64>::get(&counts) else {
            return Ok(None);
        };
        let Some(cs) = cbuf.as_mut_slice(py) else {
            return Ok(None);
        };
        if sorted_non_decreasing {
            let mut local_counts = vec![0i64; nbins];
            let mut idx = 0usize;
            for c in s.iter() {
                let x = c.get();
                if x < first32 {
                    continue;
                }
                if x > last32 {
                    break;
                }
                while idx != nbins - 1 && x >= es[idx + 1].get() {
                    idx += 1;
                }
                local_counts[idx] += 1;
            }
            for (slot, value) in cs.iter().zip(local_counts) {
                slot.set(value);
            }
        } else {
            for c in s.iter() {
                let x = c.get();
                if x < first32 || x > last32 {
                    continue;
                }
                let mut idx = (((x - first32) / norm_denom) * norm_numerator) as usize;
                if idx > nbins {
                    return Ok(None);
                }
                if idx == nbins {
                    idx -= 1;
                }
                if x < es[idx].get() {
                    if idx == 0 {
                        return Ok(None);
                    }
                    idx -= 1;
                }
                if idx != nbins - 1 && x >= es[idx + 1].get() {
                    idx += 1;
                }
                let slot = &cs[idx];
                slot.set(slot.get() + 1);
            }
        }
    }
    Ok(Some(
        PyTuple::new(py, [counts, edges])?.into_any().unbind(),
    ))
}

// O(n) uniform-bin np.histogram for exact 1-D f64/f32/integer ndarrays with
// bins=int and no range/weights/density. The f64/integer path mirrors NumPy's
// uniform-bin affine index calculation and edge corrections; the f32 path bins
// against NumPy's returned float32 edges so near-edge values classify identically.
// Unsupported layouts and values return None or call NumPy directly so fallback
// error and dtype semantics stay intact.
fn try_zerocopy_histogram(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    nbins: usize,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    match (kind.as_str(), itemsize) {
        ("f", 4) => histogram_f32(py, &numpy, a, nbins),
        ("f", 8) => histogram_typed::<f64>(py, &numpy, a, nbins, |x| x, true, |_| true),
        ("i", 1) => {
            histogram_typed::<i8>(py, &numpy, a, nbins, |x| x as f64, false, |_| true)
        }
        ("i", 2) => {
            histogram_typed::<i16>(py, &numpy, a, nbins, |x| x as f64, false, |_| true)
        }
        ("i", 4) => {
            histogram_typed::<i32>(py, &numpy, a, nbins, |x| x as f64, false, |_| true)
        }
        ("i", 8) => histogram_typed::<i64>(
            py,
            &numpy,
            a,
            nbins,
            |x| x as f64,
            false,
            i64_is_f64_exact,
        ),
        ("u", 1) => {
            histogram_typed::<u8>(py, &numpy, a, nbins, |x| x as f64, false, |_| true)
        }
        ("u", 2) => {
            histogram_typed::<u16>(py, &numpy, a, nbins, |x| x as f64, false, |_| true)
        }
        ("u", 4) => {
            histogram_typed::<u32>(py, &numpy, a, nbins, |x| x as f64, false, |_| true)
        }
        ("u", 8) => histogram_typed::<u64>(
            py,
            &numpy,
            a,
            nbins,
            |x| x as f64,
            false,
            u64_is_f64_exact,
        ),
        _ => Ok(None),
    }
}

// Native zero-copy parallel np.gradient for the common 1-D f64 case (unit spacing,
// default axis, edge_order=1). numpy.gradient runs single-threaded and allocates
// temporaries; the central-difference stencil is fully data-parallel (each output
// element is independent) and bit-identical to numpy (same formula and order):
// interior out[i] = (f[i+1]-f[i-1])/2, edges out[0]=f[1]-f[0], out[-1]=f[-1]-f[-2].
fn try_zerocopy_f64_gradient_1d(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    f: &Bound<'_, PyAny>,
    dx: f64,
    edge_order: usize,
) -> PyResult<Option<Py<PyAny>>> {
    if edge_order != 1 {
        return Ok(None);
    }
    if !f.is_exact_instance(&numpy.getattr("ndarray")?) {
        return Ok(None);
    }
    let dtype = f.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    let Ok(buffer) = PyBuffer::<f64>::get(f) else {
        return Ok(None);
    };
    if !buffer.is_c_contiguous() {
        return Ok(None);
    }
    // Handles the LAST (contiguous) axis for 1-D AND N-D: each contiguous row of length
    // L is an independent central-difference stencil. 1-D is the single-row case.
    let shape: Vec<usize> = buffer.shape().to_vec();
    let ndim = shape.len();
    if ndim == 0 {
        return Ok(None);
    }
    let l = shape[ndim - 1];
    if l < 2 {
        return Ok(None); // numpy requires >=2 samples along the axis for edge_order=1
    }
    let Some(cells) = buffer.as_slice(py) else {
        return Ok(None);
    };
    let total = cells.len();
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only under the GIL.
    let data: &[f64] = unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), total) };
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let out = numpy.call_method("empty", (total,), Some(&kwargs))?;
    {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&out) else {
            return Ok(None);
        };
        let Some(out_cells) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // SAFETY: freshly allocated numpy.empty output, cannot alias f; Cell<f64> is
        // repr(transparent) over f64; every element is written exactly once.
        let o: &mut [f64] =
            unsafe { std::slice::from_raw_parts_mut(out_cells.as_ptr() as *mut f64, total) };
        use rayon::prelude::*;
        const GRADIENT_PARALLEL_MIN: usize = 1 << 18; // serial native already crushes numpy below this
        // Per contiguous row: edge_order=1 boundaries (forward/backward diff / dx) +
        // central interior (/(2*dx)). Bit-identical to numpy.gradient along the last axis.
        let stencil = |orow: &mut [f64], r: &[f64]| {
            let l = r.len();
            orow[0] = (r[1] - r[0]) / dx;
            orow[l - 1] = (r[l - 1] - r[l - 2]) / dx;
            for j in 1..l - 1 {
                orow[j] = (r[j + 1] - r[j - 1]) / (2.0 * dx);
            }
        };
        let parallel = total >= GRADIENT_PARALLEL_MIN && rayon::current_num_threads() >= 2;
        if parallel && total == l {
            // 1-D: a single row gives no row-level parallelism -> parallelize the interior.
            o[0] = (data[1] - data[0]) / dx;
            o[l - 1] = (data[l - 1] - data[l - 2]) / dx;
            o[1..l - 1].par_iter_mut().enumerate().for_each(|(j, slot)| {
                let i = j + 1;
                *slot = (data[i + 1] - data[i - 1]) / (2.0 * dx);
            });
        } else if parallel {
            // N-D last axis: each contiguous row is independent -> parallelize over rows.
            o.par_chunks_mut(l)
                .zip(data.par_chunks(l))
                .for_each(|(orow, r)| stencil(orow, r));
        } else {
            for (orow, r) in o.chunks_mut(l).zip(data.chunks(l)) {
                stencil(orow, r);
            }
        }
    }
    if ndim == 1 {
        Ok(Some(out.unbind()))
    } else {
        let shape_tuple = PyTuple::new(py, shape.iter().copied())?;
        Ok(Some(out.call_method1("reshape", (&shape_tuple,))?.unbind()))
    }
}

// np.gradient along a single NON-last (strided) axis of a C-contiguous f64 ndarray,
// uniform spacing, edge_order=1. numpy implements gradient in pure Python with many
// whole-array slice temporaries (~30+ ms for a 4096x1024 axis=0 call). Here the array
// is laid out as outer x n x inner; the central-difference stencil along the `n` axis
// is a per-output-ROW vectorized combination of two input rows of length `inner`
// (out[i] = (f[i+1] - f[i-1]) / (2*dx); edges forward/backward / dx) - cache-friendly
// (sequential row reads) and parallel across all outer*n output rows. Bit-identical to
// numpy (same subtraction/division operands and order; verified). NaN/Inf propagate.
// Last axis (inner == 1) is handled by try_zerocopy_f64_gradient_1d; this requires a
// strictly non-last axis (inner >= 1) so it never overlaps that path.
fn try_zerocopy_f64_gradient_strided_axis(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    f: &Bound<'_, PyAny>,
    ax_raw: isize,
    dx: f64,
    edge_order: usize,
) -> PyResult<Option<Py<PyAny>>> {
    if edge_order != 1 {
        return Ok(None);
    }
    if !f.is_exact_instance(&numpy.getattr("ndarray")?) {
        return Ok(None);
    }
    let dtype = f.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    let Ok(buffer) = PyBuffer::<f64>::get(f) else {
        return Ok(None);
    };
    if !buffer.is_c_contiguous() {
        return Ok(None);
    }
    let shape: Vec<usize> = buffer.shape().to_vec();
    let ndim = shape.len() as isize;
    if ndim < 2 {
        return Ok(None);
    }
    let ax = if ax_raw < 0 { ax_raw + ndim } else { ax_raw };
    if ax < 0 || ax >= ndim - 1 {
        return Ok(None); // strictly non-last; the last axis goes to the 1-d/last-axis path
    }
    let ax = ax as usize;
    let n = shape[ax];
    if n < 2 {
        return Ok(None); // numpy requires >=2 samples along the axis for edge_order=1
    }
    let inner: usize = shape[ax + 1..].iter().product();
    if inner == 0 {
        return Ok(None);
    }
    let block = n * inner;
    let Some(cells) = buffer.as_slice(py) else {
        return Ok(None);
    };
    let total = cells.len();
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only under the GIL.
    let data: &[f64] = unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), total) };
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let out = numpy.call_method("empty", (total,), Some(&kwargs))?;
    {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&out) else {
            return Ok(None);
        };
        let Some(out_cells) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // SAFETY: freshly allocated numpy.empty output, cannot alias f; every element is
        // written exactly once (each output row is filled over j in 0..inner).
        let o: &mut [f64] =
            unsafe { std::slice::from_raw_parts_mut(out_cells.as_ptr() as *mut f64, total) };
        use rayon::prelude::*;
        const GRADIENT_PARALLEL_MIN: usize = 1 << 18;
        // Fill one output row (length `inner`) at global row index g: outer block
        // o_idx = g / n, position along the reduced axis i = g % n. Reads only input rows
        // i-1 / i+1 of the SAME outer block, so rows are independent.
        let fill_row = |g: usize, orow: &mut [f64]| {
            let o_idx = g / n;
            let i = g % n;
            let base = o_idx * block;
            if i == 0 {
                let (cur, hi) = (base, base + inner);
                for j in 0..inner {
                    orow[j] = (data[hi + j] - data[cur + j]) / dx;
                }
            } else if i == n - 1 {
                let (lo, cur) = (base + (n - 2) * inner, base + (n - 1) * inner);
                for j in 0..inner {
                    orow[j] = (data[cur + j] - data[lo + j]) / dx;
                }
            } else {
                let (lo, hi) = (base + (i - 1) * inner, base + (i + 1) * inner);
                for j in 0..inner {
                    orow[j] = (data[hi + j] - data[lo + j]) / (2.0 * dx);
                }
            }
        };
        let parallel = total >= GRADIENT_PARALLEL_MIN && rayon::current_num_threads() >= 2;
        if parallel {
            o.par_chunks_mut(inner)
                .enumerate()
                .for_each(|(g, orow)| fill_row(g, orow));
        } else {
            o.chunks_mut(inner)
                .enumerate()
                .for_each(|(g, orow)| fill_row(g, orow));
        }
    }
    let shape_tuple = PyTuple::new(py, shape.iter().copied())?;
    Ok(Some(out.call_method1("reshape", (&shape_tuple,))?.unbind()))
}

#[pyfunction]
#[pyo3(signature = (f, *varargs, axis=None, edge_order=1))]
fn gradient(
    py: Python<'_>,
    f: Py<PyAny>,
    varargs: &Bound<'_, PyTuple>,
    axis: Option<Py<PyAny>>,
    edge_order: usize,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    // Native zero-copy parallel fast path for 1-D f64 with UNIFORM spacing (no spacing
    // arg => dx=1, or a single scalar spacing arg => that dx) and default axis. A
    // coordinate-array spacing arg, explicit axis, edge_order=2, N-D, or non-f64 all
    // defer to numpy so every convention matches exactly.
    let uniform_dx: Option<f64> = match varargs.len() {
        0 => Some(1.0),
        1 => varargs.get_item(0)?.extract::<f64>().ok(), // None if it's a coordinate array
        _ => None,
    };
    // The native path computes the gradient along the LAST (contiguous) axis and returns a
    // single array. numpy returns a single array only when an axis is given (or for 1-D);
    // with no axis on N-D it returns a list. So take native only when the target axis is
    // the last one: axis=None requires ndim==1; axis=k requires k to normalize to ndim-1.
    let axis_is_last = uniform_dx.is_some()
        && match f.bind(py).getattr("ndim").and_then(|n| n.extract::<usize>()) {
            Ok(ndim) if ndim >= 1 => match axis.as_ref() {
                None => ndim == 1,
                Some(a) => a
                    .bind(py)
                    .extract::<isize>()
                    .ok()
                    .map(|ax| if ax < 0 { ax + ndim as isize } else { ax })
                    .is_some_and(|norm| norm == ndim as isize - 1),
            },
            _ => false,
        };
    if axis_is_last
        && let Some(dx) = uniform_dx
        && let Some(out) = try_zerocopy_f64_gradient_1d(py, &numpy, f.bind(py), dx, edge_order)?
    {
        return Ok(out);
    }
    // Native strided (non-last) single-axis gradient: numpy's pure-Python slice
    // implementation is ~30+ ms for a 4096x1024 axis=0 call; the row-combine kernel
    // (each output row = a vectorized combo of two input rows, parallel across rows)
    // avoids that. Uniform scalar spacing, edge_order=1, f64 C-contiguous, single int
    // axis resolving to a non-last axis. See try_zerocopy_f64_gradient_strided_axis.
    if !axis_is_last
        && let Some(dx) = uniform_dx
        && let Some(ax_obj) = axis.as_ref()
        && let Ok(ax_raw) = ax_obj.bind(py).extract::<isize>()
        && let Some(out) =
            try_zerocopy_f64_gradient_strided_axis(py, &numpy, f.bind(py), ax_raw, dx, edge_order)?
    {
        return Ok(out);
    }
    // Native FULL gradient (axis=None on an N-D array, uniform spacing): numpy returns a
    // TUPLE of per-axis gradients, each via its slow pure-Python slice path (~27 ms for a
    // 2048x1024 2-D call). Compute each axis with the native helpers (last axis contiguous,
    // others strided) and return the tuple. Any axis the helpers can't take (edge_order=2,
    // non-f64/non-contiguous) aborts to the numpy passthrough so the result matches exactly.
    if axis.as_ref().is_none_or(|v| v.bind(py).is_none())
        && let Some(dx) = uniform_dx
        && let Ok(ndim) = f.bind(py).getattr("ndim").and_then(|n| n.extract::<usize>())
        && ndim >= 2
    {
        let mut grads: Vec<Py<PyAny>> = Vec::with_capacity(ndim);
        let mut all_ok = true;
        for k in 0..ndim {
            let step = if k == ndim - 1 {
                try_zerocopy_f64_gradient_1d(py, &numpy, f.bind(py), dx, edge_order)?
            } else {
                try_zerocopy_f64_gradient_strided_axis(
                    py,
                    &numpy,
                    f.bind(py),
                    k as isize,
                    dx,
                    edge_order,
                )?
            };
            match step {
                Some(g) => grads.push(g),
                None => {
                    all_ok = false;
                    break;
                }
            }
        }
        if all_ok {
            let tuple = PyTuple::new(py, grads.iter().map(|g| g.bind(py)))?;
            return Ok(tuple.into_any().unbind());
        }
    }
    // Passthrough to np.gradient so spacing-argument handling, axis
    // selection, return-shape conventions, and boundary schemes match
    // NumPy exactly.
    let gradient_fn = numpy.getattr("gradient")?;
    let mut positional: Vec<Py<PyAny>> = Vec::with_capacity(varargs.len() + 1);
    positional.push(f);
    for arg in varargs.iter() {
        positional.push(arg.unbind());
    }
    let args = PyTuple::new(py, positional.iter().map(|item| item.bind(py)))?;
    let kwargs = PyDict::new(py);
    if let Some(axis_val) = axis {
        kwargs.set_item("axis", axis_val.bind(py))?;
    }
    if edge_order != 1 {
        kwargs.set_item("edge_order", edge_order)?;
    }
    Ok(gradient_fn.call(args, Some(&kwargs))?.unbind())
}

#[pyfunction]
#[pyo3(signature = (a, n=1, axis=-1, *varargs, **kwargs))]
fn diff(
    py: Python<'_>,
    a: Py<PyAny>,
    n: i64,
    axis: i64,
    varargs: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let diff_fn = numpy.getattr("diff")?;
    let fallback = || -> PyResult<Py<PyAny>> {
        let mut positional: Vec<Py<PyAny>> = Vec::with_capacity(varargs.len() + 3);
        positional.push(a.clone_ref(py));
        positional.push(n.into_pyobject(py)?.into_any().unbind());
        positional.push(axis.into_pyobject(py)?.into_any().unbind());
        for arg in varargs.iter() {
            positional.push(arg.unbind());
        }
        let args = PyTuple::new(py, positional.iter().map(|item| item.bind(py)))?;
        let call_kwargs = PyDict::new(py);
        if let Some(kwargs) = kwargs {
            for (key, value) in kwargs.iter() {
                call_kwargs.set_item(key, value)?;
            }
        }
        Ok(diff_fn.call(args, Some(&call_kwargs))?.unbind())
    };

    if varargs.len() > 0 || kwargs.is_some_and(|kwargs| !kwargs.is_empty()) {
        return fallback();
    }

    let Ok(n) = usize::try_from(n) else {
        return fallback();
    };
    // datetime64 / timedelta64 are int64-backed: diff(datetime64[U]) -> timedelta64[U]
    // and diff(timedelta64[U]) -> timedelta64[U]. numpy.diff handles these via Python
    // dispatch (~1.11x). View the buffer as int64, reuse the contiguous int zero-copy
    // diff (kind 'M'/'m' otherwise misses every fast path), then reinterpret the result
    // as timedelta64[U] (the M8->m8 dtype-string swap maps either input kind to the
    // timedelta output). Bit-identical (int64 subtraction is exactly numpy's). Any miss
    // (non-contiguous, empty axis) falls to the numpy.diff fallback.
    if n >= 1 {
        let a_bound = a.bind(py);
        if a_bound.is_exact_instance(&numpy.getattr("ndarray")?) {
            let dtype = a_bound.getattr("dtype")?;
            let kind = dtype.getattr("kind")?.extract::<String>()?;
            if (kind == "M" || kind == "m")
                && a_bound
                    .getattr("flags")?
                    .getattr("c_contiguous")?
                    .extract::<bool>()?
            {
                // Small inputs: the int64-view + reinterpret setup loses to numpy.diff
                // (the small-array crossing wall, measured ~2.1x @1K, ~parity @10K);
                // delegate. The native path wins from ~16K (0.45x @100K, 0.39x @200K).
                const DATETIME_DIFF_NATIVE_MIN: usize = 1 << 14;
                if a_bound.getattr("size")?.extract::<usize>()? < DATETIME_DIFF_NATIVE_MIN {
                    return fallback();
                }
                let dtype_str = dtype.getattr("str")?.extract::<String>()?; // e.g. "<M8[D]"
                let td_str = dtype_str.replace("M8", "m8"); // timedelta64[U]
                let int_view = a_bound.call_method1("view", ("int64",))?;
                let mut current: Py<PyAny> = int_view.unbind();
                let mut all_ok = true;
                for _ in 0..n {
                    let cur = current.bind(py);
                    match try_zerocopy_int_diff(py, cur, 1, axis)? {
                        Some(out) => current = out,
                        None => {
                            all_ok = false;
                            break;
                        }
                    }
                }
                if all_ok {
                    let td_dtype = numpy.call_method1("dtype", (td_str,))?;
                    return Ok(current.bind(py).call_method1("view", (&td_dtype,))?.unbind());
                }
                return fallback();
            }
        }
    }
    // Zero-copy diff via repeated first differences. numpy defines the n-th
    // difference as the first difference applied n times, so each step reuses the
    // n==1 zero-copy paths (1-D f64, per-axis f64, integer all-widths) on the
    // prior result's buffer — covering higher-order diff (n>1) for every dtype the
    // first-difference path supports. Bit-identical (each step is the same op
    // numpy performs in the same order). If any step cannot take the zero-copy
    // path (n==0, non-f64/int dtype, non-contiguous, empty axis), the whole thing
    // falls through to the general extract path below with the original full n.
    if n >= 1 {
        let mut current: Py<PyAny> = a.clone_ref(py);
        let mut all_ok = true;
        for _ in 0..n {
            let cur = current.bind(py);
            let step = if let Some(out) = try_zerocopy_f64_diff1d(py, cur, 1, axis)? {
                Some(out)
            } else if let Some(out) = try_zerocopy_f64_diff_axis(py, cur, 1, axis)? {
                Some(out)
            } else if let Some(out) = try_zerocopy_int_diff(py, cur, 1, axis)? {
                Some(out)
            } else {
                try_zerocopy_f32_diff(py, cur, 1, axis)?
            };
            match step {
                Some(out) => current = out,
                None => {
                    all_ok = false;
                    break;
                }
            }
        }
        if all_ok {
            return Ok(current);
        }
    }
    // Non-contiguous (transposed/strided) ndarrays make every zero-copy diff path bail
    // to the cold extract → native diff (~5.6x slower than numpy's strided diff).
    // Delegate them to numpy (byte-identical).
    if a.bind(py).is_exact_instance(&numpy.getattr("ndarray")?)
        && !a
            .bind(py)
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return fallback();
    }
    // Bool input reaches here (the zero-copy f64/int/f32 paths above don't take it).
    // numpy's diff(bool) is adjacent XOR with a bool output and is optimal (single
    // pass); the extract path below bridges bool->f64 and runs ~700x slower (85ms vs
    // 122us @4M). numpy is the parity reference, so defer bool to it. (Checked only on
    // the fallthrough — f64/int/f32 already returned.)
    if a
        .bind(py)
        .is_exact_instance(&numpy.getattr("ndarray")?)
        && a.bind(py).getattr("dtype")?.getattr("kind")?.extract::<String>()? == "b"
    {
        return fallback();
    }
    let a = match extract_precise_numeric_array(py, a.bind(py), "diff(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let result = match a.diff(n, Some(axis as isize)) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    build_numpy_array_from_ufunc(py, &result)
}

#[pyfunction]
#[pyo3(signature = (a, shift, axis=None))]
fn roll(
    py: Python<'_>,
    a: Py<PyAny>,
    shift: Py<PyAny>,
    axis: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    // Native roll via UFuncArray::roll / roll_multi for real/complex
    // numeric inputs. Scalar shift with scalar-or-None axis routes
    // through roll; tuple-of-shifts with tuple-of-axes routes through
    // roll_multi; mismatched tuples, non-int shifts, non-numeric dtypes
    // fall back to np.roll so numpy's dispatch surface stays exact.
    let numpy = py.import("numpy")?;
    let roll_fn = numpy.getattr("roll")?;
    let a_for_fallback = a.clone_ref(py);
    let shift_for_fallback = shift.clone_ref(py);
    let axis_for_fallback = axis.as_ref().map(|v| v.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis_for_fallback.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        Ok(roll_fn
            .call(
                (a_for_fallback.bind(py), shift_for_fallback.bind(py)),
                Some(&kwargs),
            )?
            .unbind())
    };

    // Non-contiguous (transposed/strided) ndarrays can't use the contiguous block-copy
    // fast paths and otherwise reach the cold extract → rebuild (~3.5x slower than
    // numpy's strided roll). Delegate them to numpy up front.
    if noncontiguous_ndarray(&numpy, a.bind(py))? {
        return fallback();
    }

    // Zero-copy flatten roll for C-contiguous f64 ndarrays (axis=None any ndim,
    // or 1-D with axis 0/-1); skips the cold extract/build Vecs. Bit-identical;
    // per-axis multi-dim rolls and tuple shifts fall through to the general path.
    if let Some(out) = try_zerocopy_f64_roll(py, a.bind(py), shift.bind(py), axis.as_ref())? {
        return Ok(out);
    }

    // Dtype-agnostic flatten roll (byte rotation) for every other dtype — int
    // (all widths), float32, complex, bool — covering the same axis=None / 1-D
    // axis cases. Bit-identical (elements move verbatim) and skips the cold,
    // for-ints-lossy extract Vec.
    if let Some(out) = try_zerocopy_any_roll(py, a.bind(py), shift.bind(py), axis.as_ref())? {
        return Ok(out);
    }

    // Zero-copy per-axis roll for C-contiguous f64 ndarrays with a scalar shift
    // and an explicit integer axis (the multi-dim case the flatten path skips);
    // block-copies the rotated inner-lanes. Bit-identical; tuple shifts/axes and
    // out-of-range axes fall through to the general path.
    if let (Ok(shift_scalar), Some(axis_obj)) = (shift.bind(py).extract::<i64>(), axis.as_ref()) {
        let axis_bound = axis_obj.bind(py);
        if !axis_bound.is_none()
            && let Ok(axis_int) = axis_bound.extract::<i64>()
        {
            if let Some(out) = try_zerocopy_f64_roll_axis(py, a.bind(py), shift_scalar, axis_int)? {
                return Ok(out);
            }
            // Dtype-agnostic byte per-axis roll for int/float32/bool (the non-f64
            // dtypes); contiguous per-lane block copies, bit-identical.
            if let Some(out) = try_zerocopy_any_roll_axis(py, a.bind(py), shift_scalar, axis_int)? {
                return Ok(out);
            }
        }
    }

    // Zero-copy multi-axis roll for a tuple/list of shifts with matching axes on a
    // 2-D f64 array: a single-pass fused roll (one allocation) of the net per-axis
    // shift. Bit-identical; higher-dim, non-f64, or out-of-range axes fall through.
    if let (Ok(shifts), Some(axis_obj)) = (shift.bind(py).extract::<Vec<i64>>(), axis.as_ref())
        && let Ok(axes) = axis_obj.bind(py).extract::<Vec<i64>>()
        && !axes.is_empty()
        && axes.len() == shifts.len()
        && let Some(result) = try_zerocopy_f64_roll_2d_multi(py, a.bind(py), &shifts, &axes)?
    {
        return Ok(result);
    }

    // Everything the zero-copy paths above missed — most importantly NON-f64
    // tuple-axis rolls (roll(M, (5,7), axis=(0,1))) — went through extract_precise
    // -> UFuncArray::roll(_multi) -> export-bridge rebuild, which was 37-355x slower
    // than numpy (int8 2-D tuple roll 355x). roll is a pure element relocation
    // (sequential 1-D rotations) that numpy does at memcpy speed, so delegate the
    // residual. (The f64 flatten / per-axis / 2-D-tuple fast paths above are kept.)
    fallback()
}

#[pyfunction]
#[pyo3(signature = (a, bins=None, range=None, weights=None))]
fn histogram_bin_edges(
    py: Python<'_>,
    a: Py<PyAny>,
    bins: Option<Py<PyAny>>,
    range: Option<Py<PyAny>>,
    weights: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let histogram_bin_edges_fn = numpy.getattr("histogram_bin_edges")?;
        let kwargs = PyDict::new(py);
        if let Some(bins_val) = bins.as_ref() {
            kwargs.set_item("bins", bins_val.bind(py))?;
        }
        if let Some(range_val) = range.as_ref() {
            kwargs.set_item("range", range_val.bind(py))?;
        }
        if let Some(weights_val) = weights.as_ref() {
            kwargs.set_item("weights", weights_val.bind(py))?;
        }
        Ok(histogram_bin_edges_fn
            .call((a.bind(py),), Some(&kwargs))?
            .unbind())
    };

    // Weights only affect estimator-driven bin-width choice; with explicit
    // int bins + range they're ignored. Since our native path supports
    // exactly that combo, pass through weights without using them.
    // Delegate when a string estimator or non-int bins sequence lands that
    // we don't reproduce.
    let bins_bound = bins.as_ref().map(|v| v.bind(py));
    let range_bound = range.as_ref().map(|v| v.bind(py));
    let weights_bound = weights.as_ref().map(|v| v.bind(py));

    // Case 1: explicit array-like bins → return the edges coerced through
    // numpy.asarray. This preserves identity when bins is already an
    // ndarray (matches numpy's behavior).
    if let Some(bins_val) = bins_bound
        && !bins_val.is_instance_of::<pyo3::types::PyInt>()
        && !bins_val.is_instance_of::<pyo3::types::PyString>()
        && !bins_val.is_none()
    {
        // Must be array-like. numpy.asarray to enforce dtype coercion.
        // Weights are ignored with explicit edges (documented).
        return Ok(numpy.call_method1("asarray", (bins_val,))?.unbind());
    }

    // Case 2: int bins (default 10 when bins is None or missing) with
    // no estimator. Range may or may not be present.
    if bins_bound
        .map(|v| v.is_none() || v.is_instance_of::<pyo3::types::PyInt>())
        .unwrap_or(true)
    {
        if weights_bound.is_some_and(|w| !w.is_none()) {
            // weights are ignored with int bins per numpy docs, but our
            // extraction below doesn't use them — confirm they at least
            // parse as numeric so we don't silently accept garbage.
            if extract_precise_numeric_array(
                py,
                weights_bound.unwrap(),
                "histogram_bin_edges(weights)",
            )
            .is_err()
            {
                return fallback(py);
            }
        }
        let nbins: i64 = match bins_bound {
            Some(v) if !v.is_none() => match v.extract::<i64>() {
                Ok(n) if n > 0 => n,
                _ => return fallback(py),
            },
            _ => 10,
        };

        let a_bound = a.bind(py);
        let (amin, amax) = if let Some(range_val) = range_bound
            && !range_val.is_none()
        {
            // range is a 2-tuple.
            match range_val.extract::<(f64, f64)>() {
                Ok((lo, hi)) if hi >= lo && lo.is_finite() && hi.is_finite() => (lo, hi),
                _ => return fallback(py),
            }
        } else {
            // histogram_bin_edges only needs min/max of the data. The old path extracted the
            // WHOLE array into a UFuncArray copy and THEN scanned it — two O(n) passes plus an
            // allocation, ~4x behind numpy. NumPy itself does a 2-pass a.min()/a.max(); reading
            // the borrowed f64 buffer once (min+max+finite in a SINGLE pass, no copy) beats it.
            // Non-f64 / non-contiguous / non-finite fall back to numpy.
            let ndarray_t = numpy.getattr("ndarray")?;
            if !a_bound.is_exact_instance(&ndarray_t) || !numpy_dtype_is_f64(py, a_bound) {
                return fallback(py);
            }
            if !a_bound
                .getattr("flags")?
                .getattr("c_contiguous")?
                .extract::<bool>()?
            {
                return fallback(py);
            }
            let Ok(buf) = PyBuffer::<f64>::get(a_bound) else {
                return fallback(py);
            };
            let Some(cells) = buf.as_slice(py) else {
                return fallback(py);
            };
            let n = cells.len();
            if n == 0 {
                (0.0_f64, 1.0_f64)
            } else {
                // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only under GIL.
                let data: &[f64] =
                    unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), n) };
                // Branchless single pass: f64::min/max (vectorizable, NaN-ignoring) + a
                // non-finite OR-reduce flag (no early return, so LLVM autovectorizes the
                // whole loop -> 1 SIMD pass, beating numpy's 2-pass a.min()/a.max()). Any
                // non-finite -> fall back to numpy (NaN-propagation parity). lo/hi are only
                // consumed when !bad (all finite), so NaN/inf can't leak into the result.
                let mut lo = f64::INFINITY;
                let mut hi = f64::NEG_INFINITY;
                let mut bad = false;
                for &v in data {
                    bad |= !v.is_finite();
                    lo = lo.min(v);
                    hi = hi.max(v);
                }
                if bad {
                    return fallback(py);
                }
                if lo == hi {
                    (lo - 0.5, hi + 0.5)
                } else {
                    (lo, hi)
                }
            }
        };

        let edges =
            match UFuncArray::linspace_endpoint(amin, amax, (nbins + 1) as usize, true, DType::F64)
            {
                Ok(value) => value,
                Err(_) => return fallback(py),
            };
        return build_numpy_array_from_ufunc(py, &edges);
    }

    // String estimators ('fd', 'auto', 'sturges', ...) need numpy.
    fallback(py)
}

#[pyfunction]
#[pyo3(signature = (a, order="C"))]
fn ravel(py: Python<'_>, a: Py<PyAny>, order: &str) -> PyResult<Py<PyAny>> {
    // np.ravel returns a flattened VIEW when the input is contiguous in the
    // requested order (a copy otherwise) — pure shape/stride metadata, no data
    // movement. The old native path materialized a full O(n) copy AND diverged
    // from numpy's view semantics (writing through the result must alias the
    // input). Build the view via the array's ravel method, which reproduces
    // numpy's exact view-or-copy decision and preserves the input dtype.
    let numpy = py.import("numpy")?;
    let arr = numpy.call_method1("asarray", (a.bind(py),))?;
    Ok(arr.call_method1("ravel", (order,))?.unbind())
}

#[pyfunction]
#[pyo3(signature = (a, shape=None, order="C", *, copy=None, newshape=None))]
fn reshape(
    py: Python<'_>,
    a: Py<PyAny>,
    shape: Option<Py<PyAny>>,
    order: &str,
    copy: Option<bool>,
    newshape: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    // np.reshape returns a VIEW when the new shape is stride-compatible (a copy
    // otherwise) — pure metadata. The old native path always materialized a copy
    // (slow, a view-semantics divergence, and it widened narrow dtypes). Delegate
    // to numpy.reshape, which yields the exact view/copy, preserves the input
    // dtype, and raises numpy's exact errors (including the 'K'-order ValueError).
    //
    // numpy 2.1 renamed `newshape` -> `shape` and added keyword-only `copy`; the
    // `newshape` spelling is still accepted (deprecated) on 2.1-2.3 and removed on
    // 2.4+. Rather than pin one numpy version, forward whichever bound spelling the
    // caller gives straight to numpy.reshape so fnp's accept/reject behavior tracks
    // the installed numpy EXACTLY (e.g. newshape= raises here iff it raises in the
    // numpy on this machine). copy is forwarded only when set so numpy's default
    // (copy=None) is preserved on numpy builds predating the copy argument.
    let numpy = py.import("numpy")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("order", order)?;
    if let Some(copy) = copy {
        kwargs.set_item("copy", copy)?;
    }
    if let Some(newshape) = newshape.as_ref() {
        kwargs.set_item("newshape", newshape.bind(py))?;
    }
    // `shape` is passed POSITIONALLY (the 2nd positional arg on every numpy — named
    // `newshape` pre-2.1, `shape` after — so a positional bind is version-robust,
    // unlike a `shape=` keyword which fails on pre-2.1 builds). When `shape` is
    // omitted we forward no positional bound and let numpy validate (e.g. raise its
    // own missing-argument error, or consume the `newshape` kwarg above).
    let mut args: Vec<Bound<'_, PyAny>> = vec![a.bind(py).clone()];
    if let Some(shape) = shape.as_ref() {
        args.push(shape.bind(py).clone());
    }
    Ok(numpy
        .getattr("reshape")?
        .call(PyTuple::new(py, args)?, Some(&kwargs))?
        .unbind())
}

#[pyfunction]
#[pyo3(signature = (a, axes=None))]
fn transpose(py: Python<'_>, a: Py<PyAny>, axes: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    // np.transpose is a pure stride permutation — it returns a VIEW (O(1)), never
    // moves data. The old native path materialized a full transposed copy, ~14x
    // slower AND a view-semantics divergence (and it widened narrow dtypes via the
    // extract). Delegate to numpy.transpose, which yields the exact view, preserves
    // the dtype, and reproduces numpy's exact error surface.
    let numpy = py.import("numpy")?;
    let kwargs = PyDict::new(py);
    if let Some(axes_val) = axes.as_ref() {
        kwargs.set_item("axes", axes_val.bind(py))?;
    }
    Ok(numpy
        .getattr("transpose")?
        .call((a.bind(py),), Some(&kwargs))?
        .unbind())
}

