// Generic in-place scatter a.flat[ind[i]] = v[i % vlen] for one integer dtype.
// The inverse of take/gather: numpy.put writes values (cycled when shorter than
// the index list) into a's own buffer, applying indices in order so duplicates
// resolve last-write-wins — a sequential loop matches exactly. Negative indices
// wrap by += n. A validation pass checks every index BEFORE any write, so an
// out-of-range index leaves a untouched and we defer to numpy.put for the exact
// IndexError (no partial/double application). Requires a writable C-contiguous
// buffer (as_mut_slice → None otherwise) and v of the identical dtype T
// (PyBuffer::<T>::get on v is a free dtype-equality gate); mismatches fall
// through. Returns Some(()) when the in-place write completed, None to defer.
fn put_typed<'py, T: pyo3::buffer::Element + Copy>(
    py: Python<'py>,
    a: &Bound<'py, PyAny>,
    ind64: &Bound<'py, PyAny>,
    v: &Bound<'py, PyAny>,
) -> PyResult<Option<()>> {
    let (Ok(a_buf), Ok(i_buf), Ok(v_buf)) = (
        PyBuffer::<T>::get(a),
        PyBuffer::<i64>::get(ind64),
        PyBuffer::<T>::get(v),
    ) else {
        return Ok(None);
    };
    let (Some(idx_in), Some(v_in)) = (i_buf.as_slice(py), v_buf.as_slice(py)) else {
        return Ok(None);
    };
    let vlen = v_in.len();
    let nind = idx_in.len();
    if nind == 0 {
        return Ok(Some(())); // no indices → no-op (a unchanged)
    }
    if vlen == 0 {
        return Ok(None); // numpy raises on empty values + non-empty indices; defer
    }
    let n = a_buf.item_count() as i64;
    // Validate ALL indices first so an OOB leaves a unmutated (numpy raises IndexError).
    for c in idx_in.iter() {
        let mut idx = c.get();
        if idx < 0 {
            idx += n;
        }
        if idx < 0 || idx >= n {
            return Ok(None);
        }
    }
    let Some(out) = a_buf.as_mut_slice(py) else {
        return Ok(None); // read-only / non-contiguous → defer
    };
    for (i, c) in idx_in.iter().enumerate() {
        let mut idx = c.get();
        if idx < 0 {
            idx += n;
        }
        out[idx as usize].set(v_in[i % vlen].get());
    }
    Ok(Some(()))
}

// Zero-copy in-place np.put for the integer dtypes the native path sends through
// the cold extract_numeric_array f64-bridge + full copy-back (~36-45x slower, and
// lossy for wide ints). Indices are normalized to a contiguous int64 array; the
// values are cast to a's dtype and raveled (matching numpy.put's own cast — a SCALAR
// value broadcasts, a wider/float value truncates, and an out-of-range python int
// raises OverflowError exactly as numpy does, so we defer that case to numpy). 'raise'
// mode only (gated by the caller). Float indices and non-ndarray `a` fall through.
fn try_zerocopy_any_put(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    ind: &Bound<'_, PyAny>,
    v: &Bound<'_, PyAny>,
) -> PyResult<Option<()>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let a_dtype = a.getattr("dtype")?;
    let kind = a_dtype.getattr("kind")?.extract::<String>()?;
    let itemsize = a_dtype.getattr("itemsize")?.extract::<usize>()?;
    if kind != "i" && kind != "u" && kind != "f" {
        return Ok(None);
    }
    // Normalize indices to a contiguous int64 array; only integer index dtypes
    // are accepted (float indices raise in numpy — defer).
    let ind_arr = numpy.call_method1("asarray", (ind,))?;
    let ind_kind = ind_arr.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
    if ind_kind != "i" && ind_kind != "u" {
        return Ok(None);
    }
    let kw = PyDict::new(py);
    kw.set_item("dtype", "int64")?;
    let ind64 = numpy
        .getattr("ascontiguousarray")?
        .call((ind_arr,), Some(&kw))?;
    // Cast values to a's dtype and ravel (covers scalar / list / array, any dtype),
    // matching numpy.put's cast. asarray raises OverflowError for an out-of-range
    // python int exactly as numpy.put does; on any cast failure, route the call to
    // numpy.put so it raises the canonical error (the native fallback path would
    // raise a different exception type) — numpy raises before any in-place write.
    let kw_v = PyDict::new(py);
    kw_v.set_item("dtype", &a_dtype)?;
    let v_cast = match numpy.getattr("asarray")?.call((v,), Some(&kw_v)) {
        Ok(arr) => arr.call_method1("reshape", ((-1isize,),))?,
        Err(_) => {
            let kwp = PyDict::new(py);
            kwp.set_item("mode", "raise")?;
            numpy.getattr("put")?.call((a, ind, v), Some(&kwp))?;
            return Ok(Some(()));
        }
    };
    match (kind.as_str(), itemsize) {
        ("i", 8) => put_typed::<i64>(py, a, &ind64, &v_cast),
        ("i", 4) => put_typed::<i32>(py, a, &ind64, &v_cast),
        ("i", 2) => put_typed::<i16>(py, a, &ind64, &v_cast),
        ("i", 1) => put_typed::<i8>(py, a, &ind64, &v_cast),
        ("u", 8) => put_typed::<u64>(py, a, &ind64, &v_cast),
        ("u", 4) => put_typed::<u32>(py, a, &ind64, &v_cast),
        ("u", 2) => put_typed::<u16>(py, a, &ind64, &v_cast),
        ("u", 1) => put_typed::<u8>(py, a, &ind64, &v_cast),
        // Float scatter is value-agnostic: view both `a` (aliasing its own buffer,
        // so the write is in-place) and the dtype-cast values as the same-width
        // unsigned integer and reuse the u16/u32/u64 put_typed instantiations — no
        // new monomorphizations that could perturb the already-fast integer path.
        // A non-contiguous `a` (or values) makes .view raise; defer to numpy then.
        ("f", 8) => {
            let uview = numpy.getattr("uint64")?;
            let (Ok(a_u), Ok(v_u)) = (
                a.call_method1("view", (&uview,)),
                v_cast.call_method1("view", (&uview,)),
            ) else {
                return Ok(None);
            };
            put_typed::<u64>(py, &a_u, &ind64, &v_u)
        }
        ("f", 4) => {
            let uview = numpy.getattr("uint32")?;
            let (Ok(a_u), Ok(v_u)) = (
                a.call_method1("view", (&uview,)),
                v_cast.call_method1("view", (&uview,)),
            ) else {
                return Ok(None);
            };
            put_typed::<u32>(py, &a_u, &ind64, &v_u)
        }
        ("f", 2) => {
            let uview = numpy.getattr("uint16")?;
            let (Ok(a_u), Ok(v_u)) = (
                a.call_method1("view", (&uview,)),
                v_cast.call_method1("view", (&uview,)),
            ) else {
                return Ok(None);
            };
            put_typed::<u16>(py, &a_u, &ind64, &v_u)
        }
        _ => Ok(None),
    }
}

#[pyfunction]
#[pyo3(signature = (a, ind, v, mode="raise"))]
fn put(
    py: Python<'_>,
    a: Py<PyAny>,
    ind: Py<PyAny>,
    v: Py<PyAny>,
    mode: &str,
) -> PyResult<Py<PyAny>> {
    let a_for_fallback = a.clone_ref(py);
    let ind_for_fallback = ind.clone_ref(py);
    let v_for_fallback = v.clone_ref(py);
    let mode_owned = mode.to_string();
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("mode", &mode_owned)?;
        Ok(numpy
            .getattr("put")?
            .call(
                (
                    a_for_fallback.bind(py),
                    ind_for_fallback.bind(py),
                    v_for_fallback.bind(py),
                ),
                Some(&kwargs),
            )?
            .unbind())
    };

    // The native path only models the default 'raise' mode; 'wrap'/'clip' (and
    // any invalid mode string, which NumPy rejects with ValueError) defer to
    // numpy.put.
    if mode != "raise" {
        return fallback();
    }

    let a = a.bind(py);
    require_numpy_ndarray(py, a, "put")?;

    // Check for complex dtype and fallback to numpy
    let dtype_kind = a.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
    if dtype_kind == "c" {
        return fallback();
    }

    // Zero-copy in-place scatter for integer a + integer indices + same-dtype
    // ndarray values (the common case); skips the cold extract + full copy-back.
    // Bit-identical; other dtypes/scalar-or-list values/OOB indices fall through.
    if try_zerocopy_any_put(py, a, ind.bind(py), v.bind(py))?.is_some() {
        return Ok(py.None());
    }

    let mut array = extract_numeric_array(py, a, "put(a)")?;
    let (_, indices) = extract_take_indices(py, ind.bind(py), "put(ind)")?;
    let values = extract_numeric_array(py, v.bind(py), "put(v)")?;

    // numpy.put raises IndexError (not ValueError) on out-of-bounds index.
    // Our ufunc layer returns Msg which map_ufunc_error flattens to
    // PyValueError — fall back to numpy so the exception type matches.
    if array.put(&indices, &values).is_err() {
        return fallback();
    }
    copy_result_into_numpy_array(py, a, &array)?;
    Ok(py.None())
}

#[pyfunction]
#[pyo3(signature = (dst, src, casting="same_kind", r#where=None))]
fn copyto(
    py: Python<'_>,
    dst: Py<PyAny>,
    src: Py<PyAny>,
    casting: &str,
    r#where: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    // Delegate to NumPy so in-place broadcasted writes, boolean-mask
    // selection, casting policy checks, and shape-mismatch errors stay
    // exactly aligned with numpy.
    let numpy = py.import("numpy")?;
    let copyto_fn = numpy.getattr("copyto")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("casting", casting)?;
    if let Some(where_val) = r#where {
        kwargs.set_item("where", where_val.bind(py))?;
    }
    Ok(copyto_fn
        .call((dst.bind(py), src.bind(py)), Some(&kwargs))?
        .unbind())
}

#[pyfunction]
fn place(py: Python<'_>, arr: Py<PyAny>, mask: Py<PyAny>, vals: Py<PyAny>) -> PyResult<Py<PyAny>> {
    let arr = arr.bind(py);
    require_numpy_ndarray(py, arr, "place")?;

    // Check for complex dtype and fallback to numpy
    let dtype_kind = arr.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
    if dtype_kind == "c" {
        let numpy = py.import("numpy")?;
        numpy
            .getattr("place")?
            .call1((arr, mask.bind(py), vals.bind(py)))?;
        return Ok(py.None());
    }

    // Zero-copy in-place write for the common case (f64 arr + bool mask of
    // identical shape + non-empty f64 vals); touches only the masked slots of
    // arr's own buffer, cycling vals by the running True count. Bit-identical;
    // shape mismatch, empty vals, and other dtypes fall through.
    if try_zerocopy_f64_place(py, arr, mask.bind(py), vals.bind(py))? {
        return Ok(py.None());
    }
    // All other fixed-width dtypes (narrow ints, int64/uint64, float32, bool):
    // in-place scatter through a same-width unsigned view, skipping the cold
    // extract/copy-back (6-8x slower for ints). Bit-identical.
    if try_zerocopy_any_place(py, arr, mask.bind(py), vals.bind(py))? {
        return Ok(py.None());
    }

    // Scalar / list / tuple `vals` (e.g. place(a, mask, [0])): the zero-copy paths
    // require an ndarray, so a scalar/small list fell to the cold extract path
    // (2-5x slower than numpy). numpy casts vals to arr's dtype and cycles it, so
    // materialize an arr-dtype array via np.array(vals, dtype=arr.dtype) (the exact
    // cast incl. OverflowError parity) and re-enter the in-place scatter.
    {
        let numpy = py.import("numpy")?;
        let ndarray_type = numpy.getattr("ndarray")?;
        if !vals.bind(py).is_exact_instance(&ndarray_type) {
            let arr_dtype = arr.getattr("dtype")?;
            let kwargs = PyDict::new(py);
            kwargs.set_item("dtype", arr_dtype)?;
            let vals_arr = numpy
                .call_method("array", (vals.bind(py),), Some(&kwargs))?
                .call_method1("ravel", ())?;
            if vals_arr.call_method0("__len__")?.extract::<usize>()? > 0 {
                if try_zerocopy_f64_place(py, arr, mask.bind(py), &vals_arr)? {
                    return Ok(py.None());
                }
                if try_zerocopy_any_place(py, arr, mask.bind(py), &vals_arr)? {
                    return Ok(py.None());
                }
            }
        }
    }

    let mut array = extract_numeric_array(py, arr, "place(arr)")?;
    let mask = extract_numeric_array(py, mask.bind(py), "place(mask)")?;
    let values = extract_numeric_array(py, vals.bind(py), "place(vals)")?;

    array.place(&mask, &values).map_err(map_ufunc_error)?;
    copy_result_into_numpy_array(py, arr, &array)?;
    Ok(py.None())
}

#[pyfunction]
#[pyo3(signature = (a, /, mask, values))]
fn putmask(
    py: Python<'_>,
    a: Py<PyAny>,
    mask: Py<PyAny>,
    values: Py<PyAny>,
) -> PyResult<Py<PyAny>> {
    let a = a.bind(py);
    require_numpy_ndarray(py, a, "putmask")?;

    // Check for complex dtype and fallback to numpy
    let dtype_kind = a.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
    if dtype_kind == "c" {
        let numpy = py.import("numpy")?;
        numpy
            .getattr("putmask")?
            .call1((a, mask.bind(py), values.bind(py)))?;
        return Ok(py.None());
    }

    // Zero-copy in-place write for the common case (f64 a + bool mask of identical
    // shape + non-empty f64 values); touches only the masked slots of a's own
    // buffer, skipping the cold extract/copy-back. Bit-identical; shape mismatch,
    // empty values, and other dtypes fall through.
    if try_zerocopy_f64_putmask(py, a, mask.bind(py), values.bind(py))? {
        return Ok(py.None());
    }
    // All other fixed-width dtypes (narrow ints, int64/uint64, float32, bool):
    // in-place scatter through a same-width unsigned view, skipping the cold
    // extract/copy-back that widens narrow ints through f64. Bit-identical.
    if try_zerocopy_any_putmask(py, a, mask.bind(py), values.bind(py))? {
        return Ok(py.None());
    }

    // Scalar / list / tuple `values` (e.g. the common `putmask(a, mask, 0)`): the
    // zero-copy paths above require an ndarray `values`, so a scalar fell to the cold
    // extract -> copy-back path (4.7-9.4x slower than numpy). numpy casts `values` to
    // a's dtype and cycles it by flat position, so materialize a small a-dtype array
    // (numpy performs the exact unsafe cast) and re-enter the in-place scatter. A
    // scalar becomes a 1-element array (v=1 -> constant fill). Only non-ndarray
    // `values` are normalized; ndarray inputs already went through the paths above.
    {
        let numpy = py.import("numpy")?;
        let ndarray_type = numpy.getattr("ndarray")?;
        if !values.bind(py).is_exact_instance(&ndarray_type) {
            // np.array(values, dtype=a.dtype) reproduces numpy.putmask's scalar cast
            // EXACTLY, including raising OverflowError on an out-of-range Python int
            // for a narrow dtype (numpy 2.x) — astype() would silently wrap instead.
            let a_dtype = a.getattr("dtype")?;
            let kwargs = PyDict::new(py);
            kwargs.set_item("dtype", a_dtype)?;
            let vals_arr = numpy
                .call_method("array", (values.bind(py),), Some(&kwargs))?
                .call_method1("ravel", ())?;
            if vals_arr.call_method0("__len__")?.extract::<usize>()? > 0 {
                if try_zerocopy_f64_putmask(py, a, mask.bind(py), &vals_arr)? {
                    return Ok(py.None());
                }
                if try_zerocopy_any_putmask(py, a, mask.bind(py), &vals_arr)? {
                    return Ok(py.None());
                }
            }
        }
    }

    let mut array = extract_numeric_array(py, a, "putmask(a)")?;
    let mask = extract_numeric_array(py, mask.bind(py), "putmask(mask)")?;
    let values = extract_numeric_array(py, values.bind(py), "putmask(values)")?;

    array.putmask(&mask, &values).map_err(map_ufunc_error)?;
    copy_result_into_numpy_array(py, a, &array)?;
    Ok(py.None())
}

// Generic fill of np.indices' k-th coordinate slab: output[f] = (f / inner) % dim_k,
// written as contiguous blocks of `inner` equal values cycling 0..dim_k (a memset-like
// block fill that vectorizes).
fn fill_indices_typed<'py, T: pyo3::buffer::Element + Copy, F: Fn(usize) -> T>(
    py: Python<'py>,
    out: &Bound<'py, PyAny>,
    dims: &[usize],
    total: usize,
    cast: F,
) -> PyResult<bool> {
    if total == 0 {
        return Ok(true);
    }
    let Ok(buffer) = PyBuffer::<T>::get(out) else {
        return Ok(false);
    };
    let Some(output) = buffer.as_mut_slice(py) else {
        return Ok(false);
    };
    let d = dims.len();
    for k in 0..d {
        let inner: usize = dims[k + 1..].iter().product();
        let dim_k = dims[k];
        let slab_base = k * total;
        let period = dim_k * inner; // one full cycle of the axis-k pattern
        if period == 0 {
            continue;
        }
        // Fill the first period: blocks of `inner` equal values cycling 0..dim_k.
        let mut f = 0usize;
        for v in 0..dim_k {
            let cv = cast(v);
            for cell in &output[slab_base + f..slab_base + f + inner] {
                cell.set(cv);
            }
            f += inner;
        }
        // Replicate that period across the rest of the slab with block copies (which
        // memcpy-vectorize) — far faster than re-deriving each element, especially for
        // the last axis (inner==1) whose per-element cycle does not vectorize.
        let mut dst = period;
        while dst < total {
            let (head, tail) = output[slab_base..slab_base + total].split_at(dst);
            let src = &head[..period];
            for (d8, s8) in tail[..period].iter().zip(src.iter()) {
                d8.set(s8.get());
            }
            dst += period;
        }
    }
    Ok(true)
}

// Zero-copy np.indices: build the (d, *dimensions) coordinate grid directly with
// per-axis block fills instead of the cold UFuncArray build (~160x slower). Handles
// the default and any integer dtype whose range fits every dimension (a too-narrow
// dtype, which numpy wraps, and the float/sparse forms fall through to the slow path).
fn try_zerocopy_indices(
    py: Python<'_>,
    dims: &[usize],
    dtype: Option<&Bound<'_, PyAny>>,
) -> PyResult<Option<Py<PyAny>>> {
    let d = dims.len();
    if d == 0 {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    // Resolve dtype (default int64); only integer dtypes that fit every index.
    let (kind, itemsize, dt_obj): (String, usize, Bound<'_, PyAny>) = match dtype {
        Some(dt) if !dt.is_none() => {
            let np_dt = numpy.getattr("dtype")?.call1((dt,))?;
            (
                np_dt.getattr("kind")?.extract::<String>()?,
                np_dt.getattr("itemsize")?.extract::<usize>()?,
                np_dt,
            )
        }
        _ => ("i".to_string(), 8, numpy.getattr("dtype")?.call1(("int64",))?),
    };
    if kind != "i" && kind != "u" {
        return Ok(None);
    }
    let max_idx = dims.iter().map(|&n| n.saturating_sub(1)).max().unwrap_or(0) as i128;
    let bits = (8 * itemsize) as u32;
    let fits = if kind == "i" {
        max_idx < (1i128 << (bits - 1))
    } else {
        max_idx < (1i128 << bits)
    };
    if !fits {
        return Ok(None);
    }
    let total: usize = dims.iter().product();
    let mut out_shape: Vec<usize> = Vec::with_capacity(d + 1);
    out_shape.push(d);
    out_shape.extend_from_slice(dims);
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", &dt_obj)?;
    let out = numpy.call_method("empty", (PyTuple::new(py, out_shape)?,), Some(&kwargs))?;
    let ok = match (kind.as_str(), itemsize) {
        ("i", 8) => fill_indices_typed::<i64, _>(py, &out, dims, total, |v| v as i64)?,
        ("i", 4) => fill_indices_typed::<i32, _>(py, &out, dims, total, |v| v as i32)?,
        ("i", 2) => fill_indices_typed::<i16, _>(py, &out, dims, total, |v| v as i16)?,
        ("i", 1) => fill_indices_typed::<i8, _>(py, &out, dims, total, |v| v as i8)?,
        ("u", 8) => fill_indices_typed::<u64, _>(py, &out, dims, total, |v| v as u64)?,
        ("u", 4) => fill_indices_typed::<u32, _>(py, &out, dims, total, |v| v as u32)?,
        ("u", 2) => fill_indices_typed::<u16, _>(py, &out, dims, total, |v| v as u16)?,
        ("u", 1) => fill_indices_typed::<u8, _>(py, &out, dims, total, |v| v as u8)?,
        _ => return Ok(None),
    };
    if !ok {
        return Ok(None);
    }
    Ok(Some(out.unbind()))
}

#[pyfunction]
#[pyo3(signature = (dimensions, dtype=None))]
fn indices(
    py: Python<'_>,
    dimensions: Vec<usize>,
    dtype: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    if let Some(out) = try_zerocopy_indices(py, &dimensions, dtype.as_ref().map(|d| d.bind(py)))? {
        return Ok(out);
    }
    let dtype = extract_python_dtype(py, dtype, DType::I64, "indices(dtype)")?;
    let result = UFuncArray::indices(&dimensions, dtype).map_err(map_ufunc_error)?;
    build_numpy_array_from_ufunc(py, &result)
}

#[pyfunction]
#[pyo3(signature = (n, m=None, k=0, dtype=None))]
fn tri(
    py: Python<'_>,
    n: usize,
    m: Option<usize>,
    k: i64,
    dtype: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    // numpy.tri creates the boolean/typed lower-triangle directly; the native
    // UFuncArray build-then-convert path was 18-178x slower (int8 178x). Delegate.
    let numpy = py.import("numpy")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("k", k)?;
    if let Some(mm) = m {
        kwargs.set_item("M", mm)?;
    }
    if let Some(dtype_val) = dtype.as_ref() {
        kwargs.set_item("dtype", dtype_val.bind(py))?;
    }
    Ok(numpy.getattr("tri")?.call((n,), Some(&kwargs))?.unbind())
}

#[pyfunction]
#[pyo3(signature = (condition, a, copy=true))]
fn masked_where(
    py: Python<'_>,
    condition: Py<PyAny>,
    a: Py<PyAny>,
    copy: bool,
) -> PyResult<Py<PyAny>> {
    let condition_for_fallback = condition.clone_ref(py);
    let a_for_fallback = a.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let masked_where_fn = numpy.getattr("ma")?.getattr("masked_where")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("copy", copy)?;
        Ok(masked_where_fn
            .call(
                (condition_for_fallback.bind(py), a_for_fallback.bind(py)),
                Some(&kwargs),
            )?
            .unbind())
    };

    if !copy {
        return fallback();
    }

    // Fast path: a PLAIN ndarray a (never already-masked — get_type().is(ndarray)
    // excludes MaskedArray subclasses). numpy's own masked_where is the parity
    // reference and ~12x faster than the extract -> combine -> rebuild path below
    // (159ms vs 13.5ms @4M f64), which copies both the condition and the data into
    // owned Vecs. numpy handles scalar-broadcast conditions, shape-mismatch
    // IndexErrors, and all-False mask shrinking natively, so the result is identical.
    {
        let numpy = py.import("numpy")?;
        let ndarray_type = numpy.getattr("ndarray")?;
        if a.bind(py).get_type().is(&ndarray_type) {
            return fallback();
        }
    }

    let condition = match extract_numeric_array(py, condition.bind(py), "masked_where(condition)") {
        Ok(condition) => condition,
        Err(_) => return fallback(),
    };
    let Some(masked_a) = extract_numeric_masked_array(py, a.bind(py), "masked_where(a)")? else {
        return fallback();
    };
    let condition = if condition.shape().is_empty() {
        match condition.broadcast_to(masked_a.data().shape()) {
            Ok(condition) => condition,
            Err(_) => return fallback(),
        }
    } else {
        if condition.shape() != masked_a.data().shape() {
            return fallback();
        }
        condition
    };

    let mut mask = ma_mask_or(masked_a.mask(), Some(&ma_make_mask(&condition)));
    if mask
        .as_ref()
        .is_some_and(|mask| mask.values().iter().all(|&value| value == 0.0))
    {
        mask = None;
    }

    let result = MaskedArray::new(masked_a.data().clone(), mask, Some(masked_a.fill_value()))
        .map_err(|err| map_ma_error("masked_where", err))?;
    build_numpy_masked_array(py, &result)
}

