// Zero-copy np.ma.filled for a float64 MaskedArray with a scalar-float fill: read the
// contiguous data + bool mask buffers and write `mask[i] ? fill : data[i]` straight into
// the np.empty output in one streaming pass. Returns None (defer) for anything else.
fn try_zerocopy_ma_filled_f64(
    py: Python<'_>,
    value: &Bound<'_, PyAny>,
    fill_value: Option<&Bound<'_, PyAny>>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let masked_array_type = numpy.getattr("ma")?.getattr("MaskedArray")?;
    if !value.is_instance(&masked_array_type)? {
        return Ok(None);
    }
    // f64 data only.
    let data_obj = value.getattr("data")?;
    if !numpy_dtype_is_f64(py, &data_obj) {
        return Ok(None);
    }
    // Resolve the scalar f64 fill: explicit arg if given, else the array's fill_value.
    let fill: f64 = match fill_value {
        Some(fv) => match fv.extract::<f64>() {
            Ok(f) => f,
            Err(_) => return Ok(None),
        },
        None => match value.getattr("fill_value").and_then(|f| f.extract::<f64>()) {
            Ok(f) => f,
            Err(_) => return Ok(None),
        },
    };
    let Ok(shape) = value.getattr("shape").and_then(|s| s.extract::<Vec<usize>>()) else {
        return Ok(None);
    };
    let total: usize = shape.iter().product();
    let Ok(data_buf) = PyBuffer::<f64>::get(&data_obj) else {
        return Ok(None);
    };
    let Some(data) = data_buf.as_slice(py) else {
        return Ok(None); // non-contiguous
    };
    if data.len() != total {
        return Ok(None);
    }
    // Full bool mask (getmaskarray materializes nomask -> all-False). numpy bool buffers
    // export format '?', which PyBuffer::<u8> rejects, so reinterpret as uint8 (same 1-byte
    // layout, zero-copy view) before the buffer read.
    let mask_obj = numpy
        .getattr("ma")?
        .getattr("getmaskarray")?
        .call1((value,))?
        .call_method1("view", (numpy.getattr("uint8")?,))?;
    let Ok(mask_buf) = PyBuffer::<u8>::get(&mask_obj) else {
        return Ok(None);
    };
    let Some(mask) = mask_buf.as_slice(py) else {
        return Ok(None);
    };
    if mask.len() != total {
        return Ok(None);
    }
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (total,), Some(&kwargs))?;
    if total > 0 {
        let Ok(out_buf) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(out) = out_buf.as_mut_slice(py) else {
            return Ok(None);
        };
        for ((o, d), m) in out.iter().zip(data).zip(mask) {
            o.set(if m.get() != 0 { fill } else { d.get() });
        }
    }
    let shape_tuple = PyTuple::new(py, shape)?;
    Ok(Some(flat.call_method1("reshape", (&shape_tuple,))?.unbind()))
}

// Generic-dtype counterpart of try_zerocopy_ma_filled_f64: the f64 path is f64-only, so int/uint/
// float32 masked arrays fell to the cold extract->rebuild path (~5-11x). Same one-pass zero-copy
// gather (out[i] = mask[i] ? fill : data[i]), typed over T, output dtype = `dtype_str`. Bit-identical
// to the generic path (pure element selection). A fill that doesn't fit T (e.g. 2.5 into int) ->
// extract fails -> Ok(None) (delegate, numpy does the cast).
fn try_zerocopy_ma_filled_typed<T>(
    py: Python<'_>,
    value: &Bound<'_, PyAny>,
    fill_value: Option<&Bound<'_, PyAny>>,
    dtype_str: &str,
) -> PyResult<Option<Py<PyAny>>>
where
    T: pyo3::buffer::Element + Copy + for<'a, 'b> pyo3::FromPyObject<'a, 'b>,
{
    let numpy = py.import("numpy")?;
    let masked_array_type = numpy.getattr("ma")?.getattr("MaskedArray")?;
    if !value.is_instance(&masked_array_type)? {
        return Ok(None);
    }
    let data_obj = value.getattr("data")?;
    let fill: T = match fill_value {
        Some(fv) => match fv.extract::<T>() {
            Ok(f) => f,
            Err(_) => return Ok(None),
        },
        None => {
            let Ok(fv_attr) = value.getattr("fill_value") else {
                return Ok(None);
            };
            match fv_attr.extract::<T>() {
                Ok(f) => f,
                Err(_) => return Ok(None),
            }
        }
    };
    let Ok(shape) = value.getattr("shape").and_then(|s| s.extract::<Vec<usize>>()) else {
        return Ok(None);
    };
    let total: usize = shape.iter().product();
    let Ok(data_buf) = PyBuffer::<T>::get(&data_obj) else {
        return Ok(None);
    };
    let Some(data) = data_buf.as_slice(py) else {
        return Ok(None); // non-contiguous
    };
    if data.len() != total {
        return Ok(None);
    }
    let mask_obj = numpy
        .getattr("ma")?
        .getattr("getmaskarray")?
        .call1((value,))?
        .call_method1("view", (numpy.getattr("uint8")?,))?;
    let Ok(mask_buf) = PyBuffer::<u8>::get(&mask_obj) else {
        return Ok(None);
    };
    let Some(mask) = mask_buf.as_slice(py) else {
        return Ok(None);
    };
    if mask.len() != total {
        return Ok(None);
    }
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", dtype_str)?;
    let flat = numpy.call_method("empty", (total,), Some(&kwargs))?;
    if total > 0 {
        let Ok(out_buf) = PyBuffer::<T>::get(&flat) else {
            return Ok(None);
        };
        let Some(out) = out_buf.as_mut_slice(py) else {
            return Ok(None);
        };
        for ((o, d), m) in out.iter().zip(data).zip(mask) {
            o.set(if m.get() != 0 { fill } else { d.get() });
        }
    }
    let shape_tuple = PyTuple::new(py, shape)?;
    Ok(Some(flat.call_method1("reshape", (&shape_tuple,))?.unbind()))
}

#[pyfunction]
#[pyo3(signature = (a, fill_value=None))]
fn filled(py: Python<'_>, a: Py<PyAny>, fill_value: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    let fill_value_for_fallback = fill_value.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let filled_fn = numpy.getattr("ma")?.getattr("filled")?;
        let kwargs = PyDict::new(py);
        if let Some(value) = &fill_value_for_fallback {
            kwargs.set_item("fill_value", value.bind(py))?;
        }
        Ok(filled_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    // Zero-copy fast path for the common case: a float64 MaskedArray (contiguous data +
    // contiguous bool mask) and a scalar float fill. The generic path below extracts the
    // data AND mask into owned Vecs, builds a MaskedArray, clones the data, then builds the
    // output — ~3+ full-size copies, ~13x slower than numpy. Here we read both buffers
    // zero-copy and write the result DIRECTLY into the np.empty output in ONE pass
    // (out[i] = mask[i] ? fill : data[i]). Pure element selection, so bit-identical to the
    // generic path. Non-f64 data, non-contiguous, structured/non-float fill, or any buffer
    // failure fall through to the generic extraction.
    if let Some(out) = try_zerocopy_ma_filled_f64(py, a.bind(py), fill_value.as_ref().map(|v| v.bind(py)))? {
        return Ok(out);
    }

    // Other numeric dtypes: same zero-copy gather, typed (the f64 path is f64-only -> int/uint/f32
    // otherwise hit the cold extract->rebuild path, ~5-11x). Complex / non-numeric fall through.
    if let Ok(data_obj) = a.bind(py).getattr("data")
        && let Ok(dt) = data_obj.getattr("dtype")
        && let Ok(kind) = dt.getattr("kind").and_then(|k| k.extract::<String>())
        && let Ok(isz) = dt.getattr("itemsize").and_then(|s| s.extract::<usize>())
    {
        let fv = fill_value.as_ref().map(|v| v.bind(py));
        let ab = a.bind(py);
        let res = match (kind.as_str(), isz) {
            ("i", 8) => try_zerocopy_ma_filled_typed::<i64>(py, ab, fv, "int64")?,
            ("i", 4) => try_zerocopy_ma_filled_typed::<i32>(py, ab, fv, "int32")?,
            ("i", 2) => try_zerocopy_ma_filled_typed::<i16>(py, ab, fv, "int16")?,
            ("i", 1) => try_zerocopy_ma_filled_typed::<i8>(py, ab, fv, "int8")?,
            ("u", 8) => try_zerocopy_ma_filled_typed::<u64>(py, ab, fv, "uint64")?,
            ("u", 4) => try_zerocopy_ma_filled_typed::<u32>(py, ab, fv, "uint32")?,
            ("u", 2) => try_zerocopy_ma_filled_typed::<u16>(py, ab, fv, "uint16")?,
            ("u", 1) => try_zerocopy_ma_filled_typed::<u8>(py, ab, fv, "uint8")?,
            ("f", 4) => try_zerocopy_ma_filled_typed::<f32>(py, ab, fv, "float32")?,
            _ => None,
        };
        if let Some(out) = res {
            return Ok(out);
        }
    }

    let Some(masked) = extract_numeric_masked_array(py, a.bind(py), "filled")? else {
        return fallback();
    };
    let fill_value = match fill_value.as_ref() {
        Some(value) => {
            match extract_filled_scalar_storage(py, value.bind(py), "filled(fill_value)")? {
                Some(fill_value) => fill_value,
                None => return fallback(),
            }
        }
        None => FilledScalarStorage::Storage(ArrayStorage::F64(vec![masked.fill_value()])),
    };

    if dtype_is_unsigned_integer(masked.dtype()) {
        match &fill_value {
            FilledScalarStorage::PythonFloat(value) if *value < 0.0 => return fallback(),
            FilledScalarStorage::PythonInt(ArrayStorage::I64(values)) if values[0] < 0 => {
                return fallback();
            }
            _ => {}
        }
    }

    let result = masked
        .filled_with_storage(fill_value.into_storage())
        .map_err(|err| map_ufunc_error(format!("filled: {err}")))?;
    build_numpy_scalar_or_array(py, &result)
}

#[pyfunction]
#[pyo3(signature = (a,))]
fn getmask(py: Python<'_>, a: Py<PyAny>) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let builtins = py.import("builtins")?;
    let asanyarray = numpy.call_method1("asanyarray", (a.bind(py),))?;
    let masked_array_type = numpy.getattr("ma")?.getattr("MaskedArray")?;
    let is_masked_array = builtins
        .call_method1("isinstance", (&asanyarray, masked_array_type))?
        .extract::<bool>()?;
    if is_masked_array {
        return Ok(asanyarray.getattr("mask")?.unbind());
    }
    Ok(numpy.getattr("ma")?.getattr("nomask")?.unbind())
}

#[pyfunction]
#[pyo3(signature = (x,))]
fn is_masked(py: Python<'_>, x: Py<PyAny>) -> PyResult<Py<PyAny>> {
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        Ok(numpy
            .getattr("ma")?
            .getattr("is_masked")?
            .call1((x.bind(py),))?
            .unbind())
    };

    let (is_masked_array, mask, shape) = match extract_mask_metadata(py, x.bind(py), "is_masked") {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    let masked = if is_masked_array {
        let data = build_boolean_array(&shape, false, "is_masked")?;
        let array =
            MaskedArray::new(data, mask, None).map_err(|err| map_ma_error("is_masked", err))?;
        ma_is_masked(&array)
    } else {
        false
    };
    Ok(py
        .import("builtins")?
        .getattr("bool")?
        .call1((masked,))?
        .unbind())
}

#[pyfunction]
#[pyo3(signature = (m1, m2, copy=false, shrink=true))]
fn mask_or(
    py: Python<'_>,
    m1: Py<PyAny>,
    m2: Py<PyAny>,
    copy: bool,
    shrink: bool,
) -> PyResult<Py<PyAny>> {
    let m1_for_fallback = m1.clone_ref(py);
    let m2_for_fallback = m2.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let mask_or_fn = numpy.getattr("ma")?.getattr("mask_or")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("copy", copy)?;
        kwargs.set_item("shrink", shrink)?;
        Ok(mask_or_fn
            .call(
                (m1_for_fallback.bind(py), m2_for_fallback.bind(py)),
                Some(&kwargs),
            )?
            .unbind())
    };

    // mask_or is a pure boolean OR of two masks with nomask/shrink/copy handling.
    // The previous path extracted BOTH operands into f64 UFuncArrays, OR-ed, and
    // rebuilt (~101ms @4M) where numpy does a single bool logical_or (~113us) — a
    // ~890x gap. numpy.ma.mask_or is the parity reference and handles the nomask,
    // shrink, copy and shape-mismatch (ValueError) cases natively, so defer to it.
    fallback()
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, keepdims=None))]
fn ma_count(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    keepdims: Option<bool>,
) -> PyResult<Py<PyAny>> {
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let count_fn = numpy.getattr("ma")?.getattr("count")?;
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        if let Some(keepdims_val) = keepdims {
            kwargs.set_item("keepdims", keepdims_val)?;
        }
        Ok(count_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    // ma.count returns size - count_masked. The previous path ran
    // extract_mask_metadata, which materializes the bool mask as an f64 UFuncArray
    // (8x blowup + a full copy) before counting — ~33x slower than numpy (38ms vs
    // 1.1ms @4M). numpy is the parity reference and the underlying bool reduction is
    // a bandwidth-bound C op safe Rust cannot beat, so defer to numpy (which matches
    // the axis/keepdims error surface natively).
    fallback()
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, out=None, overwrite_input=false, keepdims=false))]
fn median(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    overwrite_input: bool,
    keepdims: bool,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let median_fn = numpy.getattr("median")?;
    let axis_for_parse = axis.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        if let Some(out_val) = out.as_ref() {
            kwargs.set_item("out", out_val.bind(py))?;
        }
        kwargs.set_item("overwrite_input", overwrite_input)?;
        kwargs.set_item("keepdims", keepdims)?;
        Ok(median_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    if out.as_ref().is_some_and(|value| !value.bind(py).is_none())
        || overwrite_input
        || numpy_dtype_is_narrow_float(py, a.bind(py))
        // Integer input widens int->f64 in extract (~2x at 1M; parity at 8M) and never beats numpy
        // median; delegate (the f64 native path keeps its 0.5x win).
        || numpy_dtype_is_integer(py, a.bind(py))?
    {
        return fallback();
    }

    // Capture the original ndim before `a` is shadowed by the extracted UFuncArray — needed to
    // re-insert the reduced axis for keepdims (keepdims-on-axis class; the old gate bailed on
    // keepdims entirely, forgoing the ~0.26x native win, BlackThrush 2026-06-22).
    let orig_ndim = a
        .bind(py)
        .getattr("ndim")
        .ok()
        .and_then(|d| d.extract::<usize>().ok());
    let a = match extract_numeric_array(py, a.bind(py), "median(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let axis = match extract_axis_spec(py, axis_for_parse, "median") {
        Ok(None) => None,
        Ok(Some(axes)) if axes.len() == 1 => Some(axes[0]),
        Ok(Some(_)) => return fallback(),
        Err(_) => return fallback(),
    };
    // keepdims over the full array (axis=None) reshapes the scalar to all-ones dims; delegate
    // that rare case. Single-axis keepdims runs the fast path then re-inserts the axis below.
    if keepdims && axis.is_none() {
        return fallback();
    }
    let result = match a.median(axis) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    let output = build_numpy_array_from_ufunc(py, &result)?;
    if keepdims && let Some(ax) = axis {
        let Some(ndim) = orig_ndim else {
            return fallback();
        };
        return keepdims_expand_axis(py, &numpy, output, ax as i64, ndim);
    }
    if result.shape().is_empty() {
        return Ok(output.bind(py).get_item(())?.unbind());
    }
    Ok(output)
}

// Compute the unweighted covariance matrix following numpy's own algorithm:
// stack y onto m when present, transpose to rowvar=True orientation,
// reshape 1-D inputs to (1, n_obs), subtract the per-row mean, then
// return (X @ X.T) / (n_obs - ddof). Returns Err(fallback) for shapes
// that numpy handles via special-cases this path doesn't reproduce.
// Zero-copy parallel covariance for the common case (rowvar=True, no y, contiguous
// float64 1-D/2-D ndarray). numpy.cov here is X_centered @ X_centered.T / (n_obs - ddof)
// with variables = rows. The existing UFuncArray path costs ~10x numpy NOT because of the
// GEMM (which already matches numpy) but because of the chain of cold-mmap allocations
// (extract Vec, centered copy, explicit transpose, full(n*n) scale matrix). Here we read
// the numpy buffer directly, center into one buffer, and compute the symmetric Gram as
// parallel row-dot-products (no transpose materialization, scale folded into the dot),
// which removes those allocations. The dot reassociates the sum vs numpy's BLAS — cov
// parity is tolerance-based (np.allclose), like the existing matmul path.
// Core: returns the (n_vars x n_vars) covariance matrix flat + n_vars for the eligible
// rowvar=True / contiguous-float64 case, or None to defer. Shared by cov (builds the array)
// and corrcoef (normalizes the matrix first).
// Symmetric covariance Gram from a row-major `centered` buffer (n_vars rows of
// n_obs already mean-subtracted observations). Fills the lower triangle (each cell
// is one independent length-n_obs dot) then mirrors. Each cell's dot order is fixed
// regardless of scheduling, so serial and parallel forms are BIT-IDENTICAL to each
// other. The 8-accumulator dot breaks the dependent FP-add chain so LLVM packs it
// into AVX registers (numpy-class throughput); the reorder makes the result allclose
// (not bit-identical) to a single-accumulator sum for n_obs >= 8, but for n_obs < 8
// (the only sizes the exact-repr cov/corrcoef unit tests use) chunks_exact(8) is empty
// so it is the original left-to-right sum and those tests stay green. The large-Gram
// conformance goldens are re-pinned to this order (allclose-verified).
fn cov_gram_from_centered(centered: &[f64], n_vars: usize, n_obs: usize, ddof: usize) -> Vec<f64> {
    use rayon::prelude::*;
    let inv_fact = 1.0_f64 / (n_obs - ddof) as f64;
    let dot8 = |ci: &[f64], cj: &[f64]| -> f64 {
        let mut acc = [0.0f64; 8];
        let mut ca = ci.chunks_exact(8);
        let mut cb = cj.chunks_exact(8);
        for (ga, gb) in ca.by_ref().zip(cb.by_ref()) {
            acc[0] += ga[0] * gb[0];
            acc[1] += ga[1] * gb[1];
            acc[2] += ga[2] * gb[2];
            acc[3] += ga[3] * gb[3];
            acc[4] += ga[4] * gb[4];
            acc[5] += ga[5] * gb[5];
            acc[6] += ga[6] * gb[6];
            acc[7] += ga[7] * gb[7];
        }
        let mut s =
            ((acc[0] + acc[1]) + (acc[2] + acc[3])) + ((acc[4] + acc[5]) + (acc[6] + acc[7]));
        for (&a, &b) in ca.remainder().iter().zip(cb.remainder()) {
            s += a * b;
        }
        s
    };
    let row_dot = |i: usize, row_out: &mut [f64]| {
        let ci = &centered[i * n_obs..(i + 1) * n_obs];
        for (j, slot) in row_out.iter_mut().enumerate().take(i + 1) {
            let cj = &centered[j * n_obs..(j + 1) * n_obs];
            *slot = dot8(ci, cj) * inv_fact;
        }
    };
    let mut result = vec![0.0f64; n_vars * n_vars];
    // Fan out over rows only above the measured crossover. The old gate (1<<18 work)
    // was far too low: measured on this host, work=2.5M (e.g. corrcoef 50x1000) is
    // 36% SLOWER parallel (rayon fan-out + the triangular per-row load imbalance —
    // row i does i+1 cells — dwarf the tiny Gram), while work>=10M (100x1000) is ~43%
    // FASTER parallel. The crossover sits ~5M, so gate at 1<<22 (4.2M): below it run
    // serial (fixes the small-shape 3.3x->2.1x regression), above it fan out (keeps
    // the large-shape wins). <32 rows: too few tasks. Each cell is its own dot8, so
    // serial and parallel are bit-identical for any gate.
    let work = (n_vars as u64) * (n_vars as u64) * (n_obs as u64);
    if n_vars >= 32 && work >= (1 << 22) && rayon::current_num_threads() >= 2 {
        result
            .par_chunks_mut(n_vars)
            .enumerate()
            .for_each(|(i, row_out)| row_dot(i, row_out));
    } else {
        result
            .chunks_mut(n_vars)
            .enumerate()
            .for_each(|(i, row_out)| row_dot(i, row_out));
    }
    for i in 0..n_vars {
        for j in (i + 1)..n_vars {
            result[i * n_vars + j] = result[j * n_vars + i];
        }
    }
    result
}

// True only when `obj` is an ndarray (or array-like exposing `.ndim`) of rank 1.
// Any error (e.g. a Python list with no `.ndim`) yields false, so callers defer.
fn ndim_is_1(obj: &Bound<'_, PyAny>) -> bool {
    obj.getattr("ndim")
        .and_then(|n| n.extract::<usize>())
        .map(|n| n == 1)
        .unwrap_or(false)
}

// Read an exact-f64-ndarray's contiguous buffer as (rows, n_obs) where a 1-D array
// is a single row. Returns None for non-f64 / non-ndarray / >2-D / non-contiguous.
fn cov_rowvar_buffer_rows<'a>(
    py: Python<'a>,
    arr: &Bound<'a, PyAny>,
    ndarray_type: &Bound<'a, PyAny>,
) -> PyResult<Option<(PyBuffer<f64>, usize, usize)>> {
    if !arr.is_exact_instance(ndarray_type) {
        return Ok(None);
    }
    let dtype = arr.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    let Ok(buf) = PyBuffer::<f64>::get(arr) else {
        return Ok(None);
    };
    let shape = buf.shape();
    let (rows, n_obs) = match shape.len() {
        1 => (1usize, shape[0]),
        2 => (shape[0], shape[1]),
        _ => return Ok(None),
    };
    if buf.as_slice(py).is_none() {
        return Ok(None); // non-contiguous
    }
    Ok(Some((buf, rows, n_obs)))
}

// Zero-copy fast path for the `np.cov(m, y)` two-operand form with rowvar=True.
// numpy.cov(m, y) is exactly cov(concatenate([rows(m), rows(y)])); the existing
// single-operand fast path is gated on `y is None`, so the two-operand idiom
// (`np.cov(a, b)` for two series — extremely common) fell through to the slow
// extract+concatenate+generic native_cov_unweighted path (measured 9-17x slower
// than numpy). Here we center the rows of m and y DIRECTLY from their own buffers
// into one `centered` array (no stacking copy of the raw inputs) and reuse the
// shared autovectorized Gram — byte-for-byte the same arithmetic the single-operand
// path uses, so it inherits its allclose-verified conformance.
// Shared two-operand rowvar Gram: returns the (flattened n_vars*n_vars cov, n_vars)
// computed zero-copy from m's and y's buffers, or None to defer. Used by both
// cov(m, y) and corrcoef(m, y) so neither has to extract/stack the raw inputs.
fn cov_gram_two_rowvar_f64(
    py: Python<'_>,
    m: &Bound<'_, PyAny>,
    y: &Bound<'_, PyAny>,
    ddof: usize,
) -> PyResult<Option<(Vec<f64>, usize)>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    let Some((m_buf, m_rows, n_obs)) = cov_rowvar_buffer_rows(py, m, &ndarray_type)? else {
        return Ok(None);
    };
    let Some((y_buf, y_rows, y_obs)) = cov_rowvar_buffer_rows(py, y, &ndarray_type)? else {
        return Ok(None);
    };
    if n_obs != y_obs || n_obs == 0 || n_obs <= ddof {
        return Ok(None); // shape mismatch (numpy errors) / empty / DoF<=0: defer.
    }
    let n_vars = m_rows + y_rows;
    let (Some(m_slice), Some(y_slice)) = (m_buf.as_slice(py), y_buf.as_slice(py)) else {
        return Ok(None);
    };
    // Center every variable row (from whichever source buffer) by its own mean,
    // matching cov_gram_rowvar_f64's per-row centering exactly.
    let mut centered = vec![0.0f64; n_vars * n_obs];
    let center_into = |src: &[pyo3::buffer::ReadOnlyCell<f64>], dst: &mut [f64]| {
        let mean = src.iter().map(|c| c.get()).sum::<f64>() / n_obs as f64;
        for (o, c) in dst.iter_mut().zip(src) {
            *o = c.get() - mean;
        }
    };
    for r in 0..m_rows {
        let src = &m_slice[r * n_obs..(r + 1) * n_obs];
        center_into(src, &mut centered[r * n_obs..(r + 1) * n_obs]);
    }
    for r in 0..y_rows {
        let src = &y_slice[r * n_obs..(r + 1) * n_obs];
        let dst_row = m_rows + r;
        center_into(src, &mut centered[dst_row * n_obs..(dst_row + 1) * n_obs]);
    }
    let result = cov_gram_from_centered(&centered, n_vars, n_obs, ddof);
    Ok(Some((result, n_vars)))
}

fn try_zerocopy_cov_two_rowvar_f64(
    py: Python<'_>,
    m: &Bound<'_, PyAny>,
    y: &Bound<'_, PyAny>,
    ddof: usize,
) -> PyResult<Option<Py<PyAny>>> {
    let Some((result, n_vars)) = cov_gram_two_rowvar_f64(py, m, y, ddof)? else {
        return Ok(None);
    };
    let numpy = py.import("numpy")?;
    build_square_f64_matrix(py, &numpy, result, n_vars)
}

fn cov_gram_rowvar_f64(
    py: Python<'_>,
    m: &Bound<'_, PyAny>,
    ddof: usize,
) -> PyResult<Option<(Vec<f64>, usize)>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !m.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = m.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(m) else {
        return Ok(None);
    };
    let shape = in_buffer.shape();
    let (n_vars, n_obs) = match shape.len() {
        1 => (1usize, shape[0]),
        2 => (shape[0], shape[1]),
        _ => return Ok(None),
    };
    if n_vars == 0 || n_obs == 0 || n_obs <= ddof {
        return Ok(None); // empty / DoF<=0 (numpy warns + returns NaN): defer.
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None); // non-contiguous
    };

    // Center each variable (row) by its mean.
    let mut centered = vec![0.0f64; n_vars * n_obs];
    for i in 0..n_vars {
        let src = &input[i * n_obs..(i + 1) * n_obs];
        let mean = src.iter().map(|c| c.get()).sum::<f64>() / n_obs as f64;
        let dst = &mut centered[i * n_obs..(i + 1) * n_obs];
        for (o, c) in dst.iter_mut().zip(src) {
            *o = c.get() - mean;
        }
    }

    let result = cov_gram_from_centered(&centered, n_vars, n_obs, ddof);
    Ok(Some((result, n_vars)))
}

// Build an (n_vars x n_vars) float64 numpy array from a flat row-major Vec; numpy squeezes
// a single-variable covariance/correlation to a 0-d scalar.
fn build_square_f64_matrix(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    values: Vec<f64>,
    n_vars: usize,
) -> PyResult<Option<Py<PyAny>>> {
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (n_vars * n_vars,), Some(&kwargs))?;
    {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        for (slot, val) in output.iter().zip(values) {
            slot.set(val);
        }
    }
    if n_vars == 1 {
        let scalar = flat.call_method1("reshape", (PyTuple::empty(py),))?;
        return Ok(Some(scalar.call_method0("squeeze")?.unbind()));
    }
    let reshaped = flat.call_method1("reshape", ((n_vars, n_vars),))?;
    Ok(Some(reshaped.unbind()))
}

enum RowvarCovCore {
    Cov,
    Corrcoef,
}

fn try_ufunc_rowvar_f64_cov_core(
    py: Python<'_>,
    m: &Bound<'_, PyAny>,
    core: RowvarCovCore,
) -> PyResult<Option<Py<PyAny>>> {
    const MIN_VARS: usize = 16;
    const MAX_SIMD_VARS_EXCLUSIVE: usize = 128;
    const MIN_LONG_OBS: usize = 4096;
    const MIN_WORK: usize = 1 << 18;

    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !m.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = m.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(m) else {
        return Ok(None);
    };
    let shape = in_buffer.shape();
    if shape.len() != 2 {
        return Ok(None);
    }
    let (n_vars, n_obs) = (shape[0], shape[1]);
    if n_vars < MIN_VARS
        || n_vars >= MAX_SIMD_VARS_EXCLUSIVE
        || n_obs < MIN_LONG_OBS
        || n_vars.saturating_mul(n_vars).saturating_mul(n_obs) < MIN_WORK
    {
        return Ok(None);
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };

    let values = input.iter().map(|cell| cell.get()).collect::<Vec<f64>>();
    let array = match UFuncArray::new(vec![n_vars, n_obs], values, DType::F64) {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };
    let result = match core {
        RowvarCovCore::Cov => array.cov(),
        RowvarCovCore::Corrcoef => array.corrcoef(),
    };
    match result {
        Ok(value) => build_numpy_array_from_ufunc(py, &value).map(Some),
        Err(_) => Ok(None),
    }
}

fn try_zerocopy_cov_rowvar_f64(
    py: Python<'_>,
    m: &Bound<'_, PyAny>,
    ddof: usize,
) -> PyResult<Option<Py<PyAny>>> {
    let Some((result, n_vars)) = cov_gram_rowvar_f64(py, m, ddof)? else {
        return Ok(None);
    };
    let numpy = py.import("numpy")?;
    build_square_f64_matrix(py, &numpy, result, n_vars)
}

// numpy.corrcoef normalizes the covariance by the outer product of the diagonal stddevs,
// then clips to [-1, 1]: `c /= stddev[:,None]; c /= stddev[None,:]; clip`. ddof/bias are
// ignored by numpy here (the normalization cancels them), so the underlying cov uses ddof=1.
// Normalize a flattened n_vars*n_vars covariance matrix into a correlation matrix
// in place: c /= stddev[:,None]; c /= stddev[None,:]; clip to [-1, 1] (numpy's
// exact two-divide ULP order). Returns None to defer when any variance is
// non-finite/negative or zero (numpy yields NaN/inf warnings there).
fn corrcoef_normalize_in_place(cov: &mut [f64], n_vars: usize) -> Option<()> {
    let mut stddev = Vec::with_capacity(n_vars);
    for i in 0..n_vars {
        let var = cov[i * n_vars + i];
        if !var.is_finite() || var < 0.0 {
            return None;
        }
        let sd = var.sqrt();
        if sd == 0.0 {
            return None;
        }
        stddev.push(sd);
    }
    for row in 0..n_vars {
        let row_scale = stddev[row];
        for (col, &col_scale) in stddev.iter().enumerate().take(n_vars) {
            let idx = row * n_vars + col;
            cov[idx] /= row_scale;
            cov[idx] /= col_scale;
            cov[idx] = cov[idx].clamp(-1.0, 1.0);
        }
    }
    Some(())
}

fn try_zerocopy_corrcoef_rowvar_f64(
    py: Python<'_>,
    m: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let Some((mut cov, n_vars)) = cov_gram_rowvar_f64(py, m, 1)? else {
        return Ok(None);
    };
    if corrcoef_normalize_in_place(&mut cov, n_vars).is_none() {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    build_square_f64_matrix(py, &numpy, cov, n_vars)
}

// Two-operand corrcoef(m, y): same zero-copy two-buffer Gram as cov(m, y) (ddof=1,
// the value numpy.corrcoef always uses internally) then the shared normalize.
// Closes the 5-12x gap vs numpy on the np.corrcoef(a, b) two-series idiom.
fn try_zerocopy_corrcoef_two_rowvar_f64(
    py: Python<'_>,
    m: &Bound<'_, PyAny>,
    y: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let Some((mut cov, n_vars)) = cov_gram_two_rowvar_f64(py, m, y, 1)? else {
        return Ok(None);
    };
    if corrcoef_normalize_in_place(&mut cov, n_vars).is_none() {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    build_square_f64_matrix(py, &numpy, cov, n_vars)
}

fn native_cov_unweighted(
    py: Python<'_>,
    m: &Bound<'_, PyAny>,
    y: Option<&Bound<'_, PyAny>>,
    rowvar: bool,
    ddof: usize,
) -> PyResult<Option<UFuncArray>> {
    let m_arr = match extract_precise_numeric_array(py, m, "cov(m)") {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };
    if m_arr.has_integer_sidecar() || matches!(m_arr.dtype(), DType::Complex64 | DType::Complex128)
    {
        return Ok(None);
    }

    let y_arr = match y {
        Some(y_val) if !y_val.is_none() => {
            match extract_precise_numeric_array(py, y_val, "cov(y)") {
                Ok(value)
                    if !value.has_integer_sidecar()
                        && !matches!(value.dtype(), DType::Complex64 | DType::Complex128) =>
                {
                    Some(value)
                }
                _ => return Ok(None),
            }
        }
        _ => None,
    };

    // Normalize m to 2-D: 1-D becomes a single row (rowvar=True orientation).
    let m_was_1d = m_arr.shape().len() == 1;
    let has_y = y_arr.is_some();
    let to_2d = |arr: UFuncArray| -> Option<UFuncArray> {
        match arr.shape().len() {
            1 => {
                let n = arr.shape()[0] as isize;
                arr.reshape(&[1, n]).ok()
            }
            2 => Some(arr),
            _ => None,
        }
    };
    let Some(m_2d) = to_2d(m_arr) else {
        return Ok(None);
    };
    let stacked = if let Some(y_arr) = y_arr {
        let Some(y_2d) = to_2d(y_arr) else {
            return Ok(None);
        };
        let cat_axis: isize = if rowvar { 0 } else { 1 };
        match UFuncArray::concatenate(&[&m_2d, &y_2d], cat_axis) {
            Ok(value) => value,
            Err(_) => return Ok(None),
        }
    } else {
        m_2d
    };

    // For rowvar=False, variables are the columns, so transpose. numpy ALWAYS transposes
    // a genuine 2-D input here (even (1, N) -> N variables); only a 1-D input stays one
    // variable (it is the (1, N) reshape above, not a real (1, N) matrix). The old
    // `stacked.shape()[0] != 1` guard conflated those, so np.cov of a 2-D (1, N) array with
    // rowvar=False wrongly returned a scalar instead of (N, N). For the y path keep the
    // prior row-count guard (its stacking semantics are unchanged).
    let transpose_for_colvars = !rowvar
        && if has_y {
            stacked.shape()[0] != 1
        } else {
            !m_was_1d
        };
    let oriented = if transpose_for_colvars {
        match stacked.transpose(None) {
            Ok(value) => value,
            Err(_) => return Ok(None),
        }
    } else {
        stacked
    };

    let n_vars = oriented.shape()[0];
    let n_obs = oriented.shape()[1];
    if n_obs == 0 || n_vars == 0 {
        return Ok(None);
    }
    if n_obs <= ddof {
        return Ok(None);
    }

    // avg = mean(X, axis=1), reshape to (n_vars, 1) and subtract (broadcasts).
    let avg = match oriented.reduce_mean(Some(1), true) {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };
    let centered = match oriented.elementwise_binary(&avg, BinaryOp::Sub) {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };

    // cov = X @ X.T / (n_obs - ddof)
    let x_t = match centered.transpose(None) {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };
    let product = match centered.matmul(&x_t) {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };
    // numpy multiplies by (1 / fact) rather than dividing by fact so that
    // ULP rounding matches `c *= true_divide(1, fact)` from np.cov.
    let fact = (n_obs - ddof) as f64;
    let inv_fact = 1.0_f64 / fact;
    let scale = match UFuncArray::full(product.shape().to_vec(), inv_fact, product.dtype()) {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };
    let result = match product.elementwise_binary(&scale, BinaryOp::Mul) {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };
    Ok(Some(result))
}

// (n_vars_contributed, n_obs) for one cov operand under rowvar=True: a 2-D (r,c)
// array is r variables over c observations; a 1-D (n,) array is 1 variable over n.
fn cov_operand_vars_obs(a: &Bound<'_, PyAny>) -> Option<(usize, usize)> {
    let shape: Vec<usize> = a.getattr("shape").ok()?.extract().ok()?;
    match shape.as_slice() {
        [n] => Some((1, *n)),
        [r, c] => Some((*r, *c)),
        _ => None,
    }
}

// Shared cov/corrcoef Gram delegate predicate: native dot8 Gram loses to numpy's
// BLAS dsyrk in three measured regions (BlackThrush 2026-06-22) — the mid n_vars
// band [48,256), small n_vars with large obs (Gram work >= small_work_min), and
// large n_vars with short obs ([256,512) x n_obs<256). Native wins outside these.
// `work_vars_lo` is the smallest n_vars eligible for the small-work delegation: the
// single-operand path uses 0 (its n_vars=2 (2,huge-obs) Gram loses, so delegate it),
// but the two-operand path uses 4 — its n_vars=2 (two 1-D series) zero-copy Gram WINS
// even at 1e6 obs (0.83x), so those must stay native.
fn cov_gram_should_delegate(
    n_vars: usize,
    n_obs: usize,
    small_work_min: u64,
    work_vars_lo: usize,
) -> bool {
    (48..256).contains(&n_vars)
        || ((work_vars_lo..48).contains(&n_vars)
            && (n_vars as u64) * (n_vars as u64) * (n_obs as u64) >= small_work_min)
        || ((256..512).contains(&n_vars) && n_obs < 256)
}

#[pyfunction]
#[pyo3(signature = (m, y=None, rowvar=true, bias=false, ddof=None, fweights=None, aweights=None))]
#[allow(clippy::too_many_arguments)]
fn cov(
    py: Python<'_>,
    m: Py<PyAny>,
    y: Option<Py<PyAny>>,
    rowvar: bool,
    bias: bool,
    ddof: Option<Py<PyAny>>,
    fweights: Option<Py<PyAny>>,
    aweights: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let cov_fn = numpy.getattr("cov")?;
        let kwargs = PyDict::new(py);
        if let Some(y_val) = y.as_ref() {
            kwargs.set_item("y", y_val.bind(py))?;
        }
        kwargs.set_item("rowvar", rowvar)?;
        kwargs.set_item("bias", bias)?;
        if let Some(ddof_val) = ddof.as_ref() {
            kwargs.set_item("ddof", ddof_val.bind(py))?;
        }
        if let Some(fweights_val) = fweights.as_ref() {
            kwargs.set_item("fweights", fweights_val.bind(py))?;
        }
        if let Some(aweights_val) = aweights.as_ref() {
            kwargs.set_item("aweights", aweights_val.bind(py))?;
        }
        Ok(cov_fn.call((m.bind(py),), Some(&kwargs))?.unbind())
    };

    if fweights
        .as_ref()
        .is_some_and(|value| !value.bind(py).is_none())
        || aweights
            .as_ref()
            .is_some_and(|value| !value.bind(py).is_none())
    {
        return fallback(py);
    }

    // Resolve ddof. numpy: ddof defaults to 0 when bias=True else 1; if
    // caller passes ddof explicitly (non-None), it wins.
    let resolved_ddof = match ddof.as_ref() {
        Some(value) if !value.bind(py).is_none() => match value.bind(py).extract::<i64>() {
            Ok(d) if d >= 0 => d as usize,
            _ => return fallback(py),
        },
        _ => {
            if bias {
                0
            } else {
                1
            }
        }
    };

    let m_bound = m.bind(py);
    let y_binding = y.as_ref().map(|value| value.bind(py));
    // numpy.cov promotes every input to float64 before accumulating and always
    // returns float64 (float32/float16/int input -> float64). Our native kernel
    // accumulates in the input float width, so its float32 result differs from
    // numpy in both dtype and value. Only run it for float64 inputs; defer the
    // rest to numpy for exact parity.
    if !numpy_dtype_is_f64(py, m_bound)
        || y_binding.is_some_and(|y_val| !numpy_dtype_is_f64(py, y_val))
    {
        return fallback(py);
    }
    // cov(M, rowvar=False) 2-D column-variable form: native cov is ~10x (column access + no-C-BLAS
    // Gram; a transpose copy doesn't help). numpy.cov is faster -> delegate for parity (rowvar=True /
    // two-1-D-operand stay on the fast Gram below).
    if !rowvar
        && y_binding.as_ref().is_none_or(|y_val| y_val.is_none())
        && m_bound.getattr("ndim").ok().and_then(|n| n.extract::<usize>().ok()) == Some(2)
    {
        return fallback(py);
    }
    // Native dot8 Gram vs numpy's BLAS dsyrk: measured (BlackThrush 2026-06-22, 64-thread).
    // Native beats dsyrk ONLY at very small Gram work OR large n_vars (>=256, 0.55-0.78x).
    // Delegate the loss regions: the mid n_vars band [48,256) (all-LOSS 1.3-3.7x every n_obs),
    // and small n_vars (<48) once Gram work n_vars^2*n_obs crosses ~200k (8x5000, 16x1000,
    // 24x500 = 1.2-3.5x loss); below that tiny-Gram native still wins (2x20000=0.81, 16x500
    // =0.85). Preserve all native wins outside these regions.
    if rowvar
        && y_binding.as_ref().is_none_or(|y_val| y_val.is_none())
        && m_bound
            .getattr("ndim")
            .ok()
            .and_then(|n| n.extract::<usize>().ok())
            == Some(2)
        && let Ok(shape) = m_bound
            .getattr("shape")
            .and_then(|s| s.extract::<Vec<usize>>())
        && shape.len() == 2
        && cov_gram_should_delegate(shape[0], shape[1], 200_000, 0)
    {
        return fallback(py);
    }
    // Fast path: rowvar=True with no y is the common shape and maps to a single
    // zero-copy parallel Gram (no transpose / extract / full-matrix allocations).
    if rowvar
        && resolved_ddof == 1
        && y_binding.as_ref().is_none_or(|y_val| y_val.is_none())
        && let Some(out) = try_ufunc_rowvar_f64_cov_core(py, m_bound, RowvarCovCore::Cov)?
    {
        return Ok(out);
    }
    if rowvar
        && y_binding.as_ref().is_none_or(|y_val| y_val.is_none())
        && let Some(out) = try_zerocopy_cov_rowvar_f64(py, m_bound, resolved_ddof)?
    {
        return Ok(out);
    }
    // Two-operand form np.cov(m, y): center m's and y's rows directly from their
    // buffers and reuse the shared Gram (no extract/stack copy). Closes the 9-17x
    // gap vs numpy on np.cov(a, b). For rowvar=True this is always valid; for
    // rowvar=False it is valid ONLY when both operands are 1-D, where numpy ignores
    // rowvar (each 1-D array is one variable, no transpose) — this also FIXES the
    // pre-existing bug where cov(a,b,rowvar=False) on two 1-D arrays returned a
    // scalar instead of the 2x2 matrix. 2-D rowvar=False needs a transpose, so it
    // still defers to numpy below.
    // Two-operand cov shares the same native-Gram-vs-dsyrk loss regions; effective
    // n_vars = (m's vars) + (y's vars) over the shared observation count. Delegate the
    // same loss box (rowvar=True only — 1-D/1-D rowvar=False is n_vars=2 and wins).
    if let Some(y_val) = y_binding
        && !y_val.is_none()
        && rowvar
        && let (Some((mv, mo)), Some((yv, yo))) =
            (cov_operand_vars_obs(m_bound), cov_operand_vars_obs(y_val))
        && mo == yo
        && cov_gram_should_delegate(mv + yv, mo, 200_000, 4)
    {
        return fallback(py);
    }
    if let Some(y_val) = y_binding
        && !y_val.is_none()
        && (rowvar || (ndim_is_1(m_bound) && ndim_is_1(y_val)))
        && let Some(out) = try_zerocopy_cov_two_rowvar_f64(py, m_bound, y_val, resolved_ddof)?
    {
        return Ok(out);
    }
    let native = match native_cov_unweighted(py, m_bound, y_binding, rowvar, resolved_ddof) {
        Ok(Some(value)) => value,
        _ => return fallback(py),
    };

    // numpy returns c.squeeze() — 1-D input yields a 0-d scalar.
    let shape = native.shape().to_vec();
    let trivial_scalar = shape.iter().all(|&dim| dim == 1);
    let output = build_numpy_array_from_ufunc(py, &native)?;
    if trivial_scalar {
        return Ok(output.bind(py).call_method0("squeeze")?.unbind());
    }
    Ok(output)
}

#[pyfunction]
#[pyo3(signature = (x, y=None, rowvar=true, bias=None, ddof=None, dtype=None))]
fn corrcoef(
    py: Python<'_>,
    x: Py<PyAny>,
    y: Option<Py<PyAny>>,
    rowvar: bool,
    bias: Option<Py<PyAny>>,
    ddof: Option<Py<PyAny>>,
    dtype: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let corrcoef_fn = numpy.getattr("corrcoef")?;
        let kwargs = PyDict::new(py);
        if let Some(y_val) = y.as_ref() {
            kwargs.set_item("y", y_val.bind(py))?;
        }
        kwargs.set_item("rowvar", rowvar)?;
        if let Some(bias_val) = bias.as_ref() {
            kwargs.set_item("bias", bias_val.bind(py))?;
        }
        if let Some(ddof_val) = ddof.as_ref() {
            kwargs.set_item("ddof", ddof_val.bind(py))?;
        }
        if let Some(dtype_val) = dtype.as_ref() {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        Ok(corrcoef_fn.call((x.bind(py),), Some(&kwargs))?.unbind())
    };

    // dtype kwarg affects the cov computation path (cast before average);
    // keep numpy in charge of that surface.
    if dtype
        .as_ref()
        .is_some_and(|value| !value.bind(py).is_none())
    {
        return fallback(py);
    }

    // Compute the underlying covariance natively. numpy.corrcoef always
    // uses the default ddof (1) / bias (False) for its internal cov call
    // regardless of the (deprecated) bias/ddof args passed in.
    let x_bound = x.bind(py);
    let y_binding = y.as_ref().map(|value| value.bind(py));
    // Non-f64 input (float32 ~4-7.7x, or int): the native cov+normalize cold path widens/extracts
    // and never beats numpy.corrcoef; delegate (cov delegates non-f64 the same way -> parity). The
    // f64 zero-copy Gram fast paths below stay.
    if !numpy_dtype_is_f64(py, x_bound)
        || y_binding.is_some_and(|y_val| !y_val.is_none() && !numpy_dtype_is_f64(py, y_val))
    {
        return fallback(py);
    }
    // corrcoef(M, rowvar=False) 2-D column-variable form: the native cov+normalize path is ~4.8-6.8x
    // (column access + no-C-BLAS Gram; a contiguous transpose doesn't help — the strided copy negates
    // it). numpy.corrcoef is faster, so delegate for parity (rowvar=True / two-1-D-operand stay fast).
    if !rowvar
        && y_binding.as_ref().is_none_or(|y_val| y_val.is_none())
        && x_bound.getattr("ndim").ok().and_then(|n| n.extract::<usize>().ok()) == Some(2)
    {
        return fallback(py);
    }
    // Same native-dot8-Gram-vs-BLAS-dsyrk loss regions as cov (corrcoef shares the Gram
    // + a cheap normalize): delegate the mid n_vars band [48,256) and small n_vars (<48)
    // once Gram work n_vars^2*n_obs crosses ~400k (corrcoef's win region runs a bit larger
    // than cov's: 16x1000=0.89, 24x500=0.95 still win). Preserve native wins outside.
    if rowvar
        && y_binding.as_ref().is_none_or(|y_val| y_val.is_none())
        && x_bound
            .getattr("ndim")
            .ok()
            .and_then(|n| n.extract::<usize>().ok())
            == Some(2)
        && let Ok(shape) = x_bound
            .getattr("shape")
            .and_then(|s| s.extract::<Vec<usize>>())
        && shape.len() == 2
        && cov_gram_should_delegate(shape[0], shape[1], 400_000, 0)
    {
        return fallback(py);
    }
    // Fast path: rowvar=True with no y maps to the zero-copy parallel-Gram cov + an
    // in-place normalize, avoiding the cold-allocation UFuncArray chain (see cov).
    if rowvar
        && y_binding.as_ref().is_none_or(|y_val| y_val.is_none())
        && let Some(out) = try_ufunc_rowvar_f64_cov_core(py, x_bound, RowvarCovCore::Corrcoef)?
    {
        return Ok(out);
    }
    if rowvar
        && y_binding.as_ref().is_none_or(|y_val| y_val.is_none())
        && let Some(out) = try_zerocopy_corrcoef_rowvar_f64(py, x_bound)?
    {
        return Ok(out);
    }
    // Two-operand form np.corrcoef(x, y): zero-copy two-buffer Gram + normalize.
    // Same rowvar handling as cov: rowvar=False is valid here only for two 1-D
    // operands (numpy ignores rowvar for 1-D), which also fixes the scalar-shape
    // bug for corrcoef(a,b,rowvar=False).
    if let Some(y_val) = y_binding
        && !y_val.is_none()
        && (rowvar || (ndim_is_1(x_bound) && ndim_is_1(y_val)))
        && let Some(out) = try_zerocopy_corrcoef_two_rowvar_f64(py, x_bound, y_val)?
    {
        return Ok(out);
    }
    let cov_array = match native_cov_unweighted(py, x_bound, y_binding, rowvar, 1) {
        Ok(Some(value)) => value,
        _ => return fallback(py),
    };

    // Extract the diagonal (variances), compute 1/sqrt, and normalize the
    // covariance matrix by the outer product of 1/stddev. numpy follows
    // `c /= stddev[:, None]; c /= stddev[None, :]; clip c to [-1, 1]`.
    let shape = cov_array.shape().to_vec();
    if shape.len() != 2 || shape[0] != shape[1] {
        return fallback(py);
    }
    let n_vars = shape[0];
    let diag: Vec<f64> = (0..n_vars)
        .map(|i| cov_array.values()[i * n_vars + i])
        .collect();
    let mut stddev = Vec::with_capacity(n_vars);
    for &value in &diag {
        if !value.is_finite() || value < 0.0 {
            return fallback(py);
        }
        stddev.push(value.sqrt());
    }

    let mut output = cov_array.values().to_vec();
    for row in 0..n_vars {
        let row_scale = stddev[row];
        if row_scale == 0.0 {
            return fallback(py);
        }
        for (col, &col_scale) in stddev.iter().enumerate().take(n_vars) {
            if col_scale == 0.0 {
                return fallback(py);
            }
            let idx = row * n_vars + col;
            // numpy performs the two divides sequentially so ULP drift
            // matches `c /= stddev[:, None]` then `c /= stddev[None, :]`.
            output[idx] /= row_scale;
            output[idx] /= col_scale;
            // Clip to [-1, 1] — numpy.corrcoef guards against small
            // numerical drift that pushes values just past the limits.
            output[idx] = output[idx].clamp(-1.0, 1.0);
        }
    }

    let result = match UFuncArray::from_storage(shape, ArrayStorage::F64(output)) {
        Ok(value) => value,
        Err(_) => return fallback(py),
    };
    let built = build_numpy_array_from_ufunc(py, &result)?;
    // numpy.corrcoef of a single variable is the 0-d scalar 1.0 (like cov's squeeze),
    // not a (1, 1) matrix.
    if n_vars == 1 {
        return Ok(built.bind(py).call_method0("squeeze")?.unbind());
    }
    Ok(built)
}

#[pyfunction]
#[pyo3(signature = (a, b, fill_value=true))]
fn allequal(py: Python<'_>, a: Py<PyAny>, b: Py<PyAny>, fill_value: bool) -> PyResult<Py<PyAny>> {
    let a_for_fallback = a.clone_ref(py);
    let b_for_fallback = b.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let allequal_fn = numpy.getattr("ma")?.getattr("allequal")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("fill_value", fill_value)?;
        Ok(allequal_fn
            .call(
                (a_for_fallback.bind(py), b_for_fallback.bind(py)),
                Some(&kwargs),
            )?
            .unbind())
    };

    // Zero-copy early-exit fast path: a,b both f64 (MaskedArray or plain ndarray) of
    // the same shape. The generic path below extracts BOTH operands' data+mask into
    // owned f64 UFuncArrays before folding (~85ms @4M, 7.9x slower than numpy) — and
    // because the extract is O(n) up front, its later early-exit never pays off. Here
    // we fold straight over the data/mask buffers with a genuine short-circuit, which
    // beats numpy on the differ case AND ties it on the equal case (no extract, no
    // materialized comparison array). numpy.ma.allequal treats any masked entry as
    // fill_value and an all-finite exact compare otherwise.
    {
        let numpy = py.import("numpy")?;
        let masked_array_type = numpy.getattr("ma")?.getattr("MaskedArray")?;
        let ndarray_type = numpy.getattr("ndarray")?;
        let a_b = a.bind(py);
        let b_b = b.bind(py);
        let a_is_ma = a_b.is_instance(&masked_array_type)?;
        let b_is_ma = b_b.is_instance(&masked_array_type)?;
        if (a_is_ma || a_b.is_exact_instance(&ndarray_type))
            && (b_is_ma || b_b.is_exact_instance(&ndarray_type))
        {
            let a_data = if a_is_ma { a_b.getattr("data")? } else { a_b.clone() };
            let b_data = if b_is_ma { b_b.getattr("data")? } else { b_b.clone() };
            if numpy_dtype_is_f64(py, &a_data) && numpy_dtype_is_f64(py, &b_data) {
                let ashape = a_b.getattr("shape").and_then(|s| s.extract::<Vec<usize>>());
                let bshape = b_b.getattr("shape").and_then(|s| s.extract::<Vec<usize>>());
                if let (Ok(ashape), Ok(bshape)) = (ashape, bshape)
                    && ashape == bshape
                    && let (Ok(adb), Ok(bdb)) =
                        (PyBuffer::<f64>::get(&a_data), PyBuffer::<f64>::get(&b_data))
                    && let (Some(ad), Some(bd)) = (adb.as_slice(py), bdb.as_slice(py))
                {
                    // Fetch a bool mask buffer ONLY for MaskedArray operands — a plain
                    // ndarray has no mask, and calling getmaskarray on it would alloc a
                    // full all-False array (a needless pass that regresses the no-mask
                    // case). uint8 view: numpy bool buffers export '?' which PyBuffer<u8>
                    // rejects.
                    let uint8 = numpy.getattr("uint8")?;
                    let getmask = numpy.getattr("ma")?.getattr("getmaskarray")?;
                    let a_mask_view = if a_is_ma {
                        Some(getmask.call1((a_b,))?.call_method1("view", (&uint8,))?)
                    } else {
                        None
                    };
                    let b_mask_view = if b_is_ma {
                        Some(getmask.call1((b_b,))?.call_method1("view", (&uint8,))?)
                    } else {
                        None
                    };
                    let a_mask_buf = a_mask_view.as_ref().and_then(|v| PyBuffer::<u8>::get(v).ok());
                    let b_mask_buf = b_mask_view.as_ref().and_then(|v| PyBuffer::<u8>::get(v).ok());
                    let a_mask = a_mask_buf.as_ref().and_then(|buf| buf.as_slice(py));
                    let b_mask = b_mask_buf.as_ref().and_then(|buf| buf.as_slice(py));
                    let n = ad.len();
                    // Bail (fall through to the slow path) if a MaskedArray's mask buffer
                    // was non-contiguous / unreadable, so we never treat masked as unmasked.
                    let mask_ready = (!a_is_ma || a_mask.is_some_and(|s| s.len() == n))
                        && (!b_is_ma || b_mask.is_some_and(|s| s.len() == n));
                    if bd.len() == n && mask_ready {
                        // No-mask case (both plain ndarrays / unmasked): allequal is just
                        // all(x == y). IEEE makes x==y already False whenever either is NaN,
                        // so no explicit NaN test is needed. Fold in SIMD-friendly chunks —
                        // the inner AND-reduction has no data-dependent branch so it
                        // autovectorizes, while the per-chunk break still short-circuits
                        // (differ cases return almost instantly).
                        let equal = if a_mask.is_none() && b_mask.is_none() {
                            const CHUNK: usize = 2048;
                            let mut equal = true;
                            'chunks: for (ca, cb) in ad.chunks(CHUNK).zip(bd.chunks(CHUNK)) {
                                let mut chunk_eq = true;
                                for (x, y) in ca.iter().zip(cb) {
                                    chunk_eq &= x.get() == y.get();
                                }
                                if !chunk_eq {
                                    equal = false;
                                    break 'chunks;
                                }
                            }
                            equal
                        } else {
                            // At least one masked operand: numpy treats any masked entry as
                            // fill_value, an exact compare otherwise.
                            let mut equal = true;
                            for i in 0..n {
                                let masked = a_mask.is_some_and(|s| s[i].get() != 0)
                                    || b_mask.is_some_and(|s| s[i].get() != 0);
                                let res = if masked { fill_value } else { ad[i].get() == bd[i].get() };
                                if !res {
                                    equal = false;
                                    break;
                                }
                            }
                            equal
                        };
                        return Ok(PyBool::new(py, equal).to_owned().into_any().unbind());
                    }
                }
            }
        }
    }

    let Some(a_masked) = extract_numeric_masked_array(py, a.bind(py), "allequal(a)")? else {
        return fallback();
    };
    let Some(b_masked) = extract_numeric_masked_array(py, b.bind(py), "allequal(b)")? else {
        return fallback();
    };

    if a_masked.data().shape() != b_masked.data().shape() {
        return Ok(PyBool::new(py, false).to_owned().into_any().unbind());
    }

    let a_mask = a_masked.mask().map(|mask| mask.values());
    let b_mask = b_masked.mask().map(|mask| mask.values());
    let equal = a_masked
        .data()
        .values()
        .iter()
        .zip(b_masked.data().values().iter())
        .enumerate()
        .all(|(idx, (&lhs, &rhs))| {
            let lhs_masked = a_mask.as_ref().is_some_and(|mask| mask[idx] != 0.0);
            let rhs_masked = b_mask.as_ref().is_some_and(|mask| mask[idx] != 0.0);
            match (lhs_masked, rhs_masked) {
                // numpy.ma.allequal treats any masked entry as fill_value
                // (controls whether masked positions count as equal). When
                // fill_value=False, both-masked should return False too,
                // not True as a naive "both masked ⇒ trivially equal".
                (true, true) | (true, false) | (false, true) => fill_value,
                (false, false) => !lhs.is_nan() && !rhs.is_nan() && lhs == rhs,
            }
        });

    Ok(PyBool::new(py, equal).to_owned().into_any().unbind())
}

// True for an exact integer (signed or unsigned) ndarray. Integer data cannot hold
// NaN, so every np.nan<reduction> over it equals the plain reduction — the callers
// use this to route integer input to numpy's fast SIMD reduction (via their own
// `fallback()` to numpy.nan<op>) instead of the slow native f64-reduction machinery
// (~2.5-440x slower for integers). Bit-identical: numpy's nan<op> for an int array
// is exactly the plain reduction, same value and dtype.
fn numpy_dtype_is_integer(py: Python<'_>, a: &Bound<'_, PyAny>) -> PyResult<bool> {
    let numpy = py.import("numpy")?;
    if !a.is_exact_instance(&numpy.getattr("ndarray")?) {
        return Ok(false);
    }
    let kind = a.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
    Ok(kind == "i" || kind == "u")
}

// Direct exact-f64 np.nansum(axis=...) for C-contiguous ndarrays. The generic
// native axis path first materializes a NaN-filled copy and then reduces it; this
// scans the source once and writes the output directly. It stays in the same
// left-to-right order as the generic linear path for axes below the compensated
// summation threshold and defers all dtype/out/keepdims/long-axis cases.
fn try_zerocopy_f64_nansum_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis_obj: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }

    let Ok(ax_raw) = axis_obj.extract::<i64>() else {
        return Ok(None);
    };
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len() as i64;
    let ax = if ax_raw < 0 { ax_raw + ndim } else { ax_raw };
    if ax < 0 || ax >= ndim {
        return Ok(None);
    }
    let ax = ax as usize;
    let axis_len = shape[ax];
    const COMPENSATED_SUM_MIN_LEN: usize = 1_000_000;
    if axis_len == 0 || axis_len > COMPENSATED_SUM_MIN_LEN {
        return Ok(None);
    }

    let Ok(ab) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    let Some(asl) = ab.as_slice(py) else {
        return Ok(None);
    };

    let outer: usize = shape[..ax].iter().product();
    let inner: usize = shape[ax + 1..].iter().product();
    let total_out = outer * inner;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (total_out,), Some(&kwargs))?;
    if total_out > 0 {
        let Ok(ob) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(osl) = ob.as_mut_slice(py) else {
            return Ok(None);
        };
        if inner == 1 {
            for (row, lane) in asl.chunks_exact(axis_len).enumerate() {
                let mut sum = 0.0f64;
                for value in lane {
                    let value = value.get();
                    if !value.is_nan() {
                        sum += value;
                    }
                }
                if sum == 0.0 {
                    sum = 0.0;
                }
                osl[row].set(sum);
            }
        } else {
            let mut accs = vec![0.0f64; inner];
            for out_outer in 0..outer {
                accs.fill(0.0);
                let base = out_outer * axis_len * inner;
                for axis_index in 0..axis_len {
                    let slab = &asl[base + axis_index * inner..base + axis_index * inner + inner];
                    for (acc, value) in accs.iter_mut().zip(slab.iter()) {
                        let value = value.get();
                        if !value.is_nan() {
                            *acc += value;
                        }
                    }
                }
                let out_base = out_outer * inner;
                for inner_index in 0..inner {
                    let mut sum = accs[inner_index];
                    if sum == 0.0 {
                        sum = 0.0;
                    }
                    osl[out_base + inner_index].set(sum);
                }
            }
        }
    }

    let mut out_shape: Vec<usize> = shape[..ax].to_vec();
    out_shape.extend_from_slice(&shape[ax + 1..]);
    let shape_tuple = PyTuple::new(py, out_shape.iter().copied())?;
    let out_arr = flat.call_method1("reshape", (&shape_tuple,))?;
    if out_shape.is_empty() {
        return Ok(Some(out_arr.get_item(())?.unbind()));
    }
    Ok(Some(out_arr.unbind()))
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, dtype=None, out=None, keepdims=false))]
fn nanmean(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    dtype: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    keepdims: bool,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let nanmean_fn = numpy.getattr("nanmean")?;
    let axis_for_parse = axis.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        if let Some(dtype_val) = dtype.as_ref() {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        if let Some(out_val) = out.as_ref() {
            kwargs.set_item("out", out_val.bind(py))?;
        }
        kwargs.set_item("keepdims", keepdims)?;
        Ok(nanmean_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    if dtype
        .as_ref()
        .is_some_and(|value| !value.bind(py).is_none())
        || out.as_ref().is_some_and(|value| !value.bind(py).is_none())
    {
        return fallback();
    }

    // The native kernel computes in f64; defer float16/float32/complex inputs
    // to numpy.nanmean so the narrow float dtype is preserved.
    if !native_f64_reduction_preserves_dtype(py, a.bind(py)) {
        return fallback();
    }
    // Integer input cannot contain NaN, so nannanmean == the plain reduction; route to
    // numpy's fast reduction (via fallback) instead of the slow native f64 path.
    if numpy_dtype_is_integer(py, a.bind(py))? {
        return fallback();
    }
    // Bit-exact SIMD-pairwise flat fast path (axis=None): ~5x faster than the extract
    // → native scan; all-NaN defers to numpy (warning + NaN). keepdims reshapes the
    // scalar to numpy's all-ones shape.
    if axis.as_ref().is_none_or(|v| v.bind(py).is_none())
        && let Some(out) = try_zerocopy_f64_nanmean_flat(py, a.bind(py))?
    {
        if keepdims {
            return keepdims_reshape_scalar(py, &numpy, a.bind(py), out);
        }
        return Ok(out);
    }
    // Per-lane pairwise fast path for the contiguous last axis (~5.7x faster than
    // the extract → native scan; all-NaN lanes -> NaN + "Mean of empty slice").
    if let Some(axis_val) = axis.as_ref()
        && !axis_val.bind(py).is_none()
        && let Some(out) = try_zerocopy_f64_nanmean_axis(py, a.bind(py), axis_val.bind(py))?
    {
        if keepdims {
            let ndim = a.bind(py).getattr("ndim")?.extract::<usize>()?;
            let ax_i = axis_val.bind(py).extract::<i64>()?;
            return keepdims_expand_axis(py, &numpy, out, ax_i, ndim);
        }
        return Ok(out);
    }
    // Native first-axis (axis=0) streaming nanmean — single fused sum+count pass; numpy
    // materializes a NaN->0 copy + mask + two reduces. See try_zerocopy_f64_nanmean_axis0.
    if let Some(axis_val) = axis.as_ref()
        && !axis_val.bind(py).is_none()
        && let Some(out) = try_zerocopy_f64_nanmean_axis0(py, a.bind(py), axis_val.bind(py), keepdims)?
    {
        return Ok(out);
    }
    // Non-contiguous (transposed/strided) ndarrays bail out of the zero-copy paths
    // into the cold extract → scalar scan (3-9x slower than numpy's cache-blocked
    // strided reduction). Delegate them to numpy (same parity).
    if let Ok(ndarray_type) = numpy.getattr("ndarray")
        && a.bind(py).is_exact_instance(&ndarray_type)
        && !a
            .bind(py)
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return fallback();
    }
    // Multi-axis (tuple) reductions extract the whole array then fall back to numpy
    // on the axis re-parse below (wasteful 8x bool-bridge / f64 copy). Delegate up front.
    if axis.as_ref().is_some_and(|ax| ax.bind(py).cast::<PyTuple>().is_ok()) {
        return fallback();
    }
    let a = match extract_numeric_array(py, a.bind(py), "nanmean(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    if a.values().is_empty() {
        return fallback();
    }
    let axis = match extract_axis_spec(py, axis_for_parse, "nanmean") {
        Ok(None) => None,
        Ok(Some(axes)) if axes.len() == 1 => Some(axes[0]),
        Ok(Some(_)) => return fallback(),
        Err(_) => return fallback(),
    };
    let result = match a.nanmean(axis, keepdims) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    if contains_nan_value(&result) {
        return fallback();
    }
    // NumPy returns a numpy scalar (np.float64) for a full reduction, not a
    // 0-d ndarray; collapse the 0-d case to a scalar to match.
    build_numpy_scalar_or_array(py, &result)
}

// numpy's <=128-element pairwise base case (loops_utils.h.src), ported exactly:
// eight independent accumulators initialised from the first 8 elements, each
// adding every 8th element after, then a fixed binary-tree horizontal reduce
// `((r0+r1)+(r2+r3))+((r4+r5)+(r6+r7))`, then the scalar remainder. The eight
// accumulators ARE an f64x8 lane vector, so `r += Simd::from_slice(..)` performs
// numpy's per-accumulator add in one instruction — bit-identical, vectorized.
fn base_sum_simd(a: &[f64]) -> f64 {
    use std::simd::Simd;
    let n = a.len();
    if n < 8 {
        let mut s = 0.0f64;
        for &v in a {
            s += v;
        }
        return s;
    }
    let mut r = Simd::<f64, 8>::from_slice(&a[0..8]);
    let mut i = 8;
    while i + 8 <= n {
        r += Simd::<f64, 8>::from_slice(&a[i..i + 8]);
        i += 8;
    }
    let v = r.to_array();
    let mut res = ((v[0] + v[1]) + (v[2] + v[3])) + ((v[4] + v[5]) + (v[6] + v[7]));
    while i < n {
        res += a[i];
        i += 1;
    }
    res
}

// Faithful port of numpy's pairwise summation over the buffer cells: blocks of
// <= 128 elements are the SIMD base case; larger ranges split at n/2 rounded DOWN
// to a multiple of 8 and recurse, summing the two halves. This reproduces
// numpy's exact accumulation order, so the result is BIT-IDENTICAL to np.sum /
// np.nansum (proven in a Python prototype: 0 divergence over 5000 random sizes/
// scales/NaN densities). `nan_to_zero` substitutes NaN -> 0.0 during the copy
// (numpy's nansum semantics). Each <=128 leaf is copied into a reused 1 KiB stack
// buffer so the SIMD base case gets real aligned vector loads with no heap
// allocation. The recursion depth is O(log n) (~21 for 2 M elements).
fn pairwise_simd_f64(
    cells: &[pyo3::buffer::ReadOnlyCell<f64>],
    off: usize,
    n: usize,
    nan_to_zero: bool,
    buf: &mut [f64; 128],
) -> f64 {
    if n <= 128 {
        for j in 0..n {
            let v = cells[off + j].get();
            buf[j] = if nan_to_zero && v.is_nan() { 0.0 } else { v };
        }
        return base_sum_simd(&buf[..n]);
    }
    let mut n2 = n / 2;
    n2 -= n2 % 8;
    let left = pairwise_simd_f64(cells, off, n2, nan_to_zero, buf);
    let right = pairwise_simd_f64(cells, off + n2, n - n2, nan_to_zero, buf);
    left + right
}

// Zero-copy bit-exact nansum for the f64 full reduction (axis=None): numpy's
// pairwise sum with NaN->0, run over the buffer with no whole-array allocation.
// numpy returns 0.0 for both empty and all-NaN inputs (no warning), which the
// pairwise math reproduces directly, so there are no defer edge cases. Gated to a
// C-contiguous f64 ndarray. Returns a numpy float64 scalar.
fn try_zerocopy_f64_nansum_flat(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    if kind != "f" || itemsize != 8 {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() {
        return Ok(None);
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let mut buf = [0.0f64; 128];
    let total = pairwise_simd_f64(cells, 0, cells.len(), true, &mut buf);
    Ok(Some(numpy.getattr("float64")?.call1((total,))?.unbind()))
}

// Pairwise nansum that ALSO counts the non-NaN elements, in the same traversal:
// the <=128 leaf counts non-NaN while it copies (NaN -> 0.0), and the recursion
// sums the partial counts. The count is exact (integer), matching numpy's
// `count = sum(~isnan)`; the sum is the same bit-exact pairwise as nansum. Used by
// nanmean (= nansum / count).
fn pairwise_nansum_count_f64(
    cells: &[pyo3::buffer::ReadOnlyCell<f64>],
    off: usize,
    n: usize,
    buf: &mut [f64; 128],
) -> (f64, usize) {
    if n <= 128 {
        let mut cnt = 0usize;
        for j in 0..n {
            let v = cells[off + j].get();
            if v.is_nan() {
                buf[j] = 0.0;
            } else {
                buf[j] = v;
                cnt += 1;
            }
        }
        return (base_sum_simd(&buf[..n]), cnt);
    }
    let mut n2 = n / 2;
    n2 -= n2 % 8;
    let (ls, lc) = pairwise_nansum_count_f64(cells, off, n2, buf);
    let (rs, rc) = pairwise_nansum_count_f64(cells, off + n2, n - n2, buf);
    (ls + rs, lc + rc)
}

// Read the C-contiguous f64 buffer cells of `a`, or None to defer. Shared gate for
// the flat mean-family fast paths.
fn f64_contiguous_cells<'py>(
    _py: Python<'py>,
    a: &Bound<'py, PyAny>,
    numpy: &Bound<'py, PyModule>,
) -> PyResult<Option<PyBuffer<f64>>> {
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    if kind != "f" || itemsize != 8 {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() {
        return Ok(None);
    }
    Ok(Some(in_buffer))
}

// Bit-exact flat mean (axis=None) = numpy's pairwise sum / n. numpy's unweighted
// np.average and np.mean both reduce to umr_sum (pairwise) / n, so this matches
// both. Empty input defers (numpy raises / warns). C-contiguous f64 only.
fn try_zerocopy_f64_mean_flat(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let Some(in_buffer) = f64_contiguous_cells(py, a, &numpy)? else {
        return Ok(None);
    };
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = cells.len();
    if n == 0 {
        return Ok(None); // numpy mean/average of empty raises/warns — defer
    }
    let mut buf = [0.0f64; 128];
    let total = pairwise_simd_f64(cells, 0, n, false, &mut buf);
    let mean = total / n as f64;
    Ok(Some(numpy.getattr("float64")?.call1((mean,))?.unbind()))
}

// Bit-exact flat nanmean (axis=None) = pairwise nansum / count(non-NaN). All-NaN
// (count==0) defers to numpy for its "Mean of empty slice" RuntimeWarning + NaN.
// C-contiguous f64 only.
// Wrap a full-reduction (axis=None) scalar result as numpy's keepdims=True output:
// an all-ones-shaped ndarray of the input's ndim. The reduction has one element, so
// asarray + reshape preserves the value and dtype exactly — lets the flat fast paths
// serve keepdims=True instead of falling to the cold extract → native path.
fn keepdims_reshape_scalar(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    a: &Bound<'_, PyAny>,
    out: Py<PyAny>,
) -> PyResult<Py<PyAny>> {
    let ndim = a.getattr("ndim")?.extract::<usize>()?;
    let arr = numpy.call_method1("asarray", (out.bind(py),))?;
    Ok(arr
        .call_method1("reshape", (PyTuple::new(py, vec![1usize; ndim])?,))?
        .unbind())
}

// numpy keepdims=True for a SINGLE-int-axis reduction == the reduced result with a
// length-1 axis re-inserted at the (normalized) reduced position. np.expand_dims does
// exactly that, so the single-axis zero-copy fast paths can run unchanged (producing
// the reduced-shape result) and we restore the kept axis here.
// True when `x` is an ndarray that is NOT C-contiguous (transposed / strided / sliced
// view). Such inputs bail out of the contiguous-only zero-copy fast paths into the
// cold extract → rebuild that transpose-copies the data — far slower than numpy's
// strided ufunc kernels — so callers delegate them to numpy instead.
fn noncontiguous_ndarray(numpy: &Bound<'_, PyModule>, x: &Bound<'_, PyAny>) -> PyResult<bool> {
    Ok(x.is_exact_instance(&numpy.getattr("ndarray")?)
        && !x
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?)
}

fn keepdims_expand_axis(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    out: Py<PyAny>,
    axis: i64,
    ndim: usize,
) -> PyResult<Py<PyAny>> {
    let norm = if axis < 0 { axis + ndim as i64 } else { axis };
    Ok(numpy
        .getattr("expand_dims")?
        .call1((out.bind(py), norm))?
        .unbind())
}

fn try_zerocopy_f64_nanmean_flat(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let Some(in_buffer) = f64_contiguous_cells(py, a, &numpy)? else {
        return Ok(None);
    };
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let mut buf = [0.0f64; 128];
    let (total, count) = pairwise_nansum_count_f64(cells, 0, cells.len(), &mut buf);
    if count == 0 {
        return Ok(None); // all-NaN / empty — defer for numpy's warning + NaN
    }
    let mean = total / count as f64;
    Ok(Some(numpy.getattr("float64")?.call1((mean,))?.unbind()))
}

// Pairwise sum of squared deviations from `avg`: each <=128 leaf computes
// (x - avg)^2 for a non-NaN x and 0.0 for a NaN x, then the same bit-exact
// pairwise reduce as the sum. This matches numpy's _nanvar exactly: it subtracts
// the mean, zeroes the NaN positions, squares, then np.sum (pairwise).
fn pairwise_sqr_dev_f64(
    cells: &[pyo3::buffer::ReadOnlyCell<f64>],
    off: usize,
    n: usize,
    avg: f64,
    buf: &mut [f64; 128],
) -> f64 {
    if n <= 128 {
        for j in 0..n {
            let v = cells[off + j].get();
            buf[j] = if v.is_nan() {
                0.0
            } else {
                let d = v - avg;
                d * d
            };
        }
        return base_sum_simd(&buf[..n]);
    }
    let mut n2 = n / 2;
    n2 -= n2 % 8;
    let left = pairwise_sqr_dev_f64(cells, off, n2, avg, buf);
    let right = pairwise_sqr_dev_f64(cells, off + n2, n - n2, avg, buf);
    left + right
}

// Pairwise sum of squares with NO NaN masking - the bit-exact analog of numpy's
// `np.add.reduce((x.conj()*x).real)` for a real f64 lane (s = x*x). Same pairwise
// block structure (<=128 leaf, split trimmed to a multiple of 8) as
// pairwise_sqr_dev_f64, but squares the raw value (no avg subtraction, no NaN->0)
// so NaN/Inf propagate - norm of a lane containing a non-finite entry is NaN/Inf,
// matching numpy, which removes any need to special-case non-finite lanes.
fn pairwise_sq_f64(values: &[f64], buf: &mut [f64; 128]) -> f64 {
    let n = values.len();
    if n <= 128 {
        for (j, v) in values.iter().enumerate() {
            buf[j] = v * v;
        }
        return base_sum_simd(&buf[..n]);
    }
    let mut n2 = n / 2;
    n2 -= n2 % 8;
    let (left_values, right_values) = values.split_at(n2);
    let left = pairwise_sq_f64(left_values, buf);
    let right = pairwise_sq_f64(right_values, buf);
    left + right
}

// Pairwise sum of absolute values with NO NaN masking - the bit-exact analog of
// numpy's `np.add.reduce(abs(x), axis)` (the vector L1 / ord=1 norm) for a real
// f64 lane. Same pairwise block tree as pairwise_sq_f64, but takes |v| instead of
// v*v. abs() only clears the sign bit (exact), so this matches numpy's reduce over
// the materialized abs temporary bit-for-bit; NaN/Inf propagate (abs(NaN)=NaN,
// abs(Inf)=Inf), so non-finite lanes need no special-casing.
fn pairwise_abs_f64(values: &[f64], buf: &mut [f64; 128]) -> f64 {
    let n = values.len();
    if n <= 128 {
        for (j, v) in values.iter().enumerate() {
            buf[j] = v.abs();
        }
        return base_sum_simd(&buf[..n]);
    }
    let mut n2 = n / 2;
    n2 -= n2 % 8;
    let (left_values, right_values) = values.split_at(n2);
    let left = pairwise_abs_f64(left_values, buf);
    let right = pairwise_abs_f64(right_values, buf);
    left + right
}

// Bit-exact flat nanvar value (axis=None) via numpy's two-pass algorithm:
// avg = pairwise nansum / count, then var = pairwise sum((x-avg)^2, NaN->0) /
// (count - ddof). Returns None to defer when there is no C-contiguous f64 buffer
// or count - ddof <= 0 (numpy emits a "Degrees of freedom <= 0" warning + NaN).
fn compute_f64_nanvar_flat(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    ddof: usize,
) -> PyResult<Option<f64>> {
    let numpy = py.import("numpy")?;
    let Some(in_buffer) = f64_contiguous_cells(py, a, &numpy)? else {
        return Ok(None);
    };
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = cells.len();
    let mut buf = [0.0f64; 128];
    let (total, count) = pairwise_nansum_count_f64(cells, 0, n, &mut buf);
    if count <= ddof {
        return Ok(None); // count - ddof <= 0: numpy warns + returns NaN — defer
    }
    let avg = total / count as f64;
    let sqr_sum = pairwise_sqr_dev_f64(cells, 0, n, avg, &mut buf);
    Ok(Some(sqr_sum / (count - ddof) as f64))
}

// Bit-exact flat var value (axis=None) for the PLAIN (NaN-propagating) np.var via
// numpy's two-pass pairwise algorithm: avg = pairwise sum / n, then
// var = pairwise sum((x-avg)^2) / (n - ddof). numpy.var allocates two whole-array
// temporaries (x = a - mean, then x*x) before its pairwise sum; this fold reads the
// contiguous buffer twice with NO allocation, so it beats numpy at large n while
// staying bit-exact (same pairwise summation, same blocksize). Unlike nanvar this
// does NOT skip NaN: numpy.var propagates NaN/Inf, so any non-finite mean defers to
// numpy for exact special-value semantics (avoids the all-NaN -> 0 divergence the
// NaN->0 squared-deviation leaf would otherwise produce). C-contiguous f64 only.
fn compute_f64_var_flat(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    ddof: usize,
) -> PyResult<Option<f64>> {
    let numpy = py.import("numpy")?;
    let Some(in_buffer) = f64_contiguous_cells(py, a, &numpy)? else {
        return Ok(None);
    };
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = cells.len();
    if n == 0 || n <= ddof {
        return Ok(None); // numpy warns + returns NaN for n - ddof <= 0 — defer
    }
    let mut buf = [0.0f64; 128];
    // NaN-propagating pairwise sum (nan_to_zero = false): any NaN/Inf makes the mean
    // non-finite below, where we defer to numpy.
    let total = pairwise_simd_f64(cells, 0, n, false, &mut buf);
    let avg = total / n as f64;
    if !avg.is_finite() {
        return Ok(None);
    }
    // avg is finite => no NaN/Inf in the input, so pairwise_sqr_dev_f64's NaN->0 leaf
    // never fires and the result is bit-exact with numpy's two-pass var.
    let sqr_sum = pairwise_sqr_dev_f64(cells, 0, n, avg, &mut buf);
    Ok(Some(sqr_sum / (n - ddof) as f64))
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, dtype=None, out=None, keepdims=false))]
fn nansum(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    dtype: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    keepdims: bool,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let nansum_fn = numpy.getattr("nansum")?;
    let axis_for_parse = axis.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        if let Some(dtype_val) = dtype.as_ref() {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        if let Some(out_val) = out.as_ref() {
            kwargs.set_item("out", out_val.bind(py))?;
        }
        kwargs.set_item("keepdims", keepdims)?;
        Ok(nansum_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    if dtype
        .as_ref()
        .is_some_and(|value| !value.bind(py).is_none())
        || out.as_ref().is_some_and(|value| !value.bind(py).is_none())
    {
        return fallback();
    }

    // The native kernel computes in f64; defer float16/float32/complex inputs
    // to numpy.nansum so the narrow float dtype is preserved.
    if !native_f64_reduction_preserves_dtype(py, a.bind(py)) {
        return fallback();
    }
    // Integer input cannot contain NaN, so nannansum == the plain reduction; route to
    // numpy's fast reduction (via fallback) instead of the slow native f64 path.
    if numpy_dtype_is_integer(py, a.bind(py))? {
        return fallback();
    }
    // Bit-exact SIMD-pairwise flat fast path (axis=None): ~7x faster than the extract
    // → scalar nan-scan, and beats numpy (no whole-array temp). keepdims reshapes the
    // scalar to numpy's all-ones shape.
    if axis.as_ref().is_none_or(|v| v.bind(py).is_none())
        && let Some(out) = try_zerocopy_f64_nansum_flat(py, a.bind(py))?
    {
        if keepdims {
            return keepdims_reshape_scalar(py, &numpy, a.bind(py), out);
        }
        return Ok(out);
    }
    if let Some(axis_val) = axis.as_ref()
        && !axis_val.bind(py).is_none()
        && let Some(out) = try_zerocopy_f64_nansum_axis(py, a.bind(py), axis_val.bind(py))?
    {
        if keepdims {
            let ndim = a.bind(py).getattr("ndim")?.extract::<usize>()?;
            let ax_i = axis_val.bind(py).extract::<i64>()?;
            return keepdims_expand_axis(py, &numpy, out, ax_i, ndim);
        }
        return Ok(out);
    }
    // Non-contiguous (transposed/strided) ndarrays bail out of the zero-copy paths
    // into the cold extract → scalar scan (3-9x slower than numpy's cache-blocked
    // strided reduction). Delegate them to numpy (same parity).
    if let Ok(ndarray_type) = numpy.getattr("ndarray")
        && a.bind(py).is_exact_instance(&ndarray_type)
        && !a
            .bind(py)
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return fallback();
    }
    // Multi-axis (tuple) reductions extract the whole array then fall back to numpy
    // on the axis re-parse below (wasteful 8x bool-bridge / f64 copy). Delegate up front.
    if axis.as_ref().is_some_and(|ax| ax.bind(py).cast::<PyTuple>().is_ok()) {
        return fallback();
    }
    let a = match extract_numeric_array(py, a.bind(py), "nansum(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let axis = match extract_axis_spec(py, axis_for_parse, "nansum") {
        Ok(None) => None,
        Ok(Some(axes)) if axes.len() == 1 => Some(axes[0]),
        Ok(Some(_)) => return fallback(),
        Err(_) => return fallback(),
    };
    let result = match a.nansum(axis, keepdims) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    // NumPy returns a numpy scalar (np.float64) for a full reduction, not a
    // 0-d ndarray; collapse the 0-d case to a scalar to match.
    build_numpy_scalar_or_array(py, &result)
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, dtype=None, out=None, keepdims=None, initial=None, r#where=None))]
#[allow(clippy::too_many_arguments)]
fn nanprod(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    dtype: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    keepdims: Option<bool>,
    initial: Option<Py<PyAny>>,
    r#where: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let nanprod_fn = numpy.getattr("nanprod")?;
    let axis_for_parse = axis.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        if let Some(dtype_val) = dtype.as_ref() {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        if let Some(out_val) = out.as_ref() {
            kwargs.set_item("out", out_val.bind(py))?;
        }
        if let Some(keepdims_val) = keepdims {
            kwargs.set_item("keepdims", keepdims_val)?;
        }
        if let Some(initial_val) = initial.as_ref() {
            kwargs.set_item("initial", initial_val.bind(py))?;
        }
        if let Some(where_val) = r#where.as_ref() {
            kwargs.set_item("where", where_val.bind(py))?;
        }
        Ok(nanprod_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    if dtype
        .as_ref()
        .is_some_and(|value| !value.bind(py).is_none())
        || out.as_ref().is_some_and(|value| !value.bind(py).is_none())
        || initial
            .as_ref()
            .is_some_and(|value| !value.bind(py).is_none())
        || r#where
            .as_ref()
            .is_some_and(|value| !value.bind(py).is_none())
    {
        return fallback();
    }

    // The native kernel computes in f64; defer float16/float32/complex inputs
    // to numpy.nanprod so the narrow float dtype is preserved.
    if !native_f64_reduction_preserves_dtype(py, a.bind(py)) {
        return fallback();
    }
    // Integer input cannot contain NaN, so nannanprod == the plain reduction; route to
    // numpy's fast reduction (via fallback) instead of the slow native f64 path.
    if numpy_dtype_is_integer(py, a.bind(py))? {
        return fallback();
    }
    // Zero-copy sequential-product flat fast path (axis=None): ~4x faster than the
    // extract → native scan, single allocation-free pass. keepdims reshapes the scalar
    // to numpy's all-ones shape.
    if axis.as_ref().is_none_or(|v| v.bind(py).is_none())
        && let Some(out) = try_zerocopy_f64_nanprod_flat(py, a.bind(py))?
    {
        if keepdims.unwrap_or(false) {
            return keepdims_reshape_scalar(py, &numpy, a.bind(py), out);
        }
        return Ok(out);
    }
    // Per-lane sequential-product fast path for the contiguous last axis (bit-exact;
    // lanes are independent so they fan across the rayon pool). keepdims via expand.
    if let Some(axis_val) = axis.as_ref()
        && !axis_val.bind(py).is_none()
        && let Some(out) = try_zerocopy_f64_nanprod_axis(py, a.bind(py), axis_val.bind(py))?
    {
        if keepdims.unwrap_or(false) {
            let ndim = a.bind(py).getattr("ndim")?.extract::<usize>()?;
            let ax_i = axis_val.bind(py).extract::<i64>()?;
            return keepdims_expand_axis(py, &numpy, out, ax_i, ndim);
        }
        return Ok(out);
    }
    // Non-contiguous (transposed/strided) ndarrays bail the zero-copy paths into the
    // cold extract → rebuild (transpose-copy). Delegate to numpy.
    if noncontiguous_ndarray(&numpy, a.bind(py))? {
        return fallback();
    }
    // Multi-axis (tuple) reductions extract the whole array then fall back to numpy
    // on the axis re-parse below (wasteful 8x bool-bridge / f64 copy). Delegate up front.
    if axis.as_ref().is_some_and(|ax| ax.bind(py).cast::<PyTuple>().is_ok()) {
        return fallback();
    }
    let a = match extract_numeric_array(py, a.bind(py), "nanprod(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let axis = match extract_axis_spec(py, axis_for_parse, "nanprod") {
        Ok(None) => None,
        Ok(Some(axes)) if axes.len() == 1 => Some(axes[0]),
        Ok(Some(_)) => return fallback(),
        Err(_) => return fallback(),
    };
    let result = match a.nanprod(axis, keepdims.unwrap_or(false)) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    // NumPy returns a numpy scalar (np.float64) for a full reduction, not a
    // 0-d ndarray; collapse the 0-d case to a scalar to match.
    build_numpy_scalar_or_array(py, &result)
}

// Zero-copy bit-exact nanprod for the f64 full reduction (axis=None). numpy's
// nanprod replaces NaN with 1 and folds the product left-to-right; float
// multiplication is NOT associative, so the order must match exactly — a single
// sequential pass `acc *= v` (multiplying by 1.0 for NaN, which is the IEEE
// identity) reproduces it bit-for-bit. Empty and all-NaN inputs yield 1.0
// directly (no special case). Gated to a C-contiguous f64 ndarray; returns a
// numpy float64 scalar.
fn try_zerocopy_f64_nanprod_flat(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let Some(in_buffer) = f64_contiguous_cells(py, a, &numpy)? else {
        return Ok(None);
    };
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let mut acc = 1.0f64;
    for c in cells {
        let v = c.get();
        acc *= if v.is_nan() { 1.0 } else { v };
    }
    Ok(Some(numpy.getattr("float64")?.call1((acc,))?.unbind()))
}

// Zero-copy nanprod along any axis of a C-contiguous f64 ndarray. numpy folds the
// product DOWN the axis with NaN replaced by 1.0; float multiply is not associative,
// so the along-axis order must match. Last axis (inner==1): each contiguous lane folds
// sequentially, lanes fan across the rayon pool. Non-last axis: a per-inner running
// product accumulator walks the rows in order (down-axis order preserved → bit-exact),
// one cache-sequential pass vs numpy's NaN→1 temp; ≥2 outer groups fan across groups.
// Non-contiguous / non-f64 defer.
fn try_zerocopy_f64_nanprod_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis_obj: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    let Ok(ax_raw) = axis_obj.extract::<i64>() else {
        return Ok(None);
    };
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len() as i64;
    let ax = if ax_raw < 0 { ax_raw + ndim } else { ax_raw };
    if ax < 0 || ax >= ndim {
        return Ok(None);
    }
    let ax = ax as usize;
    let axis_len = shape[ax];
    if axis_len == 0 {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() {
        return Ok(None);
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let outer: usize = shape[..ax].iter().product();
    let inner: usize = shape[ax + 1..].iter().product();
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only buffer under
    // the GIL -> &[f64] (Sync) for the parallel folds below.
    let data: &[f64] =
        unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), cells.len()) };
    use rayon::prelude::*;
    let out: Vec<f64> = if inner == 1 {
        // Last axis: each contiguous lane folds sequentially; fan lanes across the pool.
        let lane_prod = |lane: &[f64]| -> f64 {
            let mut acc = 1.0f64;
            for &v in lane {
                acc *= if v.is_nan() { 1.0 } else { v };
            }
            acc
        };
        let parallel = outer * axis_len >= (1 << 16) && rayon::current_num_threads() >= 2;
        if parallel {
            data.par_chunks_exact(axis_len).map(lane_prod).collect()
        } else {
            data.chunks_exact(axis_len).map(lane_prod).collect()
        }
    } else {
        // Non-last axis: per-inner running product down the axis (NaN→1.0). Walking
        // rows in order preserves numpy's along-axis multiply order → bit-exact, in a
        // single cache-sequential pass. ≥2 outer groups fan across the pool.
        let lane = axis_len * inner;
        let group_prod = |o: usize| -> Vec<f64> {
            let base = o * lane;
            let mut acc = vec![1.0f64; inner];
            for r in 0..axis_len {
                let row = &data[base + r * inner..base + r * inner + inner];
                for (a_acc, &v) in acc.iter_mut().zip(row) {
                    *a_acc *= if v.is_nan() { 1.0 } else { v };
                }
            }
            acc
        };
        let parallel =
            outer >= 2 && outer * axis_len * inner >= (1 << 16) && rayon::current_num_threads() >= 2;
        let mut out = vec![0.0f64; outer * inner];
        if parallel {
            let planes: Vec<Vec<f64>> = (0..outer).into_par_iter().map(group_prod).collect();
            for (o, p) in planes.into_iter().enumerate() {
                out[o * inner..o * inner + inner].copy_from_slice(&p);
            }
        } else {
            for o in 0..outer {
                let p = group_prod(o);
                out[o * inner..o * inner + inner].copy_from_slice(&p);
            }
        }
        out
    };
    let mut out_shape = shape.clone();
    out_shape.remove(ax);
    let flat = numpy_array_from_slice(py, &numpy, &out, "float64")?;
    let reshaped =
        flat.call_method1("reshape", (PyTuple::new(py, out_shape.iter().copied())?,))?;
    if out_shape.is_empty() {
        return Ok(Some(reshaped.get_item(())?.unbind()));
    }
    Ok(Some(reshaped.unbind()))
}

// Single-pass portable-SIMD nan-ignoring max/min over an f64 slice. `take_max`
// picks nanmax (true) vs nanmin (false). std's simd_max/simd_min follow IEEE
// maxNum/minNum — a NaN lane yields the other operand — which is exactly numpy's
// nanmax/nanmin "ignore NaN" rule, so folding skips NaNs for free. The returned
// extreme is an actual input value (no arithmetic) so it is bit-identical. A lane
// mask records whether ANY non-NaN was seen; if none (all-NaN or empty), returns
// None so the caller defers to numpy, which emits the "All-NaN slice" RuntimeWarning
// and returns NaN (or raises on empty) — preserving that behavior exactly.
// Core SIMD nan-ignoring max/min fold. Returns (extreme, saw_non_nan): `extreme`
// is the IEEE maxNum/minNum fold over the non-NaN values (or init = ±inf when the
// slice is empty/all-NaN), and `saw_non_nan` is whether any non-NaN was seen.
// Block-wise over a reused 64 KiB buffer so there is no whole-array allocation.
// Direct SIMD nan-extreme over a plain &[f64]. Returns (extreme, saw_nonnan).
// IEEE maxNum/minNum (simd_max/simd_min return the non-NaN operand), so NaNs are
// skipped exactly; the fold is order-independent so it parallelizes/merges cleanly.
fn simd_nanextreme_slice(data: &[f64], take_max: bool) -> (f64, bool) {
    use std::simd::cmp::SimdPartialEq;
    use std::simd::num::SimdFloat;
    use std::simd::{Mask, Simd};
    const L: usize = 8;
    type V = Simd<f64, L>;
    let init = if take_max {
        f64::NEG_INFINITY
    } else {
        f64::INFINITY
    };
    let n = data.len();
    let full = n - n % L;
    let mut acc = V::splat(init);
    let mut vsaw = Mask::<i64, L>::splat(false);
    let mut off = 0;
    while off < full {
        let c = V::from_slice(&data[off..off + L]);
        vsaw |= c.simd_eq(c); // non-NaN lanes (c == c)
        acc = if take_max { acc.simd_max(c) } else { acc.simd_min(c) };
        off += L;
    }
    let mut m = init;
    let mut saw = vsaw.any();
    for &v in &acc.to_array() {
        m = if take_max { m.max(v) } else { m.min(v) };
    }
    for &v in &data[full..] {
        if !v.is_nan() {
            saw = true;
            m = if take_max { m.max(v) } else { m.min(v) };
        }
    }
    (m, saw)
}

// Value-only nan-extreme fold (no saw-tracking). simd_max/simd_min already skip
// NaN (IEEE maxNum), so the extreme is exact; this drops the per-iteration
// `simd_eq` that the saw-returning kernel runs (halving the SIMD ops in the hot
// loop). The caller detects the all-NaN / empty case via `m == init` (defer),
// which it must do anyway for the ±inf-extreme tie — so no accuracy is lost.
fn simd_nanextreme_value(data: &[f64], take_max: bool) -> f64 {
    use std::simd::num::SimdFloat;
    use std::simd::Simd;
    const L: usize = 8;
    type V = Simd<f64, L>;
    let init = if take_max {
        f64::NEG_INFINITY
    } else {
        f64::INFINITY
    };
    let n = data.len();
    let full = n - n % L;
    let mut acc = V::splat(init);
    let mut off = 0;
    while off < full {
        let c = V::from_slice(&data[off..off + L]);
        acc = if take_max { acc.simd_max(c) } else { acc.simd_min(c) };
        off += L;
    }
    let mut m = init;
    for &v in &acc.to_array() {
        m = if take_max { m.max(v) } else { m.min(v) };
    }
    // f64::max/min return the non-NaN operand, so the scalar tail skips NaN too.
    for &v in &data[full..] {
        m = if take_max { m.max(v) } else { m.min(v) };
    }
    m
}

// Fold one row into a per-column running extreme with explicit SIMD (vmaxpd/vminpd).
// simd_max/simd_min are IEEE maxNum/minNum (return the non-NaN operand), so this is
// NaN-skipping and bit-identical to the scalar `acc[i].max(row[i])` fold — but the
// scalar f64::max is NaN-aware and does NOT autovectorize, leaving the down-axis
// reduction 1.5-3x slower than numpy (which copy-replaces NaN then runs raw vmaxpd).
fn fold_row_extreme_simd(acc: &mut [f64], row: &[f64], take_max: bool) {
    use std::simd::num::SimdFloat;
    use std::simd::Simd;
    const L: usize = 8;
    type V = Simd<f64, L>;
    let n = acc.len();
    let full = n - n % L;
    let mut i = 0;
    while i < full {
        let a = V::from_slice(&acc[i..i + L]);
        let v = V::from_slice(&row[i..i + L]);
        let m = if take_max { a.simd_max(v) } else { a.simd_min(v) };
        m.copy_to_slice(&mut acc[i..i + L]);
        i += L;
    }
    for k in full..n {
        acc[k] = if take_max { acc[k].max(row[k]) } else { acc[k].min(row[k]) };
    }
}

fn simd_nanextreme_f64(cells: &[pyo3::buffer::ReadOnlyCell<f64>], take_max: bool) -> Option<f64> {
    if cells.is_empty() {
        return None;
    }
    let n = cells.len();
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64 and `cells` is a
    // read-only PyBuffer slice held under the GIL, so reading it as &[f64] for the
    // duration of this fold is sound. Avoids staging each block through `buf`.
    let data: &[f64] = unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), n) };
    let init = if take_max {
        f64::NEG_INFINITY
    } else {
        f64::INFINITY
    };
    // numpy runs nanmax/nanmin single-threaded; this reduction is order-independent
    // (NaN-skipping min/max), so a parallel fold across the rayon pool exploits the
    // extra memory channels and beats it — but ONLY once the array is DRAM-bound.
    // While it fits L3 the rayon task overhead dominates (measured: parallel LOSES
    // up to 2.5x at 1.2-2M = L3-resident, WINS at >=3M = DRAM), so gate at 1<<21.
    const NANEXTREME_PARALLEL_MIN: usize = 1 << 21;
    let m = if n >= NANEXTREME_PARALLEL_MIN && rayon::current_num_threads() >= 2 {
        use rayon::prelude::*;
        const CHUNK: usize = 1 << 15; // 256 KiB of f64 per task
        data.par_chunks(CHUNK)
            .map(|c| simd_nanextreme_value(c, take_max))
            .reduce(
                || init,
                |am, bm| if take_max { am.max(bm) } else { am.min(bm) },
            )
    } else {
        simd_nanextreme_value(data, take_max)
    };
    if m == init {
        return None; // all-NaN / empty / ±inf-extreme — defer to numpy (warning/NaN/inf parity)
    }
    if m == 0.0 {
        // The extreme is a zero. numpy's RETURNED SIGN of a ±0 tie is
        // position-dependent / implementation-defined (bead franken_numpy-u89e0),
        // so a fold can't reproduce it bit-exactly — defer this (rare) case.
        // `== 0.0` matches both +0.0 and -0.0.
        return None;
    }
    Some(m)
}

// Zero-copy SIMD nanmax/nanmin for the f64 full reduction (axis=None). Gated to a
// C-contiguous f64 ndarray; all-NaN/empty defer (numpy warning/error). Returns a
// numpy float64 scalar, matching numpy's full-reduction return.
fn try_zerocopy_f64_nanextreme(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    take_max: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    if kind != "f" || itemsize != 8 {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() {
        return Ok(None);
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    if cells.is_empty() {
        return Ok(None);
    }
    match simd_nanextreme_f64(cells, take_max) {
        Some(m) => Ok(Some(numpy.getattr("float64")?.call1((m,))?.unbind())),
        // all-NaN / empty / ±0-tie: let numpy produce the exact value (and its
        // "All-NaN slice" RuntimeWarning, or the empty-array ValueError, or the
        // position-dependent zero sign of bead franken_numpy-u89e0). Rare, so the
        // extra numpy call is fine and keeps parity bit-exact in every case.
        None => {
            let f = if take_max { "nanmax" } else { "nanmin" };
            Ok(Some(numpy.getattr(f)?.call1((a,))?.unbind()))
        }
    }
}

// Zero-copy SIMD nanmax/nanmin over the CONTIGUOUS LAST axis of a C-contiguous
// f64 ndarray: each lane is a contiguous run, reduced by simd_nanextreme_f64 (the
// same IEEE maxNum/minNum fold as the flat path — bit-exact, NaN-skipping). The
// result is an f64 array of shape[:-1]. If any lane is all-NaN or has a ±0 extreme
// (where numpy's value/sign is special, bead franken_numpy-u89e0), the WHOLE call
// defers to numpy so those rare lanes stay bit-exact. Non-last axis (strided
// lanes), non-contiguous, and non-f64 defer.
fn try_zerocopy_f64_nanextreme_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis_obj: &Bound<'_, PyAny>,
    take_max: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    let Ok(ax_raw) = axis_obj.extract::<i64>() else {
        return Ok(None);
    };
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len() as i64;
    let ax = if ax_raw < 0 { ax_raw + ndim } else { ax_raw };
    if ax < 0 || ax >= ndim {
        return Ok(None);
    }
    let ax = ax as usize;
    let axis_len = shape[ax];
    if axis_len == 0 {
        return Ok(None); // zero-length reduction axis — numpy raises; defer
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() {
        return Ok(None);
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let outer: usize = shape[..ax].iter().product();
    let inner: usize = shape[ax + 1..].iter().product();
    // Wide down-axis reduction (inner > 128 columns): the per-column running-extreme
    // fold reloads/stores the `inner`-wide accumulator every row and becomes acc-
    // traffic-bound, losing 1.2-2.5x to numpy's cache-blocked reduce kernel. Narrow
    // inner (<=128, and the inner==1 contiguous-last-axis lane path) keeps the native
    // win (0.3-1.0x). Delegate the wide case straight to numpy for parity not a loss.
    if inner > 128 {
        let func = if take_max { "nanmax" } else { "nanmin" };
        return Ok(Some(numpy.getattr(func)?.call1((a, axis_obj))?.unbind()));
    }
    let mut any_all_nan = false;
    let mut deferred = false;
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64 and `cells` is a
    // read-only contiguous PyBuffer slice held for this call under the GIL, so
    // reading it as &[f64] (Sync) for the parallel folds below is sound.
    let data: &[f64] =
        unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), cells.len()) };
    use rayon::prelude::*;
    const NANEXTREME_AXIS_PARALLEL_MIN: usize = 1 << 20;
    let parallel = outer * axis_len * inner >= NANEXTREME_AXIS_PARALLEL_MIN
        && rayon::current_num_threads() >= 2;
    let init = if take_max {
        f64::NEG_INFINITY
    } else {
        f64::INFINITY
    };
    let out: Vec<f64> = if inner == 1 {
        // Contiguous last axis: each lane is an independent contiguous run, reduced
        // with the direct-SIMD nan-extreme kernel. numpy runs this single-threaded,
        // so fan the per-lane reductions across the rayon pool. Order is preserved.
        // Fast path per lane: the value-only kernel (no per-iteration simd_eq). When
        // its extreme is anything but `init` the lane definitely had a non-NaN, so
        // saw=true; only the rare all-NaN / ±inf-extreme lane (m==init) re-runs the
        // accurate saw-tracking kernel to distinguish all-NaN from a real ±inf.
        let lane_reduce = |lane: &[f64]| -> (f64, bool) {
            let m = simd_nanextreme_value(lane, take_max);
            if m != init {
                (m, true)
            } else {
                simd_nanextreme_slice(lane, take_max)
            }
        };
        let per_lane: Vec<(f64, bool)> = if parallel {
            data.par_chunks_exact(axis_len).map(lane_reduce).collect()
        } else {
            data.chunks_exact(axis_len).map(lane_reduce).collect()
        };
        let mut out: Vec<f64> = Vec::with_capacity(outer);
        for (m, saw) in per_lane {
            if !saw {
                out.push(f64::NAN);
                any_all_nan = true;
            } else if m == 0.0 {
                deferred = true;
            } else {
                out.push(m);
            }
        }
        out
    } else {
        // Non-last axis (e.g. axis=0): reduce DOWN the axis into an (outer×inner)
        // plane with a per-inner running extreme. f64::max/min skip NaN (return the
        // other operand), so the fold is nan-skipping and order-independent. We do
        // NOT track "saw non-NaN" per element — that scalar `v==v` compare alongside
        // the max stops the inner loop from autovectorizing (was 1.8-3x slower than
        // numpy). The all-NaN / ±inf-extreme columns are exactly those left at
        // `init`, re-scanned afterward (essentially never for real data).
        let lane = axis_len * inner;
        let row_fold = |base: usize| -> Vec<f64> {
            let mut acc = vec![init; inner];
            for r in 0..axis_len {
                let row = &data[base + r * inner..base + r * inner + inner];
                fold_row_extreme_simd(&mut acc, row, take_max);
            }
            acc
        };
        let mut out = vec![init; outer * inner];
        if parallel && outer >= 2 {
            let planes: Vec<Vec<f64>> =
                (0..outer).into_par_iter().map(|o| row_fold(o * lane)).collect();
            for (o, acc) in planes.into_iter().enumerate() {
                out[o * inner..o * inner + inner].copy_from_slice(&acc);
            }
        } else if parallel {
            // Single group: privatize across row-blocks, merge planes elementwise.
            let acc = (0..axis_len)
                .into_par_iter()
                .fold(
                    || vec![init; inner],
                    |mut acc, r| {
                        let row = &data[r * inner..r * inner + inner];
                        fold_row_extreme_simd(&mut acc, row, take_max);
                        acc
                    },
                )
                .reduce(
                    || vec![init; inner],
                    |mut a, b| {
                        if take_max {
                            for (x, y) in a.iter_mut().zip(b.iter()) {
                                *x = x.max(*y);
                            }
                        } else {
                            for (x, y) in a.iter_mut().zip(b.iter()) {
                                *x = x.min(*y);
                            }
                        }
                        a
                    },
                );
            out[..inner].copy_from_slice(&acc);
        } else {
            for o in 0..outer {
                let acc = row_fold(o * lane);
                out[o * inner..o * inner + inner].copy_from_slice(&acc);
            }
        }
        // Resolve all-NaN / ±0 columns. A column still at `init` is either all-NaN
        // (-> NaN + numpy's warning) or has a genuine ±inf extreme (-> keep init);
        // re-scan to disambiguate (rare). A ±0 extreme defers (sign-tie).
        for o in 0..outer {
            let base = o * lane;
            for i in 0..inner {
                let j = o * inner + i;
                if out[j] == init {
                    let mut seen = false;
                    for r in 0..axis_len {
                        if !data[base + r * inner + i].is_nan() {
                            seen = true;
                            break;
                        }
                    }
                    if !seen {
                        out[j] = f64::NAN;
                        any_all_nan = true;
                    }
                } else if out[j] == 0.0 {
                    deferred = true;
                }
            }
        }
        out
    };
    if deferred {
        // ±0 extreme: numpy's returned sign is position-dependent
        // (bead franken_numpy-u89e0) — defer the whole call (rare).
        return Ok(None);
    }
    if any_all_nan {
        // Reproduce numpy's single "All-NaN slice encountered" RuntimeWarning.
        let warnings = py.import("warnings")?;
        let category = py.get_type::<pyo3::exceptions::PyRuntimeWarning>();
        warnings.call_method1("warn", ("All-NaN slice encountered", &category))?;
    }
    let flat = numpy_array_from_slice(py, &numpy, &out, "float64")?;
    let mut out_shape: Vec<usize> = shape[..ax].to_vec();
    out_shape.extend_from_slice(&shape[ax + 1..]);
    let reshaped = flat.call_method1("reshape", (PyTuple::new(py, out_shape.iter().copied())?,))?;
    if out_shape.is_empty() {
        return Ok(Some(reshaped.get_item(())?.unbind()));
    }
    Ok(Some(reshaped.unbind()))
}

// Zero-copy SIMD-pairwise nanmean over the CONTIGUOUS LAST axis of a C-contiguous
// f64 ndarray: each lane runs the bit-exact pairwise nansum-and-count, then the
// lane mean = sum / count. numpy's nanmean(axis) is per-lane nansum / count, so
// this is bit-identical. An all-NaN lane (count == 0) yields NaN and emits
// numpy's single "Mean of empty slice" RuntimeWarning. Non-last axis (strided
// lanes), non-contiguous, and non-f64 defer.
fn try_zerocopy_f64_nanmean_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis_obj: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    let Ok(ax_raw) = axis_obj.extract::<i64>() else {
        return Ok(None);
    };
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len() as i64;
    let ax = if ax_raw < 0 { ax_raw + ndim } else { ax_raw };
    if ax < 0 || ax != ndim - 1 {
        return Ok(None); // only the contiguous last axis (inner == 1)
    }
    let ax = ax as usize;
    let axis_len = shape[ax];
    if axis_len == 0 {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() {
        return Ok(None);
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let outer: usize = shape[..ax].iter().product();
    let mut out: Vec<f64> = Vec::with_capacity(outer);
    let mut any_empty = false;
    let mut buf = [0.0f64; 128]; // reused across all lanes (no per-lane allocation)
    for lane in cells.chunks_exact(axis_len) {
        let (sum, count) = pairwise_nansum_count_f64(lane, 0, lane.len(), &mut buf);
        // count == 0 (all-NaN lane) yields sum/count = 0.0/0.0, the SAME NaN bit
        // pattern numpy produces (its nansum/count division), so compute it
        // directly rather than substituting f64::NAN (a different sign of NaN).
        out.push(sum / count as f64);
        if count == 0 {
            any_empty = true;
        }
    }
    if any_empty {
        let warnings = py.import("warnings")?;
        let category = py.get_type::<pyo3::exceptions::PyRuntimeWarning>();
        warnings.call_method1("warn", ("Mean of empty slice", &category))?;
    }
    let flat = numpy_array_from_slice(py, &numpy, &out, "float64")?;
    let out_shape: Vec<usize> = shape[..ax].to_vec();
    let reshaped = flat.call_method1("reshape", (PyTuple::new(py, out_shape.iter().copied())?,))?;
    if out_shape.is_empty() {
        return Ok(Some(reshaped.get_item(())?.unbind()));
    }
    Ok(Some(reshaped.unbind()))
}

// NaN-ignoring np.nanmean along the FIRST axis (axis=0) of a C-contiguous f64 ndarray —
// the missing-data imputation reduction `np.nanmean(X, axis=0)`. numpy.nanmean
// materializes a NaN->0 copy + an isnan mask, then TWO sequential axis-0 reduces (the
// NaN->0 sum AND the ~mask count) -> ~19x slower than plain mean(axis=0). This single
// streaming pass accumulates per column both the NaN->0 sum and the non-NaN count (numpy
// reduces axis=0 SEQUENTIALLY, so bit-exact), then mean = sum / count. An all-NaN column
// (count==0) yields 0.0/0.0 == numpy's NaN bit pattern directly + the single "Mean of
// empty slice" RuntimeWarning (so no defer needed). Serial cache-friendly streaming
// (column-block parallelism is cache-hostile on row-major; see try_zerocopy_f64_var_axis0).
// Only the first axis of a >=2-D array; everything else defers.
fn try_zerocopy_f64_nanmean_axis0(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis_obj: &Bound<'_, PyAny>,
    keepdims: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let Some(in_buffer) = f64_contiguous_cells(py, a, &numpy)? else {
        return Ok(None);
    };
    let Ok(ax_raw) = axis_obj.extract::<i64>() else {
        return Ok(None);
    };
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len() as i64;
    if ndim < 1 {
        return Ok(None);
    }
    let ax = if ax_raw < 0 { ax_raw + ndim } else { ax_raw };
    if ax != 0 || ndim < 2 {
        return Ok(None);
    }
    let m = shape[0];
    if m == 0 {
        return Ok(None);
    }
    let inner: usize = shape[1..].iter().product();
    if inner == 0 {
        return Ok(None);
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only under the GIL.
    let data: &[f64] =
        unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), cells.len()) };
    let mut sum = vec![0.0f64; inner];
    let mut cnt = vec![0u64; inner];
    for i in 0..m {
        let base = i * inner;
        let row = &data[base..base + inner];
        for j in 0..inner {
            let v = row[j];
            if !v.is_nan() {
                sum[j] += v;
                cnt[j] += 1;
            }
        }
    }
    let mut any_empty = false;
    let mut out = vec![0.0f64; inner];
    for j in 0..inner {
        // 0.0 / 0.0 == numpy's NaN for an all-NaN column (same bit pattern its
        // nansum/count division produces); don't substitute f64::NAN.
        out[j] = sum[j] / cnt[j] as f64;
        if cnt[j] == 0 {
            any_empty = true;
        }
    }
    if any_empty {
        let warnings = py.import("warnings")?;
        let category = py.get_type::<pyo3::exceptions::PyRuntimeWarning>();
        warnings.call_method1("warn", ("Mean of empty slice", &category))?;
    }
    let flat = numpy_array_from_slice(py, &numpy, &out, "float64")?;
    let mut out_shape: Vec<usize> = shape[1..].to_vec();
    if keepdims {
        out_shape.insert(0, 1);
    }
    let reshaped = flat.call_method1("reshape", (PyTuple::new(py, out_shape.iter().copied())?,))?;
    if out_shape.is_empty() {
        return Ok(Some(reshaped.get_item(())?.unbind()));
    }
    Ok(Some(reshaped.unbind()))
}

// Zero-copy per-block pairwise nanvar/nanstd over the CONTIGUOUS TRAILING axes of a
// C-contiguous f64 ndarray — either a single last axis or a tuple resolving to the last
// k axes (the per-block "lane" is the product of those trailing dims). Each block is an
// independent reduction — exactly what numpy's per-lane nanvar does — so the bit-exact
// pairwise nansum/count + sum-of-squared-deviations (the SAME helpers as the axis=None
// flat fast path, compute_f64_nanvar_flat) reproduce numpy's result; numpy's multi-axis
// reduce over a contiguous trailing block is bit-identical to a flat per-block reduce.
// Any block with count <= ddof (e.g. an all-NaN block at the default ddof=0) defers the
// WHOLE call to numpy so its "Degrees of freedom <= 0" warning + NaN parity stays exact.
// Non-trailing/duplicate axes, non-contiguous, and non-f64 defer. `take_sqrt` selects
// nanstd vs nanvar.
fn try_zerocopy_f64_nanvar_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis_obj: &Bound<'_, PyAny>,
    ddof: usize,
    take_sqrt: bool,
    keepdims: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len() as i64;
    // Reduced axes must be the contiguous TRAILING block [keep .. ndim): either a single
    // int (== last axis) or a tuple resolving to the last k axes (per-block "lane" =
    // product of the trailing dims). nanvar is symmetric in the reduced axes, and a
    // contiguous-trailing reduce over a C-contiguous array is bit-identical to a flat
    // per-block reduce (verified: nanvar(x, axis=(-2,-1)) == nanvar(x.reshape(B,M*N), -1)).
    let keep: usize = if let Ok(ax_raw) = axis_obj.extract::<i64>() {
        let ax = if ax_raw < 0 { ax_raw + ndim } else { ax_raw };
        if ax < 0 || ax != ndim - 1 {
            return Ok(None); // only the contiguous last axis (inner == 1)
        }
        (ndim - 1) as usize
    } else if let Ok(axes) = axis_obj.extract::<Vec<i64>>() {
        if axes.is_empty() {
            return Ok(None);
        }
        let mut resolved: Vec<i64> = axes
            .iter()
            .map(|&ax| if ax < 0 { ax + ndim } else { ax })
            .collect();
        resolved.sort_unstable();
        let k = resolved.len();
        resolved.dedup();
        if resolved.len() != k {
            return Ok(None); // duplicate axes -> numpy raises; defer to match its error
        }
        let expected: Vec<i64> = (ndim - k as i64..ndim).collect();
        if resolved[0] < 0 || resolved != expected {
            return Ok(None); // non-trailing / out-of-range -> defer to numpy
        }
        (ndim - k as i64) as usize
    } else {
        return Ok(None);
    };
    let axis_len: usize = shape[keep..].iter().product();
    if axis_len == 0 {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() {
        return Ok(None);
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let outer: usize = shape[..keep].iter().product();
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only buffer held
    // under the GIL -> &[f64] (Sync) for the parallel per-lane fold below.
    let data: &[f64] =
        unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), cells.len()) };
    let lane_var = |lane: &[f64]| -> Option<f64> {
        let mut buf = [0.0f64; 128];
        // View the f64 lane back as the ReadOnlyCell slice the pairwise helpers take
        // (repr-transparent; a single-threaded local temporary, never shared).
        let lc: &[pyo3::buffer::ReadOnlyCell<f64>] =
            unsafe { std::slice::from_raw_parts(lane.as_ptr().cast(), lane.len()) };
        let (sum, count) = pairwise_nansum_count_f64(lc, 0, lane.len(), &mut buf);
        if count <= ddof {
            return None; // count - ddof <= 0: defer whole call (numpy warns + NaN)
        }
        let avg = sum / count as f64;
        let sq = pairwise_sqr_dev_f64(lc, 0, lane.len(), avg, &mut buf);
        let var = sq / (count - ddof) as f64;
        Some(if take_sqrt { var.sqrt() } else { var })
    };
    use rayon::prelude::*;
    // Measured crossover (BlackThrush, 64-thread): per-lane nansum+sqr-dev is cheap, so
    // rayon fan-out only pays off above ~1e5 total elements. The old 1<<16 (65536) gate sent
    // the 256x256/288x288 bands to parallel where they ran ~1.2-1.5x SLOWER than serial.
    const NANVAR_AXIS_PARALLEL_MIN: usize = 98_304;
    let parallel =
        outer * axis_len >= NANVAR_AXIS_PARALLEL_MIN && rayon::current_num_threads() >= 2;
    let results: Vec<Option<f64>> = if parallel {
        data.par_chunks_exact(axis_len).map(lane_var).collect()
    } else {
        data.chunks_exact(axis_len).map(lane_var).collect()
    };
    let Some(out): Option<Vec<f64>> = results.into_iter().collect() else {
        return Ok(None);
    };
    let flat = numpy_array_from_slice(py, &numpy, &out, "float64")?;
    let mut out_shape: Vec<usize> = shape[..keep].to_vec();
    if keepdims {
        // numpy keeps every reduced trailing axis as length 1.
        for _ in keep..ndim as usize {
            out_shape.push(1);
        }
    }
    let reshaped = flat.call_method1("reshape", (PyTuple::new(py, out_shape.iter().copied())?,))?;
    if out_shape.is_empty() {
        return Ok(Some(reshaped.get_item(())?.unbind()));
    }
    Ok(Some(reshaped.unbind()))
}

// Plain (NaN-propagating) np.var / np.std over the contiguous TRAILING axes - either a
// single last axis or a tuple resolving to the last k axes (the per-block "lane" is the
// product of those dims). numpy.var allocates whole-array temporaries (a - mean
// broadcast, then squared) before its pairwise sum; this per-block two-pass pairwise
// fold reads each contiguous block twice with no allocation, parallel across blocks ->
// big win at large outer counts, bit-exact (numpy's multi-axis reduce over a contiguous
// trailing block == a flat per-block reduce). NaN-propagating (unlike nanvar): a block
// whose mean is non-finite (any NaN/Inf) makes lane_var return None, which defers the
// WHOLE call to numpy for exact special-value semantics (numpy would emit NaN there; the
// NaN->0 squared-dev leaf cannot reproduce an all-NaN block -> 0). axis_len <= ddof also
// defers (numpy warns + NaN).
fn try_zerocopy_f64_var_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis_obj: &Bound<'_, PyAny>,
    ddof: usize,
    take_sqrt: bool,
    keepdims: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let Some(in_buffer) = f64_contiguous_cells(py, a, &numpy)? else {
        return Ok(None);
    };
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len() as i64;
    // The reduced axes must be the contiguous TRAILING block [keep .. ndim): either a
    // single int (== last axis) or a tuple resolving to the last k axes. Variance is
    // symmetric in the reduced axes, so order within the tuple is irrelevant, and a
    // contiguous-trailing reduce over a C-contiguous array is bit-identical to a flat
    // per-block two-pass (verified: var(x, axis=(-2,-1)) == var(x.reshape(B,M*N), -1)).
    let keep: usize = if let Ok(ax_raw) = axis_obj.extract::<i64>() {
        let ax = if ax_raw < 0 { ax_raw + ndim } else { ax_raw };
        if ax < 0 || ax != ndim - 1 {
            return Ok(None); // only the contiguous last axis (inner == 1)
        }
        (ndim - 1) as usize
    } else if let Ok(axes) = axis_obj.extract::<Vec<i64>>() {
        if axes.is_empty() {
            return Ok(None);
        }
        let mut resolved: Vec<i64> = axes
            .iter()
            .map(|&ax| if ax < 0 { ax + ndim } else { ax })
            .collect();
        resolved.sort_unstable();
        let k = resolved.len();
        resolved.dedup();
        if resolved.len() != k {
            return Ok(None); // duplicate axes -> numpy raises; defer to match its error
        }
        // require exactly the contiguous trailing range [ndim-k .. ndim)
        let expected: Vec<i64> = (ndim - k as i64..ndim).collect();
        if resolved[0] < 0 || resolved != expected {
            return Ok(None); // non-trailing / out-of-range -> defer to numpy
        }
        (ndim - k as i64) as usize
    } else {
        return Ok(None);
    };
    let axis_len: usize = shape[keep..].iter().product();
    if axis_len == 0 || axis_len <= ddof {
        return Ok(None);
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let outer: usize = shape[..keep].iter().product();
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only buffer held
    // under the GIL -> &[f64] (Sync) for the parallel per-lane fold below.
    let data: &[f64] =
        unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), cells.len()) };
    let lane_var = |lane: &[f64]| -> Option<f64> {
        let mut buf = [0.0f64; 128];
        let lc: &[pyo3::buffer::ReadOnlyCell<f64>] =
            unsafe { std::slice::from_raw_parts(lane.as_ptr().cast(), lane.len()) };
        // NaN-propagating pairwise sum (nan_to_zero = false): any NaN/Inf -> non-finite
        // mean -> defer the whole call to numpy below.
        let sum = pairwise_simd_f64(lc, 0, lane.len(), false, &mut buf);
        let avg = sum / lane.len() as f64;
        if !avg.is_finite() {
            return None;
        }
        let sq = pairwise_sqr_dev_f64(lc, 0, lane.len(), avg, &mut buf);
        let var = sq / (lane.len() - ddof) as f64;
        Some(if take_sqrt { var.sqrt() } else { var })
    };
    use rayon::prelude::*;
    // Same crossover as nanvar_axis: per-lane two-pass fold is cheap, so rayon fan-out
    // only pays off above ~1e5 total elements.
    const VAR_AXIS_PARALLEL_MIN: usize = 98_304;
    let parallel =
        outer * axis_len >= VAR_AXIS_PARALLEL_MIN && rayon::current_num_threads() >= 2;
    let results: Vec<Option<f64>> = if parallel {
        data.par_chunks_exact(axis_len).map(lane_var).collect()
    } else {
        data.chunks_exact(axis_len).map(lane_var).collect()
    };
    let Some(out): Option<Vec<f64>> = results.into_iter().collect() else {
        return Ok(None);
    };
    let flat = numpy_array_from_slice(py, &numpy, &out, "float64")?;
    let mut out_shape: Vec<usize> = shape[..keep].to_vec();
    if keepdims {
        // numpy keeps every reduced trailing axis as length 1.
        for _ in keep..ndim as usize {
            out_shape.push(1);
        }
    }
    let reshaped = flat.call_method1("reshape", (PyTuple::new(py, out_shape.iter().copied())?,))?;
    if out_shape.is_empty() {
        return Ok(Some(reshaped.get_item(())?.unbind()));
    }
    Ok(Some(reshaped.unbind()))
}

// Plain (NaN-propagating) np.var / np.std along the FIRST axis (axis=0) of a C-contiguous
// f64 ndarray — the ubiquitous ML feature-standardization reduction. numpy.var(axis=0)
// reduces the outer axis SEQUENTIALLY (NOT pairwise — verified: add.reduce(a, axis=0) ==
// a straight row-by-row accumulation, unlike the last-axis pairwise path) and materializes
// two whole-array temporaries (a - mean broadcast, then squared) before each reduce. This
// streaming two-pass reads each contiguous slab (the i-th sub-array of `inner` elements)
// twice with no temporary: pass 1 accumulates the row sum -> mean, pass 2 accumulates
// (slab - mean)^2 -> var. Serial (cache-optimal sequential stream); the win is numpy's
// temp avoidance, not threads (column-block parallelism is cache-hostile on a row-major
// array and was rejected). NaN/Inf propagate through the straight (a-mean)^2 exactly as
// numpy does (no NaN->0 leaf here),
// so unlike the trailing-axis path no non-finite defer is needed. M <= ddof defers
// (numpy warns + NaN). Only axis that normalizes to 0; everything else defers.
fn try_zerocopy_f64_var_axis0(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis_obj: &Bound<'_, PyAny>,
    ddof: usize,
    take_sqrt: bool,
    keepdims: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let Some(in_buffer) = f64_contiguous_cells(py, a, &numpy)? else {
        return Ok(None);
    };
    let Ok(ax_raw) = axis_obj.extract::<i64>() else {
        return Ok(None);
    };
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len() as i64;
    if ndim < 1 {
        return Ok(None);
    }
    let ax = if ax_raw < 0 { ax_raw + ndim } else { ax_raw };
    if ax != 0 || ndim < 2 {
        return Ok(None); // only the first axis of a >=2-D array (1-D axis=0 = flat path)
    }
    let m = shape[0];
    if m == 0 || m <= ddof {
        return Ok(None); // numpy warns + returns NaN for m - ddof <= 0
    }
    let inner: usize = shape[1..].iter().product();
    if inner == 0 {
        return Ok(None);
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only buffer held under
    // the GIL -> &[f64] (Sync) for the parallel disjoint-column folds below.
    let data: &[f64] =
        unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), cells.len()) };
    let denom = (m - ddof) as f64;
    let m_f = m as f64;
    // Fill output columns [c0 .. c0+width) by streaming all m slabs twice (sequential per
    // column -> bit-exact with numpy's sequential axis-0 reduce).
    let process = |c0: usize, cols: &mut [f64]| {
        let width = cols.len();
        let mut mean = vec![0.0f64; width];
        for i in 0..m {
            let base = i * inner + c0;
            let row = &data[base..base + width];
            for j in 0..width {
                mean[j] += row[j];
            }
        }
        for mj in mean.iter_mut() {
            *mj /= m_f;
        }
        let mut sq = vec![0.0f64; width];
        for i in 0..m {
            let base = i * inner + c0;
            let row = &data[base..base + width];
            for j in 0..width {
                let d = row[j] - mean[j];
                sq[j] += d * d;
            }
        }
        for j in 0..width {
            let v = sq[j] / denom;
            cols[j] = if take_sqrt { v.sqrt() } else { v };
        }
    };
    let mut out = vec![0.0f64; inner];
    // Serial streaming: the two passes read the whole array sequentially (row by row,
    // full cache lines) — bandwidth-optimal. Column-block parallelism was tried and
    // REJECTED: each thread strides through all m rows reading only its column slice, so
    // a row-major array is read with poor spatial locality; it was both slower and far
    // noisier than this cache-friendly serial stream. The win here is numpy's temp
    // avoidance (it materializes a-mean and (a-mean)^2 whole-array temps), not threads.
    process(0, &mut out);
    let flat = numpy_array_from_slice(py, &numpy, &out, "float64")?;
    let mut out_shape: Vec<usize> = shape[1..].to_vec();
    if keepdims {
        out_shape.insert(0, 1); // numpy keeps the reduced first axis as length 1
    }
    let reshaped = flat.call_method1("reshape", (PyTuple::new(py, out_shape.iter().copied())?,))?;
    if out_shape.is_empty() {
        return Ok(Some(reshaped.get_item(())?.unbind()));
    }
    Ok(Some(reshaped.unbind()))
}

// NaN-ignoring np.nanvar / np.nanstd along the FIRST axis (axis=0) of a C-contiguous f64
// ndarray — the analog of try_zerocopy_f64_var_axis0 for missing-data standardization.
// numpy.nanvar materializes a NaN->0 copy, an isnan mask, a per-column count, the
// a-mean broadcast, and the squared temp before two SEQUENTIAL axis-0 reduces (~5x slower
// than plain var). This streaming two-pass accumulates per column, skipping NaN (= numpy's
// NaN->0 then sum): pass 1 -> per-column sum + non-NaN count -> mean; pass 2 -> sum of
// (slab-mean)^2 over non-NaN -> var; std = sqrt. Serial + cache-friendly (column-block
// parallelism is cache-hostile on row-major; see try_zerocopy_f64_var_axis0). Bit-exact
// (numpy reduces axis=0 sequentially; masked positions contribute 0 in both). If ANY
// column has count <= ddof (e.g. an all-NaN column) the WHOLE call defers to numpy so its
// "Degrees of freedom <= 0" warning + per-column NaN parity stay exact.
fn try_zerocopy_f64_nanvar_axis0(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis_obj: &Bound<'_, PyAny>,
    ddof: usize,
    take_sqrt: bool,
    keepdims: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let Some(in_buffer) = f64_contiguous_cells(py, a, &numpy)? else {
        return Ok(None);
    };
    let Ok(ax_raw) = axis_obj.extract::<i64>() else {
        return Ok(None);
    };
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len() as i64;
    if ndim < 1 {
        return Ok(None);
    }
    let ax = if ax_raw < 0 { ax_raw + ndim } else { ax_raw };
    if ax != 0 || ndim < 2 {
        return Ok(None);
    }
    let m = shape[0];
    if m == 0 {
        return Ok(None);
    }
    let inner: usize = shape[1..].iter().product();
    if inner == 0 {
        return Ok(None);
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only under the GIL.
    let data: &[f64] =
        unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), cells.len()) };
    let mut sum = vec![0.0f64; inner];
    let mut cnt = vec![0u64; inner];
    for i in 0..m {
        let base = i * inner;
        let row = &data[base..base + inner];
        for j in 0..inner {
            let v = row[j];
            if !v.is_nan() {
                sum[j] += v;
                cnt[j] += 1;
            }
        }
    }
    // Any column with count <= ddof -> defer the whole call (numpy warns + NaN there).
    if cnt.iter().any(|&c| (c as usize) <= ddof) {
        return Ok(None);
    }
    let mut mean = vec![0.0f64; inner];
    for j in 0..inner {
        mean[j] = sum[j] / cnt[j] as f64;
    }
    let mut sq = vec![0.0f64; inner];
    for i in 0..m {
        let base = i * inner;
        let row = &data[base..base + inner];
        for j in 0..inner {
            let v = row[j];
            if !v.is_nan() {
                let d = v - mean[j];
                sq[j] += d * d;
            }
        }
    }
    let mut out = vec![0.0f64; inner];
    for j in 0..inner {
        let var = sq[j] / (cnt[j] as usize - ddof) as f64;
        out[j] = if take_sqrt { var.sqrt() } else { var };
    }
    let flat = numpy_array_from_slice(py, &numpy, &out, "float64")?;
    let mut out_shape: Vec<usize> = shape[1..].to_vec();
    if keepdims {
        out_shape.insert(0, 1);
    }
    let reshaped = flat.call_method1("reshape", (PyTuple::new(py, out_shape.iter().copied())?,))?;
    if out_shape.is_empty() {
        return Ok(Some(reshaped.get_item(())?.unbind()));
    }
    Ok(Some(reshaped.unbind()))
}

// Which contiguous-last-axis vector norm the native fold computes.
#[derive(Clone, Copy)]
enum VectorNormKind {
    L2,     // ord None / 2: sqrt(add.reduce(x*x))
    L1,     // ord 1:        add.reduce(abs(x))
    MaxAbs, // ord +inf:     abs(x).max(axis)  (NaN-propagating)
    MinAbs, // ord -inf:     abs(x).min(axis)  (NaN-propagating)
}

// NaN-propagating max/min of |x| over a lane — the bit-exact analog of numpy's
// `abs(x).max(axis)` / `.min(axis)` (np.maximum/minimum.reduce, which propagate
// NaN, unlike f64::max/min). abs() and max/min are exact, so this matches numpy
// bit-for-bit; any NaN in the lane yields NaN, +-Inf flow through naturally.
fn lane_extreme_abs_f64(lane: &[f64], want_max: bool) -> f64 {
    let mut acc = if want_max {
        f64::NEG_INFINITY
    } else {
        f64::INFINITY
    };
    let mut saw_nan = false;
    for &v in lane {
        let a = v.abs();
        if a.is_nan() {
            saw_nan = true;
        } else if (want_max && a > acc) || (!want_max && a < acc) {
            acc = a;
        }
    }
    if saw_nan {
        f64::NAN
    } else {
        acc
    }
}

// np.linalg.norm(x, ord in {None, 1, 2}, axis=<int last axis>) - a vector L1 or L2
// norm along the contiguous last axis. numpy materializes a whole-array temporary
// (s = (x.conj()*x).real for L2, abs(x) for L1) then a per-axis add.reduce (plus
// sqrt for L2); this per-lane fold reduces each contiguous lane with NO temporary,
// parallel across lanes -> big win at large outer counts. Bit-exact: pairwise_sq_f64
// / pairwise_abs_f64 reuse the same pairwise tree numpy's add.reduce uses over the
// materialized temp. NaN/Inf propagate naturally (sqrt(Inf)=Inf, sqrt(NaN)=NaN;
// abs(NaN)=NaN), so no non-finite defer is needed. Gated to f64 C-contiguous
// ndarray, single last-axis reduction; everything else falls through to numpy.
fn try_zerocopy_f64_vector_norm_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis_obj: &Bound<'_, PyAny>,
    kind: VectorNormKind,
    keepdims: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let Some(in_buffer) = f64_contiguous_cells(py, a, &numpy)? else {
        return Ok(None);
    };
    let Ok(ax_raw) = axis_obj.extract::<i64>() else {
        return Ok(None);
    };
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len() as i64;
    let ax = if ax_raw < 0 { ax_raw + ndim } else { ax_raw };
    if ax < 0 || ax != ndim - 1 {
        return Ok(None); // only the contiguous last axis (inner == 1)
    }
    let ax = ax as usize;
    let axis_len = shape[ax];
    if axis_len == 0 {
        return Ok(None);
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let outer: usize = shape[..ax].iter().product();
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only buffer held
    // under the GIL -> &[f64] (Sync) for the parallel per-lane fold below.
    let data: &[f64] =
        unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), cells.len()) };
    let lane_norm = |lane: &[f64]| -> f64 {
        let mut buf = [0.0f64; 128];
        match kind {
            VectorNormKind::L2 => pairwise_sq_f64(lane, &mut buf).sqrt(),
            VectorNormKind::L1 => pairwise_abs_f64(lane, &mut buf),
            VectorNormKind::MaxAbs => lane_extreme_abs_f64(lane, true),
            VectorNormKind::MinAbs => lane_extreme_abs_f64(lane, false),
        }
    };
    use rayon::prelude::*;
    // Same crossover as var_axis: the per-lane fold is cheap, rayon only pays off
    // above ~1e5 total elements.
    const NORM_AXIS_PARALLEL_MIN: usize = 98_304;
    let parallel =
        outer * axis_len >= NORM_AXIS_PARALLEL_MIN && rayon::current_num_threads() >= 2;
    let out: Vec<f64> = if parallel {
        data.par_chunks_exact(axis_len).map(lane_norm).collect()
    } else {
        data.chunks_exact(axis_len).map(lane_norm).collect()
    };
    let flat = numpy_array_from_slice(py, &numpy, &out, "float64")?;
    let mut out_shape: Vec<usize> = shape[..ax].to_vec();
    if keepdims {
        out_shape.push(1);
    }
    let reshaped = flat.call_method1("reshape", (PyTuple::new(py, out_shape.iter().copied())?,))?;
    if out_shape.is_empty() {
        return Ok(Some(reshaped.get_item(())?.unbind()));
    }
    Ok(Some(reshaped.unbind()))
}

// np.linalg.norm(x, ord in {None,'fro','f'}, axis=(<-2>,<-1>)) - the Frobenius norm
// over the TRAILING two (contiguous) axes of a C-contiguous f64 stack. numpy runs
// `sqrt(np.add.reduce((x.conj()*x).real, axis=(row,col)))`, materializing a whole
// (..., M, N) squared temporary then a single-threaded 2-axis reduce. For a
// C-contiguous array each (M, N) matrix is one contiguous M*N block, and numpy's
// 2-axis reduce is bit-identical to a flat pairwise sum-of-squares over that block
// (verified: add.reduce(x, axis=(-2,-1)) == add.reduce(x.reshape(B, M*N), axis=-1)).
// So pairwise_sq_f64 over each block + sqrt, parallel across blocks, is bit-exact
// and avoids the temporary. NaN/Inf propagate (no defer). Note `norm(x)` with
// axis=None ravels to a BLAS dot (fast) and is NOT this path - only an explicit
// trailing 2-tuple axis reaches here. ax0/ax1 are the raw (possibly negative) axis
// pair; this validates they resolve to the last two axes and bails otherwise.
fn try_zerocopy_f64_frobenius_lastaxes(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    ax0: i64,
    ax1: i64,
    keepdims: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let Some(in_buffer) = f64_contiguous_cells(py, a, &numpy)? else {
        return Ok(None);
    };
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len() as i64;
    if ndim < 2 {
        return Ok(None);
    }
    let resolve = |ax: i64| if ax < 0 { ax + ndim } else { ax };
    let (r0, r1) = (resolve(ax0), resolve(ax1));
    let mut pair = [r0, r1];
    pair.sort_unstable();
    if r0 < 0 || r1 < 0 || pair != [ndim - 2, ndim - 1] {
        return Ok(None); // only the trailing two (contiguous) axes
    }
    let nd = ndim as usize;
    let block = shape[nd - 2] * shape[nd - 1];
    if block == 0 {
        return Ok(None);
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let outer: usize = shape[..nd - 2].iter().product();
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only buffer held
    // under the GIL -> &[f64] (Sync) for the parallel per-block fold below.
    let data: &[f64] =
        unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), cells.len()) };
    let lane_norm = |blk: &[f64]| -> f64 {
        let mut buf = [0.0f64; 128];
        pairwise_sq_f64(blk, &mut buf).sqrt()
    };
    use rayon::prelude::*;
    const NORM_AXIS_PARALLEL_MIN: usize = 98_304;
    let parallel =
        outer * block >= NORM_AXIS_PARALLEL_MIN && rayon::current_num_threads() >= 2;
    let out: Vec<f64> = if parallel {
        data.par_chunks_exact(block).map(lane_norm).collect()
    } else {
        data.chunks_exact(block).map(lane_norm).collect()
    };
    let flat = numpy_array_from_slice(py, &numpy, &out, "float64")?;
    let mut out_shape: Vec<usize> = shape[..nd - 2].to_vec();
    if keepdims {
        out_shape.push(1);
        out_shape.push(1);
    }
    let reshaped = flat.call_method1("reshape", (PyTuple::new(py, out_shape.iter().copied())?,))?;
    if out_shape.is_empty() {
        return Ok(Some(reshaped.get_item(())?.unbind()));
    }
    Ok(Some(reshaped.unbind()))
}

// Which induced matrix p-norm the native fold computes over the trailing 2 axes.
#[derive(Clone, Copy)]
enum MatrixNormKind {
    MaxRowSum, // ord +inf: max over rows of add.reduce(|x|, axis=-1)
    MinRowSum, // ord -inf: min over rows of the same row abs-sums
    MaxColSum, // ord 1:    max over cols of add.reduce(|x|, axis=-2)
    MinColSum, // ord -1:   min over cols of the same column abs-sums
}

// NaN-propagating max/min over a slice of (already non-negative) abs-sums - the
// bit-exact analog of numpy's `.max(axis)` / `.min(axis)` over the reduced sums
// (np.maximum/minimum.reduce propagate NaN, unlike f64::max/min).
fn reduce_extreme_f64(sums: &[f64], want_max: bool) -> f64 {
    let mut acc = if want_max {
        f64::NEG_INFINITY
    } else {
        f64::INFINITY
    };
    let mut saw_nan = false;
    for &s in sums {
        if s.is_nan() {
            saw_nan = true;
        } else if (want_max && s > acc) || (!want_max && s < acc) {
            acc = s;
        }
    }
    if saw_nan {
        f64::NAN
    } else {
        acc
    }
}

// np.linalg.norm(x, ord in {1,-1,+inf,-inf}, axis=(<-2>,<-1>)) - an induced matrix
// p-norm over the TRAILING two (contiguous) axes of a C-contiguous f64 stack.
// numpy computes a whole-array `abs(x)` temporary, then for ord=+-inf a per-ROW
// abs-sum `add.reduce(|x|, axis=-1)` followed by max/min over rows, and for
// ord=+-1 a per-COLUMN abs-sum `add.reduce(|x|, axis=-2)` followed by max/min over
// columns - three passes over the materialized temp, single-threaded. This
// per-(M,N)-block fold reuses pairwise_abs_f64 (rows are contiguous; columns are
// gathered into a small M-buffer) so each row/column abs-sum matches numpy's
// pairwise reduce bit-for-bit, then a NaN-propagating max/min, parallel across
// blocks. Verified bit-exact: add.reduce(|x|,axis=-1).max(-1) == numpy inf-norm,
// add.reduce(|x|,axis=-2).max(-1) == numpy 1-norm. NaN/Inf propagate (no defer).
// ax0/ax1 are the raw axis pair; validated to resolve to the last two axes.
fn try_zerocopy_f64_matrix_norm_lastaxes(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    ax0: i64,
    ax1: i64,
    kind: MatrixNormKind,
    keepdims: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let Some(in_buffer) = f64_contiguous_cells(py, a, &numpy)? else {
        return Ok(None);
    };
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len() as i64;
    if ndim < 2 {
        return Ok(None);
    }
    let resolve = |ax: i64| if ax < 0 { ax + ndim } else { ax };
    let (r0, r1) = (resolve(ax0), resolve(ax1));
    // Induced matrix p-norms are NOT axis-symmetric (ord=1 and ord=inf are
    // transposes), so axis ORDER matters: require row_axis == ndim-2 and
    // col_axis == ndim-1 exactly. A reversed pair (-1,-2) defers to numpy, which
    // would swap the row/column roles.
    if r0 != ndim - 2 || r1 != ndim - 1 {
        return Ok(None);
    }
    let nd = ndim as usize;
    let (m, n) = (shape[nd - 2], shape[nd - 1]);
    let block = m * n;
    if block == 0 {
        return Ok(None); // empty matrices: defer to numpy's reduction semantics
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let outer: usize = shape[..nd - 2].iter().product();
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only buffer held
    // under the GIL -> &[f64] (Sync) for the parallel per-block fold below.
    let data: &[f64] =
        unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), cells.len()) };
    let (by_row, want_max) = match kind {
        MatrixNormKind::MaxRowSum => (true, true),
        MatrixNormKind::MinRowSum => (true, false),
        MatrixNormKind::MaxColSum => (false, true),
        MatrixNormKind::MinColSum => (false, false),
    };
    let block_norm = move |blk: &[f64]| -> f64 {
        let mut buf = [0.0f64; 128];
        if by_row {
            // per contiguous row: pairwise abs-sum, then extreme over the M rows
            let row_sums: Vec<f64> = (0..m)
                .map(|r| pairwise_abs_f64(&blk[r * n..r * n + n], &mut buf))
                .collect();
            reduce_extreme_f64(&row_sums, want_max)
        } else {
            // per column: gather the M strided entries, pairwise abs-sum, extreme over N
            let mut col = vec![0.0f64; m];
            let col_sums: Vec<f64> = (0..n)
                .map(|c| {
                    for r in 0..m {
                        col[r] = blk[r * n + c];
                    }
                    pairwise_abs_f64(&col, &mut buf)
                })
                .collect();
            reduce_extreme_f64(&col_sums, want_max)
        }
    };
    use rayon::prelude::*;
    const NORM_AXIS_PARALLEL_MIN: usize = 98_304;
    let parallel =
        outer * block >= NORM_AXIS_PARALLEL_MIN && rayon::current_num_threads() >= 2;
    let out: Vec<f64> = if parallel {
        data.par_chunks_exact(block).map(&block_norm).collect()
    } else {
        data.chunks_exact(block).map(&block_norm).collect()
    };
    let flat = numpy_array_from_slice(py, &numpy, &out, "float64")?;
    let mut out_shape: Vec<usize> = shape[..nd - 2].to_vec();
    if keepdims {
        out_shape.push(1);
        out_shape.push(1);
    }
    let reshaped = flat.call_method1("reshape", (PyTuple::new(py, out_shape.iter().copied())?,))?;
    if out_shape.is_empty() {
        return Ok(Some(reshaped.get_item(())?.unbind()));
    }
    Ok(Some(reshaped.unbind()))
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, out=None, keepdims=None))]
fn nanmax(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    keepdims: Option<bool>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let nanmax_fn = numpy.getattr("nanmax")?;
    let axis_for_parse = axis.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        if let Some(out_val) = out.as_ref() {
            kwargs.set_item("out", out_val.bind(py))?;
        }
        if let Some(keepdims_val) = keepdims {
            kwargs.set_item("keepdims", keepdims_val)?;
        }
        Ok(nanmax_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    if out.as_ref().is_some_and(|value| !value.bind(py).is_none()) {
        return fallback();
    }

    // nanmax preserves the input dtype exactly; the native kernel widens
    // narrow ints/floats, so defer anything but bool/8-byte numerics to numpy.
    if !native_minmax_preserves_dtype(py, a.bind(py)) {
        return fallback();
    }
    // Integer input cannot contain NaN, so nannanmax == the plain reduction; route to
    // numpy's fast reduction (via fallback) instead of the slow native f64 path.
    if numpy_dtype_is_integer(py, a.bind(py))? {
        return fallback();
    }
    // Zero-copy SIMD f64 fast path (axis=None): ~8x faster than the extract → scalar
    // nan-scan. All-NaN/empty defer to numpy (warning/error). keepdims=True reshapes
    // the scalar to the all-ones shape numpy returns (one element, dtype preserved).
    if axis.as_ref().is_none_or(|v| v.bind(py).is_none())
        && let Some(out) = try_zerocopy_f64_nanextreme(py, a.bind(py), true)?
    {
        if keepdims.unwrap_or(false) {
            let ndim = a.bind(py).getattr("ndim")?.extract::<usize>()?;
            let arr = numpy.call_method1("asarray", (out.bind(py),))?;
            let reshaped =
                arr.call_method1("reshape", (PyTuple::new(py, vec![1usize; ndim])?,))?;
            return Ok(reshaped.unbind());
        }
        return Ok(out);
    }
    // Zero-copy SIMD per-lane fast path for the contiguous last axis (~12x faster
    // than the extract → native scan; all-NaN/±0 lanes defer to numpy).
    if let Some(axis_val) = axis.as_ref()
        && !axis_val.bind(py).is_none()
        && let Some(out) = try_zerocopy_f64_nanextreme_axis(py, a.bind(py), axis_val.bind(py), true)?
    {
        if keepdims.unwrap_or(false) {
            let ndim = a.bind(py).getattr("ndim")?.extract::<usize>()?;
            let ax_i = axis_val.bind(py).extract::<i64>()?;
            return keepdims_expand_axis(py, &numpy, out, ax_i, ndim);
        }
        return Ok(out);
    }
    // Non-contiguous (transposed/strided) ndarrays bail out of the zero-copy paths
    // into the cold extract → scalar scan (slower than numpy's cache-blocked strided
    // reduction). Delegate them to numpy (same parity).
    if let Ok(ndarray_type) = numpy.getattr("ndarray")
        && a.bind(py).is_exact_instance(&ndarray_type)
        && !a
            .bind(py)
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return fallback();
    }
    // Multi-axis (tuple) reductions extract the whole array then fall back to numpy
    // on the axis re-parse below (wasteful 8x bool-bridge / f64 copy). Delegate up front.
    if axis.as_ref().is_some_and(|ax| ax.bind(py).cast::<PyTuple>().is_ok()) {
        return fallback();
    }
    let a = match extract_numeric_array(py, a.bind(py), "nanmax(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let axis = match extract_axis_spec(py, axis_for_parse, "nanmax") {
        Ok(None) => None,
        Ok(Some(axes)) if axes.len() == 1 => Some(axes[0]),
        Ok(Some(_)) => return fallback(),
        Err(_) => return fallback(),
    };
    let result = match a.nanmax(axis, keepdims.unwrap_or(false)) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    // NumPy returns a numpy scalar (np.float64) for a full reduction, not a
    // 0-d ndarray; collapse the 0-d case to a scalar to match.
    build_numpy_scalar_or_array(py, &result)
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, out=None, keepdims=None))]
fn nanmin(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    keepdims: Option<bool>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let nanmin_fn = numpy.getattr("nanmin")?;
    let axis_for_parse = axis.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        if let Some(out_val) = out.as_ref() {
            kwargs.set_item("out", out_val.bind(py))?;
        }
        if let Some(keepdims_val) = keepdims {
            kwargs.set_item("keepdims", keepdims_val)?;
        }
        Ok(nanmin_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    if out.as_ref().is_some_and(|value| !value.bind(py).is_none()) {
        return fallback();
    }

    // nanmin preserves the input dtype exactly; the native kernel widens
    // narrow ints/floats, so defer anything but bool/8-byte numerics to numpy.
    if !native_minmax_preserves_dtype(py, a.bind(py)) {
        return fallback();
    }
    // Integer input cannot contain NaN, so nannanmin == the plain reduction; route to
    // numpy's fast reduction (via fallback) instead of the slow native f64 path.
    if numpy_dtype_is_integer(py, a.bind(py))? {
        return fallback();
    }
    // Zero-copy SIMD f64 fast path (axis=None): ~9x faster than the extract → scalar
    // nan-scan. All-NaN/empty defer to numpy (warning/error). keepdims=True reshapes
    // the scalar to the all-ones shape numpy returns (one element, dtype preserved).
    if axis.as_ref().is_none_or(|v| v.bind(py).is_none())
        && let Some(out) = try_zerocopy_f64_nanextreme(py, a.bind(py), false)?
    {
        if keepdims.unwrap_or(false) {
            let ndim = a.bind(py).getattr("ndim")?.extract::<usize>()?;
            let arr = numpy.call_method1("asarray", (out.bind(py),))?;
            let reshaped =
                arr.call_method1("reshape", (PyTuple::new(py, vec![1usize; ndim])?,))?;
            return Ok(reshaped.unbind());
        }
        return Ok(out);
    }
    // Zero-copy SIMD per-lane fast path for the contiguous last axis (~12x faster
    // than the extract → native scan; all-NaN/±0 lanes defer to numpy).
    if let Some(axis_val) = axis.as_ref()
        && !axis_val.bind(py).is_none()
        && let Some(out) = try_zerocopy_f64_nanextreme_axis(py, a.bind(py), axis_val.bind(py), false)?
    {
        if keepdims.unwrap_or(false) {
            let ndim = a.bind(py).getattr("ndim")?.extract::<usize>()?;
            let ax_i = axis_val.bind(py).extract::<i64>()?;
            return keepdims_expand_axis(py, &numpy, out, ax_i, ndim);
        }
        return Ok(out);
    }
    // Non-contiguous (transposed/strided) ndarrays bail out of the zero-copy paths
    // into the cold extract → scalar scan (slower than numpy's cache-blocked strided
    // reduction). Delegate them to numpy (same parity).
    if let Ok(ndarray_type) = numpy.getattr("ndarray")
        && a.bind(py).is_exact_instance(&ndarray_type)
        && !a
            .bind(py)
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return fallback();
    }
    // Multi-axis (tuple) reductions extract the whole array then fall back to numpy
    // on the axis re-parse below (wasteful 8x bool-bridge / f64 copy). Delegate up front.
    if axis.as_ref().is_some_and(|ax| ax.bind(py).cast::<PyTuple>().is_ok()) {
        return fallback();
    }
    let a = match extract_numeric_array(py, a.bind(py), "nanmin(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let axis = match extract_axis_spec(py, axis_for_parse, "nanmin") {
        Ok(None) => None,
        Ok(Some(axes)) if axes.len() == 1 => Some(axes[0]),
        Ok(Some(_)) => return fallback(),
        Err(_) => return fallback(),
    };
    let result = match a.nanmin(axis, keepdims.unwrap_or(false)) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    // NumPy returns a numpy scalar (np.float64) for a full reduction, not a
    // 0-d ndarray; collapse the 0-d case to a scalar to match.
    build_numpy_scalar_or_array(py, &result)
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, dtype=None, out=None, ddof=None, keepdims=None, r#where=None, mean=None, correction=None))]
#[allow(clippy::too_many_arguments)]
fn nanstd(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    dtype: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    ddof: Option<Py<PyAny>>,
    keepdims: Option<bool>,
    r#where: Option<Py<PyAny>>,
    mean: Option<Py<PyAny>>,
    correction: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let nanstd_fn = numpy.getattr("nanstd")?;
    let axis_for_parse = axis.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        if let Some(dtype_val) = dtype.as_ref() {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        if let Some(out_val) = out.as_ref() {
            kwargs.set_item("out", out_val.bind(py))?;
        }
        if let Some(ddof_val) = ddof.as_ref() {
            kwargs.set_item("ddof", ddof_val.bind(py))?;
        }
        if let Some(keepdims_val) = keepdims {
            kwargs.set_item("keepdims", keepdims_val)?;
        }
        if let Some(where_val) = r#where.as_ref() {
            kwargs.set_item("where", where_val.bind(py))?;
        }
        if let Some(mean_val) = mean.as_ref() {
            kwargs.set_item("mean", mean_val.bind(py))?;
        }
        if let Some(correction_val) = correction.as_ref() {
            kwargs.set_item("correction", correction_val.bind(py))?;
        }
        Ok(nanstd_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    if dtype.is_some()
        || out.as_ref().is_some_and(|value| !value.bind(py).is_none())
        || r#where.is_some()
        || mean.is_some()
        || correction.is_some()
    {
        return fallback();
    }

    // The native kernel computes in f64; defer float16/float32/complex inputs to
    // numpy.nanstd so the narrow float dtype is preserved (NumPy returns float32 for
    // float32 input, float16 for float16) instead of widening every result to float64.
    if !native_f64_reduction_preserves_dtype(py, a.bind(py)) {
        return fallback();
    }
    // Integer input cannot contain NaN, so nannanstd == the plain reduction; route to
    // numpy's fast reduction (via fallback) instead of the slow native f64 path.
    if numpy_dtype_is_integer(py, a.bind(py))? {
        return fallback();
    }
    // nanstd == sqrt(nanvar); same bit-exact SIMD two-pass flat fast path.
    if axis.as_ref().is_none_or(|v| v.bind(py).is_none())
        && let Some(ddof_val) = ddof
            .as_ref()
            .map_or(Some(0isize), |v| v.bind(py).extract::<isize>().ok())
        && ddof_val >= 0
        && let Some(var) = compute_f64_nanvar_flat(py, a.bind(py), ddof_val as usize)?
    {
        let out = numpy.getattr("float64")?.call1((var.sqrt(),))?.unbind();
        if keepdims.unwrap_or(false) {
            return keepdims_reshape_scalar(py, &numpy, a.bind(py), out);
        }
        return Ok(out);
    }
    // Zero-copy per-lane pairwise nanstd over the contiguous last axis (bit-exact;
    // parallel) — skips the cold extract → native nanstd path.
    if let Some(axis_val) = axis.as_ref()
        && !axis_val.bind(py).is_none()
        && let Some(ddof_val) = ddof
            .as_ref()
            .map_or(Some(0isize), |v| v.bind(py).extract::<isize>().ok())
        && ddof_val >= 0
        && let Some(out) = try_zerocopy_f64_nanvar_axis(
            py,
            a.bind(py),
            axis_val.bind(py),
            ddof_val as usize,
            true,
            keepdims.unwrap_or(false),
        )?
    {
        return Ok(out);
    }
    // Native first-axis (axis=0) streaming nanstd — see try_zerocopy_f64_nanvar_axis0.
    if let Some(axis_val) = axis.as_ref()
        && !axis_val.bind(py).is_none()
        && let Some(ddof_val) = ddof
            .as_ref()
            .map_or(Some(0isize), |v| v.bind(py).extract::<isize>().ok())
        && ddof_val >= 0
        && let Some(out) = try_zerocopy_f64_nanvar_axis0(
            py,
            a.bind(py),
            axis_val.bind(py),
            ddof_val as usize,
            true,
            keepdims.unwrap_or(false),
        )?
    {
        return Ok(out);
    }
    if noncontiguous_ndarray(&numpy, a.bind(py))? {
        return fallback();
    }
    // Multi-axis (tuple) reductions extract the whole array then fall back to numpy
    // on the axis re-parse below (wasteful 8x bool-bridge / f64 copy). Delegate up front.
    if axis.as_ref().is_some_and(|ax| ax.bind(py).cast::<PyTuple>().is_ok()) {
        return fallback();
    }
    let a = match extract_numeric_array(py, a.bind(py), "nanstd(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let axis = match extract_axis_spec(py, axis_for_parse, "nanstd") {
        Ok(None) => None,
        Ok(Some(axes)) if axes.len() == 1 => Some(axes[0]),
        Ok(Some(_)) => return fallback(),
        Err(_) => return fallback(),
    };
    let ddof = match ddof.as_ref() {
        None => 0,
        Some(value) => match value.bind(py).extract::<isize>() {
            Ok(parsed) if parsed >= 0 => parsed as usize,
            _ => return fallback(),
        },
    };
    let result = match a.nanstd(axis, keepdims.unwrap_or(false), ddof) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    if contains_nan_value(&result) {
        return fallback();
    }
    let output = build_numpy_array_from_ufunc(py, &result)?;
    if result.shape().is_empty() {
        return Ok(output.bind(py).get_item(())?.unbind());
    }
    Ok(output)
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, dtype=None, out=None, ddof=None, keepdims=None, r#where=None, mean=None, correction=None))]
#[allow(clippy::too_many_arguments)]
fn nanvar(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    dtype: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    ddof: Option<Py<PyAny>>,
    keepdims: Option<bool>,
    r#where: Option<Py<PyAny>>,
    mean: Option<Py<PyAny>>,
    correction: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let nanvar_fn = numpy.getattr("nanvar")?;
    let axis_for_parse = axis.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        if let Some(dtype_val) = dtype.as_ref() {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        if let Some(out_val) = out.as_ref() {
            kwargs.set_item("out", out_val.bind(py))?;
        }
        if let Some(ddof_val) = ddof.as_ref() {
            kwargs.set_item("ddof", ddof_val.bind(py))?;
        }
        if let Some(keepdims_val) = keepdims {
            kwargs.set_item("keepdims", keepdims_val)?;
        }
        if let Some(where_val) = r#where.as_ref() {
            kwargs.set_item("where", where_val.bind(py))?;
        }
        if let Some(mean_val) = mean.as_ref() {
            kwargs.set_item("mean", mean_val.bind(py))?;
        }
        if let Some(correction_val) = correction.as_ref() {
            kwargs.set_item("correction", correction_val.bind(py))?;
        }
        Ok(nanvar_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    if dtype.is_some()
        || out.as_ref().is_some_and(|value| !value.bind(py).is_none())
        || r#where.is_some()
        || mean.is_some()
        || correction.is_some()
    {
        return fallback();
    }

    // The native kernel computes in f64; defer float16/float32/complex inputs to
    // numpy.nanvar so the narrow float dtype is preserved (NumPy returns float32 for
    // float32 input, float16 for float16) instead of widening every result to float64.
    if !native_f64_reduction_preserves_dtype(py, a.bind(py)) {
        return fallback();
    }
    // Integer input cannot contain NaN, so nannanvar == the plain reduction; route to
    // numpy's fast reduction (via fallback) instead of the slow native f64 path.
    if numpy_dtype_is_integer(py, a.bind(py))? {
        return fallback();
    }
    // Bit-exact SIMD two-pass flat fast path (axis=None): ~3x faster than the extract
    // → native scan. DoF<=0 / all-NaN defer to numpy (warning). keepdims reshapes the
    // scalar to numpy's all-ones shape.
    if axis.as_ref().is_none_or(|v| v.bind(py).is_none())
        && let Some(ddof_val) = ddof
            .as_ref()
            .map_or(Some(0isize), |v| v.bind(py).extract::<isize>().ok())
        && ddof_val >= 0
        && let Some(var) = compute_f64_nanvar_flat(py, a.bind(py), ddof_val as usize)?
    {
        let out = numpy.getattr("float64")?.call1((var,))?.unbind();
        if keepdims.unwrap_or(false) {
            return keepdims_reshape_scalar(py, &numpy, a.bind(py), out);
        }
        return Ok(out);
    }
    // Zero-copy per-lane pairwise nanvar over the contiguous last axis (bit-exact;
    // parallel) — skips the cold extract → native nanvar path.
    if let Some(axis_val) = axis.as_ref()
        && !axis_val.bind(py).is_none()
        && let Some(ddof_val) = ddof
            .as_ref()
            .map_or(Some(0isize), |v| v.bind(py).extract::<isize>().ok())
        && ddof_val >= 0
        && let Some(out) = try_zerocopy_f64_nanvar_axis(
            py,
            a.bind(py),
            axis_val.bind(py),
            ddof_val as usize,
            false,
            keepdims.unwrap_or(false),
        )?
    {
        return Ok(out);
    }
    // Native first-axis (axis=0) streaming nanvar — see try_zerocopy_f64_nanvar_axis0.
    if let Some(axis_val) = axis.as_ref()
        && !axis_val.bind(py).is_none()
        && let Some(ddof_val) = ddof
            .as_ref()
            .map_or(Some(0isize), |v| v.bind(py).extract::<isize>().ok())
        && ddof_val >= 0
        && let Some(out) = try_zerocopy_f64_nanvar_axis0(
            py,
            a.bind(py),
            axis_val.bind(py),
            ddof_val as usize,
            false,
            keepdims.unwrap_or(false),
        )?
    {
        return Ok(out);
    }
    if noncontiguous_ndarray(&numpy, a.bind(py))? {
        return fallback();
    }
    // Multi-axis (tuple) reductions extract the whole array then fall back to numpy
    // on the axis re-parse below (wasteful 8x bool-bridge / f64 copy). Delegate up front.
    if axis.as_ref().is_some_and(|ax| ax.bind(py).cast::<PyTuple>().is_ok()) {
        return fallback();
    }
    let a = match extract_numeric_array(py, a.bind(py), "nanvar(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let axis = match extract_axis_spec(py, axis_for_parse, "nanvar") {
        Ok(None) => None,
        Ok(Some(axes)) if axes.len() == 1 => Some(axes[0]),
        Ok(Some(_)) => return fallback(),
        Err(_) => return fallback(),
    };
    let ddof = match ddof.as_ref() {
        None => 0,
        Some(value) => match value.bind(py).extract::<isize>() {
            Ok(parsed) if parsed >= 0 => parsed as usize,
            _ => return fallback(),
        },
    };
    let result = match a.nanvar(axis, keepdims.unwrap_or(false), ddof) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    let output = build_numpy_array_from_ufunc(py, &result)?;
    if result.shape().is_empty() {
        return Ok(output.bind(py).get_item(())?.unbind());
    }
    Ok(output)
}

// Zero-copy parallel flat nanargmax/nanargmin (axis=None) for C-contiguous f64 ndarrays.
// numpy's nanarg* is single-threaded; the native path used to extract the whole buffer into
// a UFuncArray copy and scan serially. Read the borrowed buffer (from_raw_parts, NO copy)
// and run a NaN-skipping argextreme per rayon chunk, then combine in index order (replace
// only on a STRICTLY better value -> numpy's first-occurrence among non-NaN). Returns
// Ok(None) to defer: not an exact f64 C-contiguous ndarray, below the parallel crossover, or
// the array is entirely NaN (numpy raises ValueError "All-NaN slice encountered").
fn try_zerocopy_f64_nanargextreme(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    a: &Bound<'_, PyAny>,
    take_max: bool,
) -> PyResult<Option<Py<PyAny>>> {
    if !a.is_exact_instance(&numpy.getattr("ndarray")?) || !numpy_dtype_is_f64(py, a) {
        return Ok(None);
    }
    if !a.getattr("flags")?.getattr("c_contiguous")?.extract::<bool>()? {
        return Ok(None);
    }
    let Ok(buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    let Some(cells) = buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = cells.len();
    // numpy's nanargmax/min is a two-pass copy-replace-NaN + argmax that thrashes cache at
    // large N; a single-pass parallel scan over the borrowed buffer wins decisively. The
    // crossover where rayon fan-out beats numpy is ~1<<18 (the old 1<<21 gate left the whole
    // 2^18..2^21 band on the slow native extract path, 1.5-2x slower than numpy).
    const NANARG_PARALLEL_MIN: usize = 1 << 18;
    if n < NANARG_PARALLEL_MIN || rayon::current_num_threads() < 2 {
        return Ok(None);
    }
    use rayon::prelude::*;
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only under the GIL.
    let data: &[f64] = unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), n) };
    let chunk = n.div_ceil(rayon::current_num_threads());
    let combine = |best: &mut Option<(usize, f64)>, idx: usize, v: f64| {
        let take = match *best {
            None => true,
            Some(b) => {
                if take_max {
                    v > b.1
                } else {
                    v < b.1
                }
            }
        };
        if take {
            *best = Some((idx, v));
        }
    };
    let partials: Vec<Option<(usize, f64)>> = data
        .par_chunks(chunk)
        .enumerate()
        .map(|(ci, c)| {
            let base = ci * chunk;
            let mut best: Option<(usize, f64)> = None;
            for (i, &v) in c.iter().enumerate() {
                if !v.is_nan() {
                    combine(&mut best, base + i, v);
                }
            }
            best
        })
        .collect();
    let mut best: Option<(usize, f64)> = None;
    for p in partials.into_iter().flatten() {
        combine(&mut best, p.0, p.1);
    }
    match best {
        Some((idx, _)) => Ok(Some(numpy.getattr("intp")?.call1((idx,))?.unbind())),
        None => Ok(None), // all-NaN -> defer to numpy (ValueError)
    }
}

// f32 counterpart of try_zerocopy_f64_nanargextreme. The f64 path is f64-only, so nanargmax/
// nanargmin on float32 fell to the cold f32->f64 widen extract (~6-8x). Read the f32 buffer
// directly and find the first non-NaN argmax/argmin comparing in f32 (order-preserving, so the
// index matches numpy bit-for-bit). Covers ALL sizes (serial small + parallel large) since the
// f32 cold path WIDENS (unlike the f64 cold path which is only mild). all-NaN -> defer.
fn try_zerocopy_f32_nanargextreme(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    a: &Bound<'_, PyAny>,
    take_max: bool,
) -> PyResult<Option<Py<PyAny>>> {
    if !a.is_exact_instance(&numpy.getattr("ndarray")?) || !numpy_dtype_is_f32(a) {
        return Ok(None);
    }
    if !a.getattr("flags")?.getattr("c_contiguous")?.extract::<bool>()? {
        return Ok(None);
    }
    let Ok(buffer) = PyBuffer::<f32>::get(a) else {
        return Ok(None);
    };
    let Some(cells) = buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = cells.len();
    if n == 0 {
        return Ok(None);
    }
    // SAFETY: ReadOnlyCell<f32> is repr(transparent) over f32; read-only under the GIL.
    let data: &[f32] = unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f32>(), n) };
    let combine = |best: &mut Option<(usize, f32)>, idx: usize, v: f32| {
        let take = match *best {
            None => true,
            Some(b) => {
                if take_max {
                    v > b.1
                } else {
                    v < b.1
                }
            }
        };
        if take {
            *best = Some((idx, v));
        }
    };
    // Mirror the f64 gate: parallel single-pass beats numpy's copy+argmax from ~1<<18 up.
    const NANARG_PARALLEL_MIN: usize = 1 << 18;
    let best = if n >= NANARG_PARALLEL_MIN && rayon::current_num_threads() >= 2 {
        use rayon::prelude::*;
        let chunk = n.div_ceil(rayon::current_num_threads());
        let partials: Vec<Option<(usize, f32)>> = data
            .par_chunks(chunk)
            .enumerate()
            .map(|(ci, c)| {
                let base = ci * chunk;
                let mut best: Option<(usize, f32)> = None;
                for (i, &v) in c.iter().enumerate() {
                    if !v.is_nan() {
                        combine(&mut best, base + i, v);
                    }
                }
                best
            })
            .collect();
        let mut best: Option<(usize, f32)> = None;
        for p in partials.into_iter().flatten() {
            combine(&mut best, p.0, p.1);
        }
        best
    } else {
        let mut best: Option<(usize, f32)> = None;
        for (i, &v) in data.iter().enumerate() {
            if !v.is_nan() {
                combine(&mut best, i, v);
            }
        }
        best
    };
    match best {
        Some((idx, _)) => Ok(Some(numpy.getattr("intp")?.call1((idx,))?.unbind())),
        None => Ok(None),
    }
}

// f32 nanargmax/nanargmin along the contiguous LAST axis (e.g. np.nanargmax(M, axis=-1) per-row).
// The native axis path extracts f32->f64 (widen, ~7x); read the f32 buffer directly and run a
// per-lane first-non-NaN argmax/argmin comparing in f32 (order-preserving -> index bit-identical
// to numpy). Lanes are independent contiguous runs -> serial/parallel identical. An all-NaN lane
// defers the whole call (numpy raises ValueError). Non-f32 / non-last-axis / 1-D / non-contiguous
// -> Ok(None) (the flat path handles axis=None 1-D; the native path handles the rest).
fn try_zerocopy_f32_nanarg_lastaxis(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    a: &Bound<'_, PyAny>,
    axis: isize,
    take_max: bool,
) -> PyResult<Option<Py<PyAny>>> {
    if !a.is_exact_instance(&numpy.getattr("ndarray")?) || !numpy_dtype_is_f32(a) {
        return Ok(None);
    }
    if !a.getattr("flags")?.getattr("c_contiguous")?.extract::<bool>()? {
        return Ok(None);
    }
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len();
    if ndim < 2 {
        return Ok(None); // 1-D flat is handled by try_zerocopy_f32_nanargextreme
    }
    let norm = if axis < 0 { axis + ndim as isize } else { axis };
    if norm < 0 || norm as usize != ndim - 1 {
        return Ok(None); // contiguous last axis only
    }
    let lane = shape[ndim - 1];
    if lane == 0 {
        return Ok(None); // numpy raises on a zero-length reduction axis
    }
    let outer: usize = shape[..ndim - 1].iter().product();
    let Ok(buffer) = PyBuffer::<f32>::get(a) else {
        return Ok(None);
    };
    let Some(cells) = buffer.as_slice(py) else {
        return Ok(None);
    };
    if cells.len() != outer * lane {
        return Ok(None);
    }
    // SAFETY: ReadOnlyCell<f32> is repr(transparent) over f32; read-only under the GIL.
    let data: &[f32] = unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f32>(), cells.len()) };
    let per_lane = |l: &[f32]| -> Option<usize> {
        let mut best: Option<(usize, f32)> = None;
        for (i, &v) in l.iter().enumerate() {
            if !v.is_nan() {
                let take = match best {
                    None => true,
                    Some(b) => {
                        if take_max {
                            v > b.1
                        } else {
                            v < b.1
                        }
                    }
                };
                if take {
                    best = Some((i, v));
                }
            }
        }
        best.map(|(i, _)| i)
    };
    const NANARG_LASTAXIS_PARALLEL_MIN: usize = 1 << 20;
    let parallel =
        outer * lane >= NANARG_LASTAXIS_PARALLEL_MIN && rayon::current_num_threads() >= 2;
    let per: Vec<Option<usize>> = if parallel {
        use rayon::prelude::*;
        data.par_chunks_exact(lane).map(per_lane).collect()
    } else {
        data.chunks_exact(lane).map(per_lane).collect()
    };
    if per.iter().any(|x| x.is_none()) {
        return Ok(None); // an all-NaN lane -> defer (numpy ValueError)
    }
    let indices: Vec<i64> = per.into_iter().map(|i| i.unwrap() as i64).collect();
    let out_shape: Vec<usize> = shape[..ndim - 1].to_vec();
    let flat = numpy_array_from_slice(py, numpy, &indices, "intp")?;
    Ok(Some(flat.call_method1("reshape", (out_shape,))?.unbind()))
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, out=None, keepdims=None))]
fn nanargmax(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    keepdims: Option<bool>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let nanargmax_fn = numpy.getattr("nanargmax")?;
    let axis_for_parse = axis.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        if let Some(out_val) = out.as_ref() {
            kwargs.set_item("out", out_val.bind(py))?;
        }
        if let Some(keepdims_val) = keepdims {
            kwargs.set_item("keepdims", keepdims_val)?;
        }
        Ok(nanargmax_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    if out.as_ref().is_some_and(|value| !value.bind(py).is_none()) {
        return fallback();
    }
    // keepdims-on-axis: the gate used to bail on ANY keepdims, forgoing the ~0.45x native win.
    // Skip the no-keepdims fast paths when keepdims is set; the general path re-inserts the reduced
    // axis via expand_dims (axis=None+keepdims -> all-ones reshape, delegated). (BlackThrush 2026-06-22.)
    let keep = keepdims == Some(true);

    // Integer input cannot contain NaN, so nanargmax == the plain reduction; route to
    // numpy's fast reduction (via fallback) instead of the slow native f64 path.
    if numpy_dtype_is_integer(py, a.bind(py))? {
        return fallback();
    }
    if !keep {
        if axis.is_none()
            && let Some(result) = try_zerocopy_f64_nanargextreme(py, &numpy, a.bind(py), true)?
        {
            return Ok(result);
        }
        // float32: read f32 directly (the f64 path is f64-only; f32 otherwise widen-extracts ~6-8x).
        if axis.is_none()
            && let Some(result) = try_zerocopy_f32_nanargextreme(py, &numpy, a.bind(py), true)?
        {
            return Ok(result);
        }
        // float32 along the last axis: per-lane nan-skip arg reading f32 directly (~7x widen avoided).
        if let Some(ax_obj) = axis.as_ref()
            && let Ok(ax) = ax_obj.bind(py).extract::<isize>()
            && let Some(result) =
                try_zerocopy_f32_nanarg_lastaxis(py, &numpy, a.bind(py), ax, true)?
        {
            return Ok(result);
        }
    }
    let orig_ndim = a
        .bind(py)
        .getattr("ndim")
        .ok()
        .and_then(|d| d.extract::<usize>().ok());
    let a = match extract_numeric_array(py, a.bind(py), "nanargmax(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let axis = match extract_axis_spec(py, axis_for_parse, "nanargmax") {
        Ok(None) => None,
        Ok(Some(axes)) if axes.len() == 1 => Some(axes[0]),
        Ok(Some(_)) => return fallback(),
        Err(_) => return fallback(),
    };
    // keepdims over the full array (axis=None) reshapes to all-ones dims; delegate.
    if keep && axis.is_none() {
        return fallback();
    }
    let result = match a.nanargmax(axis) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    let output = build_numpy_array_from_ufunc(py, &result)?;
    if keep && let Some(ax) = axis {
        let Some(ndim) = orig_ndim else {
            return fallback();
        };
        return keepdims_expand_axis(py, &numpy, output, ax as i64, ndim);
    }
    if result.shape().is_empty() {
        return Ok(output.bind(py).get_item(())?.unbind());
    }
    Ok(output)
}

