// Build numpy's reversed VIEW of `arr` by basic slicing: `slice(None, None, -1)`
// on each axis marked in `mask`, `slice(None)` elsewhere. This is exactly what
// numpy.flip/flipud/fliplr do internally — a stride flip, no data movement — so
// the result is bit-identical AND shares memory like numpy (the previous native
// path materialized a full copy, which was both ~25x slower and a behavior
// divergence). Dtype-agnostic: works for every dtype, not just 8-byte numerics.
fn build_flip_view<'py>(
    py: Python<'py>,
    arr: &Bound<'py, PyAny>,
    mask: &[bool],
) -> PyResult<Bound<'py, PyAny>> {
    let builtins = py.import("builtins")?;
    let slice_cls = builtins.getattr("slice")?;
    let full = slice_cls.call1((py.None(),))?; // slice(None) -> whole axis
    let rev = slice_cls.call1((py.None(), py.None(), -1i64))?; // slice(None, None, -1)
    let items: Vec<Bound<'py, PyAny>> = mask
        .iter()
        .map(|&flip| if flip { rev.clone() } else { full.clone() })
        .collect();
    arr.get_item(PyTuple::new(py, items)?)
}

#[pyfunction]
#[pyo3(signature = (m, axis=None))]
fn flip(py: Python<'_>, m: Py<PyAny>, axis: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    let m_for_fallback = m.clone_ref(py);
    let axis_for_fallback = axis.as_ref().map(|v| v.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let kwargs = PyDict::new(py);
        if let Some(ax) = &axis_for_fallback {
            kwargs.set_item("axis", ax.bind(py))?;
        }
        Ok(numpy
            .getattr("flip")?
            .call((m_for_fallback.bind(py),), Some(&kwargs))?
            .unbind())
    };

    let numpy = py.import("numpy")?;
    let arr = numpy.call_method1("asarray", (m.bind(py),))?;
    let ndim = arr.getattr("ndim")?.extract::<usize>()?;

    // Resolve the set of axes to reverse into a per-axis boolean mask. Any
    // out-of-range or repeated axis defers to numpy so its exact AxisError /
    // ValueError type and message are reproduced.
    let mut mask = vec![false; ndim];
    match axis {
        None => mask.iter_mut().for_each(|f| *f = true),
        Some(ax) => {
            let ax = ax.bind(py);
            if ax.is_none() {
                mask.iter_mut().for_each(|f| *f = true);
            } else if let Ok(single) = ax.extract::<isize>() {
                match try_normalize_axis(single, ndim) {
                    Some(n) => mask[n] = true,
                    None => return fallback(),
                }
            } else if let Ok(tuple) = ax.extract::<Vec<isize>>() {
                for a in tuple {
                    match try_normalize_axis(a, ndim) {
                        Some(n) if !mask[n] => mask[n] = true,
                        _ => return fallback(), // out-of-range or repeated axis
                    }
                }
            } else {
                return fallback();
            }
        }
    }
    Ok(build_flip_view(py, &arr, &mask)?.unbind())
}

#[pyfunction]
#[pyo3(signature = (m,))]
fn flipud(py: Python<'_>, m: Py<PyAny>) -> PyResult<Py<PyAny>> {
    // numpy.flipud(m) == m[::-1, ...] — a stride-flip view of axis 0 (requires
    // ndim >= 1, else numpy raises ValueError). Build the view directly.
    let numpy = py.import("numpy")?;
    let arr = numpy.call_method1("asarray", (m.bind(py),))?;
    let ndim = arr.getattr("ndim")?.extract::<usize>()?;
    if ndim < 1 {
        return Ok(numpy.getattr("flipud")?.call1((arr,))?.unbind());
    }
    let mut mask = vec![false; ndim];
    mask[0] = true;
    Ok(build_flip_view(py, &arr, &mask)?.unbind())
}

#[pyfunction]
#[pyo3(signature = (m,))]
fn fliplr(py: Python<'_>, m: Py<PyAny>) -> PyResult<Py<PyAny>> {
    // numpy.fliplr(m) == m[:, ::-1] — a stride-flip view of axis 1 (requires
    // ndim >= 2, else numpy raises ValueError). Build the view directly.
    let numpy = py.import("numpy")?;
    let arr = numpy.call_method1("asarray", (m.bind(py),))?;
    let ndim = arr.getattr("ndim")?.extract::<usize>()?;
    if ndim < 2 {
        return Ok(numpy.getattr("fliplr")?.call1((arr,))?.unbind());
    }
    let mut mask = vec![false; ndim];
    mask[1] = true;
    Ok(build_flip_view(py, &arr, &mask)?.unbind())
}

/// Which set operation a narrow-int bitmap kernel computes.
#[derive(Clone, Copy)]
enum NarrowSetOp {
    Intersect,
    Union,
    Setdiff,
    Setxor,
}

/// Presence-bitmap set operation over two native narrow-int slices.
///
/// numpy's set ops sort the ~2N concatenated values (O(N log N)); but a narrow
/// integer's whole value domain fits a tiny fixed bitmap (≤64 KiB), so we mark
/// presence in one O(N) pass per side and scan the domain in order — the output
/// is sorted-ascending and unique by construction, matching numpy's contract
/// with no sort at all. `to_idx` maps each native value to its `[0, size)`
/// bucket. Reading the inputs at their *native* width (i8/i16, not the f64 the
/// general extract path widens to) keeps memory traffic identical to numpy's,
/// so the missing sort is a pure win regardless of memory-bandwidth pressure.
fn narrow_bitmap_setop<T: Copy>(
    a: &[T],
    b: &[T],
    size: usize,
    min: i64,
    op: NarrowSetOp,
    dt: DType,
    to_i64: impl Fn(T) -> i64,
) -> Option<UFuncArray> {
    let mut pa = vec![false; size];
    let mut pb = vec![false; size];
    for &v in a {
        pa[(to_i64(v) - min) as usize] = true;
    }
    for &v in b {
        pb[(to_i64(v) - min) as usize] = true;
    }
    let mut out: Vec<f64> = Vec::new();
    for idx in 0..size {
        let take = match op {
            NarrowSetOp::Intersect => pa[idx] && pb[idx],
            NarrowSetOp::Union => pa[idx] || pb[idx],
            NarrowSetOp::Setdiff => pa[idx] && !pb[idx],
            NarrowSetOp::Setxor => pa[idx] ^ pb[idx],
        };
        if take {
            out.push((idx as i64 + min) as f64);
        }
    }
    let n = out.len();
    UFuncArray::new(vec![n], out, dt).ok()
}

/// Decide whether a *wide* integer set op (i32/u32/i64) should run the range
/// bitmap, returning `Some((lo, hi))` bounds when eligible. Uses numpy's C
/// min/max/len so the common DEFER case (range too wide for a direct table)
/// costs a few cheap reductions — NOT a full native-buffer read. Output is
/// rebuilt through an f64-valued UFuncArray, so values must be f64-exact
/// (|v| <= 2^53); wider i64 ids defer to the exact sidecar path.
fn wide_int_table_bounds(
    py: Python<'_>,
    af: &Bound<'_, PyAny>,
    bf: &Bound<'_, PyAny>,
) -> PyResult<Option<(i64, i64)>> {
    let _ = py;
    let na = af.len()?;
    let nb = bf.len()?;
    if na == 0 && nb == 0 {
        return Ok(Some((0, 0))); // both empty → trivially eligible (empty result)
    }
    let edge = |arr: &Bound<'_, PyAny>, n: usize, m: &str| -> PyResult<Option<i64>> {
        if n == 0 {
            Ok(None)
        } else {
            Ok(Some(arr.call_method0(m)?.extract::<i64>()?))
        }
    };
    let lo = [edge(af, na, "min")?, edge(bf, nb, "min")?]
        .into_iter()
        .flatten()
        .min()
        .unwrap();
    let hi = [edge(af, na, "max")?, edge(bf, nb, "max")?]
        .into_iter()
        .flatten()
        .max()
        .unwrap();
    const MAX_EXACT_F64: i64 = 1 << 53;
    if lo < -MAX_EXACT_F64 || hi > MAX_EXACT_F64 {
        return Ok(None);
    }
    let span = (hi as i128 - lo as i128 + 1) as u128;
    // Budget: 6x the input size (amortizes the table alloc+scan against the work),
    // floored at 1<<20 and hard-capped at 1<<28 entries to bound memory.
    let budget = (6u128).saturating_mul((na + nb) as u128).max(1 << 20);
    if span > budget || span > (1 << 28) {
        return Ok(None);
    }
    Ok(Some((lo, hi)))
}

/// True when both set-op inputs are floating point. The native float path
/// extract-widens (f16/f32 -> f64), sorts, then casts back — pure overhead on
/// top of numpy's own native float sort, so it loses 1.7-3.2x with no way to
/// win (a sort can at best tie). Delegating to numpy is exact parity, including
/// numpy's NaN/signed-zero set semantics. Checked via dtype.kind so it covers
/// f16/f32/f64 and mixed float widths (numpy promotes those itself).
fn setop_inputs_are_float(
    py: Python<'_>,
    ar1: &Bound<'_, PyAny>,
    ar2: &Bound<'_, PyAny>,
) -> PyResult<bool> {
    let numpy = py.import("numpy")?;
    let a = numpy.call_method1("asarray", (ar1,))?;
    let b = numpy.call_method1("asarray", (ar2,))?;
    let ak = a.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
    let bk = b.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
    Ok(ak == "f" && bk == "f")
}

/// Run a set op via the narrow-int presence bitmap when both inputs are the same
/// narrow integer dtype (i8/u8/i16/u16). Reads each side's native-width buffer
/// directly — bypassing the f64-widening extract — then builds the sorted-unique
/// result. Returns `Ok(None)` for any other dtype/mismatch so the caller keeps
/// its existing path. Bit-identical to numpy (pure integer membership).
fn try_narrow_int_setop_native(
    py: Python<'_>,
    ar1: &Bound<'_, PyAny>,
    ar2: &Bound<'_, PyAny>,
    op: NarrowSetOp,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let a = numpy.call_method1("asarray", (ar1,))?;
    let b = numpy.call_method1("asarray", (ar2,))?;
    let adt = a.getattr("dtype")?.str()?.extract::<String>()?;
    let bdt = b.getattr("dtype")?.str()?.extract::<String>()?;
    if adt != bdt {
        return Ok(None);
    }
    // Only same-dtype integer inputs are bitmap-eligible; bail early otherwise so
    // we don't pay the reshape/buffer read for floats/complex/strings.
    let parsed = DType::parse(&adt);
    if !matches!(
        parsed,
        Some(
            DType::I8
                | DType::U8
                | DType::I16
                | DType::U16
                | DType::I32
                | DType::U32
                | DType::I64
        )
    ) {
        return Ok(None);
    }
    let af = a.call_method1("reshape", (-1,))?;
    let bf = b.call_method1("reshape", (-1,))?;
    let result = match parsed {
        // Fixed-domain narrow ints: the whole value domain is a small constant
        // bitmap, no min/max scan needed.
        Some(DType::I8) => narrow_bitmap_setop(
            &numpy_cast_contiguous_to_vec::<i8>(py, &af, "int8")?,
            &numpy_cast_contiguous_to_vec::<i8>(py, &bf, "int8")?,
            256,
            -128,
            op,
            DType::I8,
            |x| x as i64,
        ),
        Some(DType::U8) => narrow_bitmap_setop(
            &numpy_cast_contiguous_to_vec::<u8>(py, &af, "uint8")?,
            &numpy_cast_contiguous_to_vec::<u8>(py, &bf, "uint8")?,
            256,
            0,
            op,
            DType::U8,
            |x| x as i64,
        ),
        Some(DType::I16) => narrow_bitmap_setop(
            &numpy_cast_contiguous_to_vec::<i16>(py, &af, "int16")?,
            &numpy_cast_contiguous_to_vec::<i16>(py, &bf, "int16")?,
            65536,
            -32768,
            op,
            DType::I16,
            |x| x as i64,
        ),
        Some(DType::U16) => narrow_bitmap_setop(
            &numpy_cast_contiguous_to_vec::<u16>(py, &af, "uint16")?,
            &numpy_cast_contiguous_to_vec::<u16>(py, &bf, "uint16")?,
            65536,
            0,
            op,
            DType::U16,
            |x| x as i64,
        ),
        // Wide ints: bitmap only when the actual value RANGE is small (a cheap
        // numpy min/max decides; defer otherwise WITHOUT reading the buffers).
        // i32/u32/i64 values are all lossless in i64.
        Some(DType::I32) => match wide_int_table_bounds(py, &af, &bf)? {
            Some((lo, hi)) => narrow_bitmap_setop(
                &numpy_cast_contiguous_to_vec::<i32>(py, &af, "int32")?,
                &numpy_cast_contiguous_to_vec::<i32>(py, &bf, "int32")?,
                (hi - lo + 1) as usize,
                lo,
                op,
                DType::I32,
                |x| x as i64,
            ),
            None => return Ok(None),
        },
        Some(DType::U32) => match wide_int_table_bounds(py, &af, &bf)? {
            Some((lo, hi)) => narrow_bitmap_setop(
                &numpy_cast_contiguous_to_vec::<u32>(py, &af, "uint32")?,
                &numpy_cast_contiguous_to_vec::<u32>(py, &bf, "uint32")?,
                (hi - lo + 1) as usize,
                lo,
                op,
                DType::U32,
                |x| x as i64,
            ),
            None => return Ok(None),
        },
        Some(DType::I64) => match wide_int_table_bounds(py, &af, &bf)? {
            Some((lo, hi)) => narrow_bitmap_setop(
                &numpy_cast_contiguous_to_vec::<i64>(py, &af, "int64")?,
                &numpy_cast_contiguous_to_vec::<i64>(py, &bf, "int64")?,
                (hi - lo + 1) as usize,
                lo,
                op,
                DType::I64,
                |x| x,
            ),
            None => return Ok(None),
        },
        _ => return Ok(None),
    };
    match result {
        Some(arr) => Ok(Some(build_numpy_array_from_ufunc(py, &arr)?)),
        None => Ok(None),
    }
}

#[pyfunction]
#[pyo3(signature = (ar1, ar2, assume_unique=false, return_indices=false))]
fn intersect1d(
    py: Python<'_>,
    ar1: Py<PyAny>,
    ar2: Py<PyAny>,
    assume_unique: bool,
    return_indices: bool,
) -> PyResult<Py<PyAny>> {
    // Native intersect1d via UFuncArray::intersect1d for matched-dtype
    // real numeric inputs with assume_unique=false and
    // return_indices=false. Falls back to np.intersect1d when either
    // kwarg is non-default (those paths have order-preserving and
    // tuple-return semantics left to numpy) and for complex /
    // integer-sidecar / mixed-dtype inputs so numpy's dispatch surface
    // stays exact.
    let numpy = py.import("numpy")?;
    let intersect1d_fn = numpy.getattr("intersect1d")?;
    let ar1_for_fallback = ar1.clone_ref(py);
    let ar2_for_fallback = ar2.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        kwargs.set_item("assume_unique", assume_unique)?;
        kwargs.set_item("return_indices", return_indices)?;
        Ok(intersect1d_fn
            .call(
                (ar1_for_fallback.bind(py), ar2_for_fallback.bind(py)),
                Some(&kwargs),
            )?
            .unbind())
    };
    if assume_unique || return_indices {
        return fallback();
    }
    if let Some(r) =
        try_narrow_int_setop_native(py, ar1.bind(py), ar2.bind(py), NarrowSetOp::Intersect)?
    {
        return Ok(r);
    }
    if setop_inputs_are_float(py, ar1.bind(py), ar2.bind(py))? {
        return fallback();
    }
    let a = match extract_precise_numeric_array(py, ar1.bind(py), "intersect1d(ar1)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let b = match extract_precise_numeric_array(py, ar2.bind(py), "intersect1d(ar2)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    if a.has_integer_sidecar()
        || b.has_integer_sidecar()
        || matches!(a.dtype(), DType::Complex64 | DType::Complex128)
        || matches!(b.dtype(), DType::Complex64 | DType::Complex128)
        || a.dtype() != b.dtype()
    {
        return fallback();
    }
    let result = a.intersect1d(&b);
    build_numpy_array_from_ufunc(py, &result)
}

#[pyfunction]
#[pyo3(signature = (ar1, ar2))]
fn union1d(py: Python<'_>, ar1: Py<PyAny>, ar2: Py<PyAny>) -> PyResult<Py<PyAny>> {
    // Native union1d via UFuncArray::union1d — returns the sorted-unique
    // union of the two flattened inputs. Falls back to np.union1d for
    // complex/structured/string inputs and for dtype mixes that would
    // require numpy's coercion rules (e.g. int64 ∪ float64 → float64).
    let numpy = py.import("numpy")?;
    let union1d_fn = numpy.getattr("union1d")?;
    let ar1_for_fallback = ar1.clone_ref(py);
    let ar2_for_fallback = ar2.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        Ok(union1d_fn
            .call1((ar1_for_fallback.bind(py), ar2_for_fallback.bind(py)))?
            .unbind())
    };
    if let Some(r) =
        try_narrow_int_setop_native(py, ar1.bind(py), ar2.bind(py), NarrowSetOp::Union)?
    {
        return Ok(r);
    }
    if setop_inputs_are_float(py, ar1.bind(py), ar2.bind(py))? {
        return fallback();
    }
    let a = match extract_precise_numeric_array(py, ar1.bind(py), "union1d(ar1)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let b = match extract_precise_numeric_array(py, ar2.bind(py), "union1d(ar2)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    if a.has_integer_sidecar()
        || b.has_integer_sidecar()
        || matches!(a.dtype(), DType::Complex64 | DType::Complex128)
        || matches!(b.dtype(), DType::Complex64 | DType::Complex128)
        || a.dtype() != b.dtype()
    {
        return fallback();
    }
    let result = a.union1d(&b);
    build_numpy_array_from_ufunc(py, &result)
}

