#[pyfunction]
#[pyo3(signature = (element, test_elements, assume_unique=false, invert=false, kind=None))]
fn isin(
    py: Python<'_>,
    element: Py<PyAny>,
    test_elements: Py<PyAny>,
    assume_unique: bool,
    invert: bool,
    kind: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    // Native isin via UFuncArray::isin for matched-dtype real numeric
    // inputs with assume_unique=false and kind=None. Falls back to numpy
    // for complex / integer-sidecar / mixed-dtype inputs and for the
    // tuned assume_unique / kind="table"/"sort" back-ends so their
    // semantics match numpy exactly.
    let numpy = py.import("numpy")?;
    let isin_fn = numpy.getattr("isin")?;
    let element_for_fallback = element.clone_ref(py);
    let test_for_fallback = test_elements.clone_ref(py);
    let kind_for_fallback = kind.as_ref().map(|v| v.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        kwargs.set_item("assume_unique", assume_unique)?;
        kwargs.set_item("invert", invert)?;
        if let Some(kind_val) = kind_for_fallback.as_ref() {
            kwargs.set_item("kind", kind_val.bind(py))?;
        }
        Ok(isin_fn
            .call(
                (element_for_fallback.bind(py), test_for_fallback.bind(py)),
                Some(&kwargs),
            )?
            .unbind())
    };
    if assume_unique || kind.as_ref().is_some_and(|v| !v.bind(py).is_none()) {
        return fallback();
    }
    // Fast hashed-set membership for matched integer dtypes — runs BEFORE the cold
    // extract→UFuncArray path (~25x slower) so common id-membership skips it.
    if let Some(out) = try_zerocopy_int_isin(py, element.bind(py), test_elements.bind(py), invert)? {
        return Ok(out);
    }
    let ar1 = match extract_precise_numeric_array(py, element.bind(py), "isin(element)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let ar2 = match extract_precise_numeric_array(py, test_elements.bind(py), "isin(test_elements)")
    {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    if ar1.has_integer_sidecar()
        || ar2.has_integer_sidecar()
        || matches!(ar1.dtype(), DType::Complex64 | DType::Complex128)
        || matches!(ar2.dtype(), DType::Complex64 | DType::Complex128)
        || ar1.dtype() != ar2.dtype()
    {
        return fallback();
    }
    let result = ar1.isin(&ar2, invert);
    build_numpy_array_from_ufunc(py, &result)
}

// np.in1d is the 1-D form of np.isin: it FLATTENS ar1 and always returns a 1-D
// boolean array of length ar1.size (True where the element is in ar2). It is
// deprecated since NumPy 2.0 (isin is the generalization) but remains in
// numpy.__all__, so fnp must expose it for full-surface coverage. Route it
// through our native isin on a raveled ar1: isin preserves the operand shape, so
// a 1-D input yields the exact 1-D in1d result while reusing isin's fast paths.
#[pyfunction]
#[pyo3(signature = (ar1, ar2, assume_unique=false, invert=false, kind=None))]
fn in1d(
    py: Python<'_>,
    ar1: Py<PyAny>,
    ar2: Py<PyAny>,
    assume_unique: bool,
    invert: bool,
    kind: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let ar1_flat = numpy
        .getattr("asarray")?
        .call1((ar1.bind(py),))?
        .call_method0("ravel")?
        .unbind();
    isin(py, ar1_flat, ar2, assume_unique, invert, kind)
}

// A fast multiply-shift hasher for integer keys: std's default SipHash is far too
// slow for the millions of single-int lookups np.isin performs. For a single
// integer key Rust calls write_u64/write_i64 (etc.) exactly once, so a Fibonacci
// multiply on that word is a high-quality, ~1-cycle hash. (write() is implemented
// for completeness but is never on the hot integer path.)
#[derive(Default)]
struct FastIntHasher(u64);
impl core::hash::Hasher for FastIntHasher {
    fn finish(&self) -> u64 {
        self.0
    }
    fn write(&mut self, bytes: &[u8]) {
        let mut h = self.0;
        for &b in bytes {
            h = (h ^ b as u64).wrapping_mul(0x0000_0100_0000_01b3);
        }
        self.0 = h;
    }
    fn write_u8(&mut self, i: u8) {
        self.write_u64(i as u64);
    }
    fn write_u16(&mut self, i: u16) {
        self.write_u64(i as u64);
    }
    fn write_u32(&mut self, i: u32) {
        self.write_u64(i as u64);
    }
    fn write_u64(&mut self, i: u64) {
        self.0 = i.wrapping_mul(0x9E37_79B9_7F4A_7C15);
    }
    fn write_usize(&mut self, i: usize) {
        self.write_u64(i as u64);
    }
    fn write_i8(&mut self, i: i8) {
        self.write_u64(i as u64);
    }
    fn write_i16(&mut self, i: i16) {
        self.write_u64(i as u64);
    }
    fn write_i32(&mut self, i: i32) {
        self.write_u64(i as u64);
    }
    fn write_i64(&mut self, i: i64) {
        self.write_u64(i as u64);
    }
}
#[derive(Default, Clone)]
struct FastIntBuildHasher;
impl core::hash::BuildHasher for FastIntBuildHasher {
    type Hasher = FastIntHasher;
    fn build_hasher(&self) -> FastIntHasher {
        FastIntHasher(0)
    }
}

// Membership core for np.isin over a matched integer dtype. Builds a fast-hashed
// set of the test values (O(m)) then maps every element to a bool (O(n)) — an
// O(n+m) replacement for the cold extract→UFuncArray path (~25x slower). Integer
// bit-equality IS value-equality (no NaN/-0.0 hazards), so this is bit-exact.
// Result is XORed with `invert` to honour numpy's invert kwarg. Returns None if a
// buffer is non-contiguous (as_slice fails) so the caller defers to numpy.
// Lossless widening of every fixed-width integer key to i128 so isin can index a
// dense membership TABLE by `value - min`. i128 holds the full i64/u64 range.
trait IntKey: Copy + Ord {
    fn to_i128(self) -> i128;
}
macro_rules! impl_intkey {
    ($($t:ty),*) => { $(impl IntKey for $t { #[inline] fn to_i128(self) -> i128 { self as i128 } })* };
}
impl_intkey!(i8, i16, i32, i64, u8, u16, u32, u64);

fn isin_typed<'py, T: pyo3::buffer::Element + Copy + core::hash::Hash + Eq + IntKey>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    element: &Bound<'py, PyAny>,
    test: &Bound<'py, PyAny>,
) -> PyResult<Option<Bound<'py, PyAny>>> {
    let (Ok(e_buf), Ok(t_buf)) = (PyBuffer::<T>::get(element), PyBuffer::<T>::get(test)) else {
        return Ok(None);
    };
    let (Some(e_s), Some(t_s)) = (e_buf.as_slice(py), t_buf.as_slice(py)) else {
        return Ok(None);
    };
    let n = e_s.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "uint8")?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n == 0 {
        return Ok(Some(flat.call_method1("view", (numpy.getattr("bool_")?,))?));
    }
    let Ok(o_buf) = PyBuffer::<u8>::get(&flat) else {
        return Ok(None);
    };
    let Some(output) = o_buf.as_mut_slice(py) else {
        return Ok(None);
    };

    // Dense-table membership when the test value range is small relative to the
    // work — numpy's own 'table' heuristic. A bool[range] keyed by `v - min` is a
    // single direct-indexed load per element (no hashing, cache-friendly), ~3x the
    // hash set on integer id-membership. Same exact membership → bit-identical
    // result. Range too wide (sparse keys / would-be huge table) falls to the hash
    // set, which is range-independent.
    let table_built = if !t_s.is_empty() {
        let mut lo = t_s[0].get().to_i128();
        let mut hi = lo;
        for c in t_s.iter() {
            let v = c.get().to_i128();
            if v < lo {
                lo = v;
            }
            if v > hi {
                hi = v;
            }
        }
        let span = (hi - lo) as u128 + 1; // fits: i128 diff of two ints is < 2^65
        let budget = (6u128).saturating_mul((e_s.len() + t_s.len()) as u128);
        if span <= budget.max(1 << 20) && span <= (1 << 31) {
            let mut table = vec![false; span as usize];
            for c in t_s.iter() {
                table[(c.get().to_i128() - lo) as usize] = true;
            }
            for (o, c) in output.iter().zip(e_s.iter()) {
                let v = c.get().to_i128();
                let hit = v >= lo && v <= hi && table[(v - lo) as usize];
                o.set(hit as u8);
            }
            true
        } else {
            false
        }
    } else {
        // Empty test set: nothing is a member.
        for o in output.iter() {
            o.set(0);
        }
        true
    };
    if !table_built {
        let mut set: std::collections::HashSet<T, FastIntBuildHasher> =
            std::collections::HashSet::with_capacity_and_hasher(t_s.len(), FastIntBuildHasher);
        for c in t_s.iter() {
            set.insert(c.get());
        }
        for (o, c) in output.iter().zip(e_s.iter()) {
            o.set(set.contains(&c.get()) as u8);
        }
    }
    Ok(Some(flat.call_method1("view", (numpy.getattr("bool_")?,))?))
}

// Zero-copy np.isin for matched integer dtypes (the common id-membership case),
// dispatched by (kind, itemsize). Gated to: both ndarrays, identical integer
// dtype (numpy would otherwise promote — defer for exact semantics), default
// assume_unique/kind (handled by the caller). Output is a bool array of
// element.shape. Floats/complex/mixed keep the existing path.
fn try_zerocopy_int_isin(
    py: Python<'_>,
    element: &Bound<'_, PyAny>,
    test: &Bound<'_, PyAny>,
    invert: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !element.is_exact_instance(&ndarray_type) || !test.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let e_dtype = element.getattr("dtype")?;
    let t_dtype = test.getattr("dtype")?;
    if !e_dtype.eq(&t_dtype)? {
        return Ok(None); // differing dtypes → numpy promotes; defer for exact semantics
    }
    let kind = e_dtype.getattr("kind")?.extract::<String>()?;
    let itemsize = e_dtype.getattr("itemsize")?.extract::<usize>()?;
    let flat = match (kind.as_str(), itemsize) {
        ("i", 1) => isin_typed::<i8>(py, &numpy, element, test)?,
        ("i", 2) => isin_typed::<i16>(py, &numpy, element, test)?,
        ("i", 4) => isin_typed::<i32>(py, &numpy, element, test)?,
        ("i", 8) => isin_typed::<i64>(py, &numpy, element, test)?,
        ("u", 1) => isin_typed::<u8>(py, &numpy, element, test)?,
        ("u", 2) => isin_typed::<u16>(py, &numpy, element, test)?,
        ("u", 4) => isin_typed::<u32>(py, &numpy, element, test)?,
        ("u", 8) => isin_typed::<u64>(py, &numpy, element, test)?,
        _ => return Ok(None),
    };
    let Some(flat) = flat else {
        return Ok(None);
    };
    // numpy invert flips membership; XOR after the set lookups keeps it branch-light.
    let result = if invert {
        numpy.call_method1("logical_not", (&flat,))?
    } else {
        flat
    };
    let shape: Vec<usize> = element.getattr("shape")?.extract()?;
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    Ok(Some(
        result.call_method1("reshape", (&output_shape,))?.unbind(),
    ))
}

// Native np.vander for an f64 C-contiguous 1-D x. numpy builds the Vandermonde matrix via
// `tmp[:,1:] = x[:,None]; multiply.accumulate(tmp, axis=1)` — a broadcast temp + a strided
// in-place cumulative product, ~7 ms even for a tiny 200k x 8 output. This per-row fused
// cumulative product writes each (len(x), N) row directly with no temp, parallel across
// rows. Bit-exact: the powers are the SAME left-to-right cumulative product numpy's
// accumulate performs (1, x, x*x, x^2*x, ...); `increasing=False` only stores that
// sequence into reversed column positions (the multiplications are identical). f64
// C-contiguous 1-D x only (numpy preserves int64 for int input -> defer); N==0 / empty x
// defer.
fn try_zerocopy_f64_vander(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    x: &Bound<'_, PyAny>,
    n: Option<usize>,
    increasing: bool,
) -> PyResult<Option<Py<PyAny>>> {
    if !x.is_exact_instance(&numpy.getattr("ndarray")?) {
        return Ok(None);
    }
    let xdt = x.getattr("dtype")?;
    if xdt.getattr("kind")?.extract::<String>()? != "f"
        || xdt.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(x) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() || in_buffer.shape().len() != 1 {
        return Ok(None); // numpy.vander requires 1-D x
    }
    let rows = in_buffer.shape()[0];
    let cols = n.unwrap_or(rows);
    if rows == 0 || cols == 0 {
        return Ok(None); // empty output: defer for numpy's exact (rows, cols) shape
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only under the GIL.
    let data: &[f64] = unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), rows) };
    let total = rows * cols;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let out = numpy.call_method("empty", (total,), Some(&kwargs))?;
    {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&out) else {
            return Ok(None);
        };
        let Some(out_cells) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // SAFETY: freshly allocated numpy.empty output, cannot alias x; each slot written once.
        let o: &mut [f64] =
            unsafe { std::slice::from_raw_parts_mut(out_cells.as_ptr() as *mut f64, total) };
        // Fill one output row (length `cols`) from x value xv: left-to-right cumulative
        // product 1, xv, xv*xv, ... stored increasing (col j = xv^j) or reversed
        // (col j = xv^(cols-1-j)) — same multiplications either way.
        let fill_row = |xv: f64, row: &mut [f64]| {
            let mut pw = 1.0f64;
            if increasing {
                for slot in row.iter_mut() {
                    *slot = pw;
                    pw *= xv;
                }
            } else {
                for slot in row.iter_mut().rev() {
                    *slot = pw;
                    pw *= xv;
                }
            }
        };
        use rayon::prelude::*;
        const VANDER_PARALLEL_MIN: usize = 1 << 16;
        let parallel = total >= VANDER_PARALLEL_MIN && rayon::current_num_threads() >= 2;
        if parallel {
            o.par_chunks_mut(cols)
                .zip(data.par_iter())
                .for_each(|(row, &xv)| fill_row(xv, row));
        } else {
            o.chunks_mut(cols)
                .zip(data.iter())
                .for_each(|(row, &xv)| fill_row(xv, row));
        }
    }
    let reshaped = out.call_method1("reshape", ((rows, cols),))?;
    Ok(Some(reshaped.unbind()))
}

#[pyfunction]
#[pyo3(signature = (x, N=None, increasing=false))]
#[allow(non_snake_case)]
fn vander(py: Python<'_>, x: Py<PyAny>, N: Option<usize>, increasing: bool) -> PyResult<Py<PyAny>> {
    // Native fused cumulative-product path for f64 1-D x; numpy's broadcast +
    // multiply.accumulate is far slower. Other dtypes/shapes fall through so width
    // selection, increasing-order columns, int64 dtype preservation, and 1-D
    // input validation all match numpy exactly.
    let numpy = py.import("numpy")?;
    if let Some(out) = try_zerocopy_f64_vander(py, &numpy, x.bind(py), N, increasing)? {
        return Ok(out);
    }
    let vander_fn = numpy.getattr("vander")?;
    let kwargs = PyDict::new(py);
    if let Some(width) = N {
        kwargs.set_item("N", width)?;
    }
    kwargs.set_item("increasing", increasing)?;
    Ok(vander_fn.call((x.bind(py),), Some(&kwargs))?.unbind())
}

#[pyfunction]
#[pyo3(signature = (*args, dtype=None, device=None, like=None))]
fn arange(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    dtype: Option<Py<PyAny>>,
    device: Option<Py<PyAny>>,
    like: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    // Always passthrough to NumPy - our Rust→NumPy export is slower.
    // See zeros() comment and perf bead franken_numpy-yx2wt.
    let numpy = py.import("numpy")?;
    let arange_fn = numpy.getattr("arange")?;
    let kwargs = PyDict::new(py);
    if let Some(dtype_val) = dtype.as_ref() {
        kwargs.set_item("dtype", dtype_val.bind(py))?;
    }
    if let Some(device_val) = device.as_ref() {
        kwargs.set_item("device", device_val.bind(py))?;
    }
    if let Some(like_val) = like.as_ref() {
        kwargs.set_item("like", like_val.bind(py))?;
    }
    Ok(arange_fn.call(args, Some(&kwargs))?.unbind())
}

#[pyfunction]
#[pyo3(signature = (start, stop, num=50, endpoint=true, retstep=false, dtype=None, axis=0, *, device=None))]
#[allow(clippy::too_many_arguments)]
fn linspace(
    py: Python<'_>,
    start: Py<PyAny>,
    stop: Py<PyAny>,
    num: isize,
    endpoint: bool,
    retstep: bool,
    dtype: Option<Py<PyAny>>,
    axis: isize,
    device: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let linspace_fn = numpy.getattr("linspace")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("num", num)?;
        kwargs.set_item("endpoint", endpoint)?;
        kwargs.set_item("retstep", retstep)?;
        if let Some(dtype_val) = dtype.as_ref() {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        kwargs.set_item("axis", axis)?;
        if let Some(device_val) = device.as_ref() {
            kwargs.set_item("device", device_val.bind(py))?;
        }
        Ok(linspace_fn
            .call((start.bind(py), stop.bind(py)), Some(&kwargs))?
            .unbind())
    };
    if device
        .as_ref()
        .is_some_and(|value| !value.bind(py).is_none())
    {
        return fallback(py);
    }
    if num < 0 {
        return fallback(py);
    }
    let Ok(start_f) = start.bind(py).extract::<f64>() else {
        return fallback(py);
    };
    let Ok(stop_f) = stop.bind(py).extract::<f64>() else {
        return fallback(py);
    };
    let resolved_dtype = match dtype.as_ref() {
        Some(dtype_val) if !dtype_val.bind(py).is_none() => {
            let parsed = numpy.getattr("dtype")?.call1((dtype_val.bind(py),))?;
            let name = parsed.getattr("name")?.extract::<String>()?;
            match DType::parse(&name) {
                // Only float64 stays native. float32/float16 used to run the f64
                // build then convert across the export bridge (~13x slower than
                // numpy's typed linspace); delegate them to numpy (the exact oracle).
                Some(DType::F64) => DType::F64,
                _ => return fallback(py),
            }
        }
        _ => DType::F64,
    };

    let num_usize = num as usize;
    // The native f64 build is bit-identical to numpy but ~7-11x slower at scale: it
    // fills an owned Vec then copies it across the export bridge, vs numpy's direct
    // SIMD fill into the output buffer. Delegate large arrays (bit-exact); keep the
    // native path for small n where numpy's per-call dispatch overhead loses
    // (n=1000 is ~2.7x faster native).
    if num_usize >= (1 << 16) {
        return fallback(py);
    }
    if retstep {
        let (array, step) = match UFuncArray::linspace_retstep(
            start_f,
            stop_f,
            num_usize,
            endpoint,
            resolved_dtype,
        ) {
            Ok(value) => value,
            Err(_) => return fallback(py),
        };
        let array_py = build_numpy_array_from_ufunc(py, &array)?;
        let step_py = numpy
            .getattr(match resolved_dtype {
                DType::F16 => "float16",
                DType::F32 => "float32",
                _ => "float64",
            })?
            .call1((step,))?;
        let tuple = PyTuple::new(py, [array_py.bind(py), &step_py])?;
        return Ok(tuple.into_any().unbind());
    }

    let result =
        match UFuncArray::linspace_endpoint(start_f, stop_f, num_usize, endpoint, resolved_dtype) {
            Ok(value) => value,
            Err(_) => return fallback(py),
        };
    build_numpy_array_from_ufunc(py, &result)
}

#[pyfunction]
#[pyo3(signature = (start, stop, num=50, endpoint=true, dtype=None, axis=0))]
fn geomspace(
    py: Python<'_>,
    start: Py<PyAny>,
    stop: Py<PyAny>,
    num: isize,
    endpoint: bool,
    dtype: Option<Py<PyAny>>,
    axis: isize,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let geomspace_fn = numpy.getattr("geomspace")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("num", num)?;
        kwargs.set_item("endpoint", endpoint)?;
        if let Some(dtype_val) = dtype.as_ref() {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        kwargs.set_item("axis", axis)?;
        Ok(geomspace_fn
            .call((start.bind(py), stop.bind(py)), Some(&kwargs))?
            .unbind())
    };

    if axis != 0 || num < 0 {
        return fallback(py);
    }

    let Ok(start_f) = start.bind(py).extract::<f64>() else {
        return fallback(py);
    };
    let Ok(stop_f) = stop.bind(py).extract::<f64>() else {
        return fallback(py);
    };
    if !start_f.is_finite() || !stop_f.is_finite() || start_f <= 0.0 || stop_f <= 0.0 {
        return fallback(py);
    }
    if dtype
        .as_ref()
        .is_some_and(|dtype_val| !dtype_val.bind(py).is_none())
    {
        return fallback(py);
    }

    let result =
        match UFuncArray::geomspace_endpoint(start_f, stop_f, num as usize, endpoint, DType::F64) {
            Ok(value) => value,
            Err(_) => return fallback(py),
        };
    build_numpy_array_from_ufunc(py, &result)
}

#[pyfunction]
#[pyo3(signature = (shape, fill_value, dtype=None, order="C", *, device=None, like=None))]
fn full(
    py: Python<'_>,
    shape: Py<PyAny>,
    fill_value: Py<PyAny>,
    dtype: Option<Py<PyAny>>,
    order: &str,
    device: Option<Py<PyAny>>,
    like: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let full_fn = numpy.getattr("full")?;
        let kwargs = PyDict::new(py);
        if let Some(dtype_val) = dtype.as_ref() {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        kwargs.set_item("order", order)?;
        if let Some(device_val) = device.as_ref() {
            kwargs.set_item("device", device_val.bind(py))?;
        }
        if let Some(like_val) = like.as_ref() {
            kwargs.set_item("like", like_val.bind(py))?;
        }
        Ok(full_fn
            .call((shape.bind(py), fill_value.bind(py)), Some(&kwargs))?
            .unbind())
    };

    if device
        .as_ref()
        .is_some_and(|value| !value.bind(py).is_none())
        || like.as_ref().is_some_and(|value| !value.bind(py).is_none())
    {
        return fallback(py);
    }
    if !matches!(order, "C" | "K") {
        return fallback(py);
    }

    // np.full is a pure typed MEMSET (np.empty + fill). The old native path built an
    // f64 UFuncArray then converted it element-wise through the export bridge, which
    // is catastrophic for non-f64 results: full(4M, int8) was ~1200x slower than
    // numpy, float32/int32 150-250x, even float64 ~19x. numpy's fill is a C-level
    // memset that cannot be beaten in safe Rust without unsafe (and it handles the
    // exact dtype inference / scalar cast / OverflowError surface), so delegate.
    fallback(py)
}

fn parse_shape_override(shape: &Bound<'_, PyAny>, context: &str) -> PyResult<Vec<usize>> {
    if let Ok(dims) = shape.extract::<Vec<i64>>() {
        dims.into_iter()
            .map(|dim| {
                if dim < 0 {
                    Err(PyValueError::new_err(format!(
                        "{context}: negative dimensions are not allowed"
                    )))
                } else {
                    Ok(dim as usize)
                }
            })
            .collect()
    } else if let Ok(dim) = shape.extract::<i64>() {
        if dim < 0 {
            Err(PyValueError::new_err(format!(
                "{context}: negative dimensions are not allowed"
            )))
        } else {
            Ok(vec![dim as usize])
        }
    } else {
        Err(PyTypeError::new_err(format!(
            "{context}: shape must be an int or tuple of ints"
        )))
    }
}

#[allow(dead_code)]
enum LikeFill<'py> {
    Zeros,
    Ones,
    Empty,
    Full(&'py Bound<'py, PyAny>),
}

// Native creation of *_like outputs for the common numeric dtypes. Returns
// Ok(None) whenever a parameter combination (F-contiguous multi-D input with
// default order='K', unsupported dtypes, subclass preservation via subok, or
// explicit device targets) cannot be matched by the native UFuncArray path;
// callers fall back to numpy in that case so the full numpy surface is still
// exercised. Shape and dtype inheritance, dtype overrides, shape overrides,
// and zero-sized inputs are handled natively.
//
// NOTE: currently unused — the *_like callers delegate to numpy because this
// UFuncArray-build-then-convert path was catastrophically slow (empty_like ~240000x,
// zeros/ones_like ~90x for narrow ints). Retained for a future fast native rewrite
// (np.empty/zeros/ones/full of the resolved dtype directly, no UFuncArray).
#[allow(dead_code)]
#[allow(clippy::too_many_arguments)]
fn native_like_array(
    py: Python<'_>,
    source: &Bound<'_, PyAny>,
    dtype: Option<&Bound<'_, PyAny>>,
    order: &str,
    subok: bool,
    shape: Option<&Bound<'_, PyAny>>,
    device: Option<&Bound<'_, PyAny>>,
    fill: &LikeFill<'_>,
    context: &str,
) -> PyResult<Option<Py<PyAny>>> {
    if device.is_some_and(|value| !value.is_none()) {
        return Ok(None);
    }
    if !matches!(order, "K" | "C") {
        return Ok(None);
    }

    let numpy = py.import("numpy")?;
    let source_array = numpy.call_method1("asanyarray", (source,))?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if subok && !source_array.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let source_shape: Vec<usize> = source_array.getattr("shape")?.extract()?;

    let target_dtype = match dtype {
        Some(dtype_val) if !dtype_val.is_none() => {
            let parsed = numpy.getattr("dtype")?.call1((dtype_val,))?;
            let name = parsed.getattr("name")?.extract::<String>()?;
            match DType::parse(&name) {
                Some(value) if dtype_supported_by_numpy_export_bridge(value) => value,
                _ => return Ok(None),
            }
        }
        _ => {
            let source_dtype_name = source_array
                .getattr("dtype")?
                .getattr("name")?
                .extract::<String>()?;
            match DType::parse(&source_dtype_name) {
                Some(value) if dtype_supported_by_numpy_export_bridge(value) => value,
                _ => return Ok(None),
            }
        }
    };

    let shape_overridden = shape.is_some_and(|value| !value.is_none());
    let target_shape = if shape_overridden {
        parse_shape_override(shape.expect("checked above"), context)?
    } else {
        source_shape.clone()
    };

    // With order='K' and no shape override, numpy preserves the input's
    // memory layout. For multi-D F-contiguous inputs that means we need
    // to emit an F-contiguous output via the fortran export bridge.
    let mut emit_fortran = false;
    if order == "K" && !shape_overridden && source_shape.len() >= 2 {
        let flags = source_array.getattr("flags")?;
        let f_contig: bool = flags.get_item("F_CONTIGUOUS")?.extract()?;
        let c_contig: bool = flags.get_item("C_CONTIGUOUS")?.extract()?;
        if f_contig && !c_contig {
            emit_fortran = true;
        }
    }

    let result = match fill {
        LikeFill::Zeros | LikeFill::Empty => match UFuncArray::zeros(target_shape, target_dtype) {
            Ok(value) => value,
            Err(_) => return Ok(None),
        },
        LikeFill::Ones => match UFuncArray::ones(target_shape, target_dtype) {
            Ok(value) => value,
            Err(_) => return Ok(None),
        },
        LikeFill::Full(value) => {
            let fill_scalar = match value.extract::<f64>() {
                Ok(scalar) if scalar.is_finite() => scalar,
                Ok(scalar) => scalar,
                Err(_) => return Ok(None),
            };
            match UFuncArray::full(target_shape, fill_scalar, target_dtype) {
                Ok(value) => value,
                Err(_) => return Ok(None),
            }
        }
    };

    let output = if emit_fortran {
        build_numpy_array_from_ufunc_fortran(py, &result)?
    } else {
        build_numpy_array_from_ufunc(py, &result)?
    };
    Ok(Some(output))
}

#[pyfunction]
#[pyo3(signature = (a, fill_value, dtype=None, order="K", subok=true, shape=None, *, device=None))]
#[allow(clippy::too_many_arguments)]
fn full_like(
    py: Python<'_>,
    a: Py<PyAny>,
    fill_value: Py<PyAny>,
    dtype: Option<Py<PyAny>>,
    order: &str,
    subok: bool,
    shape: Option<Py<PyAny>>,
    device: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let a_bound = a.bind(py);
    let fill_bound = fill_value.bind(py);
    let dtype_bound = dtype.as_ref().map(|value| value.bind(py));
    let shape_bound = shape.as_ref().map(|value| value.bind(py));
    let device_bound = device.as_ref().map(|value| value.bind(py));
    // np.full_like is np.empty_like + a typed MEMSET fill. The native_like_array
    // path built an f64 UFuncArray then converted it element-wise through the export
    // bridge — catastrophic for non-f64 (full_like(4M, int8) was ~1300x slower than
    // numpy, float32 ~200x). numpy's fill is an unbeatable C-level memset that also
    // owns the exact dtype/cast surface, so delegate (zeros_like/ones_like keep the
    // native path — calloc/memset of 0/1 is already fast there).
    let numpy = py.import("numpy")?;
    let full_like_fn = numpy.getattr("full_like")?;
    let kwargs = PyDict::new(py);
    if let Some(dtype_val) = dtype_bound {
        kwargs.set_item("dtype", dtype_val)?;
    }
    kwargs.set_item("order", order)?;
    kwargs.set_item("subok", subok)?;
    if let Some(shape_val) = shape_bound {
        kwargs.set_item("shape", shape_val)?;
    }
    if let Some(device_val) = device_bound {
        kwargs.set_item("device", device_val)?;
    }
    Ok(full_like_fn
        .call((a_bound, fill_bound), Some(&kwargs))?
        .unbind())
}

