// Shared native fast-path for simple unary ufuncs that map 1:1 onto a
// UFuncArray::elementwise_unary kernel. numeric_unary_fallback closes over
// the numpy attribute name to delegate to on complex / object / sidecar
// inputs so the dispatch surface stays exact.
fn native_unary_elementwise(
    py: Python<'_>,
    x: &Bound<'_, PyAny>,
    op: UnaryOp,
    numpy_name: &str,
    context: &str,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |_py: Python<'_>| -> PyResult<Py<PyAny>> {
        Ok(numpy.getattr(numpy_name)?.call1((x,))?.unbind())
    };
    // float16: numpy's f16 unary ufuncs (computed via an f16<->f32 path) are the
    // reference and are far faster than fnp's native f16 round-trip (no f16 PyBuffer
    // Element, so the value Vec is rebuilt through the dtype bridge — ~80ms vs numpy's
    // <1ms for a 4M abs). numpy is bit-identical for these element ops, so defer f16.
    if numpy_dtype_is_f16(x) {
        return fallback(py);
    }
    // Zero-copy fast path: exact float64 C-contiguous ndarray inputs skip the
    // cold extract Vec entirely (see zerocopy_f64_unary_flat). Bit-identical to
    // the direct output path below; all other inputs fall through unchanged.
    if let Some((flat, shape)) = zerocopy_f64_unary_flat(py, &numpy, x, op)? {
        let output_shape = PyTuple::new(py, shape.iter().copied())?;
        let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
        if shape.is_empty() {
            return Ok(output.bind(py).get_item(())?.unbind());
        }
        return Ok(output);
    }
    // int64 zero-copy fast path (negative/positive/abs/square). Without it int64
    // input ran the cold extract Vec and then fell straight back to numpy below,
    // ~180-200x slower than numpy for a discarded result.
    if let Some((flat, shape)) = zerocopy_i64_unary_flat(py, &numpy, x, op)? {
        let output_shape = PyTuple::new(py, shape.iter().copied())?;
        let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
        if shape.is_empty() {
            return Ok(output.bind(py).get_item(())?.unbind());
        }
        return Ok(output);
    }
    // int32 zero-copy fast path. Same extract-then-discard cost as int64, plus
    // the f64 round-trip mis-wrapped square (saturating cast); this keeps int32
    // in int32 with wrapping ops, bit-identical to numpy.
    if let Some((flat, shape)) = zerocopy_i32_unary_flat(py, &numpy, x, op)? {
        let output_shape = PyTuple::new(py, shape.iter().copied())?;
        let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
        if shape.is_empty() {
            return Ok(output.bind(py).get_item(())?.unbind());
        }
        return Ok(output);
    }
    // Narrow signed / all unsigned integer widths (int8/int16, uint8/16/32/64):
    // same extract-then-discard cost as int64, plus the f64 round-trip mis-wraps
    // square. Keeps each width native with wrapping ops, bit-identical to numpy.
    if let Some((flat, shape)) = zerocopy_narrow_int_unary_flat(py, &numpy, x, op)? {
        let output_shape = PyTuple::new(py, shape.iter().copied())?;
        let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
        if shape.is_empty() {
            return Ok(output.bind(py).get_item(())?.unbind());
        }
        return Ok(output);
    }
    // float32 zero-copy fast path. float32 input otherwise extracted to an f64
    // Vec and rebuilt (~60-360x slower), and `sign` returned float64; this keeps
    // float32 in float32 throughout, bit-identical to numpy.
    if let Some((flat, shape)) = zerocopy_f32_unary_flat(py, &numpy, x, op)? {
        let output_shape = PyTuple::new(py, shape.iter().copied())?;
        let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
        if shape.is_empty() {
            return Ok(output.bind(py).get_item(())?.unbind());
        }
        return Ok(output);
    }
    // Non-contiguous (transposed/strided) ndarrays bail out of the contiguous-only
    // zero-copy fast paths into the cold extract → rebuild, which transpose-copies the
    // input (~4-5x slower than numpy's strided ufunc). Delegate them to numpy.
    if x.is_exact_instance(&numpy.getattr("ndarray")?)
        && !x
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return fallback(py);
    }
    let Ok(native) = extract_precise_numeric_array(py, x, context) else {
        return fallback(py);
    };
    if native.dtype() == DType::Bool
        || native.has_integer_sidecar()
        || matches!(native.dtype(), DType::Complex64 | DType::Complex128)
    {
        return fallback(py);
    }
    if let Some(flat) = numpy_array_from_direct_f64_unary(py, &numpy, &native, op)? {
        let output_shape = PyTuple::new(py, native.shape().iter().copied())?;
        let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
        if native.shape().is_empty() {
            return Ok(output.bind(py).get_item(())?.unbind());
        }
        return Ok(output);
    }
    let result = native.elementwise_unary(op);
    if !dtype_supported_by_numpy_export_bridge(result.dtype()) {
        return fallback(py);
    }
    let output = build_numpy_array_from_ufunc(py, &result)?;
    if native.shape().is_empty() {
        // Preserve numpy's 0-d scalar return type for scalar inputs.
        return Ok(output.bind(py).get_item(())?.unbind());
    }
    Ok(output)
}

// Like native_unary_elementwise but also falls back for integer dtypes
// (for functions like expm1/log1p that promote integers to float).
fn native_unary_promoting(
    py: Python<'_>,
    x: &Bound<'_, PyAny>,
    op: UnaryOp,
    numpy_name: &str,
    context: &str,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |_py: Python<'_>| -> PyResult<Py<PyAny>> {
        Ok(numpy.getattr(numpy_name)?.call1((x,))?.unbind())
    };
    // float16: numpy's f16 ufuncs (via an f16<->f32 path) are the reference and far
    // faster than fnp's native f16 round-trip (no f16 PyBuffer Element). Defer f16.
    if numpy_dtype_is_f16(x) {
        return fallback(py);
    }
    // Zero-copy fast path: exact float64 C-contiguous ndarray inputs skip the
    // cold extract Vec entirely (see zerocopy_f64_unary_flat). Integer inputs
    // (which this promoting path widens to float) are not float64 ndarrays, so
    // they correctly fall through unchanged.
    if let Some((flat, shape)) = zerocopy_f64_unary_flat(py, &numpy, x, op)? {
        let output_shape = PyTuple::new(py, shape.iter().copied())?;
        let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
        if shape.is_empty() {
            return Ok(output.bind(py).get_item(())?.unbind());
        }
        return Ok(output);
    }
    // float32 SIMD-transcendentals: numpy's vectorized f32 libm beats our scalar
    // per-element f32 libm 2-12x (sin/cos/tanh ~10x) — and the scalar path even
    // diverged from numpy in the last ULP for sin/cos/tanh, so delegating both
    // speeds them up AND makes them bit-exact. Only f32 inputs and only these
    // expensive ops route here; f64 keeps its tuned native path, and cheap f32
    // ops (trunc/abs/square/…) keep the zero-copy path below.
    if numpy_dtype_is_f32(x)
        && matches!(
            op,
            UnaryOp::Sin
                | UnaryOp::Cos
                | UnaryOp::Tan
                | UnaryOp::Arcsin
                | UnaryOp::Arccos
                | UnaryOp::Arctan
                | UnaryOp::Sinh
                | UnaryOp::Cosh
                | UnaryOp::Tanh
                | UnaryOp::Arcsinh
                | UnaryOp::Arccosh
                | UnaryOp::Arctanh
                | UnaryOp::Cbrt
                | UnaryOp::Expm1
                | UnaryOp::Log1p
                | UnaryOp::Sqrt
        )
    {
        return fallback(py);
    }
    // float32 input is float-preserving here (only integers promote to f64), so
    // the zero-copy float32 path applies to the ops it supports (e.g. sqrt).
    if let Some((flat, shape)) = zerocopy_f32_unary_flat(py, &numpy, x, op)? {
        let output_shape = PyTuple::new(py, shape.iter().copied())?;
        let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
        if shape.is_empty() {
            return Ok(output.bind(py).get_item(())?.unbind());
        }
        return Ok(output);
    }
    // Non-contiguous (transposed/strided) ndarrays bail out of the contiguous-only
    // zero-copy fast paths into the cold extract → rebuild (transpose-copy, ~4-5x
    // slower than numpy's strided ufunc). Delegate them to numpy.
    if x.is_exact_instance(&numpy.getattr("ndarray")?)
        && !x
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return fallback(py);
    }
    let Ok(native) = extract_precise_numeric_array(py, x, context) else {
        return fallback(py);
    };
    if native.dtype() == DType::Bool
        || native.has_integer_sidecar()
        || matches!(native.dtype(), DType::Complex64 | DType::Complex128)
        || native.dtype().is_integer()
    {
        return fallback(py);
    }
    if let Some(flat) = numpy_array_from_direct_f64_unary(py, &numpy, &native, op)? {
        let output_shape = PyTuple::new(py, native.shape().iter().copied())?;
        let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
        if native.shape().is_empty() {
            return Ok(output.bind(py).get_item(())?.unbind());
        }
        return Ok(output);
    }
    let result = native.elementwise_unary(op);
    if !dtype_supported_by_numpy_export_bridge(result.dtype()) {
        return fallback(py);
    }
    let output = build_numpy_array_from_ufunc(py, &result)?;
    if native.shape().is_empty() {
        return Ok(output.bind(py).get_item(())?.unbind());
    }
    Ok(output)
}

fn native_unary_promoting_or_passthrough(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
    op: UnaryOp,
    numpy_name: &str,
    context: &str,
) -> PyResult<Py<PyAny>> {
    if kwargs.is_none_or(|kwargs| kwargs.is_empty()) && args.len() == 1 {
        let x = args.get_item(0)?;
        native_unary_promoting(py, &x, op, numpy_name, context)
    } else {
        core_numpy_passthrough(py, numpy_name, args, kwargs)
    }
}

fn native_unary_elementwise_or_passthrough(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
    op: UnaryOp,
    numpy_name: &str,
    context: &str,
) -> PyResult<Py<PyAny>> {
    if kwargs.is_none_or(|kwargs| kwargs.is_empty()) && args.len() == 1 {
        let x = args.get_item(0)?;
        native_unary_elementwise(py, &x, op, numpy_name, context)
    } else {
        core_numpy_passthrough(py, numpy_name, args, kwargs)
    }
}

fn native_binary_arctan2_or_passthrough(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    if kwargs.is_none_or(|kwargs| kwargs.is_empty()) && args.len() == 2 {
        if !numpy_dtype_is_f64(py, &args.get_item(0)?)
            || !numpy_dtype_is_f64(py, &args.get_item(1)?)
        {
            return core_numpy_passthrough(py, "arctan2", args, kwargs);
        }
        // Zero-copy parallel path for same-shape C-contiguous f64 ndarrays: reduce
        // straight off the borrowed buffers with a rayon-parallel atan2, skipping the
        // extract_numeric_array copies (the serial extract+build marshalling, not the
        // atan2, dominated the old path — ~26ms of a 47ms 1M call).
        if let Some(out) =
            try_zerocopy_f64_binary(py, &args.get_item(0)?, &args.get_item(1)?, BinaryOp::Arctan2)?
        {
            return Ok(out);
        }
        let numpy = py.import("numpy")?;
        if noncontiguous_ndarray(&numpy, &args.get_item(0)?)?
            || noncontiguous_ndarray(&numpy, &args.get_item(1)?)?
        {
            return core_numpy_passthrough(py, "arctan2", args, kwargs);
        }
        // Scalar / broadcasting f64 operands: ufunc_arctan2's extract+broadcast is 2-2.8x slower
        // than numpy's C arctan2 (the same-shape case won above). Delegate. (BlackThrush 2026-06-23.)
        core_numpy_passthrough(py, "arctan2", args, kwargs)
    } else {
        core_numpy_passthrough(py, "arctan2", args, kwargs)
    }
}

// Retained for reference / potential reuse once a SIMD f64 path exists (bead
// 8vdtg); the python `fmax` binding now passes straight through to numpy because
// this native path was 60-72x slower. Matches the maximum/minimum convention below.
#[allow(dead_code)]
fn native_binary_fmax_or_passthrough(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    if kwargs.is_none_or(|kwargs| kwargs.is_empty()) && args.len() == 2 {
        let numpy = py.import("numpy")?;
        let arr1 = numpy.call_method1("asarray", (&args.get_item(0)?,))?;
        let arr2 = numpy.call_method1("asarray", (&args.get_item(1)?,))?;
        let dtype1_kind = arr1
            .getattr("dtype")?
            .getattr("kind")?
            .extract::<String>()?;
        let dtype2_kind = arr2
            .getattr("dtype")?
            .getattr("kind")?
            .extract::<String>()?;
        if dtype1_kind == "c" || dtype2_kind == "c" {
            return core_numpy_passthrough(py, "fmax", args, kwargs);
        }
        // fmax preserves the input dtype exactly; the f64 kernel widens narrow
        // ints/floats, so defer anything but float64 to numpy.
        if !numpy_dtype_is_f64(py, &args.get_item(0)?)
            || !numpy_dtype_is_f64(py, &args.get_item(1)?)
        {
            return core_numpy_passthrough(py, "fmax", args, kwargs);
        }
        let x1 = extract_numeric_array(py, &args.get_item(0)?, "fmax(x1)")?;
        let x2 = extract_numeric_array(py, &args.get_item(1)?, "fmax(x2)")?;
        let result = ufunc_fmax(&x1, &x2).map_err(map_ufunc_error)?;
        build_numpy_scalar_or_array(py, &result)
    } else {
        core_numpy_passthrough(py, "fmax", args, kwargs)
    }
}

