#[pyfunction]
#[pyo3(signature = (x, window_shape, axis=None, *, subok=false, writeable=false))]
fn sliding_window_view(
    py: Python<'_>,
    x: Py<PyAny>,
    window_shape: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    subok: bool,
    writeable: bool,
) -> PyResult<Py<PyAny>> {
    // Passthrough to numpy.lib.stride_tricks.sliding_window_view. Returns
    // a read-only strided view with a leading window axis per element of
    // `window_shape`; `axis` restricts which axes are windowed (None →
    // every axis, which is the NumPy default). `subok` preserves ndarray
    // subclasses like MaskedArray in the output.
    let numpy = py.import("numpy")?;
    let stride_tricks = numpy.getattr("lib")?.getattr("stride_tricks")?;
    let kwargs = PyDict::new(py);
    if let Some(axis_val) = axis {
        kwargs.set_item("axis", axis_val.bind(py))?;
    }
    kwargs.set_item("subok", subok)?;
    kwargs.set_item("writeable", writeable)?;
    Ok(stride_tricks
        .getattr("sliding_window_view")?
        .call((x.bind(py), window_shape.bind(py)), Some(&kwargs))?
        .unbind())
}

#[pyfunction]
#[pyo3(signature = (x, shape=None, strides=None, subok=false, writeable=true))]
fn as_strided(
    py: Python<'_>,
    x: Py<PyAny>,
    shape: Option<Py<PyAny>>,
    strides: Option<Py<PyAny>>,
    subok: bool,
    writeable: bool,
) -> PyResult<Py<PyAny>> {
    // Passthrough to numpy.lib.stride_tricks.as_strided. This is the
    // low-level primitive that `sliding_window_view` is built on: it
    // returns a new view whose shape and byte-level strides are set to
    // the caller-supplied values with no bounds checking, so it is
    // inherently unsafe. Exposed for callers that know what they're
    // doing and want to construct custom overlapping views.
    let numpy = py.import("numpy")?;
    let stride_tricks = numpy.getattr("lib")?.getattr("stride_tricks")?;
    let kwargs = PyDict::new(py);
    if let Some(shape_val) = shape {
        kwargs.set_item("shape", shape_val.bind(py))?;
    }
    if let Some(strides_val) = strides {
        kwargs.set_item("strides", strides_val.bind(py))?;
    }
    kwargs.set_item("subok", subok)?;
    kwargs.set_item("writeable", writeable)?;
    Ok(stride_tricks
        .getattr("as_strided")?
        .call((x.bind(py),), Some(&kwargs))?
        .unbind())
}

#[pyfunction]
#[pyo3(
    signature = (*args, **kwargs),
    text_signature = "(x1, x2, /, out=None, *, where=True, casting='same_kind', order='K', dtype=None, subok=True, signature=None)"
)]
fn true_divide(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    // np.true_divide IS np.divide. fnp exposes `divide` as numpy's own ufunc (re-export),
    // which is at parity; fnp's bespoke native true_divide path was 5-9x SLOWER than numpy
    // (an O(n) pre-scan for zero divisors + a non-competitive native divide; serial-confirmed,
    // BlackThrush 2026-06-22). Delegate to numpy.true_divide for divide-parity. (ARRAY-API-
    // ALIAS fix: route the alias to numpy's optimized impl, cf atan2->arctan2.)
    core_numpy_passthrough(py, "true_divide", args, kwargs)
}

// Per-element np.isclose predicate: finite values use the asymmetric tolerance
// |a-b| <= atol + rtol*|b|; otherwise (inf/nan) equality, with NaN==NaN only under
// equal_nan. Matches numpy.isclose exactly.
#[inline]
fn allclose_pair(x: f64, y: f64, rtol: f64, atol: f64, equal_nan: bool) -> bool {
    if x.is_finite() && y.is_finite() {
        (x - y).abs() <= atol + rtol * y.abs()
    } else {
        x == y || (equal_nan && x.is_nan() && y.is_nan())
    }
}

// Zero-copy early-exit np.allclose for f64: same-shape f64 ndarrays, or an f64
// ndarray vs an f64 scalar (broadcast against the scalar). numpy builds the whole
// isclose array then reduces; bailing on the first not-close pair skips that and
// the extract copies. Genuine broadcasting / other dtypes return None to defer.
fn try_zerocopy_f64_allclose(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    b: &Bound<'_, PyAny>,
    rtol: f64,
    atol: f64,
    equal_nan: bool,
) -> PyResult<Option<bool>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    let a_arr = a.is_exact_instance(&ndarray_type) && numpy_dtype_is_f64(py, a);
    let b_arr = b.is_exact_instance(&ndarray_type) && numpy_dtype_is_f64(py, b);
    let a_buf = if a_arr { PyBuffer::<f64>::get(a).ok() } else { None };
    let b_buf = if b_arr { PyBuffer::<f64>::get(b).ok() } else { None };
    let a_sc = if a_buf.is_none() { a.extract::<f64>().ok() } else { None };
    let b_sc = if b_buf.is_none() { b.extract::<f64>().ok() } else { None };
    let verdict = match (&a_buf, &b_buf) {
        (Some(ab), Some(bb)) => {
            if ab.shape() != bb.shape() {
                return Ok(None); // broadcasting left to numpy
            }
            let (Some(sa), Some(sb)) = (ab.as_slice(py), bb.as_slice(py)) else {
                return Ok(None);
            };
            sa.iter()
                .zip(sb.iter())
                .all(|(x, y)| allclose_pair(x.get(), y.get(), rtol, atol, equal_nan))
        }
        (Some(ab), None) => {
            let Some(bs) = b_sc else { return Ok(None) };
            let Some(sa) = ab.as_slice(py) else {
                return Ok(None);
            };
            sa.iter()
                .all(|x| allclose_pair(x.get(), bs, rtol, atol, equal_nan))
        }
        (None, Some(bb)) => {
            let Some(as_) = a_sc else { return Ok(None) };
            let Some(sb) = bb.as_slice(py) else {
                return Ok(None);
            };
            sb.iter()
                .all(|y| allclose_pair(as_, y.get(), rtol, atol, equal_nan))
        }
        (None, None) => return Ok(None),
    };
    Ok(Some(verdict))
}

// Zero-copy np.allclose for f32 arrays (same-shape f32 pair, or f32 array vs an
// f64-extractable scalar). numpy promotes the f32 isclose comparison to float64
// (the tolerances are python floats), which is exactly what our extract path
// already does — so widening each f32 element to f64 and reusing allclose_pair is
// bit-identical to the (conformance-passing) extract path, just without the copies.
// Mixed f32/f64 and other dtypes defer.
fn try_zerocopy_f32_allclose(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    b: &Bound<'_, PyAny>,
    rtol: f64,
    atol: f64,
    equal_nan: bool,
) -> PyResult<Option<bool>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    let is_f32 = |o: &Bound<'_, PyAny>| -> PyResult<bool> {
        if !o.is_exact_instance(&ndarray_type) {
            return Ok(false);
        }
        let dt = o.getattr("dtype")?;
        Ok(dt.getattr("kind")?.extract::<String>()? == "f"
            && dt.getattr("itemsize")?.extract::<usize>()? == 4)
    };
    let a_arr = is_f32(a)?;
    let b_arr = is_f32(b)?;
    if !a_arr && !b_arr {
        return Ok(None); // need at least one f32 array
    }
    let a_buf = if a_arr { PyBuffer::<f32>::get(a).ok() } else { None };
    let b_buf = if b_arr { PyBuffer::<f32>::get(b).ok() } else { None };
    let a_sc = if a_buf.is_none() { a.extract::<f64>().ok() } else { None };
    let b_sc = if b_buf.is_none() { b.extract::<f64>().ok() } else { None };
    let verdict = match (&a_buf, &b_buf) {
        (Some(ab), Some(bb)) => {
            if ab.shape() != bb.shape() {
                return Ok(None);
            }
            let (Some(sa), Some(sb)) = (ab.as_slice(py), bb.as_slice(py)) else {
                return Ok(None);
            };
            sa.iter().zip(sb.iter()).all(|(x, y)| {
                allclose_pair(x.get() as f64, y.get() as f64, rtol, atol, equal_nan)
            })
        }
        (Some(ab), None) => {
            let Some(bs) = b_sc else { return Ok(None) };
            let Some(sa) = ab.as_slice(py) else {
                return Ok(None);
            };
            sa.iter()
                .all(|x| allclose_pair(x.get() as f64, bs, rtol, atol, equal_nan))
        }
        (None, Some(bb)) => {
            let Some(as_) = a_sc else { return Ok(None) };
            let Some(sb) = bb.as_slice(py) else {
                return Ok(None);
            };
            sb.iter()
                .all(|y| allclose_pair(as_, y.get() as f64, rtol, atol, equal_nan))
        }
        (None, None) => return Ok(None),
    };
    Ok(Some(verdict))
}

#[pyfunction]
#[pyo3(signature = (a, b, rtol=1e-5, atol=1e-8, equal_nan=false))]
fn allclose(
    py: Python<'_>,
    a: Py<PyAny>,
    b: Py<PyAny>,
    rtol: f64,
    atol: f64,
    equal_nan: bool,
) -> PyResult<Py<PyAny>> {
    // Native allclose via UFuncArray::allclose_equal_nan. Delegates to
    // numpy for complex/structured/string inputs, integer-sidecar mixed
    // arrays, and shape-mismatch broadcast failures so numpy's full
    // dispatch surface (including bytes/object coercion) stays exact.
    let numpy = py.import("numpy")?;
    let allclose_fn = numpy.getattr("allclose")?;
    let a_for_fallback = a.clone_ref(py);
    let b_for_fallback = b.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        kwargs.set_item("rtol", rtol)?;
        kwargs.set_item("atol", atol)?;
        kwargs.set_item("equal_nan", equal_nan)?;
        Ok(allclose_fn
            .call(
                (a_for_fallback.bind(py), b_for_fallback.bind(py)),
                Some(&kwargs),
            )?
            .unbind())
    };

    // Zero-copy early-exit for same-shape f64 arrays or f64-array-vs-scalar.
    if let Some(verdict) =
        try_zerocopy_f64_allclose(py, a.bind(py), b.bind(py), rtol, atol, equal_nan)?
    {
        return Ok(numpy.getattr("bool_")?.call1((verdict,))?.unbind());
    }
    if let Some(verdict) =
        try_zerocopy_f32_allclose(py, a.bind(py), b.bind(py), rtol, atol, equal_nan)?
    {
        return Ok(numpy.getattr("bool_")?.call1((verdict,))?.unbind());
    }
    // Non-contiguous (transposed/strided) operands bail into the cold extract; delegate.
    if noncontiguous_ndarray(&numpy, a.bind(py))? || noncontiguous_ndarray(&numpy, b.bind(py))? {
        return fallback();
    }
    let array_a = match extract_precise_numeric_array(py, a.bind(py), "allclose(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let array_b = match extract_precise_numeric_array(py, b.bind(py), "allclose(b)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    if array_a.has_integer_sidecar()
        || array_b.has_integer_sidecar()
        || matches!(array_a.dtype(), DType::Complex64 | DType::Complex128)
        || matches!(array_b.dtype(), DType::Complex64 | DType::Complex128)
    {
        return fallback();
    }
    let verdict = match array_a.allclose_equal_nan(&array_b, rtol, atol, equal_nan) {
        Ok(value) => value,
        Err(_) => return fallback(),
    };
    // numpy.allclose returns a numpy.bool_ scalar, not Python bool; route
    // through np.bool_ so the return type matches the passthrough surface.
    Ok(numpy.getattr("bool_")?.call1((verdict,))?.unbind())
}

#[pyfunction]
#[pyo3(signature = (x,))]
fn fix(py: Python<'_>, x: Py<PyAny>) -> PyResult<Py<PyAny>> {
    // Native fix via UFuncArray::fix — round toward zero (truncate the
    // fractional part); equivalent to ceil for negatives and floor for
    // positives. Integer input passes through unchanged; NaN propagates.
    // Falls back to np.fix for complex/object/structured inputs so
    // numpy's coercion surface stays exact.
    let numpy = py.import("numpy")?;
    let fix_fn = numpy.getattr("fix")?;
    let x_for_fallback = x.clone_ref(py);
    let fallback =
        || -> PyResult<Py<PyAny>> { Ok(fix_fn.call1((x_for_fallback.bind(py),))?.unbind()) };

    // np.fix rounds toward zero, which is exactly np.trunc on real values; reuse
    // the zero-copy unary trunc path for f64 ndarrays to skip the cold
    // extract/build Vecs (bead lglck). Bit-identical (incl. -0.0/inf/nan).
    if numpy_dtype_is_f64(py, x.bind(py))
        && let Some(out) = try_zerocopy_f64_unary(py, x.bind(py), UnaryOp::Trunc)?
    {
        return Ok(out);
    }

    // float32: native zero-copy trunc (np.fix(f32) -> f32). The extract path below
    // canonicalized f32 -> f64 and rebuilt element-wise, ~150x slower than numpy.
    if let Some(out) = try_zerocopy_f32_unary(py, x.bind(py), UnaryOp::Trunc)? {
        return Ok(out);
    }
    // Integer / float16 / complex / array-like inputs: np.fix is a fast trunc ufunc
    // that preserves the input dtype (and returns integers unchanged). The native
    // extract -> f64-canonicalize -> rebuild path was 34-174x slower than numpy for
    // these dtypes, so delegate — np.fix is the exact parity oracle.
    fallback()
}

#[pyfunction]
#[pyo3(signature = (m, k=0))]
fn tril(py: Python<'_>, m: Py<PyAny>, k: i64) -> PyResult<Py<PyAny>> {
    // Native tril via UFuncArray::tril for real numeric inputs. Falls
    // back to np.tril for complex, integer sidecar, structured, and
    // object-array cases so numpy's dispatch surface stays exact.
    triangular_impl(py, m, k, /*upper=*/ false, "tril")
}

#[pyfunction]
#[pyo3(signature = (m, k=0))]
fn triu(py: Python<'_>, m: Py<PyAny>, k: i64) -> PyResult<Py<PyAny>> {
    // Native triu via UFuncArray::triu. Same fallback contract as tril.
    triangular_impl(py, m, k, /*upper=*/ true, "triu")
}

// Zero-copy np.triu / np.tril for a 2-D C-contiguous float64 ndarray: returns a
// copy with the elements outside the kept triangle zeroed. triu keeps j >= i+k,
// tril keeps j <= i+k. Each row's kept entries form a contiguous range, so this
// allocates numpy.zeros((rows, cols)) and copies that run from the input per row,
// with no intermediate Rust Vec of the full matrix (bead lglck). Kept values are
// copied verbatim, so it is bit-identical to numpy incl. -0.0/inf/nan with a
// +0.0 fill. Returns Ok(None) — caller falls through — for a non-2-D array or any
// non-f64 / non-contiguous / non-ndarray input.
fn try_zerocopy_f64_triangular(
    py: Python<'_>,
    m: &Bound<'_, PyAny>,
    k: i64,
    upper: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !m.is_exact_instance(&ndarray_type) || !numpy_dtype_is_f64(py, m) {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(m) else {
        return Ok(None);
    };
    let shape = in_buffer.shape();
    if shape.len() != 2 {
        return Ok(None);
    }
    let rows = shape[0];
    let cols = shape[1];
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let out = numpy.call_method("zeros", ((rows, cols),), Some(&kwargs))?;
    if rows > 0 && cols > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&out) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        for i in 0..rows {
            // Per row, the kept j range is contiguous; clamp the diagonal bound
            // i+k into [0, cols].
            let diag = i as i64 + k;
            let (j_start, j_end) = if upper {
                // keep j >= i+k
                let start = diag.clamp(0, cols as i64) as usize;
                (start, cols)
            } else {
                // keep j <= i+k  (i.e. j < i+k+1)
                let end = (diag + 1).clamp(0, cols as i64) as usize;
                (0, end)
            };
            let base = i * cols;
            for j in j_start..j_end {
                output[base + j].set(input[base + j].get());
            }
        }
    }
    Ok(Some(out.unbind()))
}

// Generic per-row triangle copy over a same-width unsigned view of the input and a
// pre-zeroed output (both viewed as `T`). Copies the kept contiguous j-range of each
// row verbatim; the rest stays the +0/0 zero fill numpy.zeros produced. Bit-identical
// for every dtype (verbatim element move; numpy.triu/tril fills the dropped triangle
// with 0). Returns None on a buffer-protocol failure so the caller defers to numpy.
fn triangular_typed<T: pyo3::buffer::Element + Copy>(
    py: Python<'_>,
    m_view: &Bound<'_, PyAny>,
    out_view: &Bound<'_, PyAny>,
    rows: usize,
    cols: usize,
    k: i64,
    upper: bool,
) -> PyResult<Option<()>> {
    let (Ok(in_buffer), Ok(out_buffer)) =
        (PyBuffer::<T>::get(m_view), PyBuffer::<T>::get(out_view))
    else {
        return Ok(None);
    };
    let (Some(input), Some(output)) = (in_buffer.as_slice(py), out_buffer.as_mut_slice(py)) else {
        return Ok(None);
    };
    for i in 0..rows {
        let diag = i as i64 + k;
        let (j_start, j_end) = if upper {
            (diag.clamp(0, cols as i64) as usize, cols)
        } else {
            (0, (diag + 1).clamp(0, cols as i64) as usize)
        };
        let base = i * cols;
        for j in j_start..j_end {
            output[base + j].set(input[base + j].get());
        }
    }
    Ok(Some(()))
}

// All-width zero-copy np.triu / np.tril: the f64 helper covers only float64; narrow
// ints, int64/uint64, float32 and bool fall to the cold extract path that widens
// through f64 (21x slower for int64, and that f64 bridge is also lossy for wide
// ints). triu/tril move elements verbatim, so allocate numpy.zeros of the input's
// own dtype and copy each row's kept triangle through a same-width unsigned view —
// byte-exact for every fixed-width dtype (incl. exact int64/uint64). complex (kind
// 'c') and non-2-D / non-contiguous inputs return None and defer to numpy.
fn try_zerocopy_any_triangular(
    py: Python<'_>,
    m: &Bound<'_, PyAny>,
    k: i64,
    upper: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !m.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = m.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if !matches!(kind.as_str(), "i" | "u" | "f" | "b") {
        return Ok(None);
    }
    let shape = m.getattr("shape")?.extract::<Vec<usize>>()?;
    if shape.len() != 2 {
        return Ok(None);
    }
    let (rows, cols) = (shape[0], shape[1]);
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    let uname = match itemsize {
        1 => "uint8",
        2 => "uint16",
        4 => "uint32",
        8 => "uint64",
        _ => return Ok(None),
    };
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", &dtype)?;
    let out = numpy.call_method("zeros", ((rows, cols),), Some(&kwargs))?;
    if rows > 0 && cols > 0 {
        let uview = numpy.getattr(uname)?;
        let (Ok(m_u), Ok(out_u)) = (
            m.call_method1("view", (&uview,)),
            out.call_method1("view", (&uview,)),
        ) else {
            return Ok(None);
        };
        let done = match itemsize {
            1 => triangular_typed::<u8>(py, &m_u, &out_u, rows, cols, k, upper)?,
            2 => triangular_typed::<u16>(py, &m_u, &out_u, rows, cols, k, upper)?,
            4 => triangular_typed::<u32>(py, &m_u, &out_u, rows, cols, k, upper)?,
            8 => triangular_typed::<u64>(py, &m_u, &out_u, rows, cols, k, upper)?,
            _ => None,
        };
        if done.is_none() {
            return Ok(None);
        }
    }
    Ok(Some(out.unbind()))
}

fn triangular_impl(
    py: Python<'_>,
    m: Py<PyAny>,
    k: i64,
    upper: bool,
    numpy_name: &'static str,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let numpy_fn = numpy.getattr(numpy_name)?;
    let m_for_fallback = m.clone_ref(py);
    let fallback =
        || -> PyResult<Py<PyAny>> { Ok(numpy_fn.call1((m_for_fallback.bind(py), k))?.unbind()) };
    // Zero-copy per-row triangle copy for 2-D f64 ndarrays; skips the cold
    // extract + full n*n build Vecs. Bit-identical; N-D and other dtypes fall
    // through to the general path.
    if let Some(result) = try_zerocopy_f64_triangular(py, m.bind(py), k, upper)? {
        return Ok(result);
    }
    // All other fixed-width dtypes (narrow ints, int64/uint64, float32, bool):
    // zeros-of-input-dtype + per-row verbatim triangle copy through an unsigned
    // view, skipping the cold extract+f64-bridge path (21x slower for int64).
    if let Some(result) = try_zerocopy_any_triangular(py, m.bind(py), k, upper)? {
        return Ok(result);
    }
    let array = match extract_precise_numeric_array(py, m.bind(py), numpy_name) {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    if array.has_integer_sidecar() || matches!(array.dtype(), DType::Complex64 | DType::Complex128)
    {
        return fallback();
    }
    let result = if upper { array.triu(k) } else { array.tril(k) };
    let result = match result {
        Ok(value) => value,
        Err(_) => return fallback(),
    };
    build_numpy_array_from_ufunc(py, &result)
}

#[pyfunction]
#[pyo3(signature = (m, beta))]
fn kaiser(py: Python<'_>, m: i64, beta: f64) -> PyResult<Py<PyAny>> {
    // Rust-owned port of np.kaiser. NumPy maps negative lengths to an
    // empty float64 array, keeps M <= 1 special-cased, and otherwise
    // emits the Kaiser window parameterized by beta.
    let result = UFuncArray::kaiser(m.max(0) as usize, beta);
    build_numpy_array_from_ufunc(py, &result)
}

#[pyfunction]
#[pyo3(signature = (a, dtype=None))]
fn asarray_chkfinite(
    py: Python<'_>,
    a: Py<PyAny>,
    dtype: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let asarray_fn = numpy.getattr("asarray")?;
    let kwargs = PyDict::new(py);
    if let Some(dtype_val) = dtype.as_ref() {
        kwargs.set_item("dtype", dtype_val.bind(py))?;
    }
    // Perform the coercion first (this may raise TypeError if dtype is
    // invalid), then use Rust to sweep the values for NaN/Inf. numpy's
    // own error text for non-finite input is "array must not contain
    // infs or NaNs"; emit the same message directly.
    let array = asarray_fn.call((a.bind(py),), Some(&kwargs))?;
    let array_dtype_name = array
        .getattr("dtype")?
        .getattr("name")?
        .extract::<String>()?;
    let parsed = DType::parse(&array_dtype_name);
    let needs_check = matches!(
        parsed,
        Some(DType::F16)
            | Some(DType::F32)
            | Some(DType::F64)
            | Some(DType::Complex64)
            | Some(DType::Complex128)
    );
    if needs_check {
        let isfinite = numpy.getattr("isfinite")?;
        let all_finite: bool = isfinite
            .call1((array.clone(),))?
            .call_method0("all")?
            .extract()?;
        if !all_finite {
            return Err(PyValueError::new_err("array must not contain infs or NaNs"));
        }
    }
    Ok(array.unbind())
}

#[pyfunction]
#[pyo3(signature = (*arrays))]
fn common_type(py: Python<'_>, arrays: &Bound<'_, PyTuple>) -> PyResult<Py<PyAny>> {
    // np.common_type returns a Python scalar *type* (class like
    // `np.float32`/`np.complex128`), not an ndarray. This is pure dtype
    // classification over numpy's scalar-type hierarchy — there is no
    // array computation to move to fnp crates. Delegation is the correct
    // long-term answer; keep the wrapper thin.
    let numpy = py.import("numpy")?;
    Ok(numpy.getattr("common_type")?.call1(arrays)?.unbind())
}

