#[pyfunction]
#[pyo3(signature = (a, dtype=None, requirements=None, *, like=None))]
fn require(
    py: Python<'_>,
    a: Py<PyAny>,
    dtype: Option<Py<PyAny>>,
    requirements: Option<Py<PyAny>>,
    like: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    // Passthrough to np.require. Coerces an input array to meet the
    // listed requirements (C/F contiguity, aligned, writeable, owndata).
    // Matches numpy for the single-char and multi-requirement forms
    // and for no-op behavior when the input already meets every flag.
    let numpy = py.import("numpy")?;
    let kwargs = PyDict::new(py);
    if let Some(dtype_val) = dtype {
        kwargs.set_item("dtype", dtype_val.bind(py))?;
    }
    if let Some(req_val) = requirements {
        kwargs.set_item("requirements", req_val.bind(py))?;
    }
    if let Some(like_val) = like {
        kwargs.set_item("like", like_val.bind(py))?;
    }
    Ok(numpy
        .getattr("require")?
        .call((a.bind(py),), Some(&kwargs))?
        .unbind())
}

#[pyfunction]
#[pyo3(signature = (n, mask_func, k=0))]
fn mask_indices(py: Python<'_>, n: i64, mask_func: Py<PyAny>, k: i64) -> PyResult<Py<PyAny>> {
    let n = usize::try_from(n)
        .map_err(|_| PyValueError::new_err("negative dimensions are not allowed"))?;

    // numpy.mask_indices is `mask_func(ones((n,n)), k).nonzero()` — entirely in
    // numpy. The native path built the n*n bool array, round-tripped it OUT to the
    // Python mask_func, then extracted the result BACK into a UFuncArray before
    // where_nonzero — two extra full n*n marshalling copies that numpy never makes
    // (measured ~2.56x slower at n=2000). The op is dominated by those copies, not
    // the nonzero, so delegate to numpy for parity (no native advantage exists).
    let numpy = py.import("numpy")?;
    Ok(numpy
        .getattr("mask_indices")?
        .call1((n, mask_func.bind(py), k))?
        .unbind())
}

#[pyfunction]
#[pyo3(signature = (x1, x2, *, axis=-1_i64))]
fn linalg_vecdot(py: Python<'_>, x1: Py<PyAny>, x2: Py<PyAny>, axis: i64) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let vecdot_fn = numpy.getattr("linalg")?.getattr("vecdot")?;
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        kwargs.set_item("axis", axis)?;
        Ok(vecdot_fn
            .call((x1.bind(py), x2.bind(py)), Some(&kwargs))?
            .unbind())
    };

    let x1 = match extract_precise_numeric_array(py, x1.bind(py), "linalg.vecdot(x1)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let x2 = match extract_precise_numeric_array(py, x2.bind(py), "linalg.vecdot(x2)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    if x1.has_integer_sidecar()
        || x2.has_integer_sidecar()
        || matches!(x1.dtype(), DType::Complex64 | DType::Complex128)
        || matches!(x2.dtype(), DType::Complex64 | DType::Complex128)
        || x1.shape() != x2.shape()
    {
        return fallback();
    }

    let result = match x1.vecdot(&x2, Some(axis as isize)) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };

    build_numpy_scalar_or_array(py, &result)
}

