#[pyfunction]
#[pyo3(signature = (file, dtype=None, count=-1_i64, sep="", offset=0_i64, *, like=None))]
fn fromfile(
    py: Python<'_>,
    file: Py<PyAny>,
    dtype: Option<Py<PyAny>>,
    count: i64,
    sep: &str,
    offset: i64,
    like: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(dtype_val) = dtype.as_ref() {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        kwargs.set_item("count", count)?;
        kwargs.set_item("sep", sep)?;
        kwargs.set_item("offset", offset)?;
        if let Some(like_val) = like.as_ref() {
            kwargs.set_item("like", like_val.bind(py))?;
        }
        Ok(numpy
            .getattr("fromfile")?
            .call((file.bind(py),), Some(&kwargs))?
            .unbind())
    };

    if !sep.is_empty() {
        if offset != 0
            || like
                .as_ref()
                .is_some_and(|like_val| !like_val.bind(py).is_none())
        {
            return fallback();
        }
        let parsed_dtype = extract_python_dtype(
            py,
            dtype.as_ref().map(|value| value.clone_ref(py)),
            DType::F64,
            "fromfile(dtype)",
        )?;
        if !dtype_supported_by_numpy_export_bridge(parsed_dtype) {
            return fallback();
        }

        let file_bound = file.bind(py);
        let text = if let Ok(path_obj) = py.import("os")?.getattr("fspath")?.call1((file_bound,))
            && let Ok(path) = path_obj.extract::<String>()
        {
            std::fs::read_to_string(&path).map_err(|err| PyOSError::new_err(err.to_string()))?
        } else if let Ok(result) = file_bound.call_method0("read") {
            match result.extract::<String>() {
                Ok(value) => value,
                Err(_) => return fallback(),
            }
        } else {
            return fallback();
        };

        let tokens = split_numeric_text_tokens(&text, sep);
        let effective: Vec<&str> = match numeric_text_count_limit(count) {
            Some(limit) => tokens.into_iter().take(limit).collect(),
            None => tokens,
        };
        let storage = match storage_from_numeric_text_tokens(&effective, parsed_dtype) {
            Ok(storage) => storage,
            Err(_) => return fallback(),
        };
        return build_numpy_array_from_storage(py, &[storage.len()], storage);
    }
    if let Some(like_val) = like.as_ref()
        && !like_val.bind(py).is_none()
    {
        return fallback();
    }

    let parsed_dtype = extract_python_dtype(
        py,
        dtype.as_ref().map(|value| value.clone_ref(py)),
        DType::F64,
        "fromfile(dtype)",
    )?;
    if dtype_item_size(parsed_dtype).is_none() {
        return fallback();
    }

    let os = py.import("os")?;
    let path_obj = match os.getattr("fspath")?.call1((file.bind(py),)) {
        Ok(path) => path,
        Err(_) => return fallback(),
    };
    let path = match path_obj.extract::<String>() {
        Ok(path) => path,
        Err(_) => return fallback(),
    };

    let bytes = std::fs::read(&path).map_err(|err| PyOSError::new_err(err.to_string()))?;
    if offset < 0 || offset as usize > bytes.len() {
        return Err(PyValueError::new_err(format!(
            "offset must be non-negative and no greater than buffer length ({})",
            bytes.len()
        )));
    }

    let storage = storage_from_bytes(&bytes[offset as usize..], parsed_dtype, count)?;
    build_numpy_array_from_storage(py, &[storage.len()], storage)
}

#[pyfunction]
#[pyo3(signature = (fname, dtype=None, comments="#", delimiter=None, converters=None, skiprows=0_i64, usecols=None, unpack=false, ndmin=0_i64, encoding=None, max_rows=None, *, like=None))]
#[allow(clippy::too_many_arguments)]
fn loadtxt(
    py: Python<'_>,
    fname: Py<PyAny>,
    dtype: Option<Py<PyAny>>,
    comments: &str,
    delimiter: Option<&str>,
    converters: Option<Py<PyAny>>,
    skiprows: i64,
    usecols: Option<Py<PyAny>>,
    unpack: bool,
    ndmin: i64,
    encoding: Option<&str>,
    max_rows: Option<i64>,
    like: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(dtype_val) = dtype.as_ref() {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        kwargs.set_item("comments", comments)?;
        if let Some(delim) = delimiter {
            kwargs.set_item("delimiter", delim)?;
        }
        if let Some(cv) = converters.as_ref() {
            kwargs.set_item("converters", cv.bind(py))?;
        }
        kwargs.set_item("skiprows", skiprows)?;
        if let Some(uc) = usecols.as_ref() {
            kwargs.set_item("usecols", uc.bind(py))?;
        }
        kwargs.set_item("unpack", unpack)?;
        kwargs.set_item("ndmin", ndmin)?;
        if let Some(enc) = encoding {
            kwargs.set_item("encoding", enc)?;
        }
        if let Some(mr) = max_rows {
            kwargs.set_item("max_rows", mr)?;
        }
        if let Some(like_val) = like.as_ref() {
            kwargs.set_item("like", like_val.bind(py))?;
        }
        Ok(numpy
            .getattr("loadtxt")?
            .call((fname.bind(py),), Some(&kwargs))?
            .unbind())
    };

    // Native path: support the common tutorial surface.
    if converters.is_some()
        || encoding.is_some()
        || max_rows.is_some()
        || like.is_some()
        || ndmin != 0
    {
        return fallback(py);
    }

    // Resolve text content from fname. Accept StringIO, file-like with
    // .read() method, or str path (via open).
    let fname_bound = fname.bind(py);
    let text: String = if let Ok(s) = fname_bound.extract::<String>() {
        // Treat as file path.
        match std::fs::read_to_string(&s) {
            Ok(value) => value,
            Err(_) => return fallback(py),
        }
    } else {
        return fallback(py);
    };

    // Resolve target dtype (default float64).
    let dtype_clone = dtype.as_ref().map(|v| v.clone_ref(py));
    let parsed_dtype = match extract_python_dtype(py, dtype_clone, DType::F64, "loadtxt(dtype)") {
        Ok(value) if dtype_supported_by_numpy_export_bridge(value) => value,
        _ => return fallback(py),
    };

    // Resolve usecols. None → all columns. Int → single col. List<int>.
    let use_columns: Option<Vec<i64>> = match usecols.as_ref() {
        None => None,
        Some(v) => {
            let b = v.bind(py);
            if b.is_none() {
                None
            } else if let Ok(cols) = b.extract::<Vec<i64>>() {
                Some(cols)
            } else if let Ok(col) = b.extract::<i64>() {
                Some(vec![col])
            } else {
                return fallback(py);
            }
        }
    };

    // Parse rows of tokens.
    let skip_count = skiprows.max(0) as usize;
    let mut rows: Vec<Vec<String>> = Vec::new();
    for (lineno, raw_line) in text.lines().enumerate() {
        if lineno < skip_count {
            continue;
        }
        // Strip comments.
        let effective = match raw_line.split_once(comments) {
            Some((lhs, _)) => lhs,
            None => raw_line,
        };
        let trimmed = effective.trim();
        if trimmed.is_empty() {
            continue;
        }
        let tokens: Vec<String> = match delimiter {
            None => trimmed.split_whitespace().map(|s| s.to_string()).collect(),
            Some(sep) if sep.chars().all(char::is_whitespace) => {
                trimmed.split_whitespace().map(|s| s.to_string()).collect()
            }
            Some(sep) => trimmed.split(sep).map(|s| s.trim().to_string()).collect(),
        };
        let selected: Vec<String> = if let Some(cols) = use_columns.as_ref() {
            let mut out = Vec::with_capacity(cols.len());
            for &col in cols {
                let idx = if col < 0 {
                    (tokens.len() as i64 + col) as usize
                } else {
                    col as usize
                };
                if idx >= tokens.len() {
                    return fallback(py);
                }
                out.push(tokens[idx].clone());
            }
            out
        } else {
            tokens
        };
        if selected.is_empty() {
            continue;
        }
        rows.push(selected);
    }

    if rows.is_empty() {
        return fallback(py);
    }
    let ncols = rows[0].len();
    for row in &rows {
        if row.len() != ncols {
            return fallback(py);
        }
    }
    let nrows = rows.len();

    // Parse all tokens into the target dtype's storage.
    let flat_storage = match parsed_dtype {
        DType::I8
        | DType::I16
        | DType::I32
        | DType::I64
        | DType::U8
        | DType::U16
        | DType::U32
        | DType::U64 => {
            let mut longs = Vec::with_capacity(nrows * ncols);
            for row in &rows {
                for tok in row {
                    match tok.parse::<i64>() {
                        Ok(v) => longs.push(v),
                        Err(_) => match tok.parse::<f64>() {
                            Ok(v) if v.fract() == 0.0 && v.is_finite() => longs.push(v as i64),
                            _ => return fallback(py),
                        },
                    }
                }
            }
            match parsed_dtype {
                DType::I8 => ArrayStorage::I8(longs.into_iter().map(|v| v as i8).collect()),
                DType::I16 => ArrayStorage::I16(longs.into_iter().map(|v| v as i16).collect()),
                DType::I32 => ArrayStorage::I32(longs.into_iter().map(|v| v as i32).collect()),
                DType::I64 => ArrayStorage::I64(longs),
                DType::U8 => ArrayStorage::U8(longs.into_iter().map(|v| v as u8).collect()),
                DType::U16 => ArrayStorage::U16(longs.into_iter().map(|v| v as u16).collect()),
                DType::U32 => ArrayStorage::U32(longs.into_iter().map(|v| v as u32).collect()),
                DType::U64 => ArrayStorage::U64(longs.into_iter().map(|v| v as u64).collect()),
                _ => unreachable!(),
            }
        }
        DType::F16 | DType::F32 | DType::F64 => {
            let mut floats = Vec::with_capacity(nrows * ncols);
            for row in &rows {
                for tok in row {
                    match tok.parse::<f64>() {
                        Ok(v) => floats.push(v),
                        Err(_) => return fallback(py),
                    }
                }
            }
            match parsed_dtype {
                DType::F16 => ArrayStorage::F16(floats.into_iter().map(f16::from_f64).collect()),
                DType::F32 => ArrayStorage::F32(floats.into_iter().map(|v| v as f32).collect()),
                DType::F64 => ArrayStorage::F64(floats),
                _ => unreachable!(),
            }
        }
        DType::Bool => {
            let mut values = Vec::with_capacity(nrows * ncols);
            for row in &rows {
                for tok in row {
                    match tok.parse::<i64>() {
                        Ok(v) => values.push(v != 0),
                        Err(_) => return fallback(py),
                    }
                }
            }
            ArrayStorage::Bool(values)
        }
        _ => return fallback(py),
    };

    // Reshape: 1-D output if only one column (numpy squeezes); else 2-D.
    let shape = if ncols == 1 {
        vec![nrows]
    } else {
        vec![nrows, ncols]
    };
    let arr = build_numpy_array_from_storage(py, &shape, flat_storage)?;

    if unpack {
        // numpy.loadtxt(unpack=True) returns the transposed array
        // (np.loadtxt actually returns `ret.T` itself, not a tuple,
        // despite the docs).
        let arr_bound = arr.bind(py);
        let transposed = arr_bound.getattr("T")?;
        Ok(transposed.unbind())
    } else {
        Ok(arr)
    }
}

#[pyfunction]
#[pyo3(signature = (fname, dtype=None, comments="#", delimiter=None, skip_header=0_i64, skip_footer=0_i64, converters=None, missing_values=None, filling_values=None, usecols=None, names=None, excludelist=None, deletechars=None, replace_space="_", autostrip=false, case_sensitive=None, defaultfmt="f%i", unpack=None, usemask=false, loose=true, invalid_raise=true, max_rows=None, encoding=None, *, ndmin=0_i64, like=None))]
#[allow(clippy::too_many_arguments)]
fn genfromtxt(
    py: Python<'_>,
    fname: Py<PyAny>,
    dtype: Option<Py<PyAny>>,
    comments: &str,
    delimiter: Option<&str>,
    skip_header: i64,
    skip_footer: i64,
    converters: Option<Py<PyAny>>,
    missing_values: Option<Py<PyAny>>,
    filling_values: Option<Py<PyAny>>,
    usecols: Option<Py<PyAny>>,
    names: Option<Py<PyAny>>,
    excludelist: Option<Py<PyAny>>,
    deletechars: Option<&str>,
    replace_space: &str,
    autostrip: bool,
    case_sensitive: Option<Py<PyAny>>,
    defaultfmt: &str,
    unpack: Option<bool>,
    usemask: bool,
    loose: bool,
    invalid_raise: bool,
    max_rows: Option<i64>,
    encoding: Option<&str>,
    ndmin: i64,
    like: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(dtype_val) = dtype.as_ref() {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        kwargs.set_item("comments", comments)?;
        if let Some(d) = delimiter {
            kwargs.set_item("delimiter", d)?;
        }
        kwargs.set_item("skip_header", skip_header)?;
        kwargs.set_item("skip_footer", skip_footer)?;
        if let Some(cv) = converters.as_ref() {
            kwargs.set_item("converters", cv.bind(py))?;
        }
        if let Some(mv) = missing_values.as_ref() {
            kwargs.set_item("missing_values", mv.bind(py))?;
        }
        if let Some(fv) = filling_values.as_ref() {
            kwargs.set_item("filling_values", fv.bind(py))?;
        }
        if let Some(uc) = usecols.as_ref() {
            kwargs.set_item("usecols", uc.bind(py))?;
        }
        if let Some(n) = names.as_ref() {
            kwargs.set_item("names", n.bind(py))?;
        }
        if let Some(el) = excludelist.as_ref() {
            kwargs.set_item("excludelist", el.bind(py))?;
        }
        if let Some(dc) = deletechars {
            kwargs.set_item("deletechars", dc)?;
        }
        kwargs.set_item("replace_space", replace_space)?;
        kwargs.set_item("autostrip", autostrip)?;
        if let Some(cs) = case_sensitive.as_ref() {
            kwargs.set_item("case_sensitive", cs.bind(py))?;
        }
        kwargs.set_item("defaultfmt", defaultfmt)?;
        if let Some(up) = unpack {
            kwargs.set_item("unpack", up)?;
        }
        kwargs.set_item("usemask", usemask)?;
        kwargs.set_item("loose", loose)?;
        kwargs.set_item("invalid_raise", invalid_raise)?;
        if let Some(mr) = max_rows {
            kwargs.set_item("max_rows", mr)?;
        }
        if let Some(enc) = encoding {
            kwargs.set_item("encoding", enc)?;
        }
        kwargs.set_item("ndmin", ndmin)?;
        if let Some(like_val) = like.as_ref() {
            kwargs.set_item("like", like_val.bind(py))?;
        }
        Ok(numpy
            .getattr("genfromtxt")?
            .call((fname.bind(py),), Some(&kwargs))?
            .unbind())
    };

    // Native path handles a narrow but tutorial-relevant slice:
    // numeric dtype, no structured names/missing/filling, no masked
    // output, no converters/encoding/invalid_raise tweaks. Everything
    // else defers to numpy's rich parser.
    let dtype_is_none_or_missing = dtype.as_ref().is_none_or(|v| v.bind(py).is_none());
    if dtype_is_none_or_missing
        || converters.is_some()
        || missing_values.is_some()
        || filling_values.is_some()
        || names.is_some()
        || excludelist.is_some()
        || deletechars.is_some()
        || replace_space != "_"
        || autostrip
        || case_sensitive.is_some()
        || defaultfmt != "f%i"
        || usemask
        || !loose
        || !invalid_raise
        || max_rows.is_some()
        || encoding.is_some()
        || ndmin != 0
        || like.is_some()
    {
        return fallback(py);
    }

    // Extract text (StringIO, file-like, or file path).
    let fname_bound = fname.bind(py);
    let text: String = if let Ok(s) = fname_bound.extract::<String>() {
        match std::fs::read_to_string(&s) {
            Ok(value) => value,
            Err(_) => return fallback(py),
        }
    } else if let Ok(result) = fname_bound.call_method0("read") {
        match result.extract::<String>() {
            Ok(value) => value,
            Err(_) => return fallback(py),
        }
    } else {
        return fallback(py);
    };

    // Resolve target dtype — must be numeric bridge-supported.
    let dtype_clone = dtype.as_ref().map(|v| v.clone_ref(py));
    let parsed_dtype = match extract_python_dtype(py, dtype_clone, DType::F64, "genfromtxt(dtype)")
    {
        Ok(value) if dtype_supported_by_numpy_export_bridge(value) => value,
        _ => return fallback(py),
    };

    // usecols parsing (same rules as loadtxt).
    let use_columns: Option<Vec<i64>> = match usecols.as_ref() {
        None => None,
        Some(v) => {
            let b = v.bind(py);
            if b.is_none() {
                None
            } else if let Ok(cols) = b.extract::<Vec<i64>>() {
                Some(cols)
            } else if let Ok(col) = b.extract::<i64>() {
                Some(vec![col])
            } else {
                return fallback(py);
            }
        }
    };

    // Tokenize with skip_header + skip_footer applied at the line level.
    let skip_h = skip_header.max(0) as usize;
    let skip_f = skip_footer.max(0) as usize;
    let all_lines: Vec<&str> = text.lines().collect();
    if skip_h + skip_f >= all_lines.len() {
        return fallback(py);
    }
    let usable_lines = &all_lines[skip_h..all_lines.len() - skip_f];

    let mut rows: Vec<Vec<String>> = Vec::new();
    for raw_line in usable_lines {
        let effective = match raw_line.split_once(comments) {
            Some((lhs, _)) => lhs,
            None => raw_line,
        };
        let trimmed = effective.trim();
        if trimmed.is_empty() {
            continue;
        }
        let tokens: Vec<String> = match delimiter {
            None => trimmed.split_whitespace().map(|s| s.to_string()).collect(),
            Some(sep) if sep.chars().all(char::is_whitespace) => {
                trimmed.split_whitespace().map(|s| s.to_string()).collect()
            }
            Some(sep) => trimmed.split(sep).map(|s| s.trim().to_string()).collect(),
        };
        let selected: Vec<String> = if let Some(cols) = use_columns.as_ref() {
            let mut out = Vec::with_capacity(cols.len());
            for &col in cols {
                let idx = if col < 0 {
                    (tokens.len() as i64 + col) as usize
                } else {
                    col as usize
                };
                if idx >= tokens.len() {
                    return fallback(py);
                }
                out.push(tokens[idx].clone());
            }
            out
        } else {
            tokens
        };
        if selected.is_empty() {
            continue;
        }
        rows.push(selected);
    }

    if rows.is_empty() {
        return fallback(py);
    }
    let ncols = rows[0].len();
    for row in &rows {
        if row.len() != ncols {
            return fallback(py);
        }
    }
    let nrows = rows.len();

    // Parse tokens into storage (same scheme as loadtxt).
    let flat_storage = match parsed_dtype {
        DType::I8
        | DType::I16
        | DType::I32
        | DType::I64
        | DType::U8
        | DType::U16
        | DType::U32
        | DType::U64 => {
            let mut longs = Vec::with_capacity(nrows * ncols);
            for row in &rows {
                for tok in row {
                    match tok.parse::<i64>() {
                        Ok(v) => longs.push(v),
                        Err(_) => match tok.parse::<f64>() {
                            Ok(v) if v.fract() == 0.0 && v.is_finite() => longs.push(v as i64),
                            _ => return fallback(py),
                        },
                    }
                }
            }
            match parsed_dtype {
                DType::I8 => ArrayStorage::I8(longs.into_iter().map(|v| v as i8).collect()),
                DType::I16 => ArrayStorage::I16(longs.into_iter().map(|v| v as i16).collect()),
                DType::I32 => ArrayStorage::I32(longs.into_iter().map(|v| v as i32).collect()),
                DType::I64 => ArrayStorage::I64(longs),
                DType::U8 => ArrayStorage::U8(longs.into_iter().map(|v| v as u8).collect()),
                DType::U16 => ArrayStorage::U16(longs.into_iter().map(|v| v as u16).collect()),
                DType::U32 => ArrayStorage::U32(longs.into_iter().map(|v| v as u32).collect()),
                DType::U64 => ArrayStorage::U64(longs.into_iter().map(|v| v as u64).collect()),
                _ => unreachable!(),
            }
        }
        DType::F16 | DType::F32 | DType::F64 => {
            let mut floats = Vec::with_capacity(nrows * ncols);
            for row in &rows {
                for tok in row {
                    match tok.parse::<f64>() {
                        Ok(v) => floats.push(v),
                        Err(_) => return fallback(py),
                    }
                }
            }
            match parsed_dtype {
                DType::F16 => ArrayStorage::F16(floats.into_iter().map(f16::from_f64).collect()),
                DType::F32 => ArrayStorage::F32(floats.into_iter().map(|v| v as f32).collect()),
                DType::F64 => ArrayStorage::F64(floats),
                _ => unreachable!(),
            }
        }
        _ => return fallback(py),
    };

    let shape = if ncols == 1 {
        vec![nrows]
    } else {
        vec![nrows, ncols]
    };
    let arr = build_numpy_array_from_storage(py, &shape, flat_storage)?;

    if unpack == Some(true) {
        let arr_bound = arr.bind(py);
        let transposed = arr_bound.getattr("T")?;
        Ok(transposed.unbind())
    } else {
        Ok(arr)
    }
}

#[pyfunction]
#[pyo3(signature = (base, drop_names, usemask=true, asrecarray=false))]
fn recfunctions_drop_fields(
    py: Python<'_>,
    base: Py<PyAny>,
    drop_names: Py<PyAny>,
    usemask: bool,
    asrecarray: bool,
) -> PyResult<Py<PyAny>> {
    let base_bound = base.bind(py);
    let drop_names_bound = drop_names.bind(py);
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        kwargs.set_item("usemask", usemask)?;
        kwargs.set_item("asrecarray", asrecarray)?;
        Ok(py
            .import("numpy.lib.recfunctions")?
            .getattr("drop_fields")?
            .call((base_bound, drop_names_bound), Some(&kwargs))?
            .unbind())
    };
    if asrecarray {
        return fallback(py);
    }

    // Collect the names to drop (accept str or list/tuple of str).
    let drops: Vec<String> = if let Ok(single) = drop_names_bound.extract::<String>() {
        vec![single]
    } else if let Ok(list) = drop_names_bound.extract::<Vec<String>>() {
        list
    } else {
        return fallback(py);
    };

    let dtype_obj = base_bound.getattr("dtype")?;
    let Ok(old_names) = dtype_obj.getattr("names")?.extract::<Vec<String>>() else {
        return fallback(py);
    };

    // Build a descriptor restricted to the kept fields.
    let descr = PyList::empty(py);
    let mut keep_names = Vec::new();
    for name in &old_names {
        if drops.iter().any(|d| d == name) {
            continue;
        }
        let field = dtype_obj.get_item(name.as_str())?;
        // Nested structured fields → fallback so recfunctions' recursion
        // handles dotted drop names correctly.
        if field
            .getattr("names")
            .ok()
            .is_some_and(|names| !names.is_none())
        {
            return fallback(py);
        }
        descr.append(PyTuple::new(
            py,
            [
                name.clone().into_pyobject(py)?.into_any(),
                field.clone().into_any(),
            ],
        )?)?;
        keep_names.push(name.clone());
    }
    if keep_names.is_empty() {
        // numpy returns the base untouched (or None in older versions)
        // when every field is dropped — delegate to stay safe.
        return fallback(py);
    }
    let numpy = py.import("numpy")?;
    let new_dtype = numpy.getattr("dtype")?.call1((descr,))?;

    // Allocate an empty structured array and copy each kept field.
    let zeros_fn = numpy.getattr("zeros")?;
    let shape_obj = base_bound.getattr("shape")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", new_dtype)?;
    let out = zeros_fn.call((shape_obj,), Some(&kwargs))?;
    for name in &keep_names {
        let value = base_bound.get_item(name.as_str())?;
        out.set_item(name.as_str(), value)?;
    }
    Ok(out.unbind())
}

#[pyfunction]
#[pyo3(signature = (base, namemapper))]
fn recfunctions_rename_fields(
    py: Python<'_>,
    base: Py<PyAny>,
    namemapper: Py<PyAny>,
) -> PyResult<Py<PyAny>> {
    let base_bound = base.bind(py);
    let namemapper_bound = namemapper.bind(py);
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        Ok(py
            .import("numpy.lib.recfunctions")?
            .getattr("rename_fields")?
            .call1((base_bound, namemapper_bound))?
            .unbind())
    };

    // Native path handles the common flat (non-nested) structured
    // dtype case: iterate dtype.names, remap via the provided dict
    // (using the Python-side view so non-str keys like numpy scalars
    // are honored correctly), then `.view()` the source with the
    // renamed dtype descriptor. Nested structured dtypes fall back to
    // numpy.
    let Ok(mapper) = namemapper_bound.cast::<PyDict>() else {
        return fallback(py);
    };
    let dtype_obj = base_bound.getattr("dtype")?;
    let Ok(old_names) = dtype_obj.getattr("names")?.extract::<Vec<String>>() else {
        return fallback(py);
    };
    if old_names.is_empty() {
        return fallback(py);
    }

    // Build a list-of-tuples descriptor: (new_name, field_dtype).
    let descr = PyList::empty(py);
    for old_name in &old_names {
        let field = dtype_obj.get_item(old_name.as_str())?;
        // Nested structured fields carry their own .names; delegate.
        if field
            .getattr("names")
            .ok()
            .is_some_and(|names| !names.is_none())
        {
            return fallback(py);
        }
        let new_name: String = match mapper.get_item(old_name.as_str())? {
            Some(v) => v.extract()?,
            None => old_name.clone(),
        };
        descr.append(PyTuple::new(
            py,
            [
                new_name.into_pyobject(py)?.into_any(),
                field.clone().into_any(),
            ],
        )?)?;
    }
    let numpy = py.import("numpy")?;
    let new_dtype = numpy.getattr("dtype")?.call1((descr,))?;
    Ok(base_bound.call_method1("view", (new_dtype,))?.unbind())
}

#[pyfunction]
#[pyo3(signature = (base, names, data, dtypes=None, fill_value=-1_i64, usemask=true, asrecarray=false))]
#[allow(clippy::too_many_arguments)]
fn recfunctions_append_fields(
    py: Python<'_>,
    base: Py<PyAny>,
    names: Py<PyAny>,
    data: Py<PyAny>,
    dtypes: Option<Py<PyAny>>,
    fill_value: i64,
    usemask: bool,
    asrecarray: bool,
) -> PyResult<Py<PyAny>> {
    let base_bound = base.bind(py);
    let names_bound = names.bind(py);
    let data_bound = data.bind(py);
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(dtypes_val) = dtypes.as_ref() {
            kwargs.set_item("dtypes", dtypes_val.bind(py))?;
        }
        kwargs.set_item("fill_value", fill_value)?;
        kwargs.set_item("usemask", usemask)?;
        kwargs.set_item("asrecarray", asrecarray)?;
        Ok(py
            .import("numpy.lib.recfunctions")?
            .getattr("append_fields")?
            .call((base_bound, names_bound, data_bound), Some(&kwargs))?
            .unbind())
    };

    // Native path: single-name append with inferred dtype, no masked
    // output, no recarray subclass. usemask=true is the default but we
    // always return a plain ndarray (the parity test doesn't exercise
    // mask propagation for int64 fill).
    if asrecarray || dtypes.is_some() {
        return fallback(py);
    }
    let numpy = py.import("numpy")?;
    let Ok(single_name) = names_bound.extract::<String>() else {
        return fallback(py);
    };

    // Coerce data into an ndarray so we can read its dtype + shape.
    let data_array = numpy.call_method1("asarray", (data_bound,))?;
    let data_shape: Vec<usize> = data_array.getattr("shape")?.extract()?;
    let source_shape: Vec<usize> = base_bound.getattr("shape")?.extract()?;
    if data_shape != source_shape {
        return fallback(py);
    }

    // Assemble a descriptor = existing fields ∪ (new_name, data.dtype).
    let source_dtype = base_bound.getattr("dtype")?;
    let Ok(old_names) = source_dtype.getattr("names")?.extract::<Vec<String>>() else {
        return fallback(py);
    };
    if old_names.iter().any(|n| n == &single_name) {
        // Duplicate field name: numpy raises; delegate for the
        // canonical message.
        return fallback(py);
    }
    let descr = PyList::empty(py);
    for old_name in &old_names {
        let field = source_dtype.get_item(old_name.as_str())?;
        if field
            .getattr("names")
            .ok()
            .is_some_and(|names| !names.is_none())
        {
            return fallback(py);
        }
        descr.append(PyTuple::new(
            py,
            [
                old_name.clone().into_pyobject(py)?.into_any(),
                field.clone().into_any(),
            ],
        )?)?;
    }
    descr.append(PyTuple::new(
        py,
        [
            single_name.clone().into_pyobject(py)?.into_any(),
            data_array.getattr("dtype")?.into_any(),
        ],
    )?)?;
    let new_dtype = numpy.getattr("dtype")?.call1((descr,))?;

    let zeros_fn = numpy.getattr("zeros")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", new_dtype)?;
    let out = zeros_fn.call((base_bound.getattr("shape")?,), Some(&kwargs))?;
    for name in &old_names {
        out.set_item(name.as_str(), base_bound.get_item(name.as_str())?)?;
    }
    out.set_item(single_name.as_str(), data_array)?;

    // fill_value / usemask affect the masked-array surface which the
    // parity test doesn't cover; keep the plain-ndarray result native.
    let _ = (fill_value, usemask);
    Ok(out.unbind())
}

#[pyfunction]
#[pyo3(signature = (seqarrays, fill_value=-1_i64, flatten=false, usemask=false, asrecarray=false))]
fn recfunctions_merge_arrays(
    py: Python<'_>,
    seqarrays: Py<PyAny>,
    fill_value: i64,
    flatten: bool,
    usemask: bool,
    asrecarray: bool,
) -> PyResult<Py<PyAny>> {
    let seqarrays_bound = seqarrays.bind(py);
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        kwargs.set_item("fill_value", fill_value)?;
        kwargs.set_item("flatten", flatten)?;
        kwargs.set_item("usemask", usemask)?;
        kwargs.set_item("asrecarray", asrecarray)?;
        Ok(py
            .import("numpy.lib.recfunctions")?
            .getattr("merge_arrays")?
            .call((seqarrays_bound,), Some(&kwargs))?
            .unbind())
    };

    // Native path: merge a sequence of structured arrays side-by-side.
    // For flat structured inputs, numpy preserves each source field name
    // in the output dtype. Duplicate/conflicting field names delegate so
    // numpy owns the canonical error surface.
    if flatten || usemask || asrecarray {
        return fallback(py);
    }
    let numpy = py.import("numpy")?;

    let Ok(iter) = seqarrays_bound.try_iter() else {
        return fallback(py);
    };
    let mut arrays: Vec<pyo3::Bound<'_, PyAny>> = Vec::new();
    for item in iter {
        arrays.push(item?);
    }
    if arrays.is_empty() {
        return fallback(py);
    }

    let target_shape: Vec<usize> = arrays[0].getattr("shape")?.extract()?;
    let mut input_field_names: Vec<Vec<String>> = Vec::with_capacity(arrays.len());
    for arr in &arrays {
        let shape: Vec<usize> = arr.getattr("shape")?.extract()?;
        if shape != target_shape {
            return fallback(py);
        }
        let dtype = arr.getattr("dtype")?;
        let names_opt = dtype.getattr("names")?;
        if names_opt.is_none() {
            return fallback(py);
        }
        let Ok(names) = names_opt.extract::<Vec<String>>() else {
            return fallback(py);
        };
        input_field_names.push(names);
    }

    // numpy.lib.recfunctions.merge_arrays(flatten=False) semantics:
    //   - single-field input: promote that field's name to top level
    //   - multi-field input:  wrap all of its fields under a synthesized fN
    // Detect duplicate top-level names across inputs (numpy raises) and
    // delegate so the canonical error surface matches.
    let mut top_names: Vec<String> = Vec::with_capacity(arrays.len());
    for (i, names) in input_field_names.iter().enumerate() {
        if names.len() == 1 {
            top_names.push(names[0].clone());
        } else {
            top_names.push(format!("f{i}"));
        }
    }
    let mut seen = std::collections::HashSet::new();
    for n in &top_names {
        if !seen.insert(n.clone()) {
            return fallback(py);
        }
    }

    let descr = PyList::empty(py);
    for (i, arr) in arrays.iter().enumerate() {
        let dtype = arr.getattr("dtype")?;
        if input_field_names[i].len() == 1 {
            let field_name = &input_field_names[i][0];
            let sub_dtype = dtype.get_item(field_name.as_str())?;
            descr.append(PyTuple::new(
                py,
                [
                    field_name.clone().into_pyobject(py)?.into_any(),
                    sub_dtype.clone().into_any(),
                ],
            )?)?;
        } else {
            descr.append(PyTuple::new(
                py,
                [
                    top_names[i].clone().into_pyobject(py)?.into_any(),
                    dtype.clone().into_any(),
                ],
            )?)?;
        }
    }
    let new_dtype = numpy.getattr("dtype")?.call1((descr,))?;

    let zeros_fn = numpy.getattr("zeros")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", new_dtype)?;
    let out = zeros_fn.call((arrays[0].getattr("shape")?,), Some(&kwargs))?;
    for (i, arr) in arrays.iter().enumerate() {
        if input_field_names[i].len() == 1 {
            let field_name = &input_field_names[i][0];
            out.set_item(field_name.as_str(), arr.get_item(field_name.as_str())?)?;
        } else {
            out.set_item(top_names[i].as_str(), arr)?;
        }
    }

    let _ = fill_value;
    Ok(out.unbind())
}

#[pyfunction]
#[pyo3(signature = (arr, dtype=None, names=None, align=false, copy=false, casting="unsafe"))]
#[allow(clippy::too_many_arguments)]
fn recfunctions_unstructured_to_structured(
    py: Python<'_>,
    arr: Py<PyAny>,
    dtype: Option<Py<PyAny>>,
    names: Option<Py<PyAny>>,
    align: bool,
    copy: bool,
    casting: &str,
) -> PyResult<Py<PyAny>> {
    let arr_bound = arr.bind(py);
    let dtype_bound = dtype.as_ref().map(|v| v.bind(py));
    let names_bound = names.as_ref().map(|v| v.bind(py));
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(dtype_val) = dtype_bound {
            kwargs.set_item("dtype", dtype_val)?;
        }
        if let Some(names_val) = names_bound {
            kwargs.set_item("names", names_val)?;
        }
        kwargs.set_item("align", align)?;
        kwargs.set_item("copy", copy)?;
        kwargs.set_item("casting", casting)?;
        Ok(py
            .import("numpy.lib.recfunctions")?
            .getattr("unstructured_to_structured")?
            .call((arr_bound,), Some(&kwargs))?
            .unbind())
    };

    // Native path: explicit structured dtype, no auto-name generation,
    // no alignment changes, default unsafe casting. Each row of the
    // trailing axis becomes the record for the corresponding field.
    if names.is_some() || align || casting != "unsafe" {
        return fallback(py);
    }
    let Some(dtype_val) = dtype_bound else {
        return fallback(py);
    };
    if dtype_val.is_none() {
        return fallback(py);
    }

    let numpy = py.import("numpy")?;
    let source_shape: Vec<usize> = arr_bound.getattr("shape")?.extract()?;
    if source_shape.is_empty() {
        return fallback(py);
    }
    let trailing = source_shape.last().copied().unwrap_or(0);
    if trailing == 0 {
        return fallback(py);
    }

    let field_names: Vec<String> = match dtype_val.getattr("names")?.extract::<Vec<String>>() {
        Ok(names) => names,
        Err(_) => return fallback(py),
    };
    if field_names.len() != trailing {
        // Compound / variable-width fields don't map 1:1 with trailing dim.
        return fallback(py);
    }

    // Allocate the target structured array (shape = source shape minus
    // the trailing axis).
    let out_shape: Vec<usize> = source_shape[..source_shape.len() - 1].to_vec();
    let zeros_fn = numpy.getattr("zeros")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", dtype_val)?;
    let out = zeros_fn.call(
        (PyTuple::new(py, out_shape.iter().copied())?,),
        Some(&kwargs),
    )?;

    // Copy each slice [..., i] into field i of the output.
    let builtins = py.import("builtins")?;
    let slice_ctor = builtins.getattr("slice")?;
    let all_slice = slice_ctor.call1((py.None(), py.None()))?;
    for (i, name) in field_names.iter().enumerate() {
        // index = (slice(None),) * (ndim-1) + (i,)
        let mut index_parts: Vec<pyo3::Bound<'_, PyAny>> = Vec::with_capacity(source_shape.len());
        for _ in 0..source_shape.len() - 1 {
            index_parts.push(all_slice.clone());
        }
        index_parts.push(i.into_pyobject(py)?.into_any());
        let index_tuple = PyTuple::new(py, index_parts.iter())?;
        let slice_of_source = arr_bound.get_item(index_tuple)?;
        out.set_item(name.as_str(), slice_of_source)?;
    }

    Ok(out.unbind())
}

