#[pyfunction]
#[pyo3(signature = (a, axis=None, fill_value=None, out=None, *, keepdims=false))]
fn ma_argmax(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    fill_value: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    keepdims: bool,
) -> PyResult<Py<PyAny>> {
    // The native extract->masked.argmax path widens non-f64 masked data (~3.4x for int/f32) and
    // never beats numpy.ma.argmax even for f64 (1.33x). Delegate to numpy for parity across dtypes.
    let numpy = py.import("numpy")?;
    let kwargs = PyDict::new(py);
    if let Some(axis_val) = &axis {
        kwargs.set_item("axis", axis_val.bind(py))?;
    }
    if let Some(fv) = &fill_value {
        kwargs.set_item("fill_value", fv.bind(py))?;
    }
    if let Some(out_val) = &out {
        kwargs.set_item("out", out_val.bind(py))?;
    }
    kwargs.set_item("keepdims", keepdims)?;
    Ok(numpy
        .getattr("ma")?
        .getattr("argmax")?
        .call((a.bind(py),), Some(&kwargs))?
        .unbind())
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, fill_value=None, out=None, *, keepdims=false))]
fn ma_argmin(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    fill_value: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    keepdims: bool,
) -> PyResult<Py<PyAny>> {
    // Delegate to numpy.ma.argmin: the native extract->masked.argmin path widens non-f64 (~3x) and
    // never beats numpy (f64 1.29x). Parity across dtypes (cf ma_argmax).
    let numpy = py.import("numpy")?;
    let kwargs = PyDict::new(py);
    if let Some(axis_val) = &axis {
        kwargs.set_item("axis", axis_val.bind(py))?;
    }
    if let Some(fv) = &fill_value {
        kwargs.set_item("fill_value", fv.bind(py))?;
    }
    if let Some(out_val) = &out {
        kwargs.set_item("out", out_val.bind(py))?;
    }
    kwargs.set_item("keepdims", keepdims)?;
    Ok(numpy
        .getattr("ma")?
        .getattr("argmin")?
        .call((a.bind(py),), Some(&kwargs))?
        .unbind())
}

// Native fast path for the common case: np.pad(x, pad_width, mode="constant") with
// default constant_values=0 on a 1-D f64 C-contiguous ndarray. np.pad is a Python
// function whose mode dispatch + pad_width normalization cost ~9us even for a trivial
// pad; this allocates numpy.empty, zeros the two edges, and memcpys the input interior
// — bit-identical to numpy (placement + zeros, no arithmetic). Returns None (defer to
// np.pad) for any non-constant mode, any kwargs (e.g. explicit constant_values),
// non-f64 / non-1-D / non-contiguous input, or an unrecognized pad_width form.
fn try_zerocopy_f64_pad_1d_constant(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    array: &Bound<'_, PyAny>,
    pad_width: &Bound<'_, PyAny>,
    mode: &str,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Option<Py<PyAny>>> {
    if mode != "constant" {
        return Ok(None);
    }
    if kwargs.is_some_and(|k| !k.is_empty()) {
        return Ok(None); // only the default constant_values=0
    }
    if !array.is_exact_instance(&numpy.getattr("ndarray")?) {
        return Ok(None);
    }
    let dtype = array.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    let Ok(buffer) = PyBuffer::<f64>::get(array) else {
        return Ok(None);
    };
    if buffer.shape().len() != 1 || !buffer.is_c_contiguous() {
        return Ok(None);
    }
    // pad_width: int -> (k,k); (before,after); or [(before,after)] (single-axis).
    let (before, after) = if let Ok(k) = pad_width.extract::<usize>() {
        (k, k)
    } else if let Ok(ba) = pad_width.extract::<(usize, usize)>() {
        ba
    } else if let Ok(v) = pad_width.extract::<Vec<(usize, usize)>>() {
        if v.len() != 1 {
            return Ok(None);
        }
        v[0]
    } else {
        return Ok(None);
    };
    let Some(cells) = buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = cells.len();
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only under the GIL.
    let data: &[f64] = unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), n) };
    let total = before + n + after;
    let out_kwargs = PyDict::new(py);
    out_kwargs.set_item("dtype", "float64")?;
    let out = numpy.call_method("empty", (total,), Some(&out_kwargs))?;
    {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&out) else {
            return Ok(None);
        };
        let Some(out_cells) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // SAFETY: freshly allocated numpy.empty output, cannot alias array; every
        // element is written exactly once (edges zeroed, interior copied).
        let o: &mut [f64] =
            unsafe { std::slice::from_raw_parts_mut(out_cells.as_ptr() as *mut f64, total) };
        o[..before].fill(0.0);
        o[before + n..].fill(0.0);
        o[before..before + n].copy_from_slice(data);
    }
    Ok(Some(out.unbind()))
}

// Byte-level native fast path for np.pad(x, pad_width, mode="constant") with default
// constant_values=0 on a 1-D C-contiguous ndarray of ANY numeric kind (f/i/u/c/b). For
// these kinds the fill value 0 is all-zero bytes, so the pad is dtype-agnostic: view the
// buffer as uint8, allocate numpy.empty(total, same dtype), zero the two edge byte-runs,
// memcpy the interior bytes — bit-identical to numpy. This covers f32/int*/complex/bool
// (the f64 path above handles f64 with the slightly-faster direct buffer). numpy.pad's
// ~us Python dispatch otherwise costs ~1.1-1.5x. Datetime/timedelta (M/m, 0 bytes != the
// cast fill), strings/void (S/U/V), and any kwargs/non-constant mode defer.
fn try_zerocopy_pad_bytes_1d_constant(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    array: &Bound<'_, PyAny>,
    pad_width: &Bound<'_, PyAny>,
    mode: &str,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Option<Py<PyAny>>> {
    if mode != "constant" {
        return Ok(None);
    }
    if kwargs.is_some_and(|k| !k.is_empty()) {
        return Ok(None);
    }
    if !array.is_exact_instance(&numpy.getattr("ndarray")?) {
        return Ok(None);
    }
    let dtype = array.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if !matches!(kind.as_str(), "f" | "i" | "u" | "c" | "b") {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    if itemsize == 0 {
        return Ok(None);
    }
    let shape: Vec<usize> = array.getattr("shape")?.extract()?;
    if shape.len() != 1
        || !array
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return Ok(None);
    }
    let n = shape[0];
    let (before, after) = if let Ok(k) = pad_width.extract::<usize>() {
        (k, k)
    } else if let Ok(ba) = pad_width.extract::<(usize, usize)>() {
        ba
    } else if let Ok(v) = pad_width.extract::<Vec<(usize, usize)>>() {
        if v.len() != 1 {
            return Ok(None);
        }
        v[0]
    } else {
        return Ok(None);
    };
    let uint8 = numpy.getattr("uint8")?;
    let in_u8 = array.call_method1("view", (&uint8,))?;
    let Ok(in_buf) = PyBuffer::<u8>::get(&in_u8) else {
        return Ok(None);
    };
    let Some(in_cells) = in_buf.as_slice(py) else {
        return Ok(None);
    };
    let nbytes = n * itemsize;
    if in_cells.len() != nbytes {
        return Ok(None);
    }
    // SAFETY: ReadOnlyCell<u8> is repr(transparent) over u8; read-only under the GIL.
    let in_data: &[u8] = unsafe { std::slice::from_raw_parts(in_cells.as_ptr().cast::<u8>(), nbytes) };
    let total = before + n + after;
    let out_kwargs = PyDict::new(py);
    out_kwargs.set_item("dtype", &dtype)?;
    let out = numpy.call_method("empty", (total,), Some(&out_kwargs))?;
    {
        let out_u8 = out.call_method1("view", (&uint8,))?;
        let Ok(out_buf) = PyBuffer::<u8>::get(&out_u8) else {
            return Ok(None);
        };
        let Some(out_cells) = out_buf.as_mut_slice(py) else {
            return Ok(None);
        };
        let total_bytes = total * itemsize;
        // SAFETY: freshly allocated numpy.empty output viewed as uint8, cannot alias
        // array; every byte is written exactly once (edges zeroed, interior copied).
        let o: &mut [u8] =
            unsafe { std::slice::from_raw_parts_mut(out_cells.as_ptr() as *mut u8, total_bytes) };
        let lead = before * itemsize;
        o[..lead].fill(0);
        o[lead + nbytes..].fill(0);
        o[lead..lead + nbytes].copy_from_slice(in_data);
    }
    Ok(Some(out.unbind()))
}

#[pyfunction]
#[pyo3(signature = (array, pad_width, mode="constant", **kwargs))]
fn pad(
    py: Python<'_>,
    array: Py<PyAny>,
    pad_width: Py<PyAny>,
    mode: &str,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    // Passthrough to np.pad. Supports scalar/tuple/ndarray pad_width,
    // the full mode set (constant, edge, linear_ramp, maximum, mean,
    // median, minimum, reflect, symmetric, wrap, empty), and all
    // mode-specific kwargs (constant_values, end_values, stat_length,
    // reflect_type). Extra kwargs forward through verbatim so the full
    // numpy surface is exposed.
    let numpy = py.import("numpy")?;
    // Native 1-D constant-mode fast path (bypasses np.pad's ~9us Python dispatch).
    if let Some(out) =
        try_zerocopy_f64_pad_1d_constant(py, &numpy, array.bind(py), pad_width.bind(py), mode, kwargs)?
    {
        return Ok(out);
    }
    // Same fast path for non-f64 numeric dtypes (f32/int*/complex/bool) via a byte copy.
    if let Some(out) =
        try_zerocopy_pad_bytes_1d_constant(py, &numpy, array.bind(py), pad_width.bind(py), mode, kwargs)?
    {
        return Ok(out);
    }
    let call_kwargs = PyDict::new(py);
    call_kwargs.set_item("mode", mode)?;
    if let Some(extras) = kwargs {
        for (k, v) in extras.iter() {
            call_kwargs.set_item(k, v)?;
        }
    }
    Ok(numpy
        .getattr("pad")?
        .call((array.bind(py), pad_width.bind(py)), Some(&call_kwargs))?
        .unbind())
}

#[pyfunction]
#[pyo3(signature = (a,))]
fn linalg_eig(py: Python<'_>, a: Py<PyAny>) -> PyResult<Py<PyAny>> {
    // Passthrough to np.linalg.eig. Returns (eigenvalues, eigenvectors)
    // for a general square matrix. Matches numpy on real matrices with
    // real eigenvalues, real matrices with complex-conjugate pairs,
    // complex input, and 3-D batched input (last two axes).
    let numpy = py.import("numpy")?;
    Ok(numpy
        .getattr("linalg")?
        .getattr("eig")?
        .call1((a.bind(py),))?
        .unbind())
}

#[pyfunction]
#[pyo3(signature = (x, y, deg, rcond=None, full=false, w=None, cov=None))]
#[allow(clippy::too_many_arguments)]
fn polyfit(
    py: Python<'_>,
    x: Py<PyAny>,
    y: Py<PyAny>,
    deg: i64,
    rcond: Option<Py<PyAny>>,
    full: bool,
    w: Option<Py<PyAny>>,
    cov: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    // Passthrough to np.polyfit. Least-squares polynomial fit of degree
    // `deg`. Matches numpy for scalar/array rcond, the `full` residual
    // tuple surface, optional weights, and cov ∈ {False, True, 'unscaled'}.
    let numpy = py.import("numpy")?;
    let kwargs = PyDict::new(py);
    if let Some(rcond_val) = rcond {
        kwargs.set_item("rcond", rcond_val.bind(py))?;
    }
    kwargs.set_item("full", full)?;
    if let Some(w_val) = w {
        kwargs.set_item("w", w_val.bind(py))?;
    }
    if let Some(cov_val) = cov {
        kwargs.set_item("cov", cov_val.bind(py))?;
    }
    Ok(numpy
        .getattr("polyfit")?
        .call((x.bind(py), y.bind(py), deg), Some(&kwargs))?
        .unbind())
}

#[pyfunction]
#[pyo3(signature = (x, /, *, keepdims=false, ord=None))]
fn linalg_matrix_norm(
    py: Python<'_>,
    x: Py<PyAny>,
    keepdims: bool,
    ord: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    // Array-API matrix norm on the last two axes. The SVD-derived orders
    // (ord=2 spectral = sigma_max, ord=-2 = sigma_min, ord='nuc' = sum of
    // singular values) run numpy's serial-C per-lane SVD on batched (..., M, N)
    // inputs; route those through fnp_linalg::batch_svd (parallel per-lane) —
    // same parity-safe class as batched svdvals/cond (singular values are
    // deterministic, the norm result is allclose-level). The cheap orders
    // (Frobenius/None, 1, -1, inf, -inf are row/col-sum reductions, not SVD) and
    // every 2-D / complex / non-finite case stay on the numpy passthrough.
    let numpy = py.import("numpy")?;
    // svd_mode: 0 = spectral (sigma_max), 1 = neg-spectral (sigma_min),
    // 2 = nuclear (sum). None = not an SVD-derived order.
    let svd_mode: Option<u8> = ord.as_ref().and_then(|ord_val| {
        let bound = ord_val.bind(py);
        if let Ok(text) = bound.extract::<String>() {
            if text == "nuc" {
                Some(2)
            } else {
                None
            }
        } else if let Ok(f) = bound.extract::<f64>() {
            if f == 2.0 {
                Some(0)
            } else if f == -2.0 {
                Some(1)
            } else {
                None
            }
        } else {
            None
        }
    });
    if let Some(mode) = svd_mode {
        if let Ok(array) = extract_numeric_array(py, x.bind(py), "matrix_norm(x)") {
            let shape = array.shape();
            if shape.len() >= 3
                && matches!(array.dtype(), DType::F64)
                && !array.has_integer_sidecar()
                && array.values().iter().all(|v| v.is_finite())
            {
                let m_dim = shape[shape.len() - 2];
                let n_dim = shape[shape.len() - 1];
                let k = m_dim.min(n_dim);
                let owned_shape = shape.to_vec();
                if k >= 1 {
                    if let Ok(sigmas) = fnp_linalg::batch_svd(array.values(), &owned_shape) {
                        let batch = sigmas.len() / k;
                        let mut out = Vec::with_capacity(batch);
                        for b in 0..batch {
                            let lane = &sigmas[b * k..b * k + k];
                            out.push(match mode {
                                0 => lane[0],
                                1 => lane[k - 1],
                                _ => lane.iter().sum(),
                            });
                        }
                        let mut out_shape: Vec<usize> =
                            owned_shape[..owned_shape.len() - 2].to_vec();
                        if keepdims {
                            out_shape.push(1);
                            out_shape.push(1);
                        }
                        let result = UFuncArray::new(out_shape, out, DType::F64)
                            .map_err(map_ufunc_error)?;
                        return build_numpy_array_from_ufunc(py, &result);
                    }
                }
            }
        }
    }
    let kwargs = PyDict::new(py);
    kwargs.set_item("keepdims", keepdims)?;
    if let Some(ord_val) = ord {
        kwargs.set_item("ord", ord_val.bind(py))?;
    }
    Ok(numpy
        .getattr("linalg")?
        .getattr("matrix_norm")?
        .call((x.bind(py),), Some(&kwargs))?
        .unbind())
}

#[pyfunction]
#[pyo3(signature = (subscripts, *operands, optimize=None))]
fn einsum_path(
    py: Python<'_>,
    subscripts: &str,
    operands: &Bound<'_, PyTuple>,
    optimize: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    // Passthrough to np.einsum_path. Returns a (path_list, path_string)
    // tuple describing the optimal contraction order for an einsum
    // expression. The optimize kwarg accepts True/False/str/path-list
    // inputs exactly as numpy does; numpy's default is True so we
    // forward the caller value as-is without substituting our own.
    let numpy = py.import("numpy")?;
    let subscripts_obj = subscripts.into_pyobject(py)?.unbind();
    let mut call_items: Vec<Py<PyAny>> = vec![subscripts_obj.into_any()];
    for o in operands.iter() {
        call_items.push(o.clone().unbind());
    }
    let call_args = PyTuple::new(py, call_items)?;
    let kwargs = PyDict::new(py);
    if let Some(opt_val) = optimize {
        kwargs.set_item("optimize", opt_val.bind(py))?;
    }
    Ok(numpy
        .getattr("einsum_path")?
        .call(&call_args, Some(&kwargs))?
        .unbind())
}

#[pyfunction]
#[pyo3(signature = (x,))]
fn i0(py: Python<'_>, x: Py<PyAny>) -> PyResult<Py<PyAny>> {
    // Native implementation of modified Bessel function of the first kind, order 0.
    // Uses the Abramowitz and Stegun polynomial approximation via UnaryOp::I0.
    native_unary_promoting(py, x.bind(py), UnaryOp::I0, "i0", "i0(x)")
}

#[pyfunction]
#[pyo3(signature = (a, dtype=None))]
fn asfortranarray(py: Python<'_>, a: Py<PyAny>, dtype: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let asf_fn = numpy.getattr("asfortranarray")?;
        let kwargs = PyDict::new(py);
        if let Some(dtype_val) = dtype.as_ref() {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        Ok(asf_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    let a_bound = a.bind(py);
    // Fast path: already an F-contig ndarray with the right dtype → numpy
    // returns the same object. Preserve that identity contract.
    let ndarray_type = numpy.getattr("ndarray")?;
    let source_array = numpy.call_method1("asarray", (a_bound,))?;
    let requested_dtype = match dtype.as_ref() {
        Some(dtype_val) if !dtype_val.bind(py).is_none() => Some({
            let parsed = numpy.getattr("dtype")?.call1((dtype_val.bind(py),))?;
            let name = parsed.getattr("name")?.extract::<String>()?;
            match DType::parse(&name) {
                Some(value) if dtype_supported_by_numpy_export_bridge(value) => value,
                _ => return fallback(py),
            }
        }),
        _ => None,
    };
    let source_dtype_name = source_array
        .getattr("dtype")?
        .getattr("name")?
        .extract::<String>()?;
    let source_dtype = match DType::parse(&source_dtype_name) {
        Some(value) => value,
        None => return fallback(py),
    };
    if !dtype_supported_by_numpy_export_bridge(source_dtype) {
        return fallback(py);
    }
    let target_dtype = requested_dtype.unwrap_or(source_dtype);

    if target_dtype == source_dtype && source_array.is_exact_instance(&ndarray_type) {
        let flags = source_array.getattr("flags")?;
        let f_contig: bool = flags.get_item("F_CONTIGUOUS")?.extract()?;
        if f_contig {
            if a_bound.is_exact_instance(&ndarray_type) {
                return Ok(a_bound.clone().unbind());
            }
            return Ok(source_array.unbind());
        }
    }

    // A fresh F-contig copy is needed. The native extract -> UFuncArray ->
    // export-bridge rebuild was ~10-17x slower than numpy's typed memcpy; delegate
    // the copy (the F-contig identity fast path above is kept).
    let _ = target_dtype;
    fallback(py)
}

#[pyfunction]
#[pyo3(signature = (x,))]
fn isrealobj(x: Py<PyAny>) -> PyResult<bool> {
    // Rust-owned port of np.isrealobj. NumPy arrays and scalar dtypes
    // are classified by dtype; plain Python sequences recurse so lists
    // of complex values still report False while object arrays remain
    // non-complex because their dtype is object.
    Python::attach(|py| Ok(!python_is_complex_obj(x.bind(py))?))
}

/// Returns `true` when a native f64 reduction over `value` reproduces NumPy's
/// output dtype exactly. The native path computes in f64, so it matches NumPy
/// for bool/integer/unsigned inputs (NumPy's own promotion to int64/float64 is
/// preserved by the f64 kernel) and for `float64` floats, but it cannot
/// preserve float16/float32 (NumPy keeps the narrow float) or complex — those
/// must defer to NumPy. Any extraction error is treated as "not safe".
fn native_f64_reduction_preserves_dtype(py: Python<'_>, value: &Bound<'_, PyAny>) -> bool {
    let probe = || -> PyResult<bool> {
        let numpy = py.import("numpy")?;
        let array = numpy.call_method1("asarray", (value,))?;
        let dtype = array.getattr("dtype")?;
        let kind: String = dtype.getattr("kind")?.extract()?;
        let itemsize: usize = dtype.getattr("itemsize")?.extract()?;
        Ok(match kind.as_str() {
            "b" | "i" | "u" => true,
            "f" => itemsize == 8,
            _ => false,
        })
    };
    probe().unwrap_or(false)
}

/// Like [`native_f64_reduction_preserves_dtype`] but for min/max reductions,
/// which preserve the input dtype *exactly* (NumPy's `nanmax`/`nanmin` keep
/// int32/uint8 rather than promoting to int64/uint64 the way sum/prod do).
/// The native kernel widens integers to i64/u64 and floats to f64, so only
/// bool and the 8-byte numeric dtypes survive losslessly; everything else
/// must defer to NumPy. Any extraction error is treated as "not safe".
fn native_minmax_preserves_dtype(py: Python<'_>, value: &Bound<'_, PyAny>) -> bool {
    let probe = || -> PyResult<bool> {
        let numpy = py.import("numpy")?;
        let array = numpy.call_method1("asarray", (value,))?;
        let dtype = array.getattr("dtype")?;
        let kind: String = dtype.getattr("kind")?.extract()?;
        let itemsize: usize = dtype.getattr("itemsize")?.extract()?;
        Ok(match kind.as_str() {
            "b" => true,
            "i" | "u" | "f" => itemsize == 8,
            _ => false,
        })
    };
    probe().unwrap_or(false)
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, weights=None, returned=false, keepdims=false))]
fn average(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    weights: Option<Py<PyAny>>,
    returned: bool,
    keepdims: bool,
) -> PyResult<Py<PyAny>> {
    // Flat (axis=None) no-weights average == mean. numpy.average routes to
    // numpy.mean, whose SIMD pairwise sum is FASTER than our native
    // pairwise_simd_f64 (which only ever beat the COLD extract path, never numpy) —
    // so delegating straight to numpy is parity, while the old code ran two
    // np.asarray dtype probes and then the slower native kernel (~1.55x). Delegate
    // up front for every dtype; weighted and per-axis cases keep their native wins.
    if !keepdims
        && !returned
        && axis.as_ref().is_none_or(|v| v.bind(py).is_none())
        && weights.as_ref().is_none_or(|w| w.bind(py).is_none())
    {
        return Ok(py
            .import("numpy")?
            .getattr("average")?
            .call1((a.bind(py),))?
            .unbind());
    }
    let numpy = py.import("numpy")?;
    let avg_fn = numpy.getattr("average")?;
    let axis_for_parse = axis.as_ref().map(|value| value.clone_ref(py));
    let a_for_fallback = a.clone_ref(py);
    let weights_for_fallback = weights.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        if let Some(weights_val) = weights_for_fallback.as_ref() {
            kwargs.set_item("weights", weights_val.bind(py))?;
        }
        kwargs.set_item("returned", returned)?;
        kwargs.set_item("keepdims", keepdims)?;
        Ok(avg_fn
            .call((a_for_fallback.bind(py),), Some(&kwargs))?
            .unbind())
    };

    if keepdims {
        return fallback();
    }

    // The native f64 fast-path only reproduces NumPy when the output dtype is
    // float64. float16/float32/complex inputs (and weights that would alter the
    // result dtype) are preserved by NumPy, so defer those to numpy.average to
    // match both the averaged values and the returned sum-of-weights dtype.
    if !native_f64_reduction_preserves_dtype(py, a.bind(py)) {
        return fallback();
    }
    if let Some(weights_val) = weights.as_ref()
        && !native_f64_reduction_preserves_dtype(py, weights_val.bind(py))
    {
        return fallback();
    }

    // Integer/bool data or weights are f64-preserving (so they pass the checks above) but the f64
    // fast path below is f64-buffer-only -> they fell to the cold extract path (~5-6.4x). Delegate
    // to numpy.average for parity (the f64 fast path stays for true f64 data + f64 weights).
    if !numpy_dtype_is_f64(py, a.bind(py))
        || weights
            .as_ref()
            .is_some_and(|w| !w.bind(py).is_none() && !numpy_dtype_is_f64(py, w.bind(py)))
    {
        return fallback();
    }

    // Fused one-pass flat weighted average (axis=None) — avoids numpy's
    // multiply-into-temp + sum + the cold extract path (~3.6x slower).
    let axis_is_none = axis.as_ref().is_none_or(|v| v.bind(py).is_none());
    if axis_is_none
        && let Some(weights_val) = weights.as_ref()
        && let Some(out) =
            try_zerocopy_f64_average_flat(py, a.bind(py), weights_val.bind(py), returned)?
    {
        return Ok(out);
    }
    // Unweighted flat average (axis=None, no `returned`) == mean == bit-exact
    // pairwise sum / n; ~8x faster than the extract → native average path.
    if axis_is_none
        && !returned
        && weights.as_ref().is_none_or(|w| w.bind(py).is_none())
        && let Some(out) = try_zerocopy_f64_mean_flat(py, a.bind(py))?
    {
        return Ok(out);
    }
    // Fused per-axis f64 average. Exact dtype gates above keep float32/float16,
    // complex, keepdims, and incompatible weight cases on the NumPy fallback.
    if !axis_is_none
        && let Some(axis_val) = axis.as_ref()
        && let Some(out) = try_zerocopy_f64_average_axis(
            py,
            a.bind(py),
            weights.as_ref().map(|w| w.bind(py)),
            axis_val.bind(py),
            returned,
        )?
    {
        return Ok(out);
    }

    // Non-contiguous (transposed/strided) operands bail into the cold extract (~45x
    // slower); a tuple (multi-axis) reduction extracts then falls back on the axis
    // re-parse below (~10x wasted). Delegate both to numpy up front.
    if noncontiguous_ndarray(&numpy, a.bind(py))?
        || weights
            .as_ref()
            .is_some_and(|w| noncontiguous_ndarray(&numpy, w.bind(py)).unwrap_or(false))
        || axis
            .as_ref()
            .is_some_and(|ax| ax.bind(py).cast::<PyTuple>().is_ok())
    {
        return fallback();
    }
    let a = match extract_numeric_array(py, a.bind(py), "average(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let axis = match extract_axis_spec(py, axis_for_parse, "average") {
        Ok(None) => None,
        Ok(Some(axes)) if axes.len() == 1 => Some(axes[0]),
        Ok(Some(_)) => return fallback(),
        Err(_) => return fallback(),
    };

    let mut sum_of_weights = None;
    let average = match weights.as_ref() {
        None => {
            let average = match a.average(None, axis) {
                Ok(average) => average,
                Err(_) => return fallback(),
            };
            if returned {
                let sum = match axis {
                    None => UFuncArray::new(vec![], vec![a.values().len() as f64], DType::F64),
                    Some(axis) => {
                        let Some(axis) = try_normalize_axis(axis, a.shape().len()) else {
                            return fallback();
                        };
                        let out_len = match element_count(average.shape()) {
                            Ok(out_len) => out_len,
                            Err(_) => return fallback(),
                        };
                        UFuncArray::new(
                            average.shape().to_vec(),
                            vec![a.shape()[axis] as f64; out_len],
                            DType::F64,
                        )
                    }
                }
                .map_err(map_ufunc_error)?;
                sum_of_weights = Some(sum);
            }
            average
        }
        Some(weights) => {
            let weights = match extract_numeric_array(py, weights.bind(py), "average(weights)") {
                Ok(weights) => weights,
                Err(_) => return fallback(),
            };
            // NumPy raises ZeroDivisionError("Weights sum to zero, can't be
            // normalized") when the weights sum to zero; the native path would
            // divide by zero and yield NaN. Defer to numpy for the exact error.
            if weights.values().iter().sum::<f64>() == 0.0 {
                return fallback();
            }
            match axis {
                None => {
                    if weights.shape() != a.shape() {
                        return fallback();
                    }
                    if returned {
                        // NumPy computes scl = wgt.sum(dtype=result_dtype); for the
                        // float64-safe inputs that reach this path result_dtype is
                        // float64, so emit the weight total as F64 (mirrors the
                        // axis=Some branch) rather than the weights' native int dtype.
                        let weight_total = weights.values().iter().sum::<f64>();
                        sum_of_weights = Some(
                            UFuncArray::new(vec![], vec![weight_total], DType::F64)
                                .map_err(map_ufunc_error)?,
                        );
                    }
                    match a.average(Some(&weights), None) {
                        Ok(average) => average,
                        Err(_) => return fallback(),
                    }
                }
                Some(axis) => {
                    let Some(normalized_axis) = try_normalize_axis(axis, a.shape().len()) else {
                        return fallback();
                    };
                    if weights.shape() != [a.shape()[normalized_axis]] {
                        return fallback();
                    }

                    let average = match a.average(Some(&weights), Some(axis)) {
                        Ok(average) => average,
                        Err(_) => return fallback(),
                    };
                    if returned {
                        let weight_total = weights.values().iter().sum::<f64>();
                        let out_len = match element_count(average.shape()) {
                            Ok(out_len) => out_len,
                            Err(_) => return fallback(),
                        };
                        sum_of_weights = Some(
                            UFuncArray::new(
                                average.shape().to_vec(),
                                vec![weight_total; out_len],
                                DType::F64,
                            )
                            .map_err(map_ufunc_error)?,
                        );
                    }
                    average
                }
            }
        }
    };

    let average_output = build_numpy_scalar_or_array(py, &average)?;
    if returned {
        let sum_of_weights = sum_of_weights.expect("sum_of_weights must be set when returned=true");
        let sum_output = build_numpy_scalar_or_array(py, &sum_of_weights)?;
        return Ok(
            PyTuple::new(py, [average_output.bind(py), sum_output.bind(py)])?
                .into_any()
                .unbind(),
        );
    }
    Ok(average_output)
}

// Zero-copy flat weighted np.average: avg = Σ(a·w) / Σ(w) over the whole array
// (axis=None), fused into one pass with 8 independent accumulators (breaking the
// float-add dependency chain so the FMAs vectorize) instead of numpy's
// multiply-into-temp + pairwise sum + divide. Both buffers are f64 of equal shape.
// numpy's float reductions aren't bit-reproducible (pairwise vs this), but the
// 8-way sum matches to ~1e-14 — well inside np.allclose, the conformance bar.
// Returns None (caller defers) for non-f64, shape mismatch, empty, weights summing
// to zero (numpy ZeroDivisionError), or returned with a needed exact dtype.
fn try_zerocopy_f64_average_flat(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    weights: &Bound<'_, PyAny>,
    returned: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) || !weights.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let is_f64 = |x: &Bound<'_, PyAny>| -> PyResult<bool> {
        let dt = x.getattr("dtype")?;
        Ok(dt.getattr("kind")?.extract::<String>()? == "f"
            && dt.getattr("itemsize")?.extract::<usize>()? == 8)
    };
    if !is_f64(a)? || !is_f64(weights)? {
        return Ok(None);
    }
    let ash: Vec<usize> = a.getattr("shape")?.extract()?;
    let wsh: Vec<usize> = weights.getattr("shape")?.extract()?;
    if ash != wsh {
        return Ok(None); // axis=None requires identical shapes; else defer
    }
    let (Ok(ab), Ok(wb)) = (PyBuffer::<f64>::get(a), PyBuffer::<f64>::get(weights)) else {
        return Ok(None);
    };
    let (Some(asl), Some(wsl)) = (ab.as_slice(py), wb.as_slice(py)) else {
        return Ok(None);
    };
    let n = asl.len();
    if n == 0 {
        return Ok(None);
    }
    let mut dotacc = [0.0f64; 8];
    let mut wacc = [0.0f64; 8];
    let chunks = n / 8;
    for c in 0..chunks {
        let base = c * 8;
        for j in 0..8 {
            let ai = asl[base + j].get();
            let wi = wsl[base + j].get();
            dotacc[j] += ai * wi;
            wacc[j] += wi;
        }
    }
    let mut dot = 0.0f64;
    let mut wsum = 0.0f64;
    for j in 0..8 {
        dot += dotacc[j];
        wsum += wacc[j];
    }
    for i in chunks * 8..n {
        let ai = asl[i].get();
        let wi = wsl[i].get();
        dot += ai * wi;
        wsum += wi;
    }
    if wsum == 0.0 {
        return Ok(None); // numpy raises ZeroDivisionError; defer for the exact error
    }
    let avg = dot / wsum;
    let avg_scalar = numpy.getattr("float64")?.call1((avg,))?;
    if returned {
        let w_scalar = numpy.getattr("float64")?.call1((wsum,))?;
        return Ok(Some(
            PyTuple::new(py, [avg_scalar, w_scalar])?
                .into_any()
                .unbind(),
        ));
    }
    Ok(Some(avg_scalar.unbind()))
}

// Zero-copy per-axis np.average for exact f64 arrays reduced along one axis.
// Weighted last-axis lanes keep the existing 8-accumulator dot; unweighted lanes
// mirror the generic reduce_sum_axis_contiguous order for exact output-cell
// ordering while skipping Python-side extraction into UFuncArray. Cases outside
// the exact f64 single-axis contract return None so the existing NumPy-parity
// path owns dtype preservation, errors, keepdims, and shape corner cases.
fn try_zerocopy_f64_average_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    weights: Option<&Bound<'_, PyAny>>,
    axis_obj: &Bound<'_, PyAny>,
    returned: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let is_f64 = |x: &Bound<'_, PyAny>| -> PyResult<bool> {
        let dt = x.getattr("dtype")?;
        Ok(dt.getattr("kind")?.extract::<String>()? == "f"
            && dt.getattr("itemsize")?.extract::<usize>()? == 8)
    };
    if !is_f64(a)? {
        return Ok(None);
    }

    let Ok(ax_raw) = axis_obj.extract::<i64>() else {
        return Ok(None);
    };
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len() as i64;
    let ax = if ax_raw < 0 { ax_raw + ndim } else { ax_raw };
    if ax < 0 || ax >= ndim {
        return Ok(None);
    }
    let ax = ax as usize;
    let axis_len = shape[ax];
    if axis_len == 0 {
        return Ok(None);
    }
    let outer: usize = shape[..ax].iter().product();
    let inner: usize = shape[ax + 1..].iter().product();

    // Full-shape element-wise weights (w.shape == a.shape) along the contiguous LAST
    // axis: numpy weights each element and the denominator is the PER-LANE weight sum
    // (sum_j(a*w)/sum_j(w)), so the 1-D-weights path below (constant denominator)
    // can't serve it. Compute per-lane numerator+denominator with the same
    // 8-accumulator fold as the 1-D path, fanned across the rayon pool. A lane whose
    // weights sum to zero defers the whole call to numpy (it raises ZeroDivisionError).
    if let Some(w) = weights
        && is_f64(w)?
        && inner == 1
        && w.getattr("shape")?.extract::<Vec<usize>>()? == shape
    {
        let Ok(ab) = PyBuffer::<f64>::get(a) else {
            return Ok(None);
        };
        let Some(asl) = ab.as_slice(py) else {
            return Ok(None);
        };
        let Ok(wb) = PyBuffer::<f64>::get(w) else {
            return Ok(None);
        };
        let Some(wsl) = wb.as_slice(py) else {
            return Ok(None);
        };
        if asl.len() != outer * axis_len || wsl.len() != outer * axis_len {
            return Ok(None);
        }
        // SAFETY: read-only contiguous f64 buffers held under the GIL -> &[f64] (Sync).
        let adata: &[f64] =
            unsafe { std::slice::from_raw_parts(asl.as_ptr().cast::<f64>(), asl.len()) };
        let wdata: &[f64] =
            unsafe { std::slice::from_raw_parts(wsl.as_ptr().cast::<f64>(), wsl.len()) };
        use rayon::prelude::*;
        let lane_avg = |i: usize| -> (f64, f64) {
            let a_lane = &adata[i * axis_len..i * axis_len + axis_len];
            let w_lane = &wdata[i * axis_len..i * axis_len + axis_len];
            let mut num = [0.0f64; 8];
            let mut den = [0.0f64; 8];
            let chunks = axis_len / 8;
            for c in 0..chunks {
                let b = c * 8;
                for j in 0..8 {
                    num[j] += a_lane[b + j] * w_lane[b + j];
                    den[j] += w_lane[b + j];
                }
            }
            let mut n = 0.0f64;
            let mut d = 0.0f64;
            for j in 0..8 {
                n += num[j];
                d += den[j];
            }
            for k in chunks * 8..axis_len {
                n += a_lane[k] * w_lane[k];
                d += w_lane[k];
            }
            (n, d)
        };
        let parallel = outer * axis_len >= (1 << 16) && rayon::current_num_threads() >= 2;
        let pairs: Vec<(f64, f64)> = if parallel {
            (0..outer).into_par_iter().map(lane_avg).collect()
        } else {
            (0..outer).map(lane_avg).collect()
        };
        if pairs.iter().any(|(_, d)| *d == 0.0) {
            return Ok(None); // weights sum to zero on some lane — numpy raises; defer
        }
        let out_shape: Vec<usize> = shape[..ax].to_vec();
        let avg: Vec<f64> = pairs.iter().map(|(n, d)| n / d).collect();
        let avg_flat = numpy_array_from_slice(py, &numpy, &avg, "float64")?;
        let avg_arr = avg_flat
            .call_method1("reshape", (PyTuple::new(py, out_shape.iter().copied())?,))?;
        let avg_output = if out_shape.is_empty() {
            avg_arr.get_item(())?
        } else {
            avg_arr
        };
        if returned {
            let sow: Vec<f64> = pairs.iter().map(|(_, d)| *d).collect();
            let sow_flat = numpy_array_from_slice(py, &numpy, &sow, "float64")?;
            let sow_arr = sow_flat
                .call_method1("reshape", (PyTuple::new(py, out_shape.iter().copied())?,))?;
            let sow_output = if out_shape.is_empty() {
                sow_arr.get_item(())?
            } else {
                sow_arr
            };
            return Ok(Some(
                PyTuple::new(py, [avg_output, sow_output])?.into_any().unbind(),
            ));
        }
        return Ok(Some(avg_output.unbind()));
    }

    let (weights_vec, denominator) = match weights {
        Some(w) => {
            if !is_f64(w)? {
                return Ok(None);
            }
            let wshape: Vec<usize> = w.getattr("shape")?.extract()?;
            if wshape.len() != 1 || wshape[0] != axis_len {
                return Ok(None);
            }
            let Ok(wb) = PyBuffer::<f64>::get(w) else {
                return Ok(None);
            };
            let Some(wsl) = wb.as_slice(py) else {
                return Ok(None);
            };
            let wvec: Vec<f64> = wsl.iter().map(|cell| cell.get()).collect();
            let mut wsum = 0.0f64;
            for &weight in &wvec {
                wsum += weight;
            }
            if wsum == 0.0 {
                return Ok(None);
            }
            (Some(wvec), wsum)
        }
        None => {
            // The generic Rust path switches to compensated summation only for
            // extremely long axes. Defer there so the fast path keeps the same
            // floating-point order for all accelerated unweighted reductions.
            const COMPENSATED_SUM_MIN_LEN: usize = 1_000_000;
            if axis_len > COMPENSATED_SUM_MIN_LEN {
                return Ok(None);
            }
            (None, axis_len as f64)
        }
    };
    let invden = 1.0 / denominator;

    let Ok(ab) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    let Some(asl) = ab.as_slice(py) else {
        return Ok(None);
    };
    let total_out = outer * inner;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (total_out,), Some(&kwargs))?;
    if total_out > 0 {
        let Ok(ob) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(osl) = ob.as_mut_slice(py) else {
            return Ok(None);
        };
        if inner == 1 {
            if let Some(wvec) = weights_vec.as_ref() {
                let input_values = asl.iter().map(|cell| cell.get()).collect::<Vec<_>>();
                for (row, lane) in input_values.chunks_exact(axis_len).enumerate() {
                    let mut acc = [0.0f64; 8];
                    let chunks = axis_len / 8;
                    for chunk in 0..chunks {
                        let base = chunk * 8;
                        for j in 0..8 {
                            acc[j] += lane[base + j] * wvec[base + j];
                        }
                    }
                    let mut sum = 0.0f64;
                    for value in acc {
                        sum += value;
                    }
                    for i in chunks * 8..axis_len {
                        sum += lane[i] * wvec[i];
                    }
                    osl[row].set(sum * invden);
                }
            } else {
                for (row, lane) in asl.chunks_exact(axis_len).enumerate() {
                    let mut acc = [0.0f64; 8];
                    let mut chunks = lane.chunks_exact(8);
                    for group in chunks.by_ref() {
                        for (slot, value) in acc.iter_mut().zip(group.iter()) {
                            *slot += value.get();
                        }
                    }
                    let mut sum = acc.iter().sum::<f64>();
                    for value in chunks.remainder() {
                        sum += value.get();
                    }
                    if sum == 0.0 {
                        sum = 0.0;
                    }
                    osl[row].set(sum * invden);
                }
            }
        } else {
            let mut accs = vec![0.0f64; inner];
            if let Some(wvec) = weights_vec.as_ref() {
                for out_outer in 0..outer {
                    accs.fill(0.0);
                    let base = out_outer * axis_len * inner;
                    for axis_index in 0..axis_len {
                        let slab =
                            &asl[base + axis_index * inner..base + axis_index * inner + inner];
                        let weight = wvec[axis_index];
                        for (acc, value) in accs.iter_mut().zip(slab.iter()) {
                            *acc += value.get() * weight;
                        }
                    }
                    let out_base = out_outer * inner;
                    for inner_index in 0..inner {
                        osl[out_base + inner_index].set(accs[inner_index] * invden);
                    }
                }
            } else {
                for out_outer in 0..outer {
                    accs.fill(0.0);
                    let base = out_outer * axis_len * inner;
                    for axis_index in 0..axis_len {
                        let slab =
                            &asl[base + axis_index * inner..base + axis_index * inner + inner];
                        for (acc, value) in accs.iter_mut().zip(slab.iter()) {
                            *acc += value.get();
                        }
                    }
                    let out_base = out_outer * inner;
                    for inner_index in 0..inner {
                        let mut sum = accs[inner_index];
                        if sum == 0.0 {
                            sum = 0.0;
                        }
                        osl[out_base + inner_index].set(sum * invden);
                    }
                }
            }
        }
    }

    let mut out_shape: Vec<usize> = shape[..ax].to_vec();
    out_shape.extend_from_slice(&shape[ax + 1..]);
    let shape_tuple = PyTuple::new(py, out_shape.iter().copied())?;
    let avg_arr = flat.call_method1("reshape", (&shape_tuple,))?;
    let avg_output = if out_shape.is_empty() {
        avg_arr.get_item(())?
    } else {
        avg_arr
    };
    if returned {
        let sow = if out_shape.is_empty() {
            numpy.getattr("float64")?.call1((denominator,))?
        } else {
            let sum_kwargs = PyDict::new(py);
            sum_kwargs.set_item("dtype", "float64")?;
            numpy.call_method("full", (&shape_tuple, denominator), Some(&sum_kwargs))?
        };
        return Ok(Some(
            PyTuple::new(py, [avg_output, sow])?.into_any().unbind(),
        ));
    }
    Ok(Some(avg_output.unbind()))
}

#[pyfunction]
#[pyo3(signature = (actual, desired, err_msg=None, verbose=true, *, strict=false))]
fn testing_assert_equal(
    py: Python<'_>,
    actual: Py<PyAny>,
    desired: Py<PyAny>,
    err_msg: Option<String>,
    verbose: bool,
    strict: bool,
) -> PyResult<()> {
    // Passthrough to numpy.testing.assert_equal. Raises AssertionError
    // if the two inputs are not element-wise equal. Supports nested
    // dict/list structures, NaN-aware equality, and (in modern numpy)
    // strict dtype/shape enforcement.
    let numpy = py.import("numpy")?;
    let assert_fn = numpy.getattr("testing")?.getattr("assert_equal")?;
    let kwargs = PyDict::new(py);
    if let Some(msg) = err_msg {
        kwargs.set_item("err_msg", msg)?;
    }
    kwargs.set_item("verbose", verbose)?;
    if strict {
        kwargs.set_item("strict", true)?;
    }
    assert_fn.call((actual.bind(py), desired.bind(py)), Some(&kwargs))?;
    Ok(())
}

#[pyfunction]
#[pyo3(signature = (actual, desired, decimal=7_i64, err_msg=None, verbose=true))]
fn testing_assert_almost_equal(
    py: Python<'_>,
    actual: Py<PyAny>,
    desired: Py<PyAny>,
    decimal: i64,
    err_msg: Option<String>,
    verbose: bool,
) -> PyResult<()> {
    // Passthrough to numpy.testing.assert_almost_equal. Compares scalars
    // or arrays up to `decimal` places; raises AssertionError on
    // disagreement. Kept for backward compatibility with legacy numpy.
    let numpy = py.import("numpy")?;
    let assert_fn = numpy.getattr("testing")?.getattr("assert_almost_equal")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("decimal", decimal)?;
    if let Some(msg) = err_msg {
        kwargs.set_item("err_msg", msg)?;
    }
    kwargs.set_item("verbose", verbose)?;
    assert_fn.call((actual.bind(py), desired.bind(py)), Some(&kwargs))?;
    Ok(())
}

#[pyfunction]
#[pyo3(signature = (x, y, decimal=6_i64, err_msg=None, verbose=true))]
fn testing_assert_array_almost_equal(
    py: Python<'_>,
    x: Py<PyAny>,
    y: Py<PyAny>,
    decimal: i64,
    err_msg: Option<String>,
    verbose: bool,
) -> PyResult<()> {
    // Passthrough to numpy.testing.assert_array_almost_equal. Arrays
    // are compared element-wise up to `decimal` places; NaN positions
    // must match and shapes must agree.
    let numpy = py.import("numpy")?;
    let assert_fn = numpy
        .getattr("testing")?
        .getattr("assert_array_almost_equal")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("decimal", decimal)?;
    if let Some(msg) = err_msg {
        kwargs.set_item("err_msg", msg)?;
    }
    kwargs.set_item("verbose", verbose)?;
    assert_fn.call((x.bind(py), y.bind(py)), Some(&kwargs))?;
    Ok(())
}

#[pyfunction]
#[pyo3(signature = (x, y, err_msg=None, verbose=true, *, strict=false))]
fn testing_assert_array_less(
    py: Python<'_>,
    x: Py<PyAny>,
    y: Py<PyAny>,
    err_msg: Option<String>,
    verbose: bool,
    strict: bool,
) -> PyResult<()> {
    // Passthrough to numpy.testing.assert_array_less. Raises
    // AssertionError unless all x[i] < y[i] element-wise. NaN positions
    // cause failure on both implementations.
    let numpy = py.import("numpy")?;
    let assert_fn = numpy.getattr("testing")?.getattr("assert_array_less")?;
    let kwargs = PyDict::new(py);
    if let Some(msg) = err_msg {
        kwargs.set_item("err_msg", msg)?;
    }
    kwargs.set_item("verbose", verbose)?;
    if strict {
        kwargs.set_item("strict", true)?;
    }
    assert_fn.call((x.bind(py), y.bind(py)), Some(&kwargs))?;
    Ok(())
}

#[pyfunction]
#[pyo3(signature = (actual, desired, significant=7_i64, err_msg=None, verbose=true))]
fn testing_assert_approx_equal(
    py: Python<'_>,
    actual: f64,
    desired: f64,
    significant: i64,
    err_msg: Option<String>,
    verbose: bool,
) -> PyResult<()> {
    // Passthrough to numpy.testing.assert_approx_equal. Scalar-only
    // comparison up to `significant` significant digits; raises
    // AssertionError on disagreement.
    let numpy = py.import("numpy")?;
    let assert_fn = numpy.getattr("testing")?.getattr("assert_approx_equal")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("significant", significant)?;
    if let Some(msg) = err_msg {
        kwargs.set_item("err_msg", msg)?;
    }
    kwargs.set_item("verbose", verbose)?;
    assert_fn.call((actual, desired), Some(&kwargs))?;
    Ok(())
}

#[pyfunction]
#[pyo3(signature = (actual, desired))]
fn testing_assert_string_equal(py: Python<'_>, actual: &str, desired: &str) -> PyResult<()> {
    // u98f — native assert_string_equal. numpy's semantic is plain
    // string equality with an AssertionError on mismatch whose message
    // includes a difflib-rendered diff. We replicate the exact numpy
    // message format by routing through Python's stdlib difflib (no
    // numpy import required) so the helper works on numpy-less CI
    // workers and downstream log scrapers continue to match.
    if actual == desired {
        return Ok(());
    }
    // Replicate numpy.testing._private.utils.assert_string_equal:
    //   diff = list(difflib.Differ().compare(
    //       actual.splitlines(True), desired.splitlines(True)))
    //   diff = [d for d in diff if not d.startswith('? ')]
    //   if any non-equal markers: msg = "Differences in strings:\n" + ''.join(diff).rstrip()
    let difflib = py.import("difflib")?;
    let differ = difflib.getattr("Differ")?.call0()?;
    // 2axo: route through Python's str.splitlines(keepends=True) so
    // the canonical Python separator set (\r\n, \n, \r, \v, \f, \x1c,
    // \x1d, \x1e, \x85, U+2028, U+2029) is honored — the prior
    // hand-rolled lines_keepends only handled \n / \r / \r\n which
    // diverged from numpy on rare separators.
    let actual_py: Bound<'_, PyAny> = actual.into_pyobject(py)?.into_any();
    let desired_py: Bound<'_, PyAny> = desired.into_pyobject(py)?.into_any();
    let actual_lines = actual_py.call_method1("splitlines", (true,))?;
    let desired_lines = desired_py.call_method1("splitlines", (true,))?;
    let diff_iter = differ.call_method1("compare", (actual_lines, desired_lines))?;
    // Mirror numpy.testing._private.utils.assert_string_equal:
    // collect every diff line BUT only emit `- `/`+ `/`? ` markers for
    // changed pairs, dropping the `  ` lines that mark unchanged
    // context. The simple "skip `  ` and `? `" filter matches numpy's
    // emitted output exactly because the surrounding `? ` hint lines
    // already reference their adjacent `-`/`+` counterparts.
    let mut diff_lines: Vec<String> = Vec::new();
    for item in diff_iter.try_iter()? {
        let s: String = item?.extract()?;
        if s.starts_with("  ") {
            continue;
        }
        diff_lines.push(s);
    }
    if diff_lines.is_empty() {
        return Ok(());
    }
    let body = diff_lines.join("");
    let body = body.trim_end();
    Err(pyo3::exceptions::PyAssertionError::new_err(format!(
        "Differences in strings:\n{body}"
    )))
}

// 2axo: lines_keepends helper removed — testing_assert_string_equal now
// delegates to Python's str.splitlines(True) for canonical separator coverage.

#[pyfunction]
#[pyo3(signature = (actual, desired, rtol=1e-7, atol=0.0, equal_nan=true, err_msg=None, verbose=true))]
#[allow(clippy::too_many_arguments)]
fn testing_assert_allclose(
    py: Python<'_>,
    actual: Py<PyAny>,
    desired: Py<PyAny>,
    rtol: f64,
    atol: f64,
    equal_nan: bool,
    err_msg: Option<String>,
    verbose: bool,
) -> PyResult<()> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<()> {
        let assert_fn = numpy.getattr("testing")?.getattr("assert_allclose")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("rtol", rtol)?;
        kwargs.set_item("atol", atol)?;
        kwargs.set_item("equal_nan", equal_nan)?;
        if let Some(msg) = err_msg.as_ref() {
            kwargs.set_item("err_msg", msg)?;
        }
        kwargs.set_item("verbose", verbose)?;
        assert_fn.call((actual.bind(py), desired.bind(py)), Some(&kwargs))?;
        Ok(())
    };
    // Native path handles numeric (non-complex) inputs. Use our allclose
    // kernel with broadcasting to determine pass/fail. Delegate on complex
    // / object / integer-sidecar inputs so numpy owns the dispatch surface.
    let array_a =
        match extract_precise_numeric_array(py, actual.bind(py), "assert_allclose(actual)") {
            Ok(value) => value,
            Err(_) => return fallback(py),
        };
    let array_b =
        match extract_precise_numeric_array(py, desired.bind(py), "assert_allclose(desired)") {
            Ok(value) => value,
            Err(_) => return fallback(py),
        };
    if array_a.has_integer_sidecar()
        || array_b.has_integer_sidecar()
        || matches!(array_a.dtype(), DType::Complex64 | DType::Complex128)
        || matches!(array_b.dtype(), DType::Complex64 | DType::Complex128)
    {
        return fallback(py);
    }
    let verdict = match array_a.allclose_equal_nan(&array_b, rtol, atol, equal_nan) {
        Ok(value) => value,
        Err(_) => return fallback(py),
    };
    if verdict {
        return Ok(());
    }
    // Build a concise AssertionError: prepend user err_msg when provided
    // so the parity test's substring check (custom-marker) still passes.
    let header = match err_msg.as_ref() {
        Some(msg) if !msg.is_empty() => format!("{msg}\n"),
        _ => String::new(),
    };
    Err(pyo3::exceptions::PyAssertionError::new_err(format!(
        "{header}Not equal to tolerance rtol={rtol}, atol={atol}"
    )))
}

#[pyfunction]
#[pyo3(signature = (actual, desired, err_msg=None, verbose=true, strict=false))]
fn testing_assert_array_equal(
    py: Python<'_>,
    actual: Py<PyAny>,
    desired: Py<PyAny>,
    err_msg: Option<String>,
    verbose: bool,
    strict: bool,
) -> PyResult<()> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<()> {
        let assert_fn = numpy.getattr("testing")?.getattr("assert_array_equal")?;
        let kwargs = PyDict::new(py);
        if let Some(msg) = err_msg.as_ref() {
            kwargs.set_item("err_msg", msg)?;
        }
        kwargs.set_item("verbose", verbose)?;
        kwargs.set_item("strict", strict)?;
        assert_fn.call((actual.bind(py), desired.bind(py)), Some(&kwargs))?;
        Ok(())
    };
    if strict {
        // strict=True also enforces exact dtype/shape — delegate to numpy
        // so its dtype-name message surface stays exact.
        return fallback(py);
    }
    let array_a =
        match extract_precise_numeric_array(py, actual.bind(py), "assert_array_equal(actual)") {
            Ok(value) => value,
            Err(_) => return fallback(py),
        };
    let array_b =
        match extract_precise_numeric_array(py, desired.bind(py), "assert_array_equal(desired)") {
            Ok(value) => value,
            Err(_) => return fallback(py),
        };
    if array_a.has_integer_sidecar()
        || array_b.has_integer_sidecar()
        || matches!(array_a.dtype(), DType::Complex64 | DType::Complex128)
        || matches!(array_b.dtype(), DType::Complex64 | DType::Complex128)
    {
        return fallback(py);
    }
    // Use allclose_equal_nan with zero tolerance to get bit-exact equality
    // with NaN-same-position treatment (the default for assert_array_equal).
    let verdict = match array_a.allclose_equal_nan(&array_b, 0.0, 0.0, true) {
        Ok(value) => value,
        Err(_) => return fallback(py),
    };
    if verdict {
        return Ok(());
    }
    let header = match err_msg.as_ref() {
        Some(msg) if !msg.is_empty() => format!("{msg}\n"),
        _ => String::new(),
    };
    Err(pyo3::exceptions::PyAssertionError::new_err(format!(
        "{header}Arrays are not equal"
    )))
}

#[pyfunction]
#[pyo3(signature = (x,))]
fn matrix_transpose(py: Python<'_>, x: Py<PyAny>) -> PyResult<Py<PyAny>> {
    // numpy.matrix_transpose swaps the last two axes and returns a strided VIEW
    // (shares memory, writeable). The native path extracted to UFuncArray and
    // materialized a fresh C-order copy — ~18000x slower on a 2000x2000 (numpy ~1us
    // view vs ~13ms copy) AND a semantics divergence (the result no longer aliased
    // the input). A transpose is never faster materialized than as numpy's view, so
    // delegate unconditionally — restores both the view semantics and the speed.
    let numpy = py.import("numpy")?;
    Ok(numpy
        .getattr("linalg")?
        .getattr("matrix_transpose")?
        .call1((x.bind(py),))?
        .unbind())
}

#[pyfunction]
#[pyo3(signature = (x,))]
fn svdvals(py: Python<'_>, x: Py<PyAny>) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let svdvals_fn = numpy.getattr("linalg")?.getattr("svdvals")?;
    let fallback = || -> PyResult<Py<PyAny>> { Ok(svdvals_fn.call1((x.bind(py),))?.unbind()) };

    // Single 2-D input: the native pure-Rust SVD (x.svdvals()) loses to LAPACK gesdd
    // at EVERY size measured (1.2x at 8x8 up to 3.7x rectangular; 3.31x at 800x800) —
    // same class as the pinv 2-D loss. Delegate straight to numpy BEFORE the extract
    // copy (-> ~0.97x parity). Only the batched (>=3-D) path below stays native
    // (numpy loops serial per lane -> it wins, e.g. 500x16x16 0.18x).
    if let Ok(nd) = x
        .bind(py)
        .getattr("ndim")
        .and_then(|n| n.extract::<usize>())
        && nd == 2
    {
        return fallback();
    }

    let x = match extract_numeric_array(py, x.bind(py), "svdvals(x)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    // Batched (stacked) inputs (..., M, N): svdvals returns the singular values per
    // lane in descending order — deterministic, with no sign/phase ambiguity — so the
    // parallel batch_svd (rayon across lanes) is parity-safe (the allclose oracle
    // tolerates the ~2-ULP delta vs LAPACK). NumPy's batched svdvals is a serial
    // C per-lane loop, so this closes the no-gaps batched-SVD gap. Output shape =
    // batch dims + [min(M,N)]. Real finite f64 only; complex / non-finite / any Err
    // falls back to numpy.
    let shape = x.shape();
    if shape.len() >= 3
        && matches!(x.dtype(), DType::F64)
        && !x.has_integer_sidecar()
        && x.values().iter().all(|v| v.is_finite())
    {
        let m = shape[shape.len() - 2];
        let n = shape[shape.len() - 1];
        let k = m.min(n);
        let owned_shape = shape.to_vec();
        if let Ok(values) = fnp_linalg::batch_svd(x.values(), &owned_shape) {
            let mut out_shape: Vec<usize> = owned_shape[..owned_shape.len() - 2].to_vec();
            out_shape.push(k);
            let result =
                UFuncArray::new(out_shape, values, DType::F64).map_err(map_ufunc_error)?;
            return build_numpy_array_from_ufunc(py, &result);
        }
        return fallback();
    }
    let result = match x.svdvals() {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    build_numpy_array_from_ufunc(py, &result)
}

