// Zero-copy float64 np.eye(n, m, k): an n x m matrix of zeros with ones on the
// k-th diagonal. Allocates numpy.zeros((n, m)) and writes 1.0 onto the at most
// min(n, m) diagonal positions directly, with no intermediate Rust Vec of the
// full n*m result (bead lglck). The output is exactly identity-on-diagonal, so it
// is bit-identical to numpy (1.0 ones, +0.0 fill). The diagonal element (i, i+k)
// is valid for max(0,-k) <= i < min(n, m-k).
fn build_f64_eye(py: Python<'_>, n: usize, m: usize, k: i64) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let out = numpy.call_method("zeros", ((n, m),), Some(&kwargs))?;
    if n > 0 && m > 0 {
        let i_start = if k < 0 { (-k) as usize } else { 0 };
        let i_end = if k >= 0 {
            let mk = m as i64 - k;
            if mk <= 0 { 0 } else { n.min(mk as usize) }
        } else {
            n.min(m + (-k) as usize)
        };
        if i_start < i_end {
            let Ok(out_buffer) = PyBuffer::<f64>::get(&out) else {
                // Fall back to a per-element set through Python if the buffer is
                // unexpectedly unavailable (keeps the result correct).
                for i in i_start..i_end {
                    let j = (i as i64 + k) as usize;
                    out.call_method1("__setitem__", ((i, j), 1.0_f64))?;
                }
                return Ok(out.unbind());
            };
            if let Some(output) = out_buffer.as_mut_slice(py) {
                for i in i_start..i_end {
                    let j = (i as i64 + k) as usize;
                    output[i * m + j].set(1.0);
                }
            }
        }
    }
    Ok(out.unbind())
}

#[pyfunction]
#[pyo3(signature = (*args, **kwargs))]
fn eye(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let eye_fn = numpy.getattr("eye")?;
    let call_kwargs = PyDict::new(py);
    if let Some(kwargs) = kwargs {
        for (key, value) in kwargs.iter() {
            let name = key.extract::<String>()?;
            if name == "m" {
                call_kwargs.set_item("M", value)?;
            } else {
                call_kwargs.set_item(key, value)?;
            }
        }
    }
    let fallback =
        || -> PyResult<Py<PyAny>> { Ok(eye_fn.call(args, Some(&call_kwargs))?.unbind()) };

    if args.len() > 5 {
        return fallback();
    }
    for (key, _) in call_kwargs.iter() {
        match key.extract::<String>()?.as_str() {
            "N" | "M" | "k" | "dtype" | "order" => {}
            _ => return fallback(),
        }
    }
    if args.len() >= 1 && call_kwargs.contains("N")?
        || args.len() >= 2 && call_kwargs.contains("M")?
        || args.len() >= 3 && call_kwargs.contains("k")?
        || args.len() >= 4 && call_kwargs.contains("dtype")?
        || args.len() >= 5 && call_kwargs.contains("order")?
    {
        return fallback();
    }

    let n = if args.is_empty() {
        match call_kwargs.get_item("N")? {
            Some(value) => match value.extract::<i64>() {
                Ok(value) => value,
                Err(_) => return fallback(),
            },
            None => return fallback(),
        }
    } else {
        match args.get_item(0)?.extract::<i64>() {
            Ok(value) => value,
            Err(_) => return fallback(),
        }
    };
    let m = if args.len() >= 2 {
        let value = args.get_item(1)?;
        if value.is_none() {
            None
        } else {
            match value.extract::<i64>() {
                Ok(value) => Some(value),
                Err(_) => return fallback(),
            }
        }
    } else {
        match call_kwargs.get_item("M")? {
            Some(value) if value.is_none() => None,
            Some(value) => match value.extract::<i64>() {
                Ok(value) => Some(value),
                Err(_) => return fallback(),
            },
            None => None,
        }
    };
    let k = if args.len() >= 3 {
        match args.get_item(2)?.extract::<i64>() {
            Ok(value) => value,
            Err(_) => return fallback(),
        }
    } else {
        match call_kwargs.get_item("k")? {
            Some(value) => match value.extract::<i64>() {
                Ok(value) => value,
                Err(_) => return fallback(),
            },
            None => 0,
        }
    };
    let dtype = if args.len() >= 4 {
        let value = args.get_item(3)?;
        if value.is_none() {
            None
        } else {
            Some(value.unbind())
        }
    } else {
        match call_kwargs.get_item("dtype")? {
            Some(value) if value.is_none() => None,
            Some(value) => Some(value.unbind()),
            None => None,
        }
    };
    let order = if args.len() >= 5 {
        match args.get_item(4)?.extract::<String>() {
            Ok(value) => value,
            Err(_) => return fallback(),
        }
    } else {
        match call_kwargs.get_item("order")? {
            Some(value) => match value.extract::<String>() {
                Ok(value) => value,
                Err(_) => return fallback(),
            },
            None => String::from("C"),
        }
    };

    let dtype_for_parse = dtype.as_ref().map(|value| value.clone_ref(py));

    if order != "C" || n < 0 || m.is_some_and(|value| value < 0) {
        return fallback();
    }

    let dtype = match extract_python_dtype(py, dtype_for_parse, DType::F64, "eye(dtype)") {
        Ok(dtype) => dtype,
        Err(_) => return fallback(),
    };
    if !matches!(
        dtype,
        DType::Bool
            | DType::I8
            | DType::I16
            | DType::I32
            | DType::I64
            | DType::U8
            | DType::U16
            | DType::U32
            | DType::U64
            | DType::F16
            | DType::F32
            | DType::F64
    ) {
        return fallback();
    }

    // Zero-copy float64 identity: write the diagonal into numpy.zeros directly,
    // skipping the full n*m UFuncArray build. Bit-identical; other dtypes keep the
    // native build below.
    if dtype == DType::F64 {
        let nn = n as usize;
        let mm = m.map(|value| value as usize).unwrap_or(nn);
        return build_f64_eye(py, nn, mm, k);
    }

    // Non-f64 eye: numpy creates the typed identity directly; the native UFuncArray
    // build-then-export-bridge-convert was 200-700x slower (int8 701x). Delegate.
    fallback()
}

#[pyfunction]
#[pyo3(signature = (n, dtype=None))]
fn identity(py: Python<'_>, n: i64, dtype: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let id_fn = numpy.getattr("identity")?;
    let dtype_for_parse = dtype.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(dtype_val) = dtype.as_ref() {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        Ok(id_fn.call((n,), Some(&kwargs))?.unbind())
    };

    if n < 0 {
        return fallback();
    }

    let dtype = match extract_python_dtype(py, dtype_for_parse, DType::F64, "identity(dtype)") {
        Ok(dtype) => dtype,
        Err(_) => return fallback(),
    };
    if !matches!(
        dtype,
        DType::Bool
            | DType::I8
            | DType::I16
            | DType::I32
            | DType::I64
            | DType::U8
            | DType::U16
            | DType::U32
            | DType::U64
            | DType::F16
            | DType::F32
            | DType::F64
    ) {
        return fallback();
    }

    // numpy.identity (np.eye) is a fast direct-dtype creation; the native
    // UFuncArray build-then-export-bridge-convert was 22-991x slower (int8 991x).
    // Delegate.
    let _ = dtype;
    fallback()
}

#[pyfunction]
#[pyo3(signature = (start, stop, num=50, endpoint=true, base=10.0, dtype=None, axis=0))]
#[allow(clippy::too_many_arguments)]
fn logspace(
    py: Python<'_>,
    start: Py<PyAny>,
    stop: Py<PyAny>,
    num: i64,
    endpoint: bool,
    base: f64,
    dtype: Option<Py<PyAny>>,
    axis: i64,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let ls_fn = numpy.getattr("logspace")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("num", num)?;
        kwargs.set_item("endpoint", endpoint)?;
        kwargs.set_item("base", base)?;
        if let Some(dtype_val) = dtype.as_ref() {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        kwargs.set_item("axis", axis)?;
        Ok(ls_fn
            .call((start.bind(py), stop.bind(py)), Some(&kwargs))?
            .unbind())
    };

    if axis != 0 || num < 0 || base.to_bits() != 10.0_f64.to_bits() {
        return fallback(py);
    }
    if dtype
        .as_ref()
        .is_some_and(|dtype_val| !dtype_val.bind(py).is_none())
    {
        return fallback(py);
    }
    let Ok(start_f) = start.bind(py).extract::<f64>() else {
        return fallback(py);
    };
    let Ok(stop_f) = stop.bind(py).extract::<f64>() else {
        return fallback(py);
    };
    if !start_f.is_finite() || !stop_f.is_finite() {
        return fallback(py);
    }

    let result = match UFuncArray::logspace_endpoint(
        start_f,
        stop_f,
        num as usize,
        10.0,
        endpoint,
        DType::F64,
    ) {
        Ok(value) => value,
        Err(_) => return fallback(py),
    };
    build_numpy_array_from_ufunc(py, &result)
}

#[pyfunction]
#[pyo3(signature = (a, order="K", subok=false))]
fn copy(py: Python<'_>, a: Py<PyAny>, order: &str, subok: bool) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let copy_fn = numpy.getattr("copy")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("order", order)?;
        kwargs.set_item("subok", subok)?;
        Ok(copy_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };
    if !matches!(order, "C" | "K" | "F") {
        return fallback(py);
    }
    let a_bound = a.bind(py);
    let ndarray_type = numpy.getattr("ndarray")?;
    let source_array = numpy.call_method1("asanyarray", (a_bound,))?;
    if subok && !source_array.is_exact_instance(&ndarray_type) {
        return fallback(py);
    }
    // Resolve the actual output layout. 'C' / 'F' are explicit; 'K'
    // inherits from source contiguity (F-contig multi-D → F output).
    let source_shape: Vec<usize> = source_array.getattr("shape")?.extract()?;
    let mut emit_fortran = order == "F";
    if order == "K" && source_shape.len() >= 2 {
        let flags = source_array.getattr("flags")?;
        let f_contig: bool = flags.get_item("F_CONTIGUOUS")?.extract()?;
        let c_contig: bool = flags.get_item("C_CONTIGUOUS")?.extract()?;
        if f_contig && !c_contig {
            emit_fortran = true;
        }
    }
    // np.copy is a pure typed memcpy. The native extract -> UFuncArray -> export-bridge
    // rebuild was 20-205x slower than numpy (copy(int8 4M) 205x), and never faster.
    // Delegate (numpy owns the exact order/subok/dtype surface).
    let _ = emit_fortran;
    fallback(py)
}

// Parallel flat f64 sort. numpy.sort is single-threaded introsort; for a 1-D C-contiguous
// f64 array (default kind) a rayon par_sort_unstable over a fresh numpy.empty copy beats it
// once n amortizes the fan-out + export (the passthrough comment about "export overhead" was
// for a SERIAL native sort — parallel offsets it). Bit-identical for no-NaN input: np.sort
// returns ascending values, and ties are equal values so unstable order is irrelevant.
// Defers (Ok(None) -> passthrough) for: not exact 1-D C-contiguous f64, below the crossover,
// or ANY NaN (numpy's NaN-at-end ordering of mixed payloads is algorithm-specific).
fn try_zerocopy_f64_sort_flat(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    a: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    if !a.is_exact_instance(&numpy.getattr("ndarray")?) || !numpy_dtype_is_f64(py, a) {
        return Ok(None);
    }
    if a.getattr("ndim")?.extract::<usize>()? != 1
        || !a.getattr("flags")?.getattr("c_contiguous")?.extract::<bool>()?
    {
        return Ok(None);
    }
    let Ok(buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    let Some(cells) = buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = cells.len();
    // Parallel merge sort has more per-element overhead than a pure reduction, so the
    // crossover is higher: at 256K it's noisy break-even (can regress), at 1M+ it cleanly
    // wins ~1.6-1.85x. Gate at 1<<20; below it the numpy passthrough is parity.
    const SORT_PARALLEL_MIN: usize = 1 << 20;
    if n < SORT_PARALLEL_MIN || rayon::current_num_threads() < 2 {
        return Ok(None);
    }
    use rayon::prelude::*;
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only under the GIL.
    let src: &[f64] = unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), n) };
    if src.par_iter().any(|v| v.is_nan()) {
        return Ok(None);
    }
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let out = numpy.call_method("empty", (n,), Some(&kwargs))?;
    let out_buffer = PyBuffer::<f64>::get(&out)?;
    let Some(out_cells) = out_buffer.as_mut_slice(py) else {
        return Ok(None);
    };
    // SAFETY: fresh numpy.empty buffer we own (no alias with src).
    let dst: &mut [f64] =
        unsafe { std::slice::from_raw_parts_mut(out_cells.as_ptr() as *mut f64, n) };
    dst.copy_from_slice(src);
    // No NaN -> partial_cmp is a total order; unstable parallel sort matches numpy's values.
    dst.par_sort_unstable_by(|x, y| x.partial_cmp(y).expect("no NaN after check"));
    Ok(Some(out.unbind()))
}

#[pyfunction]
#[pyo3(signature = (*args, **kwargs))]
fn sort(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    // Fast path: np.sort(a) / np.sort(a, axis in {-1,0,None}) on a 1-D f64 array, default
    // kind. Any kind/order kwarg or other axis -> passthrough (handles every other surface).
    if args.len() == 1 {
        let axis_ok = match kwargs {
            None => true,
            Some(kw) => kw.iter().all(|(k, v)| {
                k.extract::<String>().ok().as_deref() == Some("axis")
                    && (v.is_none()
                        || v.extract::<isize>().map(|x| x == -1 || x == 0).unwrap_or(false))
            }),
        };
        if axis_ok {
            let numpy = py.import("numpy")?;
            if let Some(out) = try_zerocopy_f64_sort_flat(py, &numpy, &args.get_item(0)?)? {
                return Ok(out);
            }
        }
    }
    core_numpy_passthrough(py, "sort", args, kwargs)
}

// Parallel flat f64 argsort. numpy.argsort default kind is quicksort (UNSTABLE), so for
// equal values the returned index order is algorithm-specific and cannot be reproduced.
// BUT when all values are DISTINCT the sorting permutation is UNIQUE — any correct sort
// yields exactly numpy's result. So: parallel-sort an index buffer by value, then verify
// there are NO ties (no adjacent-equal values in sorted order); if any tie -> defer to the
// passthrough (numpy's unstable order). Any NaN -> defer (numpy's NaN-at-end ordering).
// Defers (Ok(None)) for: not exact 1-D C-contiguous f64, below the crossover, NaN, or ties.
fn try_zerocopy_f64_argsort_flat(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    a: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    if !a.is_exact_instance(&numpy.getattr("ndarray")?) || !numpy_dtype_is_f64(py, a) {
        return Ok(None);
    }
    if a.getattr("ndim")?.extract::<usize>()? != 1
        || !a.getattr("flags")?.getattr("c_contiguous")?.extract::<bool>()?
    {
        return Ok(None);
    }
    let Ok(buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    let Some(cells) = buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = cells.len();
    const ARGSORT_PARALLEL_MIN: usize = 1 << 20;
    if n < ARGSORT_PARALLEL_MIN || rayon::current_num_threads() < 2 {
        return Ok(None);
    }
    use rayon::prelude::*;
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only under the GIL.
    let data: &[f64] = unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), n) };
    if data.par_iter().any(|v| v.is_nan()) {
        return Ok(None);
    }
    let out = numpy.call_method1("empty", ((n,), numpy.getattr("intp")?))?;
    let out_buffer = PyBuffer::<i64>::get(&out)?;
    let Some(out_cells) = out_buffer.as_mut_slice(py) else {
        return Ok(None);
    };
    // SAFETY: fresh numpy.empty intp buffer we own (no alias).
    let perm: &mut [i64] =
        unsafe { std::slice::from_raw_parts_mut(out_cells.as_ptr() as *mut i64, n) };
    perm.par_iter_mut().enumerate().for_each(|(i, s)| *s = i as i64);
    // No NaN -> partial_cmp is a total order on the values.
    perm.par_sort_unstable_by(|&x, &y| {
        data[x as usize]
            .partial_cmp(&data[y as usize])
            .expect("no NaN after check")
    });
    // Any tie (adjacent equal values in sorted order) -> numpy's unstable order is
    // algorithm-specific, so defer; distinct values give the unique permutation numpy returns.
    let sorted: &[i64] = perm;
    let has_tie = (1..n)
        .into_par_iter()
        .any(|i| data[sorted[i] as usize] == data[sorted[i - 1] as usize]);
    if has_tie {
        return Ok(None);
    }
    Ok(Some(out.unbind()))
}

// Passthrough to NumPy for everything except the parallel flat-f64-distinct fast path above.
#[pyfunction]
#[pyo3(signature = (*args, **kwargs))]
fn argsort(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    if args.len() == 1 {
        let axis_ok = match kwargs {
            None => true,
            Some(kw) => kw.iter().all(|(k, v)| {
                k.extract::<String>().ok().as_deref() == Some("axis")
                    && (v.is_none()
                        || v.extract::<isize>().map(|x| x == -1 || x == 0).unwrap_or(false))
            }),
        };
        if axis_ok {
            let numpy = py.import("numpy")?;
            if let Some(out) = try_zerocopy_f64_argsort_flat(py, &numpy, &args.get_item(0)?)? {
                return Ok(out);
            }
        }
    }
    core_numpy_passthrough(py, "argsort", args, kwargs)
}

fn try_zerocopy_f64_sort_complex_flat(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    a: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    if !a.is_exact_instance(&numpy.getattr("ndarray")?) || !numpy_dtype_is_f64(py, a) {
        return Ok(None);
    }
    if a.getattr("ndim")?.extract::<usize>()? != 1
        || !a.getattr("flags")?.getattr("c_contiguous")?.extract::<bool>()?
    {
        return Ok(None);
    }
    let n = a.len()?;
    const SORT_COMPLEX_PARALLEL_MIN: usize = 1 << 19;
    const SORT_COMPLEX_PARALLEL_THREADS_MIN: usize = 8;
    if n < SORT_COMPLEX_PARALLEL_MIN
        || rayon::current_num_threads() < SORT_COMPLEX_PARALLEL_THREADS_MIN
    {
        return Ok(Some(numpy.getattr("sort_complex")?.call1((a,))?.unbind()));
    }

    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    let Some(in_cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    if in_cells.len() != n {
        return Ok(None);
    }
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only under the GIL.
    let input: &[f64] = unsafe { std::slice::from_raw_parts(in_cells.as_ptr().cast::<f64>(), n) };

    use rayon::prelude::*;
    if input.par_iter().any(|value| value.is_nan()) {
        return Ok(Some(numpy.getattr("sort_complex")?.call1((a,))?.unbind()));
    }

    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "complex128")?;
    let out = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n == 0 {
        return Ok(Some(out.unbind()));
    }
    let view = out.call_method1("view", ("float64",))?;
    let out_buffer = PyBuffer::<f64>::get(&view)?;
    let Some(out_cells) = out_buffer.as_mut_slice(py) else {
        return Ok(None);
    };
    if out_cells.len() != n * 2 {
        return Ok(None);
    }

    // SAFETY: both buffer cell types are transparent over f64; the output is freshly
    // allocated complex128 storage viewed as float64, so it cannot alias the input.
    let output: &mut [f64] =
        unsafe { std::slice::from_raw_parts_mut(out_cells.as_ptr() as *mut f64, n * 2) };
    output[..n].copy_from_slice(input);
    output[..n].par_sort_by(sort_complex_real_cmp);

    for index in (0..n).rev() {
        output[index * 2] = output[index];
        output[index * 2 + 1] = 0.0;
    }

    Ok(Some(out.unbind()))
}

#[pyfunction]
fn sort_complex(py: Python<'_>, a: Py<PyAny>) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        Ok(numpy
            .getattr("sort_complex")?
            .call1((a.bind(py),))?
            .unbind())
    };
    // Real-valued arrays are native: extract, sort via fnp_ufunc::sort_complex
    // (which flattens to 1-D and compares by (real, imag) with NaN last),
    // then materialize as a complex128 numpy array. Complex/structured/string
    // inputs still defer to numpy — our export bridge doesn't round-trip
    // complex via reshape.
    let a_bound = a.bind(py);
    if let Some(out) = try_zerocopy_f64_sort_complex_flat(py, &numpy, a_bound)? {
        return Ok(out);
    }
    let native = match extract_precise_numeric_array(py, a_bound, "sort_complex(a)") {
        Ok(value) => value,
        Err(_) => return fallback(py),
    };
    if native.has_integer_sidecar()
        || matches!(native.dtype(), DType::Complex64 | DType::Complex128)
        || native.shape().is_empty()
    {
        return fallback(py);
    }

    // fnp_ufunc::sort_complex requires a 1-D input; matrix tests call
    // numpy.sort_complex on a 2-D array, and numpy sorts along the last
    // axis there — we don't reproduce that axis behavior natively, so
    // hand 2-D+ inputs back to numpy.
    if native.shape().len() != 1 {
        return fallback(py);
    }

    let sorted = match fnp_ufunc::sort_complex(&native) {
        Ok(value) => value,
        Err(_) => return fallback(py),
    };
    // sorted has shape [n, 2] with interleaved (re, im) f64 values.
    let pairs = sorted.values();
    let n = sorted.shape()[0];
    debug_assert_eq!(pairs.len(), n * 2);
    Ok(numpy_complex128_array_from_interleaved_f64(py, &numpy, pairs)?.unbind())
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, out=None, overwrite_input=false, keepdims=false))]
fn nanmedian(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    overwrite_input: bool,
    keepdims: bool,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let nanmedian_fn = numpy.getattr("nanmedian")?;
    let axis_for_parse = axis.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        if let Some(out_val) = out.as_ref() {
            kwargs.set_item("out", out_val.bind(py))?;
        }
        kwargs.set_item("overwrite_input", overwrite_input)?;
        kwargs.set_item("keepdims", keepdims)?;
        Ok(nanmedian_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    if out.as_ref().is_some_and(|value| !value.bind(py).is_none()) || overwrite_input {
        return fallback();
    }

    // The native kernel computes in f64; defer float16/float32/complex inputs to
    // numpy.nanmedian so the narrow float dtype is preserved (numpy keeps float32 ->
    // float32) instead of widening to float64. int/bool/float64 keep the native path
    // (numpy's nanmedian of integers is float64, matching the widened native result).
    if !native_f64_reduction_preserves_dtype(py, a.bind(py)) {
        return fallback();
    }

    // Original ndim for keepdims axis re-insertion (keepdims-on-axis class; the gate used to
    // bail on keepdims, forgoing the native win. BlackThrush 2026-06-22).
    let orig_ndim = a
        .bind(py)
        .getattr("ndim")
        .ok()
        .and_then(|d| d.extract::<usize>().ok());
    let a = match extract_numeric_array(py, a.bind(py), "nanmedian(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let axis = match extract_axis_spec(py, axis_for_parse, "nanmedian") {
        Ok(None) => None,
        Ok(Some(axes)) if axes.len() == 1 => Some(axes[0]),
        Ok(Some(_)) => return fallback(),
        Err(_) => return fallback(),
    };
    // keepdims over the full array (axis=None) reshapes to all-ones dims; delegate. Single-axis
    // keepdims runs the native path then re-inserts the reduced axis.
    if keepdims && axis.is_none() {
        return fallback();
    }
    let result = match a.nanmedian(axis) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    let output = build_numpy_array_from_ufunc(py, &result)?;
    if keepdims && let Some(ax) = axis {
        let Some(ndim) = orig_ndim else {
            return fallback();
        };
        return keepdims_expand_axis(py, &numpy, output, ax as i64, ndim);
    }
    if result.shape().is_empty() {
        return Ok(output.bind(py).get_item(())?.unbind());
    }
    Ok(output)
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, weights=None, returned=false))]
fn ma_average(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    weights: Option<Py<PyAny>>,
    returned: bool,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let axis_for_parse = axis.as_ref().map(|value| value.clone_ref(py));
    let a_for_fallback = a.clone_ref(py);
    let weights_for_fallback = weights.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let avg_fn = numpy.getattr("ma")?.getattr("average")?;
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        if let Some(weights_val) = weights_for_fallback.as_ref() {
            kwargs.set_item("weights", weights_val.bind(py))?;
        }
        kwargs.set_item("returned", returned)?;
        Ok(avg_fn
            .call((a_for_fallback.bind(py),), Some(&kwargs))?
            .unbind())
    };

    // Fast path: with no weights, ma.average reduces to the masked mean. The manual
    // extract + per-element accumulation below runs ~7x slower than numpy.ma.average
    // (106ms vs 14ms @4M f64). numpy is the parity reference and handles the
    // returned-tuple and all-masked -> masked-scalar cases natively, so defer the
    // (common) no-weights case to it.
    if weights.is_none() {
        return fallback();
    }

    let input_is_masked_array = extract_mask_metadata(py, a.bind(py), "ma_average(a)")
        .map(|(is_masked, _, _)| is_masked)
        .unwrap_or(false);
    let Some(masked) = extract_numeric_masked_array(py, a.bind(py), "ma_average(a)")? else {
        return fallback();
    };
    let axis = match extract_axis_spec(py, axis_for_parse, "ma_average") {
        Ok(None) => None,
        Ok(Some(axes)) if axes.len() == 1 => Some(axes[0]),
        Ok(Some(_)) => return fallback(),
        Err(_) => return fallback(),
    };
    if let Some(weights) = weights.as_ref() {
        let Some(masked_weights) =
            extract_numeric_masked_array(py, weights.bind(py), "ma_average(weights)")?
        else {
            return fallback();
        };
        let masked_scalar = numpy.getattr("ma")?.getattr("masked")?.unbind();
        match axis {
            None => {
                if masked.shape() != masked_weights.shape() {
                    return fallback();
                }

                let combined_mask = ma_mask_or(masked.mask(), masked_weights.mask());
                let mut numerator = 0.0;
                let mut denominator = 0.0;
                let mut any_valid = false;
                for index in 0..masked.data().values().len() {
                    let is_masked = combined_mask
                        .as_ref()
                        .is_some_and(|mask| mask.values()[index] != 0.0);
                    if is_masked {
                        continue;
                    }
                    any_valid = true;
                    let weight = masked_weights.data().values()[index];
                    denominator += weight;
                    numerator += masked.data().values()[index] * weight;
                }

                if !any_valid {
                    if returned {
                        return Ok(PyTuple::new(
                            py,
                            [masked_scalar.bind(py), masked_scalar.bind(py)],
                        )?
                        .into_any()
                        .unbind());
                    }
                    return Ok(masked_scalar);
                }

                let average_output = build_numpy_scalar_or_array(
                    py,
                    &UFuncArray::scalar(numerator / denominator, DType::F64),
                )?;
                if returned {
                    let sum_output = build_numpy_scalar_or_array(
                        py,
                        &UFuncArray::scalar(denominator, DType::F64),
                    )?;
                    return Ok(
                        PyTuple::new(py, [average_output.bind(py), sum_output.bind(py)])?
                            .into_any()
                            .unbind(),
                    );
                }
                return Ok(average_output);
            }
            Some(axis) => {
                let Some(normalized_axis) = try_normalize_axis(axis, masked.shape().len()) else {
                    return fallback();
                };
                let axis_len = masked.shape()[normalized_axis];
                if masked_weights.shape() != [axis_len] {
                    return fallback();
                }

                let outer = element_count(&masked.shape()[..normalized_axis])
                    .map_err(|err| PyValueError::new_err(err.to_string()))?;
                let inner = element_count(&masked.shape()[normalized_axis + 1..])
                    .map_err(|err| PyValueError::new_err(err.to_string()))?;
                let out_shape = masked
                    .count(Some(axis))
                    .map_err(|err| map_ma_error("ma_average", err))?
                    .shape()
                    .to_vec();
                let out_len = outer * inner;
                let mut avg_values = vec![0.0; out_len];
                let mut avg_mask_values = vec![0.0; out_len];
                let mut sum_values = vec![0.0; out_len];
                let mut sum_mask_values = vec![0.0; out_len];
                let mut any_valid_values = vec![false; out_len];

                for outer_idx in 0..outer {
                    let base = outer_idx * axis_len * inner;
                    for inner_idx in 0..inner {
                        let dst = outer_idx * inner + inner_idx;
                        let mut numerator = 0.0;
                        let mut denominator = 0.0;
                        let mut any_valid = false;
                        for lane_idx in 0..axis_len {
                            let src = base + lane_idx * inner + inner_idx;
                            let data_masked =
                                masked.mask().is_some_and(|mask| mask.values()[src] != 0.0);
                            let weight_masked = masked_weights
                                .mask()
                                .is_some_and(|mask| mask.values()[lane_idx] != 0.0);
                            if data_masked || weight_masked {
                                continue;
                            }
                            any_valid = true;
                            let weight = masked_weights.data().values()[lane_idx];
                            denominator += weight;
                            numerator += masked.data().values()[src] * weight;
                        }
                        any_valid_values[dst] = any_valid;

                        if !any_valid {
                            avg_mask_values[dst] = 1.0;
                            if input_is_masked_array {
                                sum_mask_values[dst] = 1.0;
                            } else {
                                sum_values[dst] = 0.0;
                            }
                            continue;
                        }

                        sum_values[dst] = denominator;
                        if denominator == 0.0 {
                            if out_shape.is_empty() {
                                avg_values[dst] = numerator / denominator;
                            } else {
                                avg_mask_values[dst] = 1.0;
                                avg_values[dst] = f64::NAN;
                            }
                        } else {
                            avg_values[dst] = numerator / denominator;
                        }
                    }
                }

                if out_shape.is_empty() {
                    if !any_valid_values[0] {
                        if returned {
                            return Ok(PyTuple::new(
                                py,
                                [masked_scalar.bind(py), masked_scalar.bind(py)],
                            )?
                            .into_any()
                            .unbind());
                        }
                        return Ok(masked_scalar);
                    }

                    let average_output = build_numpy_scalar_or_array(
                        py,
                        &UFuncArray::scalar(avg_values[0], DType::F64),
                    )?;
                    if returned {
                        let sum_output = build_numpy_scalar_or_array(
                            py,
                            &UFuncArray::scalar(sum_values[0], DType::F64),
                        )?;
                        return Ok(PyTuple::new(
                            py,
                            [average_output.bind(py), sum_output.bind(py)],
                        )?
                        .into_any()
                        .unbind());
                    }
                    return Ok(average_output);
                }

                let average = MaskedArray::new(
                    UFuncArray::new(out_shape.clone(), avg_values, DType::F64)
                        .map_err(map_ufunc_error)?,
                    Some(
                        UFuncArray::new(out_shape.clone(), avg_mask_values, DType::Bool)
                            .map_err(map_ufunc_error)?,
                    ),
                    Some(masked.fill_value()),
                )
                .map_err(|err| map_ma_error("ma_average", err))?;
                let average_output = build_numpy_masked_array(py, &average)?;
                average_output
                    .bind(py)
                    .call_method1("set_fill_value", (masked.fill_value(),))?;
                if returned {
                    let sum_output = if input_is_masked_array {
                        let sum_weights = MaskedArray::new(
                            UFuncArray::new(out_shape, sum_values, DType::F64)
                                .map_err(map_ufunc_error)?,
                            Some(
                                UFuncArray::new(
                                    average.data().shape().to_vec(),
                                    sum_mask_values,
                                    DType::Bool,
                                )
                                .map_err(map_ufunc_error)?,
                            ),
                            Some(masked.fill_value()),
                        )
                        .map_err(|err| map_ma_error("ma_average", err))?;
                        let sum_output = build_numpy_masked_array(py, &sum_weights)?;
                        sum_output
                            .bind(py)
                            .call_method1("set_fill_value", (masked.fill_value(),))?;
                        sum_output
                    } else {
                        build_numpy_scalar_or_array(
                            py,
                            &UFuncArray::new(out_shape, sum_values, DType::F64)
                                .map_err(map_ufunc_error)?,
                        )?
                    };
                    return Ok(
                        PyTuple::new(py, [average_output.bind(py), sum_output.bind(py)])?
                            .into_any()
                            .unbind(),
                    );
                }
                return Ok(average_output);
            }
        }
    }

    let counts = match masked.count(axis) {
        Ok(counts) => counts,
        Err(_) => return fallback(),
    };
    let counts_output = build_numpy_scalar_or_array(py, &counts)?;

    if axis.is_none() && counts.values().first().copied().unwrap_or(0.0) == 0.0 {
        let masked_output = numpy.getattr("ma")?.getattr("masked")?.unbind();
        if returned {
            return Ok(
                PyTuple::new(py, [masked_output.bind(py), counts_output.bind(py)])?
                    .into_any()
                    .unbind(),
            );
        }
        return Ok(masked_output);
    }

    let mean = match masked.mean(axis, false) {
        Ok(mean) => mean,
        Err(_) => return fallback(),
    };

    if axis.is_none() {
        let mean_output = build_numpy_scalar_or_array(py, mean.data())?;
        if returned {
            return Ok(
                PyTuple::new(py, [mean_output.bind(py), counts_output.bind(py)])?
                    .into_any()
                    .unbind(),
            );
        }
        return Ok(mean_output);
    }

    let mask = if counts.values().contains(&0.0) {
        let mask_values: Vec<f64> = counts
            .values()
            .iter()
            .map(|&value| if value == 0.0 { 1.0 } else { 0.0 })
            .collect();
        Some(
            UFuncArray::new(counts.shape().to_vec(), mask_values, DType::Bool)
                .map_err(map_ufunc_error)?,
        )
    } else {
        None
    };
    let result = MaskedArray::new(mean.data().clone(), mask, Some(masked.fill_value()))
        .map_err(|err| map_ma_error("ma_average", err))?;
    let py_result = build_numpy_masked_array(py, &result)?;
    py_result
        .bind(py)
        .call_method1("set_fill_value", (masked.fill_value(),))?;
    if returned {
        return Ok(
            PyTuple::new(py, [py_result.bind(py), counts_output.bind(py)])?
                .into_any()
                .unbind(),
        );
    }
    Ok(py_result)
}

#[pyfunction]
#[pyo3(signature = (a, axis=None))]
fn size_count(py: Python<'_>, a: Py<PyAny>, axis: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    // Passthrough to np.size. Returns total elements (axis=None) or
    // count along axis. Exposed as size_count to avoid clashing with
    // std::mem::size_of.
    let numpy = py.import("numpy")?;
    let size_fn = numpy.getattr("size")?;
    let kwargs = PyDict::new(py);
    if let Some(axis_val) = axis {
        kwargs.set_item("axis", axis_val.bind(py))?;
    }
    Ok(size_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
}

#[pyfunction]
#[pyo3(signature = (x,))]
fn iscomplexobj(x: Py<PyAny>) -> PyResult<bool> {
    // Rust-owned port of np.iscomplexobj. This mirrors NumPy's
    // object-vs-complex distinction: ndarray/scalar inputs use their
    // dtype when available, while plain Python sequences recurse to the
    // complex element type they would coerce to under array creation.
    Python::attach(|py| python_is_complex_obj(x.bind(py)))
}

#[pyfunction]
#[pyo3(signature = (a, q, axis=None, out=None, overwrite_input=false, method=None, keepdims=false, weights=None))]
#[allow(clippy::too_many_arguments)]
fn quantile(
    py: Python<'_>,
    a: Py<PyAny>,
    q: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    overwrite_input: bool,
    method: Option<String>,
    keepdims: bool,
    weights: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let quantile_fn = numpy.getattr("quantile")?;
    let axis_for_parse = axis.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        if let Some(out_val) = out.as_ref() {
            kwargs.set_item("out", out_val.bind(py))?;
        }
        kwargs.set_item("overwrite_input", overwrite_input)?;
        if let Some(method_val) = method.as_ref() {
            kwargs.set_item("method", method_val)?;
        }
        kwargs.set_item("keepdims", keepdims)?;
        if let Some(weights_val) = weights.as_ref() {
            kwargs.set_item("weights", weights_val.bind(py))?;
        }
        Ok(quantile_fn
            .call((a.bind(py), q.bind(py)), Some(&kwargs))?
            .unbind())
    };

    if out.as_ref().is_some_and(|value| !value.bind(py).is_none())
        || overwrite_input
        || method.is_some()
        || weights.is_some()
        || numpy_dtype_is_narrow_float(py, a.bind(py))
        || numpy_dtype_is_bool(py, a.bind(py))
        // Integer input widens int->f64 in extract (~1.9x at 1M; parity at 8M) and never beats
        // numpy percentile/quantile; delegate (the f64 native path keeps its win).
        || numpy_dtype_is_integer(py, a.bind(py))?
    {
        return fallback();
    }

    // Original ndim for keepdims axis re-insertion (keepdims-on-axis class, BlackThrush 2026-06-22).
    let orig_ndim = a
        .bind(py)
        .getattr("ndim")
        .ok()
        .and_then(|d| d.extract::<usize>().ok());
    let a = match extract_numeric_array(py, a.bind(py), "quantile(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let axis = match extract_axis_spec(py, axis_for_parse, "quantile") {
        Ok(None) => None,
        Ok(Some(axes)) if axes.len() == 1 => Some(axes[0]),
        Ok(Some(_)) => return fallback(),
        Err(_) => return fallback(),
    };
    // Empty input: numpy.quantile raises IndexError (internal kth lookup
    // into 0-length array). Our in-Rust path returns Ok(NaN). Fall back to
    // numpy so the exception type matches.
    if a.values().is_empty() {
        return fallback();
    }
    // keepdims over the full array (axis=None) reshapes to all-ones dims; delegate. Single-axis
    // keepdims runs the native path then re-inserts the reduced axis.
    if keepdims && axis.is_none() {
        return fallback();
    }
    if let Ok(q) = q.bind(py).extract::<f64>() {
        let result = match a.quantile(q, axis) {
            Ok(result) => result,
            Err(_) => return fallback(),
        };
        let output = build_numpy_array_from_ufunc(py, &result)?;
        if keepdims && let Some(ax) = axis {
            let Some(ndim) = orig_ndim else {
                return fallback();
            };
            return keepdims_expand_axis(py, &numpy, output, ax as i64, ndim);
        }
        if result.shape().is_empty() {
            return Ok(output.bind(py).get_item(())?.unbind());
        }
        return Ok(output);
    }
    if axis.is_none() && !keepdims {
        if let Ok(qs) = q.bind(py).extract::<Vec<f64>>() {
            let result = match a.quantiles_axis_none(&qs) {
                Ok(result) => result,
                Err(_) => return fallback(),
            };
            return build_numpy_array_from_ufunc(py, &result);
        }
    }
    fallback()
}

// Native fused Horner np.polyval(p, x) for real coefficients and an f64 C-contiguous x
// array. numpy.polyval runs a PYTHON loop `y = zeros_like(x); for pv in p: y = y*x + pv`,
// materializing two whole-array temporaries (y*x, then +pv) per coefficient -> O(deg)
// passes + temps, multi-ms for large x. This evaluates the polynomial per element in
// registers (a single pass over x, deg fused mul-then-add steps), parallel across
// elements, writing the output buffer directly. Bit-exact: it reproduces numpy's exact
// recurrence including the first `0.0*x + p[0]` step (so x = +-inf -> 0*inf = NaN matches)
// and uses SEPARATE multiply then add (Rust does NOT contract a*b+c to FMA), the same two
// roundings numpy's `y*x` then `y+pv` produce. Real (int/uint/float) coefficients only
// (cast to f64, matching numpy's promotion with an f64 x); complex p, non-f64 / scalar /
// non-contiguous x, and 0-d x defer to numpy.
fn try_zerocopy_f64_polyval(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    p: &Bound<'_, PyAny>,
    x: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    if !x.is_exact_instance(&numpy.getattr("ndarray")?) {
        return Ok(None);
    }
    let xdt = x.getattr("dtype")?;
    if xdt.getattr("kind")?.extract::<String>()? != "f"
        || xdt.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    // Coefficients must be real (int/uint/float); complex defers. Cast to f64 (numpy
    // promotes int/float coeffs against an f64 x to f64).
    let p_arr = numpy.call_method1("asarray", (p,))?;
    let pkind = p_arr.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
    if pkind != "f" && pkind != "i" && pkind != "u" {
        return Ok(None);
    }
    let coeffs: Vec<f64> = match p_arr
        .call_method1("astype", ("float64",))
        .and_then(|a| a.call_method0("ravel"))
        .and_then(|a| a.extract::<Vec<f64>>())
    {
        Ok(c) => c,
        Err(_) => return Ok(None),
    };
    let Ok(in_buffer) = PyBuffer::<f64>::get(x) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() {
        return Ok(None);
    }
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    if shape.is_empty() {
        return Ok(None); // 0-d x: defer (scalar/0-d return semantics)
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let total = cells.len();
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only under the GIL.
    let data: &[f64] = unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), total) };
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let out = numpy.call_method("empty", (total,), Some(&kwargs))?;
    {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&out) else {
            return Ok(None);
        };
        let Some(out_cells) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // SAFETY: freshly allocated numpy.empty output, cannot alias x; each slot written once.
        let o: &mut [f64] =
            unsafe { std::slice::from_raw_parts_mut(out_cells.as_ptr() as *mut f64, total) };
        let coeffs = &coeffs;
        let horner = move |xv: f64| -> f64 {
            let mut y = 0.0f64;
            for &pv in coeffs {
                // separate multiply then add (no FMA) -> numpy's two roundings.
                y = y * xv + pv;
            }
            y
        };
        use rayon::prelude::*;
        const POLYVAL_PARALLEL_MIN: usize = 1 << 16;
        let parallel = total.saturating_mul(coeffs.len().max(1)) >= POLYVAL_PARALLEL_MIN
            && rayon::current_num_threads() >= 2;
        if parallel {
            o.par_iter_mut()
                .zip(data.par_iter())
                .for_each(|(slot, &xv)| *slot = horner(xv));
        } else {
            for (slot, &xv) in o.iter_mut().zip(data.iter()) {
                *slot = horner(xv);
            }
        }
    }
    let shape_tuple = PyTuple::new(py, shape.iter().copied())?;
    Ok(Some(out.call_method1("reshape", (&shape_tuple,))?.unbind()))
}

#[pyfunction]
#[pyo3(signature = (p, x))]
fn polyval(py: Python<'_>, p: Py<PyAny>, x: Py<PyAny>) -> PyResult<Py<PyAny>> {
    // Coefficients `p` are in decreasing powers (p[0]*x^n + ... + p[n]). `x` may be
    // scalar or array-like; output matches numpy's dtype-promotion rules (including
    // complex coefficients broadcasting up).
    let numpy = py.import("numpy")?;
    // Native fused Horner for real coefficients + an f64 C-contiguous x array.
    if let Some(out) = try_zerocopy_f64_polyval(py, &numpy, p.bind(py), x.bind(py))? {
        return Ok(out);
    }
    Ok(numpy
        .getattr("polyval")?
        .call1((p.bind(py), x.bind(py)))?
        .unbind())
}

#[pyfunction]
#[pyo3(signature = (arr,))]
fn getmaskarray(py: Python<'_>, arr: Py<PyAny>) -> PyResult<Py<PyAny>> {
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        Ok(numpy
            .getattr("ma")?
            .getattr("getmaskarray")?
            .call1((arr.bind(py),))?
            .unbind())
    };

    // Fast path: for a MaskedArray whose mask is already a full bool ndarray (the common
    // case), np.ma.getmaskarray just returns that array — O(1). The generic path below
    // extracts the bool mask into an f64 Vec and rebuilds it (bool->f64->bool), ~235000x
    // slower than numpy. Return arr.mask directly when it is an ndarray of the data shape;
    // nomask / scalar masks fall through to the zeros-building generic path.
    {
        let numpy = py.import("numpy")?;
        let masked_array_type = numpy.getattr("ma")?.getattr("MaskedArray")?;
        if arr.bind(py).is_instance(&masked_array_type)?
            && let Ok(mask) = arr.bind(py).getattr("mask")
            && mask.is_instance(&numpy.getattr("ndarray")?)?
            && let (Ok(mshape), Ok(dshape)) = (
                mask.getattr("shape").and_then(|s| s.extract::<Vec<usize>>()),
                arr.bind(py).getattr("shape").and_then(|s| s.extract::<Vec<usize>>()),
            )
            && mshape == dshape
            && mask.getattr("dtype")?.getattr("kind")?.extract::<String>()? == "b"
        {
            return Ok(mask.unbind());
        }
    }

    let (_, mask, shape) = match extract_mask_metadata(py, arr.bind(py), "getmaskarray") {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    let mask = match mask {
        Some(mask) => mask,
        None => build_boolean_array(&shape, false, "getmaskarray")?,
    };
    build_numpy_array_from_ufunc(py, &mask)
}

#[pyfunction]
#[pyo3(signature = (m, copy=false, shrink=true, dtype=None))]
fn make_mask(
    py: Python<'_>,
    m: Py<PyAny>,
    copy: bool,
    shrink: bool,
    dtype: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let m_for_fallback = m.clone_ref(py);
    let dtype_for_fallback = dtype.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let make_mask_fn = numpy.getattr("ma")?.getattr("make_mask")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("copy", copy)?;
        kwargs.set_item("shrink", shrink)?;
        if let Some(dtype_val) = &dtype_for_fallback {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        Ok(make_mask_fn
            .call((m_for_fallback.bind(py),), Some(&kwargs))?
            .unbind())
    };

    let numpy = py.import("numpy")?;
    let source = m.bind(py);
    let nomask = numpy.getattr("ma")?.getattr("nomask")?;
    if source.is(&nomask) {
        return Ok(nomask.clone().unbind());
    }
    if let Some(dtype_val) = &dtype
        && !dtype_val.bind(py).is_none()
    {
        return fallback();
    }

    // Everything past the O(1) nomask/dtype short-circuits is a pure bool
    // conversion (truthiness -> bool, all-False shrink to nomask, optional copy).
    // The previous path extracted the operand into an f64 UFuncArray and rebuilt
    // it (~74ms @4M) where numpy.ma.make_mask does a single bool view/copy (~132us)
    // — a ~560x gap. Defer to numpy, which is the parity reference and handles
    // shrink/copy/nomask natively.
    fallback()
}

#[pyfunction]
#[pyo3(signature = (shape, dtype=None))]
fn masked_all(py: Python<'_>, shape: Py<PyAny>, dtype: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    let dtype_for_fallback = dtype.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let masked_all_fn = numpy.getattr("ma")?.getattr("masked_all")?;
        let kwargs = PyDict::new(py);
        if let Some(dtype_val) = &dtype_for_fallback {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        Ok(masked_all_fn
            .call((shape.bind(py),), Some(&kwargs))?
            .unbind())
    };

    let shape = match extract_index_shape(py, shape.bind(py), "masked_all") {
        Ok(shape) => shape,
        Err(_) => return fallback(),
    };
    let dtype = match extract_python_dtype(
        py,
        dtype.as_ref().map(|value| value.clone_ref(py)),
        DType::F64,
        "masked_all",
    ) {
        Ok(dtype) => dtype,
        Err(_) => return fallback(),
    };
    if !dtype_supported_by_numpy_export_bridge(dtype) {
        return fallback();
    }
    let result =
        MaskedArray::masked_all(shape, dtype).map_err(|err| map_ma_error("masked_all", err))?;
    build_numpy_masked_array(py, &result)
}

#[pyfunction]
#[pyo3(signature = (arr,))]
fn masked_all_like(py: Python<'_>, arr: Py<PyAny>) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    Ok(numpy
        .getattr("ma")?
        .getattr("masked_all_like")?
        .call1((arr.bind(py),))?
        .unbind())
}

// Zero-copy np.ma.compressed for a float64 MaskedArray: gather the unmasked (mask==0)
// elements, in C-order, straight into the np.empty 1-D output. Returns None to defer.
fn try_zerocopy_ma_compressed_f64(
    py: Python<'_>,
    value: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let masked_array_type = numpy.getattr("ma")?.getattr("MaskedArray")?;
    if !value.is_instance(&masked_array_type)? {
        return Ok(None);
    }
    let data_obj = value.getattr("data")?;
    if !numpy_dtype_is_f64(py, &data_obj) {
        return Ok(None);
    }
    let Ok(shape) = value.getattr("shape").and_then(|s| s.extract::<Vec<usize>>()) else {
        return Ok(None);
    };
    let total: usize = shape.iter().product();
    let Ok(data_buf) = PyBuffer::<f64>::get(&data_obj) else {
        return Ok(None);
    };
    let Some(data) = data_buf.as_slice(py) else {
        return Ok(None);
    };
    if data.len() != total {
        return Ok(None);
    }
    // bool mask reinterpreted as uint8 (zero-copy view) for the PyBuffer read.
    let mask_obj = numpy
        .getattr("ma")?
        .getattr("getmaskarray")?
        .call1((value,))?
        .call_method1("view", (numpy.getattr("uint8")?,))?;
    let Ok(mask_buf) = PyBuffer::<u8>::get(&mask_obj) else {
        return Ok(None);
    };
    let Some(mask) = mask_buf.as_slice(py) else {
        return Ok(None);
    };
    if mask.len() != total {
        return Ok(None);
    }
    let kept = mask.iter().filter(|m| m.get() == 0).count();
    // fnp's direct gather beats numpy's boolean-index only when MOST elements are kept (sparse
    // mask -> ~0.13x; the common masked case). At moderate density numpy's C compaction wins
    // (kept~50% -> ~3.6x). Bail to numpy unless >=90% kept (the count pass above is cheap u8).
    if kept * 10 < total * 9 {
        return Ok(None);
    }
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (kept,), Some(&kwargs))?;
    if kept > 0 {
        let Ok(out_buf) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(out) = out_buf.as_mut_slice(py) else {
            return Ok(None);
        };
        let mut j = 0usize;
        for (d, m) in data.iter().zip(mask) {
            if m.get() == 0 {
                out[j].set(d.get());
                j += 1;
            }
        }
    }
    Ok(Some(flat.unbind()))
}

#[pyfunction]
#[pyo3(signature = (x,))]
fn compressed(py: Python<'_>, x: Py<PyAny>) -> PyResult<Py<PyAny>> {
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        Ok(numpy
            .getattr("ma")?
            .getattr("compressed")?
            .call1((x.bind(py),))?
            .unbind())
    };

    // Zero-copy fast path for an f64 MaskedArray (same extract-3-copies gap as ma.filled):
    // read the contiguous data + bool mask buffers and gather the unmasked elements
    // directly into the np.empty output, no owned-Vec extraction or MaskedArray rebuild.
    if let Some(out) = try_zerocopy_ma_compressed_f64(py, x.bind(py))? {
        return Ok(out);
    }

    // Non-f64 (int/complex/...) and moderate-density f64 reach here: the native extract->compress->
    // rebuild path was ~17x for int (dtype-gap); numpy.ma.compressed (C boolean-index) is faster.
    fallback()
}

