#[pyfunction]
#[pyo3(signature = (a, UPLO="L"))]
#[allow(non_snake_case)]
fn eigh(py: Python<'_>, a: Py<PyAny>, UPLO: &str) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let eigh_fn = numpy.getattr("linalg")?.getattr("eigh")?;
    let a_for_fallback = a.clone_ref(py);
    let kwargs = PyDict::new(py);
    kwargs.set_item("UPLO", UPLO)?;
    let fallback = || -> PyResult<Py<PyAny>> {
        Ok(eigh_fn
            .call((a_for_fallback.bind(py),), Some(&kwargs))?
            .unbind())
    };

    // STALE-CLIFF class (2026-06-21, same as det/slogdet/inv/solve/eigvalsh): the
    // native 2-D symmetric eigendecomposition loses to LAPACK syevd on the current
    // NumPy 2.4.3 (measured ~4.2x at n=200, ~4.0x at n=800). Delegate ALL real 2-D
    // square inputs to numpy before the extract copy. Returning numpy's exact
    // (eigenvalues, eigenvectors) is parity-safe — eigh conformance compares
    // |eigenvectors| (column sign is non-deterministic across LAPACK builds), so the
    // numpy signs match the contract. The batched (>=3-D) batch_eigh path below is
    // unchanged (numpy loops serial per lane -> it wins). NOTE: committed code-only
    // during a disk-low pause; build/conformance verification pending disk recovery.
    if let Ok(ndarray_type) = numpy.getattr("ndarray")
        && a.bind(py).is_exact_instance(&ndarray_type)
        && let Ok(shape) = a
            .bind(py)
            .getattr("shape")
            .and_then(|s| s.extract::<Vec<usize>>())
        && shape.len() == 2
        && shape[0] == shape[1]
        && a
            .bind(py)
            .getattr("dtype")
            .and_then(|d| d.getattr("kind"))
            .and_then(|k| k.extract::<String>())
            .map(|k| k == "f")
            .unwrap_or(false)
    {
        return fallback();
    }

    let array = match extract_precise_numeric_array(py, a.bind(py), "eigh(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let shape = array.shape();
    let real_f64_finite = matches!(array.dtype(), DType::F64)
        && !array.has_integer_sidecar()
        && array.values().iter().all(|value| value.is_finite())
        && matches!(UPLO, "L" | "U");
    // Batched (stacked) symmetric inputs: eigendecompose every lane natively via the
    // parallel batch_eigh instead of passing the whole stack through to numpy's LAPACK
    // (a no-gaps violation — and numpy's batched eigh is a serial per-lane C loop).
    // Eigenvalues are ascending (NumPy convention) and conformance compares
    // |eigenvectors| (a column's sign is non-deterministic across LAPACK builds), so
    // the per-lane sign choice is parity-safe. Symmetrize each lane from the selected
    // UPLO triangle (matching the 2-D path), then run batch_eigh. On any Err
    // (non-convergence / shape) fall back to numpy. Mirrors the eigvalsh batched path.
    if shape.len() >= 3 && shape[shape.len() - 1] == shape[shape.len() - 2] && real_f64_finite {
        let n = shape[shape.len() - 1];
        let mat_size = n * n;
        let vals = array.values();
        let batch = vals.len() / mat_size;
        let mut sym = vec![0.0f64; vals.len()];
        for b in 0..batch {
            let base = b * mat_size;
            if UPLO == "L" {
                for row in 0..n {
                    for col in 0..=row {
                        let v = vals[base + row * n + col];
                        sym[base + row * n + col] = v;
                        sym[base + col * n + row] = v;
                    }
                }
            } else {
                for row in 0..n {
                    for col in row..n {
                        let v = vals[base + row * n + col];
                        sym[base + row * n + col] = v;
                        sym[base + col * n + row] = v;
                    }
                }
            }
        }
        let owned_shape = shape.to_vec();
        if let Ok((eigenvalues, eigenvectors)) = fnp_linalg::batch_eigh(&sym, &owned_shape) {
            let mut val_shape: Vec<usize> = owned_shape[..owned_shape.len() - 2].to_vec();
            val_shape.push(n);
            let eval_arr =
                UFuncArray::new(val_shape, eigenvalues, DType::F64).map_err(map_ufunc_error)?;
            let evec_arr = UFuncArray::new(owned_shape, eigenvectors, DType::F64)
                .map_err(map_ufunc_error)?;
            return build_numpy_eigh_result(py, &eval_arr, &evec_arr);
        }
        return fallback();
    }
    if shape.len() != 2
        || shape[0] != shape[1]
        || !matches!(array.dtype(), DType::F64)
        || array.has_integer_sidecar()
        || array.values().iter().any(|value| !value.is_finite())
        || !matches!(UPLO, "L" | "U")
    {
        return fallback();
    }

    let sym = match symmetric_matrix_from_selected_triangle(&array, UPLO) {
        Ok(sym) => sym,
        Err(_) => return fallback(),
    };
    let (eigenvalues, eigenvectors) = match sym.eigh() {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    build_numpy_eigh_result(py, &eigenvalues, &eigenvectors)
}

#[pyfunction]
#[pyo3(signature = (a, b, axes=None))]
fn tensordot(
    py: Python<'_>,
    a: Py<PyAny>,
    b: Py<PyAny>,
    axes: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let tensordot_fn = numpy.getattr("tensordot")?;
    let fallback = || -> PyResult<Py<PyAny>> {
        let axes_arg = match axes.as_ref() {
            Some(value) => value.bind(py).clone(),
            None => 2_i64.into_pyobject(py)?.into_any(),
        };
        Ok(tensordot_fn
            .call1((a.bind(py), b.bind(py), axes_arg))?
            .unbind())
    };

    let axes = match axes.as_ref() {
        Some(value) => match value.bind(py).extract::<i64>() {
            Ok(value) if value >= 0 => value as usize,
            _ => return fallback(),
        },
        None => 2usize,
    };

    // Cheap metadata pre-gate (no extraction): tensordot(axes=k) flattens to the
    // GEMM (m x contract) @ (contract x n). Our native matmul_accumulate only
    // beats numpy's BLAS inside the SAME profiled sweet spot np.matmul/np.dot
    // gate on (flops >= PY_NATIVE_GEMM_MIN_FLOPS, every flattened dim <=
    // PY_NATIVE_GEMM_MAX_DIM). tensordot used to ALWAYS take the native path —
    // up to ~16x slower than numpy below the flop floor / above the dim cap.
    // Read the shapes straight off the ndarrays and delegate the non-competitive
    // contractions to numpy.tensordot before paying for any Rust-side extraction.
    if let (Ok(a_shape), Ok(b_shape)) = (
        a.bind(py)
            .getattr("shape")
            .and_then(|s| s.extract::<Vec<usize>>()),
        b.bind(py)
            .getattr("shape")
            .and_then(|s| s.extract::<Vec<usize>>()),
    ) && axes <= a_shape.len()
        && axes <= b_shape.len()
    {
        let an = a_shape.len();
        let contract: usize = a_shape[an - axes..].iter().product();
        let m: usize = a_shape[..an - axes].iter().product();
        let n: usize = b_shape[axes..].iter().product();
        let in_native_window = m.saturating_mul(contract).saturating_mul(n)
            >= PY_NATIVE_GEMM_MIN_FLOPS
            && m <= PY_NATIVE_GEMM_MAX_DIM
            && contract <= PY_NATIVE_GEMM_MAX_DIM
            && n <= PY_NATIVE_GEMM_MAX_DIM;
        if !in_native_window {
            return fallback();
        }
    }

    let a = match extract_precise_numeric_array(py, a.bind(py), "tensordot(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let b = match extract_precise_numeric_array(py, b.bind(py), "tensordot(b)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    if a.has_integer_sidecar()
        || b.has_integer_sidecar()
        || matches!(a.dtype(), DType::Complex64 | DType::Complex128)
        || matches!(b.dtype(), DType::Complex64 | DType::Complex128)
    {
        return fallback();
    }

    // tensordot(axes=k) flattens to the GEMM (m x contract) @ (contract x n).
    // Our native matmul_accumulate only beats numpy's BLAS inside the SAME
    // profiled sweet spot that np.matmul/np.dot gate on (flops >=
    // PY_NATIVE_GEMM_MIN_FLOPS and every flattened GEMM dim <=
    // PY_NATIVE_GEMM_MAX_DIM). tensordot previously ALWAYS took the native
    // path, so for contractions below that flop floor (or above the dim cap) it
    // ran up to ~16x slower than numpy. Route those to numpy.tensordot — the
    // result is numpy's own (the conformance reference is allclose), just far
    // faster — and keep the native GEMM only where it actually wins.
    let a_ndim = a.shape().len();
    let b_ndim = b.shape().len();
    if axes > a_ndim || axes > b_ndim {
        return fallback();
    }
    let contract: usize = a.shape()[a_ndim - axes..].iter().product();
    let m: usize = a.shape()[..a_ndim - axes].iter().product();
    let n: usize = b.shape()[axes..].iter().product();
    let native_competitive = a.dtype() == DType::F64
        && b.dtype() == DType::F64
        && m.saturating_mul(contract).saturating_mul(n) >= PY_NATIVE_GEMM_MIN_FLOPS
        && m <= PY_NATIVE_GEMM_MAX_DIM
        && contract <= PY_NATIVE_GEMM_MAX_DIM
        && n <= PY_NATIVE_GEMM_MAX_DIM;
    if !native_competitive {
        return fallback();
    }

    let result = match a.tensordot(&b, axes) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    build_numpy_scalar_or_array(py, &result)
}

// Zero-copy np.cross for two C-contiguous float64 ndarrays of identical shape
// (N, 3) with the default axes — the common 3-vector batch. Reads both operands'
// buffers directly and writes each row's cross product into a fresh
// numpy.empty((N, 3)) in one fused serial pass, skipping the two extract copies
// and the build round-trip the general path pays (the native UFuncArray::cross
// loop is itself serial, so this loses no parallelism). The component formula and
// output order (cx, cy, cz) are byte-for-byte identical to numpy and to that
// native f64 loop — same non-fused mul/sub ops, no FMA — so results are
// bit-identical incl. -0.0/inf/nan. Returns None (caller falls through) for any
// non-f64, non-(N,3), shape-mismatched, non-contiguous, or non-ndarray input.
fn try_zerocopy_f64_cross_n3(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    b: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) || !b.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    if !numpy_dtype_is_f64(py, a) || !numpy_dtype_is_f64(py, b) {
        return Ok(None);
    }
    let a_shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let b_shape: Vec<usize> = b.getattr("shape")?.extract()?;
    if a_shape.len() != 2 || a_shape[1] != 3 || a_shape != b_shape {
        return Ok(None);
    }
    // C-contiguous required so the flat buffer is row-major (row i begins at 3*i).
    if !a
        .getattr("flags")?
        .getattr("c_contiguous")?
        .extract::<bool>()?
        || !b
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return Ok(None);
    }
    let n = a_shape[0];
    let (Ok(a_buf), Ok(b_buf)) = (PyBuffer::<f64>::get(a), PyBuffer::<f64>::get(b)) else {
        return Ok(None);
    };
    let (Some(a_in), Some(b_in)) = (a_buf.as_slice(py), b_buf.as_slice(py)) else {
        return Ok(None);
    };
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let out = numpy.call_method("empty", ((n, 3),), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buf) = PyBuffer::<f64>::get(&out) else {
            return Ok(None);
        };
        let Some(output) = out_buf.as_mut_slice(py) else {
            return Ok(None);
        };
        for i in 0..n {
            let base = i * 3;
            let ax = a_in[base].get();
            let ay = a_in[base + 1].get();
            let az = a_in[base + 2].get();
            let bx = b_in[base].get();
            let by = b_in[base + 1].get();
            let bz = b_in[base + 2].get();
            output[base].set(ay * bz - az * by);
            output[base + 1].set(az * bx - ax * bz);
            output[base + 2].set(ax * by - ay * bx);
        }
    }
    Ok(Some(out.unbind()))
}

// f32 counterpart of try_zerocopy_f64_cross_n3: the f64 path is f64-only so float32 cross fell to
// the cold extract (~6x, 47ms@1Mx3). numpy.cross(float32) computes each component in f32 via the
// fixed formula (ay*bz - az*by, ...) -> no accumulation/reassociation -> bit-identical here.
fn try_zerocopy_f32_cross_n3(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    b: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) || !b.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    if !numpy_dtype_is_f32(a) || !numpy_dtype_is_f32(b) {
        return Ok(None);
    }
    let a_shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let b_shape: Vec<usize> = b.getattr("shape")?.extract()?;
    if a_shape.len() != 2 || a_shape[1] != 3 || a_shape != b_shape {
        return Ok(None);
    }
    if !a
        .getattr("flags")?
        .getattr("c_contiguous")?
        .extract::<bool>()?
        || !b
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return Ok(None);
    }
    let n = a_shape[0];
    let (Ok(a_buf), Ok(b_buf)) = (PyBuffer::<f32>::get(a), PyBuffer::<f32>::get(b)) else {
        return Ok(None);
    };
    let (Some(a_in), Some(b_in)) = (a_buf.as_slice(py), b_buf.as_slice(py)) else {
        return Ok(None);
    };
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float32")?;
    let out = numpy.call_method("empty", ((n, 3),), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buf) = PyBuffer::<f32>::get(&out) else {
            return Ok(None);
        };
        let Some(output) = out_buf.as_mut_slice(py) else {
            return Ok(None);
        };
        for i in 0..n {
            let base = i * 3;
            let ax = a_in[base].get();
            let ay = a_in[base + 1].get();
            let az = a_in[base + 2].get();
            let bx = b_in[base].get();
            let by = b_in[base + 1].get();
            let bz = b_in[base + 2].get();
            output[base].set(ay * bz - az * by);
            output[base + 1].set(az * bx - ax * bz);
            output[base + 2].set(ax * by - ay * bx);
        }
    }
    Ok(Some(out.unbind()))
}

#[pyfunction]
#[pyo3(signature = (a, b, axisa=-1, axisb=-1, axisc=-1, axis=None))]
fn cross(
    py: Python<'_>,
    a: Py<PyAny>,
    b: Py<PyAny>,
    axisa: i64,
    axisb: i64,
    axisc: i64,
    axis: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let cross_fn = numpy.getattr("cross")?;
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        kwargs.set_item("axisa", axisa)?;
        kwargs.set_item("axisb", axisb)?;
        kwargs.set_item("axisc", axisc)?;
        if let Some(value) = axis.as_ref() {
            kwargs.set_item("axis", value.bind(py))?;
        }
        Ok(cross_fn
            .call((a.bind(py), b.bind(py)), Some(&kwargs))?
            .unbind())
    };

    if axis.is_some() || axisa != -1 || axisb != -1 || axisc != -1 {
        return fallback();
    }

    // Zero-copy fast path for the common (N, 3) f64 batch: skips both extract copies
    // and the build round-trip the native path pays. Other dtypes/shapes fall through.
    if let Some(out) = try_zerocopy_f64_cross_n3(py, a.bind(py), b.bind(py))? {
        return Ok(out);
    }
    // f32 (N,3) cross: read f32 directly (the f64 path is f64-only; f32 otherwise ~6x cold extract).
    if let Some(out) = try_zerocopy_f32_cross_n3(py, a.bind(py), b.bind(py))? {
        return Ok(out);
    }

    let a = match extract_precise_numeric_array(py, a.bind(py), "cross(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let b = match extract_precise_numeric_array(py, b.bind(py), "cross(b)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    if a.has_integer_sidecar()
        || b.has_integer_sidecar()
        || matches!(a.dtype(), DType::Complex64 | DType::Complex128)
        || matches!(b.dtype(), DType::Complex64 | DType::Complex128)
    {
        return fallback();
    }

    let result = match a.cross(&b) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    build_numpy_scalar_or_array(py, &result)
}

#[pyfunction]
#[pyo3(signature = (arrays, *, out=None))]
fn multi_dot(py: Python<'_>, arrays: Py<PyAny>, out: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let multi_dot_fn = numpy.getattr("linalg")?.getattr("multi_dot")?;
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(value) = out.as_ref() {
            kwargs.set_item("out", value.bind(py))?;
        }
        Ok(multi_dot_fn
            .call((arrays.bind(py),), Some(&kwargs))?
            .unbind())
    };

    // Defer to numpy. multi_dot is just an optimally-ordered chain of matmuls; numpy
    // computes the same DP order and runs each product through threaded LAPACK/BLAS.
    // fnp's native `UFuncArray::multi_dot` also picks the optimal order but evaluates
    // each product through the register-tiled native GEMM, which is 1.7-7.6x SLOWER
    // than numpy across every measured chain shape (tiny3 4.5x, mixed4 7.6x, large3
    // 1.7x) — the same native-GEMM-vs-OpenBLAS gap that gates `matmul`/`dot`. The
    // result is float and the only conformance contract is allclose (no bit-exact
    // golden pins multi_dot's stream), so deferring matches numpy in both value and
    // speed with no parity regression. (The native path stays available for direct
    // Rust callers and its own fnp-ufunc tests.)
    fallback()
}

#[pyfunction]
#[pyo3(signature = (x, value, rtol=1e-5, atol=1e-8, copy=true, shrink=true))]
fn masked_values(
    py: Python<'_>,
    x: Py<PyAny>,
    value: Py<PyAny>,
    rtol: f64,
    atol: f64,
    copy: bool,
    shrink: bool,
) -> PyResult<Py<PyAny>> {
    let x_for_fallback = x.clone_ref(py);
    let value_for_fallback = value.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let masked_values_fn = numpy.getattr("ma")?.getattr("masked_values")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("rtol", rtol)?;
        kwargs.set_item("atol", atol)?;
        kwargs.set_item("copy", copy)?;
        kwargs.set_item("shrink", shrink)?;
        Ok(masked_values_fn
            .call(
                (x_for_fallback.bind(py), value_for_fallback.bind(py)),
                Some(&kwargs),
            )?
            .unbind())
    };

    // Fast path: a PLAIN ndarray x (never already-masked — get_type().is(ndarray)
    // excludes MaskedArray subclasses). numpy's own masked_values is the parity
    // reference and ~15x faster than the extract -> isclose -> rebuild path below
    // (194ms vs 12.7ms @4M f64). numpy computes the isclose mask, fills/shrinks, and
    // sets fill_value=value natively, so the result is identical.
    {
        let numpy = py.import("numpy")?;
        let ndarray_type = numpy.getattr("ndarray")?;
        if x.bind(py).get_type().is(&ndarray_type) {
            return fallback();
        }
    }

    let Some(masked_x) = extract_numeric_masked_array(py, x.bind(py), "masked_values(x)")? else {
        return fallback();
    };
    let scalar = match extract_precise_numeric_array(py, value.bind(py), "masked_values(value)") {
        Ok(value) if value.shape().is_empty() => value,
        _ => return fallback(),
    };

    let condition = if matches!(
        masked_x.data().dtype(),
        DType::F16 | DType::F32 | DType::F64
    ) || matches!(scalar.dtype(), DType::F16 | DType::F32 | DType::F64)
    {
        match masked_x.data().isclose(&scalar, rtol, atol) {
            Ok(condition) => condition,
            Err(_) => return fallback(),
        }
    } else {
        match masked_x.data().elementwise_binary(&scalar, BinaryOp::Equal) {
            Ok(condition) => condition,
            Err(_) => return fallback(),
        }
    };

    let filled_data = if masked_x.mask().is_some() {
        match masked_x.filled(scalar.values()[0]) {
            Ok(data) => data,
            Err(_) => return fallback(),
        }
    } else {
        masked_x.data().clone()
    };

    let mut mask = ma_mask_or(masked_x.mask(), Some(&condition));
    if shrink
        && mask
            .as_ref()
            .is_some_and(|mask| mask.values().iter().all(|&value| value == 0.0))
    {
        mask = None;
    }

    let result = MaskedArray::new(filled_data, mask, Some(scalar.values()[0]))
        .map_err(|err| map_ma_error("masked_values", err))?;
    let py_result = build_numpy_masked_array(py, &result)?;
    py_result
        .bind(py)
        .call_method1("set_fill_value", (value.bind(py),))?;
    Ok(py_result)
}

#[pyfunction]
#[pyo3(signature = (arr, to_end=None, to_begin=None))]
fn ma_ediff1d(
    py: Python<'_>,
    arr: Py<PyAny>,
    to_end: Option<Py<PyAny>>,
    to_begin: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let builtins = py.import("builtins")?;
    let arr_any = numpy.call_method1("asanyarray", (arr.bind(py),))?;
    let masked_array_type = numpy.getattr("ma")?.getattr("MaskedArray")?;
    let input_is_masked_array = builtins
        .call_method1("isinstance", (&arr_any, masked_array_type))?
        .extract::<bool>()?;
    let fill_value = if input_is_masked_array {
        arr_any.getattr("fill_value")?.unbind()
    } else {
        numpy
            .getattr("ma")?
            .getattr("default_fill_value")?
            .call1((&arr_any,))?
            .unbind()
    };

    let arr_for_fallback = arr.clone_ref(py);
    let to_end_for_fallback = to_end.as_ref().map(|value| value.clone_ref(py));
    let to_begin_for_fallback = to_begin.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let ma_ediff1d_fn = numpy.getattr("ma")?.getattr("ediff1d")?;
        let kwargs = PyDict::new(py);
        if let Some(value) = &to_end_for_fallback {
            kwargs.set_item("to_end", value.bind(py))?;
        }
        if let Some(value) = &to_begin_for_fallback {
            kwargs.set_item("to_begin", value.bind(py))?;
        }
        Ok(ma_ediff1d_fn
            .call((arr_for_fallback.bind(py),), Some(&kwargs))?
            .unbind())
    };

    let Some(flat) = extract_numeric_masked_array(py, arr.bind(py), "ma_ediff1d(arr)")?
        .map(|array| array.ravel())
    else {
        return fallback();
    };

    let diff = if flat.data().values().len() < 2 {
        MaskedArray::new(
            flat.data().ediff1d().map_err(map_ufunc_error)?,
            None,
            Some(flat.fill_value()),
        )
        .map_err(|err| map_ma_error("ma_ediff1d", err))?
    } else {
        let right_indices = (1..flat.data().values().len())
            .map(|index| index as i64)
            .collect::<Vec<_>>();
        let left_indices = (0..flat.data().values().len() - 1)
            .map(|index| index as i64)
            .collect::<Vec<_>>();
        let right = flat
            .take(&right_indices)
            .map_err(|err| map_ma_error("ma_ediff1d", err))?;
        let left = flat
            .take(&left_indices)
            .map_err(|err| map_ma_error("ma_ediff1d", err))?;
        right
            .elementwise_binary(&left, BinaryOp::Sub)
            .map_err(|err| map_ma_error("ma_ediff1d", err))?
    };

    let begin = match to_begin {
        Some(value) => {
            match extract_numeric_masked_array(py, value.bind(py), "ma_ediff1d(to_begin)")? {
                Some(value) => Some(value.ravel()),
                None => return fallback(),
            }
        }
        None => None,
    };
    let end = match to_end {
        Some(value) => {
            match extract_numeric_masked_array(py, value.bind(py), "ma_ediff1d(to_end)")? {
                Some(value) => Some(value.ravel()),
                None => return fallback(),
            }
        }
        None => None,
    };

    let result = match (begin.as_ref(), end.as_ref()) {
        (None, None) => diff,
        (Some(begin), None) => MaskedArray::concatenate(&[begin, &diff], 0)
            .map_err(|err| map_ma_error("ma_ediff1d", err))?,
        (None, Some(end)) => MaskedArray::concatenate(&[&diff, end], 0)
            .map_err(|err| map_ma_error("ma_ediff1d", err))?,
        (Some(begin), Some(end)) => MaskedArray::concatenate(&[begin, &diff, end], 0)
            .map_err(|err| map_ma_error("ma_ediff1d", err))?,
    };

    let py_result = build_numpy_masked_array(py, &result)?;
    py_result
        .bind(py)
        .call_method1("set_fill_value", (fill_value.bind(py),))?;
    // numpy.ma.ediff1d uses an explicit all-False bool mask (not the
    // nomask scalar) ONLY when to_begin or to_end is provided — in that
    // case numpy's concat path synthesises an explicit mask for the
    // boundary entries. Without boundaries it reuses the input's
    // nomask. Match that asymmetry so repr parity holds (tuf2).
    let had_boundary = begin.is_some() || end.is_some();
    if had_boundary {
        let mask_attr = py_result.bind(py).getattr("mask")?;
        let ma = numpy.getattr("ma")?;
        let is_nomask: bool = mask_attr.is(&ma.getattr("nomask")?);
        if is_nomask {
            let shape = py_result.bind(py).getattr("shape")?;
            let zeros_kwargs = PyDict::new(py);
            zeros_kwargs.set_item("dtype", numpy.getattr("bool_")?)?;
            let explicit_mask = numpy
                .getattr("zeros")?
                .call((shape,), Some(&zeros_kwargs))?;
            py_result.bind(py).setattr("mask", explicit_mask)?;
        }
    }
    Ok(py_result)
}

