#[pyfunction]
#[pyo3(signature = (x, p=None))]
fn cond(py: Python<'_>, x: Py<PyAny>, p: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    // 2-norm condition number (p in {None, 2, -2}) is purely svd-derived:
    // sigma_max/sigma_min (or its reciprocal for -2). For batched (..., M, N)
    // inputs numpy runs a serial-C per-lane SVD, whereas fnp_linalg::batch_svd
    // does the same per-lane svd_mxn in parallel (rayon) — a no-gaps win in the
    // same parity-safe class as batched svdvals/eigvalsh (singular values are
    // deterministic; cond's allclose-level result tolerates the ~2-ULP delta).
    // The other p values (1, -1, 'fro', inf, -inf) use matrix-inverse norms and
    // every 2-D case stay on the numpy passthrough so all eight semantics and
    // complex inputs match exactly.
    let numpy = py.import("numpy")?;
    let cond_fn = numpy.getattr("linalg")?.getattr("cond")?;
    // p_mode: Some(2) -> sigma_max/sigma_min, Some(-2) -> sigma_min/sigma_max,
    // None -> not a 2-norm selector (fall back to numpy).
    let p_mode: Option<i8> = match &p {
        None => Some(2),
        Some(value) => match value.bind(py).extract::<f64>() {
            Ok(f) if f == 2.0 => Some(2),
            Ok(f) if f == -2.0 => Some(-2),
            _ => None,
        },
    };
    if let Some(mode) = p_mode {
        if let Ok(array) = extract_numeric_array(py, x.bind(py), "cond(x)") {
            let shape = array.shape();
            if shape.len() >= 3
                && matches!(array.dtype(), DType::F64)
                && !array.has_integer_sidecar()
                && array.values().iter().all(|v| v.is_finite())
            {
                let m = shape[shape.len() - 2];
                let n = shape[shape.len() - 1];
                let k = m.min(n);
                let owned_shape = shape.to_vec();
                if k >= 1 {
                    if let Ok(sigmas) = fnp_linalg::batch_svd(array.values(), &owned_shape) {
                        let batch = sigmas.len() / k;
                        let mut out = Vec::with_capacity(batch);
                        for b in 0..batch {
                            let smax = sigmas[b * k];
                            let smin = sigmas[b * k + k - 1];
                            let ratio = if mode == 2 { smax / smin } else { smin / smax };
                            // numpy.linalg.cond converts a NaN result (0/0 from an
                            // all-zero / fully singular matrix) to +Inf whenever the
                            // input had no NaN entries. Our gate already requires
                            // all-finite input, so every NaN here becomes Inf.
                            out.push(if ratio.is_nan() {
                                f64::INFINITY
                            } else {
                                ratio
                            });
                        }
                        let out_shape: Vec<usize> =
                            owned_shape[..owned_shape.len() - 2].to_vec();
                        let result = UFuncArray::new(out_shape, out, DType::F64)
                            .map_err(map_ufunc_error)?;
                        return build_numpy_array_from_ufunc(py, &result);
                    }
                }
            }
        }
    }
    let kwargs = PyDict::new(py);
    if let Some(value) = p {
        kwargs.set_item("p", value.bind(py))?;
    }
    Ok(cond_fn.call((x.bind(py),), Some(&kwargs))?.unbind())
}

/// Maps an `ord` value to the SVD-derived matrix-norm reduction mode, or `None`
/// for the cheap (non-SVD) orders. 0 = spectral (sigma_max), 1 = neg-spectral
/// (sigma_min), 2 = nuclear (sum of singular values).
fn svd_matrix_norm_mode(py: Python<'_>, ord: &Py<PyAny>) -> Option<u8> {
    let bound = ord.bind(py);
    if let Ok(text) = bound.extract::<String>() {
        if text == "nuc" {
            Some(2)
        } else {
            None
        }
    } else if let Ok(f) = bound.extract::<f64>() {
        if f == 2.0 {
            Some(0)
        } else if f == -2.0 {
            Some(1)
        } else {
            None
        }
    } else {
        None
    }
}

/// Batched SVD-derived matrix norm on the trailing two axes. Returns
/// `Ok(Some(result))` when the fast path applies (real-finite-f64, ndim >= 3),
/// else `Ok(None)` to signal the caller should fall back to numpy. The singular
/// values are deterministic so this is parity-safe at the allclose level.
fn try_batched_svd_matrix_norm(
    py: Python<'_>,
    array: &UFuncArray,
    mode: u8,
    keepdims: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let shape = array.shape();
    if shape.len() < 3
        || !matches!(array.dtype(), DType::F64)
        || array.has_integer_sidecar()
        || !array.values().iter().all(|v| v.is_finite())
    {
        return Ok(None);
    }
    let m_dim = shape[shape.len() - 2];
    let n_dim = shape[shape.len() - 1];
    let k = m_dim.min(n_dim);
    if k < 1 {
        return Ok(None);
    }
    let owned_shape = shape.to_vec();
    let sigmas = match fnp_linalg::batch_svd(array.values(), &owned_shape) {
        Ok(sigmas) => sigmas,
        Err(_) => return Ok(None),
    };
    let batch = sigmas.len() / k;
    let mut out = Vec::with_capacity(batch);
    for b in 0..batch {
        let lane = &sigmas[b * k..b * k + k];
        out.push(match mode {
            0 => lane[0],
            1 => lane[k - 1],
            _ => lane.iter().sum(),
        });
    }
    let mut out_shape: Vec<usize> = owned_shape[..owned_shape.len() - 2].to_vec();
    if keepdims {
        out_shape.push(1);
        out_shape.push(1);
    }
    let result = UFuncArray::new(out_shape, out, DType::F64).map_err(map_ufunc_error)?;
    Ok(Some(build_numpy_array_from_ufunc(py, &result)?))
}

#[pyfunction]
#[pyo3(signature = (x, ord=None, axis=None, keepdims=false))]
fn norm(
    py: Python<'_>,
    x: Py<PyAny>,
    ord: Option<Py<PyAny>>,
    axis: Option<Py<PyAny>>,
    keepdims: bool,
) -> PyResult<Py<PyAny>> {
    // np.linalg.norm with an SVD-derived matrix order (ord in {2, -2, 'nuc'})
    // over the trailing two axes (axis a 2-tuple resolving to {ndim-2, ndim-1})
    // on a batched real-finite-f64 stack is the same parallel batch_svd win as
    // matrix_norm — numpy runs a serial-C per-lane SVD. Spectral/nuclear norms
    // are transpose-invariant, so axis order within the pair is irrelevant.
    // Everything else (vector norms, other orders, non-trailing axes, complex,
    // non-finite, 2-D) stays on the numpy passthrough.
    if let (Some(ord_val), Some(axis_val)) = (ord.as_ref(), axis.as_ref()) {
        if let Some(mode) = svd_matrix_norm_mode(py, ord_val) {
            if let Ok((ax0, ax1)) = axis_val.bind(py).extract::<(i64, i64)>() {
                if let Ok(array) = extract_numeric_array(py, x.bind(py), "norm(x)") {
                    let nd = array.shape().len() as i64;
                    let resolve = |a: i64| if a < 0 { a + nd } else { a };
                    let (r0, r1) = (resolve(ax0), resolve(ax1));
                    let mut pair = [r0, r1];
                    pair.sort_unstable();
                    let trailing = nd >= 3
                        && r0 >= 0
                        && r1 >= 0
                        && r0 < nd
                        && r1 < nd
                        && pair == [nd - 2, nd - 1];
                    if trailing {
                        if let Some(result) =
                            try_batched_svd_matrix_norm(py, &array, mode, keepdims)?
                        {
                            return Ok(result);
                        }
                    }
                }
            }
        }
    }
    // Vector norm along the contiguous last axis (ord None/1/2/+-inf, single int
    // axis): numpy materializes abs(x) (L1, +-inf) or (x.conj()*x).real (L2) then a
    // per-axis reduce (add.reduce +sqrt for L2; max/min for +-inf); the native
    // per-lane fold avoids the temporary. See try_zerocopy_f64_vector_norm_axis.
    if let Some(axis_val) = axis.as_ref() {
        let kind = match ord.as_ref() {
            None => Some(VectorNormKind::L2),
            Some(o) => {
                let ob = o.bind(py);
                let as_i = ob.extract::<i64>().ok();
                let as_f = ob.extract::<f64>().ok();
                if as_i == Some(2) || as_f == Some(2.0) {
                    Some(VectorNormKind::L2)
                } else if as_i == Some(1) || as_f == Some(1.0) {
                    Some(VectorNormKind::L1)
                } else if as_f == Some(f64::INFINITY) {
                    Some(VectorNormKind::MaxAbs)
                } else if as_f == Some(f64::NEG_INFINITY) {
                    Some(VectorNormKind::MinAbs)
                } else {
                    None
                }
            }
        };
        if let Some(kind) = kind
            && let Some(result) = try_zerocopy_f64_vector_norm_axis(
                py,
                x.bind(py),
                axis_val.bind(py),
                kind,
                keepdims,
            )?
        {
            return Ok(result);
        }
    }
    // Batched Frobenius norm (ord None/'fro'/'f' over an explicit trailing 2-tuple
    // axis): numpy materializes (x*x).real then a single-threaded add.reduce over
    // both axes; the per-(M*N)-block pairwise-sq fold avoids the temporary. See
    // try_zerocopy_f64_frobenius_lastaxes. (ord=None with axis=None is the BLAS-dot
    // ravel path and is left to numpy - this only fires for a 2-tuple axis.)
    if let Some(axis_val) = axis.as_ref() {
        let is_fro = match ord.as_ref() {
            None => true,
            Some(o) => o
                .bind(py)
                .extract::<String>()
                .is_ok_and(|s| s == "fro" || s == "f"),
        };
        if is_fro
            && let Ok((ax0, ax1)) = axis_val.bind(py).extract::<(i64, i64)>()
            && let Some(result) =
                try_zerocopy_f64_frobenius_lastaxes(py, x.bind(py), ax0, ax1, keepdims)?
        {
            return Ok(result);
        }
    }
    // Induced matrix p-norm (ord 1/-1/+inf/-inf over an explicit trailing 2-tuple
    // axis): numpy materializes abs(x) then a per-row/col add.reduce + max/min (three
    // passes); the per-block fold avoids the temporary. ord=2/-2/'nuc' are the SVD
    // path above; this only handles the row/column abs-sum orders. See
    // try_zerocopy_f64_matrix_norm_lastaxes.
    if let (Some(ord_val), Some(axis_val)) = (ord.as_ref(), axis.as_ref()) {
        let ob = ord_val.bind(py);
        let as_i = ob.extract::<i64>().ok();
        let as_f = ob.extract::<f64>().ok();
        let kind = if as_i == Some(1) || as_f == Some(1.0) {
            Some(MatrixNormKind::MaxColSum)
        } else if as_i == Some(-1) || as_f == Some(-1.0) {
            Some(MatrixNormKind::MinColSum)
        } else if as_f == Some(f64::INFINITY) {
            Some(MatrixNormKind::MaxRowSum)
        } else if as_f == Some(f64::NEG_INFINITY) {
            Some(MatrixNormKind::MinRowSum)
        } else {
            None
        };
        if let Some(kind) = kind
            && let Ok((ax0, ax1)) = axis_val.bind(py).extract::<(i64, i64)>()
            && let Some(result) =
                try_zerocopy_f64_matrix_norm_lastaxes(py, x.bind(py), ax0, ax1, kind, keepdims)?
        {
            return Ok(result);
        }
    }
    // Passthrough to np.linalg.norm so ord (None/fro/nuc/int/inf/-inf/real),
    // axis (None/int/tuple), keepdims, and 1-D vector vs 2-D matrix vs
    // batched (..., M, N) broadcasting semantics all match numpy exactly.
    let numpy = py.import("numpy")?;
    let norm_fn = numpy.getattr("linalg")?.getattr("norm")?;
    let kwargs = PyDict::new(py);
    if let Some(value) = ord {
        kwargs.set_item("ord", value.bind(py))?;
    }
    if let Some(value) = axis {
        kwargs.set_item("axis", value.bind(py))?;
    }
    kwargs.set_item("keepdims", keepdims)?;
    Ok(norm_fn.call((x.bind(py),), Some(&kwargs))?.unbind())
}

#[pyfunction]
#[pyo3(signature = (x, axes=None))]
fn fftshift(py: Python<'_>, x: Py<PyAny>, axes: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    // Native fftshift via UFuncArray::roll{,_multi}: for every axis ax,
    // shift the array by shape[ax] // 2. Falls back to np.fft.fftshift for
    // non-numeric dtypes or unusual axis encodings (e.g. duplicate axes,
    // negative-axis tuples that numpy rejects) so error surface matches.
    fft_shift_impl(py, x, axes, /*inverse=*/ false, "fftshift")
}

#[pyfunction]
#[pyo3(signature = (x, axes=None))]
fn ifftshift(py: Python<'_>, x: Py<PyAny>, axes: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    // Native ifftshift — same as fftshift with negated shifts. On odd-length
    // arrays ifftshift is the true inverse of fftshift.
    fft_shift_impl(py, x, axes, /*inverse=*/ true, "ifftshift")
}

fn fft_shift_impl(
    py: Python<'_>,
    x: Py<PyAny>,
    axes: Option<Py<PyAny>>,
    _inverse: bool,
    numpy_name: &'static str,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let np_fn = numpy.getattr("fft")?.getattr(numpy_name)?;
    let x_for_fallback = x.clone_ref(py);
    let axes_for_fallback = axes.as_ref().map(|v| v.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(value) = axes_for_fallback.as_ref() {
            kwargs.set_item("axes", value.bind(py))?;
        }
        Ok(np_fn
            .call((x_for_fallback.bind(py),), Some(&kwargs))?
            .unbind())
    };

    // Passthrough to np.fft.{i}fftshift. The native roll-based path
    // (UFuncArray::roll/roll_multi) matches numpy's algorithm — a circular shift is
    // a pure data move — but pays the Py<->Rust bridge's per-call full-size
    // allocations (extracted Vec + rolled buffer + exported buffer), running
    // 14-72x slower on non-trivial arrays (1M f64: native 13.1ms vs numpy 0.18ms;
    // even N=1000 is 1.24x). A circular shift can at best tie numpy, so route to
    // numpy — same rationale as sort/norm/partition. Parity is exact (it IS numpy).
    fallback()
}

#[pyfunction]
#[pyo3(signature = (n, d=1.0, device=None))]
fn rfftfreq(py: Python<'_>, n: usize, d: f64, device: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    validate_cpu_device_kwarg(py, device)?;
    if n == 0 || d == 0.0 {
        return Err(PyZeroDivisionError::new_err("float division by zero"));
    }
    // numpy.fft.rfftfreq is a single tight `arange(0, n//2+1) / (n*d)` generation;
    // our native UFuncArray build + bridge copy round-trips a fresh Rust Vec and is
    // ~3.4x slower for large n (1.25ms vs 0.36ms at n=1<<20). The output is the
    // bit-identical sequence k/(n*d) for k in 0..=n/2 (verified array_equal across n,
    // d), and numpy returns the same writeable/owndata float64 array our build did,
    // so delegate the generation to numpy. The device kwarg was validated above and
    // n==0 / d==0 already raise the same ZeroDivisionError numpy itself would.
    let numpy = py.import("numpy")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("d", d)?;
    Ok(numpy
        .getattr("fft")?
        .call_method("rfftfreq", (n,), Some(&kwargs))?
        .unbind())
}

#[pyfunction]
#[pyo3(signature = (n, d=1.0, device=None))]
fn fftfreq(py: Python<'_>, n: usize, d: f64, device: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    // Mirror the rfftfreq wrapper's device-kwarg guard and zero-division
    // checks, then delegate to the Rust UFuncArray::fftfreq fast path so
    // n/d semantics match numpy exactly for even and odd n.
    validate_cpu_device_kwarg(py, device)?;
    if n == 0 || d == 0.0 {
        return Err(PyZeroDivisionError::new_err("float division by zero"));
    }
    let result = UFuncArray::fftfreq(n, d);
    build_numpy_array_from_ufunc(py, &result)
}

fn validate_irfft_norm(norm: Option<&str>) -> PyResult<()> {
    match norm {
        None | Some("backward") | Some("ortho") | Some("forward") => Ok(()),
        Some(other) => Err(PyValueError::new_err(format!(
            "Invalid norm value {other}; should be \"backward\",\"ortho\" or \"forward\"."
        ))),
    }
}

