#[pyfunction]
#[pyo3(signature = (v, k=0))]
fn diag(py: Python<'_>, v: Py<PyAny>, k: i64) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let arr = numpy.call_method1("asarray", (v.bind(py),))?;
    let dtype_kind = arr.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
    if dtype_kind == "c" {
        return Ok(numpy.getattr("diag")?.call1((arr, k))?.unbind());
    }
    // 2-D input: np.diag(M, k) returns numpy's read-only, strided VIEW of the
    // k-diagonal — O(1), shares memory with M — because the numpy function simply
    // forwards to M.diagonal(k). The previous fast path read those N values through
    // the bridge into a fresh contiguous owndata copy, which was both O(N) work AND
    // a semantic divergence: numpy's result is a non-contiguous, read-only view that
    // aliases M (writeable=False, owndata=False), whereas the copy was writeable and
    // owned. Delegate to numpy.diag for the exact view, dtype, writeable flag, and
    // aliasing — we cannot beat an O(1) stride trick by copying. (1-D input
    // CONSTRUCTS a matrix and is handled by the zero-copy diagflat path below.)
    if let Ok(shape) = arr.getattr("shape").and_then(|s| s.extract::<Vec<usize>>())
        && shape.len() == 2
    {
        return Ok(numpy.getattr("diag")?.call1((arr, k))?.unbind());
    }
    // 1-D input CONSTRUCTS an (n+|k|)×(n+|k|) matrix with v on the k-th diagonal —
    // identical to diagflat for a 1-D operand. The generic path below materializes
    // the WHOLE n² output Vec (mostly zeros) in the UFuncArray and copies it across
    // the bridge — O(n²); numpy uses lazy calloc + writes only the n diagonal cells.
    // Route f64 1-D to the zero-copy diagflat construction (numpy.zeros lazy pages +
    // diagonal write), which is byte-identical (zeros + verbatim diagonal values).
    // 20x faster at n=2000 (33.5ms→~1.6ms).
    if let Ok(shape) = arr.getattr("shape").and_then(|s| s.extract::<Vec<usize>>())
        && shape.len() == 1
        && let Some(out) = try_zerocopy_f64_diagflat(py, &arr, k)?
    {
        return Ok(out);
    }
    // Non-f64 1-D construct: the native path materialized the WHOLE n² output Vec
    // (mostly zeros) then converted it across the bridge — ~573x slower for int8 at
    // n=2000. numpy uses lazy calloc + writes only the n diagonal cells. Delegate.
    Ok(numpy.getattr("diag")?.call1((arr, k))?.unbind())
}

// Zero-copy np.diagflat(v, k) for a C-contiguous float64 ndarray: numpy flattens
// v (length n) and returns a square (n+|k|) matrix of zeros with v placed on the
// k-th diagonal — out[i, i+k] = v[i] for k>=0, out[i+|k|, i] = v[i] for k<0. This
// writes those n diagonal entries straight into a numpy.zeros((s, s)) buffer with
// no intermediate Rust Vec of the full s*s result, dropping the cold extract/build
// Vecs (bead lglck). Values are copied verbatim, so it is bit-identical to numpy
// incl. -0.0/inf/nan. Returns Ok(None) — caller falls through — for any non-f64 /
// non-contiguous / non-ndarray input.
fn try_zerocopy_f64_diagflat(
    py: Python<'_>,
    v: &Bound<'_, PyAny>,
    k: i64,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !v.is_exact_instance(&ndarray_type) || !numpy_dtype_is_f64(py, v) {
        return Ok(None);
    }
    let Ok(buffer) = PyBuffer::<f64>::get(v) else {
        return Ok(None);
    };
    let Some(input) = buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = input.len();
    let abs_k = k.unsigned_abs() as usize;
    let s = n + abs_k;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let out = numpy.call_method("zeros", ((s, s),), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&out) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // Flat index of element (row, col) in the s*s C-contiguous output.
        for (i, cell) in input.iter().enumerate() {
            let (row, col) = if k >= 0 {
                (i, i + abs_k)
            } else {
                (i + abs_k, i)
            };
            output[row * s + col].set(cell.get());
        }
    }
    Ok(Some(out.unbind()))
}

#[pyfunction]
#[pyo3(signature = (v, k=0))]
fn diagflat(py: Python<'_>, v: Py<PyAny>, k: i64) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let arr = numpy.call_method1("asarray", (v.bind(py),))?;
    let dtype_kind = arr.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
    if dtype_kind == "c" {
        return Ok(numpy.getattr("diagflat")?.call1((arr, k))?.unbind());
    }
    // Zero-copy diagonal write for C-contiguous f64 ndarrays; skips the cold
    // extract + full s*s build Vecs. Bit-identical; other dtypes fall through.
    if let Some(result) = try_zerocopy_f64_diagflat(py, v.bind(py), k)? {
        return Ok(result);
    }
    // Non-f64: the native path materialized the whole s² output then converted it
    // across the bridge (~34x slower). numpy writes only the diagonal into lazy
    // calloc memory. Delegate.
    Ok(numpy.getattr("diagflat")?.call1((arr, k))?.unbind())
}

#[pyfunction]
#[pyo3(signature = (a, offset=0, axis1=0, axis2=1))]
fn diagonal(
    py: Python<'_>,
    a: Py<PyAny>,
    offset: i64,
    axis1: isize,
    axis2: isize,
) -> PyResult<Py<PyAny>> {
    // np.diagonal returns a strided, READ-ONLY VIEW (O(1)) since numpy 1.9 — it
    // never copies. The old native path materialized a writable copy, which both
    // cost O(n^2) (it bridged the whole matrix) and diverged from numpy's
    // read-only-view semantics. Delegate to numpy.diagonal for the exact view,
    // dtype, writeable flag, and error surface.
    let numpy = py.import("numpy")?;
    Ok(numpy
        .getattr("diagonal")?
        .call1((a.bind(py), offset, axis1, axis2))?
        .unbind())
}

// Zero-copy in-place np.fill_diagonal(a, val) for a 2-D float64 ndarray with a
// scalar val. numpy writes a[i, i] = val for i in 0..min(rows, cols), i.e. the
// flat positions i*(cols+1). This writes those at most min(rows, cols) entries
// straight into a's own buffer via as_mut_slice — no extract of the whole matrix
// and no full copy-back (the general path round-trips the entire n*n array),
// dropping the cold boundary-tax Vecs (bead lglck). The value is copied verbatim,
// so the mutation is bit-identical incl. -0.0/inf/nan. Returns Ok(false) — caller
// falls through — for a non-scalar val, a non-2-D array, a wrapping tall matrix
// (wrap && rows > cols, which fills extra wrapped entries), a read-only array, or
// any non-f64 / non-contiguous / non-ndarray input.
fn try_zerocopy_f64_fill_diagonal(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    val: &Bound<'_, PyAny>,
    wrap: bool,
) -> PyResult<bool> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) || !numpy_dtype_is_f64(py, a) {
        return Ok(false);
    }
    // Only a scalar float val keeps the fast path (array vals cycle along the
    // diagonal and are deferred to the general path).
    let Ok(fill) = val.extract::<f64>() else {
        return Ok(false);
    };
    let Ok(buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(false);
    };
    let shape = buffer.shape();
    if shape.len() != 2 {
        return Ok(false);
    }
    let rows = shape[0];
    let cols = shape[1];
    // A wrapping tall matrix fills additional wrapped diagonal entries; defer.
    if wrap && rows > cols {
        return Ok(false);
    }
    let count = rows.min(cols);
    let step = cols + 1;
    let Some(output) = buffer.as_mut_slice(py) else {
        return Ok(false);
    };
    for i in 0..count {
        output[i * step].set(fill);
    }
    Ok(true)
}

#[pyfunction]
#[pyo3(signature = (a, val, wrap=false))]
fn fill_diagonal(py: Python<'_>, a: Py<PyAny>, val: Py<PyAny>, wrap: bool) -> PyResult<Py<PyAny>> {
    let a = a.bind(py);
    require_numpy_ndarray(py, a, "fill_diagonal")?;

    // Check for complex dtype and fallback to numpy
    let dtype_kind = a.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
    if dtype_kind == "c" {
        let numpy = py.import("numpy")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("wrap", wrap)?;
        numpy
            .getattr("fill_diagonal")?
            .call((a, val.bind(py)), Some(&kwargs))?;
        return Ok(py.None());
    }

    // Zero-copy in-place write for the common case (2-D f64 matrix + scalar val);
    // touches only the diagonal slots of a's own buffer, skipping the full-matrix
    // extract and copy-back. Bit-identical; array vals, non-2-D, wrapping tall
    // matrices, and other dtypes fall through.
    if try_zerocopy_f64_fill_diagonal(py, a, val.bind(py), wrap)? {
        return Ok(py.None());
    }

    // Residual (non-f64 dtype, array val, non-2-D, wrapping tall matrix): the old
    // path extracted the ENTIRE matrix to an f64 Vec and copied it back, even though
    // fill_diagonal only writes the n diagonal slots — ~60-611x slower than numpy for
    // a 2000x2000 int8. numpy writes only the diagonal in place (and owns the exact
    // dtype-cast surface), so delegate.
    let numpy = py.import("numpy")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("wrap", wrap)?;
    numpy
        .getattr("fill_diagonal")?
        .call((a, val.bind(py)), Some(&kwargs))?;
    Ok(py.None())
}

#[pyfunction]
#[pyo3(signature = (*args))]
fn ix_(py: Python<'_>, args: &Bound<'_, PyTuple>) -> PyResult<Py<PyAny>> {
    // numpy.ix_ just reshapes each 1-D input to its broadcast axis ((N,1)/(1,N)/...) —
    // O(1) view-reshapes, ~1.7us flat. The native path cold-extracted each operand and
    // materialized via UFuncArray::ix_, scaling O(N) and hitting 2530x at N=100K
    // (BlackThrush 2026-06-22). Delegate to numpy.ix_ for parity. (composite-op-routes-
    // to-slow-native-path fix, cf matrix_power / einsum-diagonal / true_divide.)
    Ok(py
        .import("numpy")?
        .getattr("ix_")?
        .call(args, None)?
        .unbind())
}

// Build np.repeat(v, times).reshape(len(v), times): each row i is the scalar v[i]
// repeated `times` times. Value-agnostic via a uintN bit-view chosen by itemsize; the
// per-row fill is a memset that vectorizes. Returns None for complex128 / object /
// string / non-contiguous (no fixed uintN mover).
fn try_zerocopy_repeat_each(
    py: Python<'_>,
    v: &Bound<'_, PyAny>,
    times: usize,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let dtype = v.getattr("dtype")?;
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    if !matches!(itemsize, 1 | 2 | 4 | 8) {
        return Ok(None);
    }
    let mover_name = match itemsize {
        1 => "uint8",
        2 => "uint16",
        4 => "uint32",
        _ => "uint64",
    };
    let mover = numpy.getattr(mover_name)?;
    let v_view = v.call_method1("view", (&mover,))?;
    fn fill<'py, T: pyo3::buffer::Element + Copy>(
        py: Python<'py>,
        numpy: &Bound<'py, PyModule>,
        v_view: &Bound<'py, PyAny>,
        times: usize,
        mover_name: &str,
    ) -> PyResult<Option<(Bound<'py, PyAny>, usize)>> {
        let Ok(in_buf) = PyBuffer::<T>::get(v_view) else {
            return Ok(None);
        };
        let Some(input) = in_buf.as_slice(py) else {
            return Ok(None);
        };
        let m = input.len();
        let total = m * times;
        let kw = PyDict::new(py);
        kw.set_item("dtype", mover_name)?;
        let out = numpy.call_method("empty", (total,), Some(&kw))?;
        if total > 0 {
            let Ok(out_buf) = PyBuffer::<T>::get(&out) else {
                return Ok(None);
            };
            let Some(output) = out_buf.as_mut_slice(py) else {
                return Ok(None);
            };
            for (i, c) in input.iter().enumerate() {
                let val = c.get();
                for cell in &output[i * times..i * times + times] {
                    cell.set(val);
                }
            }
        }
        Ok(Some((out, m)))
    }
    let res = match itemsize {
        1 => fill::<u8>(py, &numpy, &v_view, times, mover_name)?,
        2 => fill::<u16>(py, &numpy, &v_view, times, mover_name)?,
        4 => fill::<u32>(py, &numpy, &v_view, times, mover_name)?,
        _ => fill::<u64>(py, &numpy, &v_view, times, mover_name)?,
    };
    let Some((out, m)) = res else {
        return Ok(None);
    };
    let restored = out.call_method1("view", (&dtype,))?;
    let shape = PyTuple::new(py, [m, times])?;
    Ok(Some(restored.call_method1("reshape", (&shape,))?.unbind()))
}

// Zero-copy np.meshgrid for the common 2-input, dense, copy=True, xy/ij case. Each
// output keeps its own input's dtype: one is the input tiled as rows (tile), the other
// is the input repeated element-wise across rows (repeat_each) — both value-agnostic
// byte/typed fills, far cheaper than the UFuncArray build (~160x). >2 inputs, sparse,
// copy=False, non-1-D inputs, and complex128/object fall through to the existing path.
fn try_zerocopy_meshgrid_2d(
    py: Python<'_>,
    xi: &Bound<'_, PyTuple>,
    copy: bool,
    sparse: bool,
    indexing: &str,
) -> PyResult<Option<Py<PyAny>>> {
    if sparse || !copy || xi.len() != 2 || (indexing != "xy" && indexing != "ij") {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    let x = xi.get_item(0)?;
    let y = xi.get_item(1)?;
    for v in [&x, &y] {
        if !v.is_exact_instance(&ndarray_type) || v.getattr("ndim")?.extract::<usize>()? != 1 {
            return Ok(None);
        }
        let k = v.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
        if !matches!(k.as_str(), "b" | "i" | "u" | "f" | "c") {
            return Ok(None);
        }
    }
    let n = x.len()?; // len(x)
    let m = y.len()?; // len(y)
    // xy: X = tile(x) as m rows (m,n); Y = repeat each y across n cols (m,n).
    // ij: X = repeat each x across m cols (n,m); Y = tile(y) as n rows (n,m).
    let (out0, out1) = if indexing == "xy" {
        let x_tile = try_zerocopy_any_tile(py, &x, &[m, 1])?;
        let y_rep = try_zerocopy_repeat_each(py, &y, n)?;
        match (x_tile, y_rep) {
            (Some(a), Some(b)) => (a, b),
            _ => return Ok(None),
        }
    } else {
        let x_rep = try_zerocopy_repeat_each(py, &x, m)?;
        let y_tile = try_zerocopy_any_tile(py, &y, &[n, 1])?;
        match (x_rep, y_tile) {
            (Some(a), Some(b)) => (a, b),
            _ => return Ok(None),
        }
    };
    Ok(Some(
        PyTuple::new(py, [out0.bind(py), out1.bind(py)])?
            .unbind()
            .into_any(),
    ))
}

#[pyfunction]
#[pyo3(signature = (*xi, copy=true, sparse=false, indexing="xy"))]
fn meshgrid(
    py: Python<'_>,
    xi: &Bound<'_, PyTuple>,
    copy: bool,
    sparse: bool,
    indexing: &str,
) -> PyResult<Py<PyAny>> {
    if let Some(out) = try_zerocopy_meshgrid_2d(py, xi, copy, sparse, indexing)? {
        return Ok(out);
    }
    let arrays = normalize_meshgrid_inputs(py, xi)?;
    if copy && meshgrid_rust_compatible(py, &arrays)? {
        let arrays = arrays
            .iter()
            .enumerate()
            .map(|(index, array)| {
                extract_precise_numeric_array(py, array.bind(py), &format!("meshgrid(xi[{index}])"))
            })
            .collect::<PyResult<Vec<_>>>()?;
        let result =
            UFuncArray::meshgrid_advanced(&arrays, indexing, sparse).map_err(map_ufunc_error)?;
        return build_numpy_tuple_from_ufuncs(py, &result);
    }

    build_meshgrid_numpy_outputs(py, &arrays, indexing, sparse, copy)
}

#[pyfunction]
#[pyo3(signature = (multi_index, dims, mode=None, order="C"))]
fn ravel_multi_index(
    py: Python<'_>,
    multi_index: Py<PyAny>,
    dims: Py<PyAny>,
    mode: Option<Py<PyAny>>,
    order: &str,
) -> PyResult<Py<PyAny>> {
    // Zero-copy multiply-add flat-index for int64 coords in C order, raise mode
    // (~5x slower otherwise via the cold extract→UFuncArray path). Defers the rest.
    if let Some(out) = try_zerocopy_ravel_c(
        py,
        multi_index.bind(py),
        dims.bind(py),
        mode.as_ref().map(|m| m.bind(py)),
        order,
    )? {
        return Ok(out);
    }
    let dims = extract_index_shape(py, dims.bind(py), "ravel_multi_index(dims)")?;
    let coords = extract_ravel_multi_index_inputs(py, multi_index.bind(py), dims.len())?;
    let modes = extract_ravel_multi_index_modes(py, mode)?;
    let refs: Vec<&UFuncArray> = coords.iter().collect();
    let raw_modes: Vec<&str> = modes.iter().map(String::as_str).collect();
    let result = UFuncArray::ravel_multi_index_with_options(&refs, &dims, &raw_modes, order)
        .map_err(map_ufunc_error)?;
    build_numpy_scalar_or_array_from_ufunc(py, &result)
}

// Zero-copy np.ravel_multi_index for the common case: a tuple/list of d int64
// ndarray coordinate arrays of equal shape, C order, default "raise" mode. Each
// output flat index is the multiply-add flat = Σ coord[d]·stride[d] (C strides,
// no division), read straight from the coordinate buffers into one int64 output.
// Integer arithmetic is exact ⇒ bit-identical to numpy. Handles raise (default),
// clip (clamp), and wrap (rem_euclid) scalar modes. Returns None (caller defers)
// for non-int64/scalar/ragged coords, F order, a per-axis mode SEQUENCE, a
// coord-count mismatch, non-contiguous input, or (raise mode) any out-of-range
// coordinate so numpy's exact ValueError and scalar-return semantics are preserved.
fn try_zerocopy_ravel_c(
    py: Python<'_>,
    multi_index: &Bound<'_, PyAny>,
    dims_obj: &Bound<'_, PyAny>,
    mode: Option<&Bound<'_, PyAny>>,
    order: &str,
) -> PyResult<Option<Py<PyAny>>> {
    if order != "C" {
        return Ok(None);
    }
    // mode: 0=raise (default, OOB defers for numpy's ValueError), 1=clip (clamp each coord to
    // [0,dim-1]), 2=wrap (coord.rem_euclid(dim)). A sequence of modes / anything else defers.
    let mode_kind: u8 = match mode {
        None => 0,
        Some(m) if m.is_none() => 0,
        Some(m) => match m.extract::<String>() {
            Ok(s) if s == "raise" => 0,
            Ok(s) if s == "clip" => 1,
            Ok(s) if s == "wrap" => 2,
            _ => return Ok(None),
        },
    };
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    // dims may be an int or a sequence of ints.
    let dims: Vec<i64> = if let Ok(seq) = dims_obj.extract::<Vec<i64>>() {
        seq
    } else if let Ok(single) = dims_obj.extract::<i64>() {
        vec![single]
    } else {
        return Ok(None);
    };
    let d = dims.len();
    if d == 0 || dims.iter().any(|&v| v <= 0) {
        return Ok(None);
    }
    // multi_index must be a sequence of exactly d int64 ndarrays of equal shape.
    let Ok(seq) = multi_index.try_iter() else {
        return Ok(None);
    };
    let mut coord_arrays: Vec<Bound<'_, PyAny>> = Vec::new();
    for item in seq {
        coord_arrays.push(item?);
    }
    if coord_arrays.len() != d {
        return Ok(None);
    }
    let mut shape0: Option<Vec<usize>> = None;
    for c in &coord_arrays {
        if !c.is_exact_instance(&ndarray_type) {
            return Ok(None);
        }
        let dt = c.getattr("dtype")?;
        if dt.getattr("kind")?.extract::<String>()? != "i"
            || dt.getattr("itemsize")?.extract::<usize>()? != 8
        {
            return Ok(None);
        }
        let sh: Vec<usize> = c.getattr("shape")?.extract()?;
        if sh.is_empty() {
            return Ok(None); // scalar coord → numpy returns a scalar; defer
        }
        match &shape0 {
            None => shape0 = Some(sh),
            Some(s0) if *s0 == sh => {}
            _ => return Ok(None), // ragged/broadcast coords defer
        }
    }
    let ishape = shape0.unwrap();
    // C-order strides: stride[d-1] = 1, stride[k] = stride[k+1] * dims[k+1].
    let mut strides = vec![0i64; d];
    let mut acc: i128 = 1;
    for k in (0..d).rev() {
        strides[k] = acc as i64;
        acc *= dims[k] as i128;
    }
    if acc > i64::MAX as i128 {
        return Ok(None);
    }
    // Read all coordinate buffers.
    let bufs: Vec<PyBuffer<i64>> = {
        let mut v = Vec::with_capacity(d);
        for c in &coord_arrays {
            match PyBuffer::<i64>::get(c) {
                Ok(b) => v.push(b),
                Err(_) => return Ok(None),
            }
        }
        v
    };
    let mut inputs: Vec<&[pyo3::buffer::ReadOnlyCell<i64>]> = Vec::with_capacity(d);
    for b in &bufs {
        match b.as_slice(py) {
            Some(sl) => inputs.push(sl),
            None => return Ok(None),
        }
    }
    let n = inputs[0].len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "int64")?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(ob) = PyBuffer::<i64>::get(&flat) else {
            return Ok(None);
        };
        let Some(out) = ob.as_mut_slice(py) else {
            return Ok(None);
        };
        for i in 0..n {
            let mut flat_idx: i64 = 0;
            for dd in 0..d {
                let mut coord = inputs[dd][i].get();
                match mode_kind {
                    0 => {
                        if coord < 0 || coord >= dims[dd] {
                            return Ok(None); // raise mode OOB → defer for numpy's ValueError
                        }
                    }
                    1 => coord = coord.clamp(0, dims[dd] - 1), // clip
                    _ => coord = coord.rem_euclid(dims[dd]),   // wrap
                }
                flat_idx += coord * strides[dd];
            }
            out[i].set(flat_idx);
        }
    }
    let out_shape = PyTuple::new(py, ishape.iter().copied())?;
    Ok(Some(flat.call_method1("reshape", (&out_shape,))?.unbind()))
}

#[pyfunction]
#[pyo3(signature = (indices, shape, order="C"))]
fn unravel_index(
    py: Python<'_>,
    indices: Py<PyAny>,
    shape: Py<PyAny>,
    order: &str,
) -> PyResult<Py<PyAny>> {
    // Zero-copy integer index→coordinate conversion for the common case (int64
    // ndarray indices, C order). Skips the cold extract→UFuncArray path (~6.6x
    // slower than numpy). Pure integer div/mod ⇒ bit-exact. Scalar indices,
    // non-int64, F order, and out-of-bounds indices defer to the path below.
    if let Some(out) = try_zerocopy_unravel_c(py, indices.bind(py), shape.bind(py), order)? {
        return Ok(out);
    }
    let indices = extract_integer_array(py, indices.bind(py), "unravel_index(indices)")?;
    let shape = extract_index_shape(py, shape.bind(py), "unravel_index(shape)")?;
    let scalar_output = indices.shape().is_empty();
    let result =
        UFuncArray::unravel_index_order(&indices, &shape, order).map_err(map_ufunc_error)?;
    build_numpy_index_tuple_from_ufuncs(py, &result, scalar_output)
}

// Zero-copy np.unravel_index for int64 ndarray indices in C order: each flat index
// x maps to coordinates via the standard last-axis-first div/mod sweep
// (coord[d] = (x / inner_d) % shape[d]). Returns a tuple of d int64 coordinate
// arrays, each shaped like `indices`. Integer arithmetic is exact ⇒ bit-identical
// to numpy. Returns None (caller defers) for non-int64 indices, scalar (0-d)
// indices, F order, non-contiguous input, an empty/zero shape, or any index out of
// range, so numpy's exact tuple/scalar return and ValueError are preserved.
fn try_zerocopy_unravel_c(
    py: Python<'_>,
    indices: &Bound<'_, PyAny>,
    shape: &Bound<'_, PyAny>,
    order: &str,
) -> PyResult<Option<Py<PyAny>>> {
    if order != "C" {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !indices.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = indices.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "i"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    let ishape: Vec<usize> = indices.getattr("shape")?.extract()?;
    if ishape.is_empty() {
        return Ok(None); // scalar indices → numpy returns a tuple of scalars; defer
    }
    // shape may be an int or a sequence of ints.
    let dims: Vec<i64> = if let Ok(seq) = shape.extract::<Vec<i64>>() {
        seq
    } else if let Ok(single) = shape.extract::<i64>() {
        vec![single]
    } else {
        return Ok(None);
    };
    let d = dims.len();
    if d == 0 || dims.iter().any(|&v| v <= 0) {
        return Ok(None); // empty/zero/negative dims → defer for numpy's semantics
    }
    let mut total: i128 = 1;
    for &v in &dims {
        total *= v as i128;
    }
    if total > i64::MAX as i128 {
        return Ok(None);
    }
    let total = total as i64;
    let Ok(buf) = PyBuffer::<i64>::get(indices) else {
        return Ok(None);
    };
    let Some(s) = buf.as_slice(py) else {
        return Ok(None);
    };
    let n = s.len();
    // Validate range; any OOB index defers so numpy raises its exact ValueError.
    for c in s.iter() {
        let x = c.get();
        if x < 0 || x >= total {
            return Ok(None);
        }
    }
    // Allocate the d int64 coordinate arrays up front and write coordinates
    // straight into their buffers in a single pass — no intermediate Vec, so the
    // working set is just the inputs + outputs (avoids a memory-bound cache cliff
    // at large n).
    let flats: Vec<Bound<'_, PyAny>> = {
        let mut v = Vec::with_capacity(d);
        for _ in 0..d {
            let kwargs = PyDict::new(py);
            kwargs.set_item("dtype", "int64")?;
            v.push(numpy.call_method("empty", (n,), Some(&kwargs))?);
        }
        v
    };
    let bufs: Vec<PyBuffer<i64>> = {
        let mut v = Vec::with_capacity(d);
        for f in flats.iter() {
            match PyBuffer::<i64>::get(f) {
                Ok(b) => v.push(b),
                Err(_) => return Ok(None),
            }
        }
        v
    };
    let mut slices: Vec<&[std::cell::Cell<i64>]> = Vec::with_capacity(d);
    for b in bufs.iter() {
        match b.as_mut_slice(py) {
            Some(sl) => slices.push(sl),
            None => return Ok(None),
        }
    }
    for (i, c) in s.iter().enumerate() {
        let mut rem = c.get();
        for dd in (0..d).rev() {
            let dim = dims[dd];
            slices[dd][i].set(rem % dim);
            rem /= dim;
        }
    }
    let out_shape = PyTuple::new(py, ishape.iter().copied())?;
    let mut outputs: Vec<Bound<'_, PyAny>> = Vec::with_capacity(d);
    for f in flats.iter() {
        outputs.push(f.call_method1("reshape", (&out_shape,))?);
    }
    Ok(Some(PyTuple::new(py, outputs)?.into_any().unbind()))
}

#[pyfunction]
#[pyo3(signature = (n, ndim=2))]
fn diag_indices(py: Python<'_>, n: usize, ndim: usize) -> PyResult<Py<PyAny>> {
    build_diag_indices_tuple(py, n, ndim)
}

fn build_diag_indices_tuple(py: Python<'_>, n: usize, ndim: usize) -> PyResult<Py<PyAny>> {
    if n > i64::MAX as usize {
        return Err(PyOverflowError::new_err(
            "diag_indices n is too large for int64 indices",
        ));
    }

    // numpy.diag_indices is `idx = arange(n); (idx,) * ndim` — one arange and a tuple
    // of references to the SAME array. Build it the same way: np.arange(n) reproduces
    // numpy's value sequence and (platform-default) dtype exactly, and cloning the
    // Bound is a refcount bump so all ndim tuple entries alias one array (t[0] is t[1]),
    // matching numpy. This drops the per-call dtype-dict, np.empty, PyBuffer fetch, and
    // fill loop the previous path paid — pure call overhead that dominated at small n
    // (1.32us -> ~numpy's 0.56us at n=64).
    let numpy = py.import("numpy")?;
    let idx = numpy.call_method1("arange", (n,))?;
    let mut outputs = Vec::with_capacity(ndim);
    for _ in 0..ndim {
        outputs.push(idx.clone());
    }
    Ok(PyTuple::new(py, outputs)?.into_any().unbind())
}

#[pyfunction]
fn diag_indices_from(py: Python<'_>, arr: Py<PyAny>) -> PyResult<Py<PyAny>> {
    let shape = extract_array_shape(py, arr.bind(py), "diag_indices_from(arr)")?;
    if shape.len() < 2 {
        return Err(PyValueError::new_err("input array must be at least 2-d"));
    }

    let n = shape[0];
    if shape[1..].iter().any(|&dim| dim != n) {
        return Err(PyValueError::new_err(
            "All dimensions of input must be of equal length",
        ));
    }

    build_diag_indices_tuple(py, n, shape.len())
}

#[pyfunction]
#[pyo3(signature = (n, k=0, m=None))]
fn tril_indices(py: Python<'_>, n: usize, k: i64, m: Option<usize>) -> PyResult<Py<PyAny>> {
    if let Some(out) = build_tri_indices(py, n, m.unwrap_or(n), k, false)? {
        return Ok(out);
    }
    let (rows, cols) = UFuncArray::tril_indices(n, m.unwrap_or(n), k);
    build_numpy_tuple_from_ufuncs(py, &[rows, cols])
}

