// Direct O(count) construction of np.tril_indices / np.triu_indices: numpy builds
// the full n×m triangular mask and runs nonzero (O(n·m) + an n×m allocation); this
// emits the row/col index pairs straight in row-major order, visiting only the
// kept entries. For each row i the kept columns are a contiguous run — triu: j in
// [max(i+k,0), m); tril: j in [0, min(i+k, m-1)] — so rows is a constant fill and
// cols an arange per row, written directly into two int64 buffers. Exact integers
// ⇒ bit-identical to numpy (intp = int64). Returns None on buffer failure so the
// caller keeps the UFuncArray path.
fn build_tri_indices(
    py: Python<'_>,
    n: usize,
    m: usize,
    k: i64,
    upper: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let mut count: usize = 0;
    for i in 0..n {
        let r = i as i64;
        if upper {
            let start = (r + k).max(0);
            if (start as i128) < m as i128 {
                count += m - start as usize;
            }
        } else {
            let end = (r + k).min(m as i64 - 1);
            if end >= 0 {
                count += end as usize + 1;
            }
        }
    }
    let kw = PyDict::new(py);
    kw.set_item("dtype", "int64")?;
    let rows = numpy.call_method("empty", (count,), Some(&kw))?;
    let cols = numpy.call_method("empty", (count,), Some(&kw))?;
    if count > 0 {
        let (Ok(rb), Ok(cb)) = (PyBuffer::<i64>::get(&rows), PyBuffer::<i64>::get(&cols)) else {
            return Ok(None);
        };
        let (Some(rs), Some(cs)) = (rb.as_mut_slice(py), cb.as_mut_slice(py)) else {
            return Ok(None);
        };
        let mut p = 0usize;
        for i in 0..n {
            let r = i as i64;
            let (jstart, jend) = if upper {
                ((r + k).max(0), m as i64) // [jstart, jend)
            } else {
                (0i64, (r + k).min(m as i64 - 1) + 1) // [0, jend)
            };
            let mut j = jstart;
            while j < jend {
                rs[p].set(r);
                cs[p].set(j);
                p += 1;
                j += 1;
            }
        }
    }
    Ok(Some(PyTuple::new(py, [rows, cols])?.into_any().unbind()))
}

// Generic per-axis in-place scatter core for put_along_axis — the inverse of
// gather_along_typed, parameterized by a mover type T chosen by itemsize. Writes
// arr[o, idx[o,l,inr], inr] = values[o,l,inr] over the outer*axis*inner
// decomposition, straight into arr's own buffer through a uintN bit-view (so it
// mutates arr in place and is value-agnostic across dtypes). ALL indices are
// validated in range FIRST (negative wrap k += la); an out-of-range index returns
// None with arr untouched, so the caller can defer to numpy for the exact
// IndexError without a partial/double write. Duplicate indices in a lane resolve
// last-write-wins, matching numpy's sequential scatter.
#[allow(clippy::too_many_arguments)]
fn scatter_along_typed<'py, T: pyo3::buffer::Element + Copy>(
    py: Python<'py>,
    arr_u: &Bound<'py, PyAny>,
    val_u: &Bound<'py, PyAny>,
    idx_in: &[pyo3::buffer::ReadOnlyCell<i64>],
    outer: usize,
    la: usize,
    li: usize,
    inner: usize,
) -> PyResult<Option<()>> {
    let (Ok(arr_buf), Ok(val_buf)) = (PyBuffer::<T>::get(arr_u), PyBuffer::<T>::get(val_u)) else {
        return Ok(None);
    };
    let Some(val_in) = val_buf.as_slice(py) else {
        return Ok(None);
    };
    let la_i = la as i64;
    // Validate every index BEFORE any write so an OOB leaves arr unmutated.
    for o in 0..outer {
        let obase = o * li * inner;
        for l in 0..li {
            let dbase = obase + l * inner;
            for inr in 0..inner {
                let mut k = idx_in[dbase + inr].get();
                if k < 0 {
                    k += la_i;
                }
                if k < 0 || k >= la_i {
                    return Ok(None);
                }
            }
        }
    }
    let Some(arr_out) = arr_buf.as_mut_slice(py) else {
        return Ok(None); // read-only / non-contiguous → defer
    };
    for o in 0..outer {
        let abase = o * la * inner;
        let obase = o * li * inner;
        for l in 0..li {
            let dbase = obase + l * inner;
            for inr in 0..inner {
                let mut k = idx_in[dbase + inr].get();
                if k < 0 {
                    k += la_i;
                }
                arr_out[abase + (k as usize) * inner + inr].set(val_in[dbase + inr].get());
            }
        }
    }
    Ok(Some(()))
}

// Zero-copy in-place put_along_axis for an explicit axis: a per-axis typed scatter
// (inverse of take_along_axis) that writes straight into arr's buffer via a uintN
// bit-view chosen by itemsize, covering int/float/bool in one path. Skips the cold
// extract + native scatter + full copy-back. Gated to: writable C-contiguous arr,
// int64 indices, values an ndarray of arr's exact dtype and of the indices' shape
// (broadcast/scalar values defer), equal ndim with every non-axis dim equal, and
// itemsize 1/2/4/8. Bit-identical (elements copied verbatim). Returns None to defer.
fn try_zerocopy_put_along_axis(
    py: Python<'_>,
    arr: &Bound<'_, PyAny>,
    indices: &Bound<'_, PyAny>,
    values: &Bound<'_, PyAny>,
    axis: Option<isize>,
) -> PyResult<Option<()>> {
    let Some(axis) = axis else {
        return Ok(None);
    };
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !arr.is_exact_instance(&ndarray_type)
        || !indices.is_exact_instance(&ndarray_type)
        || !values.is_exact_instance(&ndarray_type)
    {
        return Ok(None);
    }
    let idx_dtype = indices.getattr("dtype")?;
    if idx_dtype.getattr("kind")?.extract::<String>()? != "i"
        || idx_dtype.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    let arr_dtype = arr.getattr("dtype")?;
    let kind = arr_dtype.getattr("kind")?.extract::<String>()?;
    let itemsize = arr_dtype.getattr("itemsize")?.extract::<usize>()?;
    if kind == "c" || !matches!(itemsize, 1 | 2 | 4 | 8) {
        return Ok(None);
    }
    // values must be an ndarray of arr's exact dtype (so the uintN bit-view matches).
    let val_dtype = values.getattr("dtype")?;
    if val_dtype.getattr("kind")?.extract::<String>()? != kind
        || val_dtype.getattr("itemsize")?.extract::<usize>()? != itemsize
    {
        return Ok(None);
    }
    let s_arr: Vec<usize> = arr.getattr("shape")?.extract()?;
    let s_idx: Vec<usize> = indices.getattr("shape")?.extract()?;
    let s_val: Vec<usize> = values.getattr("shape")?.extract()?;
    let d = s_arr.len();
    if d == 0 || s_idx.len() != d || s_val != s_idx {
        return Ok(None); // values must match indices' shape exactly (no broadcast)
    }
    let ax = if axis < 0 { axis + d as isize } else { axis };
    if ax < 0 || ax >= d as isize {
        return Ok(None);
    }
    let ax = ax as usize;
    for k in 0..d {
        if k != ax && s_arr[k] != s_idx[k] {
            return Ok(None);
        }
    }
    let la = s_arr[ax];
    let li = s_idx[ax];
    let outer: usize = s_arr[..ax].iter().product();
    let inner: usize = s_arr[ax + 1..].iter().product();
    let Ok(idx_buf) = PyBuffer::<i64>::get(indices) else {
        return Ok(None);
    };
    let Some(idx_in) = idx_buf.as_slice(py) else {
        return Ok(None);
    };
    let mover_name = match itemsize {
        1 => "uint8",
        2 => "uint16",
        4 => "uint32",
        _ => "uint64",
    };
    let mover = numpy.getattr(mover_name)?;
    let arr_u = arr.call_method1("view", (&mover,))?;
    let val_u = values.call_method1("view", (&mover,))?;
    match itemsize {
        1 => scatter_along_typed::<u8>(py, &arr_u, &val_u, idx_in, outer, la, li, inner),
        2 => scatter_along_typed::<u16>(py, &arr_u, &val_u, idx_in, outer, la, li, inner),
        4 => scatter_along_typed::<u32>(py, &arr_u, &val_u, idx_in, outer, la, li, inner),
        _ => scatter_along_typed::<u64>(py, &arr_u, &val_u, idx_in, outer, la, li, inner),
    }
}

#[pyfunction]
#[pyo3(signature = (arr, indices, values, axis=Some(-1)))]
fn put_along_axis(
    py: Python<'_>,
    arr: Py<PyAny>,
    indices: Py<PyAny>,
    values: Py<PyAny>,
    axis: Option<isize>,
) -> PyResult<Py<PyAny>> {
    let arr_for_fallback = arr.clone_ref(py);
    let indices_for_fallback = indices.clone_ref(py);
    let values_for_fallback = values.clone_ref(py);
    let invoke_fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item(
            "axis",
            match axis {
                Some(axis) => axis.into_pyobject(py)?.into_any(),
                None => py.None().into_bound(py),
            },
        )?;
        Ok(numpy
            .getattr("put_along_axis")?
            .call(
                (
                    arr_for_fallback.bind(py),
                    indices_for_fallback.bind(py),
                    values_for_fallback.bind(py),
                ),
                Some(&kwargs),
            )?
            .unbind())
    };
    let arr = arr.bind(py);
    let _ = arr.getattr("ndim")?;

    // Check for complex dtype and fallback to numpy
    let dtype_kind = arr.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
    if dtype_kind == "c" {
        return invoke_fallback();
    }

    // Zero-copy in-place typed scatter (explicit axis, equal non-axis dims, int64
    // indices, same-dtype same-shape values); writes straight into arr's buffer and
    // skips the cold extract + copy-back. Bit-identical; broadcast/scalar values,
    // axis=None, OOB indices, and other layouts fall through.
    if try_zerocopy_put_along_axis(py, arr, indices.bind(py), values.bind(py), axis)?.is_some() {
        return Ok(py.None());
    }

    // Residual (most importantly SCALAR/broadcast `values` — the common
    // put_along_axis(arr, idx, 0, axis=0) idiom): the old path extracted the WHOLE
    // array to a UFuncArray, scattered, and copied it ALL back — 18-576x slower than
    // numpy even though only the indexed cells change (int8 scatter 576x). numpy
    // writes only the indexed elements in place and owns the IndexError surface, so
    // delegate. (The zero-copy in-place same-dtype-array fast path above is kept.)
    invoke_fallback()
}

// Generic per-axis gather core for take_along_axis, parameterized by a mover type
// T chosen by itemsize (u8/u16/u32/u64) — take_along_axis moves whole ELEMENTS
// verbatim, so gathering the raw bits as an unsigned integer of the matching width
// covers every dtype (int/float/bool/datetime) in one path. out[o,l,inr] =
// arr[o, idx[o,l,inr], inr] over the outer*axis*inner decomposition. Negative
// indices wrap (k += la, matching numpy's fancy-index semantics); an out-of-range
// index returns None so the caller defers to numpy for the exact IndexError (the
// half-filled fresh buffer is simply dropped). Returns the flat uintN output.
#[allow(clippy::too_many_arguments)]
fn gather_along_typed<'py, T: pyo3::buffer::Element + Copy>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    arr_u: &Bound<'py, PyAny>,
    idx_in: &[pyo3::buffer::ReadOnlyCell<i64>],
    out_dtype_name: &str,
    outer: usize,
    la: usize,
    li: usize,
    inner: usize,
) -> PyResult<Option<Bound<'py, PyAny>>> {
    let Ok(arr_buf) = PyBuffer::<T>::get(arr_u) else {
        return Ok(None);
    };
    let Some(arr_s) = arr_buf.as_slice(py) else {
        return Ok(None);
    };
    let total_out = outer * li * inner;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", out_dtype_name)?;
    let flat = numpy.call_method("empty", (total_out,), Some(&kwargs))?;
    if total_out > 0 {
        let Ok(out_buffer) = PyBuffer::<T>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        let la_i = la as i64;
        for o in 0..outer {
            let abase = o * la * inner;
            let obase = o * li * inner;
            for l in 0..li {
                let dbase = obase + l * inner;
                for inr in 0..inner {
                    let mut k = idx_in[dbase + inr].get();
                    if k < 0 {
                        k += la_i;
                    }
                    if k < 0 || k >= la_i {
                        return Ok(None); // OOB → defer to numpy for exact IndexError
                    }
                    output[dbase + inr].set(arr_s[abase + (k as usize) * inner + inr].get());
                }
            }
        }
    }
    Ok(Some(flat))
}

// Zero-copy take_along_axis for an explicit axis: a per-axis typed gather that
// skips the cold extract→f64 Vec→rebuild path (~8x slower, lossy for wide ints).
// numpy moves whole elements, so the gather is done on a uintN bit-view chosen by
// itemsize and viewed back to the original dtype — covering int/float/bool in one
// path. Gated to: both ndarrays of equal ndim, every non-axis dim equal (no
// broadcast — those defer), an int64 index array, a C-contiguous arr, and an
// itemsize of 1/2/4/8 (complex128 and non-contiguous inputs defer). Bit-identical
// (elements copied verbatim incl. nan/inf/signed zeros).
fn try_zerocopy_take_along_axis(
    py: Python<'_>,
    arr: &Bound<'_, PyAny>,
    indices: &Bound<'_, PyAny>,
    axis: Option<isize>,
) -> PyResult<Option<Py<PyAny>>> {
    let Some(axis) = axis else {
        return Ok(None);
    };
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !arr.is_exact_instance(&ndarray_type) || !indices.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let idx_dtype = indices.getattr("dtype")?;
    if idx_dtype.getattr("kind")?.extract::<String>()? != "i"
        || idx_dtype.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    let arr_dtype = arr.getattr("dtype")?;
    let kind = arr_dtype.getattr("kind")?.extract::<String>()?;
    let itemsize = arr_dtype.getattr("itemsize")?.extract::<usize>()?;
    if kind == "c" || !matches!(itemsize, 1 | 2 | 4 | 8) {
        return Ok(None);
    }
    let s_arr: Vec<usize> = arr.getattr("shape")?.extract()?;
    let s_idx: Vec<usize> = indices.getattr("shape")?.extract()?;
    let d = s_arr.len();
    if d == 0 || s_idx.len() != d {
        return Ok(None);
    }
    let ax = if axis < 0 { axis + d as isize } else { axis };
    if ax < 0 || ax >= d as isize {
        return Ok(None);
    }
    let ax = ax as usize;
    for k in 0..d {
        if k != ax && s_arr[k] != s_idx[k] {
            return Ok(None); // broadcast on a non-axis dim → defer to numpy
        }
    }
    let la = s_arr[ax];
    let li = s_idx[ax];
    let outer: usize = s_arr[..ax].iter().product();
    let inner: usize = s_arr[ax + 1..].iter().product();
    let Ok(idx_buf) = PyBuffer::<i64>::get(indices) else {
        return Ok(None);
    };
    let Some(idx_in) = idx_buf.as_slice(py) else {
        return Ok(None);
    };
    // View arr's raw bits as the unsigned integer of matching width, gather, view back.
    let (mover_name, orig_name): (&str, String) = (
        match itemsize {
            1 => "uint8",
            2 => "uint16",
            4 => "uint32",
            _ => "uint64",
        },
        arr_dtype.getattr("name")?.extract::<String>()?,
    );
    let arr_u = arr.call_method1("view", (numpy.getattr(mover_name)?,))?;
    let flat = match itemsize {
        1 => gather_along_typed::<u8>(py, &numpy, &arr_u, idx_in, "uint8", outer, la, li, inner)?,
        2 => gather_along_typed::<u16>(py, &numpy, &arr_u, idx_in, "uint16", outer, la, li, inner)?,
        4 => gather_along_typed::<u32>(py, &numpy, &arr_u, idx_in, "uint32", outer, la, li, inner)?,
        _ => gather_along_typed::<u64>(py, &numpy, &arr_u, idx_in, "uint64", outer, la, li, inner)?,
    };
    let Some(flat) = flat else {
        return Ok(None);
    };
    let restored = flat.call_method1("view", (numpy.getattr(orig_name.as_str())?,))?;
    let output_shape = PyTuple::new(py, s_idx.iter().copied())?;
    Ok(Some(restored.call_method1("reshape", (&output_shape,))?.unbind()))
}

#[pyfunction]
#[pyo3(signature = (arr, indices, axis=Some(-1)))]
fn take_along_axis(
    py: Python<'_>,
    arr: Py<PyAny>,
    indices: Py<PyAny>,
    axis: Option<isize>,
) -> PyResult<Py<PyAny>> {
    let arr_for_fallback = arr.clone_ref(py);
    let indices_for_fallback = indices.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item(
            "axis",
            match axis {
                Some(axis) => axis.into_pyobject(py)?.into_any(),
                None => py.None().into_bound(py),
            },
        )?;
        Ok(numpy
            .getattr("take_along_axis")?
            .call(
                (arr_for_fallback.bind(py), indices_for_fallback.bind(py)),
                Some(&kwargs),
            )?
            .unbind())
    };

    // Check for complex dtype and fallback to numpy
    let numpy = py.import("numpy")?;
    let arr_bound = numpy.call_method1("asarray", (arr.bind(py),))?;
    let dtype_kind = arr_bound
        .getattr("dtype")?
        .getattr("kind")?
        .extract::<String>()?;
    if dtype_kind == "c" {
        return fallback();
    }

    // Zero-copy per-axis typed gather (explicit axis, equal non-axis dims, int64
    // indices); covers int/float/bool via a uintN bit-view. Skips the cold extract +
    // rebuild. Bit-identical; broadcast, axis=None, OOB indices, and other layouts
    // fall through.
    if let Some(out) =
        try_zerocopy_take_along_axis(py, arr.bind(py), indices.bind(py), axis)?
    {
        return Ok(out);
    }

    // Residual (most importantly a BROADCAST index — idx (n,1) / (1,m) that does not
    // match arr's non-axis dims, e.g. argsort/argmax-style gathers): the old path
    // extracted the WHOLE array to a UFuncArray, gathered, and rebuilt the result
    // across the export bridge — 2.5-5.3x slower than numpy. numpy's take_along_axis
    // is a strided gather that owns the exact broadcast + IndexError surface, so
    // delegate. (The zero-copy equal-non-axis-dim fast path above is kept.)
    fallback()
}

// ---------------------------------------------------------------------------
// Historical reality-check (k74v.8) - 31 core numpy passthrough wrappers.
//
// Each wrapper forwards all args + kwargs to `numpy.<name>`, preserving the
// full numpy signature surface without re-typing it. This was one tranche of
// the numpy.__all__ coverage closure; coverage is now locked at 499/499 by
// fnp_python_covers_full_numpy_all. The helper `core_numpy_passthrough`
// amortizes the common work so each #[pyfunction] is a 3-line trampoline.
// ---------------------------------------------------------------------------

fn core_numpy_passthrough(
    py: Python<'_>,
    name: &str,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    // Cache the numpy module once instead of re-importing it on every call. This
    // passthrough backs 185 ops; on SMALL arrays the per-call `py.import("numpy")`
    // (~200ns, measured) dominates the trivial kernel, so caching it cuts the
    // dispatch overhead for every passthrough ufunc with zero behaviour change
    // (same module, same getattr+call). Large-array ops are unaffected (amortized).
    static NUMPY_MODULE: PyOnceLock<Py<PyModule>> = PyOnceLock::new();
    let numpy = NUMPY_MODULE
        .get_or_try_init(py, || -> PyResult<Py<PyModule>> { Ok(py.import("numpy")?.unbind()) })?
        .bind(py);
    Ok(numpy.getattr(name)?.call(args, kwargs)?.unbind())
}

fn clone_py_kwargs<'py>(
    py: Python<'py>,
    kwargs: Option<&Bound<'py, PyDict>>,
) -> PyResult<Bound<'py, PyDict>> {
    let cloned = PyDict::new(py);
    if let Some(kwargs) = kwargs {
        for (key, value) in kwargs.iter() {
            cloned.set_item(key, value)?;
        }
    }
    Ok(cloned)
}

fn has_unrecognized_kwargs(kwargs: Option<&Bound<'_, PyDict>>, allowed: &[&str]) -> PyResult<bool> {
    let Some(kwargs) = kwargs else {
        return Ok(false);
    };
    for (key, _) in kwargs.iter() {
        let key = key.extract::<String>()?;
        if !allowed.contains(&key.as_str()) {
            return Ok(true);
        }
    }
    Ok(false)
}

// Array creators
// NOTE: zeros/ones/arange passthrough to NumPy because our Rust→NumPy array
// export path (build_numpy_array_from_storage) creates a Python list intermediate,
// which is O(n) Python object allocation. NumPy's native C allocation is faster.
// Once we implement buffer-protocol export, we can revisit the native path.
#[pyfunction]
#[pyo3(signature = (shape, dtype=None, order=None, **kwargs))]
fn zeros(
    py: Python<'_>,
    shape: &Bound<'_, PyAny>,
    dtype: Option<&Bound<'_, PyAny>>,
    order: Option<&str>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    // Always passthrough to NumPy - our Rust→NumPy export is slower than
    // letting NumPy allocate directly. See perf bead franken_numpy-o9up3.
    let numpy = py.import("numpy")?;
    let zeros_fn = numpy.getattr("zeros")?;
    let kw = PyDict::new(py);
    kw.set_item("shape", shape)?;
    if let Some(d) = dtype {
        kw.set_item("dtype", d)?;
    }
    if let Some(o) = order {
        kw.set_item("order", o)?;
    }
    if let Some(extra) = kwargs {
        for (k, v) in extra.iter() {
            kw.set_item(k, v)?;
        }
    }
    Ok(zeros_fn.call((), Some(&kw))?.unbind())
}

#[pyfunction]
#[pyo3(signature = (shape, dtype=None, order=None, **kwargs))]
fn ones(
    py: Python<'_>,
    shape: &Bound<'_, PyAny>,
    dtype: Option<&Bound<'_, PyAny>>,
    order: Option<&str>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    // Always passthrough to NumPy - see zeros() comment
    let numpy = py.import("numpy")?;
    let ones_fn = numpy.getattr("ones")?;
    let kw = PyDict::new(py);
    kw.set_item("shape", shape)?;
    if let Some(d) = dtype {
        kw.set_item("dtype", d)?;
    }
    if let Some(o) = order {
        kw.set_item("order", o)?;
    }
    if let Some(extra) = kwargs {
        for (k, v) in extra.iter() {
            kw.set_item(k, v)?;
        }
    }
    Ok(ones_fn.call((), Some(&kw))?.unbind())
}

#[pyfunction]
#[pyo3(signature = (*args, **kwargs))]
fn empty(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    core_numpy_passthrough(py, "empty", args, kwargs)
}

#[pyfunction]
#[pyo3(signature = (*args, **kwargs))]
fn array(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    core_numpy_passthrough(py, "array", args, kwargs)
}

// Reductions: passthrough to NumPy because our input extraction (extract_precise_numeric_array)
// calls .tolist() which is O(n) Python object creation. NumPy's native C path is faster.
// See perf bead franken_numpy-c6t1m.
#[pyfunction]
#[pyo3(signature = (a, axis=None, dtype=None, out=None, keepdims=false, initial=None, **kwargs))]
#[allow(clippy::too_many_arguments)]
fn sum(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    dtype: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    keepdims: bool,
    initial: Option<Py<PyAny>>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    // Always passthrough to NumPy - our input extraction is slower
    let numpy = py.import("numpy")?;
    let sum_fn = numpy.getattr("sum")?;
    let kw = clone_py_kwargs(py, kwargs)?;
    if let Some(ax) = axis.as_ref() {
        kw.set_item("axis", ax.bind(py))?;
    }
    if let Some(dt) = dtype.as_ref() {
        kw.set_item("dtype", dt.bind(py))?;
    }
    if let Some(o) = out.as_ref() {
        kw.set_item("out", o.bind(py))?;
    }
    kw.set_item("keepdims", keepdims)?;
    if let Some(init) = initial.as_ref() {
        kw.set_item("initial", init.bind(py))?;
    }
    Ok(sum_fn.call((a.bind(py),), Some(&kw))?.unbind())
}

// Zero-copy np.prod reduction for a C-contiguous float64 ndarray (no out/dtype/
// initial/where). numpy.prod multiplies SEQUENTIALLY (unlike the pairwise add of
// np.sum), so a straight left-to-right product is bit-identical. Using the
// outer * axis * inner decomposition, out(o, i) = product over a of in(o, a, i),
// accumulated in axis order; axis=None reduces the whole flat buffer. The result
// is written into a numpy.empty output (no per-input extract Vec, no reduce-build
// Vec). The product starts from 1.0 (the empty-axis identity, matching numpy) and
// 1.0 * x == x bit-exactly, so signed zeros / inf / nan propagate exactly.
// Returns Ok(None) — caller falls through — for a tuple axis, an out-of-range
// axis, a 0-d array, or any non-f64 / non-contiguous / non-ndarray input.
fn try_zerocopy_f64_prod(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
    keepdims: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) || !numpy_dtype_is_f64(py, a) {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    if shape.is_empty() {
        return Ok(None);
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let ndim = shape.len();

    // Resolve the reduction into outer * axis_len * inner and the output shape.
    let (outer, axis_len, inner, out_shape): (usize, usize, usize, Vec<usize>) = match axis {
        None => {
            let total = input.len();
            let out_shape = if keepdims { vec![1; ndim] } else { Vec::new() };
            (1, total, 1, out_shape)
        }
        Some(ax) => {
            let ndim_i = ndim as isize;
            let norm = if ax < 0 { ax + ndim_i } else { ax };
            if norm < 0 || norm >= ndim_i {
                return Ok(None);
            }
            let axu = norm as usize;
            let outer: usize = shape[..axu].iter().product();
            let inner: usize = shape[axu + 1..].iter().product();
            let mut out_shape = shape.clone();
            if keepdims {
                out_shape[axu] = 1;
            } else {
                out_shape.remove(axu);
            }
            (outer, shape[axu], inner, out_shape)
        }
    };

    let out_elems = outer * inner;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (out_elems,), Some(&kwargs))?;
    if out_elems > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        if inner == 1 {
            // Each outer lane is contiguous: accumulate the product in a register.
            for (o, slot) in output.iter().enumerate() {
                let base = o * axis_len;
                let mut acc = 1.0_f64;
                for a in 0..axis_len {
                    acc *= input[base + a].get();
                }
                slot.set(acc);
            }
        } else {
            // inner > 1: multiply slab by slab so the access stays sequential.
            for slot in output.iter() {
                slot.set(1.0);
            }
            let lane = axis_len * inner;
            for o in 0..outer {
                let obase = o * inner;
                let ibase = o * lane;
                for a in 0..axis_len {
                    let in_a = ibase + a * inner;
                    for i in 0..inner {
                        let slot = &output[obase + i];
                        slot.set(slot.get() * input[in_a + i].get());
                    }
                }
            }
        }
    }
    if out_shape.is_empty() {
        // Scalar result: reshape to 0-d and unwrap to a numpy scalar.
        let zerod = flat.call_method1("reshape", (PyTuple::empty(py),))?;
        return Ok(Some(zerod.get_item(())?.unbind()));
    }
    let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    Ok(Some(output))
}

#[derive(Clone, Copy)]
enum F64MinMaxOp {
    Min,
    Max,
}

enum F64MinMaxFastPath {
    Output(Py<PyAny>),
    DelegateToNumpy,
    NotApplicable,
}

#[inline(always)]
fn f64_minmax_update(acc: f64, value: f64, op: F64MinMaxOp) -> f64 {
    match op {
        F64MinMaxOp::Max => {
            if acc > value {
                acc
            } else {
                value
            }
        }
        F64MinMaxOp::Min => {
            if acc < value {
                acc
            } else {
                value
            }
        }
    }
}

fn numpy_array_any_nan(numpy: &Bound<'_, PyModule>, value: &Bound<'_, PyAny>) -> PyResult<bool> {
    numpy
        .getattr("isnan")?
        .call1((value,))?
        .call_method0("any")?
        .extract::<bool>()
}

// Zero-copy finite np.min/np.max reduction for exact C-contiguous float64
// ndarrays. The finite update uses NumPy's later-equal tie behavior
// (`if acc > v { acc } else { v }` for max, `<` for min), preserving signed-zero
// selection in scan order. NaN reductions delegate to NumPy as soon as the scan
// observes one instead of paying a separate finite prepass; this keeps the
// position-dependent SIMD/scalar payload choices owned by NumPy.
fn try_zerocopy_f64_minmax(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
    keepdims: bool,
    op: F64MinMaxOp,
) -> PyResult<F64MinMaxFastPath> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) || !numpy_dtype_is_f64(py, a) {
        return Ok(F64MinMaxFastPath::NotApplicable);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(F64MinMaxFastPath::NotApplicable);
    };
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    if shape.is_empty() {
        return Ok(F64MinMaxFastPath::NotApplicable);
    }
    let Some(input) = in_buffer.as_slice(py) else {
        if numpy_array_any_nan(&numpy, a)? {
            return Ok(F64MinMaxFastPath::DelegateToNumpy);
        }
        return Ok(F64MinMaxFastPath::NotApplicable);
    };
    // numpy's SIMD min/max beats this scalar cell-by-cell fold at EVERY size past a
    // few KiB (measured fnp-native/numpy 1.5x@1k → 2.5x@8k → 4x@64k → 5x@1M, and the
    // axis paths 3.9-4.8x); it is genuinely SIMD-bound (a NaN-propagating,
    // signed-zero-ordered reduction the compiler can't vectorize in safe Rust — bead
    // 8vdtg). Delegate large f64 reductions to numpy (which also fixes any large-array
    // signed-zero divergence: the result is now numpy's exact bits). Tiny arrays keep
    // the native path — numpy's per-call dispatch isn't worth it below the crossover.
    const ZEROCOPY_MINMAX_NUMPY_MIN_LEN: usize = 4096;
    if input.len() >= ZEROCOPY_MINMAX_NUMPY_MIN_LEN {
        return Ok(F64MinMaxFastPath::DelegateToNumpy);
    }
    let ndim = shape.len();

    let (outer, axis_len, inner, out_shape): (usize, usize, usize, Vec<usize>) = match axis {
        None => {
            let total = input.len();
            let out_shape = if keepdims { vec![1; ndim] } else { Vec::new() };
            (1, total, 1, out_shape)
        }
        Some(ax) => {
            let ndim_i = ndim as isize;
            let norm = if ax < 0 { ax + ndim_i } else { ax };
            if norm < 0 || norm >= ndim_i {
                return Ok(F64MinMaxFastPath::NotApplicable);
            }
            let axu = norm as usize;
            let outer: usize = shape[..axu].iter().product();
            let inner: usize = shape[axu + 1..].iter().product();
            let mut out_shape = shape.clone();
            if keepdims {
                out_shape[axu] = 1;
            } else {
                out_shape.remove(axu);
            }
            (outer, shape[axu], inner, out_shape)
        }
    };
    if axis_len == 0 || input.is_empty() {
        return Ok(F64MinMaxFastPath::NotApplicable);
    }

    let out_elems = outer * inner;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (out_elems,), Some(&kwargs))?;
    if out_elems > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(F64MinMaxFastPath::NotApplicable);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(F64MinMaxFastPath::NotApplicable);
        };
        if inner == 1 {
            for (o, slot) in output.iter().enumerate() {
                let base = o * axis_len;
                let mut acc = input[base].get();
                if acc.is_nan() {
                    return Ok(F64MinMaxFastPath::DelegateToNumpy);
                }
                for a in 1..axis_len {
                    let value = input[base + a].get();
                    if value.is_nan() {
                        return Ok(F64MinMaxFastPath::DelegateToNumpy);
                    }
                    acc = f64_minmax_update(acc, value, op);
                }
                slot.set(acc);
            }
        } else {
            let lane = axis_len * inner;
            for o in 0..outer {
                let obase = o * inner;
                let ibase = o * lane;
                for i in 0..inner {
                    let value = input[ibase + i].get();
                    if value.is_nan() {
                        return Ok(F64MinMaxFastPath::DelegateToNumpy);
                    }
                    output[obase + i].set(value);
                }
                for a in 1..axis_len {
                    let in_a = ibase + a * inner;
                    for i in 0..inner {
                        let value = input[in_a + i].get();
                        if value.is_nan() {
                            return Ok(F64MinMaxFastPath::DelegateToNumpy);
                        }
                        let slot = &output[obase + i];
                        slot.set(f64_minmax_update(slot.get(), value, op));
                    }
                }
            }
        }
    }
    if out_shape.is_empty() {
        let zerod = flat.call_method1("reshape", (PyTuple::empty(py),))?;
        return Ok(F64MinMaxFastPath::Output(zerod.get_item(())?.unbind()));
    }
    let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    Ok(F64MinMaxFastPath::Output(output))
}

// Generic typed core for zero-copy integer np.min/np.max (axis=None or one axis,
// keepdims). Unlike the f64 path — which delegates to numpy because its
// NaN-propagating, signed-zero-ordered fold can't autovectorize in safe Rust —
// integer min/max is a TOTAL-ORDER reduction (no NaN, no signed zero), so
// `acc.min/max(v)` is branchless and autovectorizes, hitting memory bandwidth.
// The cold fallback widened ints to an f64 Vec and ran reduce_min/max's strided
// per-column scan (~22-50x slower for an int axis reduction). inner==1 (last
// axis / full reduction) folds each contiguous lane with a register accumulator;
// inner>1 (non-last axis) folds ROW-WISE into a cache-resident per-column array.
// min/max preserves the INPUT dtype and is order-independent, so the result is
// bit-identical to numpy. C-contiguous gated; empty axis defers.
fn minmax_int_typed<'py, T>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    a: &Bound<'py, PyAny>,
    axis: Option<isize>,
    keepdims: bool,
    take_min: bool,
) -> PyResult<Option<Py<PyAny>>>
where
    T: pyo3::buffer::Element + Copy + Ord + IntoPyObject<'py> + Sync + Send,
{
    let Ok(in_buffer) = PyBuffer::<T>::get(a) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() {
        return Ok(None);
    }
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    if shape.is_empty() {
        return Ok(None);
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let ndim = shape.len();
    let fold = |acc: T, v: T| -> T {
        if take_min {
            if v < acc { v } else { acc }
        } else if v > acc {
            v
        } else {
            acc
        }
    };

    let (outer, axis_len, inner, out_shape): (usize, usize, usize, Vec<usize>) = match axis {
        None => {
            let out_shape = if keepdims { vec![1; ndim] } else { Vec::new() };
            (1, input.len(), 1, out_shape)
        }
        Some(ax) => {
            let ndim_i = ndim as isize;
            let norm = if ax < 0 { ax + ndim_i } else { ax };
            if norm < 0 || norm >= ndim_i {
                return Ok(None);
            }
            let axu = norm as usize;
            let outer: usize = shape[..axu].iter().product();
            let inner: usize = shape[axu + 1..].iter().product();
            let mut out_shape = shape.clone();
            if keepdims {
                out_shape[axu] = 1;
            } else {
                out_shape.remove(axu);
            }
            (outer, shape[axu], inner, out_shape)
        }
    };
    if axis_len == 0 || input.is_empty() {
        // numpy raises on an empty min/max — let it produce the error.
        return Ok(None);
    }

    let out_elems = outer * inner;
    let dt = a.getattr("dtype")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", &dt)?;
    let flat = numpy.call_method("empty", (out_elems,), Some(&kwargs))?;
    if out_elems > 0 {
        let Ok(out_buffer) = PyBuffer::<T>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        if inner == 1 {
            // Each output cell reduces a contiguous run of `axis_len`. SAFETY:
            // repr-transparent read-only buffer under the GIL -> &[T] (Sync).
            let data: &[T] =
                unsafe { std::slice::from_raw_parts(input.as_ptr().cast::<T>(), input.len()) };
            use rayon::prelude::*;
            let lane_fold = |lane: &[T]| -> T {
                let mut acc = lane[0];
                for &v in &lane[1..] {
                    acc = fold(acc, v);
                }
                acc
            };
            let parallel = outer * axis_len >= (1 << 16) && rayon::current_num_threads() >= 2;
            if outer >= 2 {
                // Many independent contiguous lanes (last axis): fan across the pool.
                let results: Vec<T> = if parallel {
                    data.par_chunks_exact(axis_len).map(&lane_fold).collect()
                } else {
                    data.chunks_exact(axis_len).map(&lane_fold).collect()
                };
                for (slot, v) in output.iter().zip(results) {
                    slot.set(v);
                }
            } else {
                // Single big run (full reduction): chunk + reduce (min/max associative).
                let acc = if parallel {
                    data.par_chunks(1 << 14)
                        .map(&lane_fold)
                        .reduce_with(|a, b| fold(a, b))
                        .unwrap()
                } else {
                    lane_fold(data)
                };
                output[0].set(acc);
            }
        } else {
            // Non-last axis: per-inner running min/max accumulator down the axis,
            // walking rows in order (cache-sequential). numpy runs this single-threaded,
            // so parallelize: ≥2 outer groups fan across the pool; a single group (2-D
            // axis=0) privatizes across ROW-BLOCKS and merges the inner-wide planes by
            // elementwise fold. min/max is order-independent, so the result is identical.
            let lane = axis_len * inner;
            // SAFETY: ReadOnlyCell<T> is repr(transparent) over T; read-only buffer held
            // under the GIL -> &[T] (Sync) for the parallel folds.
            let data: &[T] =
                unsafe { std::slice::from_raw_parts(input.as_ptr().cast::<T>(), input.len()) };
            let group_plane = |o: usize| -> Vec<T> {
                let ibase = o * lane;
                let mut acc: Vec<T> = data[ibase..ibase + inner].to_vec();
                for k in 1..axis_len {
                    let in_a = ibase + k * inner;
                    for (i, ac) in acc.iter_mut().enumerate() {
                        *ac = fold(*ac, data[in_a + i]);
                    }
                }
                acc
            };
            use rayon::prelude::*;
            let parallel =
                outer * axis_len * inner >= (1 << 16) && rayon::current_num_threads() >= 2;
            let accs: Vec<T> = if parallel && outer >= 2 {
                let planes: Vec<Vec<T>> = (0..outer).into_par_iter().map(group_plane).collect();
                let mut accs = vec![data[0]; out_elems];
                for (o, p) in planes.into_iter().enumerate() {
                    accs[o * inner..o * inner + inner].copy_from_slice(&p);
                }
                accs
            } else if parallel {
                // Single group (axis=0): privatize across row-blocks, merge planes.
                (0..axis_len)
                    .into_par_iter()
                    .fold(
                        || None::<Vec<T>>,
                        |acc_opt, k| {
                            let row = &data[k * inner..k * inner + inner];
                            match acc_opt {
                                None => Some(row.to_vec()),
                                Some(mut acc) => {
                                    for (ac, &v) in acc.iter_mut().zip(row) {
                                        *ac = fold(*ac, v);
                                    }
                                    Some(acc)
                                }
                            }
                        },
                    )
                    .reduce(
                        || None::<Vec<T>>,
                        |a, b| match (a, b) {
                            (None, x) | (x, None) => x,
                            (Some(mut a), Some(b)) => {
                                for (ac, v) in a.iter_mut().zip(b) {
                                    *ac = fold(*ac, v);
                                }
                                Some(a)
                            }
                        },
                    )
                    .unwrap_or_else(|| vec![data[0]; out_elems])
            } else {
                (0..outer).flat_map(group_plane).collect()
            };
            for (slot, &v) in output.iter().zip(accs.iter()) {
                slot.set(v);
            }
        }
    }
    if out_shape.is_empty() {
        let zerod = flat.call_method1("reshape", (PyTuple::empty(py),))?;
        return Ok(Some(zerod.get_item(())?.unbind()));
    }
    let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    Ok(Some(output))
}

fn minmax_bool_typed(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
    keepdims: bool,
    take_min: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let viewed = a.call_method1("view", (numpy.getattr("uint8")?,))?;
    let Ok(in_buffer) = PyBuffer::<u8>::get(&viewed) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() {
        return Ok(None);
    }
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    if shape.is_empty() {
        return Ok(None);
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let ndim = shape.len();
    let (outer, axis_len, inner, out_shape): (usize, usize, usize, Vec<usize>) = match axis {
        None => {
            let out_shape = if keepdims { vec![1; ndim] } else { Vec::new() };
            (1, input.len(), 1, out_shape)
        }
        Some(ax) => {
            let ndim_i = ndim as isize;
            let norm = if ax < 0 { ax + ndim_i } else { ax };
            if norm < 0 || norm >= ndim_i {
                return Ok(None);
            }
            let axu = norm as usize;
            let outer: usize = shape[..axu].iter().product();
            let inner: usize = shape[axu + 1..].iter().product();
            let mut out_shape = shape.clone();
            if keepdims {
                out_shape[axu] = 1;
            } else {
                out_shape.remove(axu);
            }
            (outer, shape[axu], inner, out_shape)
        }
    };
    if axis_len == 0 || input.is_empty() {
        return Ok(None);
    }

    let out_elems = outer * inner;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "uint8")?;
    let flat_u8 = numpy.call_method("empty", (out_elems,), Some(&kwargs))?;
    if out_elems > 0 {
        let Ok(out_buffer) = PyBuffer::<u8>::get(&flat_u8) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        if axis.is_none() {
            let value = if take_min {
                input.iter().all(|cell| cell.get() != 0)
            } else {
                input.iter().any(|cell| cell.get() != 0)
            };
            output[0].set(u8::from(value));
        } else if inner == 1 {
            for (o, slot) in output.iter().enumerate() {
                let base = o * axis_len;
                let value = if take_min {
                    input[base..base + axis_len]
                        .iter()
                        .all(|cell| cell.get() != 0)
                } else {
                    input[base..base + axis_len]
                        .iter()
                        .any(|cell| cell.get() != 0)
                };
                slot.set(u8::from(value));
            }
        } else {
            let mut accs = vec![if take_min { 1u8 } else { 0u8 }; out_elems];
            let lane = axis_len * inner;
            for o in 0..outer {
                let obase = o * inner;
                let ibase = o * lane;
                for k in 0..axis_len {
                    let in_a = ibase + k * inner;
                    for i in 0..inner {
                        let value = u8::from(input[in_a + i].get() != 0);
                        let acc = &mut accs[obase + i];
                        if take_min {
                            *acc &= value;
                        } else {
                            *acc |= value;
                        }
                    }
                }
            }
            for (slot, &value) in output.iter().zip(accs.iter()) {
                slot.set(value);
            }
        }
    }

    let flat_bool = flat_u8.call_method1("view", (numpy.getattr("bool_")?,))?;
    if out_shape.is_empty() {
        let zerod = flat_bool.call_method1("reshape", (PyTuple::empty(py),))?;
        return Ok(Some(zerod.get_item(())?.unbind()));
    }
    let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
    let output = flat_bool.call_method1("reshape", (&output_shape,))?.unbind();
    Ok(Some(output))
}

// Dispatch zero-copy integer np.min/np.max by dtype width. Non-integer / non-
// ndarray inputs return None so the caller's f64 fast path or numpy fallback runs.
fn try_zerocopy_int_minmax(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
    keepdims: bool,
    take_min: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if kind == "b" {
        return minmax_bool_typed(py, &numpy, a, axis, keepdims, take_min);
    }
    if kind != "i" && kind != "u" {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    // numpy's SIMD min/max processes 16-64 narrow-int lanes per instruction; a scalar
    // (even parallel) fold can't beat it for NARROW ints (1/2-byte) at any size, nor
    // for WIDE ints (4/8-byte) below ~4M elements where the parallel native fold's
    // 64-core bandwidth advantage hasn't yet overtaken SIMD. Delegate both to numpy;
    // large wide ints fall through to the parallel native fold.
    let size: usize = a.getattr("size").and_then(|s| s.extract()).unwrap_or(0);
    if itemsize <= 2 || size < (1 << 23) {
        let op = if take_min { "min" } else { "max" };
        let kwargs = PyDict::new(py);
        if let Some(ax) = axis {
            kwargs.set_item("axis", ax)?;
        }
        kwargs.set_item("keepdims", keepdims)?;
        return Ok(Some(numpy.getattr(op)?.call((a,), Some(&kwargs))?.unbind()));
    }
    match (kind.as_str(), itemsize) {
        ("i", 1) => minmax_int_typed::<i8>(py, &numpy, a, axis, keepdims, take_min),
        ("i", 2) => minmax_int_typed::<i16>(py, &numpy, a, axis, keepdims, take_min),
        ("i", 4) => minmax_int_typed::<i32>(py, &numpy, a, axis, keepdims, take_min),
        ("i", 8) => minmax_int_typed::<i64>(py, &numpy, a, axis, keepdims, take_min),
        ("u", 1) => minmax_int_typed::<u8>(py, &numpy, a, axis, keepdims, take_min),
        ("u", 2) => minmax_int_typed::<u16>(py, &numpy, a, axis, keepdims, take_min),
        ("u", 4) => minmax_int_typed::<u32>(py, &numpy, a, axis, keepdims, take_min),
        ("u", 8) => minmax_int_typed::<u64>(py, &numpy, a, axis, keepdims, take_min),
        _ => Ok(None),
    }
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, dtype=None, out=None, keepdims=false, initial=None, **kwargs))]
#[allow(clippy::too_many_arguments)]
fn prod(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    dtype: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    keepdims: bool,
    initial: Option<Py<PyAny>>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    let where_ = kwargs.and_then(|kw| kw.get_item("where").ok().flatten());
    let numpy = py.import("numpy")?;
    let prod_fn = numpy.getattr("prod")?;

    let a_for_fallback = a.clone_ref(py);
    let axis_for_fallback = axis.as_ref().map(|v| v.clone_ref(py));
    let dtype_for_fallback = dtype.as_ref().map(|v| v.clone_ref(py));
    let out_for_fallback = out.as_ref().map(|v| v.clone_ref(py));
    let initial_for_fallback = initial.as_ref().map(|v| v.clone_ref(py));
    let where_for_fallback = where_.as_ref().map(|v| v.clone().unbind());

    let fallback = || -> PyResult<Py<PyAny>> {
        let kw = clone_py_kwargs(py, kwargs)?;
        if let Some(ax) = axis_for_fallback.as_ref() {
            kw.set_item("axis", ax.bind(py))?;
        }
        if let Some(dt) = dtype_for_fallback.as_ref() {
            kw.set_item("dtype", dt.bind(py))?;
        }
        if let Some(o) = out_for_fallback.as_ref() {
            kw.set_item("out", o.bind(py))?;
        }
        kw.set_item("keepdims", keepdims)?;
        if let Some(init) = initial_for_fallback.as_ref() {
            kw.set_item("initial", init.bind(py))?;
        }
        if let Some(w) = where_for_fallback.as_ref() {
            kw.set_item("where", w.bind(py))?;
        }
        Ok(prod_fn
            .call((a_for_fallback.bind(py),), Some(&kw))?
            .unbind())
    };

    // Fallback for out, dtype, initial, or where parameters
    if has_unrecognized_kwargs(kwargs, &["where"])?
        || out.as_ref().is_some_and(|v| !v.bind(py).is_none())
        || dtype.as_ref().is_some_and(|v| !v.bind(py).is_none())
        || initial.as_ref().is_some_and(|v| !v.bind(py).is_none())
        || where_.as_ref().is_some_and(|v| !v.is_none())
    {
        return fallback();
    }

    // Parse axis: None, integer, or tuple → fallback for tuple
    let axis_val: Option<isize> = match &axis {
        None => None,
        Some(ax) => {
            let ax_bound = ax.bind(py);
            if ax_bound.is_none() {
                None
            } else if let Ok(i) = ax_bound.extract::<isize>() {
                Some(i)
            } else {
                return fallback();
            }
        }
    };

    // Zero-copy sequential product reduction for C-contiguous f64 ndarrays; skips
    // the cold extract + reduce-build Vecs. numpy.prod multiplies sequentially, so
    // this is bit-identical. Tuple axes and other dtypes fall through.
    if let Some(out) = try_zerocopy_f64_prod(py, a.bind(py), axis_val, keepdims)? {
        return Ok(out);
    }

    // Zero-copy integer prod (full reduction): wrapping product with numpy's
    // accumulator promotion (signed->int64, unsigned->uint64). Skips the cold,
    // for-wide-ints lossy extract Vec. keepdims/per-axis/non-integer fall through.
    if !keepdims && let Some(out) = try_zerocopy_int_prod(py, a.bind(py), axis_val)? {
        return Ok(out);
    }

    // f32 prod: numpy's SIMD product beats a widening native fold and avoids any
    // f32->f64->f32 reassociation risk; delegate instead of the cold extract->f64
    // widen path (~10-52x slower than numpy).
    if numpy_dtype_is_f32(a.bind(py)) {
        return fallback();
    }

    // Non-contiguous (transposed/strided) ndarrays bail out of the contiguous-only
    // fast paths into the cold extract → native fold (~47x slower than numpy's
    // cache-blocked strided reduction). Delegate them to numpy.
    if let Ok(ndarray_type) = numpy.getattr("ndarray")
        && a.bind(py).is_exact_instance(&ndarray_type)
        && !a
            .bind(py)
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return fallback();
    }

    // Extract input array
    let array = match extract_precise_numeric_array(py, a.bind(py), "prod(a)") {
        Ok(arr) => arr,
        Err(_) => return fallback(),
    };

    // Call native Rust reduce_prod
    let result = match array.reduce_prod(axis_val, keepdims) {
        Ok(r) => r,
        Err(_) => return fallback(),
    };

    let output = build_numpy_array_from_ufunc(py, &result)?;
    if result.shape().is_empty() {
        return Ok(output.bind(py).get_item(())?.unbind());
    }
    Ok(output)
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, dtype=None, out=None, keepdims=false, **kwargs))]
#[allow(clippy::too_many_arguments)]
fn mean(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    dtype: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    keepdims: bool,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    // Always passthrough to NumPy - see sum() comment
    let numpy = py.import("numpy")?;
    let mean_fn = numpy.getattr("mean")?;
    let kw = clone_py_kwargs(py, kwargs)?;
    if let Some(ax) = axis.as_ref() {
        kw.set_item("axis", ax.bind(py))?;
    }
    if let Some(dt) = dtype.as_ref() {
        kw.set_item("dtype", dt.bind(py))?;
    }
    if let Some(o) = out.as_ref() {
        kw.set_item("out", o.bind(py))?;
    }
    kw.set_item("keepdims", keepdims)?;
    Ok(mean_fn.call((a.bind(py),), Some(&kw))?.unbind())
}

enum DdofArg {
    Native(usize),
    Delegate(Py<PyAny>),
}

impl DdofArg {
    fn set_numpy_kwarg(&self, py: Python<'_>, kw: &Bound<'_, PyDict>) -> PyResult<()> {
        match self {
            Self::Native(value) => kw.set_item("ddof", *value),
            Self::Delegate(value) => kw.set_item("ddof", value.bind(py)),
        }
    }
}

#[allow(clippy::unnecessary_wraps)]
fn parse_ddof_arg(value: &Bound<'_, PyAny>) -> PyResult<DdofArg> {
    match value.extract::<usize>() {
        Ok(value) => Ok(DdofArg::Native(value)),
        Err(_) => Ok(DdofArg::Delegate(value.clone().unbind())),
    }
}

// std: passthrough to NumPy - see sum() comment
#[pyfunction]
#[pyo3(name = "std", signature = (a, axis=None, dtype=None, out=None, ddof=DdofArg::Native(0), keepdims=false, **kwargs))]
#[allow(clippy::too_many_arguments)]
fn py_std(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    dtype: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    #[pyo3(from_py_with = parse_ddof_arg)] ddof: DdofArg,
    keepdims: bool,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    // Native bit-exact flat fast path (axis=None, f64 contiguous, no out/dtype/keepdims,
    // native ddof): two-pass pairwise fold with no whole-array temporaries beats numpy's
    // allocate-two-temps var at large n; std = var.sqrt(). [BlackThrush]
    if kwargs.is_none_or(|kw| kw.is_empty())
        && axis.as_ref().is_none_or(|v| v.bind(py).is_none())
        && dtype.as_ref().is_none_or(|v| v.bind(py).is_none())
        && out.as_ref().is_none_or(|v| v.bind(py).is_none())
        && !keepdims
        && let DdofArg::Native(d) = &ddof
        && let Some(v) = compute_f64_var_flat(py, a.bind(py), *d)?
    {
        return Ok(numpy.getattr("float64")?.call1((v.sqrt(),))?.unbind());
    }
    // Native last-axis fast path (single contiguous axis, f64, no out/dtype, native ddof):
    // per-lane no-alloc two-pass pairwise fold parallel across lanes beats numpy's
    // allocate-temps var(axis=-1).
    if kwargs.is_none_or(|kw| kw.is_empty())
        && dtype.as_ref().is_none_or(|v| v.bind(py).is_none())
        && out.as_ref().is_none_or(|v| v.bind(py).is_none())
        && let DdofArg::Native(d) = &ddof
        && let Some(ax) = axis.as_ref().filter(|v| !v.bind(py).is_none())
        && let Some(o) =
            try_zerocopy_f64_var_axis(py, a.bind(py), ax.bind(py), *d, true, keepdims)?
    {
        return Ok(o);
    }
    // Native first-axis (axis=0) streaming two-pass — the ML standardization reduction
    // numpy materializes two temps + a sequential reduce for. See try_zerocopy_f64_var_axis0.
    if kwargs.is_none_or(|kw| kw.is_empty())
        && dtype.as_ref().is_none_or(|v| v.bind(py).is_none())
        && out.as_ref().is_none_or(|v| v.bind(py).is_none())
        && let DdofArg::Native(d) = &ddof
        && let Some(ax) = axis.as_ref().filter(|v| !v.bind(py).is_none())
        && let Some(o) = try_zerocopy_f64_var_axis0(py, a.bind(py), ax.bind(py), *d, true, keepdims)?
    {
        return Ok(o);
    }
    let std_fn = numpy.getattr("std")?;
    let kw = clone_py_kwargs(py, kwargs)?;
    if let Some(ax) = axis.as_ref() {
        kw.set_item("axis", ax.bind(py))?;
    }
    if let Some(dt) = dtype.as_ref() {
        kw.set_item("dtype", dt.bind(py))?;
    }
    if let Some(o) = out.as_ref() {
        kw.set_item("out", o.bind(py))?;
    }
    ddof.set_numpy_kwarg(py, &kw)?;
    kw.set_item("keepdims", keepdims)?;
    Ok(std_fn.call((a.bind(py),), Some(&kw))?.unbind())
}

// Passthrough to NumPy — our Rust→NumPy export is slower due to bridge overhead.
#[pyfunction]
#[pyo3(signature = (a, axis=None, dtype=None, out=None, ddof=DdofArg::Native(0), keepdims=false, **kwargs))]
#[allow(clippy::too_many_arguments)]
fn var(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    dtype: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    #[pyo3(from_py_with = parse_ddof_arg)] ddof: DdofArg,
    keepdims: bool,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    // Native bit-exact flat fast path — see py_std. numpy.var allocates two whole-array
    // temporaries before its pairwise sum; our two-pass fold reads the buffer twice with
    // no allocation -> big win at large n, bit-exact pairwise. [BlackThrush]
    if kwargs.is_none_or(|kw| kw.is_empty())
        && axis.as_ref().is_none_or(|v| v.bind(py).is_none())
        && dtype.as_ref().is_none_or(|v| v.bind(py).is_none())
        && out.as_ref().is_none_or(|v| v.bind(py).is_none())
        && !keepdims
        && let DdofArg::Native(d) = &ddof
        && let Some(v) = compute_f64_var_flat(py, a.bind(py), *d)?
    {
        return Ok(numpy.getattr("float64")?.call1((v,))?.unbind());
    }
    // Native last-axis fast path — see py_std. take_sqrt = false for var.
    if kwargs.is_none_or(|kw| kw.is_empty())
        && dtype.as_ref().is_none_or(|v| v.bind(py).is_none())
        && out.as_ref().is_none_or(|v| v.bind(py).is_none())
        && let DdofArg::Native(d) = &ddof
        && let Some(ax) = axis.as_ref().filter(|v| !v.bind(py).is_none())
        && let Some(o) =
            try_zerocopy_f64_var_axis(py, a.bind(py), ax.bind(py), *d, false, keepdims)?
    {
        return Ok(o);
    }
    // Native first-axis (axis=0) streaming two-pass — see py_std. take_sqrt = false for var.
    if kwargs.is_none_or(|kw| kw.is_empty())
        && dtype.as_ref().is_none_or(|v| v.bind(py).is_none())
        && out.as_ref().is_none_or(|v| v.bind(py).is_none())
        && let DdofArg::Native(d) = &ddof
        && let Some(ax) = axis.as_ref().filter(|v| !v.bind(py).is_none())
        && let Some(o) = try_zerocopy_f64_var_axis0(py, a.bind(py), ax.bind(py), *d, false, keepdims)?
    {
        return Ok(o);
    }
    let var_fn = numpy.getattr("var")?;
    let kw = clone_py_kwargs(py, kwargs)?;
    if let Some(ax) = axis.as_ref() {
        kw.set_item("axis", ax.bind(py))?;
    }
    if let Some(dt) = dtype.as_ref() {
        kw.set_item("dtype", dt.bind(py))?;
    }
    if let Some(o) = out.as_ref() {
        kw.set_item("out", o.bind(py))?;
    }
    ddof.set_numpy_kwarg(py, &kw)?;
    kw.set_item("keepdims", keepdims)?;
    Ok(var_fn.call((a.bind(py),), Some(&kw))?.unbind())
}

// Native Rust min with fallback for unsupported parameters.
#[pyfunction]
#[pyo3(name = "min", signature = (a, axis=None, out=None, keepdims=false, initial=None, **kwargs))]
#[allow(clippy::too_many_arguments)]
fn py_min(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    keepdims: bool,
    initial: Option<Py<PyAny>>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    let where_ = kwargs.and_then(|kw| kw.get_item("where").ok().flatten());
    let numpy = py.import("numpy")?;
    let min_fn = numpy.getattr("min")?;

    let a_for_fallback = a.clone_ref(py);
    let axis_for_fallback = axis.as_ref().map(|v| v.clone_ref(py));
    let out_for_fallback = out.as_ref().map(|v| v.clone_ref(py));
    let initial_for_fallback = initial.as_ref().map(|v| v.clone_ref(py));
    let where_for_fallback = where_.as_ref().map(|v| v.clone().unbind());

    let fallback = || -> PyResult<Py<PyAny>> {
        let kw = clone_py_kwargs(py, kwargs)?;
        if let Some(ax) = axis_for_fallback.as_ref() {
            kw.set_item("axis", ax.bind(py))?;
        }
        if let Some(o) = out_for_fallback.as_ref() {
            kw.set_item("out", o.bind(py))?;
        }
        kw.set_item("keepdims", keepdims)?;
        if let Some(init) = initial_for_fallback.as_ref() {
            kw.set_item("initial", init.bind(py))?;
        }
        if let Some(w) = where_for_fallback.as_ref() {
            kw.set_item("where", w.bind(py))?;
        }
        Ok(min_fn.call((a_for_fallback.bind(py),), Some(&kw))?.unbind())
    };

    // Fallback for out, initial, or where parameters
    if has_unrecognized_kwargs(kwargs, &["where"])?
        || out.as_ref().is_some_and(|v| !v.bind(py).is_none())
        || initial.as_ref().is_some_and(|v| !v.bind(py).is_none())
        || where_.as_ref().is_some_and(|v| !v.is_none())
    {
        return fallback();
    }

    // Non-contiguous (transposed/strided) ndarrays can't use the zero-copy fold and
    // make the cold extract → native scan ~19-32x slower than numpy's cache-blocked
    // strided reduction. Delegate to numpy up front (before the any-NaN scan inside
    // the f64 fast path, which itself is O(n) on a non-contiguous array).
    if let Ok(ndarray_type) = numpy.getattr("ndarray")
        && a.bind(py).is_exact_instance(&ndarray_type)
        && !a
            .bind(py)
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return fallback();
    }

    // Parse axis: None, integer, or tuple → fallback for tuple
    let axis_val: Option<isize> = match &axis {
        None => None,
        Some(ax) => {
            let ax_bound = ax.bind(py);
            if ax_bound.is_none() {
                None
            } else if let Ok(i) = ax_bound.extract::<isize>() {
                Some(i)
            } else {
                return fallback();
            }
        }
    };

    match try_zerocopy_f64_minmax(py, a.bind(py), axis_val, keepdims, F64MinMaxOp::Min)? {
        F64MinMaxFastPath::Output(out) => return Ok(out),
        F64MinMaxFastPath::DelegateToNumpy => return fallback(),
        F64MinMaxFastPath::NotApplicable => {}
    }

    // Zero-copy integer min: total-order autovectorizing fold (the f64 path
    // delegates to numpy, but native int min/max beats numpy's strided reduce).
    if let Some(out) = try_zerocopy_int_minmax(py, a.bind(py), axis_val, keepdims, true)? {
        return Ok(out);
    }

    // f32/f16 min: numpy's native reduction beats fnp's widening extract->f64 scan
    // (8vdtg ceiling, ~1.5-20x slower); delegate.
    if numpy_dtype_is_f32(a.bind(py)) || numpy_dtype_is_f16(a.bind(py)) {
        return fallback();
    }

    // Extract input array
    let array = match extract_precise_numeric_array(py, a.bind(py), "min(a)") {
        Ok(arr) => arr,
        Err(_) => return fallback(),
    };

    // Call native Rust reduce_min
    let result = match array.reduce_min(axis_val, keepdims) {
        Ok(r) => r,
        Err(_) => return fallback(),
    };

    let output = build_numpy_array_from_ufunc(py, &result)?;
    if result.shape().is_empty() {
        return Ok(output.bind(py).get_item(())?.unbind());
    }
    Ok(output)
}

