// Native Rust all with fallback for unsupported parameters.
#[pyfunction]
#[pyo3(signature = (a, axis=None, out=None, keepdims=false, **kwargs))]
fn all(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    keepdims: bool,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    let where_ = kwargs.and_then(|kw| kw.get_item("where").ok().flatten());
    let numpy = py.import("numpy")?;
    let all_fn = numpy.getattr("all")?;

    let a_for_fallback = a.clone_ref(py);
    let axis_for_fallback = axis.as_ref().map(|v| v.clone_ref(py));
    let out_for_fallback = out.as_ref().map(|v| v.clone_ref(py));
    let where_for_fallback = where_.as_ref().map(|v| v.clone().unbind());

    let fallback = || -> PyResult<Py<PyAny>> {
        let kw = clone_py_kwargs(py, kwargs)?;
        if let Some(ax) = axis_for_fallback.as_ref() {
            kw.set_item("axis", ax.bind(py))?;
        }
        if let Some(o) = out_for_fallback.as_ref() {
            kw.set_item("out", o.bind(py))?;
        }
        kw.set_item("keepdims", keepdims)?;
        if let Some(w) = where_for_fallback.as_ref() {
            kw.set_item("where", w.bind(py))?;
        }
        Ok(all_fn.call((a_for_fallback.bind(py),), Some(&kw))?.unbind())
    };

    // Fallback for out, keepdims, or where parameters
    if has_unrecognized_kwargs(kwargs, &["where"])?
        || out.as_ref().is_some_and(|v| !v.bind(py).is_none())
        || keepdims
        || where_.as_ref().is_some_and(|v| !v.is_none())
    {
        return fallback();
    }

    // Parse axis: None, integer, or tuple → fallback for tuple
    let axis_val: Option<isize> = match &axis {
        None => None,
        Some(ax) => {
            let ax_bound = ax.bind(py);
            if ax_bound.is_none() {
                None
            } else if let Ok(i) = ax_bound.extract::<isize>() {
                Some(i)
            } else {
                return fallback();
            }
        }
    };

    // Bool along an AXIS: numpy's SIMD all (byte scan + early-exit) beats the per-lane
    // scalar fold. Delegate (axis=None bool and f64 stay native).
    if axis_val.is_some()
        && a.bind(py).is_exact_instance(&numpy.getattr("ndarray")?)
        && a.bind(py).getattr("dtype")?.getattr("kind")?.extract::<String>()? == "b"
    {
        return fallback();
    }

    // Zero-copy AND-fold for C-contiguous bool / f64 ndarrays (axis=None or a
    // single integer axis); skips the cold extract Vec. Truthiness is
    // order-independent so the short-circuit result is bit-identical.
    if let Some(out) = try_zerocopy_any_all(py, a.bind(py), axis_val, true)? {
        return Ok(out);
    }

    // Extract input array
    let array = match extract_precise_numeric_array(py, a.bind(py), "all(a)") {
        Ok(arr) => arr,
        Err(_) => return fallback(),
    };

    // Call native Rust all
    let result = match array.all(axis_val) {
        Ok(r) => r,
        Err(_) => return fallback(),
    };

    let output = build_numpy_array_from_ufunc(py, &result)?;
    if result.shape().is_empty() {
        return Ok(output.bind(py).get_item(())?.unbind());
    }
    Ok(output)
}

