// Cumulative sum with native Rust fast path.
#[pyfunction]
#[pyo3(signature = (a, axis=None, dtype=None, out=None))]
fn cumsum(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    dtype: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let cumsum_fn = numpy.getattr("cumsum")?;

    let a_for_fallback = a.clone_ref(py);
    let axis_for_fallback = axis.as_ref().map(|v| v.clone_ref(py));
    let dtype_for_fallback = dtype.as_ref().map(|v| v.clone_ref(py));
    let out_for_fallback = out.as_ref().map(|v| v.clone_ref(py));

    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(ax) = axis_for_fallback.as_ref() {
            kwargs.set_item("axis", ax.bind(py))?;
        }
        if let Some(dt) = dtype_for_fallback.as_ref() {
            kwargs.set_item("dtype", dt.bind(py))?;
        }
        if let Some(o) = out_for_fallback.as_ref() {
            kwargs.set_item("out", o.bind(py))?;
        }
        Ok(cumsum_fn
            .call((a_for_fallback.bind(py),), Some(&kwargs))?
            .unbind())
    };

    // Fallback for `out` buffer or explicit dtype (conversion not native)
    if out.as_ref().is_some_and(|v| !v.bind(py).is_none())
        || dtype.as_ref().is_some_and(|v| !v.bind(py).is_none())
    {
        return fallback();
    }

    // Parse axis: None or integer
    let axis_val: Option<isize> = match &axis {
        None => None,
        Some(ax) => {
            let ax_bound = ax.bind(py);
            if ax_bound.is_none() {
                None
            } else if let Ok(i) = ax_bound.extract::<isize>() {
                Some(i)
            } else {
                return fallback();
            }
        }
    };

    // float16 accumulates STEPWISE in float16 in numpy (each partial sum rounded to
    // f16); our extract path accumulates in f64 then casts once, diverging by ~1 ULP.
    // Delegate f16 to numpy for exact parity.
    if numpy_dtype_is_f16(a.bind(py)) {
        return fallback();
    }
    // Zero-copy flatten cumsum for C-contiguous f64 ndarrays (axis=None any ndim,
    // or 1-D with axis 0/-1); skips the cold extract/build Vecs. Bit-identical
    // (strictly sequential accumulation); per-axis multi-dim cumsums fall through.
    if let Some(result) = try_zerocopy_f64_cumsum(py, a.bind(py), axis_val)? {
        return Ok(result);
    }
    // Zero-copy integer cumsum (flatten case, all widths) with numpy's accumulator
    // promotion (signed->int64, unsigned->uint64). Skips the cold, for-wide-ints
    // lossy extract Vec.
    if let Some(result) = try_zerocopy_int_cumsum(py, a.bind(py), axis_val)? {
        return Ok(result);
    }
    // Zero-copy per-axis cumsum for multi-dim f64 ndarrays (explicit axis); slab-
    // by-slab accumulation. Bit-identical; out-of-range axes fall through.
    if let Some(ax) = axis_val
        && let Some(result) = try_zerocopy_f64_cumulative_axis(py, a.bind(py), ax, false, false)?
    {
        return Ok(result);
    }
    // Zero-copy per-axis integer cumsum (explicit axis) with numpy's accumulator
    // promotion; the flatten helper above only covers axis=None.
    if let Some(ax) = axis_val
        && let Some(result) = try_zerocopy_int_cumsum_axis(py, a.bind(py), ax)?
    {
        return Ok(result);
    }
    // Zero-copy float32 cumsum: flatten (axis=None / 1-D) then per-axis multi-dim.
    // numpy keeps the float32 accumulator (no promotion) and accumulates left-to-
    // right, so the sequential f32 add is bit-identical. Falls through otherwise.
    if let Some(result) = try_zerocopy_f32_cumsum(py, a.bind(py), axis_val)? {
        return Ok(result);
    }
    if let Some(ax) = axis_val
        && let Some(result) = try_zerocopy_f32_cumsum_axis(py, a.bind(py), ax)?
    {
        return Ok(result);
    }

    // Non-contiguous (transposed/strided) ndarrays bail out of the contiguous-only
    // zero-copy paths into the cold extract → native scan (~3x slower than numpy's
    // strided accumulate). Delegate them to numpy.
    if let Ok(ndarray_type) = numpy.getattr("ndarray")
        && a.bind(py).is_exact_instance(&ndarray_type)
        && !a
            .bind(py)
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return fallback();
    }

    // Extract input array
    let array = match extract_precise_numeric_array(py, a.bind(py), "cumsum(a)") {
        Ok(arr) => arr,
        Err(_) => return fallback(),
    };

    // Call native Rust cumsum
    let result = match array.cumsum(axis_val) {
        Ok(r) => r,
        Err(_) => return fallback(),
    };

    build_numpy_array_from_ufunc(py, &result)
}

// Cumulative product with native Rust fast path.
#[pyfunction]
#[pyo3(signature = (a, axis=None, dtype=None, out=None))]
fn cumprod(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    dtype: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let cumprod_fn = numpy.getattr("cumprod")?;

    let a_for_fallback = a.clone_ref(py);
    let axis_for_fallback = axis.as_ref().map(|v| v.clone_ref(py));
    let dtype_for_fallback = dtype.as_ref().map(|v| v.clone_ref(py));
    let out_for_fallback = out.as_ref().map(|v| v.clone_ref(py));

    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(ax) = axis_for_fallback.as_ref() {
            kwargs.set_item("axis", ax.bind(py))?;
        }
        if let Some(dt) = dtype_for_fallback.as_ref() {
            kwargs.set_item("dtype", dt.bind(py))?;
        }
        if let Some(o) = out_for_fallback.as_ref() {
            kwargs.set_item("out", o.bind(py))?;
        }
        Ok(cumprod_fn
            .call((a_for_fallback.bind(py),), Some(&kwargs))?
            .unbind())
    };

    // Fallback for `out` buffer or explicit dtype (conversion not native)
    if out.as_ref().is_some_and(|v| !v.bind(py).is_none())
        || dtype.as_ref().is_some_and(|v| !v.bind(py).is_none())
    {
        return fallback();
    }

    // Parse axis: None or integer
    let axis_val: Option<isize> = match &axis {
        None => None,
        Some(ax) => {
            let ax_bound = ax.bind(py);
            if ax_bound.is_none() {
                None
            } else if let Ok(i) = ax_bound.extract::<isize>() {
                Some(i)
            } else {
                return fallback();
            }
        }
    };

    // float16 accumulates STEPWISE in float16 in numpy (each partial product rounded
    // to f16); our extract path accumulates in f64 then casts once, diverging by
    // ~1 ULP. Delegate f16 to numpy for exact parity.
    if numpy_dtype_is_f16(a.bind(py)) {
        return fallback();
    }
    // Zero-copy flatten cumprod for C-contiguous f64 ndarrays (axis=None any ndim,
    // or 1-D with axis 0/-1); skips the cold extract/build Vecs. Bit-identical
    // (strictly sequential accumulation); per-axis multi-dim cumprods fall through.
    if let Some(result) = try_zerocopy_f64_cumprod(py, a.bind(py), axis_val)? {
        return Ok(result);
    }
    // Zero-copy per-axis cumprod for multi-dim f64 ndarrays (explicit axis); slab-
    // by-slab accumulation. Bit-identical; out-of-range axes fall through.
    if let Some(ax) = axis_val
        && let Some(result) = try_zerocopy_f64_cumulative_axis(py, a.bind(py), ax, true, false)?
    {
        return Ok(result);
    }
    // Zero-copy integer cumprod: flatten (axis=None / 1-D) then per-axis multi-dim.
    // numpy promotes the accumulator (signed -> int64, unsigned -> uint64) and wraps;
    // strictly sequential so wrapping_mul is bit-identical. Also fixes the wide-int
    // overflow-to-inf crash the f64-bridge extract path hit. Falls through otherwise.
    if let Some(result) = try_zerocopy_int_cumprod(py, a.bind(py), axis_val)? {
        return Ok(result);
    }
    if let Some(ax) = axis_val
        && let Some(result) = try_zerocopy_int_cumprod_axis(py, a.bind(py), ax)?
    {
        return Ok(result);
    }
    // Zero-copy float32 cumprod: flatten (axis=None / 1-D) then per-axis multi-dim.
    // numpy keeps the float32 accumulator (no promotion) and accumulates left-to-
    // right, so the sequential f32 multiply is bit-identical. Falls through otherwise.
    if let Some(result) = try_zerocopy_f32_cumprod(py, a.bind(py), axis_val)? {
        return Ok(result);
    }
    if let Some(ax) = axis_val
        && let Some(result) = try_zerocopy_f32_cumprod_axis(py, a.bind(py), ax)?
    {
        return Ok(result);
    }

    // Non-contiguous (transposed/strided) ndarrays bail the zero-copy paths into the
    // cold extract → rebuild (transpose-copy). Delegate to numpy.
    if noncontiguous_ndarray(&numpy, a.bind(py))? {
        return fallback();
    }
    // Extract input array
    let array = match extract_precise_numeric_array(py, a.bind(py), "cumprod(a)") {
        Ok(arr) => arr,
        Err(_) => return fallback(),
    };

    // Call native Rust cumprod
    let result = match array.cumprod(axis_val) {
        Ok(r) => r,
        Err(_) => return fallback(),
    };

    build_numpy_array_from_ufunc(py, &result)
}

// Trace (sum along diagonal) with native Rust fast path.
#[pyfunction]
#[pyo3(signature = (a, offset=0, axis1=0, axis2=1, dtype=None, out=None))]
fn trace(
    py: Python<'_>,
    a: Py<PyAny>,
    offset: i64,
    axis1: isize,
    axis2: isize,
    dtype: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let a_for_fallback = a.clone_ref(py);
    let dtype_for_fallback = dtype.as_ref().map(|v| v.clone_ref(py));
    let out_for_fallback = out.as_ref().map(|v| v.clone_ref(py));

    let fallback = || -> PyResult<Py<PyAny>> {
        // Import numpy lazily here so the native fast paths below pay neither the
        // module-import lookup nor the `trace` attribute fetch on the hot path.
        let numpy = py.import("numpy")?;
        let trace_fn = numpy.getattr("trace")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("offset", offset)?;
        kwargs.set_item("axis1", axis1)?;
        kwargs.set_item("axis2", axis2)?;
        if let Some(dt) = dtype_for_fallback.as_ref() {
            kwargs.set_item("dtype", dt.bind(py))?;
        }
        if let Some(o) = out_for_fallback.as_ref() {
            kwargs.set_item("out", o.bind(py))?;
        }
        Ok(trace_fn
            .call((a_for_fallback.bind(py),), Some(&kwargs))?
            .unbind())
    };

    // Fallback for `out` buffer or explicit dtype (conversion not native)
    if out.as_ref().is_some_and(|v| !v.bind(py).is_none())
        || dtype.as_ref().is_some_and(|v| !v.bind(py).is_none())
    {
        return fallback();
    }

    // NumPy's trace uses the same default accumulator dtype as sum: bool and
    // sub-platform integers/unsigned promote to int64/uint64, while float widths
    // are preserved. Our native trace_axis preserves the input dtype, so it only
    // matches NumPy for int64/uint64/float inputs; defer bool and narrow int/uint
    // (which NumPy widens) to numpy.trace.
    if numpy_dtype_is_subplatform_integer(py, a.bind(py)) {
        return fallback();
    }

    // Zero-copy fast path: a contiguous 2-D float64 matrix in the canonical
    // (axis1, axis2) == (0, 1) orientation. Read its row-major buffer directly and
    // sum the diagonal a[i, i+offset] by striding (i*ncols + i + offset) — no numpy
    // import, no `diagonal` view object, no per-element extract across the bridge.
    // Bit-identical to the diagonal-view path below: identical i-ascending order and
    // the same left-to-right f64 fold from 0.0 (matching UFuncArray::scalar(_,F64)).
    let a_bound = a.bind(py);
    {
        let n1 = if axis1 < 0 { axis1 + 2 } else { axis1 };
        let n2 = if axis2 < 0 { axis2 + 2 } else { axis2 };
        if n1 == 0
            && n2 == 1
            && let Ok(buffer) = PyBuffer::<f64>::get(a_bound)
            && buffer.dimensions() == 2
            && buffer.is_c_contiguous()
            && let Some(data) = buffer.as_slice(py)
        {
            let shape = buffer.shape();
            let (nrows, ncols) = (shape[0], shape[1]);
            let mut sum = 0.0f64;
            if offset >= 0 {
                let off = offset as usize;
                if off < ncols {
                    let count = nrows.min(ncols - off);
                    for i in 0..count {
                        sum += data[i * ncols + i + off].get();
                    }
                }
            } else {
                let off = offset.unsigned_abs() as usize;
                if off < nrows {
                    let count = (nrows - off).min(ncols);
                    for i in 0..count {
                        sum += data[(i + off) * ncols + i].get();
                    }
                }
            }
            return build_f64_scalar(py, sum);
        }
    }

    // Fast path: a 2-D matrix's trace only needs its N diagonal elements, but the
    // generic native path below extracts the whole N×N matrix across the bridge
    // (O(n²) data movement) just to sum the diagonal. Ask NumPy for the diagonal
    // VIEW (O(1), strided, no copy), extract only those N elements, and sum them
    // left-to-right. This is bit-identical to UFuncArray::trace — np.diagonal
    // yields a[i, i+offset] in the same i-ascending order as self.diag(offset), the
    // f64 fold and the scalar dtype match exactly. Restricted to the canonical
    // (axis1, axis2) == (0, 1) form (trace_axis is transpose-invariant for 2-D, so
    // swapped/other axes keep the validated full path).
    if let Ok(shape) = a_bound
        .getattr("shape")
        .and_then(|s| s.extract::<Vec<usize>>())
        && shape.len() == 2
    {
        let n1 = if axis1 < 0 { axis1 + 2 } else { axis1 };
        let n2 = if axis2 < 0 { axis2 + 2 } else { axis2 };
        if n1 == 0
            && n2 == 1
            && let Ok(diag_view) = a_bound.call_method1("diagonal", (offset,))
            && let Ok(diag_array) = extract_precise_numeric_array(py, &diag_view, "trace(diagonal)")
        {
            // diag_array is the 1-D diagonal view. Sum it via the shared helper,
            // which accumulates the exact-integer sidecar with wraparound for
            // int64/uint64 and folds f64 otherwise — matching NumPy's native
            // accumulator. This keeps the O(n) diagonal-only fast path while fixing
            // the int64/uint64 precision loss the plain f64 sum had for |x| > 2^53.
            let result = diag_array.sum_extracted_diagonal_to_scalar();
            return build_numpy_scalar_or_array(py, &result);
        }
    }

    // Extract input array
    let array = match extract_precise_numeric_array(py, a.bind(py), "trace(a)") {
        Ok(arr) => arr,
        Err(_) => return fallback(),
    };

    // Call native Rust trace_axis
    let result = match array.trace_axis(offset, axis1, axis2) {
        Ok(r) => r,
        Err(_) => return fallback(),
    };

    build_numpy_scalar_or_array(py, &result)
}

// Single-pass portable-SIMD argmax/argmin over a finite f64 slice. `take_max`
// selects argmax (true) vs argmin (false). Returns the index of the FIRST
// occurrence of the extreme value (numpy's tie-break), or None if any NaN is
// present (numpy's argmax/argmin return the first NaN index, which we hand back
// to the scalar/numpy path rather than special-case in the vector loop). Each
// 8-wide lane keeps a running extreme value and the first index achieving it
// (strict compare → first occurrence within the lane); a final horizontal reduce
// picks the global extreme and breaks ties by the smallest index. This replaces
// the cold extract_precise → reduce_argmax scalar scan, which is ~5-13x slower
// than numpy's vectorized argmax.
fn simd_argextreme_f64(data: &[f64], take_max: bool) -> Option<usize> {
    use std::simd::cmp::{SimdPartialEq, SimdPartialOrd};
    use std::simd::{Mask, Select, Simd};
    const L: usize = 8;
    let n = data.len();
    if n == 0 {
        return None;
    }
    type V = Simd<f64, L>;
    type I = Simd<u64, L>;
    let lane_off = I::from_array([0, 1, 2, 3, 4, 5, 6, 7]);
    let init = if take_max {
        f64::NEG_INFINITY
    } else {
        f64::INFINITY
    };
    let mut vext = V::splat(init);
    let mut vidx = I::splat(0);
    let mut vnan = Mask::<i64, L>::splat(false);
    let chunks = n / L;
    for ci in 0..chunks {
        let off = ci * L;
        let c = V::from_slice(&data[off..off + L]);
        vnan |= c.simd_ne(c); // NaN lanes (c != c)
        let cur = I::splat((off) as u64) + lane_off;
        let better = if take_max {
            c.simd_gt(vext)
        } else {
            c.simd_lt(vext)
        };
        vext = better.select(c, vext);
        vidx = better.select(cur, vidx);
    }
    let ext_arr = vext.to_array();
    let idx_arr = vidx.to_array();
    let mut best_v = ext_arr[0];
    let mut best_i = idx_arr[0];
    for l in 1..L {
        let v = ext_arr[l];
        let i = idx_arr[l];
        let is_better = if take_max { v > best_v } else { v < best_v };
        if is_better || (v == best_v && i < best_i) {
            best_v = v;
            best_i = i;
        }
    }
    let mut saw_nan = vnan.any();
    // Scalar remainder. Tail indices exceed every SIMD index, so a tie must NOT
    // displace the earlier SIMD result (strict compare preserves first occurrence).
    for (i, &v) in data.iter().enumerate().take(n).skip(chunks * L) {
        if v.is_nan() {
            saw_nan = true;
            continue;
        }
        let is_better = if take_max { v > best_v } else { v < best_v };
        if is_better {
            best_v = v;
            best_i = i as u64;
        }
    }
    if saw_nan {
        return None;
    }
    Some(best_i as usize)
}

// Zero-copy SIMD f64 argmax/argmin for the full reduction (axis=None). Gated to a
// C-contiguous f64 ndarray (axis=None flattens C-order == memory order only when
// contiguous). NaN-containing arrays, non-f64, non-ndarray, per-axis reductions,
// and empty input all defer to the existing path. Returns a numpy intp scalar.
fn try_zerocopy_f64_argextreme(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
    take_max: bool,
) -> PyResult<Option<Py<PyAny>>> {
    if axis.is_some() {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    if kind != "f" || itemsize != 8 {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() {
        return Ok(None);
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    if cells.is_empty() {
        return Ok(None);
    }
    // numpy's argmin/argmax is a single fused SIMD pass, single-threaded. Large arrays:
    // run simd_argextreme_f64 per rayon chunk over the borrowed buffer (NO Vec copy) and
    // combine — aggregate read bandwidth beats numpy's one thread. Tie-break: chunks are
    // processed in index order and a chunk only replaces the running best on a STRICTLY
    // better value, so equal values keep the earliest index (numpy's first-occurrence).
    // Any chunk seeing a NaN (simd kernel returns None) -> defer the whole array to numpy
    // for its first-NaN semantics. Memory-bound (compare-only) -> high gate like cheap unary.
    let n = cells.len();
    const ARGEXTREME_PARALLEL_MIN: usize = 1 << 21;
    if n >= ARGEXTREME_PARALLEL_MIN && rayon::current_num_threads() >= 2 {
        use rayon::prelude::*;
        // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only under the GIL.
        let data: &[f64] = unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), n) };
        let chunk = n.div_ceil(rayon::current_num_threads());
        let partials: Vec<Option<(usize, f64)>> = data
            .par_chunks(chunk)
            .enumerate()
            .map(|(ci, c)| simd_argextreme_f64(c, take_max).map(|i| (ci * chunk + i, c[i])))
            .collect();
        if partials.iter().any(Option::is_none) {
            let fname = if take_max { "argmax" } else { "argmin" };
            return Ok(Some(numpy.getattr(fname)?.call1((a,))?.unbind()));
        }
        let mut best: Option<(usize, f64)> = None;
        for p in partials.into_iter().flatten() {
            let take = match best {
                None => true,
                Some(b) => {
                    if take_max {
                        p.1 > b.1
                    } else {
                        p.1 < b.1
                    }
                }
            };
            if take {
                best = Some(p);
            }
        }
        let idx = best.expect("non-empty buffer has a best").0;
        return Ok(Some(numpy.getattr("intp")?.call1((idx,))?.unbind()));
    }
    // Medium arrays: the old copy-then-scan native path was ~2.5x behind numpy's fused SIMD
    // pass, so delegate (same first-occurrence + first-NaN semantics). Tiny arrays keep the
    // native scan (numpy's per-call dispatch isn't worth it below the crossover).
    const ARGEXTREME_NUMPY_MIN_LEN: usize = 4096;
    if n >= ARGEXTREME_NUMPY_MIN_LEN {
        let fname = if take_max { "argmax" } else { "argmin" };
        return Ok(Some(numpy.getattr(fname)?.call1((a,))?.unbind()));
    }
    // Tight contiguous read of the buffer into an owned f64 Vec (a memcpy-shaped
    // loop the compiler vectorizes), so the SIMD kernel gets real aligned vector
    // loads instead of per-element cell reads.
    let data: Vec<f64> = cells.iter().map(|c| c.get()).collect();
    match simd_argextreme_f64(&data, take_max) {
        Some(idx) => {
            let scalar = numpy.getattr("intp")?.call1((idx,))?;
            Ok(Some(scalar.unbind()))
        }
        None => Ok(None), // NaN present — defer to numpy's first-NaN semantics.
    }
}

// Per-lane integer argmax/argmin over the contiguous last axis: each lane is L
// consecutive elements of the typed buffer. A single scan that tracks the running
// extreme AND its index can't vectorize (the index carries a loop-dependency), so
// it was element-bound (~10x behind numpy's SIMD argmax on narrow ints). Instead
// run TWO vectorizable passes per lane: pass 1 folds the extreme VALUE with a
// branchless max/min (lowers to pmaxs/pmins); pass 2 finds the FIRST index equal
// to it (short-circuits — for narrow ints the extreme recurs early so this is
// nearly free). First-equal == numpy's first-occurrence tie rule, and integer
// order is total, so the result is identical to the sequential scan.
fn lastaxis_argextreme_int<T: pyo3::buffer::Element + Copy + PartialOrd + PartialEq + Sync>(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    outer: usize,
    lane: usize,
    take_max: bool,
) -> Option<Vec<i64>> {
    let in_buffer = PyBuffer::<T>::get(a).ok()?;
    let cells = in_buffer.as_slice(py)?;
    if cells.len() != outer * lane {
        return None;
    }
    // SAFETY: ReadOnlyCell<T> is repr(transparent) over T; read-only buffer under the
    // GIL -> &[T] (Sync, T a POD numeric). Each lane is independent — fan across the
    // rayon pool (numpy runs argmax single-threaded).
    let data: &[T] = unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<T>(), cells.len()) };
    let lane_arg = |row: &[T]| -> i64 {
        // Pass 1: extreme value (branchless fold autovectorizes).
        let mut ext = row[0];
        if take_max {
            for &v in &row[1..] {
                ext = if v > ext { v } else { ext };
            }
        } else {
            for &v in &row[1..] {
                ext = if v < ext { v } else { ext };
            }
        }
        // Pass 2: first index achieving it (numpy's first-occurrence tie-break).
        let mut best_i = 0usize;
        for (j, &v) in row.iter().enumerate() {
            if v == ext {
                best_i = j;
                break;
            }
        }
        best_i as i64
    };
    use rayon::prelude::*;
    // Same tiny-per-lane-scan crossover as the float last-axis argextreme above:
    // total<~1M is faster serial (rayon fan-out dwarfs the scan), >=1<<20 wins
    // parallel. Raised from 1<<16. Lane scans independent -> serial/parallel identical.
    const ARGEXTREME_INT_LASTAXIS_PARALLEL_MIN: usize = 1 << 20;
    let out: Vec<i64> = if outer * lane >= ARGEXTREME_INT_LASTAXIS_PARALLEL_MIN
        && rayon::current_num_threads() >= 2
    {
        data.par_chunks_exact(lane).map(lane_arg).collect()
    } else {
        data.chunks_exact(lane).map(lane_arg).collect()
    };
    Some(out)
}

// Zero-copy argmax/argmin over the CONTIGUOUS LAST axis of a C-contiguous
// ndarray, for f64 (per-lane portable-SIMD) and every integer width (per-lane
// scalar scan). Each lane is a contiguous run of `lane` elements; the SIMD/scalar
// kernel runs over a reused row buffer (f64) or directly over the typed cells
// (int), so there is no big intermediate allocation. The result is an intp array
// of shape[:-1]. Gated to axis == last axis, ndim >= 2, non-empty lane. f64 lanes
// containing NaN defer the whole call to numpy (first-NaN semantics); non-last
// axis, non-contiguous, f32/complex, and 1-D inputs all defer.
fn try_zerocopy_lastaxis_argextreme(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
    take_max: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let Some(ax) = axis else {
        return Ok(None);
    };
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    if !a.getattr("flags")?.getattr("c_contiguous")?.extract::<bool>()? {
        return Ok(None);
    }
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len();
    if ndim < 2 {
        return Ok(None);
    }
    let norm = if ax < 0 { ax + ndim as isize } else { ax };
    if norm != (ndim - 1) as isize {
        return Ok(None); // only the contiguous last axis
    }
    let lane = shape[ndim - 1];
    if lane == 0 {
        return Ok(None); // numpy raises on a zero-length reduction axis
    }
    let outer: usize = shape[..ndim - 1].iter().product();
    let out_shape: Vec<usize> = shape[..ndim - 1].to_vec();

    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;

    let indices: Vec<i64> = if kind == "f" && itemsize == 8 {
        let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
            return Ok(None);
        };
        let Some(cells) = in_buffer.as_slice(py) else {
            return Ok(None);
        };
        if cells.len() != outer * lane {
            return Ok(None);
        }
        // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only buffer
        // under the GIL -> &[f64] (Sync). Each lane is an independent contiguous run,
        // so pass the sub-slice straight to simd_argextreme_f64 (no per-lane copy) and
        // fan the lanes across the rayon pool. simd_argextreme_f64 keeps the FIRST max
        // on ties, so per-lane results match numpy exactly; any NaN lane defers whole.
        let data: &[f64] =
            unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), cells.len()) };
        use rayon::prelude::*;
        // Per-lane argextreme is a tiny scan, so rayon fan-out only pays off well above
        // the old 1<<16 gate: measured, total<~1M is FASTER serial (argmax 256x256
        // (65K) was 6.1x SLOWER parallel than numpy, ~1x serial; 524K serial 121<136us
        // parallel), while >=1<<20 (1M, e.g. 1024x1024) parallel wins (113<173us serial,
        // beats numpy) and 4M is ~8x. Gate at 1<<20. Lane scans are independent ->
        // serial/parallel bit-identical.
        const ARGEXTREME_LASTAXIS_PARALLEL_MIN: usize = 1 << 20;
        let parallel = outer * lane >= ARGEXTREME_LASTAXIS_PARALLEL_MIN
            && rayon::current_num_threads() >= 2;
        let per: Vec<Option<usize>> = if parallel {
            data.par_chunks_exact(lane)
                .map(|l| simd_argextreme_f64(l, take_max))
                .collect()
        } else {
            data.chunks_exact(lane)
                .map(|l| simd_argextreme_f64(l, take_max))
                .collect()
        };
        if per.iter().any(|x| x.is_none()) {
            return Ok(None); // NaN lane — defer the whole call to numpy
        }
        per.into_iter().map(|i| i.unwrap() as i64).collect()
    } else if kind == "i" || kind == "u" {
        let res = match (kind.as_str(), itemsize) {
            ("i", 1) => lastaxis_argextreme_int::<i8>(py, a, outer, lane, take_max),
            ("i", 2) => lastaxis_argextreme_int::<i16>(py, a, outer, lane, take_max),
            ("i", 4) => lastaxis_argextreme_int::<i32>(py, a, outer, lane, take_max),
            ("i", 8) => lastaxis_argextreme_int::<i64>(py, a, outer, lane, take_max),
            ("u", 1) => lastaxis_argextreme_int::<u8>(py, a, outer, lane, take_max),
            ("u", 2) => lastaxis_argextreme_int::<u16>(py, a, outer, lane, take_max),
            ("u", 4) => lastaxis_argextreme_int::<u32>(py, a, outer, lane, take_max),
            ("u", 8) => lastaxis_argextreme_int::<u64>(py, a, outer, lane, take_max),
            _ => None,
        };
        match res {
            Some(v) => v,
            None => return Ok(None),
        }
    } else if kind == "b" {
        // bool as uint8: argmax = first 0x01 (first True) / index 0 if all-False; argmin = first
        // 0x00 (first False) / index 0 if all-True — exactly numpy argmax/argmin(bool). Reuse the
        // u8 int path on a uint8 view, avoiding the cold bool->f64 widen (~2500x along last axis).
        let view = a.call_method1("view", (numpy.getattr("uint8")?,))?;
        match lastaxis_argextreme_int::<u8>(py, &view, outer, lane, take_max) {
            Some(v) => v,
            None => return Ok(None),
        }
    } else {
        return Ok(None);
    };

    let flat = numpy_array_from_slice(py, &numpy, &indices, "intp")?;
    let reshaped = flat.call_method1("reshape", (out_shape,))?;
    Ok(Some(reshaped.unbind()))
}

// Zero-copy NON-last-axis argmin/argmax over a C-contiguous f64 ndarray (e.g.
// argmin(M, axis=0)). Runs a per-inner (best value, best index) accumulator DOWN
// the axis, reading rows sequentially off the borrowed buffer (cache-friendly vs
// the strided per-column scan the native path does, and skipping the whole-array
// extract). The strict `<` (argmin) / `>` (argmax) keeps the FIRST occurrence on
// ties — matching numpy, and correct for signed zeros (compared equal). The
// branchless select lets the per-inner value/index update autovectorize. NaN
// cannot be ordered this way (numpy has its own first-NaN-wins arg semantics), so
// any NaN defers the whole call. The contiguous last axis is handled elsewhere.
fn try_zerocopy_f64_argextreme_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
    take_max: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let Some(ax) = axis else {
        return Ok(None);
    };
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len();
    if ndim < 2 {
        return Ok(None);
    }
    let norm = if ax < 0 { ax + ndim as isize } else { ax };
    if norm < 0 || norm as usize >= ndim - 1 {
        return Ok(None); // non-last axis only; the last axis is handled separately
    }
    let k = norm as usize;
    let axis_len = shape[k];
    if axis_len == 0 {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() {
        return Ok(None);
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let outer: usize = shape[..k].iter().product();
    let inner: usize = shape[k + 1..].iter().product();
    let lane = axis_len * inner;
    let mut indices = vec![0i64; outer * inner];
    let mut best_val = vec![0.0f64; inner];
    let mut any_nan = false;
    for o in 0..outer {
        let base = o * lane;
        // Seed from row 0 (its index is already 0 in `indices`).
        for (bv, c) in best_val.iter_mut().zip(cells[base..base + inner].iter()) {
            let v = c.get();
            *bv = v;
            any_nan |= v != v;
        }
        let idx_out = &mut indices[o * inner..o * inner + inner];
        for r in 1..axis_len {
            let row = &cells[base + r * inner..base + r * inner + inner];
            let ri = r as i64;
            if take_max {
                for ((bv, oi), c) in best_val.iter_mut().zip(idx_out.iter_mut()).zip(row) {
                    let v = c.get();
                    any_nan |= v != v;
                    let better = v > *bv;
                    *oi = if better { ri } else { *oi };
                    *bv = if better { v } else { *bv };
                }
            } else {
                for ((bv, oi), c) in best_val.iter_mut().zip(idx_out.iter_mut()).zip(row) {
                    let v = c.get();
                    any_nan |= v != v;
                    let better = v < *bv;
                    *oi = if better { ri } else { *oi };
                    *bv = if better { v } else { *bv };
                }
            }
        }
    }
    if any_nan {
        return Ok(None);
    }
    let mut out_shape: Vec<usize> = shape[..k].to_vec();
    out_shape.extend_from_slice(&shape[k + 1..]);
    let flat = numpy_array_from_slice(py, &numpy, &indices, "intp")?;
    let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
    let reshaped = flat.call_method1("reshape", (&output_shape,))?;
    if out_shape.is_empty() {
        return Ok(Some(reshaped.get_item(())?.unbind()));
    }
    Ok(Some(reshaped.unbind()))
}

// Generic typed core for integer argmax/argmin over a NON-last axis. Mirrors the
// f64 non-last-axis path but for total-order integer types (no NaN): row 0 seeds
// each column's running best, later rows update on a STRICT improvement so the
// FIRST occurrence wins (numpy's tie rule). Walking rows sequentially with a
// branchless per-column update vectorizes and is cache-friendly, replacing the
// cold extract_precise -> reduce_argmax strided scan (~2.6x slower for int ax0).
fn argextreme_axis_int_typed<T>(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    a: &Bound<'_, PyAny>,
    shape: &[usize],
    k: usize,
    take_max: bool,
) -> PyResult<Option<Py<PyAny>>>
where
    T: pyo3::buffer::Element + Copy + PartialOrd,
{
    let axis_len = shape[k];
    if axis_len == 0 {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<T>::get(a) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() {
        return Ok(None);
    }
    let Some(cells) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    if cells.is_empty() {
        return Ok(None);
    }
    let outer: usize = shape[..k].iter().product();
    let inner: usize = shape[k + 1..].iter().product();
    let lane = axis_len * inner;
    let mut indices = vec![0i64; outer * inner];
    let mut best_val: Vec<T> = vec![cells[0].get(); inner];
    for o in 0..outer {
        let base = o * lane;
        for (bv, c) in best_val.iter_mut().zip(cells[base..base + inner].iter()) {
            *bv = c.get();
        }
        let idx_out = &mut indices[o * inner..o * inner + inner];
        for r in 1..axis_len {
            let row = &cells[base + r * inner..base + r * inner + inner];
            let ri = r as i64;
            if take_max {
                for ((bv, oi), c) in best_val.iter_mut().zip(idx_out.iter_mut()).zip(row) {
                    let v = c.get();
                    let better = v > *bv;
                    *oi = if better { ri } else { *oi };
                    *bv = if better { v } else { *bv };
                }
            } else {
                for ((bv, oi), c) in best_val.iter_mut().zip(idx_out.iter_mut()).zip(row) {
                    let v = c.get();
                    let better = v < *bv;
                    *oi = if better { ri } else { *oi };
                    *bv = if better { v } else { *bv };
                }
            }
        }
    }
    let mut out_shape: Vec<usize> = shape[..k].to_vec();
    out_shape.extend_from_slice(&shape[k + 1..]);
    let flat = numpy_array_from_slice(py, numpy, &indices, "intp")?;
    let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
    let reshaped = flat.call_method1("reshape", (&output_shape,))?;
    if out_shape.is_empty() {
        return Ok(Some(reshaped.get_item(())?.unbind()));
    }
    Ok(Some(reshaped.unbind()))
}

// Dispatch the integer non-last-axis argmax/argmin by dtype width.
fn try_zerocopy_int_argextreme_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
    take_max: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let Some(ax) = axis else {
        return Ok(None);
    };
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if kind != "i" && kind != "u" && kind != "b" {
        return Ok(None);
    }
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    let ndim = shape.len();
    if ndim < 2 {
        return Ok(None);
    }
    let norm = if ax < 0 { ax + ndim as isize } else { ax };
    if norm < 0 || norm as usize >= ndim - 1 {
        return Ok(None); // non-last axis only; the last axis is handled separately
    }
    let k = norm as usize;
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    if kind == "b" {
        // bool as uint8: argmax/argmin(u8 0/1) per inner = first True / first False, matching
        // numpy bool semantics. Reuse the u8 typed path on a uint8 view (no bool->f64 widen).
        let view = a.call_method1("view", (numpy.getattr("uint8")?,))?;
        return argextreme_axis_int_typed::<u8>(py, &numpy, &view, &shape, k, take_max);
    }
    match (kind.as_str(), itemsize) {
        ("i", 1) => argextreme_axis_int_typed::<i8>(py, &numpy, a, &shape, k, take_max),
        ("i", 2) => argextreme_axis_int_typed::<i16>(py, &numpy, a, &shape, k, take_max),
        ("i", 4) => argextreme_axis_int_typed::<i32>(py, &numpy, a, &shape, k, take_max),
        ("i", 8) => argextreme_axis_int_typed::<i64>(py, &numpy, a, &shape, k, take_max),
        ("u", 1) => argextreme_axis_int_typed::<u8>(py, &numpy, a, &shape, k, take_max),
        ("u", 2) => argextreme_axis_int_typed::<u16>(py, &numpy, a, &shape, k, take_max),
        ("u", 4) => argextreme_axis_int_typed::<u32>(py, &numpy, a, &shape, k, take_max),
        ("u", 8) => argextreme_axis_int_typed::<u64>(py, &numpy, a, &shape, k, take_max),
        _ => Ok(None),
    }
}

// Flat argmax/argmin for a bool ndarray (axis=None). numpy short-circuits at the first True
// (argmax) / first False (argmin) — the very common `np.argmax(cond)` find-first-True idiom — so
// it's ~instant when the target is near the start. fnp's bool input missed the int/f64 fast paths
// and fell to the cold bool->f64 extract + scalar scan (~40ms for 8M, ~36000x). Here we scan the
// bool buffer as u64 words: skip all-False words (argmax) / all-True words (argmin), then locate
// the first hit byte. Bit-identical index to numpy (first occurrence of the max/min; 0 if none).
fn try_zerocopy_bool_argextreme_flat(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis_val: Option<isize>,
    want_max: bool,
) -> PyResult<Option<Py<PyAny>>> {
    if axis_val.is_some() {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_t = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_t)
        || a.getattr("dtype")?.getattr("kind")?.extract::<String>()? != "b"
        || !a
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return Ok(None);
    }
    let view = a.call_method1("view", (numpy.getattr("uint8")?,))?;
    let Ok(buf) = PyBuffer::<u8>::get(&view) else {
        return Ok(None);
    };
    let Some(cells) = buf.as_slice(py) else {
        return Ok(None);
    };
    let n = cells.len();
    if n == 0 {
        return Ok(None); // numpy raises on empty argmax/argmin; defer
    }
    // SAFETY: ReadOnlyCell<u8> is repr(transparent) over u8; read-only under the GIL.
    let bytes: &[u8] = unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<u8>(), n) };
    // canonical bool bytes are 0x00/0x01: all-False word = 0, all-True word = 0x0101..01.
    let skip_word: u64 = if want_max { 0 } else { 0x0101_0101_0101_0101 };
    let hit = |b: u8| if want_max { b != 0 } else { b == 0 };
    let mut idx = 0usize; // all-skip (all-False for max / all-True for min) -> index 0
    let mut done = false;
    let mut i = 0usize;
    while i + 8 <= n {
        let w = u64::from_ne_bytes(bytes[i..i + 8].try_into().unwrap());
        if w != skip_word {
            for j in 0..8 {
                if hit(bytes[i + j]) {
                    idx = i + j;
                    done = true;
                    break;
                }
            }
            if done {
                break;
            }
        }
        i += 8;
    }
    if !done {
        for (k, &b) in bytes.iter().enumerate().take(n).skip(i) {
            if hit(b) {
                idx = k;
                break;
            }
        }
    }
    Ok(Some(numpy.getattr("intp")?.call1((idx,))?.unbind()))
}

// Arg reductions
// Native Rust argmax with fallback for unsupported parameters.
#[pyfunction]
#[pyo3(signature = (a, axis=None, out=None, **kwargs))]
fn argmax(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    let keepdims_arg = kwargs.and_then(|kw| kw.get_item("keepdims").ok().flatten());
    let numpy = py.import("numpy")?;
    let argmax_fn = numpy.getattr("argmax")?;

    let a_for_fallback = a.clone_ref(py);
    let axis_for_fallback = axis.as_ref().map(|v| v.clone_ref(py));
    let out_for_fallback = out.as_ref().map(|v| v.clone_ref(py));

    let fallback = || -> PyResult<Py<PyAny>> {
        let kw = clone_py_kwargs(py, kwargs)?;
        if let Some(ax) = axis_for_fallback.as_ref() {
            kw.set_item("axis", ax.bind(py))?;
        }
        if let Some(o) = out_for_fallback.as_ref() {
            kw.set_item("out", o.bind(py))?;
        }
        Ok(argmax_fn
            .call((a_for_fallback.bind(py),), Some(&kw))?
            .unbind())
    };

    let keepdims = match keepdims_arg.as_ref() {
        Some(value) => match value.extract::<bool>() {
            Ok(value) => value,
            Err(_) => return fallback(),
        },
        None => false,
    };

    // Fallback for out or keepdims parameters
    if has_unrecognized_kwargs(kwargs, &["keepdims"])?
        || out.as_ref().is_some_and(|v| !v.bind(py).is_none())
        || keepdims
    {
        return fallback();
    }

    // Parse axis: None or integer
    let axis_val: Option<isize> = match &axis {
        None => None,
        Some(ax) => {
            let ax_bound = ax.bind(py);
            if ax_bound.is_none() {
                None
            } else if let Ok(i) = ax_bound.extract::<isize>() {
                Some(i)
            } else {
                return fallback();
            }
        }
    };

    // Zero-copy integer fast path (axis=None): scan the buffer for the first
    // maximum directly instead of widening to an f64 Vec (~55x slower for int64).
    if let Some(out) = try_zerocopy_int_argextreme(py, a.bind(py), axis_val, true)? {
        return Ok(out);
    }
    // Single-pass SIMD f64 fast path (axis=None): ~5-13x faster than the cold
    // extract_precise → reduce_argmax scalar scan (NaN arrays defer to numpy).
    if let Some(out) = try_zerocopy_f64_argextreme(py, a.bind(py), axis_val, true)? {
        return Ok(out);
    }
    // Flat bool argmax (np.argmax(cond) find-first-True): bool missed the int/f64 paths and fell
    // to the cold bool->f64 extract (~36000x). Short-circuit u64-word scan for the first True.
    if let Some(out) = try_zerocopy_bool_argextreme_flat(py, a.bind(py), axis_val, true)? {
        return Ok(out);
    }
    // Narrow ints (1/2-byte) along an axis: numpy's SIMD argmax (16-64 lanes per
    // instruction) beats the scalar per-lane scan; delegate. (Flat narrow ints are
    // split in try_zerocopy_int_argextreme above.)
    if axis_val.is_some()
        && let Ok(dt) = a.bind(py).getattr("dtype")
        && let Ok(k) = dt.getattr("kind").and_then(|x| x.extract::<String>())
        && (k == "i" || k == "u")
        && dt
            .getattr("itemsize")
            .and_then(|x| x.extract::<usize>())
            .map(|s| s <= 2)
            .unwrap_or(false)
    {
        return fallback();
    }
    // Zero-copy contiguous last-axis fast path (f64 SIMD + every int width): the
    // per-axis extract_precise → reduce_argmax path was ~3x (f64) to ~50x (int64)
    // slower than numpy.
    if let Some(out) = try_zerocopy_lastaxis_argextreme(py, a.bind(py), axis_val, true)? {
        return Ok(out);
    }
    // Zero-copy non-last-axis f64 fast path (e.g. argmax(M, axis=0)): see argmin.
    if let Some(out) = try_zerocopy_f64_argextreme_axis(py, a.bind(py), axis_val, true)? {
        return Ok(out);
    }
    // Zero-copy non-last-axis integer fast path (e.g. argmax(int_M, axis=0)).
    if let Some(out) = try_zerocopy_int_argextreme_axis(py, a.bind(py), axis_val, true)? {
        return Ok(out);
    }
    // f32/f16 argmax: numpy's native argextreme beats fnp's widening extract->scan
    // (~1.3-35x slower); delegate.
    if numpy_dtype_is_f32(a.bind(py)) || numpy_dtype_is_f16(a.bind(py)) {
        return fallback();
    }

    // Non-contiguous (transposed/strided) ndarrays bail out of the contiguous-only
    // fast paths into the cold extract → native scan (~1.4-2.8x slower than numpy's
    // strided argextreme). Delegate them to numpy.
    if let Ok(ndarray_type) = numpy.getattr("ndarray")
        && a.bind(py).is_exact_instance(&ndarray_type)
        && !a
            .bind(py)
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return fallback();
    }

    // Extract input array
    let array = match extract_precise_numeric_array(py, a.bind(py), "argmax(a)") {
        Ok(arr) => arr,
        Err(_) => return fallback(),
    };

    // Call native Rust reduce_argmax
    let result = match array.reduce_argmax(axis_val) {
        Ok(r) => r,
        Err(_) => return fallback(),
    };

    let output = build_numpy_array_from_ufunc(py, &result)?;
    if result.shape().is_empty() {
        return Ok(output.bind(py).get_item(())?.unbind());
    }
    Ok(output)
}

// Native Rust argmin with fallback for unsupported parameters.
#[pyfunction]
#[pyo3(signature = (a, axis=None, out=None, **kwargs))]
fn argmin(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    let keepdims_arg = kwargs.and_then(|kw| kw.get_item("keepdims").ok().flatten());
    let numpy = py.import("numpy")?;
    let argmin_fn = numpy.getattr("argmin")?;

    let a_for_fallback = a.clone_ref(py);
    let axis_for_fallback = axis.as_ref().map(|v| v.clone_ref(py));
    let out_for_fallback = out.as_ref().map(|v| v.clone_ref(py));

    let fallback = || -> PyResult<Py<PyAny>> {
        let kw = clone_py_kwargs(py, kwargs)?;
        if let Some(ax) = axis_for_fallback.as_ref() {
            kw.set_item("axis", ax.bind(py))?;
        }
        if let Some(o) = out_for_fallback.as_ref() {
            kw.set_item("out", o.bind(py))?;
        }
        Ok(argmin_fn
            .call((a_for_fallback.bind(py),), Some(&kw))?
            .unbind())
    };

    let keepdims = match keepdims_arg.as_ref() {
        Some(value) => match value.extract::<bool>() {
            Ok(value) => value,
            Err(_) => return fallback(),
        },
        None => false,
    };

    // Fallback for out or keepdims parameters
    if has_unrecognized_kwargs(kwargs, &["keepdims"])?
        || out.as_ref().is_some_and(|v| !v.bind(py).is_none())
        || keepdims
    {
        return fallback();
    }

    // Parse axis: None or integer
    let axis_val: Option<isize> = match &axis {
        None => None,
        Some(ax) => {
            let ax_bound = ax.bind(py);
            if ax_bound.is_none() {
                None
            } else if let Ok(i) = ax_bound.extract::<isize>() {
                Some(i)
            } else {
                return fallback();
            }
        }
    };

    // Zero-copy integer fast path (axis=None): scan the buffer for the first
    // minimum directly instead of widening to an f64 Vec (~55x slower for int64).
    if let Some(out) = try_zerocopy_int_argextreme(py, a.bind(py), axis_val, false)? {
        return Ok(out);
    }
    // Single-pass SIMD f64 fast path (axis=None): ~5-13x faster than the cold
    // extract_precise → reduce_argmin scalar scan (NaN arrays defer to numpy).
    if let Some(out) = try_zerocopy_f64_argextreme(py, a.bind(py), axis_val, false)? {
        return Ok(out);
    }
    // Flat bool argmin (find-first-False): same cold-extract gap as argmax; short-circuit
    // u64-word scan skipping all-True words for the first False.
    if let Some(out) = try_zerocopy_bool_argextreme_flat(py, a.bind(py), axis_val, false)? {
        return Ok(out);
    }
    // Narrow ints (1/2-byte) along an axis: numpy's SIMD argmin beats the scalar
    // per-lane scan; delegate. (Flat narrow ints are split in try_zerocopy_int_argextreme.)
    if axis_val.is_some()
        && let Ok(dt) = a.bind(py).getattr("dtype")
        && let Ok(k) = dt.getattr("kind").and_then(|x| x.extract::<String>())
        && (k == "i" || k == "u")
        && dt
            .getattr("itemsize")
            .and_then(|x| x.extract::<usize>())
            .map(|s| s <= 2)
            .unwrap_or(false)
    {
        return fallback();
    }
    // Zero-copy contiguous last-axis fast path (f64 SIMD + every int width): the
    // per-axis extract_precise → reduce_argmin path was ~3x (f64) to ~50x (int64)
    // slower than numpy.
    if let Some(out) = try_zerocopy_lastaxis_argextreme(py, a.bind(py), axis_val, false)? {
        return Ok(out);
    }
    // Zero-copy non-last-axis f64 fast path (e.g. argmin(M, axis=0)): the per-axis
    // extract_precise → reduce_argmin path copies the whole array then scans
    // strided per-column (~2.8x numpy on a 1000x1000). Defers NaN to numpy.
    if let Some(out) = try_zerocopy_f64_argextreme_axis(py, a.bind(py), axis_val, false)? {
        return Ok(out);
    }
    // Zero-copy non-last-axis integer fast path (e.g. argmin(int_M, axis=0)).
    if let Some(out) = try_zerocopy_int_argextreme_axis(py, a.bind(py), axis_val, false)? {
        return Ok(out);
    }
    // f32/f16 argmin: numpy's native argextreme beats fnp's widening extract->scan
    // (~1.3-34x slower); delegate.
    if numpy_dtype_is_f32(a.bind(py)) || numpy_dtype_is_f16(a.bind(py)) {
        return fallback();
    }

    // Non-contiguous (transposed/strided) ndarrays bail out of the contiguous-only
    // fast paths into the cold extract → native scan (~1.4-2.8x slower than numpy's
    // strided argextreme). Delegate them to numpy.
    if let Ok(ndarray_type) = numpy.getattr("ndarray")
        && a.bind(py).is_exact_instance(&ndarray_type)
        && !a
            .bind(py)
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return fallback();
    }

    // Extract input array
    let array = match extract_precise_numeric_array(py, a.bind(py), "argmin(a)") {
        Ok(arr) => arr,
        Err(_) => return fallback(),
    };

    // Call native Rust reduce_argmin
    let result = match array.reduce_argmin(axis_val) {
        Ok(r) => r,
        Err(_) => return fallback(),
    };

    let output = build_numpy_array_from_ufunc(py, &result)?;
    if result.shape().is_empty() {
        return Ok(output.bind(py).get_item(())?.unbind());
    }
    Ok(output)
}

const PY_NATIVE_GEMM_MIN_FLOPS: usize = 320 * 320 * 320;
// Upper dim bound for routing np.matmul/np.dot to the native packed GEMM. The
// B-micropanel packing (e509860c, ~5x) moved the crossover vs the local numpy
// BLAS from 896 to 1024 (measured same-host, parity=True: at n=1024 fnp 20.0 ms
// vs numpy 26.0 ms; at n=1280 numpy 32.0 ms vs fnp 41.2 ms, so numpy wins above).
const PY_NATIVE_GEMM_MAX_DIM: usize = 1024;

#[derive(Clone, Copy)]
enum PythonNativeGemmOp {
    Matmul,
    Dot,
}

fn python_native_gemm_f64_2d_eligible(a: &UFuncArray, b: &UFuncArray) -> bool {
    if !matches!(a.dtype(), DType::F64)
        || !matches!(b.dtype(), DType::F64)
        || a.has_integer_sidecar()
        || b.has_integer_sidecar()
        || a.shape().len() != 2
        || b.shape().len() != 2
    {
        return false;
    }
    let (m, k1) = (a.shape()[0], a.shape()[1]);
    let (k2, n) = (b.shape()[0], b.shape()[1]);
    if k1 != k2
        || [m, k1, n]
            .iter()
            .any(|&dim| dim == 0 || dim > PY_NATIVE_GEMM_MAX_DIM)
    {
        return false;
    }
    if a.values()
        .iter()
        .chain(b.values().iter())
        .any(|value| !value.is_finite())
    {
        return false;
    }
    m.saturating_mul(k1).saturating_mul(n) >= PY_NATIVE_GEMM_MIN_FLOPS
}

fn python_native_gemm_f64_2d_metadata_gate(
    py: Python<'_>,
    a_obj: &Bound<'_, PyAny>,
    b_obj: &Bound<'_, PyAny>,
) -> PyResult<bool> {
    let numpy = py.import("numpy")?;
    let ndarray = numpy.getattr("ndarray")?;
    if !a_obj.is_instance(&ndarray)? || !b_obj.is_instance(&ndarray)? {
        return Ok(false);
    }

    let a_shape = a_obj.getattr("shape")?.extract::<Vec<usize>>()?;
    let b_shape = b_obj.getattr("shape")?.extract::<Vec<usize>>()?;
    if a_shape.len() != 2 || b_shape.len() != 2 {
        return Ok(false);
    }

    let (m, k1) = (a_shape[0], a_shape[1]);
    let (k2, n) = (b_shape[0], b_shape[1]);
    if k1 != k2
        || [m, k1, n]
            .iter()
            .any(|&dim| dim == 0 || dim > PY_NATIVE_GEMM_MAX_DIM)
        || m.saturating_mul(k1).saturating_mul(n) < PY_NATIVE_GEMM_MIN_FLOPS
    {
        return Ok(false);
    }

    let a_dtype = a_obj.getattr("dtype")?;
    let b_dtype = b_obj.getattr("dtype")?;
    let a_kind = a_dtype.getattr("kind")?.extract::<String>()?;
    let b_kind = b_dtype.getattr("kind")?.extract::<String>()?;
    let a_itemsize = a_dtype.getattr("itemsize")?.extract::<usize>()?;
    let b_itemsize = b_dtype.getattr("itemsize")?.extract::<usize>()?;
    Ok(a_kind == "f" && b_kind == "f" && a_itemsize == 8 && b_itemsize == 8)
}

fn python_native_gemm_f64_2d(
    py: Python<'_>,
    a_obj: &Bound<'_, PyAny>,
    b_obj: &Bound<'_, PyAny>,
    op: PythonNativeGemmOp,
    require_profile_gate: bool,
) -> PyResult<Option<Py<PyAny>>> {
    if require_profile_gate && !python_native_gemm_f64_2d_metadata_gate(py, a_obj, b_obj)? {
        return Ok(None);
    }

    let a = match extract_precise_numeric_array(py, a_obj, "native_gemm(a)") {
        Ok(array) => array,
        Err(_) => return Ok(None),
    };
    let b = match extract_precise_numeric_array(py, b_obj, "native_gemm(b)") {
        Ok(array) => array,
        Err(_) => return Ok(None),
    };
    if require_profile_gate && !python_native_gemm_f64_2d_eligible(&a, &b) {
        return Ok(None);
    }
    if !matches!(a.dtype(), DType::F64)
        || !matches!(b.dtype(), DType::F64)
        || a.has_integer_sidecar()
        || b.has_integer_sidecar()
        || a.shape().len() != 2
        || b.shape().len() != 2
        || a.shape()[1] != b.shape()[0]
    {
        return Ok(None);
    }
    let result = match op {
        PythonNativeGemmOp::Matmul => a.matmul(&b),
        PythonNativeGemmOp::Dot => a.dot(&b),
    };
    match result {
        Ok(array) => Ok(Some(build_numpy_scalar_or_array(py, &array)?)),
        Err(_) => Ok(None),
    }
}

fn python_explicit_out_is_absent_or_none(py: Python<'_>, out: Option<&Py<PyAny>>) -> bool {
    out.is_none_or(|value| value.bind(py).is_none())
}

// Medium-large float64 GEMM-shaped calls route to the native Rust kernel; the
// rest pass through to NumPy so small matrices, out=, dtype/ufunc kwargs,
// integer/complex dtypes, non-finite payloads, and unprofiled sizes retain the
// exact incumbent behavior.
#[pyfunction]
#[pyo3(signature = (x1, x2, out=None, **kwargs))]
fn matmul(
    py: Python<'_>,
    x1: Py<PyAny>,
    x2: Py<PyAny>,
    out: Option<Py<PyAny>>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    if kwargs.is_none_or(|kw| kw.is_empty())
        && python_explicit_out_is_absent_or_none(py, out.as_ref())
        && let Some(result) = python_native_gemm_f64_2d(
            py,
            x1.bind(py),
            x2.bind(py),
            PythonNativeGemmOp::Matmul,
            true,
        )?
    {
        return Ok(result);
    }

    let numpy = py.import("numpy")?;
    let matmul_fn = numpy.getattr("matmul")?;
    match out {
        Some(o) => Ok(matmul_fn
            .call((x1.bind(py), x2.bind(py), o.bind(py)), kwargs)?
            .unbind()),
        None => Ok(matmul_fn.call((x1.bind(py), x2.bind(py)), kwargs)?.unbind()),
    }
}

// Same profiled native GEMM gate as matmul for the 2-D float64 dot case.
#[pyfunction]
#[pyo3(signature = (a, b, out=None))]
fn dot(py: Python<'_>, a: Py<PyAny>, b: Py<PyAny>, out: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    if python_explicit_out_is_absent_or_none(py, out.as_ref())
        && let Some(result) =
            python_native_gemm_f64_2d(py, a.bind(py), b.bind(py), PythonNativeGemmOp::Dot, true)?
    {
        return Ok(result);
    }

    let numpy = py.import("numpy")?;
    let dot_fn = numpy.getattr("dot")?;
    match out {
        Some(o) => Ok(dot_fn
            .call((a.bind(py), b.bind(py), o.bind(py)), None)?
            .unbind()),
        None => Ok(dot_fn.call((a.bind(py), b.bind(py)), None)?.unbind()),
    }
}

// np.einsum('ij->ji', a) and any single-operand PURE PERMUTATION of all (distinct)
// input labels — 'ijk->kij', 'ab->ba', … — is a transpose: numpy returns a
// writable VIEW (stride permutation, zero data movement), but our native kernel
// materialized a full copy (np.einsum('ij->ji') on 1000² was ~4600x numpy AND
// np.shares_memory disagreed). Return a.transpose(perm) — exactly numpy's view —
// for the permutation case. Dtype-agnostic (no arithmetic), so this runs before
// the float/int dtype policy. Repeated labels (diagonal 'ii->i'), dropped labels
// (reduction 'ij->i'), implicit mode, ellipsis, and out=/dtype= kwargs fall
// through to the existing paths.
fn try_einsum_transpose_view(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Option<Py<PyAny>>> {
    if args.len() != 2 {
        return Ok(None);
    }
    // Only `optimize` is harmless for a transpose; out=/dtype=/order=/casting= change
    // the result, so defer those.
    if let Some(kw) = kwargs {
        for key in kw.keys() {
            if key.extract::<String>().map(|k| k != "optimize").unwrap_or(true) {
                return Ok(None);
            }
        }
    }
    let Ok(subscripts) = args.get_item(0)?.extract::<String>() else {
        return Ok(None);
    };
    let Some((inp, outp)) = subscripts.split_once("->") else {
        return Ok(None);
    };
    let inb: Vec<char> = inp.trim().chars().collect();
    let oub: Vec<char> = outp.trim().chars().collect();
    let distinct = |s: &[char]| {
        s.iter().collect::<std::collections::HashSet<_>>().len() == s.len()
    };
    // Must be a permutation of ALL labels: same length, all alphabetic, both sides
    // distinct, and same label set.
    if inb.is_empty()
        || inb.len() != oub.len()
        || !inb.iter().all(|c| c.is_ascii_alphabetic())
        || !oub.iter().all(|c| c.is_ascii_alphabetic())
        || !distinct(&inb)
        || !distinct(&oub)
        || !oub.iter().all(|c| inb.contains(c))
    {
        return Ok(None);
    }
    let operand = args.get_item(1)?;
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !operand.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let ndim = operand.getattr("ndim")?.extract::<usize>()?;
    if ndim != inb.len() {
        return Ok(None);
    }
    // perm[k] = axis of `operand` that supplies output axis k.
    let perm: Vec<usize> = oub
        .iter()
        .map(|c| inb.iter().position(|x| x == c).unwrap())
        .collect();
    Ok(Some(
        operand.call_method1("transpose", (perm,))?.unbind(),
    ))
}

// True for a single-operand pure REDUCTION spec ("ijk->k", "ij->", "ijk->ik"):
// explicit arrow, no ellipsis/comma, unique input labels (no diagonal), output a
// strict unique subset of the input labels. Such a spec is just a sum over the
// dropped axes (with an optional reorder), which our generic native kernel runs
// 1.6-2.6x slower than numpy's optimized einsum reduction -> delegate for parity.
// (Pure permutations / diagonals / multi-operand contractions are excluded and keep
// their existing fast paths.)
fn einsum_spec_is_single_reduce(spec: &str) -> bool {
    let spec: String = spec.chars().filter(|c| !c.is_whitespace()).collect();
    if spec.contains("...") || spec.contains(',') {
        return false;
    }
    let Some((inp, out)) = spec.split_once("->") else {
        return false;
    };
    if inp.is_empty()
        || !inp.bytes().all(|b| b.is_ascii_alphabetic())
        || !out.bytes().all(|b| b.is_ascii_alphabetic())
    {
        return false;
    }
    let mut in_seen = [false; 256];
    for &b in inp.as_bytes() {
        if in_seen[b as usize] {
            return false; // repeated input label = diagonal, not a plain reduction
        }
        in_seen[b as usize] = true;
    }
    let mut out_seen = [false; 256];
    for &b in out.as_bytes() {
        if !in_seen[b as usize] || out_seen[b as usize] {
            return false; // output label absent from input, or repeated
        }
        out_seen[b as usize] = true;
    }
    out.len() < inp.len() // must drop (sum) at least one axis
}

// True for a single-operand spec with a REPEATED input index = diagonal extraction.
// The plain "ii->i" 2-D case is handled by the buffered-diagonal fast path earlier; this
// catches the variants it misses — "bii->bi" (batched), "...ii->...i" (ellipsis), "iij->ij",
// "ii" (trace) — which the generic native kernel runs 43-1339x slower than numpy's strided
// diagonal. Multi-operand contractions (comma) are excluded.
fn einsum_spec_is_single_diag(spec: &str) -> bool {
    let spec: String = spec.chars().filter(|c| !c.is_whitespace()).collect();
    if spec.contains(',') {
        return false;
    }
    let input = spec.split("->").next().unwrap_or("");
    let input = input.replace("...", ""); // ellipsis = broadcast dims, irrelevant to the repeat test
    if input.is_empty() || !input.bytes().all(|b| b.is_ascii_alphabetic()) {
        return false;
    }
    let mut seen = [false; 256];
    for &b in input.as_bytes() {
        if seen[b as usize] {
            return true; // a repeated input index -> diagonal-like
        }
        seen[b as usize] = true;
    }
    false
}

// True for a GENERALIZED OUTER product ("i,j,k->ijk", "ij,k->ijk", "ij,kl->ijkl"): every
// index appears exactly once across all operands (no contraction, no diagonal) and the output
// is all of them (no axis summed). The generic native kernel runs these 2-16x slower than
// numpy's optimized outer build, so delegate — EXCEPT the small all-vector 2-operand outer
// ("i,j->ij"), which WINS natively. Delegate when 3+ operands OR any operand has >=2 indices
// (i.e. a matrix/tensor operand -> large output where the native build loses).
fn einsum_spec_is_outer(spec: &str) -> bool {
    let spec: String = spec.chars().filter(|c| !c.is_whitespace()).collect();
    if spec.contains("...") {
        return false;
    }
    let Some((inp, out)) = spec.split_once("->") else {
        return false;
    };
    let groups: Vec<&str> = inp.split(',').collect();
    if groups.len() < 2 {
        return false; // single operand is not an outer product
    }
    // Keep the small all-single-char 2-operand outer ("i,j->ij") native (it wins); delegate
    // 3+ operands or any matrix/tensor operand (the slow large-output builds).
    if groups.len() < 3 && !groups.iter().any(|g| g.len() >= 2) {
        return false;
    }
    let inp_clean: String = groups.concat();
    if inp_clean.is_empty()
        || !inp_clean.bytes().all(|b| b.is_ascii_alphabetic())
        || !out.bytes().all(|b| b.is_ascii_alphabetic())
    {
        return false;
    }
    let mut in_seen = [false; 256];
    for &b in inp_clean.as_bytes() {
        if in_seen[b as usize] {
            return false; // a repeated index = contraction/diagonal, not a pure outer
        }
        in_seen[b as usize] = true;
    }
    let mut out_seen = [false; 256];
    for &b in out.as_bytes() {
        if !in_seen[b as usize] || out_seen[b as usize] {
            return false; // output label absent from input, or repeated
        }
        out_seen[b as usize] = true;
    }
    out.len() == inp_clean.len() // every index kept (none summed) = pure outer
}

// True for a 2-operand vector contraction the native kernel runs slowly: one operand is a
// vector (1 index) whose index is contracted (summed) against a matrix/tensor operand, EXCEPT
// the fast matvec-RIGHT case ("ij,j->i", contracting the matrix's LAST/contiguous axis — that
// WINS natively). Delegated: matvec-LEFT "i,ij->j" (first/strided axis, 6-7x) and tensor-vector
// "ijk,k->ij" (3-D+, 3-12x). Spec group lengths give operand ndims (no shapes needed). numpy's
// einsum reshapes these to a contiguous GEMV; fnp's generic kernel doesn't. (bead x6ndg.)
fn einsum_spec_is_slow_vector_contraction(spec: &str) -> bool {
    let spec: String = spec.chars().filter(|c| !c.is_whitespace()).collect();
    if spec.contains("...") {
        return false;
    }
    let Some((inp, out)) = spec.split_once("->") else {
        return false;
    };
    let groups: Vec<&str> = inp.split(',').collect();
    if groups.len() != 2
        || !groups
            .iter()
            .all(|g| g.bytes().all(|b| b.is_ascii_alphabetic()))
        || !out.bytes().all(|b| b.is_ascii_alphabetic())
    {
        return false;
    }
    // exactly one operand is a vector (one index); the other a matrix/tensor (>=2 indices)
    let (vec_i, mat_i) = if groups[0].len() == 1 && groups[1].len() >= 2 {
        (0, 1)
    } else if groups[1].len() == 1 && groups[0].len() >= 2 {
        (1, 0)
    } else {
        return false;
    };
    let vchar = groups[vec_i].as_bytes()[0];
    let mat = groups[mat_i].as_bytes();
    // the vector index must be contracted: present in the matrix operand, absent from output
    if !mat.contains(&vchar) || out.as_bytes().contains(&vchar) {
        return false;
    }
    // tensor-vector (matrix operand >=3-D) is always slow; a 2-D matvec is slow ONLY when the
    // contracted index is NOT the matrix's last axis (matvec-LEFT / strided). matvec-RIGHT
    // (last axis == vchar) wins natively and is kept.
    if mat.len() >= 3 {
        return true;
    }
    mat[mat.len() - 1] != vchar
}

// True for a 2-operand ELLIPSIS contraction that is NOT a GEMM ("i...,i...->..." 42x dot,
// "...ij,...j->...i" 3.2x batched-matvec). The ellipsis is a batch; strip it and inspect the
// per-batch operands: if either is a vector (<2 distinct indices) or a diagonal (repeated index),
// it's non-GEMM and the native kernel loses, so delegate. The ellipsis-batched-matmul case
// "...ij,...jk->...ik" (both per-batch operands 2 distinct indices) WINS natively and is kept. (x6ndg.)
fn einsum_spec_is_ellipsis_2op_nongemm(spec: &str) -> bool {
    let spec: String = spec.chars().filter(|c| !c.is_whitespace()).collect();
    if !spec.contains("...") {
        return false;
    }
    let Some((inp, _out)) = spec.split_once("->") else {
        return false; // implicit-output ellipsis: leave to the generic path
    };
    let groups: Vec<&str> = inp.split(',').collect();
    if groups.len() != 2 {
        return false;
    }
    for g in &groups {
        let core = g.replace("...", "");
        if !core.bytes().all(|b| b.is_ascii_alphabetic()) {
            return false; // unexpected form -> keep native
        }
        let mut seen = [false; 256];
        let mut distinct = 0usize;
        for &b in core.as_bytes() {
            if seen[b as usize] {
                return true; // diagonal operand -> non-GEMM
            }
            seen[b as usize] = true;
            distinct += 1;
        }
        if distinct < 2 {
            return true; // vector/scalar per-batch operand -> non-GEMM (batched matvec/dot)
        }
    }
    false // both per-batch operands are 2+ distinct indices: GEMM-shape, keep native
}

// True for a 2-operand contraction where some operand has a REPEATED index (a diagonal), e.g.
// "ii,jj->ij" (22x), "iij,jk->ik" (41x), "ij,jj->ij" (11x). A repeated index means the operand is
// a diagonal/trace, not a plain matrix, so the native kernel never hits matmul_accumulate and loses
// 10-41x to numpy. GEMM operands have all-distinct indices, so they are never caught. Single-operand
// diagonals are handled earlier (buffered view / single_diag). Ellipsis handled separately. (x6ndg.)
fn einsum_spec_is_diagonal_2op(spec: &str) -> bool {
    let spec: String = spec.chars().filter(|c| !c.is_whitespace()).collect();
    if spec.contains("...") {
        return false;
    }
    let Some((inp, _out)) = spec.split_once("->") else {
        return false;
    };
    let groups: Vec<&str> = inp.split(',').collect();
    if groups.len() != 2 {
        return false;
    }
    groups.iter().any(|g| {
        if !g.bytes().all(|b| b.is_ascii_alphabetic()) {
            return false;
        }
        let mut seen = [false; 256];
        for &b in g.as_bytes() {
            if seen[b as usize] {
                return true; // a repeated index within an operand = diagonal
            }
            seen[b as usize] = true;
        }
        false
    })
}

// True for a 2-operand BATCHED vector contraction ("bij,bj->bi", "bi,bij->bj", "bijk,bk->bij"):
// after removing the shared batch indices (present in both operands AND output), the per-batch
// op is a vector-vs-matrix/tensor contraction. The native kernel's per-batch loop runs these
// 3-12x slower than numpy (which batches the GEMV) — and UNLIKE the non-batched case, even the
// "last-axis" matvec loses once batched, so delegate regardless of contracted-axis position.
// Batched matmul/gram/full/row-reduce keep >=2-index reduced operands and are NOT caught (wins).
fn einsum_spec_is_batched_vector_contraction(spec: &str) -> bool {
    let spec: String = spec.chars().filter(|c| !c.is_whitespace()).collect();
    if spec.contains("...") {
        return false;
    }
    let Some((inp, out)) = spec.split_once("->") else {
        return false;
    };
    let groups: Vec<&str> = inp.split(',').collect();
    if groups.len() != 2 {
        return false;
    }
    let (g0, g1) = (groups[0].as_bytes(), groups[1].as_bytes());
    let outb = out.as_bytes();
    if !g0.iter().all(|b| b.is_ascii_alphabetic())
        || !g1.iter().all(|b| b.is_ascii_alphabetic())
        || !outb.iter().all(|b| b.is_ascii_alphabetic())
    {
        return false;
    }
    // batch index = present in op1 AND op2 AND output
    let is_batch = |c: u8| g0.contains(&c) && g1.contains(&c) && outb.contains(&c);
    let r0: Vec<u8> = g0.iter().copied().filter(|&c| !is_batch(c)).collect();
    let r1: Vec<u8> = g1.iter().copied().filter(|&c| !is_batch(c)).collect();
    if r0.len() == g0.len() {
        return false; // no batch index removed -> not a batched contraction
    }
    let rout: Vec<u8> = outb.iter().copied().filter(|&c| !is_batch(c)).collect();
    // one reduced operand is a vector (1 index), the other a matrix/tensor (>=2 indices)
    let (vec, mat) = if r0.len() == 1 && r1.len() >= 2 {
        (&r0, &r1)
    } else if r1.len() == 1 && r0.len() >= 2 {
        (&r1, &r0)
    } else {
        return false;
    };
    let v = vec[0];
    mat.contains(&v) && !rout.contains(&v) // the vector index is contracted (summed)
}

// True for a 2-operand contraction where the SECOND operand carries >=2 free indices (present
// in op2 and the output, absent from op1) over a contraction — e.g. "ij,bjk->bik" (free b,k).
// numpy reshapes op2's free dims into one and runs a single GEMM; fnp's native kernel does not
// reshape op2's multiple free dims and loops inefficiently (39x). The MIRROR "bij,jk->bik"
// (op1 carries the multiple free dims) reshapes fine and WINS, so this is intentionally
// asymmetric: only op2-multi-free is delegated. (bead x6ndg.)
fn einsum_spec_is_op2_multifree_contraction(spec: &str) -> bool {
    let spec: String = spec.chars().filter(|c| !c.is_whitespace()).collect();
    if spec.contains("...") {
        return false;
    }
    let Some((inp, out)) = spec.split_once("->") else {
        return false;
    };
    let groups: Vec<&str> = inp.split(',').collect();
    if groups.len() != 2 {
        return false;
    }
    let (g0, g1) = (groups[0].as_bytes(), groups[1].as_bytes());
    let outb = out.as_bytes();
    if !g0.iter().all(|b| b.is_ascii_alphabetic())
        || !g1.iter().all(|b| b.is_ascii_alphabetic())
        || !outb.iter().all(|b| b.is_ascii_alphabetic())
    {
        return false;
    }
    // a contracted index: in both operands, absent from output
    let has_contraction = g0.iter().any(|&c| g1.contains(&c) && !outb.contains(&c));
    if !has_contraction {
        return false; // pure outer / no contraction handled elsewhere
    }
    // op2-free indices: in op2 AND output, absent from op1
    let op2_free = outb
        .iter()
        .filter(|&&c| g1.contains(&c) && !g0.contains(&c))
        .count();
    op2_free >= 2
}

#[pyfunction]
#[pyo3(signature = (*args, **kwargs))]
fn einsum(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    // A single-operand pure label permutation is a transpose — numpy returns a
    // zero-copy writable view; match that exactly (and skip the materializing
    // kernel) before anything else.
    if let Some(view) = try_einsum_transpose_view(py, args, kwargs)? {
        return Ok(view);
    }
    if let Some(view) = try_buffered_f64_einsum_single_diagonal(py, args, kwargs)? {
        return Ok(view);
    }
    // Single-operand ELLIPSIS einsum: the native kernel handles ellipsis catastrophically slowly
    // — "...ij->...ji" (transpose) is 1000-5000x (numpy returns an O(1) view), "...ij->...i"/
    // "...ii->...i" (reduce/diagonal) 1.9-5.4x. No single-operand ellipsis form can hit a native
    // win, so delegate them all to numpy. (Multi-operand ellipsis is handled below / kept native
    // for the GEMM case.) (BlackThrush 2026-06-22.)
    if args.len() == 2
        && let Ok(spec) = args.get_item(0)?.extract::<String>()
        && spec.contains("...")
    {
        return core_numpy_passthrough(py, "einsum", args, kwargs);
    }
    // Single-operand reduction ("ijk->k") = sum over the dropped axes. Our generic
    // native kernel is 1.6-2.6x slower than numpy's optimized einsum reduction here
    // (which beats even np.sum-over-axes), so delegate this pattern for parity. The
    // winning two-operand contractions and the transpose/diagonal views are excluded.
    if args.len() == 2
        && let Ok(spec) = args.get_item(0)?.extract::<String>()
        && einsum_spec_is_single_reduce(&spec)
    {
        return core_numpy_passthrough(py, "einsum", args, kwargs);
    }
    // Single-operand diagonal extraction with a repeated index ("bii->bi", "...ii->...i",
    // "iij->ij", "ii"=trace) that the plain-"ii->i" fast path above misses: the generic
    // native kernel is 43-1339x slower than numpy's strided diagonal -> delegate for parity.
    if args.len() == 2
        && let Ok(spec) = args.get_item(0)?.extract::<String>()
        && einsum_spec_is_single_diag(&spec)
    {
        return core_numpy_passthrough(py, "einsum", args, kwargs);
    }
    // Generalized outer product ("i,j,k->ijk", "ij,k->ijk", "ij,kl->ijkl", no contraction):
    // the generic native kernel is 2-16x slower than numpy's optimized outer build. Delegate
    // (the small all-vector 2-op outer "i,j->ij" is kept native by the detector — it wins).
    // (BlackThrush 2026-06-22; cf single-reduce / single-diag delegates above.)
    if args.len() >= 3
        && let Ok(spec) = args.get_item(0)?.extract::<String>()
        && einsum_spec_is_outer(&spec)
    {
        return core_numpy_passthrough(py, "einsum", args, kwargs);
    }
    // 2-operand vector contraction the native kernel runs slowly (matvec-LEFT "i,ij->j" 6-7x,
    // tensor-vector "ijk,k->ij" 3-12x). The fast matvec-RIGHT "ij,j->i" is kept native by the
    // detector. (bead x6ndg, BlackThrush 2026-06-22.)
    if args.len() == 3
        && let Ok(spec) = args.get_item(0)?.extract::<String>()
        && einsum_spec_is_slow_vector_contraction(&spec)
    {
        return core_numpy_passthrough(py, "einsum", args, kwargs);
    }
    // Batched vector contraction ("bij,bj->bi" 4x, "bi,bij->bj" 8x, "bijk,bk->bij" 3x): the
    // per-batch GEMV loop loses to numpy's batched build. (bead x6ndg, BlackThrush 2026-06-22.)
    if args.len() == 3
        && let Ok(spec) = args.get_item(0)?.extract::<String>()
        && einsum_spec_is_batched_vector_contraction(&spec)
    {
        return core_numpy_passthrough(py, "einsum", args, kwargs);
    }
    // 2-operand contraction with a diagonal operand ("ii,jj->ij" 22x, "iij,jk->ik" 41x): a repeated
    // index makes the operand a diagonal -> never GEMM-able -> native kernel loses 10-41x. Delegate.
    // (bead x6ndg, BlackThrush 2026-06-23.)
    if args.len() == 3
        && let Ok(spec) = args.get_item(0)?.extract::<String>()
        && einsum_spec_is_diagonal_2op(&spec)
    {
        return core_numpy_passthrough(py, "einsum", args, kwargs);
    }
    // 2-operand ellipsis non-GEMM ("i...,i->..." dot 42x, "...ij,...j->...i" batched-matvec 3.2x):
    // ellipsis-batched-matmul stays native (wins). (bead x6ndg, BlackThrush 2026-06-23.)
    if args.len() == 3
        && let Ok(spec) = args.get_item(0)?.extract::<String>()
        && einsum_spec_is_ellipsis_2op_nongemm(&spec)
    {
        return core_numpy_passthrough(py, "einsum", args, kwargs);
    }
    // Second-operand multi-free contraction ("ij,bjk->bik" 39x): op2 carries >=2 free dims the
    // native kernel won't reshape into one GEMM. The op1-multi-free mirror "bij,jk->bik" WINS and
    // is kept native. (bead x6ndg, BlackThrush 2026-06-22.)
    if args.len() == 3
        && let Ok(spec) = args.get_item(0)?.extract::<String>()
        && einsum_spec_is_op2_multifree_contraction(&spec)
    {
        return core_numpy_passthrough(py, "einsum", args, kwargs);
    }
    // Route the common case (string subscripts, real-float operands, no special
    // kwargs) through our native UFuncArray::einsum — which sends GEMM-shaped
    // contractions through the cache-blocked, register-tiled matmul_accumulate —
    // instead of delegating to C-BLAS numpy (the NO-GAPS gap, bead 7put0). Fall
    // back to numpy for anything our kernel can't reproduce identically: integer/
    // complex operands, out=/dtype=/order=/casting= kwargs, the interleaved-list
    // subscript form, or any kernel error. Behavior parity stays absolute.
    // Our native kernel extracts every operand to f64, so its result is always float64.
    // numpy.einsum keeps the (promoted) input dtype: float32->float32, int*->int*, etc.
    // Decide from the ORIGINAL operand dtypes whether to (a) run native unchanged (all
    // promote to float64), (b) run native then cast the result to float32, or (c) defer to
    // numpy — for integer/bool (where einsum sums in the input dtype and WRAPS on overflow,
    // which f64-then-cast cannot reproduce) and float16 (whose accumulation precision the
    // f64 path would not match within tolerance).
    match einsum_operand_dtype_policy(py, args)? {
        EinsumDtypePolicy::Defer => {}
        EinsumDtypePolicy::Native => {
            if let Some(result) = einsum_native(py, args, kwargs)? {
                return Ok(result);
            }
        }
        EinsumDtypePolicy::CastFloat32 => {
            if let Some(result) = einsum_native(py, args, kwargs)? {
                return Ok(result
                    .bind(py)
                    .call_method1("astype", ("float32",))?
                    .unbind());
            }
        }
    }
    core_numpy_passthrough(py, "einsum", args, kwargs)
}

#[derive(Clone, Copy)]
enum EinsumDtypePolicy {
    /// All operands promote to float64 — run the native kernel as-is.
    Native,
    /// Result is float32 — run native (computing in f64) then cast the result to float32.
    CastFloat32,
    /// Integer/bool/float16/complex result — defer to numpy for exact dtype + overflow.
    Defer,
}

fn einsum_operand_dtype_policy(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
) -> PyResult<EinsumDtypePolicy> {
    // Only the string-subscript form (`einsum("ij,jk->ik", a, b, ...)`) has operands at
    // args[1..]; the interleaved-list form and empty calls fall through to einsum_native,
    // which returns None for them, so leaving them Native is harmless.
    if args.len() < 2 || args.get_item(0)?.extract::<String>().is_err() {
        return Ok(EinsumDtypePolicy::Native);
    }
    let numpy = py.import("numpy")?;
    let mut operand_arrays: Vec<Bound<'_, PyAny>> = Vec::with_capacity(args.len() - 1);
    let mut all_float64 = true;
    for i in 1..args.len() {
        let arr = numpy.call_method1("asarray", (&args.get_item(i)?,))?;
        let dtype = arr.getattr("dtype")?;
        let kind: String = dtype.getattr("kind")?.extract()?;
        let itemsize: usize = dtype.getattr("itemsize")?.extract()?;
        if kind != "f" || itemsize != 8 {
            all_float64 = false;
        }
        operand_arrays.push(arr);
    }
    if all_float64 {
        return Ok(EinsumDtypePolicy::Native);
    }
    let result_dtype = numpy
        .getattr("result_type")?
        .call(PyTuple::new(py, &operand_arrays)?, None)?;
    let kind: String = result_dtype.getattr("kind")?.extract()?;
    let itemsize: usize = result_dtype.getattr("itemsize")?.extract()?;
    Ok(match (kind.as_str(), itemsize) {
        ("f", 8) => EinsumDtypePolicy::Native,
        ("f", 4) => EinsumDtypePolicy::CastFloat32,
        _ => EinsumDtypePolicy::Defer,
    })
}

/// Native einsum fast path: returns `Some(result)` when the call is the common
/// real-float, string-subscripts form our kernel handles, else `None` (caller
/// falls back to numpy).
#[derive(Clone, Copy)]
enum EinsumSingleDiagonalKind {
    Trace,
    Diagonal,
}

#[derive(Clone, Copy)]
enum EinsumSingleReduction2dKind {
    All,
    KeepFirstLabel,
    KeepSecondLabel,
}

fn parse_single_operand_diagonal_einsum(subscripts: &str) -> Option<EinsumSingleDiagonalKind> {
    let compact = subscripts
        .chars()
        .filter(|c| !c.is_whitespace())
        .collect::<String>();
    if compact.contains(',') || compact.contains('.') {
        return None;
    }
    let (input, output) = compact
        .split_once("->")
        .map_or((compact.as_str(), None), |(inp, out)| (inp, Some(out)));
    let mut input_chars = input.chars();
    let label = input_chars.next()?;
    if !label.is_ascii_alphabetic()
        || input_chars.next() != Some(label)
        || input_chars.next().is_some()
    {
        return None;
    }
    match output {
        None | Some("") => Some(EinsumSingleDiagonalKind::Trace),
        Some(out) => {
            let mut output_chars = out.chars();
            if output_chars.next() == Some(label) && output_chars.next().is_none() {
                Some(EinsumSingleDiagonalKind::Diagonal)
            } else {
                None
            }
        }
    }
}

fn parse_single_operand_reduction_2d_einsum(
    subscripts: &str,
) -> Option<EinsumSingleReduction2dKind> {
    let compact = subscripts
        .chars()
        .filter(|c| !c.is_whitespace())
        .collect::<String>();
    if compact.contains(',') || compact.contains('.') {
        return None;
    }
    let (input, output) = compact.split_once("->")?;
    let labels: Vec<char> = input.chars().collect();
    if labels.len() != 2
        || labels[0] == labels[1]
        || !labels.iter().all(|c| c.is_ascii_alphabetic())
    {
        return None;
    }
    let out: Vec<char> = output.chars().collect();
    match out.as_slice() {
        [] => Some(EinsumSingleReduction2dKind::All),
        [c] if *c == labels[0] => Some(EinsumSingleReduction2dKind::KeepFirstLabel),
        [c] if *c == labels[1] => Some(EinsumSingleReduction2dKind::KeepSecondLabel),
        _ => None,
    }
}

fn einsum_kwargs_are_native_eligible(kwargs: Option<&Bound<'_, PyDict>>) -> PyResult<bool> {
    if let Some(kw) = kwargs {
        for key in kw.keys() {
            let name: String = key.extract()?;
            if name != "optimize" {
                return Ok(false);
            }
        }
    }
    Ok(true)
}

fn is_exact_numpy_ndarray(py: Python<'_>, value: &Bound<'_, PyAny>) -> PyResult<bool> {
    static NUMPY_NDARRAY_TYPE: PyOnceLock<Py<PyType>> = PyOnceLock::new();
    let ndarray_type = NUMPY_NDARRAY_TYPE.get_or_try_init(py, || -> PyResult<Py<PyType>> {
        let ty = py.import("numpy")?.getattr("ndarray")?;
        Ok(ty.cast_into::<PyType>()?.unbind())
    })?;
    Ok(value.get_type().is(ndarray_type.bind(py)))
}

fn build_f64_scalar(py: Python<'_>, value: f64) -> PyResult<Py<PyAny>> {
    static NUMPY_FLOAT64_TYPE: PyOnceLock<Py<PyType>> = PyOnceLock::new();
    let float64_type = NUMPY_FLOAT64_TYPE.get_or_try_init(py, || -> PyResult<Py<PyType>> {
        let ty = py.import("numpy")?.getattr("float64")?;
        Ok(ty.cast_into::<PyType>()?.unbind())
    })?;
    Ok(float64_type.bind(py).call1((value,))?.unbind())
}

fn try_buffered_f64_einsum_single_diagonal(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Option<Py<PyAny>>> {
    if args.len() != 2 || !einsum_kwargs_are_native_eligible(kwargs)? {
        return Ok(None);
    }
    let Ok(subscripts) = args.get_item(0)?.extract::<String>() else {
        return Ok(None);
    };
    let Some(kind) = parse_single_operand_diagonal_einsum(&subscripts) else {
        return Ok(None);
    };
    let operand = args.get_item(1)?;
    if !is_exact_numpy_ndarray(py, &operand)? {
        return Ok(None);
    }
    let Ok(buffer) = PyBuffer::<f64>::get(&operand) else {
        return Ok(None);
    };
    if buffer.dimensions() != 2 {
        return Ok(None);
    }
    let shape = buffer.shape();
    if shape[0] != shape[1] {
        return Ok(None);
    }

    match kind {
        EinsumSingleDiagonalKind::Diagonal => {
            let Ok(diag_view) = operand.call_method0(pyo3::intern!(py, "diagonal")) else {
                return Ok(None);
            };
            if !buffer.readonly() {
                let kwargs = PyDict::new(py);
                kwargs.set_item(pyo3::intern!(py, "write"), true)?;
                diag_view.call_method(pyo3::intern!(py, "setflags"), (), Some(&kwargs))?;
            }
            Ok(Some(diag_view.unbind()))
        }
        EinsumSingleDiagonalKind::Trace => {
            if !buffer.is_c_contiguous() {
                return Ok(None);
            }
            let Some(input) = buffer.as_slice(py) else {
                return Ok(None);
            };
            let n = shape[0];
            let stride = n + 1;
            let mut total = 0.0f64;
            for i in 0..n {
                total += input[i * stride].get();
            }
            Ok(Some(build_f64_scalar(py, total)?))
        }
    }
}

fn try_zerocopy_f64_einsum_trace_contiguous(
    py: Python<'_>,
    numpy: &Bound<'_, PyModule>,
    operand: &Bound<'_, PyAny>,
    n: usize,
) -> PyResult<Option<Py<PyAny>>> {
    let Some(expected_len) = n.checked_mul(n) else {
        return Ok(None);
    };
    let Ok(buffer) = PyBuffer::<f64>::get(operand) else {
        return Ok(None);
    };
    let Some(input) = buffer.as_slice(py) else {
        return Ok(None);
    };
    if input.len() != expected_len {
        return Ok(None);
    }
    let stride = n + 1;
    let mut total = 0.0f64;
    for i in 0..n {
        total += input[i * stride].get();
    }
    Ok(Some(numpy.getattr("float64")?.call1((total,))?.unbind()))
}

fn try_zerocopy_f64_einsum_single_diagonal(
    py: Python<'_>,
    subscripts: &str,
    operand: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let Some(kind) = parse_single_operand_diagonal_einsum(subscripts) else {
        return Ok(None);
    };
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !operand.is_exact_instance(&ndarray_type) || !numpy_dtype_is_f64(py, operand) {
        return Ok(None);
    }
    let Ok(shape) = operand
        .getattr("shape")
        .and_then(|shape| shape.extract::<Vec<usize>>())
    else {
        return Ok(None);
    };
    if shape.len() != 2 || shape[0] != shape[1] {
        return Ok(None);
    }
    match kind {
        EinsumSingleDiagonalKind::Diagonal => {
            let Ok(diag_view) = operand.call_method0("diagonal") else {
                return Ok(None);
            };
            let writeable = operand
                .getattr("flags")?
                .getattr("writeable")?
                .extract::<bool>()?;
            if writeable {
                let kwargs = PyDict::new(py);
                kwargs.set_item("write", true)?;
                diag_view.call_method("setflags", (), Some(&kwargs))?;
            }
            Ok(Some(diag_view.unbind()))
        }
        EinsumSingleDiagonalKind::Trace => {
            if let Some(result) =
                try_zerocopy_f64_einsum_trace_contiguous(py, &numpy, operand, shape[0])?
            {
                return Ok(Some(result));
            }
            let Ok(diag_view) = operand.call_method0("diagonal") else {
                return Ok(None);
            };
            let diag_array = match extract_precise_numeric_array(py, &diag_view, "einsum(diagonal)")
            {
                Ok(array) => array,
                Err(_) => return Ok(None),
            };
            let result = diag_array.sum_extracted_diagonal_to_scalar();
            Ok(Some(build_numpy_scalar_or_array(py, &result)?))
        }
    }
}

// Single-operand 2-D reductions ('ij->', 'ij->i', 'ij->j') are pure sums over
// dropped axes. The native fallback already recognizes these, but only after
// extracting the full operand into a UFuncArray. For large f64 ndarrays that copy
// dominates. This path reads an exact contiguous float64 ndarray through PyBuffer
// and streams the reduction directly; non-exact forms fall through unchanged.
fn try_zerocopy_f64_einsum_single_reduction_2d(
    py: Python<'_>,
    subscripts: &str,
    operand: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let Some(kind) = parse_single_operand_reduction_2d_einsum(subscripts) else {
        return Ok(None);
    };
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !operand.is_exact_instance(&ndarray_type) || !numpy_dtype_is_f64(py, operand) {
        return Ok(None);
    }
    let Ok(shape) = operand
        .getattr("shape")
        .and_then(|shape| shape.extract::<Vec<usize>>())
    else {
        return Ok(None);
    };
    if shape.len() != 2 {
        return Ok(None);
    }
    let (nrows, ncols) = (shape[0], shape[1]);
    let Some(expected_len) = nrows.checked_mul(ncols) else {
        return Ok(None);
    };
    let Ok(buffer) = PyBuffer::<f64>::get(operand) else {
        return Ok(None);
    };
    let Some(input) = buffer.as_slice(py) else {
        return Ok(None);
    };
    if input.len() != expected_len {
        return Ok(None);
    }

    let result = match kind {
        EinsumSingleReduction2dKind::All => {
            let mut acc = [0.0f64; 8];
            let mut chunks = input.chunks_exact(8);
            for group in chunks.by_ref() {
                acc[0] += group[0].get();
                acc[1] += group[1].get();
                acc[2] += group[2].get();
                acc[3] += group[3].get();
                acc[4] += group[4].get();
                acc[5] += group[5].get();
                acc[6] += group[6].get();
                acc[7] += group[7].get();
            }
            let mut sum = acc.iter().sum::<f64>();
            for value in chunks.remainder() {
                sum += value.get();
            }
            return Ok(Some(build_f64_scalar(py, sum)?));
        }
        EinsumSingleReduction2dKind::KeepFirstLabel => {
            if ncols == 0 {
                UFuncArray::new(vec![nrows], vec![0.0; nrows], DType::F64)
            } else {
                let mut out = Vec::with_capacity(nrows);
                for row in input.chunks_exact(ncols) {
                    let mut acc = [0.0f64; 8];
                    let mut chunks = row.chunks_exact(8);
                    for group in chunks.by_ref() {
                        acc[0] += group[0].get();
                        acc[1] += group[1].get();
                        acc[2] += group[2].get();
                        acc[3] += group[3].get();
                        acc[4] += group[4].get();
                        acc[5] += group[5].get();
                        acc[6] += group[6].get();
                        acc[7] += group[7].get();
                    }
                    let mut sum = acc.iter().sum::<f64>();
                    for value in chunks.remainder() {
                        sum += value.get();
                    }
                    out.push(sum);
                }
                UFuncArray::new(vec![nrows], out, DType::F64)
            }
        }
        EinsumSingleReduction2dKind::KeepSecondLabel => {
            let mut out = vec![0.0f64; ncols];
            if ncols != 0 {
                for row in input.chunks_exact(ncols) {
                    for (slot, value) in out.iter_mut().zip(row) {
                        *slot += value.get();
                    }
                }
            }
            UFuncArray::new(vec![ncols], out, DType::F64)
        }
    };
    let result = match result {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };
    Ok(Some(build_numpy_scalar_or_array(py, &result)?))
}

// Two-operand FULL contraction to a scalar: subscripts of the form 'L,L->' where the
// two operands carry the SAME distinct label string and the output is empty. Every axis
// is summed over matched indices, i.e. the Frobenius inner product Σ_k a_flat[k]·b_flat[k]
// (C-order flattening preserves the pairing). The general einsum kernel walks this with a
// Cartesian loop AND first copies both operands into UFuncArrays (extract_precise_numeric_
// array) — for a 1M-element pair that 16MB extraction alone dominates, leaving the op
// ~25x slower than numpy. Reading the two f64 buffers zero-copy and folding them in a
// single 8-accumulator pass skips the extraction entirely. einsum parity is tolerance-
// based (einsum_multi_operand_values_match_numpy_within_tolerance), so the strided
// 8-way accumulation order is fine. Repeated labels (diagonals/traces), ellipsis,
// transposed/mismatched label strings ('ij,ji->'), non-f64, non-contiguous, or unequal-
// shape operands all return None and fall through to the general kernel.
fn try_zerocopy_f64_einsum_full_contraction(
    py: Python<'_>,
    subscripts: &str,
    a: &Bound<'_, PyAny>,
    b: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let Some((inp, outp)) = subscripts.split_once("->") else {
        return Ok(None);
    };
    if !outp.trim().is_empty() {
        return Ok(None);
    }
    let parts: Vec<&str> = inp.trim().split(',').collect();
    if parts.len() != 2 {
        return Ok(None);
    }
    let (lhs, rhs) = (parts[0].trim(), parts[1].trim());
    if lhs.is_empty() || lhs != rhs || lhs.contains('.') {
        return Ok(None);
    }
    let labels: Vec<char> = lhs.chars().collect();
    if !labels.iter().all(|c| c.is_ascii_alphabetic()) {
        return Ok(None);
    }
    let mut seen = std::collections::HashSet::new();
    if !labels.iter().all(|c| seen.insert(*c)) {
        return Ok(None); // repeated label = diagonal/trace contraction, not a plain dot
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type)
        || !b.is_exact_instance(&ndarray_type)
        || !numpy_dtype_is_f64(py, a)
        || !numpy_dtype_is_f64(py, b)
    {
        return Ok(None);
    }
    let (Ok(sa), Ok(sb)) = (
        a.getattr("shape").and_then(|s| s.extract::<Vec<usize>>()),
        b.getattr("shape").and_then(|s| s.extract::<Vec<usize>>()),
    ) else {
        return Ok(None);
    };
    if sa != sb || sa.len() != labels.len() {
        return Ok(None);
    }
    let (Ok(ba), Ok(bb)) = (PyBuffer::<f64>::get(a), PyBuffer::<f64>::get(b)) else {
        return Ok(None);
    };
    let (Some(va), Some(vb)) = (ba.as_slice(py), bb.as_slice(py)) else {
        return Ok(None); // non-contiguous
    };
    if va.len() != vb.len() {
        return Ok(None);
    }
    // Eight independent accumulators break the single dependency chain so the fold is
    // load-throughput bound, not add-latency bound (the PyBuffer cells are !Sync, so a
    // single serial streaming pass is the contiguous read — matching numpy's bandwidth).
    let mut acc = [0.0f64; 8];
    let mut ca = va.chunks_exact(8);
    let mut cb = vb.chunks_exact(8);
    for (ga, gb) in ca.by_ref().zip(cb.by_ref()) {
        acc[0] += ga[0].get() * gb[0].get();
        acc[1] += ga[1].get() * gb[1].get();
        acc[2] += ga[2].get() * gb[2].get();
        acc[3] += ga[3].get() * gb[3].get();
        acc[4] += ga[4].get() * gb[4].get();
        acc[5] += ga[5].get() * gb[5].get();
        acc[6] += ga[6].get() * gb[6].get();
        acc[7] += ga[7].get() * gb[7].get();
    }
    let mut dot = acc.iter().sum::<f64>();
    for (x, y) in ca.remainder().iter().zip(cb.remainder()) {
        dot += x.get() * y.get();
    }
    let result = match UFuncArray::new(vec![], vec![dot], DType::F64) {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };
    Ok(Some(build_numpy_scalar_or_array(py, &result)?))
}

// Two-operand 2-D PARTIAL contraction keeping ONE axis: 'ij,ij->i' (out[i]=Σ_j a[i,j]·b[i,j],
// a row-wise fused dot) or 'ij,ij->j' (out[j]=Σ_i a[i,j]·b[i,j], a column-wise fused
// accumulate). Same motivation as the full-contraction sibling: the general kernel first
// copies both operands into UFuncArrays, so a 1M-element pair is ~16-28x slower than numpy.
// Reading the buffers zero-copy and fusing the multiply-reduce in one pass (no product
// materialization) matches numpy's streaming bandwidth. einsum parity is tolerance-based,
// so the per-output accumulation order is fine: the row form uses an 8-accumulator dot per
// row, the column form accumulates in row-ascending order per column. Non-2-D, transposed
// ('ij,ji->i'), repeated-label, non-f64, non-contiguous, or unequal-shape operands defer.
fn try_zerocopy_f64_einsum_pair_partial(
    py: Python<'_>,
    subscripts: &str,
    a: &Bound<'_, PyAny>,
    b: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let Some((inp, outp)) = subscripts.split_once("->") else {
        return Ok(None);
    };
    let parts: Vec<&str> = inp.trim().split(',').collect();
    if parts.len() != 2 {
        return Ok(None);
    }
    let (lhs, rhs, out) = (parts[0].trim(), parts[1].trim(), outp.trim());
    // Both operands carry the SAME distinct labels; output is a non-empty STRICT subset.
    if lhs.is_empty() || lhs != rhs || out.is_empty() || out.contains('.') {
        return Ok(None);
    }
    let labels: Vec<char> = lhs.chars().collect();
    let outc: Vec<char> = out.chars().collect();
    if !labels.iter().all(|c| c.is_ascii_alphabetic())
        || outc.len() >= labels.len()
        || labels.iter().collect::<std::collections::HashSet<_>>().len() != labels.len()
    {
        return Ok(None);
    }
    // Supported output shapes:
    //   PREFIX: out == labels[0..k] — keep the leading k axes, sum the trailing
    //     (contiguous) axes. out[g] = Σ_t a[g·block+t]·b[g·block+t], a contiguous
    //     block dot. Covers 'ij,ij->i', 'ijk,ijk->i', 'ijk,ijk->ij'.
    //   2-D SUFFIX: 'ij,ij->j' — keep the trailing axis, sum the leading (strided) one.
    let is_prefix = labels[..outc.len()] == outc[..];
    let is_2d_suffix = labels.len() == 2 && outc.len() == 1 && outc[0] == labels[1];
    if !is_prefix && !is_2d_suffix {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type)
        || !b.is_exact_instance(&ndarray_type)
        || !numpy_dtype_is_f64(py, a)
        || !numpy_dtype_is_f64(py, b)
    {
        return Ok(None);
    }
    let (Ok(sa), Ok(sb)) = (
        a.getattr("shape").and_then(|s| s.extract::<Vec<usize>>()),
        b.getattr("shape").and_then(|s| s.extract::<Vec<usize>>()),
    ) else {
        return Ok(None);
    };
    if sa.len() != labels.len() || sa != sb {
        return Ok(None);
    }
    let total: usize = sa.iter().product();
    let (Ok(ba), Ok(bb)) = (PyBuffer::<f64>::get(a), PyBuffer::<f64>::get(b)) else {
        return Ok(None);
    };
    let (Some(va), Some(vb)) = (ba.as_slice(py), bb.as_slice(py)) else {
        return Ok(None); // non-contiguous
    };
    if va.len() != total || vb.len() != total {
        return Ok(None);
    }
    // Contiguous-block 8-accumulator dot — bit-stable per block, allclose vs numpy.
    let block_dot = |ra: &[pyo3::buffer::ReadOnlyCell<f64>],
                     rb: &[pyo3::buffer::ReadOnlyCell<f64>]|
     -> f64 {
        let mut acc = [0.0f64; 8];
        let mut ca = ra.chunks_exact(8);
        let mut cb = rb.chunks_exact(8);
        for (ga, gb) in ca.by_ref().zip(cb.by_ref()) {
            acc[0] += ga[0].get() * gb[0].get();
            acc[1] += ga[1].get() * gb[1].get();
            acc[2] += ga[2].get() * gb[2].get();
            acc[3] += ga[3].get() * gb[3].get();
            acc[4] += ga[4].get() * gb[4].get();
            acc[5] += ga[5].get() * gb[5].get();
            acc[6] += ga[6].get() * gb[6].get();
            acc[7] += ga[7].get() * gb[7].get();
        }
        let mut s = acc.iter().sum::<f64>();
        for (x, y) in ca.remainder().iter().zip(cb.remainder()) {
            s += x.get() * y.get();
        }
        s
    };
    let (out_values, out_shape): (Vec<f64>, Vec<usize>) = if is_prefix {
        // Keep leading outc.len() axes; sum the trailing (contiguous) block.
        let n_groups: usize = sa[..outc.len()].iter().product();
        let block = if n_groups == 0 { 0 } else { total / n_groups };
        let vals = (0..n_groups)
            .map(|g| block_dot(&va[g * block..(g + 1) * block], &vb[g * block..(g + 1) * block]))
            .collect();
        (vals, sa[..outc.len()].to_vec())
    } else {
        // 2-D suffix 'ij,ij->j': out[j] = Σ_i a[i,j]·b[i,j] — stream rows into a
        // length-ncols accumulator (cache-resident); ascending-i order per column.
        let (nrows, ncols) = (sa[0], sa[1]);
        let mut out = vec![0.0f64; ncols];
        for i in 0..nrows {
            let ra = &va[i * ncols..(i + 1) * ncols];
            let rb = &vb[i * ncols..(i + 1) * ncols];
            for ((slot, x), y) in out.iter_mut().zip(ra).zip(rb) {
                *slot += x.get() * y.get();
            }
        }
        (out, vec![ncols])
    };
    let result = match UFuncArray::new(out_shape, out_values, DType::F64) {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };
    Ok(Some(build_numpy_scalar_or_array(py, &result)?))
}

// Two-operand OUTER product 'i,j->ij': out[i,j] = a[i]·b[j] from two 1-D operands,
// distinct labels, output = both in order. The general einsum kernel copies both
// operands then walks the Cartesian loop (~26x slower than numpy for a 1M output).
// The two input vectors are tiny, so copy them into Vecs (the only serial read of the
// !Sync PyBuffer cells) and fill the large output IN PARALLEL over rows — each output
// row i is `a[i]·b[..]`, a scalar·vector broadcast written to a disjoint slice. Pure
// product, no reduction, so parity is exact. Non-1-D, repeated labels, output not the
// in-order label pair, non-f64 or non-contiguous operands defer.
fn try_zerocopy_f64_einsum_outer_2vec(
    py: Python<'_>,
    subscripts: &str,
    a: &Bound<'_, PyAny>,
    b: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let Some((inp, outp)) = subscripts.split_once("->") else {
        return Ok(None);
    };
    let parts: Vec<&str> = inp.trim().split(',').collect();
    if parts.len() != 2 {
        return Ok(None);
    }
    let (lhs, rhs, out) = (parts[0].trim(), parts[1].trim(), outp.trim());
    // Two distinct single labels; output is exactly the two in input order.
    if lhs.len() != 1 || rhs.len() != 1 || lhs == rhs || out.len() != 2 {
        return Ok(None);
    }
    let li = lhs.chars().next().unwrap();
    let rj = rhs.chars().next().unwrap();
    let outc: Vec<char> = out.chars().collect();
    if !li.is_ascii_alphabetic() || !rj.is_ascii_alphabetic() || outc[0] != li || outc[1] != rj {
        return Ok(None);
    }
    // 'i,j->ij' with two 1-D operands is exactly np.outer(a, b). Delegate to the shared
    // f64 outer fast path, which fills the result DIRECTLY into the np.empty output buffer
    // (no intermediate Vec + build copy that the prior einsum-local fill incurred) and so
    // beats numpy. Require 1-D operands so the single-label semantics hold (np.outer would
    // ravel a higher-rank operand, which einsum 'i,j->ij' does not).
    let (Ok(sa), Ok(sb)) = (
        a.getattr("shape").and_then(|s| s.extract::<Vec<usize>>()),
        b.getattr("shape").and_then(|s| s.extract::<Vec<usize>>()),
    ) else {
        return Ok(None);
    };
    if sa.len() != 1 || sb.len() != 1 {
        return Ok(None);
    }
    try_zerocopy_f64_outer(py, a, b)
}

// Two-operand MATRIX·VECTOR contraction 'ij,j->i' (out[i] = Σ_j A[i,j]·v[j], a matvec)
// or its full reduction 'ij,j->' (Σ_ij A[i,j]·v[j], a scalar). The general einsum kernel
// copies both operands and walks the Cartesian loop — 'ij,j->' was ~12x slower than numpy,
// 'ij,j->i' ~2.7x. Here A's rows are contiguous, so each output is an 8-accumulator dot of
// row i against the (tiny, copied-once) vector v. The PyBuffer cells are !Sync so the scan
// is serial, but the 8 independent accumulators break the add-latency chain and the single
// streaming pass over A matches numpy's bandwidth. einsum parity is tolerance-based, so the
// per-output accumulation order is fine. The vector must match the SECOND (contiguous,
// contracted) matrix label; the 'ij,i->...' (strided row-contraction), repeated-label,
// non-2-D-matrix, non-f64, non-contiguous, or shape-mismatched forms defer.
fn try_zerocopy_f64_einsum_matvec(
    py: Python<'_>,
    subscripts: &str,
    a: &Bound<'_, PyAny>,
    b: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let Some((inp, outp)) = subscripts.split_once("->") else {
        return Ok(None);
    };
    let parts: Vec<&str> = inp.trim().split(',').collect();
    if parts.len() != 2 {
        return Ok(None);
    }
    let (lhs, rhs, out) = (parts[0].trim(), parts[1].trim(), outp.trim());
    if lhs.len() != 2 || rhs.len() != 1 {
        return Ok(None);
    }
    let labels: Vec<char> = lhs.chars().collect();
    if !labels.iter().all(|c| c.is_ascii_alphabetic()) || labels[0] == labels[1] {
        return Ok(None);
    }
    // The vector contracts one matrix axis: its label is either the SECOND (column,
    // contiguous → matvec A·v) or the FIRST (row, strided → vecmat Aᵀ·v) matrix label.
    let vc = rhs.chars().next();
    let contract_col = vc == Some(labels[1]);
    let contract_row = vc == Some(labels[0]);
    if !contract_col && !contract_row {
        return Ok(None);
    }
    // Output keeps the surviving label (matvec 'ij,j->i' keeps 'i'; vecmat 'ij,i->j'
    // keeps 'j') or is empty (full reduction to a scalar).
    let kept = if contract_col { labels[0] } else { labels[1] };
    let keep_axis = match out.len() {
        0 => false,
        1 if out.chars().next() == Some(kept) => true,
        _ => return Ok(None),
    };
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type)
        || !b.is_exact_instance(&ndarray_type)
        || !numpy_dtype_is_f64(py, a)
        || !numpy_dtype_is_f64(py, b)
    {
        return Ok(None);
    }
    let (Ok(sa), Ok(sb)) = (
        a.getattr("shape").and_then(|s| s.extract::<Vec<usize>>()),
        b.getattr("shape").and_then(|s| s.extract::<Vec<usize>>()),
    ) else {
        return Ok(None);
    };
    let (nrows, ncols) = if sa.len() == 2 { (sa[0], sa[1]) } else { return Ok(None) };
    // Vector length must match the contracted axis: column→ncols, row→nrows.
    let want_vlen = if contract_col { ncols } else { nrows };
    if sb.len() != 1 || sb[0] != want_vlen {
        return Ok(None);
    }
    let (Ok(ba), Ok(bv)) = (PyBuffer::<f64>::get(a), PyBuffer::<f64>::get(b)) else {
        return Ok(None);
    };
    let (Some(va), Some(vv)) = (ba.as_slice(py), bv.as_slice(py)) else {
        return Ok(None); // non-contiguous
    };
    if va.len() != nrows * ncols || vv.len() != want_vlen {
        return Ok(None);
    }
    // Copy the small vector out of the !Sync cells once; rows of A are read in place.
    let vvec: Vec<f64> = vv.iter().map(|c| c.get()).collect();
    let (out_values, out_shape): (Vec<f64>, Vec<usize>) = if contract_col {
        // matvec: each output is an 8-accumulator dot of a contiguous row against v.
        let row_dot = |row: &[pyo3::buffer::ReadOnlyCell<f64>]| -> f64 {
            let mut acc = [0.0f64; 8];
            let mut ca = row.chunks_exact(8);
            let mut cv = vvec.chunks_exact(8);
            for (gr, gv) in ca.by_ref().zip(cv.by_ref()) {
                acc[0] += gr[0].get() * gv[0];
                acc[1] += gr[1].get() * gv[1];
                acc[2] += gr[2].get() * gv[2];
                acc[3] += gr[3].get() * gv[3];
                acc[4] += gr[4].get() * gv[4];
                acc[5] += gr[5].get() * gv[5];
                acc[6] += gr[6].get() * gv[6];
                acc[7] += gr[7].get() * gv[7];
            }
            let mut s = acc.iter().sum::<f64>();
            for (x, y) in ca.remainder().iter().zip(cv.remainder()) {
                s += x.get() * y;
            }
            s
        };
        if keep_axis {
            ((0..nrows).map(|i| row_dot(&va[i * ncols..(i + 1) * ncols])).collect(), vec![nrows])
        } else {
            let mut total = 0.0f64;
            for i in 0..nrows {
                total += row_dot(&va[i * ncols..(i + 1) * ncols]);
            }
            (vec![total], vec![])
        }
    } else {
        // vecmat 'ij,i->j': out[j] = Σ_i A[i,j]·v[i]. Stream each row, fused multiply-add
        // of (row · v[i]) into the length-ncols accumulator (kept cache-resident), in
        // ascending-i order per column — the strided keep-column reduction done as one
        // contiguous pass over A instead of numpy's strided column gather (62x faster).
        let mut col = vec![0.0f64; ncols];
        for i in 0..nrows {
            let scale = vvec[i];
            let row = &va[i * ncols..(i + 1) * ncols];
            for (slot, x) in col.iter_mut().zip(row) {
                *slot += x.get() * scale;
            }
        }
        if keep_axis {
            (col, vec![ncols])
        } else {
            // 'ij,i->': sum the column accumulator (ascending-j) for the scalar.
            (vec![col.iter().sum::<f64>()], vec![])
        }
    };
    let result = match UFuncArray::new(out_shape, out_values, DType::F64) {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };
    Ok(Some(build_numpy_scalar_or_array(py, &result)?))
}

fn einsum_native(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Option<Py<PyAny>>> {
    if !einsum_kwargs_are_native_eligible(kwargs)? {
        // Only `optimize` is acceptable here; out=/dtype=/order=/casting= go to numpy.
        return Ok(None);
    }
    if let Some(kw) = kwargs {
        // Our native kernel does a single simultaneous multi-operand contraction
        // and does NOT optimize the pairwise contraction PATH. For >=3 operands
        // with `optimize` explicitly requested (True/'greedy'/'optimal'/a path
        // list), numpy's path optimizer + BLAS is orders of magnitude faster
        // (measured ~680x on 'ij,jk,kl->il'), so defer those to numpy. The default
        // optimize=False keeps our native kernel (which beats numpy's naive
        // default). The result is identical (same contraction, associativity
        // within float tolerance).
        if args.len() >= 4
            && let Some(opt) = kw.get_item("optimize")?
            && !opt.is_none()
            && opt.is_truthy()?
        {
            return Ok(None);
        }
    }
    if args.len() < 2 {
        return Ok(None);
    }
    let subscripts: String = match args.get_item(0)?.extract() {
        Ok(s) => s,
        Err(_) => return Ok(None),
    };
    if args.len() == 2
        && let Some(result) =
            try_zerocopy_f64_einsum_single_diagonal(py, &subscripts, &args.get_item(1)?)?
    {
        return Ok(Some(result));
    }
    if args.len() == 2
        && let Some(result) = try_zerocopy_f64_einsum_single_reduction_2d(
            py,
            &subscripts,
            &args.get_item(1)?,
        )?
    {
        return Ok(Some(result));
    }
    // Two-operand FULL contraction to a scalar ('ij,ij->', 'i,i->', 'abc,abc->'):
    // run BEFORE the per-operand UFuncArray extraction (which copies both inputs),
    // reading the buffers zero-copy. See the helper for the parity rationale.
    if args.len() == 3
        && let Some(result) = try_zerocopy_f64_einsum_full_contraction(
            py,
            &subscripts,
            &args.get_item(1)?,
            &args.get_item(2)?,
        )?
    {
        return Ok(Some(result));
    }
    // Two-operand 2-D partial contraction keeping one axis ('ij,ij->i' / 'ij,ij->j'):
    // also zero-copy, before the extraction that otherwise dominates.
    if args.len() == 3
        && let Some(result) = try_zerocopy_f64_einsum_pair_partial(
            py,
            &subscripts,
            &args.get_item(1)?,
            &args.get_item(2)?,
        )?
    {
        return Ok(Some(result));
    }
    // Two-operand outer product ('i,j->ij'): copy the small vectors, fill in parallel.
    if args.len() == 3
        && let Some(result) = try_zerocopy_f64_einsum_outer_2vec(
            py,
            &subscripts,
            &args.get_item(1)?,
            &args.get_item(2)?,
        )?
    {
        return Ok(Some(result));
    }
    // Two-operand matrix·vector contraction ('ij,j->i' / 'ij,j->'): zero-copy fused scan.
    if args.len() == 3
        && let Some(result) = try_zerocopy_f64_einsum_matvec(
            py,
            &subscripts,
            &args.get_item(1)?,
            &args.get_item(2)?,
        )?
    {
        return Ok(Some(result));
    }
    let mut operands: Vec<UFuncArray> = Vec::with_capacity(args.len() - 1);
    for i in 1..args.len() {
        let item = args.get_item(i)?;
        let arr = match extract_precise_numeric_array(py, &item, "einsum") {
            Ok(a) => a,
            Err(_) => return Ok(None),
        };
        if arr.has_integer_sidecar() || matches!(arr.dtype(), DType::Complex64 | DType::Complex128)
        {
            return Ok(None);
        }
        operands.push(arr);
    }
    // Single-operand pure-reduction fast path ('ij->i', 'ij->j', 'ijk->ik',
    // 'ij->', ...): the output labels are an in-order subsequence of the (all
    // distinct) input labels, so the call just sums the dropped axes. numpy
    // itself treats this as a plain reduction (np.einsum('ij->j', a) ==
    // np.sum(a, axis=0)); routing to reduce_sum_axes skips the general einsum
    // kernel, which was ~19x slower than numpy for a pure row/col reduction.
    // Transposes (output not in input order), diagonals/traces (repeated input
    // labels), ellipsis, implicit-mode (no '->'), and multi-operand contractions
    // all fall through to the existing kernel. Float-tolerance identical (same
    // summed values), matching how numpy's float einsum is conformance-checked.
    if operands.len() == 1
        && let Some((inp, outp)) = subscripts.split_once("->")
    {
        let inp = inp.trim();
        let outp = outp.trim();
        let op = &operands[0];
        let inb: Vec<char> = inp.chars().collect();
        let oub: Vec<char> = outp.chars().collect();
        let distinct = |s: &[char]| {
            s.iter()
                .collect::<std::collections::HashSet<_>>()
                .len()
                == s.len()
        };
        if op.dtype() == DType::F64
            && !inp.contains('.')
            && !outp.contains('.')
            && inb.iter().all(|c| c.is_ascii_alphabetic())
            && oub.iter().all(|c| c.is_ascii_alphabetic())
            && inb.len() == op.shape().len()
            && distinct(&inb)
            && distinct(&oub)
        {
            // Output must be an in-order subsequence of the input labels.
            let mut last_pos: isize = -1;
            let mut subseq_ok = true;
            for &c in &oub {
                match inb.iter().position(|&x| x == c) {
                    Some(p) if (p as isize) > last_pos => last_pos = p as isize,
                    _ => {
                        subseq_ok = false;
                        break;
                    }
                }
            }
            if subseq_ok {
                let dropped: Vec<isize> = inb
                    .iter()
                    .enumerate()
                    .filter(|(_, c)| !oub.contains(c))
                    .map(|(i, _)| i as isize)
                    .collect();
                if !dropped.is_empty()
                    && let Ok(result) = op.reduce_sum_axes(&dropped, false)
                {
                    return Ok(Some(build_numpy_scalar_or_array(py, &result)?));
                }
            }
        }
    }
    let refs: Vec<&UFuncArray> = operands.iter().collect();
    match UFuncArray::einsum(&subscripts, &refs) {
        Ok(result) => Ok(Some(build_numpy_scalar_or_array(py, &result)?)),
        Err(_) => Ok(None),
    }
}

// Parallel flat f64 np.unique(ar): numpy flattens then returns SORTED DISTINCT values — a
// deterministic output, so a parallel sort + dedup is unconditionally bit-identical (unlike
// argsort, no tie ambiguity). numpy.unique is single-threaded sort+dedup; the native path
// here extracted a UFuncArray copy then sorted serially. Read the borrowed buffer (any
// C-contiguous shape -> flat, matching numpy's flatten), rayon par_sort, Vec::dedup, copy
// the distinct values into a right-sized numpy.empty. Defers (Ok(None)) for: not exact
// C-contiguous f64, below the crossover, or ANY NaN (numpy collapses multiple NaN to one at
// the end — a special case — and partial_cmp has no total order with NaN).
fn try_zerocopy_f64_unique_flat(
    py: Python<'_>,
    item: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    if !item.is_exact_instance(&numpy.getattr("ndarray")?) || !numpy_dtype_is_f64(py, item) {
        return Ok(None);
    }
    if !item.getattr("flags")?.getattr("c_contiguous")?.extract::<bool>()? {
        return Ok(None);
    }
    let Ok(buffer) = PyBuffer::<f64>::get(item) else {
        return Ok(None);
    };
    let Some(cells) = buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = cells.len();
    const UNIQUE_PARALLEL_MIN: usize = 1 << 20;
    if n < UNIQUE_PARALLEL_MIN || rayon::current_num_threads() < 2 {
        return Ok(None);
    }
    use rayon::prelude::*;
    // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64; read-only under the GIL.
    let data: &[f64] = unsafe { std::slice::from_raw_parts(cells.as_ptr().cast::<f64>(), n) };
    if data.par_iter().any(|v| v.is_nan()) {
        return Ok(None);
    }
    let mut sorted: Vec<f64> = data.to_vec();
    sorted.par_sort_unstable_by(|x, y| x.partial_cmp(y).expect("no NaN after check"));
    sorted.dedup(); // sorted -> equal values are consecutive; == collapses them (incl -0.0/0.0)
    let m = sorted.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let out = numpy.call_method("empty", (m,), Some(&kwargs))?;
    if m > 0 {
        let out_buffer = PyBuffer::<f64>::get(&out)?;
        let Some(out_cells) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // SAFETY: fresh numpy.empty buffer we own (no alias).
        let dst: &mut [f64] =
            unsafe { std::slice::from_raw_parts_mut(out_cells.as_ptr() as *mut f64, m) };
        dst.copy_from_slice(&sorted);
    }
    Ok(Some(out.unbind()))
}

// Set / shortcut helpers
#[pyfunction]
#[pyo3(signature = (*args, **kwargs))]
fn unique(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    // Fast path for simple single-arg calls
    if kwargs.is_none_or(|k| k.is_empty()) && args.len() == 1 {
        let item = args.get_item(0)?;
        // Counting-sort dedup for small-range integers — O(n+range) beats the sort
        // path (and numpy) for narrow widths and tight value ranges.
        if let Some(out) = try_zerocopy_int_unique(py, &item)? {
            return Ok(out);
        }
        // Parallel sort+dedup for large flat f64 (deterministic output -> bit-exact).
        if let Some(out) = try_zerocopy_f64_unique_flat(py, &item)? {
            return Ok(out);
        }
        // f64 that didn't take the parallel path (sub-1<<20, NaN, or non-contiguous):
        // numpy's sort+dedup beats our native extract+serial across the whole medium range
        // (measured 1.1-2.4x at 50K-512K), so delegate. int/other dtypes fall through to the
        // native path unchanged below.
        if is_exact_numpy_ndarray(py, &item)? && numpy_dtype_is_f64(py, &item) {
            return core_numpy_passthrough(py, "unique", args, kwargs);
        }
        // NumPy's unique preserves the input dtype exactly; our native kernel
        // canonicalizes narrow ints/floats (int32 -> int64, float32 -> float64),
        // so defer any non-canonical width to NumPy.
        if !numpy_dtype_native_roundtrip_preserves(py, &item) {
            return core_numpy_passthrough(py, "unique", args, kwargs);
        }
        let arr = match extract_numeric_array(py, &item, "unique(ar)") {
            Ok(a) => a,
            Err(_) => return core_numpy_passthrough(py, "unique", args, kwargs),
        };
        if arr.has_integer_sidecar() {
            return core_numpy_passthrough(py, "unique", args, kwargs);
        }
        let result = arr.unique();
        return build_numpy_array_from_ufunc(py, &result);
    }
    // Counting-sort path for return_index/return_inverse/return_counts on a
    // small-range integer array — numpy is sort-based (O(n log n)) here too, so
    // these defer to numpy at parity; the counting pass yields all three outputs
    // O(n+range). Only engage when the sole kwargs are those three flags (axis,
    // equal_nan, or anything else defers).
    if args.len() == 1
        && let Some(kw) = kwargs
        && !kw.is_empty()
    {
        let mut allowed_only = true;
        let (mut ri, mut rinv, mut rc) = (false, false, false);
        for (k, v) in kw.iter() {
            match k.extract::<String>()?.as_str() {
                "return_index" => ri = v.extract()?,
                "return_inverse" => rinv = v.extract()?,
                "return_counts" => rc = v.extract()?,
                _ => allowed_only = false,
            }
        }
        if allowed_only && (ri || rinv || rc) {
            let item = args.get_item(0)?;
            if let Some(out) = try_zerocopy_int_unique_full(py, &item, ri, rinv, rc)? {
                return Ok(out);
            }
        }
    }
    core_numpy_passthrough(py, "unique", args, kwargs)
}

// Counting-sort dedup core for np.unique over a small-range integer array. numpy
// (and our native kernel) sort then dedup — O(n log n). When the value range is
// small a bitset pass is O(n + range): mark each value's bucket, then collect set
// buckets in ascending order, which yields the sorted unique values directly.
// Integer bit-equality is value-equality so this is bit-exact. `widen`/`narrow`
// convert T to/from i128 for offset arithmetic (handles negative mins and the
// full u64 range). Returns None for an empty array or a range too large to be
// worth (or fit) a bucket array, so the caller keeps the sort path.
fn unique_counting_typed<'py, T: pyo3::buffer::Element + Copy>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    item: &Bound<'py, PyAny>,
    dtype_name: &str,
    widen: fn(T) -> i128,
    narrow: fn(i128) -> T,
) -> PyResult<Option<Bound<'py, PyAny>>> {
    let Ok(buf) = PyBuffer::<T>::get(item) else {
        return Ok(None);
    };
    let Some(s) = buf.as_slice(py) else {
        return Ok(None);
    };
    let n = s.len();
    if n == 0 {
        return Ok(None); // empty → let the existing path return the right empty array
    }
    let mut mn = widen(s[0].get());
    let mut mx = mn;
    for c in s.iter() {
        let x = widen(c.get());
        if x < mn {
            mn = x;
        }
        if x > mx {
            mx = x;
        }
    }
    let range = (mx - mn) as u128;
    // Use counting only when the bucket array is both worth it (range within a
    // small multiple of n) and memory-bounded; otherwise defer to the sort path
    // (which already beats numpy for wide ranges).
    let cap = (4u128 * n as u128).max(1 << 16);
    if range >= cap || range >= (1 << 26) {
        return Ok(None);
    }
    let size = range as usize + 1;
    let mut seen = vec![false; size];
    for c in s.iter() {
        seen[(widen(c.get()) - mn) as usize] = true;
    }
    let count = seen.iter().filter(|&&b| b).count();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", dtype_name)?;
    let out = numpy.call_method("empty", (count,), Some(&kwargs))?;
    if count > 0 {
        let Ok(obuf) = PyBuffer::<T>::get(&out) else {
            return Ok(None);
        };
        let Some(output) = obuf.as_mut_slice(py) else {
            return Ok(None);
        };
        let mut w = 0usize;
        for (i, &b) in seen.iter().enumerate() {
            if b {
                output[w].set(narrow(mn + i as i128));
                w += 1;
            }
        }
    }
    Ok(Some(out))
}

// Zero-copy np.unique(ar) for a small-range integer array via counting-sort dedup
// (O(n+range) vs the sort path's O(n log n)). Gated to a C-contiguous integer
// ndarray; dispatched by (kind, itemsize). Wide ranges / non-contiguous / empty
// inputs return None so the caller keeps the existing sort path.
fn try_zerocopy_int_unique(
    py: Python<'_>,
    item: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !item.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    if !item
        .getattr("flags")?
        .getattr("c_contiguous")?
        .extract::<bool>()?
    {
        return Ok(None);
    }
    let dtype = item.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    let out = match (kind.as_str(), itemsize) {
        ("i", 1) => {
            unique_counting_typed::<i8>(py, &numpy, item, "int8", |x| x as i128, |v| v as i8)?
        }
        ("i", 2) => {
            unique_counting_typed::<i16>(py, &numpy, item, "int16", |x| x as i128, |v| v as i16)?
        }
        ("i", 4) => {
            unique_counting_typed::<i32>(py, &numpy, item, "int32", |x| x as i128, |v| v as i32)?
        }
        ("i", 8) => {
            unique_counting_typed::<i64>(py, &numpy, item, "int64", |x| x as i128, |v| v as i64)?
        }
        ("u", 1) => {
            unique_counting_typed::<u8>(py, &numpy, item, "uint8", |x| x as i128, |v| v as u8)?
        }
        ("u", 2) => {
            unique_counting_typed::<u16>(py, &numpy, item, "uint16", |x| x as i128, |v| v as u16)?
        }
        ("u", 4) => {
            unique_counting_typed::<u32>(py, &numpy, item, "uint32", |x| x as i128, |v| v as u32)?
        }
        ("u", 8) => {
            unique_counting_typed::<u64>(py, &numpy, item, "uint64", |x| x as i128, |v| v as u64)?
        }
        _ => return Ok(None),
    };
    Ok(out.map(|o| o.unbind()))
}

// Counting-sort core for np.unique with return_index/return_inverse/return_counts.
// One mark pass over the small-range integer array records, per bucket, presence,
// the first-occurrence index, and the tally; the ascending bucket walk then yields
// the sorted unique values plus the matching first-index and count arrays in one
// sweep (O(n+range) vs numpy's O(n log n) sort). return_inverse builds a
// bucket→rank map during that walk and remaps the input in a second O(n) pass.
// All auxiliary outputs are intp (int64); inverse is reshaped to the input shape.
// Returns the requested components in numpy's order; None (caller defers) for an
// empty array or a range too large to bucket.
#[allow(clippy::too_many_arguments, clippy::type_complexity)]
fn unique_counting_full_typed<'py, T: pyo3::buffer::Element + Copy>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    item: &Bound<'py, PyAny>,
    dtype_name: &str,
    widen: fn(T) -> i128,
    narrow: fn(i128) -> T,
    want_index: bool,
    want_inverse: bool,
    want_counts: bool,
) -> PyResult<
    Option<(
        Bound<'py, PyAny>,
        Option<Bound<'py, PyAny>>,
        Option<Bound<'py, PyAny>>,
        Option<Bound<'py, PyAny>>,
    )>,
> {
    let Ok(buf) = PyBuffer::<T>::get(item) else {
        return Ok(None);
    };
    let Some(s) = buf.as_slice(py) else {
        return Ok(None);
    };
    let n = s.len();
    if n == 0 {
        return Ok(None);
    }
    let mut mn = widen(s[0].get());
    let mut mx = mn;
    for c in s.iter() {
        let x = widen(c.get());
        if x < mn {
            mn = x;
        }
        if x > mx {
            mx = x;
        }
    }
    let range = (mx - mn) as u128;
    let cap = (4u128 * n as u128).max(1 << 16);
    if range >= cap || range >= (1 << 26) {
        return Ok(None);
    }
    let size = range as usize + 1;
    let mut seen = vec![false; size];
    let mut first_idx = if want_index { vec![0i64; size] } else { Vec::new() };
    let mut counts = if want_counts || want_inverse {
        vec![0i64; size]
    } else {
        Vec::new()
    };
    for (i, c) in s.iter().enumerate() {
        let off = (widen(c.get()) - mn) as usize;
        if !seen[off] {
            seen[off] = true;
            if want_index {
                first_idx[off] = i as i64;
            }
        }
        if want_counts || want_inverse {
            counts[off] += 1;
        }
    }
    // Ascending bucket walk → sorted unique values + aligned aux arrays.
    let mut uvals: Vec<i128> = Vec::new();
    let mut idxv: Vec<i64> = Vec::new();
    let mut cntv: Vec<i64> = Vec::new();
    let mut rank = if want_inverse { vec![0i64; size] } else { Vec::new() };
    let mut w: i64 = 0;
    for (i, &b) in seen.iter().enumerate() {
        if b {
            uvals.push(mn + i as i128);
            if want_index {
                idxv.push(first_idx[i]);
            }
            if want_counts {
                cntv.push(counts[i]);
            }
            if want_inverse {
                rank[i] = w;
            }
            w += 1;
        }
    }
    let count = uvals.len();
    // Build the unique-values array in the input dtype.
    let ukw = PyDict::new(py);
    ukw.set_item("dtype", dtype_name)?;
    let uarr = numpy.call_method("empty", (count,), Some(&ukw))?;
    {
        let Ok(ub) = PyBuffer::<T>::get(&uarr) else {
            return Ok(None);
        };
        let Some(uout) = ub.as_mut_slice(py) else {
            return Ok(None);
        };
        for (o, &v) in uout.iter().zip(uvals.iter()) {
            o.set(narrow(v));
        }
    }
    // Helper: build an intp array from a Vec<i64>.
    let build_i64 = |data: &[i64]| -> PyResult<Option<Bound<'py, PyAny>>> {
        let kw = PyDict::new(py);
        kw.set_item("dtype", "intp")?;
        let arr = numpy.call_method("empty", (data.len(),), Some(&kw))?;
        let Ok(ab) = PyBuffer::<i64>::get(&arr) else {
            return Ok(None);
        };
        let Some(aout) = ab.as_mut_slice(py) else {
            return Ok(None);
        };
        for (o, &v) in aout.iter().zip(data.iter()) {
            o.set(v);
        }
        Ok(Some(arr))
    };
    let index_arr = if want_index {
        match build_i64(&idxv)? {
            Some(a) => Some(a),
            None => return Ok(None),
        }
    } else {
        None
    };
    let counts_arr = if want_counts {
        match build_i64(&cntv)? {
            Some(a) => Some(a),
            None => return Ok(None),
        }
    } else {
        None
    };
    let inverse_arr = if want_inverse {
        let kw = PyDict::new(py);
        kw.set_item("dtype", "intp")?;
        let inv = numpy.call_method("empty", (n,), Some(&kw))?;
        {
            let Ok(ib) = PyBuffer::<i64>::get(&inv) else {
                return Ok(None);
            };
            let Some(iout) = ib.as_mut_slice(py) else {
                return Ok(None);
            };
            for (o, c) in iout.iter().zip(s.iter()) {
                o.set(rank[(widen(c.get()) - mn) as usize]);
            }
        }
        // numpy (>=2.0) reshapes inverse to the input shape.
        let shape: Vec<usize> = item.getattr("shape")?.extract()?;
        let output_shape = PyTuple::new(py, shape.iter().copied())?;
        Some(inv.call_method1("reshape", (&output_shape,))?)
    } else {
        None
    };
    Ok(Some((uarr, index_arr, inverse_arr, counts_arr)))
}

// Zero-copy np.unique(ar, return_index/inverse/counts=...) for small-range
// integers. Dispatches the counting core by (kind, itemsize) and assembles the
// requested outputs in numpy's order: unique, [index], [inverse], [counts].
fn try_zerocopy_int_unique_full(
    py: Python<'_>,
    item: &Bound<'_, PyAny>,
    want_index: bool,
    want_inverse: bool,
    want_counts: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !item.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    if !item
        .getattr("flags")?
        .getattr("c_contiguous")?
        .extract::<bool>()?
    {
        return Ok(None);
    }
    let dtype = item.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    macro_rules! run {
        ($t:ty, $name:expr, $narrow:expr) => {
            unique_counting_full_typed::<$t>(
                py,
                &numpy,
                item,
                $name,
                |x| x as i128,
                $narrow,
                want_index,
                want_inverse,
                want_counts,
            )?
        };
    }
    let parts = match (kind.as_str(), itemsize) {
        ("i", 1) => run!(i8, "int8", |v| v as i8),
        ("i", 2) => run!(i16, "int16", |v| v as i16),
        ("i", 4) => run!(i32, "int32", |v| v as i32),
        ("i", 8) => run!(i64, "int64", |v| v as i64),
        ("u", 1) => run!(u8, "uint8", |v| v as u8),
        ("u", 2) => run!(u16, "uint16", |v| v as u16),
        ("u", 4) => run!(u32, "uint32", |v| v as u32),
        ("u", 8) => run!(u64, "uint64", |v| v as u64),
        _ => return Ok(None),
    };
    let Some((uarr, index_arr, inverse_arr, counts_arr)) = parts else {
        return Ok(None);
    };
    // Assemble in numpy's fixed order: unique, [index], [inverse], [counts].
    let mut outputs: Vec<Bound<'_, PyAny>> = vec![uarr];
    if let Some(a) = index_arr {
        outputs.push(a);
    }
    if let Some(a) = inverse_arr {
        outputs.push(a);
    }
    if let Some(a) = counts_arr {
        outputs.push(a);
    }
    Ok(Some(PyTuple::new(py, outputs)?.into_any().unbind()))
}

#[pyfunction]
#[pyo3(signature = (*args, **kwargs))]
fn concat(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    // `concat` is the array-API alias of `concatenate` (numpy.concat IS
    // numpy.concatenate, incl axis=None flattening). The old native path extracted
    // every operand + ran UFuncArray::concatenate + build — three full copies vs
    // numpy's one (~23x slower at 4M). Reuse `concatenate`'s zero-copy byte-concat
    // fast path (which already BEATS numpy ~0.89x) and its exact numpy fallback.
    concatenate(py, args, kwargs)
}

#[pyfunction]
#[pyo3(signature = (x, out=None, **kwargs))]
fn conj(
    py: Python<'_>,
    x: Py<PyAny>,
    out: Option<Py<PyAny>>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    // Delegate to NumPy to preserve scalar return type for scalar inputs.
    let numpy = py.import("numpy")?;
    let call_kwargs = PyDict::new(py);
    if let Some(out_val) = out {
        call_kwargs.set_item("out", out_val.bind(py))?;
    }
    if let Some(kw) = kwargs {
        for (key, value) in kw.iter() {
            call_kwargs.set_item(key, value)?;
        }
    }
    Ok(numpy
        .getattr("conj")?
        .call((x.bind(py),), Some(&call_kwargs))?
        .unbind())
}

