/// Returns `true` only when `value`'s NumPy dtype is exactly `float64`. Used to
/// gate f64-only native kernels (e.g. divmod) that would otherwise widen integer
/// or narrow-float inputs and diverge from NumPy's output dtype. Any extraction
/// error is treated as "not float64".
fn numpy_dtype_is_f64(py: Python<'_>, value: &Bound<'_, PyAny>) -> bool {
    let probe = || -> PyResult<bool> {
        let numpy = py.import("numpy")?;
        let array = numpy.call_method1("asarray", (value,))?;
        let dtype = array.getattr("dtype")?;
        let kind: String = dtype.getattr("kind")?.extract()?;
        let itemsize: usize = dtype.getattr("itemsize")?.extract()?;
        Ok(kind == "f" && itemsize == 8)
    };
    probe().unwrap_or(false)
}

fn numpy_dtype_is_f32(value: &Bound<'_, PyAny>) -> bool {
    let probe = || -> PyResult<bool> {
        let dtype = value.getattr("dtype")?;
        let kind: String = dtype.getattr("kind")?.extract()?;
        let itemsize: usize = dtype.getattr("itemsize")?.extract()?;
        Ok(kind == "f" && itemsize == 4)
    };
    probe().unwrap_or(false)
}

fn numpy_dtype_is_f16(value: &Bound<'_, PyAny>) -> bool {
    let probe = || -> PyResult<bool> {
        let dtype = value.getattr("dtype")?;
        let kind: String = dtype.getattr("kind")?.extract()?;
        let itemsize: usize = dtype.getattr("itemsize")?.extract()?;
        Ok(kind == "f" && itemsize == 2)
    };
    probe().unwrap_or(false)
}

// True for a complex64/complex128 ndarray (dtype kind 'c'). Any extraction error
// (non-ndarray, missing dtype) is treated as "not complex".
fn numpy_dtype_is_complex(value: &Bound<'_, PyAny>) -> bool {
    let probe = || -> PyResult<bool> {
        let dtype = value.getattr("dtype")?;
        let kind: String = dtype.getattr("kind")?.extract()?;
        Ok(kind == "c")
    };
    probe().unwrap_or(false)
}

fn try_zerocopy_unicode_ascii_case(
    py: Python<'_>,
    input: &Bound<'_, PyAny>,
    method: &str,
) -> PyResult<Option<Py<PyAny>>> {
    if !matches!(method, "upper" | "lower" | "swapcase") {
        return Ok(None); // unknown op -> delegate to numpy
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !input.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = input.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "U" {
        return Ok(None);
    }
    if !input
        .getattr("flags")?
        .getattr("c_contiguous")?
        .extract::<bool>()?
    {
        return Ok(None);
    }

    let uint32_dtype = numpy.getattr("uint32")?;
    let codepoints = input.call_method1("view", (&uint32_dtype,))?;
    let Ok(in_buffer) = PyBuffer::<u32>::get(&codepoints) else {
        return Ok(None);
    };
    let Some(codepoints_in) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    if codepoints_in.iter().any(|codepoint| codepoint.get() > 0x7f) {
        return Ok(None);
    }

    let codepoints_out = numpy.call_method1("empty_like", (&codepoints,))?;
    let Ok(out_buffer) = PyBuffer::<u32>::get(&codepoints_out) else {
        return Ok(None);
    };
    let Some(output) = out_buffer.as_mut_slice(py) else {
        return Ok(None);
    };
    for (src, dst) in codepoints_in.iter().zip(output.iter()) {
        let codepoint = src.get();
        let is_lower = (u32::from(b'a')..=u32::from(b'z')).contains(&codepoint);
        let is_upper = (u32::from(b'A')..=u32::from(b'Z')).contains(&codepoint);
        let mapped = match method {
            "upper" if is_lower => codepoint - 32,
            "lower" if is_upper => codepoint + 32,
            "swapcase" if is_lower => codepoint - 32,
            "swapcase" if is_upper => codepoint + 32,
            _ => codepoint,
        };
        dst.set(mapped);
    }

    Ok(Some(
        codepoints_out.call_method1("view", (&dtype,))?.unbind(),
    ))
}

// Per-fixed-width-slot ASCII capitalize/title for '<U' arrays (numpy.char/strings.capitalize/title
// delegate to slow per-element Python str methods). Each string occupies itemsize/4 codepoints
// (null-padded); capitalize = first codepoint upper + rest lower; title = first letter of each word
// (a cased char preceded by an uncased char) upper + other letters lower — matching str.capitalize/
// str.title for ASCII. All-ASCII fast path; non-ASCII / non-U / non-contiguous delegates to numpy.
fn try_zerocopy_unicode_ascii_cap_title(
    py: Python<'_>,
    input: &Bound<'_, PyAny>,
    is_title: bool,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    if !input.is_exact_instance(&numpy.getattr("ndarray")?) {
        return Ok(None);
    }
    let dtype = input.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "U" {
        return Ok(None);
    }
    if !input
        .getattr("flags")?
        .getattr("c_contiguous")?
        .extract::<bool>()?
    {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    if itemsize == 0 || itemsize % 4 != 0 {
        return Ok(None);
    }
    let w = itemsize / 4; // codepoints per fixed-width string slot
    let uint32_dtype = numpy.getattr("uint32")?;
    let codepoints = input.call_method1("view", (&uint32_dtype,))?;
    let Ok(in_buffer) = PyBuffer::<u32>::get(&codepoints) else {
        return Ok(None);
    };
    let Some(codepoints_in) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    if codepoints_in.iter().any(|c| c.get() > 0x7f) {
        return Ok(None);
    }
    if codepoints_in.len() % w != 0 {
        return Ok(None);
    }
    let codepoints_out = numpy.call_method1("empty_like", (&codepoints,))?;
    let Ok(out_buffer) = PyBuffer::<u32>::get(&codepoints_out) else {
        return Ok(None);
    };
    let Some(output) = out_buffer.as_mut_slice(py) else {
        return Ok(None);
    };
    let ascii_upper =
        |c: u32| if (u32::from(b'a')..=u32::from(b'z')).contains(&c) { c - 32 } else { c };
    let ascii_lower =
        |c: u32| if (u32::from(b'A')..=u32::from(b'Z')).contains(&c) { c + 32 } else { c };
    let is_letter = |c: u32| {
        (u32::from(b'a')..=u32::from(b'z')).contains(&c)
            || (u32::from(b'A')..=u32::from(b'Z')).contains(&c)
    };
    for (slot_in, slot_out) in codepoints_in.chunks(w).zip(output.chunks(w)) {
        if is_title {
            let mut prev_cased = false;
            for (s, d) in slot_in.iter().zip(slot_out.iter()) {
                let c = s.get();
                if is_letter(c) {
                    d.set(if prev_cased { ascii_lower(c) } else { ascii_upper(c) });
                    prev_cased = true;
                } else {
                    d.set(c);
                    prev_cased = false;
                }
            }
        } else {
            for (j, (s, d)) in slot_in.iter().zip(slot_out.iter()).enumerate() {
                let c = s.get();
                d.set(if j == 0 { ascii_upper(c) } else { ascii_lower(c) });
            }
        }
    }
    Ok(Some(codepoints_out.call_method1("view", (&dtype,))?.unbind()))
}

// numpy.char.translate delegates to slow per-element str.translate (~448ns/el, Python). Fast-path the
// common case: table is a dict of ASCII ordinal->ordinal (1:1 remap, SAME width), no None/str values,
// no null key (0), deletechars=None, ASCII input. Build a 128-entry lookup and map per codepoint.
// str-table form / None|str values / null key / deletechars / non-ASCII -> Ok(None) (delegate).
fn try_zerocopy_unicode_ascii_translate(
    py: Python<'_>,
    input: &Bound<'_, PyAny>,
    table: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let Ok(tdict) = table.cast::<PyDict>() else {
        return Ok(None);
    };
    let mut lookup: [u32; 128] = std::array::from_fn(|i| i as u32);
    for (k, v) in tdict.iter() {
        let Ok(ki) = k.extract::<i64>() else {
            return Ok(None);
        };
        if ki <= 0 || ki > 127 {
            return Ok(None); // null-key or non-ASCII key -> delegate
        }
        let Ok(vi) = v.extract::<i64>() else {
            return Ok(None); // None / str value (delete/expand) -> delegate
        };
        if !(0..=127).contains(&vi) {
            return Ok(None); // non-ASCII value -> delegate
        }
        lookup[ki as usize] = vi as u32;
    }
    let numpy = py.import("numpy")?;
    if !input.is_exact_instance(&numpy.getattr("ndarray")?) {
        return Ok(None);
    }
    let dtype = input.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "U" {
        return Ok(None);
    }
    if !input
        .getattr("flags")?
        .getattr("c_contiguous")?
        .extract::<bool>()?
    {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    if itemsize == 0 || itemsize % 4 != 0 {
        return Ok(None);
    }
    let uint32_dtype = numpy.getattr("uint32")?;
    let codepoints = input.call_method1("view", (&uint32_dtype,))?;
    let Ok(in_buffer) = PyBuffer::<u32>::get(&codepoints) else {
        return Ok(None);
    };
    let Some(codepoints_in) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    if codepoints_in.iter().any(|c| c.get() > 0x7f) {
        return Ok(None);
    }
    let codepoints_out = numpy.call_method1("empty_like", (&codepoints,))?;
    let Ok(out_buffer) = PyBuffer::<u32>::get(&codepoints_out) else {
        return Ok(None);
    };
    let Some(output) = out_buffer.as_mut_slice(py) else {
        return Ok(None);
    };
    // lookup[0] == 0 (null key gated out) -> NUL padding maps to itself; ASCII gate -> index < 128.
    for (s, d) in codepoints_in.iter().zip(output.iter()) {
        d.set(lookup[s.get() as usize]);
    }
    Ok(Some(codepoints_out.call_method1("view", (&dtype,))?.unbind()))
}

fn unicode_ascii_translate_or_numpy(
    py: Python<'_>,
    input: Py<PyAny>,
    table: Py<PyAny>,
    deletechars: Option<Py<PyAny>>,
    namespace: &str,
) -> PyResult<Py<PyAny>> {
    let del_given = deletechars.as_ref().is_some_and(|d| !d.bind(py).is_none());
    if !del_given
        && let Some(result) =
            try_zerocopy_unicode_ascii_translate(py, input.bind(py), table.bind(py))?
    {
        return Ok(result);
    }
    let func = py.import("numpy")?.getattr(namespace)?.getattr("translate")?;
    match deletechars {
        Some(d) => Ok(func
            .call1((input.bind(py), table.bind(py), d.bind(py)))?
            .unbind()),
        None => Ok(func.call1((input.bind(py), table.bind(py)))?.unbind()),
    }
}

fn unicode_ascii_cap_title_or_numpy(
    py: Python<'_>,
    input: Py<PyAny>,
    namespace: &str,
    method: &str,
    is_title: bool,
) -> PyResult<Py<PyAny>> {
    if let Some(result) = try_zerocopy_unicode_ascii_cap_title(py, input.bind(py), is_title)? {
        return Ok(result);
    }
    Ok(py
        .import("numpy")?
        .getattr(namespace)?
        .getattr(method)?
        .call1((input.bind(py),))?
        .unbind())
}

fn unicode_ascii_case_or_numpy(
    py: Python<'_>,
    input: Py<PyAny>,
    namespace: &str,
    method: &str,
) -> PyResult<Py<PyAny>> {
    if let Some(result) = try_zerocopy_unicode_ascii_case(py, input.bind(py), method)? {
        return Ok(result);
    }
    Ok(py
        .import("numpy")?
        .getattr(namespace)?
        .getattr(method)?
        .call1((input.bind(py),))?
        .unbind())
}

#[pyfunction(name = "upper", signature = (a))]
fn char_upper_ascii(py: Python<'_>, a: Py<PyAny>) -> PyResult<Py<PyAny>> {
    unicode_ascii_case_or_numpy(py, a, "char", "upper")
}

