fn copy_numpy_module_attrs(from: &Bound<'_, PyAny>, to: &Bound<'_, PyModule>) -> PyResult<()> {
    let dict_any = from.getattr("__dict__")?;
    let dict = dict_any.cast::<PyDict>()?;
    for (key, value) in dict.iter() {
        if let Ok(name) = key.extract::<String>() {
            to.setattr(name, value)?;
        }
    }
    Ok(())
}

// True when `value` is a narrow float (float16 / float32). NumPy preserves the
// input float width for reductions like median/percentile/quantile, but our
// in-Rust kernels accumulate in float64. The native fast path therefore matches
// NumPy for float64 and integer/bool inputs (integer reductions promote to
// float64 in both), but would widen float16/float32 results to float64. Callers
// gate on this to defer narrow-float inputs to numpy, preserving exact dtype.
fn numpy_dtype_is_narrow_float(py: Python<'_>, value: &Bound<'_, PyAny>) -> bool {
    let probe = || -> PyResult<bool> {
        let numpy = py.import("numpy")?;
        let array = numpy.call_method1("asarray", (value,))?;
        let dtype = array.getattr("dtype")?;
        let kind: String = dtype.getattr("kind")?.extract()?;
        let itemsize: usize = dtype.getattr("itemsize")?.extract()?;
        Ok(kind == "f" && itemsize < 8)
    };
    probe().unwrap_or(false)
}

// True when `value` is a boolean array/scalar. percentile/quantile reject bool in
// NumPy (the interpolation subtracts, and `-` is unsupported on bool -> TypeError),
// while median allows it; callers gate on this to reproduce that asymmetry.
fn numpy_dtype_is_bool(py: Python<'_>, value: &Bound<'_, PyAny>) -> bool {
    let probe = || -> PyResult<bool> {
        let numpy = py.import("numpy")?;
        let array = numpy.call_method1("asarray", (value,))?;
        let kind: String = array.getattr("dtype")?.getattr("kind")?.extract()?;
        Ok(kind == "b")
    };
    probe().unwrap_or(false)
}

// True when the native UFuncArray round-trip (extract_numeric_array -> kernel ->
// build_numpy_array_from_ufunc) reproduces NumPy's exact dtype. extract_numeric_array
// canonicalizes storage to bool / int64 / uint64 / float64, so the fast path only
// preserves dtype for those four widths; a narrow int/uint/float input would be
// silently widened (e.g. int32 -> int64). Functions whose NumPy contract is to
// preserve the input element dtype (unique, extract, ...) gate on this and defer
// every other dtype to NumPy, which keeps the original width.
fn numpy_dtype_native_roundtrip_preserves(py: Python<'_>, value: &Bound<'_, PyAny>) -> bool {
    let probe = || -> PyResult<bool> {
        let numpy = py.import("numpy")?;
        let array = numpy.call_method1("asarray", (value,))?;
        let dtype = array.getattr("dtype")?;
        let kind: String = dtype.getattr("kind")?.extract()?;
        let itemsize: usize = dtype.getattr("itemsize")?.extract()?;
        Ok(kind == "b" || (matches!(kind.as_str(), "i" | "u" | "f") && itemsize == 8))
    };
    probe().unwrap_or(false)
}

// True when `value`'s dtype is one NumPy widens to the platform accumulator under
// its default sum/trace reduction: bool and any integer/unsigned narrower than
// 8 bytes (-> int64 / uint64). Float dtypes are preserved (not widened) and so are
// excluded. Callers whose native kernel preserves the input dtype gate on this to
// defer the widened cases to NumPy.
fn numpy_dtype_is_subplatform_integer(py: Python<'_>, value: &Bound<'_, PyAny>) -> bool {
    let probe = || -> PyResult<bool> {
        let numpy = py.import("numpy")?;
        let array = numpy.call_method1("asarray", (value,))?;
        let dtype = array.getattr("dtype")?;
        let kind: String = dtype.getattr("kind")?.extract()?;
        let itemsize: usize = dtype.getattr("itemsize")?.extract()?;
        Ok(kind == "b" || (matches!(kind.as_str(), "i" | "u") && itemsize < 8))
    };
    probe().unwrap_or(false)
}

// Arithmetic: divmod + mod/remainder (3).
// Zero-copy np.divmod for two same-shape f64 ndarrays. The general path extracts BOTH operands
// into UFuncArray copies, scans for zero, computes, and builds TWO output arrays — the cold
// extract+build traffic scales with n (2.7x@1M -> 3.75x@16M). Here we read both buffers, defer
// (return None) when any special value is present (zero divisor / non-finite — numpy's exact
// edge handling lives in the cold path), and otherwise compute quotient+remainder straight into
// two numpy.empty buffers in parallel. Finite-nonzero formula is bit-identical to divmod_arrays.
fn try_zerocopy_f64_divmod(
    py: Python<'_>,
    x1: &Bound<'_, PyAny>,
    x2: &Bound<'_, PyAny>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_t = numpy.getattr("ndarray")?;
    if !x1.is_exact_instance(&ndarray_t)
        || !x2.is_exact_instance(&ndarray_t)
        || !numpy_dtype_is_f64(py, x1)
        || !numpy_dtype_is_f64(py, x2)
    {
        return Ok(None);
    }
    let c_contig = |a: &Bound<'_, PyAny>| -> PyResult<bool> {
        a.getattr("flags")?.getattr("c_contiguous")?.extract::<bool>()
    };
    if !c_contig(x1)? || !c_contig(x2)? {
        return Ok(None);
    }
    let (Ok(b1), Ok(b2)) = (PyBuffer::<f64>::get(x1), PyBuffer::<f64>::get(x2)) else {
        return Ok(None);
    };
    if b1.shape() != b2.shape() {
        return Ok(None); // no broadcasting: defer to numpy
    }
    let (Some(c1), Some(c2)) = (b1.as_slice(py), b2.as_slice(py)) else {
        return Ok(None);
    };
    let n = c1.len();
    let shape: Vec<usize> = b1.shape().to_vec();
    // SAFETY: ReadOnlyCell<f64> repr(transparent); read-only under the GIL.
    let a: &[f64] = unsafe { std::slice::from_raw_parts(c1.as_ptr().cast::<f64>(), n) };
    let b: &[f64] = unsafe { std::slice::from_raw_parts(c2.as_ptr().cast::<f64>(), n) };
    // Defer any special case (zero divisor / non-finite) to numpy's exact edge handling.
    let clean = {
        use rayon::prelude::*;
        if n >= (1 << 16) && rayon::current_num_threads() >= 2 {
            a.par_iter()
                .zip(b.par_iter())
                .all(|(&av, &bv)| av.is_finite() && bv.is_finite() && bv != 0.0)
        } else {
            a.iter()
                .zip(b.iter())
                .all(|(&av, &bv)| av.is_finite() && bv.is_finite() && bv != 0.0)
        }
    };
    if !clean {
        return Ok(None);
    }
    let mk = |nm: &str| -> PyResult<Bound<'_, PyAny>> {
        let kw = PyDict::new(py);
        kw.set_item("dtype", nm)?;
        numpy.call_method("empty", (n,), Some(&kw))
    };
    let quotient = mk("float64")?;
    let remainder = mk("float64")?;
    if n > 0 {
        let (Ok(qb), Ok(rb)) = (
            PyBuffer::<f64>::get(&quotient),
            PyBuffer::<f64>::get(&remainder),
        ) else {
            return Ok(None);
        };
        let (Some(qc), Some(rc)) = (qb.as_mut_slice(py), rb.as_mut_slice(py)) else {
            return Ok(None);
        };
        // SAFETY: fresh numpy.empty buffers we own; disjoint chunks under par_chunks_mut.
        let q: &mut [f64] = unsafe { std::slice::from_raw_parts_mut(qc.as_ptr() as *mut f64, n) };
        let r: &mut [f64] = unsafe { std::slice::from_raw_parts_mut(rc.as_ptr() as *mut f64, n) };
        let kernel = |q: &mut [f64], r: &mut [f64], a: &[f64], b: &[f64]| {
            for (((qs, rs), &av), &bv) in q.iter_mut().zip(r.iter_mut()).zip(a).zip(b) {
                *qs = (av / bv).floor();
                let rem = av % bv;
                *rs = if rem != 0.0 && (rem > 0.0) != (bv > 0.0) {
                    rem + bv
                } else if rem == 0.0 {
                    0.0_f64.copysign(bv)
                } else {
                    rem
                };
            }
        };
        const DIVMOD_PARALLEL_MIN: usize = 1 << 18;
        if n >= DIVMOD_PARALLEL_MIN && rayon::current_num_threads() >= 2 {
            use rayon::prelude::*;
            let chunk = n.div_ceil(rayon::current_num_threads());
            q.par_chunks_mut(chunk)
                .zip(r.par_chunks_mut(chunk))
                .zip(a.par_chunks(chunk))
                .zip(b.par_chunks(chunk))
                .for_each(|(((qq, rr), aa), bb)| kernel(qq, rr, aa, bb));
        } else {
            kernel(q, r, a, b);
        }
    }
    let shape_t = PyTuple::new(py, shape.iter().copied())?;
    let quotient = quotient.call_method1("reshape", (&shape_t,))?;
    let remainder = remainder.call_method1("reshape", (&shape_t,))?;
    if shape.is_empty() {
        let qs = quotient.get_item(())?;
        let rs = remainder.get_item(())?;
        return Ok(Some(PyTuple::new(py, [&qs, &rs])?.into_any().unbind()));
    }
    Ok(Some(
        PyTuple::new(py, [&quotient, &remainder])?.into_any().unbind(),
    ))
}

#[pyfunction]
#[pyo3(signature = (x1, x2))]
fn divmod(py: Python<'_>, x1: Py<PyAny>, x2: Py<PyAny>) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = || -> PyResult<Py<PyAny>> {
        Ok(numpy
            .getattr("divmod")?
            .call1((x1.bind(py), x2.bind(py)))?
            .unbind())
    };

    // divmod_arrays is an f64-only kernel, but NumPy's divmod preserves the
    // integer result dtype for integer inputs (int32 stays int32) and the narrow
    // float dtype for float16/float32. Only run the native path when both
    // operands are float64, where the f64 kernel reproduces NumPy's dtype
    // exactly; defer everything else to numpy.divmod.
    if !numpy_dtype_is_f64(py, x1.bind(py)) || !numpy_dtype_is_f64(py, x2.bind(py)) {
        return fallback();
    }

    // Zero-copy same-shape f64 fast path (avoids 2 extract copies + 2 builds; the cold path's
    // traffic scales with n, 2.7-3.75x). Defers broadcasting / special values to the cold path.
    if let Some(out) = try_zerocopy_f64_divmod(py, x1.bind(py), x2.bind(py))? {
        return Ok(out);
    }

    let x1a = match extract_numeric_array(py, x1.bind(py), "divmod(x1)") {
        Ok(arr) => arr,
        Err(_) => return fallback(),
    };
    let x2a = match extract_numeric_array(py, x2.bind(py), "divmod(x2)") {
        Ok(arr) => arr,
        Err(_) => return fallback(),
    };
    // Defer zero-divisor cases so numpy emits the RuntimeWarning (matches the
    // floor_divide fast path).
    if x2a.values().contains(&0.0) {
        return fallback();
    }
    let (quotient, remainder) = match ufunc_divmod(&x1a, &x2a) {
        Ok(pair) => pair,
        Err(_) => return fallback(),
    };
    let outputs = [quotient, remainder];
    build_numpy_scalar_or_array_tuple(py, &outputs)
}

// `mod` is a reserved word in Rust — use py_mod with name override.
#[allow(dead_code)]
#[pyfunction]
#[pyo3(name = "mod", signature = (*args, **kwargs))]
fn py_mod(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    native_binary_remainder_or_passthrough(py, args, kwargs)
}

#[allow(dead_code)]
#[pyfunction]
#[pyo3(signature = (*args, **kwargs))]
fn remainder(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    native_binary_remainder_or_passthrough(py, args, kwargs)
}

// Datetime-aware ufunc (1).
#[pyfunction]
#[pyo3(signature = (*args, **kwargs))]
fn isnat(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    core_numpy_passthrough(py, "isnat", args, kwargs)
}

// Generic typed core for integer sign: write sign_fn(v) into a fresh same-dtype
// buffer via the monomorphic unary_map_int (branchless -> autovectorizes).
fn sign_typed<'py, T, F>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    a: &Bound<'py, PyAny>,
    dtype_name: &str,
    sign_fn: F,
) -> PyResult<Option<(Bound<'py, PyAny>, Vec<usize>)>>
where
    T: pyo3::buffer::Element + Copy,
    F: Fn(T) -> T,
{
    let Ok(in_buffer) = PyBuffer::<T>::get(a) else {
        return Ok(None);
    };
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    let n = input.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", dtype_name)?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<T>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        unary_map_int(input, output, sign_fn);
    }
    Ok(Some((flat, shape)))
}

// Zero-copy integer np.sign for all widths. numpy's sign preserves the input
// dtype: signed -> -1/0/1, unsigned -> 0/1 (unsigned is never negative). Branchless
// (v>0) - (v<0). Otherwise these extracted to an f64 Vec (~80x slower, lossy for
// wide ints). Returns None for non-integer / non-ndarray inputs.
fn try_zerocopy_int_sign(py: Python<'_>, a: &Bound<'_, PyAny>) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if kind != "i" && kind != "u" {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    let result = match (kind.as_str(), itemsize) {
        ("i", 1) => {
            sign_typed::<i8, _>(py, &numpy, a, "int8", |v| i8::from(v > 0) - i8::from(v < 0))?
        }
        ("i", 2) => {
            sign_typed::<i16, _>(py, &numpy, a, "int16", |v| i16::from(v > 0) - i16::from(v < 0))?
        }
        ("i", 4) => {
            sign_typed::<i32, _>(py, &numpy, a, "int32", |v| i32::from(v > 0) - i32::from(v < 0))?
        }
        ("i", 8) => sign_typed::<i64, _>(py, &numpy, a, "int64", |v| {
            i64::from(v > 0) - i64::from(v < 0)
        })?,
        ("u", 1) => sign_typed::<u8, _>(py, &numpy, a, "uint8", |v| u8::from(v > 0))?,
        ("u", 2) => sign_typed::<u16, _>(py, &numpy, a, "uint16", |v| u16::from(v > 0))?,
        ("u", 4) => sign_typed::<u32, _>(py, &numpy, a, "uint32", |v| u32::from(v > 0))?,
        ("u", 8) => sign_typed::<u64, _>(py, &numpy, a, "uint64", |v| u64::from(v > 0))?,
        _ => return Ok(None),
    };
    let Some((flat, shape)) = result else {
        return Ok(None);
    };
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    if shape.is_empty() {
        return Ok(Some(output.bind(py).get_item(())?.unbind()));
    }
    Ok(Some(output))
}

// Generic typed core for the integer prod full reduction. numpy promotes the
// product accumulator (signed -> int64, unsigned -> uint64) and wraps on
// overflow; integer multiplication is associative mod 2^n so the (vectorizable)
// running wrapping product is bit-identical regardless of order. The empty
// product is the identity 1. Returns a numpy scalar of the promoted dtype
// (numpy.prod(axis=None) returns a scalar, not a 0-d array).
fn prod_typed<'py, T, A, FC, FM>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    a: &Bound<'py, PyAny>,
    out_dtype_name: &str,
    identity: A,
    convert: FC,
    mul: FM,
) -> PyResult<Option<Py<PyAny>>>
where
    T: pyo3::buffer::Element + Copy,
    A: Copy + IntoPyObject<'py>,
    FC: Fn(T) -> A,
    FM: Fn(A, A) -> A,
{
    let Ok(in_buffer) = PyBuffer::<T>::get(a) else {
        return Ok(None);
    };
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let mut acc = identity;
    for c in input.iter() {
        acc = mul(acc, convert(c.get()));
    }
    let scalar = numpy.getattr(out_dtype_name)?.call1((acc,))?;
    Ok(Some(scalar.unbind()))
}

// Zero-copy integer prod along a single axis (keepdims=False), promoted to the
// int64/uint64 accumulator like the full reduction. The fallback for this case
// widens to an f64 Vec and runs reduce_prod's strided per-column scan (~41x
// slower for int axis=0 of a wide 2-D array). For inner==1 (last axis) each lane
// is contiguous, so multiply it with a register accumulator. For inner>1
// (non-last axis) scanning each output column strides by `inner` and thrashes
// cache — instead accumulate ROW-WISE into a per-column accumulator array kept
// cache-resident. Each column multiplies factors in ascending axis order, the
// same order numpy uses, so wrapping integer products are bit-identical. Gated
// to a C-contiguous buffer (memory order == reduction order) and ndim>=2.
fn prod_axis_typed<'py, T, A, FC, FM>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    a: &Bound<'py, PyAny>,
    out_dtype_name: &str,
    identity: A,
    convert: FC,
    mul: FM,
    axis: isize,
) -> PyResult<Option<Py<PyAny>>>
where
    T: pyo3::buffer::Element + Copy,
    A: pyo3::buffer::Element + Copy + IntoPyObject<'py>,
    FC: Fn(T) -> A,
    FM: Fn(A, A) -> A,
{
    let Ok(in_buffer) = PyBuffer::<T>::get(a) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() {
        return Ok(None);
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let shape: Vec<usize> = a.getattr("shape")?.extract()?;
    if shape.len() < 2 {
        return Ok(None);
    }
    let ndim = shape.len() as isize;
    let norm = if axis < 0 { axis + ndim } else { axis };
    if norm < 0 || norm >= ndim {
        return Ok(None);
    }
    let axu = norm as usize;
    let outer: usize = shape[..axu].iter().product();
    let axis_len = shape[axu];
    let inner: usize = shape[axu + 1..].iter().product();
    let mut out_shape = shape.clone();
    out_shape.remove(axu);
    let out_elems = outer * inner;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", out_dtype_name)?;
    let flat = numpy.call_method("empty", (out_elems,), Some(&kwargs))?;
    if out_elems > 0 {
        let Ok(out_buffer) = PyBuffer::<A>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        let lane = axis_len * inner;
        if inner == 1 {
            for o in 0..outer {
                let ibase = o * lane;
                let mut acc = identity;
                for k in 0..axis_len {
                    acc = mul(acc, convert(input[ibase + k].get()));
                }
                output[o].set(acc);
            }
        } else {
            let mut accs = vec![identity; out_elems];
            for o in 0..outer {
                let obase = o * inner;
                let ibase = o * lane;
                for k in 0..axis_len {
                    let abase = ibase + k * inner;
                    let arow = &mut accs[obase..obase + inner];
                    for (i, ac) in arow.iter_mut().enumerate() {
                        *ac = mul(*ac, convert(input[abase + i].get()));
                    }
                }
            }
            for (slot, &v) in output.iter().zip(accs.iter()) {
                slot.set(v);
            }
        }
    }
    let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    Ok(Some(output))
}

// Zero-copy integer prod for the full reduction (axis=None), all widths, with
// numpy's accumulator promotion (signed -> int64, unsigned -> uint64). Otherwise
// these extracted to an f64 Vec (~45x slower, lossy for wide ints). Returns None
// for a per-axis reduction, a non-integer dtype, or a non-ndarray input.
fn try_zerocopy_int_prod(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if kind != "i" && kind != "u" && kind != "b" {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    // numpy promotes a bool product to int64 (the 0/1 product never wraps). bool
    // buffers export '?', which PyBuffer<u8> rejects, so read the bytes via a
    // zero-copy uint8 view. Was falling through to the f64-bridge extract (~18x slow).
    if kind == "b" {
        let viewed = a.call_method1("view", (numpy.getattr("uint8")?,))?;
        let mul = |x: i64, y: i64| x.wrapping_mul(y);
        return match axis {
            None => prod_typed::<u8, i64, _, _>(py, &numpy, &viewed, "int64", 1, |v| v as i64, mul),
            Some(ax) => {
                prod_axis_typed::<u8, i64, _, _>(py, &numpy, &viewed, "int64", 1, |v| v as i64, mul, ax)
            }
        };
    }
    // Dispatch each (input type T, accumulator type A) pair to either the full
    // reduction (prod_typed) or the per-axis row-wise path (prod_axis_typed).
    macro_rules! dispatch {
        ($t:ty, $a:ty, $dt:literal, $conv:expr) => {
            match axis {
                None => prod_typed::<$t, $a, _, _>(
                    py,
                    &numpy,
                    a,
                    $dt,
                    1,
                    $conv,
                    |x: $a, y: $a| x.wrapping_mul(y),
                ),
                Some(ax) => prod_axis_typed::<$t, $a, _, _>(
                    py,
                    &numpy,
                    a,
                    $dt,
                    1,
                    $conv,
                    |x: $a, y: $a| x.wrapping_mul(y),
                    ax,
                ),
            }
        };
    }
    match (kind.as_str(), itemsize) {
        ("i", 1) => dispatch!(i8, i64, "int64", |v| v as i64),
        ("i", 2) => dispatch!(i16, i64, "int64", |v| v as i64),
        ("i", 4) => dispatch!(i32, i64, "int64", |v| v as i64),
        ("i", 8) => dispatch!(i64, i64, "int64", |v| v),
        ("u", 1) => dispatch!(u8, u64, "uint64", |v| v as u64),
        ("u", 2) => dispatch!(u16, u64, "uint64", |v| v as u64),
        ("u", 4) => dispatch!(u32, u64, "uint64", |v| v as u64),
        ("u", 8) => dispatch!(u64, u64, "uint64", |v| v),
        _ => Ok(None),
    }
}

// Generic typed core for the integer argmax/argmin full reduction (axis=None).
// `take_max` selects argmax (true) vs argmin (false). Two vectorizable passes:
// pass 1 finds the extreme VALUE via the same `.max()`/`.min()` fold ptp uses
// (pmaxs/pmins — fully autovectorized); pass 2 finds the FIRST buffer index
// holding it via `.position()` (a short-circuiting equality scan). numpy returns
// the index of the first occurrence of the extreme, so first-position is
// bit-identical. Integer comparison is total (no NaN/signed-zero hazard), so the
// result is exact. Gated to a C-contiguous buffer: numpy's axis=None flattens in
// C order, which equals memory order only when C-contiguous (a strided/Fortran
// view would scan in the wrong order → defer to numpy). Empty input defers
// (numpy raises ValueError). Returns a numpy intp scalar, matching
// np.argmax/argmin(axis=None). This replaces the cold
// extract_precise_numeric_array → f64 widen → reduce_argmax path (~55x slower for
// int64, which both allocates an f64 Vec and loses the zero-copy scan).
fn argextreme_typed<'py, T>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    a: &Bound<'py, PyAny>,
    take_max: bool,
) -> PyResult<Option<Py<PyAny>>>
where
    T: pyo3::buffer::Element + Copy + Ord + Sync + Send,
{
    let Ok(in_buffer) = PyBuffer::<T>::get(a) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() {
        return Ok(None);
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let n = input.len();
    if n == 0 {
        return Ok(None);
    }
    // SAFETY: ReadOnlyCell<T> is repr(transparent) over T; read-only contiguous buffer
    // under the GIL -> &[T] (Sync+Send, T a POD integer).
    let data: &[T] = unsafe { std::slice::from_raw_parts(input.as_ptr().cast::<T>(), n) };
    // SINGLE-PASS (value, first-index) fold — the old `.max()` then `.position()` was
    // two full scans; numpy's int argmax is one SIMD pass. Parallel reduce keeps the
    // FIRST occurrence on ties (higher value wins; equal value -> lower index), so it
    // is bit-identical to numpy's first-occurrence argmax.
    let chunk_arg = |base: usize, chunk: &[T]| -> (T, usize) {
        let mut best_v = chunk[0];
        let mut best_i = base;
        if take_max {
            for (j, &v) in chunk.iter().enumerate().skip(1) {
                if v > best_v {
                    best_v = v;
                    best_i = base + j;
                }
            }
        } else {
            for (j, &v) in chunk.iter().enumerate().skip(1) {
                if v < best_v {
                    best_v = v;
                    best_i = base + j;
                }
            }
        }
        (best_v, best_i)
    };
    let combine = |a: (T, usize), b: (T, usize)| -> (T, usize) {
        let better = if take_max { b.0 > a.0 } else { b.0 < a.0 };
        if better || (b.0 == a.0 && b.1 < a.1) {
            b
        } else {
            a
        }
    };
    use rayon::prelude::*;
    // Flat argmax/argmin is a single memory-bound scan, so rayon (per-chunk arg +
    // reduce) adds combine overhead without speeding the bandwidth-saturated read.
    // Measured: SERIAL beats parallel for all N<~8M (even 4M: serial 1.28ms <
    // parallel 1.60ms, and serial BEATS numpy 0.81x while parallel loses 1.11x);
    // parallel only edges ahead by ~16M. Old gate 1<<16 (65K) forced parallel on the
    // common 100K-4M range -> turned a serial win into a loss. Gate at 1<<23 (8M).
    // Chunk args are position-offset + combined deterministically -> serial/parallel
    // pick the same index (bit-identical).
    const ARGEXTREME_PARALLEL_MIN: usize = 1 << 23;
    const CHUNK: usize = 1 << 14;
    let idx = if n >= ARGEXTREME_PARALLEL_MIN && rayon::current_num_threads() >= 2 {
        data.par_chunks(CHUNK)
            .enumerate()
            .map(|(ci, chunk)| chunk_arg(ci * CHUNK, chunk))
            .reduce_with(combine)
            .unwrap()
            .1
    } else {
        chunk_arg(0, data).1
    };
    let scalar = numpy.getattr("intp")?.call1((idx,))?;
    Ok(Some(scalar.unbind()))
}

// Zero-copy integer argmax/argmin for the full reduction (axis=None), all 8
// widths. `take_max` picks argmax vs argmin. None for a per-axis reduction, a
// non-integer dtype, or a non-ndarray input — those keep the existing path.
fn try_zerocopy_int_argextreme(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
    take_max: bool,
) -> PyResult<Option<Py<PyAny>>> {
    if axis.is_some() {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if kind != "i" && kind != "u" {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    // Narrow ints (1/2-byte): numpy's SIMD argmax processes 16-64 lanes per
    // instruction, which the scalar (even parallel) fold can't beat — delegate to
    // numpy (still bit-identical first-occurrence).
    if itemsize <= 2 {
        let op = if take_max { "argmax" } else { "argmin" };
        return Ok(Some(numpy.getattr(op)?.call1((a,))?.unbind()));
    }
    // Wide ints (4/8-byte): the native single-pass fold (argextreme_typed) is SCALAR —
    // its data-dependent `if v > best` branch doesn't autovectorize, so it measures
    // ~1.4-2.6x behind numpy's fused SIMD int argmax past a few KiB (the old "beats
    // numpy" claim was stale). Mirror the f64 flat policy: above the crossover delegate
    // to numpy (bit-identical — integer order is total, same first-occurrence tie), and
    // keep the native fold for small inputs where numpy's per-call dispatch isn't worth
    // it. (Delegation also covers non-contiguous, which argextreme_typed bails on.)
    const ARGEXTREME_WIDE_INT_NUMPY_MIN_LEN: usize = 4096;
    if a.getattr("size")?.extract::<usize>()? >= ARGEXTREME_WIDE_INT_NUMPY_MIN_LEN {
        let op = if take_max { "argmax" } else { "argmin" };
        return Ok(Some(numpy.getattr(op)?.call1((a,))?.unbind()));
    }
    match (kind.as_str(), itemsize) {
        ("i", 4) => argextreme_typed::<i32>(py, &numpy, a, take_max),
        ("i", 8) => argextreme_typed::<i64>(py, &numpy, a, take_max),
        ("u", 4) => argextreme_typed::<u32>(py, &numpy, a, take_max),
        ("u", 8) => argextreme_typed::<u64>(py, &numpy, a, take_max),
        _ => Ok(None),
    }
}

// Generic typed core for the integer ptp (peak-to-peak = max - min) full
// reduction. max() and min() over the buffer are independent vectorizable
// reductions (pmaxs/pmins); the difference wraps in the input width, matching
// numpy. Returns a numpy scalar of the input dtype (numpy.ptp(axis=None) returns
// a scalar, not a 0-d array). None for an empty input (numpy raises — let the
// fallback reproduce it).
fn ptp_typed<'py, T, FS>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    a: &Bound<'py, PyAny>,
    dtype_name: &str,
    sub: FS,
) -> PyResult<Option<Py<PyAny>>>
where
    T: pyo3::buffer::Element + Copy + Ord + IntoPyObject<'py>,
    FS: Fn(T, T) -> T,
{
    let Ok(in_buffer) = PyBuffer::<T>::get(a) else {
        return Ok(None);
    };
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    if input.is_empty() {
        return Ok(None);
    }
    let max_v = input.iter().map(|c| c.get()).max().unwrap();
    let min_v = input.iter().map(|c| c.get()).min().unwrap();
    let result = sub(max_v, min_v);
    let scalar = numpy.getattr(dtype_name)?.call1((result,))?;
    Ok(Some(scalar.unbind()))
}

// Zero-copy integer ptp for the full reduction (axis=None), all widths. numpy's
// ptp is max - min wrapping in the input dtype; both reductions are order-
// independent so this is bit-identical. Otherwise these extracted to an f64 Vec
// (~40-100x slower, lossy for wide ints). Returns None for a per-axis reduction,
// a non-integer dtype, or a non-ndarray input.
fn try_zerocopy_int_ptp(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: Option<isize>,
) -> PyResult<Option<Py<PyAny>>> {
    if axis.is_some() {
        return Ok(None);
    }
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if kind != "i" && kind != "u" {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    match (kind.as_str(), itemsize) {
        ("i", 1) => ptp_typed::<i8, _>(py, &numpy, a, "int8", |x, y| x.wrapping_sub(y)),
        ("i", 2) => ptp_typed::<i16, _>(py, &numpy, a, "int16", |x, y| x.wrapping_sub(y)),
        ("i", 4) => ptp_typed::<i32, _>(py, &numpy, a, "int32", |x, y| x.wrapping_sub(y)),
        ("i", 8) => ptp_typed::<i64, _>(py, &numpy, a, "int64", |x, y| x.wrapping_sub(y)),
        ("u", 1) => ptp_typed::<u8, _>(py, &numpy, a, "uint8", |x, y| x.wrapping_sub(y)),
        ("u", 2) => ptp_typed::<u16, _>(py, &numpy, a, "uint16", |x, y| x.wrapping_sub(y)),
        ("u", 4) => ptp_typed::<u32, _>(py, &numpy, a, "uint32", |x, y| x.wrapping_sub(y)),
        ("u", 8) => ptp_typed::<u64, _>(py, &numpy, a, "uint64", |x, y| x.wrapping_sub(y)),
        _ => Ok(None),
    }
}

// Generic per-axis integer ptp core: out[lane] = max(lane) - min(lane) over the axis,
// preserving the input dtype (wrapping). Integer max/min are order-independent (no
// signed-zero wall), so this is bit-identical. The contiguous (inner==1, last-axis)
// case uses slice-iterator max/min scans that autovectorize; the strided (inner>1)
// case uses an indexed reduction.
fn ptp_axis_typed<'py, T, FS>(
    py: Python<'py>,
    numpy: &Bound<'py, PyModule>,
    a: &Bound<'py, PyAny>,
    axis: isize,
    dtype_name: &str,
    sub: FS,
) -> PyResult<Option<(Bound<'py, PyAny>, Vec<usize>)>>
where
    T: pyo3::buffer::Element + Copy + Ord + Sync + Send,
    FS: Fn(T, T) -> T + Sync,
{
    let Ok(in_buffer) = PyBuffer::<T>::get(a) else {
        return Ok(None);
    };
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    let ndim = shape.len() as isize;
    if ndim == 0 {
        return Ok(None);
    }
    let norm = if axis < 0 { axis + ndim } else { axis };
    if norm < 0 || norm >= ndim {
        return Ok(None);
    }
    let ax = norm as usize;
    let axis_len = shape[ax];
    if axis_len == 0 {
        return Ok(None); // numpy raises on a zero-length reduction axis; defer
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let outer: usize = shape[..ax].iter().product();
    let inner: usize = shape[ax + 1..].iter().product();
    let mut out_shape = shape.clone();
    out_shape.remove(ax);
    let out_elems = outer * inner;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", dtype_name)?;
    let flat = numpy.call_method("empty", (out_elems,), Some(&kwargs))?;
    if out_elems > 0 {
        let Ok(out_buffer) = PyBuffer::<T>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        let lane = axis_len * inner;
        // SAFETY: ReadOnlyCell<T> is repr(transparent) over T; read-only buffer under
        // the GIL -> &[T] (Sync) for the parallel folds (wide ints only; narrow ints
        // delegated to numpy in the caller). min/max/sub are order-independent.
        let data: &[T] =
            unsafe { std::slice::from_raw_parts(input.as_ptr().cast::<T>(), input.len()) };
        use rayon::prelude::*;
        let parallel = outer * axis_len * inner >= (1 << 16) && rayon::current_num_threads() >= 2;
        let parallel_nonlast = parallel;
        if inner == 1 {
            let lane_ptp = |l: &[T]| -> T {
                let mut mx = l[0];
                let mut mn = l[0];
                for &v in &l[1..] {
                    mx = if v > mx { v } else { mx };
                    mn = if v < mn { v } else { mn };
                }
                sub(mx, mn)
            };
            if outer >= 2 {
                let results: Vec<T> = if parallel {
                    data.par_chunks_exact(axis_len).map(&lane_ptp).collect()
                } else {
                    data.chunks_exact(axis_len).map(&lane_ptp).collect()
                };
                for (slot, v) in output.iter().zip(results) {
                    slot.set(v);
                }
            } else {
                // Single big run (1-D ptp): chunk-reduce (max, min) then sub.
                let (mx, mn) = if parallel {
                    data.par_chunks(1 << 14)
                        .map(|c| {
                            let mut mx = c[0];
                            let mut mn = c[0];
                            for &v in &c[1..] {
                                mx = if v > mx { v } else { mx };
                                mn = if v < mn { v } else { mn };
                            }
                            (mx, mn)
                        })
                        .reduce_with(|(amx, amn), (bmx, bmn)| {
                            (
                                if bmx > amx { bmx } else { amx },
                                if bmn < amn { bmn } else { amn },
                            )
                        })
                        .unwrap()
                } else {
                    let mut mx = data[0];
                    let mut mn = data[0];
                    for &v in &data[1..] {
                        mx = if v > mx { v } else { mx };
                        mn = if v < mn { v } else { mn };
                    }
                    (mx, mn)
                };
                output[0].set(sub(mx, mn));
            }
        } else {
            // Non-last axis: per-inner running (max, min) plane down the axis. ≥2 outer
            // groups fan across the pool; a single group (2-D axis=0) privatizes across
            // row-blocks, merging the (max,min) planes elementwise.
            let group_plane = |o: usize| -> Vec<T> {
                let obase = o * lane;
                let mut mxv: Vec<T> = data[obase..obase + inner].to_vec();
                let mut mnv: Vec<T> = mxv.clone();
                for a_idx in 1..axis_len {
                    let slab = &data[obase + a_idx * inner..obase + a_idx * inner + inner];
                    for ((m, n), &v) in mxv.iter_mut().zip(mnv.iter_mut()).zip(slab) {
                        *m = if v > *m { v } else { *m };
                        *n = if v < *n { v } else { *n };
                    }
                }
                mxv.iter().zip(&mnv).map(|(&m, &n)| sub(m, n)).collect()
            };
            let planes: Vec<T> = if parallel_nonlast && outer >= 2 {
                let ps: Vec<Vec<T>> = (0..outer).into_par_iter().map(group_plane).collect();
                let mut out = vec![data[0]; out_elems];
                for (o, p) in ps.into_iter().enumerate() {
                    out[o * inner..o * inner + inner].copy_from_slice(&p);
                }
                out
            } else if parallel_nonlast {
                // Single group: privatize (max,min) across row-blocks, merge, then sub.
                let (mxv, mnv) = (0..axis_len)
                    .into_par_iter()
                    .fold(
                        || None::<(Vec<T>, Vec<T>)>,
                        |acc, k| {
                            let row = &data[k * inner..k * inner + inner];
                            match acc {
                                None => Some((row.to_vec(), row.to_vec())),
                                Some((mut mx, mut mn)) => {
                                    for ((m, n), &v) in mx.iter_mut().zip(mn.iter_mut()).zip(row) {
                                        *m = if v > *m { v } else { *m };
                                        *n = if v < *n { v } else { *n };
                                    }
                                    Some((mx, mn))
                                }
                            }
                        },
                    )
                    .reduce(
                        || None::<(Vec<T>, Vec<T>)>,
                        |a, b| match (a, b) {
                            (None, x) | (x, None) => x,
                            (Some((mut amx, mut amn)), Some((bmx, bmn))) => {
                                for (m, v) in amx.iter_mut().zip(bmx) {
                                    *m = if v > *m { v } else { *m };
                                }
                                for (n, v) in amn.iter_mut().zip(bmn) {
                                    *n = if v < *n { v } else { *n };
                                }
                                Some((amx, amn))
                            }
                        },
                    )
                    .unwrap_or_else(|| (vec![data[0]; inner], vec![data[0]; inner]));
                mxv.iter().zip(&mnv).map(|(&m, &n)| sub(m, n)).collect()
            } else {
                (0..outer).flat_map(group_plane).collect()
            };
            for (slot, &v) in output.iter().zip(planes.iter()) {
                slot.set(v);
            }
        }
    }
    Ok(Some((flat, out_shape)))
}

// Zero-copy per-axis integer ptp (explicit axis), all widths. The flatten helper
// covers axis=None; this covers a single integer axis of a multi-dim array (~15x
// slower via the f64 extract otherwise). Returns None for a non-integer dtype, a
// 0-d / out-of-range / zero-length axis, or a non-ndarray input.
fn try_zerocopy_int_ptp_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: isize,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if kind != "i" && kind != "u" {
        return Ok(None);
    }
    let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
    // numpy's SIMD max/min beats the scalar fold for NARROW ints (any size) and for
    // WIDE ints below ~4M elements (where the parallel fold's bandwidth edge hasn't
    // overtaken SIMD). Delegate both to numpy's ptp; large wide ints fall through to
    // the parallel native fold below.
    let size: usize = a.getattr("size").and_then(|s| s.extract()).unwrap_or(0);
    if itemsize <= 2 || size < (1 << 23) {
        let kwargs = PyDict::new(py);
        kwargs.set_item("axis", axis)?;
        return Ok(Some(numpy.getattr("ptp")?.call((a,), Some(&kwargs))?.unbind()));
    }
    let result = match (kind.as_str(), itemsize) {
        ("i", 1) => ptp_axis_typed::<i8, _>(py, &numpy, a, axis, "int8", |x, y| x.wrapping_sub(y))?,
        ("i", 2) => ptp_axis_typed::<i16, _>(py, &numpy, a, axis, "int16", |x, y| x.wrapping_sub(y))?,
        ("i", 4) => ptp_axis_typed::<i32, _>(py, &numpy, a, axis, "int32", |x, y| x.wrapping_sub(y))?,
        ("i", 8) => ptp_axis_typed::<i64, _>(py, &numpy, a, axis, "int64", |x, y| x.wrapping_sub(y))?,
        ("u", 1) => ptp_axis_typed::<u8, _>(py, &numpy, a, axis, "uint8", |x, y| x.wrapping_sub(y))?,
        ("u", 2) => ptp_axis_typed::<u16, _>(py, &numpy, a, axis, "uint16", |x, y| x.wrapping_sub(y))?,
        ("u", 4) => ptp_axis_typed::<u32, _>(py, &numpy, a, axis, "uint32", |x, y| x.wrapping_sub(y))?,
        ("u", 8) => ptp_axis_typed::<u64, _>(py, &numpy, a, axis, "uint64", |x, y| x.wrapping_sub(y))?,
        _ => return Ok(None),
    };
    let Some((flat, out_shape)) = result else {
        return Ok(None);
    };
    let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    if out_shape.is_empty() {
        return Ok(Some(output.bind(py).get_item(())?.unbind()));
    }
    Ok(Some(output))
}

// Zero-copy per-axis float64 ptp (explicit axis). f64 is not Ord, so it cannot
// use ptp_axis_typed; this mirrors it with the native ptp's NaN-propagating,
// keep-2nd min/max so the result is byte-identical to numpy. The whole point is
// to skip extract_precise_numeric_array, which copies the ENTIRE input into an
// owned Vec<f64> (an ~8MB memcpy at [1000,1000] — measured ~3x the kernel cost);
// here the reduction runs straight off the borrowed PyBuffer. ptp's value is
// invariant to signed-zero tie order (mx - mn is never -0.0: that needs
// mx=-0.0 AND mn=+0.0 at once, impossible since mx>=mn; and x-(±0)=x), so the
// running keep-1st accumulators below produce the same f64 bits as the keep-2nd
// scalar reference. Returns None (caller falls through) for non-f64, f32/f16,
// 0-d / out-of-range / zero-length axis, non-contiguous, or non-ndarray input.
fn try_zerocopy_f64_ptp_axis(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    axis: isize,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 8
    {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    if !in_buffer.is_c_contiguous() {
        return Ok(None);
    }
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    let ndim = shape.len() as isize;
    if ndim == 0 {
        return Ok(None);
    }
    let norm = if axis < 0 { axis + ndim } else { axis };
    if norm < 0 || norm >= ndim {
        return Ok(None);
    }
    let ax = norm as usize;
    let axis_len = shape[ax];
    if axis_len == 0 {
        return Ok(None); // numpy raises on a zero-length reduction axis; defer
    }
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let outer: usize = shape[..ax].iter().product();
    let inner: usize = shape[ax + 1..].iter().product();
    let mut out_shape = shape.clone();
    out_shape.remove(ax);
    let out_elems = outer * inner;
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (out_elems,), Some(&kwargs))?;
    if out_elems > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // SAFETY: ReadOnlyCell<f64> is repr(transparent) over f64 and `input` is a
        // read-only contiguous PyBuffer slice held under the GIL, so reading it as
        // &[f64] (Sync) for the parallel folds below is sound.
        let data: &[f64] =
            unsafe { std::slice::from_raw_parts(input.as_ptr().cast::<f64>(), input.len()) };
        use rayon::prelude::*;
        const PTP_AXIS_PARALLEL_MIN: usize = 1 << 21;
        let parallel = outer * axis_len * inner >= PTP_AXIS_PARALLEL_MIN
            && rayon::current_num_threads() >= 2;
        let lane = axis_len * inner;
        // ptp tracks NaN-presence SEPARATELY and emits NaN for any nan lane, so the
        // running max/min can use branchless NaN-skipping f64::max/min (vectorizes;
        // the previous `if v > *m` branch did not). Output is bit-identical: when a
        // lane has no NaN this is the true max/min; when it has a NaN the `any_nan`
        // override forces NaN regardless of the skipped extreme, and a ±0 extreme
        // can't change a difference `a - 0`.
        let result: Vec<f64> = if inner == 1 {
            // Last axis: each lane is an independent contiguous run — fan across the
            // rayon pool (numpy runs this single-threaded).
            let lane_ptp = |l: &[f64]| -> f64 {
                let first = l[0];
                let (mut mn, mut mx) = (first, first);
                let mut any_nan = first != first;
                for &v in &l[1..] {
                    any_nan |= v != v;
                    mx = mx.max(v);
                    mn = mn.min(v);
                }
                if any_nan { f64::NAN } else { mx - mn }
            };
            if parallel {
                data.par_chunks_exact(axis_len).map(lane_ptp).collect()
            } else {
                data.chunks_exact(axis_len).map(lane_ptp).collect()
            }
        } else {
            // Strided (non-last axis): per-inner running max/min/nan plane. ≥2 outer
            // groups fan across groups; a single group (2-D axis=0) privatizes across
            // row-blocks and merges the planes elementwise.
            let to_ptp = |mxv: &[f64], mnv: &[f64], nanv: &[bool]| -> Vec<f64> {
                mxv.iter()
                    .zip(mnv)
                    .zip(nanv)
                    .map(|((&m, &n), &nf)| if nf { f64::NAN } else { m - n })
                    .collect()
            };
            let group_plane = |obase: usize| -> (Vec<f64>, Vec<f64>, Vec<bool>) {
                let mut mxv = data[obase..obase + inner].to_vec();
                let mut mnv = mxv.clone();
                let mut nanv: Vec<bool> = data[obase..obase + inner].iter().map(|&v| v != v).collect();
                for a_idx in 1..axis_len {
                    let slab = &data[obase + a_idx * inner..obase + a_idx * inner + inner];
                    for (((m, n), nf), &v) in mxv
                        .iter_mut()
                        .zip(mnv.iter_mut())
                        .zip(nanv.iter_mut())
                        .zip(slab.iter())
                    {
                        *nf |= v != v;
                        *m = m.max(v);
                        *n = n.min(v);
                    }
                }
                (mxv, mnv, nanv)
            };
            if parallel && outer >= 2 {
                let planes: Vec<Vec<f64>> = (0..outer)
                    .into_par_iter()
                    .map(|o| {
                        let (mx, mn, nf) = group_plane(o * lane);
                        to_ptp(&mx, &mn, &nf)
                    })
                    .collect();
                let mut result = vec![0.0f64; out_elems];
                for (o, p) in planes.into_iter().enumerate() {
                    result[o * inner..o * inner + inner].copy_from_slice(&p);
                }
                result
            } else if parallel {
                // Single group: privatize across row-blocks, merge planes elementwise.
                let (mxv, mnv, nanv) = (0..axis_len)
                    .into_par_iter()
                    .fold(
                        || {
                            (
                                vec![f64::NEG_INFINITY; inner],
                                vec![f64::INFINITY; inner],
                                vec![false; inner],
                            )
                        },
                        |(mut mx, mut mn, mut nf), r| {
                            let slab = &data[r * inner..r * inner + inner];
                            for (((m, n), f), &v) in mx
                                .iter_mut()
                                .zip(mn.iter_mut())
                                .zip(nf.iter_mut())
                                .zip(slab.iter())
                            {
                                *f |= v != v;
                                *m = m.max(v);
                                *n = n.min(v);
                            }
                            (mx, mn, nf)
                        },
                    )
                    .reduce(
                        || {
                            (
                                vec![f64::NEG_INFINITY; inner],
                                vec![f64::INFINITY; inner],
                                vec![false; inner],
                            )
                        },
                        |(mut amx, mut amn, mut anf), (bmx, bmn, bnf)| {
                            for (x, y) in amx.iter_mut().zip(bmx) {
                                *x = x.max(y);
                            }
                            for (x, y) in amn.iter_mut().zip(bmn) {
                                *x = x.min(y);
                            }
                            for (x, y) in anf.iter_mut().zip(bnf) {
                                *x |= y;
                            }
                            (amx, amn, anf)
                        },
                    );
                to_ptp(&mxv, &mnv, &nanv)
            } else {
                let mut result = vec![0.0f64; out_elems];
                for o in 0..outer {
                    let (mx, mn, nf) = group_plane(o * lane);
                    let p = to_ptp(&mx, &mn, &nf);
                    result[o * inner..o * inner + inner].copy_from_slice(&p);
                }
                result
            }
        };
        for (slot, &v) in output.iter().zip(result.iter()) {
            slot.set(v);
        }
    }
    let output_shape = PyTuple::new(py, out_shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    if out_shape.is_empty() {
        return Ok(Some(output.bind(py).get_item(())?.unbind()));
    }
    Ok(Some(output))
}

// Peak-to-peak reduction (max - min) with native Rust fast path.
#[pyfunction]
#[pyo3(signature = (a, axis=None, out=None, keepdims=false))]
fn ptp(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    keepdims: bool,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let ptp_fn = numpy.getattr("ptp")?;

    let a_for_fallback = a.clone_ref(py);
    let axis_for_fallback = axis.as_ref().map(|v| v.clone_ref(py));
    let out_for_fallback = out.as_ref().map(|v| v.clone_ref(py));

    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(ax) = axis_for_fallback.as_ref() {
            kwargs.set_item("axis", ax.bind(py))?;
        }
        if let Some(o) = out_for_fallback.as_ref() {
            kwargs.set_item("out", o.bind(py))?;
        }
        kwargs.set_item("keepdims", keepdims)?;
        Ok(ptp_fn
            .call((a_for_fallback.bind(py),), Some(&kwargs))?
            .unbind())
    };

    // Fallback for `out` buffer, keepdims, or tuple axis (multi-axis reduction)
    if out.as_ref().is_some_and(|v| !v.bind(py).is_none()) || keepdims {
        return fallback();
    }

    // Parse axis: None, integer, or tuple → fallback for tuple
    let axis_val: Option<isize> = match &axis {
        None => None,
        Some(ax) => {
            let ax_bound = ax.bind(py);
            if ax_bound.is_none() {
                None
            } else if let Ok(i) = ax_bound.extract::<isize>() {
                Some(i)
            } else {
                // tuple axis or other → fallback
                return fallback();
            }
        }
    };

    // Zero-copy integer ptp (full reduction): two vectorizable max/min scans,
    // wrapping difference. Bit-identical; skips the cold, for-wide-ints lossy
    // extract Vec. Per-axis and non-integer dtypes fall through.
    if let Some(result) = try_zerocopy_int_ptp(py, a.bind(py), axis_val)? {
        return Ok(result);
    }
    // Zero-copy per-axis integer ptp (explicit axis): max/min reduction per lane,
    // wrapping difference, dtype-preserving. Bit-identical; skips the f64 extract.
    if let Some(ax) = axis_val
        && let Some(result) = try_zerocopy_int_ptp_axis(py, a.bind(py), ax)?
    {
        return Ok(result);
    }
    // Small f64 per-axis ptp: numpy's SIMD max−min beats both the serial scalar column
    // fold and the parallel privatized plane (thread overhead) below ~4M elements; the
    // native parallel only out-runs numpy past that. Delegate small arrays to numpy.
    if axis_val.is_some()
        && numpy_dtype_is_f64(py, a.bind(py))
        && a.bind(py)
            .getattr("size")
            .and_then(|s| s.extract::<usize>())
            .map(|s| s < (1 << 22))
            .unwrap_or(false)
    {
        return fallback();
    }
    // Zero-copy per-axis float64 ptp (explicit axis): the native kernel is already
    // at numpy parity, but extract_precise_numeric_array copies the whole input
    // first (~8MB memcpy at [1000,1000] ≈ 3x the kernel). Reduce straight off the
    // borrowed PyBuffer instead — byte-identical (ptp value is signed-zero invariant).
    if let Some(ax) = axis_val
        && let Some(result) = try_zerocopy_f64_ptp_axis(py, a.bind(py), ax)?
    {
        return Ok(result);
    }

    // Large f64 full reduction: the native max−min over an owned f64 Vec is ~3.8x
    // behind numpy's fused SIMD ptp (measured 2.82x@16k, 3.79x@1M). Delegate to numpy
    // — byte-identical result. Tiny arrays and the per-axis/int cases keep native.
    if axis_val.is_none() {
        let ab = a.bind(py);
        let size = ab
            .getattr("size")
            .ok()
            .and_then(|s| s.extract::<usize>().ok())
            .unwrap_or(0);
        if size >= 4096 && numpy_dtype_is_f64(py, ab) {
            return fallback();
        }
    }

    // f32/f16 ptp (any axis): numpy's fused SIMD ptp beats fnp's widening native
    // max−min (8vdtg ceiling, ~1.5-12x slower); delegate.
    if numpy_dtype_is_f32(a.bind(py)) || numpy_dtype_is_f16(a.bind(py)) {
        return fallback();
    }

    // Non-contiguous (transposed / strided) ndarrays bail out of every zero-copy
    // path above into the cold extract → native reduction, which is ~22x slower than
    // numpy's cache-blocked strided ptp. Delegate them to numpy (byte-identical).
    if let Ok(ndarray_type) = numpy.getattr("ndarray")
        && a.bind(py).is_exact_instance(&ndarray_type)
        && !a
            .bind(py)
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return fallback();
    }

    // Extract input array
    let array = match extract_precise_numeric_array(py, a.bind(py), "ptp(a)") {
        Ok(arr) => arr,
        Err(_) => return fallback(),
    };

    // Complex arrays → fallback (ptp not defined for complex)
    if matches!(array.dtype(), DType::Complex64 | DType::Complex128) {
        return fallback();
    }

    // Bool → numpy raises TypeError ("numpy boolean subtract ... not supported") because
    // ptp is max−min; the native max−min instead returns a bool. Delegate so numpy
    // raises the same error (parity for bool list and bool ndarray inputs alike).
    if matches!(array.dtype(), DType::Bool) {
        return fallback();
    }

    // Call native Rust ptp
    let result = match array.ptp(axis_val) {
        Ok(r) => r,
        Err(_) => return fallback(),
    };

    build_numpy_scalar_or_array(py, &result)
}

