// Zero-copy np.around(a, decimals) for decimals != 0 on a C-contiguous float64
// ndarray. Reproduces exactly the formula the general path uses —
// (v * 10^decimals).round_ties_even() / 10^decimals — reading the input buffer
// and writing the result buffer with no intermediate Rust Vec, dropping the cold
// extract/build Vecs (bead lglck). Same per-element op in the same order, so it
// is bit-identical to the existing native around path. Returns Ok(None) — caller
// falls through — for any non-f64 / non-contiguous / non-ndarray input.
fn try_zerocopy_f64_around(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    decimals: i32,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) || !numpy_dtype_is_f64(py, a) {
        return Ok(None);
    }
    let Ok(in_buffer) = PyBuffer::<f64>::get(a) else {
        return Ok(None);
    };
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    let n = input.len();
    let scale = 10_f64.powi(decimals);
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float64")?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<f64>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        for (slot, cell) in output.iter().zip(input.iter()) {
            slot.set((cell.get() * scale).round_ties_even() / scale);
        }
    }
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    if shape.is_empty() {
        return Ok(Some(output.bind(py).get_item(())?.unbind()));
    }
    Ok(Some(output))
}

// Zero-copy np.around/round for float32 ndarrays, any decimals. numpy rounds with
// f = 10^|decimals| and, crucially, DIVIDES FIRST for negative decimals
// (out = rint(a / f) * f) rather than multiplying by the unrepresentable 10^d:
// for float32 the ~1e-7 error in float32(0.001) flips rint, so the naive
// multiply-form the f64 helper can afford here diverges. The scale f is the
// python-float 10^|decimals| cast to float32 exactly as numpy adopts it into the
// array's float32 dtype. decimals==0 falls out as scale==1 (a plain rint). All
// arithmetic in float32; nan/inf/-0.0 propagate. The f64 helper gates on float64,
// so float32 otherwise extracted to an f64 Vec (~87x slower). Returns None for a
// non-float32 dtype, a non-ndarray input, or a non-finite/zero scale (absurd
// |decimals| — deferred to numpy).
fn try_zerocopy_f32_around(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    decimals: i32,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let dtype = a.getattr("dtype")?;
    if dtype.getattr("kind")?.extract::<String>()? != "f"
        || dtype.getattr("itemsize")?.extract::<usize>()? != 4
    {
        return Ok(None);
    }
    let neg = decimals < 0;
    let scale = 10_f64.powi(if neg { -decimals } else { decimals }) as f32;
    if !scale.is_finite() || scale == 0.0 {
        // Absurd |decimals|: 10^|decimals| overflows/underflows float32, so the f32
        // arithmetic below would not match numpy's own overflow result. Delegate
        // this pathological case straight to numpy.around for exact parity.
        let kwargs = PyDict::new(py);
        kwargs.set_item("decimals", decimals)?;
        return Ok(Some(
            numpy.getattr("around")?.call((a,), Some(&kwargs))?.unbind(),
        ));
    }
    let Ok(in_buffer) = PyBuffer::<f32>::get(a) else {
        return Ok(None);
    };
    let Some(input) = in_buffer.as_slice(py) else {
        return Ok(None);
    };
    let shape: Vec<usize> = in_buffer.shape().to_vec();
    let n = input.len();
    let kwargs = PyDict::new(py);
    kwargs.set_item("dtype", "float32")?;
    let flat = numpy.call_method("empty", (n,), Some(&kwargs))?;
    if n > 0 {
        let Ok(out_buffer) = PyBuffer::<f32>::get(&flat) else {
            return Ok(None);
        };
        let Some(output) = out_buffer.as_mut_slice(py) else {
            return Ok(None);
        };
        // Split by mode into three branchless loops (each autovectorizes). decimals==0
        // is a plain round-half-even (scale==1), so skip the wasted *1/÷1 the scaled
        // forms would otherwise do.
        if decimals == 0 {
            for (slot, cell) in output.iter().zip(input.iter()) {
                slot.set(cell.get().round_ties_even());
            }
        } else if neg {
            for (slot, cell) in output.iter().zip(input.iter()) {
                slot.set((cell.get() / scale).round_ties_even() * scale);
            }
        } else {
            for (slot, cell) in output.iter().zip(input.iter()) {
                slot.set((cell.get() * scale).round_ties_even() / scale);
            }
        }
    }
    let output_shape = PyTuple::new(py, shape.iter().copied())?;
    let output = flat.call_method1("reshape", (&output_shape,))?.unbind();
    if shape.is_empty() {
        return Ok(Some(output.bind(py).get_item(())?.unbind()));
    }
    Ok(Some(output))
}

// np.around/np.round of an integer ndarray.
//
// decimals >= 0 is the identity (rounding an integer to zero-or-more decimal
// places leaves it unchanged); numpy returns a fresh copy preserving the input
// dtype, so a.copy() is bit-identical and skips the cold extract -> f64 Vec ->
// Rint -> rebuild path (~140-270x slower).
//
// decimals < 0 rounds to a power of ten. numpy computes this with a *lossy*
// float cast (int -> f64 -> round -> back), which overflow-wraps and warns for
// wide ints. fnp's extract path instead RAISES on any int that cannot round-trip
// through f64 exactly (`to_storage ... cannot be represented exactly`), so it
// CRASHED where numpy returns a value (bead xti0b). Delegate this case straight
// to numpy.around for exact parity (including numpy's own overflow behavior) and
// no crash. Returns None for non-integer / non-ndarray inputs.
fn try_zerocopy_int_around(
    py: Python<'_>,
    a: &Bound<'_, PyAny>,
    decimals: i32,
) -> PyResult<Option<Py<PyAny>>> {
    let numpy = py.import("numpy")?;
    let ndarray_type = numpy.getattr("ndarray")?;
    if !a.is_exact_instance(&ndarray_type) {
        return Ok(None);
    }
    let kind = a.getattr("dtype")?.getattr("kind")?.extract::<String>()?;
    if kind != "i" && kind != "u" {
        return Ok(None);
    }
    if decimals >= 0 {
        return Ok(Some(a.call_method0("copy")?.unbind()));
    }
    let kwargs = PyDict::new(py);
    kwargs.set_item("decimals", decimals)?;
    Ok(Some(
        numpy.getattr("around")?.call((a,), Some(&kwargs))?.unbind(),
    ))
}

// Rounding aliases (2).
#[pyfunction]
#[pyo3(signature = (a, decimals=0, out=None))]
fn around(
    py: Python<'_>,
    a: Py<PyAny>,
    decimals: i32,
    out: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let around_fn = numpy.getattr("around")?;
    let a_for_fallback = a.clone_ref(py);
    let out_for_fallback = out.as_ref().map(|v| v.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        kwargs.set_item("decimals", decimals)?;
        if let Some(o) = out_for_fallback.as_ref() {
            kwargs.set_item("out", o.bind(py))?;
        }
        Ok(around_fn
            .call((a_for_fallback.bind(py),), Some(&kwargs))?
            .unbind())
    };

    if out.as_ref().is_some_and(|v| !v.bind(py).is_none()) {
        return fallback();
    }

    // decimals==0 is plain round-half-even (Rint); take the zero-copy buffer
    // path for exact f64 C-contiguous ndarrays (bit-identical to the
    // elementwise(Rint) branch below). Other inputs fall through unchanged.
    if decimals == 0
        && let Some(result) = try_zerocopy_f64_unary(py, a.bind(py), UnaryOp::Rint)?
    {
        return Ok(result);
    }

    // decimals != 0: zero-copy (v*10^d).round_ties_even()/10^d for f64 ndarrays
    // (the common case); skips the cold extract/build Vecs. Bit-identical to the
    // general native path below (same formula). Other inputs fall through.
    if decimals != 0
        && let Some(result) = try_zerocopy_f64_around(py, a.bind(py), decimals)?
    {
        return Ok(result);
    }

    // Integer input with decimals >= 0 is the identity; return a fast copy.
    if let Some(result) = try_zerocopy_int_around(py, a.bind(py), decimals)? {
        return Ok(result);
    }

    // float32 around (any decimals): numpy's divide-first-for-negative form in f32;
    // skips the cold f64 round-trip. Bit-identical. Other inputs fall through.
    if let Some(result) = try_zerocopy_f32_around(py, a.bind(py), decimals)? {
        return Ok(result);
    }

    // Bool input reaches here (the zero-copy f64/int/f32 paths above don't take it).
    // numpy.around(bool) PROMOTES to float16 (a numpy quirk) — the native extract path
    // would instead return a bool array (wrong dtype). And around(float16) rounds via an
    // f64 intermediate that diverges from numpy's f16-native rounding in the last bit
    // (decimals!=0). numpy is the parity reference for both, so defer (checked only on
    // the fallthrough — f64/int/f32 already returned above).
    if a.bind(py).is_exact_instance(&numpy.getattr("ndarray")?) {
        let dtype = a.bind(py).getattr("dtype")?;
        let kind = dtype.getattr("kind")?.extract::<String>()?;
        let itemsize = dtype.getattr("itemsize")?.extract::<usize>()?;
        if kind == "b" || (kind == "f" && itemsize == 2) {
            return fallback();
        }
    }
    // Non-contiguous (transposed/strided) ndarrays bail out of the contiguous-only
    // zero-copy paths into the cold extract → rebuild (~4.6x slower than numpy's
    // strided rounding). Delegate them to numpy.
    if a.bind(py).is_exact_instance(&numpy.getattr("ndarray")?)
        && !a
            .bind(py)
            .getattr("flags")?
            .getattr("c_contiguous")?
            .extract::<bool>()?
    {
        return fallback();
    }
    let array = match extract_precise_numeric_array(py, a.bind(py), "around(a)") {
        Ok(arr) => arr,
        Err(_) => return fallback(),
    };

    if matches!(array.dtype(), DType::Complex64 | DType::Complex128) {
        return fallback();
    }

    // Bool reaching here came from a non-ndarray input (e.g. a Python bool list, which
    // skips the ndarray-gated bool delegate above): numpy.around PROMOTES bool to
    // float16, but the native Rint path returns a bool array. Delegate for parity.
    if matches!(array.dtype(), DType::Bool) {
        return fallback();
    }

    let result = if decimals == 0 {
        array.elementwise_unary(UnaryOp::Rint)
    } else {
        let scale = 10_f64.powi(decimals);
        let values: Vec<f64> = array
            .values()
            .iter()
            .map(|&v| (v * scale).round_ties_even() / scale)
            .collect();
        UFuncArray::new(array.shape().to_vec(), values, array.dtype()).map_err(map_ufunc_error)?
    };
    build_numpy_scalar_or_array(py, &result)
}

