    static PY_TEST_MUTEX: std::sync::Mutex<()> = std::sync::Mutex::new(());

    fn with_python(test: impl FnOnce(Python<'_>) -> PyResult<()>) {
        let _guard = PY_TEST_MUTEX
            .lock()
            .unwrap_or_else(|poisoned| poisoned.into_inner());
        Python::initialize();
        let outcome = Python::attach(|py| {
            let outcome = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| test(py)));
            let _ = py
                .import("gc")
                .and_then(|gc| gc.call_method0("collect"))
                .map(drop);
            outcome
        });
        match outcome {
            Ok(result) => result.unwrap(),
            Err(payload) => std::panic::resume_unwind(payload),
        }
    }

    #[test]
    fn with_python_serializes_unsendable_module_singletons_across_threads() {
        let threads = (0..4)
            .map(|i| {
                std::thread::spawn(move || {
                    with_python(|py| {
                        let module_name = format!("fnp_python_thread_safety_{i}");
                        let module = PyModule::new(py, &module_name)?;
                        fnp_python(&module)?;
                        drop(module);
                        Ok(())
                    });
                })
            })
            .collect::<Vec<_>>();

        for thread in threads {
            thread
                .join()
                .expect("threaded fnp_python initialization should not panic");
        }
    }

    /// Process-wide mutex serializing every AttrGuard-based poisoning. The
    /// guard installs sentinel/bomb lambdas onto shared Python globals
    /// (numpy.frompyfunc, linalg.pinv, ma.minimum_fill_value, …); holding
    /// this mutex for the lifetime of each guard prevents sibling cargo
    /// test threads from observing the polluted state. Fixes
    /// franken_numpy-4jlw where parallel runs intermittently saw numpy
    /// state clobbered mid-test.
    static POISON_MUTEX: std::sync::Mutex<()> = std::sync::Mutex::new(());

    /// RAII guard that restores a Python attribute to its original value on
    /// drop. Tests use it to swap numpy/ma/linalg attributes with sentinels
    /// ("bomb" / "poison" lambdas) to prove our code path does NOT delegate
    /// back to numpy. If the scope panics before manually restoring, other
    /// parallel tests would see the polluted global state — this guard
    /// prevents that.
    struct AttrGuard {
        owner: Py<pyo3::types::PyAny>,
        name: &'static str,
        original: Py<pyo3::types::PyAny>,
        _mutex: std::sync::MutexGuard<'static, ()>,
    }

    impl AttrGuard {
        fn new(owner: &pyo3::Bound<'_, pyo3::types::PyAny>, name: &'static str) -> PyResult<Self> {
            // Acquire the process-wide poison mutex first so no sibling
            // test thread can observe the clobbered state. PoisonError is
            // recovered into_inner — a panicking poisoning test still
            // leaves this env clean because AttrGuard::drop restores state
            // unconditionally.
            let mutex = POISON_MUTEX
                .lock()
                .unwrap_or_else(|poisoned| poisoned.into_inner());
            let original = owner.getattr(name)?.unbind();
            Ok(Self {
                owner: owner.clone().unbind(),
                name,
                original,
                _mutex: mutex,
            })
        }
    }

    impl Drop for AttrGuard {
        fn drop(&mut self) {
            Python::attach(|py| {
                let _ = self
                    .owner
                    .bind(py)
                    .setattr(self.name, self.original.bind(py));
            });
        }
    }

    fn numpy_available(py: Python<'_>) -> bool {
        py.import("numpy").is_ok()
    }

    fn object_dtype<'py>(py: Python<'py>) -> pyo3::Bound<'py, pyo3::types::PyAny> {
        py.import("builtins")
            .unwrap()
            .getattr("object")
            .expect("builtins.object should exist")
    }

    fn object_array<'py>(
        py: Python<'py>,
        values: impl IntoPyObject<'py>,
    ) -> pyo3::Bound<'py, pyo3::types::PyAny> {
        let numpy = py.import("numpy").unwrap();
        let kwargs = PyDict::new(py);
        kwargs
            .set_item("dtype", object_dtype(py))
            .expect("dtype should be accepted");
        numpy
            .call_method("array", (values,), Some(&kwargs))
            .expect("np.array should work")
    }

    fn numeric_array<'py>(
        py: Python<'py>,
        values: impl IntoPyObject<'py>,
        dtype: &str,
    ) -> pyo3::Bound<'py, pyo3::types::PyAny> {
        let numpy = py.import("numpy").unwrap();
        let kwargs = PyDict::new(py);
        kwargs
            .set_item("dtype", dtype)
            .expect("dtype should be accepted");
        numpy
            .call_method("array", (values,), Some(&kwargs))
            .expect("np.array should work")
    }

    fn append_numeric_storage_bytes(storage: &ArrayStorage, out: &mut Vec<u8>) -> PyResult<()> {
        out.extend_from_slice(storage.dtype().name().as_bytes());
        out.push(0);
        match storage {
            ArrayStorage::I8(values) => {
                for value in values {
                    out.extend_from_slice(&value.to_le_bytes());
                }
            }
            ArrayStorage::I16(values) => {
                for value in values {
                    out.extend_from_slice(&value.to_le_bytes());
                }
            }
            ArrayStorage::I32(values) => {
                for value in values {
                    out.extend_from_slice(&value.to_le_bytes());
                }
            }
            ArrayStorage::I64(values) => {
                for value in values {
                    out.extend_from_slice(&value.to_le_bytes());
                }
            }
            ArrayStorage::U8(values) => out.extend_from_slice(values),
            ArrayStorage::U16(values) => {
                for value in values {
                    out.extend_from_slice(&value.to_le_bytes());
                }
            }
            ArrayStorage::U32(values) => {
                for value in values {
                    out.extend_from_slice(&value.to_le_bytes());
                }
            }
            ArrayStorage::U64(values) => {
                for value in values {
                    out.extend_from_slice(&value.to_le_bytes());
                }
            }
            ArrayStorage::F32(values) => {
                for value in values {
                    out.extend_from_slice(&value.to_bits().to_le_bytes());
                }
            }
            ArrayStorage::F64(values) => {
                for value in values {
                    out.extend_from_slice(&value.to_bits().to_le_bytes());
                }
            }
            _ => {
                return Err(PyValueError::new_err(
                    "unexpected storage variant for buffer extraction proof",
                ));
            }
        }
        out.push(0xff);
        Ok(())
    }

    fn py_sha256_hex(py: Python<'_>, bytes: &[u8]) -> PyResult<String> {
        let digest = py
            .import("hashlib")?
            .getattr("sha256")?
            .call1((PyBytes::new(py, bytes),))?;
        digest.call_method0("hexdigest")?.extract::<String>()
    }

    fn append_numpy_array_bytes(
        py: Python<'_>,
        array: &pyo3::Bound<'_, pyo3::types::PyAny>,
        out: &mut Vec<u8>,
    ) -> PyResult<()> {
        let contiguous = py
            .import("numpy")?
            .getattr("ascontiguousarray")?
            .call1((array,))?;
        let shape = contiguous.getattr("shape")?.extract::<Vec<usize>>()?;
        for dim in shape {
            out.extend_from_slice(&(dim as u64).to_le_bytes());
        }
        out.push(0);
        out.extend_from_slice(contiguous.getattr("dtype")?.str()?.to_string().as_bytes());
        out.push(0);
        out.extend_from_slice(&contiguous.call_method0("tobytes")?.extract::<Vec<u8>>()?);
        out.push(0xff);
        Ok(())
    }

    fn native_inner_without_python_gate(
        py: Python<'_>,
        a: &Bound<'_, PyAny>,
        b: &Bound<'_, PyAny>,
    ) -> PyResult<Py<PyAny>> {
        let a = extract_precise_numeric_array(py, a, "inner(a)")?;
        let b = extract_precise_numeric_array(py, b, "inner(b)")?;
        let result = a.inner(&b).map_err(super::map_ufunc_error)?;
        let output = build_numpy_array_from_ufunc(py, &result)?;
        if result.shape().is_empty() {
            return Ok(output.bind(py).get_item(())?.unbind());
        }
        Ok(output)
    }

    fn median_ms(samples: &mut [f64]) -> f64 {
        samples.sort_by(|a, b| a.partial_cmp(b).expect("timing sample should be finite"));
        samples[samples.len() / 2]
    }

    fn repr_string(value: &pyo3::Bound<'_, pyo3::types::PyAny>) -> String {
        value.repr().unwrap().extract::<String>().unwrap()
    }

    #[test]
    fn buffer_protocol_numeric_extraction_matches_pylist_golden_sha() {
        with_python(|py| {
            let precise_cases = vec![
                (
                    "precise-int8",
                    numeric_array(py, vec![-5_i64, 0, 7], "int8"),
                    ArrayStorage::I8(vec![-5, 0, 7]),
                ),
                (
                    "precise-int16",
                    numeric_array(py, vec![-32000_i64, 0, 12345], "int16"),
                    ArrayStorage::I16(vec![-32000, 0, 12345]),
                ),
                (
                    "precise-int32",
                    numeric_array(py, vec![-2_000_000_i64, 0, 2_000_000], "int32"),
                    ArrayStorage::I32(vec![-2_000_000, 0, 2_000_000]),
                ),
                (
                    "precise-int64",
                    numeric_array(
                        py,
                        vec![-9_007_199_254_740_993_i64, -1, 9_007_199_254_740_993],
                        "int64",
                    ),
                    ArrayStorage::I64(vec![-9_007_199_254_740_993, -1, 9_007_199_254_740_993]),
                ),
                (
                    "precise-uint8",
                    numeric_array(py, vec![0_u64, 127, 255], "uint8"),
                    ArrayStorage::U8(vec![0, 127, 255]),
                ),
                (
                    "precise-uint16",
                    numeric_array(py, vec![0_u64, 1024, 65535], "uint16"),
                    ArrayStorage::U16(vec![0, 1024, 65535]),
                ),
                (
                    "precise-uint32",
                    numeric_array(py, vec![0_u64, 1024, 4_000_000_000], "uint32"),
                    ArrayStorage::U32(vec![0, 1024, 4_000_000_000]),
                ),
                (
                    "precise-uint64",
                    numeric_array(py, vec![0_u64, 7, 9_007_199_254_740_993], "uint64"),
                    ArrayStorage::U64(vec![0, 7, 9_007_199_254_740_993]),
                ),
                (
                    "precise-float32",
                    numeric_array(py, vec![1.25_f64, -0.0, 3.5], "float32"),
                    ArrayStorage::F32(vec![1.25, -0.0, 3.5]),
                ),
                (
                    "precise-float64",
                    numeric_array(py, vec![1.25_f64, -0.0, 3.5], "float64"),
                    ArrayStorage::F64(vec![1.25, -0.0, 3.5]),
                ),
            ];

            let mut proof_bytes = Vec::new();
            for (label, input, expected_storage) in precise_cases {
                let extracted = extract_precise_numeric_array(py, &input, label)?;
                assert_eq!(extracted.shape(), &[3], "{label} shape drift");
                let storage = extracted
                    .to_storage()
                    .map_err(|err| PyValueError::new_err(err.to_string()))?;
                assert_eq!(storage, expected_storage, "{label} storage drift");
                proof_bytes.extend_from_slice(label.as_bytes());
                proof_bytes.push(0);
                append_numeric_storage_bytes(&storage, &mut proof_bytes)?;
            }

            let generic_cases = vec![
                (
                    "generic-int",
                    numeric_array(py, vec![-7_i64, 0, 12], "int32"),
                    ArrayStorage::I64(vec![-7, 0, 12]),
                ),
                (
                    "generic-uint",
                    numeric_array(py, vec![0_u64, 7, 12], "uint32"),
                    ArrayStorage::U64(vec![0, 7, 12]),
                ),
                (
                    "generic-float",
                    numeric_array(py, vec![1.25_f64, -0.0, 3.5], "float32"),
                    ArrayStorage::F64(vec![1.25, -0.0, 3.5]),
                ),
            ];

            for (label, input, expected_storage) in generic_cases {
                let extracted = extract_numeric_array(py, &input, label)?;
                assert_eq!(extracted.shape(), &[3], "{label} shape drift");
                let storage = extracted
                    .to_storage()
                    .map_err(|err| PyValueError::new_err(err.to_string()))?;
                assert_eq!(storage, expected_storage, "{label} storage drift");
                proof_bytes.extend_from_slice(label.as_bytes());
                proof_bytes.push(0);
                append_numeric_storage_bytes(&storage, &mut proof_bytes)?;
            }

            let digest = py_sha256_hex(py, &proof_bytes)?;
            assert_eq!(
                digest,
                "92b607a7e4d64fd01b975e9795f2f2a0ecf68c126fec5948651afb01af8e9f04"
            );
            Ok(())
        });
    }

    #[test]
    fn native_matmul_dot_f64_gemm_gate_and_golden_sha256() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }
            let numpy = py.import("numpy")?;
            let allclose = numpy.getattr("allclose")?;
            let a = numpy
                .getattr("arange")?
                .call1((12_i64,))?
                .call_method1("reshape", (3_i64, 4_i64))?
                .call_method1("astype", ("float64",))?;
            let b = numpy
                .getattr("arange")?
                .call1((20_i64,))?
                .call_method1("reshape", (4_i64, 5_i64))?
                .call_method1("astype", ("float64",))?;

            let native_matmul =
                python_native_gemm_f64_2d(py, &a, &b, PythonNativeGemmOp::Matmul, false)?
                    .expect("small f64 2-D matmul should be supported by native helper");
            let native_dot = python_native_gemm_f64_2d(py, &a, &b, PythonNativeGemmOp::Dot, false)?
                .expect("small f64 2-D dot should be supported by native helper");

            let expected_matmul = numpy.getattr("matmul")?.call1((&a, &b))?;
            let expected_dot = numpy.getattr("dot")?.call1((&a, &b))?;
            assert!(
                allclose
                    .call1((native_matmul.bind(py), &expected_matmul))?
                    .extract::<bool>()?,
                "native matmul helper diverged from numpy"
            );
            assert!(
                allclose
                    .call1((native_dot.bind(py), &expected_dot))?
                    .extract::<bool>()?,
                "native dot helper diverged from numpy"
            );

            let mut proof_bytes = Vec::new();
            append_numpy_array_bytes(py, native_matmul.bind(py), &mut proof_bytes)?;
            append_numpy_array_bytes(py, native_dot.bind(py), &mut proof_bytes)?;
            let digest = py_sha256_hex(py, &proof_bytes)?;
            assert_eq!(
                digest, "a2fd2db2e207c8d79c237d8b938c73d2e154ed31bd30ee9f7f7a0819739b6085",
                "native matmul/dot helper output bit pattern changed"
            );

            let medium_a =
                UFuncArray::new(vec![320, 320], vec![1.0; 320 * 320], DType::F64).unwrap();
            let medium_b =
                UFuncArray::new(vec![320, 320], vec![1.0; 320 * 320], DType::F64).unwrap();
            assert!(
                python_native_gemm_f64_2d_eligible(&medium_a, &medium_b),
                "profiled 320^3 f64 GEMM should take the native gate"
            );

            let small_a =
                UFuncArray::new(vec![256, 256], vec![1.0; 256 * 256], DType::F64).unwrap();
            let small_b =
                UFuncArray::new(vec![256, 256], vec![1.0; 256 * 256], DType::F64).unwrap();
            assert!(
                !python_native_gemm_f64_2d_eligible(&small_a, &small_b),
                "profiled 256^3 GEMM should stay on numpy fallback"
            );
            let small_np = numpy
                .getattr("ones")?
                .call1(((256_i64, 256_i64),))?
                .call_method1("astype", ("float64",))?;
            assert!(
                !python_native_gemm_f64_2d_metadata_gate(py, &small_np, &small_np)?,
                "metadata gate must reject 256^3 before the Rust extraction copy"
            );

            // A dimension above PY_NATIVE_GEMM_MAX_DIM (1024 since e6468d9c raised the
            // crossover from 896) must stay on the numpy fallback. 1024 itself is now
            // at the cap and eligible, so test one genuinely above it.
            let cap = super::PY_NATIVE_GEMM_MAX_DIM;
            let too_large_a =
                UFuncArray::new(vec![1280, 320], vec![1.0; 1280 * 320], DType::F64).unwrap();
            let too_large_b =
                UFuncArray::new(vec![320, 320], vec![1.0; 320 * 320], DType::F64).unwrap();
            assert!(
                !python_native_gemm_f64_2d_eligible(&too_large_a, &too_large_b),
                "dimension above the {cap} cap should stay on numpy fallback"
            );
            // And the cap boundary itself is eligible under the raised crossover.
            let at_cap_a =
                UFuncArray::new(vec![cap, 320], vec![1.0; cap * 320], DType::F64).unwrap();
            assert!(
                python_native_gemm_f64_2d_eligible(&at_cap_a, &too_large_b),
                "dimension at the {cap} cap should take the native gate"
            );

            let f32_a = UFuncArray::new(vec![320, 320], vec![1.0; 320 * 320], DType::F32).unwrap();
            assert!(
                !python_native_gemm_f64_2d_eligible(&f32_a, &medium_b),
                "non-f64 dtypes should stay on numpy fallback"
            );

            Ok(())
        });
    }

    fn reduce_outcome(
        py: Python<'_>,
        ufunc: &pyo3::Bound<'_, pyo3::types::PyAny>,
        array: &pyo3::Bound<'_, pyo3::types::PyAny>,
        kwargs: Option<&pyo3::Bound<'_, PyDict>>,
    ) -> PyResult<String> {
        match ufunc.call_method("reduce", (array,), kwargs) {
            Ok(value) => Ok(format!("ok:{}", repr_string(&value))),
            Err(err) => {
                let name = err.get_type(py).name()?;
                let message = err.value(py).str()?.extract::<String>()?;
                Ok(format!("err:{name}:{message}"))
            }
        }
    }

    fn call_outcome(
        py: Python<'_>,
        callable: &pyo3::Bound<'_, pyo3::types::PyAny>,
        args: &pyo3::Bound<'_, PyTuple>,
        kwargs: Option<&pyo3::Bound<'_, PyDict>>,
    ) -> PyResult<String> {
        match callable.call(args, kwargs) {
            Ok(value) => Ok(format!("ok:{}", repr_string(&value))),
            Err(err) => {
                let name = err.get_type(py).name()?;
                let message = err.value(py).str()?.extract::<String>()?;
                Ok(format!("err:{name}:{message}"))
            }
        }
    }

    fn slice_object(
        py: Python<'_>,
        start: Option<Py<PyAny>>,
        stop: Option<Py<PyAny>>,
        step: Option<Py<PyAny>>,
    ) -> PyResult<Py<PyAny>> {
        let builtins = py.import("builtins")?;
        let start = start.unwrap_or_else(|| py.None());
        let stop = stop.unwrap_or_else(|| py.None());
        let step = step.unwrap_or_else(|| py.None());
        Ok(builtins
            .getattr("slice")?
            .call1((start.bind(py), stop.bind(py), step.bind(py)))?
            .unbind())
    }

    fn assert_array_matches_numpy(
        actual: &pyo3::Bound<'_, pyo3::types::PyAny>,
        expected: &pyo3::Bound<'_, pyo3::types::PyAny>,
    ) -> PyResult<()> {
        // Some numpy entry-points return a plain Python scalar (int/float)
        // while our wrapper returns a numpy 0-D array (or vice versa),
        // e.g. np.ma.count(axis=None) returns Python int but our rust-port
        // returns numpy.int64. Normalize both sides to a scalar via .item()
        // when either side lacks `.dtype`.
        let actual_is_py_scalar = actual.getattr("dtype").is_err();
        let expected_is_py_scalar = expected.getattr("dtype").is_err();
        if actual_is_py_scalar || expected_is_py_scalar {
            // Unify: if one side is a 0-D numpy array/scalar, call .item()
            // to reduce it to a Python scalar, so repr comparison works.
            let actual_normalized: String = if actual_is_py_scalar {
                repr_string(actual)
            } else {
                match actual.call_method0("item") {
                    Ok(item) => repr_string(&item),
                    Err(_) => repr_string(actual),
                }
            };
            let expected_normalized: String = if expected_is_py_scalar {
                repr_string(expected)
            } else {
                match expected.call_method0("item") {
                    Ok(item) => repr_string(&item),
                    Err(_) => repr_string(expected),
                }
            };
            assert_eq!(
                actual_normalized, expected_normalized,
                "scalar result mismatch (after .item() normalisation)"
            );
            return Ok(());
        }
        // Fall through to the original array path by re-checking — this
        // legacy branch preserves the old string-compare for reference;
        // the early return above handles all scalar / asymmetric cases.
        if actual.getattr("dtype").is_err() {
            assert!(
                expected.getattr("dtype").is_err(),
                "assert_array_matches_numpy: sides disagree on array-ness \
                 (ours is scalar, theirs is array)"
            );
            assert_eq!(
                repr_string(actual),
                repr_string(expected),
                "scalar result mismatch"
            );
            return Ok(());
        }
        assert_eq!(
            actual.getattr("dtype")?.str()?.extract::<String>()?,
            expected.getattr("dtype")?.str()?.extract::<String>()?
        );
        assert_eq!(
            actual.getattr("shape")?.extract::<Vec<usize>>()?,
            expected.getattr("shape")?.extract::<Vec<usize>>()?
        );
        assert_eq!(
            repr_string(&actual.call_method0("tolist")?),
            repr_string(&expected.call_method0("tolist")?)
        );
        Ok(())
    }

    fn assert_random_sample_matches_numpy(
        actual: &pyo3::Bound<'_, pyo3::types::PyAny>,
        expected: &pyo3::Bound<'_, pyo3::types::PyAny>,
    ) -> PyResult<()> {
        let py = actual.py();
        if actual.getattr("dtype").is_err() {
            assert!(
                expected.getattr("dtype").is_err(),
                "assert_random_sample_matches_numpy: sides disagree on array-ness \
                 (ours is scalar, theirs is array)"
            );
        } else {
            assert_eq!(
                actual.getattr("dtype")?.str()?.extract::<String>()?,
                expected.getattr("dtype")?.str()?.extract::<String>()?
            );
            assert_eq!(
                actual.getattr("shape")?.extract::<Vec<usize>>()?,
                expected.getattr("shape")?.extract::<Vec<usize>>()?
            );
        }

        let kwargs = PyDict::new(py);
        kwargs.set_item("rtol", 1e-14_f64)?;
        kwargs.set_item("atol", 0.0_f64)?;
        kwargs.set_item("equal_nan", true)?;
        py.import("numpy")?.getattr("testing")?.call_method(
            "assert_allclose",
            (actual, expected),
            Some(&kwargs),
        )?;
        Ok(())
    }

    fn assert_index_tuple_matches_numpy(
        actual: &pyo3::Bound<'_, pyo3::types::PyAny>,
        expected: &pyo3::Bound<'_, pyo3::types::PyAny>,
    ) -> PyResult<()> {
        let actual_tuple = actual.cast::<PyTuple>()?;
        let expected_tuple = expected.cast::<PyTuple>()?;
        assert_eq!(actual_tuple.len()?, expected_tuple.len()?);

        for (actual_item, expected_item) in actual_tuple.try_iter()?.zip(expected_tuple.try_iter()?)
        {
            let actual_item = actual_item?;
            let expected_item = expected_item?;
            assert_eq!(
                actual_item.getattr("dtype")?.str()?.extract::<String>()?,
                expected_item.getattr("dtype")?.str()?.extract::<String>()?
            );
            assert_eq!(
                actual_item.getattr("shape")?.extract::<Vec<usize>>()?,
                expected_item.getattr("shape")?.extract::<Vec<usize>>()?
            );
            assert_eq!(
                repr_string(&actual_item.call_method0("tolist")?),
                repr_string(&expected_item.call_method0("tolist")?)
            );
        }

        Ok(())
    }

    fn assert_array_list_matches_numpy(
        actual: &pyo3::Bound<'_, pyo3::types::PyAny>,
        expected: &pyo3::Bound<'_, pyo3::types::PyAny>,
    ) -> PyResult<()> {
        assert_eq!(actual.len()?, expected.len()?);

        for (actual_item, expected_item) in actual.try_iter()?.zip(expected.try_iter()?) {
            assert_array_matches_numpy(&actual_item?, &expected_item?)?;
        }

        Ok(())
    }

    fn assert_pyerr_matches_numpy(
        py: Python<'_>,
        actual: pyo3::PyErr,
        expected: pyo3::PyErr,
    ) -> PyResult<()> {
        assert_eq!(
            actual.get_type(py).name()?.extract::<String>()?,
            expected.get_type(py).name()?.extract::<String>()?
        );
        assert_eq!(actual.to_string(), expected.to_string());
        Ok(())
    }

    fn random_generator_pair<'py>(
        random: &Bound<'py, PyAny>,
        numpy_random: &Bound<'py, PyAny>,
        seed: u64,
    ) -> PyResult<(Bound<'py, PyAny>, Bound<'py, PyAny>)> {
        let ours_bg = random.getattr("PCG64DXSM")?.call1((seed,))?;
        let theirs_bg = numpy_random.getattr("PCG64DXSM")?.call1((seed,))?;
        Ok((
            random.getattr("Generator")?.call1((ours_bg,))?,
            numpy_random.getattr("Generator")?.call1((theirs_bg,))?,
        ))
    }

    #[test]
    fn random_namespace_matches_numpy_bit_generator_oracles() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test_random")?;
            fnp_python(&module)?;
            let random = module.getattr("random")?;
            let numpy_random = py.import("numpy")?.getattr("random")?;
            let numpy_random_all = numpy_random.getattr("__all__")?;
            if repr_string(&random.getattr("__all__")?) != repr_string(&numpy_random_all) {
                return Err(PyValueError::new_err(
                    "fnp_python.random.__all__ must match numpy.random.__all__",
                ));
            }
            for item in numpy_random_all.try_iter()? {
                let name = item?.extract::<String>()?;
                if !random.hasattr(name.as_str())? {
                    return Err(PyValueError::new_err(format!(
                        "fnp_python.random missing numpy.random public name {name}"
                    )));
                }
            }

            for name in [
                "SeedSequence",
                "Generator",
                "RandomState",
                "MT19937",
                "PCG64",
                "PCG64DXSM",
                "Philox",
                "SFC64",
                "default_rng",
                // g1ji/x9my: NumPy-owned bit-generator abstract base and
                // singleton bridge helpers.
                "BitGenerator",
                "bit_generator",
                "get_bit_generator",
                "set_bit_generator",
                "test",
                // t44q: module-level legacy aliases bound to the shared
                // numpy.random._rand RandomState singleton.
                "_rand",
                "seed",
                "get_state",
                "set_state",
                "rand",
                "randn",
                "randint",
                "random",
                "random_sample",
                "ranf",
                "sample",
                "random_integers",
                "tomaxint",
                "bytes",
                "choice",
                "shuffle",
                "permutation",
                "normal",
                "standard_normal",
                "standard_cauchy",
                "standard_exponential",
                "standard_gamma",
                "exponential",
                "uniform",
                "beta",
                "binomial",
                "gamma",
                "chisquare",
                "dirichlet",
                "f",
                "geometric",
                "gumbel",
                "hypergeometric",
                "laplace",
                "logistic",
                "lognormal",
                "logseries",
                "multinomial",
                "multivariate_normal",
                "negative_binomial",
                "noncentral_chisquare",
                "noncentral_f",
                "pareto",
                "poisson",
                "power",
                "rayleigh",
                "standard_t",
                "triangular",
                "vonmises",
                "wald",
                "weibull",
                "zipf",
            ] {
                assert!(random.getattr(name).is_ok(), "missing random.{name}");
            }

            for name in [
                "BitGenerator",
                "bit_generator",
                "get_bit_generator",
                "set_bit_generator",
                "test",
            ] {
                assert!(
                    random.getattr(name)?.is(&numpy_random.getattr(name)?),
                    "fnp_python.random.{name} must be numpy.random.{name}"
                );
            }

            let get_bit_generator = random.getattr("get_bit_generator")?;
            let set_bit_generator = random.getattr("set_bit_generator")?;
            let original_bit_generator = get_bit_generator.call0()?;
            let replacement_bit_generator = numpy_random.getattr("PCG64")?.call1((777_u64,))?;
            let set_result = set_bit_generator.call1((&replacement_bit_generator,))?;
            let bridged_bit_generator = get_bit_generator.call0()?;
            let numpy_bit_generator = numpy_random.getattr("get_bit_generator")?.call0()?;
            let bridge_matches = set_result.is_none()
                && bridged_bit_generator.is(&replacement_bit_generator)
                && numpy_bit_generator.is(&replacement_bit_generator);
            set_bit_generator.call1((&original_bit_generator,))?;
            assert!(
                bridge_matches,
                "fnp_python.random bit-generator bridge must track numpy.random singleton"
            );
            assert!(
                get_bit_generator.call0()?.is(&original_bit_generator),
                "fnp_python.random.set_bit_generator must restore numpy.random singleton"
            );

            let ours_pcg64 = random.getattr("PCG64")?.call1((42_u64,))?;
            let theirs_pcg64 = numpy_random.getattr("PCG64")?.call1((42_u64,))?;
            assert_array_matches_numpy(
                &ours_pcg64.call_method1("random_raw", (4_usize,))?,
                &theirs_pcg64.call_method1("random_raw", (4_usize,))?,
            )?;

            let shape = PyTuple::new(py, [2_usize, 2_usize])?;
            let ours_dxsm = random.getattr("PCG64DXSM")?.call1((123_u64,))?;
            let theirs_dxsm = numpy_random.getattr("PCG64DXSM")?.call1((123_u64,))?;
            let ours_generator = random.getattr("Generator")?.call1((ours_dxsm,))?;
            let theirs_generator = numpy_random.getattr("Generator")?.call1((theirs_dxsm,))?;

            assert_array_matches_numpy(
                &ours_generator.call_method1("random", (shape.clone(),))?,
                &theirs_generator.call_method1("random", (shape.clone(),))?,
            )?;
            assert_array_matches_numpy(
                &ours_generator.call_method1("integers", (0_i64, 10_i64, shape.clone()))?,
                &theirs_generator.call_method1("integers", (0_i64, 10_i64, shape.clone()))?,
            )?;
            assert_array_matches_numpy(
                &ours_generator.call_method1("normal", (5.0_f64, 2.0_f64, 4_usize))?,
                &theirs_generator.call_method1("normal", (5.0_f64, 2.0_f64, 4_usize))?,
            )?;
            assert_eq!(
                repr_string(&ours_generator.call_method1("bytes", (8_usize,))?),
                repr_string(&theirs_generator.call_method1("bytes", (8_usize,))?),
            );

            let ours_state = random.getattr("RandomState")?.call1((7_u64,))?;
            let theirs_state = numpy_random.getattr("RandomState")?.call1((7_u64,))?;
            assert_array_matches_numpy(
                &ours_state.call_method1("random_sample", (shape.clone(),))?,
                &theirs_state.call_method1("random_sample", (shape,))?,
            )?;

            // t44q bit-exact parity: the module-level alias `random.rand`
            // must route through the singleton `_rand` RandomState. After
            // calling random.seed(7), random.rand(3) should match
            // numpy.random.rand(3) after numpy.random.seed(7).
            random.call_method1("seed", (7_u64,))?;
            numpy_random.call_method1("seed", (7_u64,))?;
            assert_array_matches_numpy(
                &random.call_method1("rand", (3_usize,))?,
                &numpy_random.call_method1("rand", (3_usize,))?,
            )?;
            // Back-to-back calls on the same singleton also advance the
            // same underlying RNG state in lockstep with numpy's.
            assert_array_matches_numpy(
                &random.call_method1("standard_normal", (4_usize,))?,
                &numpy_random.call_method1("standard_normal", (4_usize,))?,
            )?;
            assert_array_matches_numpy(
                &random.call_method1("randint", (0_i64, 100_i64, 5_usize))?,
                &numpy_random.call_method1("randint", (0_i64, 100_i64, 5_usize))?,
            )?;

            Ok(())
        });
    }

    #[test]
    fn hermite_e_wrappers_match_numpy() {
        // 7a8q: every fnp_python.herme* wrapper must produce bit-exact
        // output against numpy.polynomial.hermite_e.<same_name>. 15
        // wrappers × 1 representative call each.
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }
            let module = PyModule::new(py, "fnp_python_test_hermite_e")?;
            fnp_python(&module)?;
            let np_hermite_e = py.import("numpy.polynomial.hermite_e")?;

            let c1 = PyTuple::new(py, [1.0_f64, 2.0_f64, 3.0_f64])?;
            let c2 = PyTuple::new(py, [1.0_f64, 0.0_f64, 1.0_f64])?;
            let x = 0.5_f64;
            let roots = PyTuple::new(py, [-1.0_f64, 1.0_f64])?;

            for (name, call_args) in [
                ("hermeadd", "binary"),
                ("hermesub", "binary"),
                ("hermemul", "binary"),
                ("hermediv", "binary"),
                ("hermeroots", "unary"),
                ("hermefromroots", "roots"),
                ("hermemulx", "unary"),
                ("hermetrim", "unary_tol"),
                ("herme2poly", "unary"),
                ("poly2herme", "unary"),
            ] {
                let ours_fn = module.getattr(name)?;
                let theirs_fn = np_hermite_e.getattr(name)?;
                let (ours, theirs): (Py<PyAny>, Py<PyAny>) = match call_args {
                    "binary" => (
                        ours_fn.call1((c1.clone(), c2.clone()))?.unbind(),
                        theirs_fn.call1((c1.clone(), c2.clone()))?.unbind(),
                    ),
                    "unary" => match name {
                        "hermeroots" | "hermemulx" => (
                            ours_fn.call1((c1.clone(),))?.unbind(),
                            theirs_fn.call1((c1.clone(),))?.unbind(),
                        ),
                        _ => (
                            ours_fn.call1((c1.clone(),))?.unbind(),
                            theirs_fn.call1((c1.clone(),))?.unbind(),
                        ),
                    },
                    "roots" => (
                        ours_fn.call1((roots.clone(),))?.unbind(),
                        theirs_fn.call1((roots.clone(),))?.unbind(),
                    ),
                    "unary_tol" => (
                        ours_fn.call1((c1.clone(), 0.0_f64))?.unbind(),
                        theirs_fn.call1((c1.clone(), 0.0_f64))?.unbind(),
                    ),
                    _ => unreachable!(),
                };
                assert_eq!(
                    repr_string(ours.bind(py)),
                    repr_string(theirs.bind(py)),
                    "fnp_python.{name} diverges from numpy.polynomial.hermite_e.{name}"
                );
            }
            // hermeval / hermeder / hermeint / hermepow / hermeline have
            // unique signatures — exercise each with a single call.
            let ours_val = module.getattr("hermeval")?.call1((x, c1.clone()))?;
            let theirs_val = np_hermite_e.getattr("hermeval")?.call1((x, c1.clone()))?;
            assert_eq!(repr_string(&ours_val), repr_string(&theirs_val));
            let ours_der = module.getattr("hermeder")?.call1((c1.clone(),))?;
            let theirs_der = np_hermite_e.getattr("hermeder")?.call1((c1.clone(),))?;
            assert_eq!(repr_string(&ours_der), repr_string(&theirs_der));
            let ours_int = module.getattr("hermeint")?.call1((c1.clone(),))?;
            let theirs_int = np_hermite_e.getattr("hermeint")?.call1((c1.clone(),))?;
            assert_eq!(repr_string(&ours_int), repr_string(&theirs_int));
            let ours_pow = module.getattr("hermepow")?.call1((c1.clone(), 2_i64))?;
            let theirs_pow = np_hermite_e
                .getattr("hermepow")?
                .call1((c1.clone(), 2_i64))?;
            assert_eq!(repr_string(&ours_pow), repr_string(&theirs_pow));
            let ours_line = module.getattr("hermeline")?.call1((1.0_f64, 2.0_f64))?;
            let theirs_line = np_hermite_e
                .getattr("hermeline")?
                .call1((1.0_f64, 2.0_f64))?;
            assert_eq!(repr_string(&ours_line), repr_string(&theirs_line));
            Ok(())
        });
    }

    #[test]
    fn polynomial_namespace_exposes_nested_subpackages() {
        // crid: fnp_python.polynomial.{polynomial, chebyshev, legendre,
        // hermite, hermite_e, laguerre, polyutils} must resolve to numpy's real
        // submodules so user code written against numpy's canonical
        // import paths works verbatim.
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }
            let module_name = "fnp_python_test_polynomial_nested";
            let module = PyModule::new(py, module_name)?;
            let sys_modules = py.import("sys")?.getattr("modules")?;
            sys_modules.set_item(module_name, &module)?;
            fnp_python(&module)?;
            let polynomial = module.getattr("polynomial")?;
            let np_poly = py.import("numpy.polynomial")?;
            let import_module = py.import("importlib")?.getattr("import_module")?;
            for sub in [
                "polynomial",
                "chebyshev",
                "legendre",
                "hermite",
                "hermite_e",
                "laguerre",
                "polyutils",
            ] {
                let ours = polynomial.getattr(sub)?;
                let theirs = np_poly.getattr(sub)?;
                assert!(
                    ours.is(&theirs),
                    "fnp_python.polynomial.{sub} must BE numpy.polynomial.{sub}"
                );
                let alias = format!("{module_name}.polynomial.{sub}");
                assert!(
                    sys_modules.get_item(&alias)?.is(&theirs),
                    "{alias} should be registered under sys.modules"
                );
                assert!(
                    import_module.call1((&alias,))?.is(&theirs),
                    "importlib.import_module({alias:?}) must return numpy.polynomial.{sub}"
                );
            }
            // Round-trip: numpy.polynomial.chebyshev.chebadd is reachable
            // via fnp_python.polynomial.chebyshev.chebadd and returns
            // matching output.
            let ours_chebadd = polynomial
                .getattr("chebyshev")?
                .getattr("chebadd")?
                .call1((
                    PyTuple::new(py, [1.0_f64, 2.0_f64])?,
                    PyTuple::new(py, [1.0_f64, 1.0_f64, 3.0_f64])?,
                ))?;
            let theirs_chebadd = np_poly.getattr("chebyshev")?.getattr("chebadd")?.call1((
                PyTuple::new(py, [1.0_f64, 2.0_f64])?,
                PyTuple::new(py, [1.0_f64, 1.0_f64, 3.0_f64])?,
            ))?;
            assert_eq!(repr_string(&ours_chebadd), repr_string(&theirs_chebadd));
            Ok(())
        });
    }

    #[test]
    fn polynomial_polyutils_helpers_match_numpy() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test_polynomial_polyutils")?;
            fnp_python(&module)?;
            let polyutils = module.getattr("polynomial")?.getattr("polyutils")?;
            let numpy_polyutils = py.import("numpy.polynomial.polyutils")?;
            assert!(
                polyutils.is(&numpy_polyutils),
                "fnp_python.polynomial.polyutils must BE numpy.polynomial.polyutils"
            );

            let numpy = py.import("numpy")?;
            let builtins = py.import("builtins")?;
            let eval_fn = builtins.getattr("eval")?;
            let globals = PyDict::new(py);
            globals.set_item("np", numpy.clone())?;
            let eval_with_globals = |code: &str| -> PyResult<pyo3::Bound<'_, PyAny>> {
                eval_fn.call((code, &globals), None::<&pyo3::Bound<'_, PyDict>>)
            };

            let as_series_input = eval_with_globals(
                "[[1.0, 2.0, 0.0], np.array([0.0, 3.0, 0.0], dtype=np.float32)]",
            )?;
            let as_series = polyutils.getattr("as_series")?;
            let numpy_as_series = numpy_polyutils.getattr("as_series")?;
            assert_eq!(
                repr_string(&as_series.call1((as_series_input.clone(),))?),
                repr_string(&numpy_as_series.call1((as_series_input.clone(),))?)
            );
            let no_trim_kwargs = PyDict::new(py);
            no_trim_kwargs.set_item("trim", false)?;
            assert_eq!(
                repr_string(&as_series.call((as_series_input.clone(),), Some(&no_trim_kwargs))?),
                repr_string(
                    &numpy_as_series.call((as_series_input.clone(),), Some(&no_trim_kwargs))?
                )
            );

            let trimseq = polyutils.getattr("trimseq")?;
            let numpy_trimseq = numpy_polyutils.getattr("trimseq")?;
            assert_eq!(
                repr_string(&trimseq.call1((vec![1.0_f64, 2.0, 0.0, 0.0],))?),
                repr_string(&numpy_trimseq.call1((vec![1.0_f64, 2.0, 0.0, 0.0],))?)
            );

            let trimcoef = polyutils.getattr("trimcoef")?;
            let numpy_trimcoef = numpy_polyutils.getattr("trimcoef")?;
            assert_array_matches_numpy(
                &trimcoef.call1((vec![1.0_f64, 1.0e-5, 0.0], 1.0e-4_f64))?,
                &numpy_trimcoef.call1((vec![1.0_f64, 1.0e-5, 0.0], 1.0e-4_f64))?,
            )?;
            let all_zero_coeffs = vec![0.0_f64, 0.0, 0.0];
            assert_array_matches_numpy(
                &trimcoef.call1((all_zero_coeffs.clone(),))?,
                &numpy_trimcoef.call1((all_zero_coeffs.clone(),))?,
            )?;

            let getdomain = polyutils.getattr("getdomain")?;
            let numpy_getdomain = numpy_polyutils.getattr("getdomain")?;
            for code in [
                "np.array([3.0, -1.0, 2.0])",
                "np.array([1.0 + 2.0j, -3.0 + 0.5j])",
            ] {
                let input = eval_with_globals(code)?;
                assert_array_matches_numpy(
                    &getdomain.call1((input.clone(),))?,
                    &numpy_getdomain.call1((input.clone(),))?,
                )?;
            }

            let mapparms = polyutils.getattr("mapparms")?;
            let numpy_mapparms = numpy_polyutils.getattr("mapparms")?;
            assert_eq!(
                repr_string(&mapparms.call1((vec![-1.0_f64, 1.0], vec![0.0_f64, 10.0]))?),
                repr_string(&numpy_mapparms.call1((vec![-1.0_f64, 1.0], vec![0.0_f64, 10.0]))?)
            );

            let mapdomain = polyutils.getattr("mapdomain")?;
            let numpy_mapdomain = numpy_polyutils.getattr("mapdomain")?;
            assert_array_matches_numpy(
                &mapdomain.call1((
                    vec![-1.0_f64, 0.0, 1.0],
                    vec![-1.0_f64, 1.0],
                    vec![0.0_f64, 10.0],
                ))?,
                &numpy_mapdomain.call1((
                    vec![-1.0_f64, 0.0, 1.0],
                    vec![-1.0_f64, 1.0],
                    vec![0.0_f64, 10.0],
                ))?,
            )?;

            let format_float = polyutils.getattr("format_float")?;
            let numpy_format_float = numpy_polyutils.getattr("format_float")?;
            assert_eq!(
                repr_string(&format_float.call1((1.25_f64,))?),
                repr_string(&numpy_format_float.call1((1.25_f64,))?)
            );
            let parens_kwargs = PyDict::new(py);
            parens_kwargs.set_item("parens", true)?;
            assert_eq!(
                repr_string(&format_float.call((-1.25_f64,), Some(&parens_kwargs))?),
                repr_string(&numpy_format_float.call((-1.25_f64,), Some(&parens_kwargs))?)
            );

            let bad_series = eval_with_globals("[np.array([[1.0, 2.0]])]")?;
            assert_eq!(
                call_outcome(
                    py,
                    &as_series,
                    &PyTuple::new(py, [bad_series.clone()])?,
                    None,
                )?,
                call_outcome(
                    py,
                    &numpy_as_series,
                    &PyTuple::new(py, [bad_series.clone()])?,
                    None,
                )?
            );
            let bad_tol_kwargs = PyDict::new(py);
            bad_tol_kwargs.set_item("tol", -1.0_f64)?;
            let coeffs = eval_with_globals("[1.0, 2.0]")?;
            assert_eq!(
                call_outcome(
                    py,
                    &trimcoef,
                    &PyTuple::new(py, [coeffs.clone()])?,
                    Some(&bad_tol_kwargs),
                )?,
                call_outcome(
                    py,
                    &numpy_trimcoef,
                    &PyTuple::new(py, [coeffs.clone()])?,
                    Some(&bad_tol_kwargs),
                )?
            );

            Ok(())
        });
    }

    #[test]
    fn polynomial_namespace_exposes_numpy_classes() {
        // d7a1: fnp_python.polynomial.{Polynomial, Chebyshev, Legendre,
        // Hermite, HermiteE, Laguerre} must resolve to numpy's real
        // class objects so isinstance checks + direct construction work.
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }
            let module = PyModule::new(py, "fnp_python_test_polynomial")?;
            fnp_python(&module)?;
            let polynomial = module.getattr("polynomial")?;
            let np_poly = py.import("numpy.polynomial")?;
            let numpy_polynomial_all = np_poly.getattr("__all__")?;
            if repr_string(&polynomial.getattr("__all__")?) != repr_string(&numpy_polynomial_all) {
                return Err(PyValueError::new_err(
                    "fnp_python.polynomial.__all__ must match numpy.polynomial.__all__",
                ));
            }
            for item in numpy_polynomial_all.try_iter()? {
                let name = item?.extract::<String>()?;
                if !polynomial.hasattr(name.as_str())? {
                    return Err(PyValueError::new_err(format!(
                        "fnp_python.polynomial missing numpy.polynomial public name {name}"
                    )));
                }
            }
            for name in [
                "Polynomial",
                "Chebyshev",
                "Legendre",
                "Hermite",
                "HermiteE",
                "Laguerre",
            ] {
                let ours = polynomial.getattr(name)?;
                let theirs = np_poly.getattr(name)?;
                assert!(
                    ours.is(&theirs),
                    "fnp_python.polynomial.{name} must BE numpy.polynomial.{name} (identity, not just equality)"
                );
            }
            let ours_set_style = polynomial.getattr("set_default_printstyle")?;
            let theirs_set_style = np_poly.getattr("set_default_printstyle")?;
            assert!(
                ours_set_style.is(&theirs_set_style),
                "fnp_python.polynomial.set_default_printstyle must BE numpy.polynomial.set_default_printstyle"
            );
            let ours_test = polynomial.getattr("test")?;
            let theirs_test = np_poly.getattr("test")?;
            assert!(
                ours_test.is(&theirs_test),
                "fnp_python.polynomial.test must BE numpy.polynomial.test"
            );
            assert!(ours_set_style.call1(("unicode",))?.is_none());
            let bad_style = PyTuple::new(py, ["bogus"])?;
            assert_eq!(
                call_outcome(py, &ours_set_style, &bad_style, None)?,
                call_outcome(py, &theirs_set_style, &bad_style, None)?
            );
            // Round-trip: constructing a Polynomial via fnp_python yields
            // the same coefficients numpy would produce.
            let cls = polynomial.getattr("Polynomial")?;
            let poly = cls.call1(((1.0_f64, 2.0_f64, 3.0_f64),))?;
            let coef: Vec<f64> = poly.getattr("coef")?.extract()?;
            assert_eq!(coef, vec![1.0, 2.0, 3.0]);
            Ok(())
        });
    }

    #[test]
    fn random_state_delegated_legacy_methods_match_numpy_oracles() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test_random_state_delegated_legacy")?;
            fnp_python(&module)?;
            let random = module.getattr("random")?;
            let numpy = py.import("numpy")?;
            let numpy_random = numpy.getattr("random")?;
            let shape = PyTuple::new(py, [2_usize, 3_usize])?;

            let ours = random.getattr("RandomState")?.call1((42_u64,))?;
            let theirs = numpy_random.getattr("RandomState")?.call1((42_u64,))?;

            assert_random_sample_matches_numpy(
                &ours.call_method1("binomial", (10_u64, 0.25_f64, shape.clone()))?,
                &theirs.call_method1("binomial", (10_u64, 0.25_f64, shape.clone()))?,
            )?;
            assert_random_sample_matches_numpy(
                &ours.call_method1("poisson", (3.5_f64, shape.clone()))?,
                &theirs.call_method1("poisson", (3.5_f64, shape.clone()))?,
            )?;
            assert_random_sample_matches_numpy(
                &ours.call_method1("negative_binomial", (5_i64, 0.4_f64, shape.clone()))?,
                &theirs.call_method1("negative_binomial", (5_i64, 0.4_f64, shape.clone()))?,
            )?;
            assert_random_sample_matches_numpy(
                &ours.call_method1("hypergeometric", (5_u64, 7_u64, 3_u64, shape.clone()))?,
                &theirs.call_method1("hypergeometric", (5_u64, 7_u64, 3_u64, shape.clone()))?,
            )?;
            assert_random_sample_matches_numpy(
                &ours.call_method1("logseries", (0.5_f64, shape.clone()))?,
                &theirs.call_method1("logseries", (0.5_f64, shape.clone()))?,
            )?;
            assert_random_sample_matches_numpy(
                &ours.call_method1("vonmises", (1.0_f64, 2.0_f64, shape.clone()))?,
                &theirs.call_method1("vonmises", (1.0_f64, 2.0_f64, shape.clone()))?,
            )?;
            assert_random_sample_matches_numpy(
                &ours.call_method1("wald", (2.0_f64, 3.0_f64, shape.clone()))?,
                &theirs.call_method1("wald", (2.0_f64, 3.0_f64, shape.clone()))?,
            )?;

            let pvals = PyList::new(py, [0.2_f64, 0.3_f64, 0.5_f64])?;
            assert_random_sample_matches_numpy(
                &ours.call_method1("multinomial", (5_u64, pvals.clone(), 4_usize))?,
                &theirs.call_method1("multinomial", (5_u64, pvals.clone(), 4_usize))?,
            )?;
            let alpha = PyList::new(py, [1.0_f64, 2.0_f64, 3.0_f64])?;
            assert_random_sample_matches_numpy(
                &ours.call_method1("dirichlet", (alpha.clone(), 4_usize))?,
                &theirs.call_method1("dirichlet", (alpha.clone(), 4_usize))?,
            )?;
            let mean = PyList::new(py, [0.0_f64, 1.0_f64])?;
            let cov = numpy.call_method1(
                "array",
                (vec![vec![1.0_f64, 0.1_f64], vec![0.1_f64, 1.5_f64]],),
            )?;
            assert_random_sample_matches_numpy(
                &ours.call_method1("multivariate_normal", (mean.clone(), cov.clone(), 4_usize))?,
                &theirs
                    .call_method1("multivariate_normal", (mean.clone(), cov.clone(), 4_usize))?,
            )?;
            assert_random_sample_matches_numpy(
                &ours.call_method1("noncentral_chisquare", (4.0_f64, 1.5_f64, shape.clone()))?,
                &theirs.call_method1("noncentral_chisquare", (4.0_f64, 1.5_f64, shape.clone()))?,
            )?;
            assert_random_sample_matches_numpy(
                &ours.call_method1("noncentral_f", (4.0_f64, 7.0_f64, 1.5_f64, shape.clone()))?,
                &theirs.call_method1("noncentral_f", (4.0_f64, 7.0_f64, 1.5_f64, shape.clone()))?,
            )?;
            assert_random_sample_matches_numpy(
                &ours.call_method1("choice", (10_i64, shape.clone(), false))?,
                &theirs.call_method1("choice", (10_i64, shape.clone(), false))?,
            )?;
            assert_random_sample_matches_numpy(
                &ours.call_method1("permutation", (6_i64,))?,
                &theirs.call_method1("permutation", (6_i64,))?,
            )?;

            let ours_array = numpy.call_method1("arange", (8_i64,))?;
            let theirs_array = numpy.call_method1("arange", (8_i64,))?;
            assert_eq!(
                repr_string(&ours.call_method1("shuffle", (ours_array.clone(),))?),
                repr_string(&theirs.call_method1("shuffle", (theirs_array.clone(),))?)
            );
            assert_array_matches_numpy(&ours_array, &theirs_array)?;

            assert_random_sample_matches_numpy(
                &ours.call_method1("random_sample", (shape.clone(),))?,
                &theirs.call_method1("random_sample", (shape,))?,
            )?;

            Ok(())
        });
    }

    #[test]
    fn random_state_rand_matches_numpy_oracles() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test_random_state_rand")?;
            fnp_python(&module)?;
            let random = module.getattr("random")?;
            let numpy_random = py.import("numpy")?.getattr("random")?;

            let ours_state = random.getattr("RandomState")?.call1((7_u64,))?;
            let theirs_state = numpy_random.getattr("RandomState")?.call1((7_u64,))?;
            assert_random_sample_matches_numpy(
                &ours_state.call_method0("rand")?,
                &theirs_state.call_method0("rand")?,
            )?;
            assert_random_sample_matches_numpy(
                &ours_state.call_method1("rand", (2_usize, 3_usize))?,
                &theirs_state.call_method1("rand", (2_usize, 3_usize))?,
            )?;
            assert_random_sample_matches_numpy(
                &ours_state.call_method1("rand", (0_usize,))?,
                &theirs_state.call_method1("rand", (0_usize,))?,
            )?;

            let ours_negative = random.getattr("RandomState")?.call1((7_u64,))?;
            let theirs_negative = numpy_random.getattr("RandomState")?.call1((7_u64,))?;
            let ours_negative_err = match ours_negative.call_method1("rand", (-1_i64,)) {
                Ok(_) => {
                    return Err(pyo3::PyErr::new::<pyo3::exceptions::PyAssertionError, _>(
                        "RandomState.rand(-1) unexpectedly succeeded",
                    ));
                }
                Err(err) => err,
            };
            let theirs_negative_err = match theirs_negative.call_method1("rand", (-1_i64,)) {
                Ok(_) => {
                    return Err(pyo3::PyErr::new::<pyo3::exceptions::PyAssertionError, _>(
                        "numpy RandomState.rand(-1) unexpectedly succeeded",
                    ));
                }
                Err(err) => err,
            };
            assert_pyerr_matches_numpy(py, ours_negative_err, theirs_negative_err)?;

            let ours_bool = random.getattr("RandomState")?.call1((7_u64,))?;
            let theirs_bool = numpy_random.getattr("RandomState")?.call1((7_u64,))?;
            let ours_bool_err = match ours_bool.call_method1("rand", (true,)) {
                Ok(_) => {
                    return Err(pyo3::PyErr::new::<pyo3::exceptions::PyAssertionError, _>(
                        "RandomState.rand(True) unexpectedly succeeded",
                    ));
                }
                Err(err) => err,
            };
            let theirs_bool_err = match theirs_bool.call_method1("rand", (true,)) {
                Ok(_) => {
                    return Err(pyo3::PyErr::new::<pyo3::exceptions::PyAssertionError, _>(
                        "numpy RandomState.rand(True) unexpectedly succeeded",
                    ));
                }
                Err(err) => err,
            };
            assert_pyerr_matches_numpy(py, ours_bool_err, theirs_bool_err)?;

            Ok(())
        });
    }

