    #[test]
    fn take_index_out_of_bounds_matches_numpy_indexerror() {
        // numpy.take(arr, idx) raises IndexError (not ValueError) when idx
        // is out of range. Our take raised PyValueError via map_ufunc_error.
        // Fall back to numpy (or raise PyIndexError) so downstream code
        // catching IndexError specifically keeps working.
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }
            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let numpy = py.import("numpy")?;
            let take_fn = module.getattr("take")?;
            let numpy_take = numpy.getattr("take")?;

            let arr = numeric_array(py, vec![1_i64, 2, 3], "int64");
            let ours = take_fn
                .call1((arr.clone(), 10_i64))
                .expect_err("take(10) must error");
            let theirs = numpy_take
                .call1((arr, 10_i64))
                .expect_err("numpy take(10) must error");
            assert_eq!(
                ours.get_type(py).name()?.extract::<String>()?,
                theirs.get_type(py).name()?.extract::<String>()?,
                "take out-of-bounds error type diverges from numpy"
            );
            Ok(())
        });
    }

    #[test]
    fn swapaxes_moveaxis_axis_error_surface_probe() {
        // numpy.swapaxes and numpy.moveaxis raise AxisError on out-of-bounds
        // axes. Our in-Rust paths already fall back to numpy on error; this
        // probe is a regression gate locking that behavior in place.
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }
            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let numpy = py.import("numpy")?;

            let arr = numpy.getattr("ones")?.call1(((2_i64, 2_i64),))?;

            // swapaxes out-of-bounds axis1
            let ours_sw = module
                .getattr("swapaxes")?
                .call1((arr.clone(), 5_i64, 0_i64))
                .expect_err("swapaxes(5,0) must error");
            let theirs_sw = numpy
                .getattr("swapaxes")?
                .call1((arr.clone(), 5_i64, 0_i64))
                .expect_err("numpy swapaxes(5,0) must error");
            assert_eq!(
                ours_sw.get_type(py).name()?.extract::<String>()?,
                theirs_sw.get_type(py).name()?.extract::<String>()?,
                "swapaxes out-of-bounds error type diverges from numpy"
            );

            // moveaxis out-of-bounds source
            let ours_mv = module
                .getattr("moveaxis")?
                .call1((arr.clone(), 5_i64, 0_i64))
                .expect_err("moveaxis(5,0) must error");
            let theirs_mv = numpy
                .getattr("moveaxis")?
                .call1((arr, 5_i64, 0_i64))
                .expect_err("numpy moveaxis(5,0) must error");
            assert_eq!(
                ours_mv.get_type(py).name()?.extract::<String>()?,
                theirs_mv.get_type(py).name()?.extract::<String>()?,
                "moveaxis out-of-bounds error type diverges from numpy"
            );
            Ok(())
        });
    }

