    #[test]
    fn outer_matches_numpy_across_shapes_dtypes_and_out_kwarg() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let outer_fn = module.getattr("outer")?;
            let numpy = py.import("numpy")?;
            let numpy_outer = numpy.getattr("outer")?;
            let allclose = numpy.getattr("allclose")?;
            let array_equal = numpy.getattr("array_equal")?;

            // Float 1-D × float 1-D — basic case.
            let a = numpy.getattr("array")?.call1((vec![1.0_f64, 2.0, 3.0],))?;
            let b = numpy.getattr("array")?.call1((vec![4.0_f64, 5.0],))?;
            assert!(
                allclose
                    .call1((
                        &outer_fn.call1((a.clone(), b.clone()))?,
                        &numpy_outer.call1((a.clone(), b.clone()))?,
                    ))?
                    .extract::<bool>()?,
                "outer 1-D float diverged"
            );

            // Integer 1-D × integer 1-D — exact match required.
            let ia = numpy.getattr("array")?.call(
                (vec![1_i64, 2, 3, 4],),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("dtype", "int64")?;
                    kw
                }),
            )?;
            let ib = numpy.getattr("array")?.call(
                (vec![10_i64, 20],),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("dtype", "int64")?;
                    kw
                }),
            )?;
            assert!(
                array_equal
                    .call1((
                        &outer_fn.call1((ia.clone(), ib.clone()))?,
                        &numpy_outer.call1((ia.clone(), ib.clone()))?,
                    ))?
                    .extract::<bool>()?,
                "outer 1-D int diverged"
            );

            // Higher-dimensional inputs are flattened by numpy.outer.
            let a2d = numpy.getattr("array")?.call1((PyList::new(
                py,
                [
                    PyList::new(py, [1.0_f64, 2.0])?,
                    PyList::new(py, [3.0_f64, 4.0])?,
                ],
            )?,))?;
            let b2d = numpy.getattr("array")?.call1((vec![5.0_f64, 6.0],))?;
            assert!(
                allclose
                    .call1((
                        &outer_fn.call1((a2d.clone(), b2d.clone()))?,
                        &numpy_outer.call1((a2d.clone(), b2d.clone()))?,
                    ))?
                    .extract::<bool>()?,
                "outer 2-D flattened diverged"
            );

            // Mixed dtype promotion (int + float -> float).
            let mixed_a = numpy.getattr("array")?.call1((vec![1_i64, 2, 3],))?;
            let mixed_b = numpy.getattr("array")?.call1((vec![0.5_f64, 1.5],))?;
            assert!(
                allclose
                    .call1((
                        &outer_fn.call1((mixed_a.clone(), mixed_b.clone()))?,
                        &numpy_outer.call1((mixed_a.clone(), mixed_b.clone()))?,
                    ))?
                    .extract::<bool>()?,
                "outer mixed dtype diverged"
            );

            // Complex 1-D × complex 1-D.
            let builtins = py.import("builtins")?;
            let complex_a = numpy.getattr("array")?.call(
                (PyList::new(
                    py,
                    [
                        builtins.getattr("complex")?.call1((1.0_f64, 1.0_f64))?,
                        builtins.getattr("complex")?.call1((2.0_f64, 0.0_f64))?,
                    ],
                )?,),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("dtype", "complex128")?;
                    kw
                }),
            )?;
            let complex_b = numpy.getattr("array")?.call(
                (PyList::new(
                    py,
                    [
                        builtins.getattr("complex")?.call1((0.0_f64, 1.0_f64))?,
                        builtins.getattr("complex")?.call1((-1.0_f64, 0.0_f64))?,
                    ],
                )?,),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("dtype", "complex128")?;
                    kw
                }),
            )?;
            assert!(
                allclose
                    .call1((
                        &outer_fn.call1((complex_a.clone(), complex_b.clone()))?,
                        &numpy_outer.call1((complex_a.clone(), complex_b.clone()))?,
                    ))?
                    .extract::<bool>()?,
                "outer complex diverged"
            );

            // out= kwarg writes into a pre-allocated array of correct shape.
            let out_buf = numpy
                .getattr("zeros")?
                .call1((PyTuple::new(py, [3_i64, 2_i64])?,))?;
            let out_kwargs = PyDict::new(py);
            out_kwargs.set_item("out", out_buf.clone())?;
            let returned = outer_fn.call((a.clone(), b.clone()), Some(&out_kwargs))?;
            // numpy returns the same out buffer
            let expected_out = numpy_outer.call1((a.clone(), b.clone()))?;
            assert!(
                allclose
                    .call1((&returned, &expected_out))?
                    .extract::<bool>()?,
                "outer out= diverged"
            );

            Ok(())
        });
    }

    #[test]
    fn inner_native_gemm_gate_keeps_numpy_parity_across_sizes() {
        // The GEMM sweet-spot gate delegates small/large inner contractions to
        // numpy and keeps the native kernel only in the profiled window. Verify
        // parity vs numpy on BOTH sides: n=64 (below flop floor -> delegate),
        // n=384 (inside the native window), n=1100 (above the dim cap -> delegate).
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }
            let module = PyModule::new(py, "fnp_python_inner_gate")?;
            fnp_python(&module)?;
            let inner_fn = module.getattr("inner")?;
            let numpy = py.import("numpy")?;
            let numpy_inner = numpy.getattr("inner")?;
            let allclose = numpy.getattr("allclose")?;
            let rng = numpy
                .getattr("random")?
                .getattr("default_rng")?
                .call1((0_i64,))?;
            // NOTE: this gate is allclose-only by design. The native path runs a
            // BAND-PARALLEL, register-blocked GEMM whose per-output f64 accumulation
            // order is not fixed across compilations (codegen-unit / incremental-cache
            // nondeterminism shuffles how the reductions vectorize), so a byte-exact
            // sha256 over its output is build-UNSTABLE and false-fails unrelated edits
            // (bead deadlock-audit-kcwpj). allclose vs numpy at rtol/atol 1e-9 IS the
            // parity contract for a floating-point GEMM; do NOT re-add a byte golden
            // here.
            for n in [64_i64, 384, 1100] {
                let a = rng
                    .call_method1("standard_normal", ((n, n),))?
                    .call_method1("astype", ("float64",))?;
                let b = rng
                    .call_method1("standard_normal", ((n, n),))?
                    .call_method1("astype", ("float64",))?;
                let got = inner_fn.call1((a.clone(), b.clone()))?;
                let want = numpy_inner.call1((a.clone(), b.clone()))?;
                assert!(
                    allclose
                        .call(
                            (&got, &want),
                            Some(&{
                                let kw = PyDict::new(py);
                                kw.set_item("rtol", 1e-9)?;
                                kw.set_item("atol", 1e-9)?;
                                kw
                            })
                        )?
                        .extract::<bool>()?,
                    "inner gate diverged from numpy at n={n}"
                );
            }
            Ok(())
        });
    }

    #[test]
    #[ignore = "perf proof: compares gated np.inner against the pre-gate native path"]
    fn inner_native_gemm_gate_ab_bench() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }
            let module = PyModule::new(py, "fnp_python_inner_gate_ab")?;
            fnp_python(&module)?;
            let inner_fn = module.getattr("inner")?;
            let numpy = py.import("numpy")?;
            let allclose = numpy.getattr("allclose")?;
            let rng = numpy
                .getattr("random")?
                .getattr("default_rng")?
                .call1((0_i64,))?;
            let n = 240_i64;
            let a = rng
                .call_method1("standard_normal", ((n, n),))?
                .call_method1("astype", ("float64",))?;
            let b = rng
                .call_method1("standard_normal", ((n, n),))?
                .call_method1("astype", ("float64",))?;

            let gated = inner_fn.call1((a.clone(), b.clone()))?;
            let old_native = native_inner_without_python_gate(py, &a, &b)?;
            assert!(
                allclose
                    .call(
                        (&gated, old_native.bind(py)),
                        Some(&{
                            let kw = PyDict::new(py);
                            kw.set_item("rtol", 1e-9)?;
                            kw.set_item("atol", 1e-9)?;
                            kw
                        })
                    )?
                    .extract::<bool>()?,
                "gated inner diverged from the pre-gate native path"
            );

            let mut gated_samples = Vec::with_capacity(5);
            let mut old_native_samples = Vec::with_capacity(5);
            for _ in 0..5 {
                let start = Instant::now();
                std::hint::black_box(inner_fn.call1((a.clone(), b.clone()))?);
                gated_samples.push(start.elapsed().as_secs_f64() * 1_000.0);

                let start = Instant::now();
                std::hint::black_box(native_inner_without_python_gate(py, &a, &b)?);
                old_native_samples.push(start.elapsed().as_secs_f64() * 1_000.0);
            }

            let gated_ms = median_ms(&mut gated_samples);
            let old_native_ms = median_ms(&mut old_native_samples);
            let speedup = old_native_ms / gated_ms;
            println!(
                "INNER_GATE n={n} gated={gated_ms:.3}ms old_native={old_native_ms:.3}ms speedup={speedup:.2}x"
            );
            assert!(
                speedup >= 2.0,
                "inner gate speedup {speedup:.2}x failed Score>=2 perf floor"
            );
            Ok(())
        });
    }

